/* GENERATED theory-syntax-theory.js — full textbook theory. */
(function () {
  "use strict";
  if (!window.SYNTAX || !window.SYNTAX.get) return;
  function T(id, theory) { var L = window.SYNTAX.get(id); if (L && theory && theory.length) L.theory = theory; }
  T("syn-kyrioi-oroi", [{"h":"Τι είναι η πρόταση και ποιοι είναι οι κύριοι όροι της","body":"<p><b>Πρόταση</b> ονομάζουμε μια οργανωμένη ομάδα λέξεων που είναι τοποθετημένες η μία δίπλα στην άλλη σύμφωνα με τους νόμους της μορφολογίας και της σύνταξης της γλώσσας και εκφράζουν ένα <i>αυτοτελές νόημα</i>. Η πρόταση είναι η μικρότερη μονάδα του λόγου που μπορεί να σταθεί μόνη της και να μας πει κάτι ολοκληρωμένο.</p><p>Κάθε πρόταση που έχει ρήμα στηρίζεται σε δύο θεμελιώδη, αναγκαία στοιχεία, που τα ονομάζουμε <b>κύριους όρους</b> (ή <i>βασικούς / θεμελιώδεις όρους</i>):</p><ul><li><b>το Υποκείμενο (Υ)</b> — εκείνο για το οποίο γίνεται λόγος στην πρόταση· αυτό που <i>ενεργεί</i>, που <i>παθαίνει</i> κάτι ή που <i>βρίσκεται σε μια κατάσταση</i>·</li><li><b>το Κατηγόρημα</b> — αυτό που λέμε (κατηγορούμε) για το υποκείμενο· πυρήνας του είναι πάντοτε <i>το ρήμα</i>, μαζί με όσες λέξεις είναι αναγκαίες για να συμπληρωθεί η σημασία του.</li></ul><p>Οι κύριοι όροι αντιδιαστέλλονται προς τους <b>δευτερεύοντες όρους</b> (τους <i>προσδιορισμούς</i>), οι οποίοι δεν είναι απαραίτητοι για να υπάρξει η πρόταση, αλλά απλώς προσθέτουν, επεξηγούν ή περιορίζουν. Στην πρόταση <i>«ὁ σοφός ἀνήρ τότε ἐσιώπησε»</i> κύριοι όροι είναι μόνο το <i>ἀνήρ</i> (Υ) και το <i>ἐσιώπησε</i> (κατηγόρημα)· τα <i>σοφός</i> και <i>τότε</i> είναι προσδιορισμοί.</p><p>Συγγενικές, ευρύτερες μονάδες του λόγου είναι: η <b>περίοδος</b> (τμήμα λόγου από μία ή περισσότερες προτάσεις που εκφράζει ολοκληρωμένο νόημα και κλείνει με ισχυρό σημείο στίξης — τελεία, ερωτηματικό, θαυμαστικό, αποσιωπητικά) και το <b>κῶλον</b> ή <b>ημιπερίοδος</b> (τμήμα με αυτοτελές αλλά όχι ολοκληρωμένο νόημα, ανάμεσα σε ισχυρή στίξη και άνω τελεία).</p>","examples":[{"gr":"Ὁ Φίλιππος γράφει.","an":"Υποκείμενο: ὁ Φίλιππος (αυτός για τον οποίο γίνεται λόγος). Κατηγόρημα: γράφει (αυτό που λέμε για το υποκείμενο). Πρόκειται για τους δύο κύριους όρους στην πιο γυμνή τους μορφή."},{"gr":"Ὁ ἥλιος λάμπει.","an":"Υ = ὁ ἥλιος, κατηγόρημα = λάμπει. Το υποκείμενο βρίσκεται σε κατάσταση/ενέργεια· κανείς προσδιορισμός δεν είναι αναγκαίος."},{"gr":"Οἱ στρατιῶται ἐμάχοντο γενναίως.","an":"Κύριοι όροι: οἱ στρατιῶται (Υ) + ἐμάχοντο (κατηγόρημα). Το γενναίως είναι επιρρηματικός προσδιορισμός (δευτερεύων όρος), όχι κύριος."},{"gr":"Ἐνταῦθα ἔμειναν ἡμέρας τρεῖς.","an":"Ξεν. Ἀνάβ. (τύπου) — εννοούμενο Υ: (οἱ στρατιῶται / οἱ Ἕλληνες), κατηγόρημα: ἔμειναν. Τα ἐνταῦθα (τόπου) και ἡμέρας τρεῖς (χρόνου-διάρκειας) είναι δευτερεύοντες όροι/προσδιορισμοί."},{"gr":"Δαρείου καί Παρυσάτιδος γίγνονται παῖδες δύο.","an":"Ξεν. Ἀνάβ. 1.1.1 — κύριοι όροι: Υ = παῖδες δύο, κατηγόρημα = γίγνονται· τα Δαρείου καί Παρυσάτιδος είναι γενικές (προσδιορισμοί), δευτερεύοντες όροι."}],"note":"Προσοχή στη διάκριση: «κατηγόρημα» (το ρήμα μαζί με τους αναγκαίους συμπληρωματικούς όρους του) ≠ «κατηγορούμενο» (μία μόνο λέξη που αποδίδεται στο υποκείμενο μέσω συνδετικού ρήματος). Το κατηγορούμενο είναι μέρος του περιφραστικού κατηγορήματος, όχι συνώνυμό του."},{"h":"Το Υποκείμενο: ορισμός, πτώση και τρόπος εύρεσης","body":"<p><b>Υποκείμενο</b> είναι η λέξη (ή η φράση) για την οποία γίνεται λόγος στην πρόταση και η οποία <i>συμφωνεί</i> με το ρήμα στο πρόσωπο και τον αριθμό. Το υποκείμενο του ρήματος μπαίνει <b>πάντοτε στην ονομαστική πτώση</b>, όποιο κι αν είναι το πρόσωπο και ο αριθμός του ρήματος. Αυτός είναι ο πρώτος, χρυσός κανόνας του συντακτικού.</p><h3>Πώς βρίσκουμε το υποκείμενο</h3><ul><li>Αν το ρήμα είναι <b>α΄ ή β΄ προσώπου</b>, το υποκείμενο είναι η <i>προσωπική αντωνυμία</i> (ἐγώ, σύ, ἡμεῖς, ὑμεῖς), η οποία συνήθως <b>παραλείπεται</b>, γιατί φανερώνεται από την κατάληξη του ρήματος: <i>γράφω</i> → (ἐγώ), <i>γράφετε</i> → (ὑμεῖς).</li><li>Αν το ρήμα είναι <b>γ΄ προσώπου</b>, ρωτάμε <i>«ποιος; ποια; ποιο;»</i> (ή στον πληθυντικό <i>«ποιοι; ποιες; ποια;»</i>) πριν από το ρήμα· η απάντηση σε ονομαστική είναι το υποκείμενο.</li></ul><h3>Ποια μέρη του λόγου γίνονται υποκείμενο</h3><p>Υποκείμενο μπορεί να είναι οποιαδήποτε λέξη ή φράση λειτουργεί <i>ονοματικά</i> (έχει αξία ουσιαστικού):</p>","table":{"title":"Μέρη του λόγου ως υποκείμενο","cols":["Είδος","Παράδειγμα","Υποκείμενο"],"rows":[["Ουσιαστικό","Ὁ Φίλιππος γράφει.","ὁ Φίλιππος"],["Επίθετο (ουσιαστικοποιημένο)","Οἱ τελευταῖοι κατέβαινον.","οἱ τελευταῖοι"],["Αντωνυμία","Ἐγώ εἰμι.","ἐγώ"],["Αριθμητικό","Οἱ τριάκοντα ἦσαν.","οἱ τριάκοντα"],["Μετοχή έναρθρη","Οἱ ἐργαζόμενοι ἀφίκοντο.","οἱ ἐργαζόμενοι"],["Έναρθρο απαρέμφατο","Τό λακωνίζειν ἐστί φιλοσοφεῖν.","τό λακωνίζειν"],["Εμπρόθετος φράση","Οἱ ἐκ τῆς ἀγορᾶς ἔφυγον.","οἱ ἐκ τῆς ἀγορᾶς"],["Ολόκληρη πρόταση","Δῆλόν ἐστιν ὅτι ἥκουσιν.","ὅτι ἥκουσιν"]]},"examples":[{"gr":"Οἱ Ἀθηναῖοι ἐνίκησαν τούς Πέρσας.","an":"Ρήμα ἐνίκησαν (γ΄ πληθ.). Ρωτάμε «ποιοι ἐνίκησαν;» → οἱ Ἀθηναῖοι (ονομαστική) = Υ."},{"gr":"Τό γνῶθι σαυτόν πᾶσιν ὠφέλιμόν ἐστιν.","an":"Υ = τό γνῶθι σαυτόν (έναρθρη φράση με αξία ουσιαστικού, ονομαστική ουδετέρου)· κατηγορούμενο: ὠφέλιμον· συνδετικό: ἐστιν."},{"gr":"Ἔδοξεν αὐτοῖς πορεύεσθαι.","an":"Παράδειγμα όπου το υποκείμενο του απρόσωπου ἔδοξεν είναι ολόκληρο το απαρέμφατο πορεύεσθαι (= «το να πορευθούν φάνηκε καλό σ' αυτούς»)."},{"gr":"Οἱ τελευταῖοι κατέβαινον.","an":"Υ = οἱ τελευταῖοι (ουσιαστικοποιημένο επίθετο σε ονομαστική πληθ.)· ρωτάμε «ποιοι κατέβαινον;». Παράδειγμα επιθέτου σε θέση υποκειμένου."},{"gr":"Ξενοφῶν ἦν Ἀθηναῖος.","an":"Smyth (παράδειγμα συνδέσμου) — Υ = Ξενοφῶν (ουσιαστικό σε ονομαστική), συνδετικό ἦν, κατηγορούμενο Ἀθηναῖος (ονομαστική, συμφωνεί με το Υ)."}],"note":"Μην μπερδεύετε το υποκείμενο του ρήματος (πάντα ονομαστική) με το υποκείμενο του απαρεμφάτου ή της μετοχής, που μπορεί να είναι σε αιτιατική (ετεροπροσωπία) — π.χ. «νομίζω τούς πολεμίους φεύγειν». Αυτό αναπτύσσεται σε ξεχωριστό κεφάλαιο."},{"h":"Όταν το υποκείμενο λείπει: εννοούμενο / παραλειπόμενο υποκείμενο","body":"<p>Πολύ συχνά το υποκείμενο δεν εκφέρεται ρητά, αλλά <b>εννοείται</b>. Η αρχαία ελληνική, όπως και η νέα, είναι γλώσσα που επιτρέπει την παράλειψη του υποκειμένου (γλώσσα «pro-drop»), γιατί η κατάληξη του ρήματος φανερώνει πρόσωπο και αριθμό. Διακρίνουμε τις εξής βασικές περιπτώσεις:</p><ol><li><b>Ρήμα α΄ ή β΄ προσώπου:</b> εννοείται η αντίστοιχη προσωπική αντωνυμία. <i>«Λέγω»</i> → (ἐγώ)· <i>«πορεύεσθε»</i> → (ὑμεῖς). Όταν η αντωνυμία εκφέρεται, υπάρχει έμφαση ή αντιδιαστολή: <i>«ἐγώ μέν οὐκ οἶδα»</i>.</li><li><b>Σύστοιχο / ομόρριζο υποκείμενο:</b> με ορισμένα ρήματα το υποκείμενο εννοείται γιατί είναι ομόρριζο ή προφανές από το ίδιο το ρήμα. <i>«Ἐσάλπιγξε»</i> → εννοούμενο Υ: ὁ σαλπικτής· <i>«ἐκήρυξε»</i> → ὁ κῆρυξ.</li><li><b>Ρήματα «λέγουσι», «φασί», «οἴονται»:</b> γενικό-αόριστο υποκείμενο, εννοείται <i>ἄνθρωποι / οἱ ἄνθρωποι / πάντες</i> (= «λένε, λέει ο κόσμος»).</li><li><b>Από τα συμφραζόμενα:</b> σε περιόδους με πολλές προτάσεις, το υποκείμενο που έχει ήδη δηλωθεί δεν επαναλαμβάνεται. <i>«Ὁ Κῦρος συνέλεξε στράτευμα καί (ὁ Κῦρος) ἐπορεύετο.»</i></li><li><b>Φυσικά / μετεωρολογικά φαινόμενα:</b> εννοείται <i>θεός</i> ή <i>Ζεύς</i>. <i>«Ὕει»</i> (= βρέχει) → (ὁ Ζεύς / ὁ θεός)· <i>«ἀστράπτει», «βροντᾷ», «νείφει»</i>.</li></ol><p>Σε όλες αυτές τις περιπτώσεις το υποκείμενο, αν και αφανές, παραμένει σε <b>ονομαστική</b> και πρέπει στην ανάλυση να το αποκαθιστούμε μέσα σε παρένθεση.</p>","examples":[{"gr":"Ἐσάλπιγξε καί οἱ στρατιῶται ἐπορεύοντο.","an":"Στο ἐσάλπιγξε εννοούμενο Υ: (ὁ σαλπικτής) — σύστοιχο/ομόρριζο. Στο ἐπορεύοντο ρητό Υ: οἱ στρατιῶται."},{"gr":"Φασί τόν Σωκράτη σοφόν εἶναι.","an":"Στο φασί εννοούμενο Υ: (οἱ ἄνθρωποι / πάντες). Το τόν Σωκράτη είναι υποκείμενο του απαρεμφάτου εἶναι (ετεροπροσωπία, αιτιατική)."},{"gr":"Ἔνειφε πολλῇ χιόνι.","an":"Μετεωρολογικό· εννοούμενο Υ: (ὁ Ζεύς / ὁ θεός). Παράδειγμα παράλειψης σε φυσικό φαινόμενο."},{"gr":"Λέγουσιν ὡς οὐ καλῶς ἔπραξεν.","an":"Στο λέγουσιν εννοούμενο αόριστο Υ: (οἱ ἄνθρωποι). Ακολουθεί ειδική πρόταση ως αντικείμενο."},{"gr":"Ἐνταῦθα ἔμεινεν ἡμέρας ἑπτά.","an":"Ξεν. Ἀνάβ. (τύπου) — γ΄ ενικό ἔμεινεν με εννοούμενο Υ από τα συμφραζόμενα: (ὁ Κῦρος / ὁ στρατηγός). Παράδειγμα παράλειψης από το συγκείμενο."},{"gr":"Ἐγώ μέν οὐκ οἶδα.","an":"Ρήμα α΄ ενικού (οἶδα)· εδώ το ἐγώ εκφέρεται ρητά για έμφαση/αντιδιαστολή (μέν). Δείχνει ότι κανονικά θα παραλειπόταν."}],"note":"Το «εννοούμενο» δεν σημαίνει «ανύπαρκτο»: στη συντακτική ανάλυση γράφουμε πάντοτε ποιο είναι το παραλειπόμενο υποκείμενο, σε ονομαστική, μέσα σε παρένθεση."},{"h":"Συμφωνία υποκειμένου–ρήματος και η αττική σύνταξη","body":"<p>Κανονικά το ρήμα συμφωνεί με το υποκείμενο στο <b>πρόσωπο και τον αριθμό</b>. Στην αρχαία ελληνική όμως υπάρχουν σημαντικές ιδιαιτερότητες:</p><h3>1. Αττική σύνταξη (σχήμα Ἀττικόν)</h3><p>Όταν το υποκείμενο είναι <b>ουδέτερο πληθυντικού αριθμού</b>, το ρήμα μπαίνει κανονικά σε <b>ενικό αριθμό</b> (γ΄ ενικό). Η λογική είναι ότι τα ουδέτερα πληθυντικά νοούνται ως ένα συλλογικό σύνολο. Είναι από τους πιο χαρακτηριστικούς κανόνες του αττικού λόγου.</p><h3>2. Σχήμα κατά το νοούμενο</h3><p>Το ρήμα (ή τα συμφωνούντα στοιχεία) συμφωνεί όχι με τον γραμματικό τύπο αλλά με το <i>νόημα</i> του υποκειμένου: περιληπτικό υποκείμενο ενικού + ρήμα πληθυντικού, όταν εννοούνται πολλά πρόσωπα.</p><h3>3. Σχήμα κατά το σύνηθες (σχηματισμός προς το ισχυρότερο πρόσωπο)</h3><p>Σε πολλαπλό υποκείμενο διαφορετικών προσώπων, το ρήμα παίρνει το <i>ισχυρότερο</i> πρόσωπο: το α΄ υπερισχύει του β΄, και το β΄ του γ΄.</p>","table":{"title":"Ειδικά σχήματα συμφωνίας","cols":["Σχήμα","Κανόνας","Παράδειγμα"],"rows":[["Αττική σύνταξη","ουδέτερο πληθ. Υ → ρήμα ενικού","τά ζῷα τρέχει"],["Κατά το νοούμενο","τύπος ενικός / νόημα πληθυντικό → ρήμα πληθ.","τό πλῆθος ἐψηφίσαντο"],["Προς το ισχυρότερο πρόσωπο","α΄ > β΄ > γ΄","ἐγώ καί σύ ἐρχόμεθα"],["Σχήμα Πινδαρικό/κατά το σχῆμα","πληθ. Υ + ρήμα ενικού (έμφαση στο πλησιέστερο)","ἦν δ' αὐτῷ δύο ἀδελφοί"]]},"examples":[{"gr":"Τά ζῷα τρέχει.","an":"Υ ουδέτερο πληθυντικού (τά ζῷα), ρήμα όμως σε ενικό (τρέχει) — η κατεξοχήν εφαρμογή της αττικής σύνταξης. Μεταφράζεται κανονικά: «τα ζώα τρέχουν»."},{"gr":"Καλά τά τῆς πόλεως πράγματά ἐστιν.","an":"Ουδέτερο πληθ. Υ (τά πράγματα) με ρήμα σε ενικό (ἐστιν)· κατηγορούμενο σε πληθ. ουδέτερο (καλά). Πλήρης εικόνα της αττικής σύνταξης."},{"gr":"Τό στρατόπεδον ἐπαύσαντο τῆς πορείας.","an":"Σχήμα κατά το νοούμενο: το περιληπτικό τό στρατόπεδον (ενικός) συντάσσεται με ρήμα πληθυντικού (ἐπαύσαντο), γιατί νοούνται πολλοί στρατιώτες."},{"gr":"Ὑμεῖς καί ἡμεῖς ὁμολογοῦμεν.","an":"Πολλαπλό Υ β΄ + α΄ προσώπου → ρήμα α΄ πληθ. (ὁμολογοῦμεν), γιατί το α΄ πρόσωπο υπερισχύει."},{"gr":"Φανερά ἦν καί ἵππων καί ἀνθρώπων ἴχνη πολλά.","an":"Smyth (Ξεν. Ἀνάβ. 1.7.17 τύπου) — εδώ το ουδέτερο πληθ. Υ ἴχνη δηλώνει πολλά ξεχωριστά αντικείμενα, γι' αυτό το συμφωνούν στοιχείο τίθεται πληθυντικά· η εξαίρεση της αττικής σύνταξης."},{"gr":"Τά τέλη τῶν Λακεδαιμονίων αὐτόν ἐξέπεμψαν.","an":"Smyth (Θουκ. τύπου) — ουδέτερο πληθ. Υ (τά τέλη = οι άρχοντες) με ρήμα πληθυντικού (ἐξέπεμψαν), επειδή νοούνται πρόσωπα· σχήμα κατά το νοούμενο, εξαίρεση στην αττική σύνταξη."}],"note":"Η αττική σύνταξη ΔΕΝ εφαρμόζεται υποχρεωτικά όταν το ουδέτερο πληθυντικό δηλώνει χωριστά, ξεχωριστά έμψυχα όντα ή πρόσωπα· τότε συναντάμε και ρήμα πληθυντικού. Είναι ο πιο συχνός «τραπ» στις εξετάσεις."},{"h":"Το Κατηγόρημα: μονολεκτικό και περιφραστικό","body":"<p><b>Κατηγόρημα</b> είναι ό,τι λέμε (κατηγορούμε) για το υποκείμενο. Πυρήνας του είναι το ρήμα. Ανάλογα με το αν το ρήμα αρκεί μόνο του ή χρειάζεται συμπληρώματα, το κατηγόρημα διακρίνεται σε δύο μεγάλες κατηγορίες:</p><h3>Α. Μονολεκτικό κατηγόρημα</h3><p>Αποτελείται από <b>ένα ρήμα μόνο</b>, το οποίο έχει πλήρη, αυτοτελή σημασία και δεν χρειάζεται συμπλήρωμα. Πρόκειται για <i>αμετάβατα</i> κυρίως ρήματα. <i>«Ὁ στρατηγός εἶπε.»</i> — το εἶπε φτάνει.</p><h3>Β. Περιφραστικό κατηγόρημα</h3><p>Αποτελείται από <b>ρήμα + μία ή περισσότερες λέξεις</b> που είναι αναγκαίες για να ολοκληρωθεί το νόημα. Το ρήμα από μόνο του δεν αρκεί. Διακρίνουμε <b>τέσσερις τύπους</b> περιφραστικού κατηγορήματος:</p><ol><li><b>Μεταβατικό ρήμα + αντικείμενο</b> (μονόπτωτο): <i>«γράφει ἐπιστολήν»</i>.</li><li><b>Μεταβατικό ρήμα + δύο αντικείμενα</b> (δίπτωτο): <i>«διδάσκει τούς παῖδας μουσικήν»</i>.</li><li><b>Συνδετικό ρήμα + κατηγορούμενο του υποκειμένου</b>: <i>«ὁ Σωκράτης ἐστί σοφός»</i>.</li><li><b>Μεταβατικό ρήμα + αντικείμενο + κατηγορούμενο του αντικειμένου</b>: <i>«εἵλοντο αὐτόν στρατηγόν»</i>.</li></ol><p>Στο μονολεκτικό κατηγόρημα το ρήμα φέρει όλο το βάρος του νοήματος· στο περιφραστικό μοιράζεται με τους συμπληρωματικούς όρους.</p>","table":{"title":"Οι τύποι του κατηγορήματος","cols":["Τύπος","Δομή","Παράδειγμα"],"rows":[["Μονολεκτικό","ρήμα αυτοτελές","Ὁ παῖς τρέχει."],["Περιφραστικό 1","μεταβ. ρ. + αντικείμενο","Λύει τόν ἵππον."],["Περιφραστικό 2","μεταβ. ρ. + δύο αντικείμενα","Διδάσκει τούς νέους τήν ἀρετήν."],["Περιφραστικό 3","συνδετικό ρ. + κατηγορούμενο Υ","Ὁ Κῦρος ἦν βασιλεύς."],["Περιφραστικό 4","μεταβ. ρ. + αντικ. + κατηγ. αντικ.","Ἀπέδειξαν αὐτόν δικαστήν."]]},"examples":[{"gr":"Οἱ πολῖται ἐβόησαν.","an":"Μονολεκτικό κατηγόρημα: ἐβόησαν (αμετάβατο, πλήρες νόημα). Δεν χρειάζεται συμπλήρωμα."},{"gr":"Ὁ Δημοσθένης ἔγραψε λόγον.","an":"Περιφραστικό τύπου 1: μεταβατικό ρ. ἔγραψε + άμεσο αντικείμενο λόγον (αιτιατική)."},{"gr":"Ἐνέδυσαν τόν παῖδα χιτῶνα.","an":"Περιφραστικό τύπου 2: δίπτωτο ρήμα ἐνέδυσαν + δύο αντικείμενα (τόν παῖδα, χιτῶνα)."},{"gr":"Ἡγοῦντο τόν Κῦρον ἄριστον.","an":"Περιφραστικό τύπου 4: ρ. ἡγοῦντο + αντικείμενο τόν Κῦρον + κατηγορούμενο του αντικειμένου ἄριστον."},{"gr":"Κῦρος συλλέγει στράτευμα.","an":"Ξεν. Ἀνάβ. (τύπου) — περιφραστικό τύπου 1: μεταβατικό ρ. συλλέγει + αντικείμενο στράτευμα (αιτιατική). Πυρήνας: το ρήμα μοιράζεται το νόημα με το αντικείμενο."},{"gr":"Οἱ Ἕλληνες ἐδίδασκον τούς παῖδας γράμματα.","an":"Περιφραστικό τύπου 2 (δίπτωτο): ρ. ἐδίδασκον + δύο αντικείμενα, το πρόσωπο (τούς παῖδας) και το πράγμα (γράμματα), αμφότερα σε αιτιατική."}],"note":"Διάκριση-κλειδί: στον τύπο 3 το ρήμα είναι συνδετικό και η συμπληρωματική λέξη μπαίνει σε ΟΝΟΜΑΣΤΙΚΗ (κατηγορούμενο του υποκειμένου). Στους τύπους 1, 2, 4 η συμπληρωματική λέξη-αντικείμενο μπαίνει σε πλάγια πτώση (συνήθως αιτιατική)."},{"h":"Συνδετικά ρήματα και κατηγορούμενο του υποκειμένου","body":"<p><b>Συνδετικά</b> (ή <i>συνδετικά / κατηγορηματικά</i>) λέγονται τα ρήματα που από μόνα τους έχουν <i>ατελή, αμυδρή</i> σημασία και χρειάζονται μια άλλη λέξη — το <b>κατηγορούμενο</b> — για να ολοκληρώσουν το νόημά τους. Δεν δείχνουν ενέργεια αλλά απλώς <i>συνδέουν</i> το υποκείμενο με μια ιδιότητα, κατάσταση ή χαρακτηρισμό. Γι' αυτό δεν παίρνουν αντικείμενο αλλά <b>κατηγορούμενο</b>.</p><h3>Το κατηγορούμενο του υποκειμένου</h3><p>Το <b>κατηγορούμενο</b> είναι η λέξη που, μέσω του συνδετικού ρήματος, αποδίδεται στο υποκείμενο ως ιδιότητα/χαρακτηρισμός. Μπαίνει σε <b>ονομαστική</b> πτώση και <i>συμφωνεί</i> με το υποκείμενο κατά το γένος, τον αριθμό (και, αν είναι ουσιαστικό, στην πτώση): <i>«ὁ Σωκράτης ἐστί σοφός»</i> (σοφός: αρσ., εν., ονομ., όπως ο Σωκράτης).</p><h3>Κατηγορίες συνδετικών ρημάτων</h3><p>Τα συνδετικά ρήματα παραδοσιακά ταξινομούνται ως εξής:</p>","table":{"title":"Τα συνδετικά (κατηγορηματικά) ρήματα","cols":["Κατηγορία","Ρήματα","Σημασία"],"rows":[["Υπαρκτικά / του «είναι»","εἰμί, ὑπάρχω, πέλω","είμαι, υπάρχω"],["Γίγνεσθαι / μεταβολής","γίγνομαι, φύομαι (πέφυκα, ἔφυν)","γίνομαι, είμαι από τη φύση"],["Φαίνεσθαι / δοκείν","φαίνομαι, δοκῶ, ἔοικα","φαίνομαι, μοιάζω"],["Κλήσεως / ονομασίας","καλοῦμαι, ὀνομάζομαι, λέγομαι, ἀκούω","ονομάζομαι, αποκαλούμαι"],["Εκλογής / ανάδειξης (παθ.)","αἱροῦμαι, χειροτονοῦμαι, ἀποδείκνυμαι","εκλέγομαι, αναδεικνύομαι"],["Νομίζεσθαι / κρίσεως (παθ.)","νομίζομαι, κρίνομαι, ἡγοῦμαι (παθ.)","θεωρούμαι, κρίνομαι"]]},"examples":[{"gr":"Ὁ Κῦρος ἦν βασιλεύς.","an":"Συνδετικό ρ. ἦν + κατηγορούμενο βασιλεύς (ονομαστική, αρσ. εν., συμφωνεί με το Υ ὁ Κῦρος)."},{"gr":"Οἱ στρατιῶται ἐγένοντο ἀνδρεῖοι.","an":"Συνδετικό γίγνομαι (ἐγένοντο) + κατηγ. ἀνδρεῖοι (ονομ. πληθ.). Δηλώνει μεταβολή/κατάσταση."},{"gr":"Σωκράτης σοφός ἐνομίζετο.","an":"Παθητικό συνδετικό ἐνομίζετο (= θεωρούνταν) + κατηγορούμενο σοφός. Το ρήμα κρίσεως γίνεται συνδετικό στην παθητική."},{"gr":"Οὗτος ὁ ποταμός καλεῖται Εὐφράτης.","an":"Ρήμα κλήσεως καλεῖται + κατηγ. Εὐφράτης (ονομαστική). Στην ενεργητική («καλοῦσι τοῦτον Εὐφράτην») θα είχαμε κατηγ. του αντικειμένου σε αιτιατική."},{"gr":"Ξενοφῶν ἦν Ἀθηναῖος.","an":"Smyth (παράδειγμα copula) — συνδετικό ἦν + κατηγορούμενο Ἀθηναῖος (ονομ. αρσ. εν., συμφωνεί με το Υ Ξενοφῶν). Πρότυπο της σύνδεσης Υ–ιδιότητας."},{"gr":"Δίκαιος ὁ Ἀριστείδης ἐκαλεῖτο.","an":"Ρήμα κλήσεως (ἐκαλεῖτο) ως συνδετικό + κατηγορούμενο δίκαιος (ονομαστική). Δηλώνει χαρακτηρισμό που αποδίδεται στο Υ."}],"note":"Ένα ρήμα δεν είναι «εκ φύσεως» συνδετικό ή μη: είναι συνδετικό ΟΤΑΝ συνδέει το Υ με κατηγορούμενο. Το «εἰμί» μπορεί να είναι και υπαρκτικό-αυτοτελές (= υπάρχω): «ἔστι θεός» = υπάρχει θεός (τότε δίνει μονολεκτικό κατηγόρημα, χωρίς κατηγορούμενο). Επίσης τα γίγνομαι, μένω κ.ά. άλλοτε είναι συνδετικά κι άλλοτε αμετάβατα με πλήρη σημασία."},{"h":"Είδη προτάσεων ως προς τη δομή: απλή – σύνθετη – ελλειπτική – επαυξημένη","body":"<p>Με κριτήριο τους <b>όρους</b> που περιέχουν και τη <b>δομή</b> τους, οι προτάσεις διακρίνονται σε τέσσερα είδη. Η διάκριση αυτή είναι ανεξάρτητη από το αν η πρόταση είναι κύρια ή δευτερεύουσα.</p><h3>1. Απλή πρόταση</h3><p>Αποτελείται <b>μόνο από τους κύριους όρους</b> — υποκείμενο και κατηγόρημα (με τα τυχόν αναγκαία αντικείμενα/κατηγορούμενα του πυρήνα), χωρίς προσδιορισμούς. <i>«Ὁ παῖς γράφει.»</i></p><h3>2. Επαυξημένη πρόταση</h3><p>Είναι η απλή πρόταση που έχει <b>επαυξηθεί με προσδιορισμούς</b> — ονοματικούς (επιθετικός, κατηγορηματικός, παράθεση, επεξήγηση, γενική) ή επιρρηματικούς (τόπου, χρόνου, τρόπου κ.ά.). <i>«Ὁ ἐπιμελής παῖς καλῶς γράφει τήν ἐπιστολήν.»</i></p><h3>3. Σύνθετη πρόταση</h3><p>Έχει <b>περισσότερους από έναν</b> όμοιους κύριους όρους — δύο ή περισσότερα υποκείμενα, ή κατηγορούμενα, ή αντικείμενα — που είναι <i>ομοιόπτωτα</i> και συνδέονται παρατακτικά (με σύνδεσμο) ή χωρίζονται με κόμμα. <i>«Ὁ Σωκράτης καί ὁ Πλάτων ἦσαν φιλόσοφοι.»</i></p><h3>4. Ελλειπτική πρόταση</h3><p>Είναι η πρόταση από την οποία <b>παραλείπεται ένας ή περισσότεροι όροι</b> (συχνά το ρήμα ή το υποκείμενο), επειδή εύκολα εννοούνται από τα συμφραζόμενα ή από την κοινή γλωσσική πείρα. Είναι πολύ συχνή σε παροιμίες, αποφθέγματα, επιγραφές, απαντήσεις. <i>«Οὐδέν ἄγαν.»</i> (ενν. χρή ποιεῖν / πρᾶττε)</p>","table":{"title":"Τα είδη προτάσεων ως προς τη δομή","cols":["Είδος","Κριτήριο","Παράδειγμα"],"rows":[["Απλή","μόνο κύριοι όροι","Ὁ ἥλιος λάμπει."],["Επαυξημένη","κύριοι όροι + προσδιορισμοί","Ὁ λαμπρός ἥλιος ἄνω λάμπει."],["Σύνθετη","πολλαπλοί όμοιοι όροι","Ὁ ἥλιος καί ἡ σελήνη λάμπουσιν."],["Ελλειπτική","παράλειψη όρου","Καλός (ἐστίν) ὁ λόγος."]]},"examples":[{"gr":"Ὁ Κῦρος ἐβασίλευσεν.","an":"Απλή: μόνο Υ (ὁ Κῦρος) + κατηγόρημα (ἐβασίλευσεν), χωρίς προσδιορισμό."},{"gr":"Ὁ νέος Κῦρος ταχέως ἐβασίλευσεν τῶν Περσῶν.","an":"Επαυξημένη: προστέθηκαν ο επιθετικός νέος, το επίρρημα ταχέως και η γενική τῶν Περσῶν (προσδιορισμοί)."},{"gr":"Φίλιππος καί Ἀλέξανδρος καί Ἀντίπατρος ἐστράτευσαν.","an":"Σύνθετη: τρία ομοιόπτωτα υποκείμενα σε ονομαστική, συνδεδεμένα παρατακτικά με καί + ρήμα στον πληθυντικό."},{"gr":"Γνῶθι σαυτόν.","an":"Ελλειπτική ως προς το υποκείμενο (εννοείται σύ)· γνωμικό. Σε «Μηδέν ἄγαν» λείπει και το ρήμα."},{"gr":"Μηδέν ἄγαν.","an":"Δελφικό απόφθεγμα — ελλειπτική: λείπει και το ρήμα (ενν. πρᾶττε / χρή ποιεῖν) και το υποκείμενο (ενν. σύ). Τυπική ελλειπτική γνωμική πρόταση."},{"gr":"Πρεσβύτερος μέν Ἀρταξέρξης, νεώτερος δέ Κῦρος.","an":"Ξεν. Ἀνάβ. 1.1.1 — δύο ελλειπτικές προτάσεις: σε καθεμία λείπει το συνδετικό ρήμα (ενν. ἦν)· πρόκειται για κατηγορούμενα (πρεσβύτερος, νεώτερος) με τα υποκείμενά τους."}],"note":"Τα τέσσερα είδη ΔΕΝ αλληλοαποκλείονται απόλυτα: μια πρόταση μπορεί να είναι ταυτόχρονα σύνθετη και επαυξημένη («οἱ ἀνδρεῖοι στρατιῶται καί οἱ σοφοί στρατηγοί γενναίως ἐμάχοντο»). Κρίνουμε με βάση το κυρίαρχο χαρακτηριστικό που μας ζητείται."},{"h":"Άλλες ταξινομήσεις των προτάσεων (συμπληρωματικός χάρτης)","body":"<p>Για να είναι πλήρης η εικόνα, οι προτάσεις ταξινομούνται και με άλλα κριτήρια, που συχνά ζητούνται μαζί με τη δομή.</p><h3>1. Ως προς το περιεχόμενο</h3><ul><li><b>Προτάσεις κρίσεως:</b> εκφράζουν κρίση, σκέψη, πληροφορία· δέχονται άρνηση <b>οὐ</b>. <i>«Ὁ Σωκράτης σοφός ἐστιν.»</i></li><li><b>Προτάσεις επιθυμίας:</b> εκφράζουν ευχή, προτροπή, προσταγή, παράκληση· δέχονται άρνηση <b>μή</b>. <i>«Μή ἀδίκει.»</i></li><li><b>Επιφωνηματικές:</b> εκφράζουν έντονο συναίσθημα (θαυμασμό, έκπληξη). <i>«Ὡς καλός ὁ παῖς!»</i></li><li><b>Ερωτηματικές:</b> διατυπώνουν ερώτηση. <i>«Τίς εἶ;»</i></li></ul><h3>2. Ως προς το ποιόν (την άρνηση)</h3><ul><li><b>Καταφατικές:</b> χωρίς άρνηση.</li><li><b>Αποφατικές (αρνητικές):</b> με άρνηση οὐ / οὐκ / οὐχ ή μή.</li></ul><h3>3. Ως προς τη σχέση με άλλες προτάσεις</h3><ul><li><b>Κύριες / ανεξάρτητες:</b> εκφράζουν αυτοτελές νόημα, στέκονται μόνες τους.</li><li><b>Δευτερεύουσες / εξαρτημένες:</b> προσδιορίζουν / συμπληρώνουν άλλη πρόταση, από την οποία εξαρτώνται· εισάγονται με σύνδεσμο ή αναφορική/ερωτηματική λέξη.</li></ul><p>Η σχέση οὐ/μή με τις προτάσεις κρίσεως/επιθυμίας είναι από τα πιο εξεταζόμενα σημεία: η επιλογή της άρνησης φανερώνει το είδος της πρότασης.</p>","table":{"title":"Συγκεντρωτικός πίνακας ταξινομήσεων","cols":["Κριτήριο","Είδη","Διακριτικό"],"rows":[["Περιεχόμενο","κρίσεως / επιθυμίας / επιφωνηματικές / ερωτηματικές","άρνηση οὐ vs μή· στίξη"],["Ποιόν","καταφατικές / αποφατικές","παρουσία άρνησης"],["Σχέση","κύριες / δευτερεύουσες","αυτοτέλεια vs εξάρτηση"],["Δομή/όροι","απλές / επαυξημένες / σύνθετες / ελλειπτικές","αριθμός & είδος όρων"]]},"examples":[{"gr":"Οὐκ οἶδα τήν ἀλήθειαν.","an":"Πρόταση κρίσεως (πληροφορία), αποφατική (οὐκ), κύρια. Άρνηση οὐ → κρίση."},{"gr":"Μή θορυβεῖτε, ὦ ἄνδρες.","an":"Πρόταση επιθυμίας (προσταγή/παράκληση), αποφατική (μή). Η άρνηση μή φανερώνει επιθυμία."},{"gr":"Ὅτε ὁ Κῦρος ἦλθεν, οἱ στρατιῶται ἐχάρησαν.","an":"Δύο προτάσεις: «ὅτε... ἦλθεν» δευτερεύουσα χρονική (εξαρτημένη)· «οἱ στρατιῶται ἐχάρησαν» κύρια/ανεξάρτητη."},{"gr":"Ὦ τῆς ἀναιδείας!","an":"Επιφωνηματική πρόταση (έντονο συναίσθημα, αγανάκτηση), ελλειπτική (λείπει το ρήμα)· γενική επιφωνηματική."},{"gr":"Τίς εἶ καί πόθεν ἥκεις;","an":"Ερωτηματικές προτάσεις (ευθεία ερώτηση)· κύριες. Διακριτικό: το ερωτηματικό σημείο και οι ερωτηματικές λέξεις (τίς, πόθεν)."},{"gr":"Μή ἀδίκει τούς φίλους.","an":"Πρόταση επιθυμίας (απαγόρευση), αποφατική (μή), κύρια· ως προς τη δομή απλή & ελλειπτική (ενν. Υ σύ). Η άρνηση μή φανερώνει το είδος (επιθυμίας, όχι κρίσεως)."}],"note":"Μια ίδια πρόταση κατατάσσεται ταυτόχρονα και στις τέσσερις διαστάσεις. Π.χ. το «Μή ἀδίκει» είναι: ως προς το περιεχόμενο επιθυμίας, ως προς το ποιόν αποφατική, ως προς τη σχέση κύρια, ως προς τη δομή απλή & ελλειπτική (εννοείται το σύ)."}]);
  T("syn-eidi-protaseon", [{"h":"Πρόταση, περίοδος, ημιπερίοδος: οι θεμελιώδεις μονάδες του λόγου","body":"<p><b>Πρόταση</b> ονομάζουμε το συντομότερο τμήμα του λόγου που εκφράζει ένα <i>αυτοτελές νόημα</i> — μια κρίση, μια επιθυμία, ένα συναίσθημα ή μια ερώτηση. Πυρήνας κάθε πρότασης είναι το <b>ρήμα</b> (ή το ρηματικό κατηγόρημα): όπου υπάρχει ένα ρήμα σε προσωπική έγκλιση, εκεί υπάρχει και μία πρόταση. Γι' αυτό, ο πρώτος κανόνας της συντακτικής ανάλυσης είναι: <i>μετράμε τα ρήματα — τόσες προτάσεις, όσα τα ρήματα</i>.</p><p>Η πρόταση δεν ταυτίζεται πάντα με μία ολοκληρωμένη φράση. Πολλές προτάσεις μαζί, οργανωμένες γύρω από ισχυρά σημεία στίξης, συγκροτούν μεγαλύτερες ενότητες:</p><h3>Περίοδος</h3><p><b>Περίοδος</b> είναι το τμήμα του λόγου που αποτελείται από μία ή περισσότερες προτάσεις και εκφράζει <i>αυτοτελές και ολοκληρωμένο</i> νόημα. Αρχίζει και τελειώνει σε <b>ισχυρό σημείο στίξης</b> (τελεία, ερωτηματικό, θαυμαστικό). Η περίοδος είναι η φυσική «πρόταση» του γραπτού λόγου με τη νεοελληνική έννοια.</p><h3>Ημιπερίοδος (κώλον περιόδου)</h3><p><b>Ημιπερίοδος</b> ή <b>κώλον περιόδου</b> είναι το τμήμα του λόγου που εκφράζει νόημα <i>αυτοτελές μεν αλλά όχι ολοκληρωμένο</i>· τελειώνει σε <b>άνω τελεία</b>. Δύο ή περισσότερες ημιπερίοδοι συμπληρώνει η μία το νόημα της άλλης, ώσπου να κλείσει ολόκληρη η περίοδος σε ισχυρή στίξη.</p><p>Έτσι, η ιεραρχία είναι: <b>πρόταση → ημιπερίοδος → περίοδος</b>. Μέσα σε κάθε περίοδο ή ημιπερίοδο πρέπει υποχρεωτικά να υπάρχει <i>τουλάχιστον μία κύρια πρόταση</i>.</p>","examples":[{"gr":"Παλαιότατοι οὗτοι οἱ νόμοι εἰσίν.","an":"Αυτοί οι νόμοι είναι παλαιότατοι. — Μία πρόταση = μία περίοδος (ένα ρήμα, εἰσίν· κλείνει σε τελεία)."},{"gr":"Ἐπεί δ' ἦλθον οἱ κήρυκες, ἐζήτουν τούς ἄρχοντας.","an":"Όταν ήρθαν οι κήρυκες, αναζητούσαν τους άρχοντες. — Μία περίοδος με δύο προτάσεις: μία δευτερεύουσα (Ἐπεί… ἦλθον) και μία κύρια (ἐζήτουν…)."},{"gr":"Οἱ μέν στρατιῶται ἔμενον· οἱ δέ στρατηγοί ἐβουλεύοντο.","an":"Οι στρατιώτες περίμεναν· οι στρατηγοί συσκέπτονταν. — Δύο ημιπερίοδοι (η πρώτη κλείνει σε άνω τελεία) που συγκροτούν μία περίοδο."},{"gr":"Ἐνταῦθα ἔμεινεν ἡμέρας ἑπτά.","an":"(τύπου Ξεν. Ἀνάβ.) Εκεί έμεινε εφτά μέρες. — Μία πρόταση = μία περίοδος· ένα ρήμα (ἔμεινεν), κλείνει σε τελεία."},{"gr":"Δαρείου καί Παρυσάτιδος γίγνονται παῖδες δύο, πρεσβύτερος μέν Ἀρταξέρξης, νεώτερος δέ Κῦρος.","an":"Ξεν. Ἀνάβ. 1.1.1 — Από τον Δαρείο και την Παρύσατι γεννιούνται δύο παιδιά, ο πρεσβύτερος ο Ἀρταξέρξης, ο νεότερος ο Κῦρος. — Μία περίοδος με ένα ρήμα προσωπικής έγκλισης (γίγνονται)· οι επεξηγήσεις δεν προσθέτουν προτάσεις."},{"gr":"Οἱ μέν ἔφευγον, οἱ δέ ἐδίωκον· τέλος δ' οἱ πολέμιοι ἐνίκησαν.","an":"Άλλοι έφευγαν, άλλοι κατεδίωκαν· στο τέλος νίκησαν οι εχθροί. — Τρεις προτάσεις σε δύο ημιπερίοδους (άνω τελεία) και μία περίοδο."}],"note":"Προσοχή: η μετοχή και το απαρέμφατο ΔΕΝ σχηματίζουν αυτοτελή πρόταση, γιατί δεν είναι ρήματα προσωπικής έγκλισης. Είναι ρηματικοί τύποι που μετέχουν στη δομή μιας πρότασης (συχνά ισοδυναμούν με δευτερεύουσα — «μετοχή/απαρέμφατο αντί δευτερεύουσας»), αλλά δεν αυξάνουν τον αριθμό των προτάσεων κατά την καταμέτρηση."},{"h":"Πανοραμική ταξινόμηση: τα τέσσερα κριτήρια διαίρεσης","body":"<p>Η ίδια πρόταση μπορεί να καταταχθεί ταυτόχρονα και από τις τέσσερις σκοπιές — δεν πρόκειται για αποκλειστικές κατηγορίες αλλά για <i>τέσσερα διαφορετικά κριτήρια</i> που εφαρμόζονται συμπληρωματικά. Έτσι, μία και η αυτή πρόταση μπορεί π.χ. να είναι «κρίσεως, καταφατική, κύρια και επαυξημένη».</p><h3>Τα τέσσερα κριτήρια</h3><ul><li><b>Ως προς το περιεχόμενο</b> (τι εκφράζουν): προτάσεις <i>κρίσεως</i>, <i>επιθυμίας</i>, <i>επιφωνηματικές</i>, <i>ερωτηματικές</i>.</li><li><b>Ως προς το ποιόν / τη μορφή</b> (αν περιέχουν άρνηση): <i>καταφατικές</i> και <i>αποφατικές (αρνητικές)</i> — με τον θεμελιώδη κανόνα <i>οὐ</i> έναντι <i>μή</i>.</li><li><b>Ως προς τη σχέση τους με άλλες προτάσεις</b> (αν στέκονται μόνες): <i>κύριες / ανεξάρτητες</i> και <i>δευτερεύουσες / εξαρτημένες</i>.</li><li><b>Ως προς τους όρους τους</b> (από πόσα και ποια μέρη απαρτίζονται): <i>απλές</i>, <i>σύνθετες</i>, <i>ελλειπτικές</i>, <i>επαυξημένες</i>.</li></ul><p>Στη σωστή συντακτική ανάλυση δηλώνουμε, όταν ζητείται πλήρης χαρακτηρισμός, και τα τέσσερα γνωρίσματα. Στις επόμενες ενότητες αναπτύσσεται καθένα ξεχωριστά, με έμφαση στην <b>εισαγωγή</b> (με ποια λέξη μπαίνει η πρόταση) και την <b>εκφορά</b> (με ποια έγκλιση εκφέρεται το ρήμα της), που είναι οι δύο όροι-κλειδιά κάθε εξεταστικής απάντησης.</p>","table":{"title":"Συνοπτικός πίνακας των τεσσάρων διαιρέσεων","cols":["Κριτήριο","Είδη","Διακριτικό γνώρισμα"],"rows":[["Περιεχόμενο","κρίσεως / επιθυμίας / επιφωνηματικές / ερωτηματικές","τι εκφράζουν (σκέψη, θέληση, συναίσθημα, ερώτηση)"],["Ποιόν (μορφή)","καταφατικές / αποφατικές","παρουσία ή απουσία άρνησης (οὐ ή μή)"],["Σχέση","κύριες (ανεξάρτητες) / δευτερεύουσες (εξαρτημένες)","αν στέκονται νοηματικά μόνες"],["Όροι","απλές / σύνθετες / ελλειπτικές / επαυξημένες","πλήθος και είδος των όρων"]]},"note":"Μην συγχέεις τα κριτήρια. «Καταφατική/αρνητική» αφορά ΜΟΝΟ την άρνηση, όχι το αν η πρόταση είναι κρίσεως ή επιθυμίας. «Κύρια/δευτερεύουσα» αφορά ΜΟΝΟ τη σχέση εξάρτησης, όχι το περιεχόμενο. Μια αρνητική πρόταση δεν είναι αυτομάτως «κρίσεως»."},{"h":"Ως προς το περιεχόμενο Α: Προτάσεις κρίσεως","body":"<p><b>Προτάσεις κρίσεως</b> (ή <i>αποφαντικές</i>) είναι όσες εκφράζουν μια <b>κρίση, μια σκέψη, μια πληροφορία, μια διαπίστωση ή έναν ισχυρισμό</b> — δηλαδή κάτι που ο ομιλητής παρουσιάζει ως αληθές ή πραγματικό (ή ως δυνατό/πιθανό). Είναι το συνηθέστερο είδος πρότασης σε αφηγηματικό και αποδεικτικό λόγο.</p><h3>Εκφορά (έγκλιση)</h3><p>Οι προτάσεις κρίσεως εκφέρονται με τις εγκλίσεις που δηλώνουν το πραγματικό ή το δυνατό:</p><ul><li><b>Οριστική</b> (απλή): δηλώνει το <i>πραγματικό, το βέβαιο</i>. <i>π.χ. γράφει, ἔγραψεν.</i></li><li><b>Δυνητική οριστική</b> (οριστική ιστορικού χρόνου + <b>ἄν</b>): δηλώνει το <i>δυνατό στο παρελθόν</i> ή το μη πραγματικό (αντίθετο του πραγματικού). <i>π.χ. ἔγραψεν ἄν = θα έγραφε.</i></li><li><b>Δυνητική ευκτική</b> (ευκτική + <b>ἄν</b>): δηλώνει το <i>δυνατό στο παρόν ή στο μέλλον</i> και την πιθανότητα. <i>π.χ. γράψειεν ἄν = θα μπορούσε να γράψει.</i></li></ul><h3>Άρνηση</h3><p>Η άρνηση των προτάσεων κρίσεως είναι πάντοτε <b>οὐ</b> (με τους τύπους <i>οὐκ</i> προ φωνήεντος ψιλούμενου, <i>οὐχ</i> προ δασυνομένου): <i>οὐ γράφει, οὐκ ἔγραψεν, οὐχ ὁρῶμεν</i>.</p>","examples":[{"gr":"Παλαιότατοι οὗτοι οἱ νόμοι εἰσίν.","an":"Αυτοί οι νόμοι είναι παλαιότατοι. — Κρίσεως, καταφατική· εκφορά: οριστική (πραγματικό)."},{"gr":"Οὐ παύσομαι φιλοσοφῶν.","an":"Δεν θα πάψω να φιλοσοφώ. — Κρίσεως, αρνητική (άρνηση οὐ)· εκφορά: οριστική μέλλοντα."},{"gr":"Ταῦτα οὐκ ἄν ἐγένετο.","an":"Αυτά δεν θα είχαν συμβεί. — Κρίσεως, αρνητική· εκφορά: δυνητική οριστική (μη πραγματικό στο παρελθόν, οριστική + ἄν)."},{"gr":"Ῥᾳδίως ἄν τοῦτο μάθοις.","an":"Εύκολα θα μπορούσες να το μάθεις αυτό. — Κρίσεως, καταφατική· εκφορά: δυνητική ευκτική (δυνατό στο παρόν/μέλλον, ευκτική + ἄν)."},{"gr":"Νομίζω γάρ ὑμᾶς ἐμοί εἶναι καί πατρίδα καί φίλους.","an":"Ξεν. Ἀνάβ. 1.3.6 — Γιατί θεωρώ εσάς και πατρίδα και φίλους μου. — Κρίσεως, καταφατική· εκφορά: οριστική (δηλώνει σκέψη/κρίση)."},{"gr":"Οὐκ ἔστι ταῦτα.","an":"Δεν είναι έτσι αυτά. — Κρίσεως, αρνητική (άρνηση οὐκ)· εκφορά: οριστική (διαπίστωση)."},{"gr":"Οὐκ ἄν δικαίως ἐς ἀκληρίαν τήν ἐμήν ἀναμένοιτε.","an":"(τύπου ρητορικού λόγου) Δεν θα περιμένατε δίκαια ως την κακή μου τύχη. — Κρίσεως, αρνητική· εκφορά: δυνητική ευκτική (ευκτική + ἄν)."}],"note":"Το ταυτόσημο κριτήριο για να αναγνωρίσεις πρόταση κρίσεως είναι η ΑΡΝΗΣΗ οὐ μαζί με εγκλίσεις του πραγματικού/δυνατού (οριστική, δυνητική οριστική, δυνητική ευκτική). Αν η άρνηση είναι μή ή το ρήμα είναι προστακτική/υποτακτική/ευχετική ευκτική, ΔΕΝ είναι κρίσεως αλλά επιθυμίας."},{"h":"Ως προς το περιεχόμενο Β: Προτάσεις επιθυμίας","body":"<p><b>Προτάσεις επιθυμίας</b> είναι όσες εκφράζουν <b>επιθυμία, θέληση, προτροπή, προσταγή, παράκληση, ευχή, απαγόρευση ή απορία για το πρακτέο</b> — δηλαδή κάτι που ο ομιλητής θέλει ή ζητεί να γίνει (ή να μη γίνει), όχι κάτι που διαπιστώνει ως γεγονός.</p><h3>Εκφορά (έγκλιση) — το πλουσιότερο σύστημα εγκλίσεων</h3><p>Οι προτάσεις επιθυμίας εκφέρονται με τις εγκλίσεις της θέλησης και της ευχής, καθεμία με τεχνικό όνομα:</p><ul><li><b>Προστακτική</b>: δηλώνει προσταγή, παράκληση (<i>καταφατική</i>) ή απαγόρευση (<i>απαγορευτική/αποτρεπτική προστακτική</i>). <i>π.χ. λέγε· μή κλαῖε.</i></li><li><b>Προτρεπτική υποτακτική</b> (α΄ πληθ., σπανίως α΄ εν.): προτροπή προς κοινή ενέργεια. <i>π.χ. ἴωμεν = ας πάμε.</i></li><li><b>Αποτρεπτική υποτακτική</b> (μή + υποτακτική αορίστου, β΄/γ΄ προσ.): έντονη απαγόρευση. <i>π.χ. μή ποιήσῃς τοῦτο = μην το κάνεις.</i></li><li><b>Απορηματική υποτακτική</b>: απορία για το τι πρέπει να γίνει. <i>π.χ. τί εἴπω; = τι να πω;</i></li><li><b>Ευχετική ευκτική</b> (καθαρή/απλή ευκτική, συχνά με εἴθε, εἰ γάρ, ὡς): ευχή <i>πραγματοποιήσιμη</i> ή κατάρα. <i>π.χ. εἴθε γένοιο εὐτυχής.</i></li><li><b>Ευχετική / απευκτική οριστική</b> (παρατατικού/αορίστου με εἴθε, εἰ γάρ): ευχή <i>απραγματοποίητη</i>, ανεκπλήρωτη. <i>π.χ. εἴθε τοῦτο ἐποίεις = μακάρι να το έκανες.</i></li></ul><h3>Άρνηση</h3><p>Η άρνηση των προτάσεων επιθυμίας είναι πάντοτε <b>μή</b>: <i>μή θορυβεῖτε, μή ποιήσῃς, μή γένοιτο</i>.</p>","table":{"title":"Εγκλίσεις των προτάσεων επιθυμίας (κύριες προτάσεις)","cols":["Τεχνικό όνομα","Έγκλιση","Σημασία","Παράδειγμα"],"rows":[["(απλή) προστακτική","προστακτική","προσταγή / παράκληση","λέγε μοι (πες μου)"],["απαγορευτική / αποτρεπτική","μή + προστακτ. ή υποτακτ. αορ.","απαγόρευση","μή κλαῖε / μή κλαύσῃς (μην κλαις)"],["προτρεπτική υποτακτική","υποτακτική α΄ προσ.","προτροπή","ἴωμεν (ας πάμε)"],["απορηματική υποτακτική","υποτακτική (συχνά α΄ προσ.)","απορία για το πρακτέο","τί ποιῶμεν; (τι να κάνουμε;)"],["ευχετική ευκτική","ευκτική (εἴθε / εἰ γάρ)","πραγματοποιήσιμη ευχή","εἴθε γένοιο σοφός"],["ευχετική / απευκτική οριστική","οριστ. ιστ. χρόνου (εἴθε)","απραγματοποίητη ευχή","εἴθε μή ἀπέθανεν"]]},"examples":[{"gr":"Μή θορυβεῖτε, ὦ ἄνδρες.","an":"Μη θορυβείτε, άνδρες. — Επιθυμίας, αρνητική (άρνηση μή)· εκφορά: αποτρεπτική προστακτική."},{"gr":"Ἴωμεν ἐπί τούς πολεμίους.","an":"Ας βαδίσουμε εναντίον των εχθρών. — Επιθυμίας, καταφατική· εκφορά: προτρεπτική υποτακτική."},{"gr":"Εἴθε γενοίμην σοφός.","an":"Μακάρι να γινόμουν σοφός. — Επιθυμίας, καταφατική· εκφορά: ευχετική ευκτική (πραγματοποιήσιμη ευχή)."},{"gr":"Μή γένοιτο.","an":"Μη γένοιτο / μακάρι να μη συμβεί. — Επιθυμίας, αρνητική (άρνηση μή)· εκφορά: ευχετική (απευκτική) ευκτική."},{"gr":"Μή ἀναμένωμεν ἄλλους.","an":"Ξεν. Ἀνάβ. 3.1.24 — Ας μην περιμένουμε άλλους. — Επιθυμίας, αρνητική (μή)· εκφορά: προτρεπτική υποτακτική σε άρνηση."},{"gr":"Ἀκούσατε δή μου, ὦ ἄνδρες Ἀθηναῖοι.","an":"(τύπου ρητορικού λόγου) Ακούστε με λοιπόν, άνδρες Αθηναίοι. — Επιθυμίας, καταφατική· εκφορά: προστακτική (παράκληση/προσταγή)."},{"gr":"Μηδείς τοῦτο θαυμασάτω.","an":"Κανείς ας μην το θαυμάσει αυτό. — Επιθυμίας, αρνητική (μηδείς)· εκφορά: προστακτική γ΄ προσώπου (προτροπή/απαγόρευση)."}],"note":"ΚΛΕΙΔΙ διάκρισης κρίσεως/επιθυμίας: η άρνηση. οὐ → κρίσεως· μή → επιθυμίας. Επίσης η προστακτική, η προτρεπτική/αποτρεπτική/απορηματική υποτακτική και η ευχετική ευκτική ανήκουν ΠΑΝΤΑ σε προτάσεις επιθυμίας."},{"h":"Ως προς το περιεχόμενο Γ: Επιφωνηματικές προτάσεις","body":"<p><b>Επιφωνηματικές</b> είναι οι προτάσεις με τις οποίες ο ομιλητής εκφράζει ένα <b>έντονο συναίσθημα</b>: θαυμασμό, έκπληξη, αγανάκτηση, χαρά, λύπη, αποτροπιασμό. Δεν διατυπώνουν ψυχρή κρίση ούτε θέληση, αλλά συναισθηματική αντίδραση, και γι' αυτό κλείνουν συνήθως σε <b>θαυμαστικό</b>.</p><h3>Μορφή και εισαγωγή</h3><p>Συχνά εισάγονται με <b>θαυμαστικά / αναφορικά επιφωνηματικά</b> μόρια και λέξεις, που εκφράζουν ποσό ή ποιόν με έμφαση:</p><ul><li><b>ὡς</b> (πόσο…!), <b>ὅσος, οἷος, ἡλίκος</b> (πόσο μεγάλος, τι λογής, πόσο σημαντικός…!)</li><li>επιφωνήματα όπως <b>φεῦ, οἴμοι, ὦ, παπαῖ, βαβαί</b></li></ul><p>Πολλές επιφωνηματικές είναι <b>ελλειπτικές</b> (παραλείπεται το ρήμα ή το «είναι»), επειδή η συναισθηματική φόρτιση οδηγεί σε σύντομη, σπασμωδική διατύπωση.</p><p>Ως προς τη μορφή τους, οι επιφωνηματικές διακρίνονται περαιτέρω σε <i>κύριες</i> (ευθέα επιφωνήματα) και σε <i>δευτερεύουσες αναφορικές επιφωνηματικές</i> όταν εισάγονται με αναφορικό-επιφωνηματικό (ὡς, ὅσος, οἷος) και εξαρτώνται νοηματικά από ρήμα ψυχικού πάθους.</p>","examples":[{"gr":"Οἵα κεφαλή καί ἐγκέφαλον οὐκ ἔχει!","an":"Τι κεφάλι, και μυαλό δεν έχει! — Επιφωνηματική· εκφράζει αγανάκτηση/ειρωνεία· εισαγωγή με το επιφωνηματικό οἵα."},{"gr":"Ὡς ἀστεῖος ὁ ἄνθρωπος!","an":"Πόσο χαριτωμένος είναι ο άνθρωπος! — Επιφωνηματική, ελλειπτική (εννοείται ἐστί)· εισαγωγή με ὡς."},{"gr":"Φεῦ τῆς ἀνοίας.","an":"Αλίμονο για την ανοησία! — Επιφωνηματική με επιφώνημα φεῦ + γενική του επιφωνήματος· ελλειπτική."},{"gr":"Ὅσην φλυαρίαν λέγεις!","an":"Πόση φλυαρία λες! — Επιφωνηματική· έμφαση στο ποσό με το επιφωνηματικό ὅσην."},{"gr":"Ὡς ἡδύ μοι τό φῶς!","an":"(τύπου τραγωδίας) Πόσο γλυκό είναι σ' εμένα το φως! — Επιφωνηματική, ελλειπτική (εννοείται ἐστί)· εισαγωγή με ὡς."},{"gr":"Οἴμοι, τί δράσω;","an":"(τύπου τραγωδίας) Αλίμονο, τι να κάνω; — Επιφωνηματικό επιφώνημα (οἴμοι) + ευθεία απορηματική· δηλώνει οδύνη."},{"gr":"Ὦ τῆς ἀναιδείας.","an":"Ω τι αναίδεια! — Επιφωνηματική, ελλειπτική· επιφώνημα ὦ + γενική επιφωνηματική."}],"note":"Προσοχή στη διάκριση από τις ερωτηματικές: οι λέξεις ὡς, οἷος, ὅσος εδώ ΔΕΝ ρωτούν αλλά θαυμάζουν (κλείνουν σε θαυμαστικό, όχι ερωτηματικό). Συγκρ.: «Πόσο μεγάλος είναι;» (ερώτηση) — «Πόσο μεγάλος είναι!» (επιφώνημα)."},{"h":"Ως προς το περιεχόμενο Δ: Ερωτηματικές προτάσεις","body":"<p><b>Ερωτηματικές</b> είναι οι προτάσεις με τις οποίες διατυπώνεται <b>ερώτηση</b>. Κατά βάθος είναι προτάσεις κρίσεως ή επιθυμίας σε ερωτηματική μορφή, γι' αυτό εκφέρονται με τις αντίστοιχες εγκλίσεις. Διακρίνονται σε <b>ευθείες</b> (κύριες προτάσεις, κλείνουν σε ερωτηματικό) και <b>πλάγιες</b> (δευτερεύουσες ονοματικές, σε πλάγιο λόγο — βλ. ενότητα δευτερευουσών).</p><h3>1) Διάκριση ως προς την έκταση της άγνοιας</h3><ul><li><b>Ολικής αγνοίας</b>: η αμφιβολία αφορά <i>ολόκληρο</i> το περιεχόμενο της πρότασης· απαντώνται με <b>ναί / οὔ</b>. <i>π.χ. ἆρα ἔρχεται;</i></li><li><b>Μερικής αγνοίας</b>: η αμφιβολία αφορά <i>ένα μέρος</i> (ποιος, πότε, πώς…)· απαντώνται με τη συγκεκριμένη λέξη/φράση. Είναι πάντοτε <b>μονομελείς</b>. <i>π.χ. τίς ἔρχεται;</i></li></ul><h3>2) Διάκριση ως προς τον αριθμό των μελών</h3><ul><li><b>Μονομελείς</b>: ένα σκέλος ερώτησης.</li><li><b>Διμελείς (διαζευκτικές)</b>: δύο (ή περισσότερα) αντιπαρατιθέμενα σκέλη, με <b>πότερον (πότερα) … ἤ …</b> (ποιο από τα δύο…ή…). <i>π.χ. πότερον ἀληθῆ ἤ ψευδῆ λέγεις;</i></li></ul><h3>Εισαγωγή</h3><p><b>Ολικής αγνοίας</b> — με ερωτηματικά μόρια ή και μόνο με τον τόνο της φωνής: <b>ἆρα, ἆρ' οὖν, ἆρά γε, ἦ, μῶν, οὐ / ἆρ' οὐ / οὔκουν / οὐκοῦν</b> (όταν περιμένουμε καταφατική απάντηση), <b>μή / ἆρα μή / μῶν</b> (όταν περιμένουμε αρνητική). Διμελείς: <b>πότερον … ἤ</b>.</p><p><b>Μερικής αγνοίας</b> — με ερωτηματικές αντωνυμίες (<b>τίς, πόσος, ποῖος, πότερος, ποδαπός, πηλίκος</b>) ή ερωτηματικά επιρρήματα (<b>ποῦ, ποῖ, πόθεν, πῶς, πότε, πηνίκα, πῇ, πόσον</b>).</p><h3>Εκφορά</h3><p>Ως προτάσεις κρίσεως: <b>οριστική</b> (ερώτηση για το πραγματικό), <b>δυνητική οριστική</b> (για το μη πραγματικό/δυνατό στο παρελθόν), <b>δυνητική ευκτική</b> (για το δυνατό στο παρόν/μέλλον). Ως προτάσεις επιθυμίας: <b>απορηματική υποτακτική</b> (ερώτηση για το πρακτέο, «τι να κάνω;»). Άρνηση: <b>οὐ</b> στις κρίσεως, <b>μή</b> στις επιθυμίας.</p>","table":{"title":"Εισαγωγή ευθειών ερωτηματικών προτάσεων","cols":["Είδος","Μέλη","Εισαγωγή","Απάντηση"],"rows":[["Ολικής αγνοίας","μονομελής","ἆρα, ἆρ' οὖν, ἦ, μῶν, οὐκοῦν / ἆρα μή, μή (ή μόνο τόνος)","ναί / οὔ"],["Ολικής αγνοίας","διμελής","πότερον (πότερα) … ἤ …","το ένα από τα σκέλη"],["Μερικής αγνοίας","πάντα μονομελής (αντωνυμίες)","τίς, πόσος, ποῖος, πότερος, ποδαπός","λέξη/φράση"],["Μερικής αγνοίας","πάντα μονομελής (επιρρήματα)","ποῦ, ποῖ, πόθεν, πῶς, πότε, πηνίκα, πῇ","λέξη/φράση"]]},"examples":[{"gr":"Ἆρα ἀκούεις τί λέγω;","an":"Άραγε ακούς τι λέω; — Ευθεία, ολικής αγνοίας, μονομελής· εισαγωγή ἆρα· εκφορά οριστική (κρίσεως)."},{"gr":"Τίς οὖν ἐστιν ὁ διδάξας σε;","an":"Ποιος λοιπόν είναι αυτός που σε δίδαξε; — Ευθεία, μερικής αγνοίας, μονομελής· εισαγωγή με ερωτ. αντωνυμία τίς."},{"gr":"Πότερον ἀληθῆ ἤ ψευδῆ λέγεις;","an":"Λες αλήθεια ή ψέματα; — Ευθεία, ολικής αγνοίας, διμελής (διαζευκτική)· εισαγωγή πότερον…ἤ."},{"gr":"Τί ποιῶμεν, ὦ ἄνδρες;","an":"Τι να κάνουμε, άνδρες; — Ευθεία ερωτηματική επιθυμίας· εκφορά: απορηματική υποτακτική· άρνηση (αν υπήρχε) θα ήταν μή."},{"gr":"Μῶν τι σε ἠδίκησεν;","an":"Μήπως σε αδίκησε σε κάτι; — Ευθεία, ολικής αγνοίας, με μῶν (αναμένεται αρνητική απάντηση)."},{"gr":"Εἴπωμεν ἤ σιγῶμεν;","an":"Smyth §1805 — Να μιλήσουμε ή να σωπάσουμε; — Ευθεία ερωτηματική επιθυμίας, διμελής· εκφορά: απορηματική υποτακτική."},{"gr":"Ποῖ τις οὖν φύγῃ;","an":"Σοφ. Αἴας 403 — Πού λοιπόν να φύγει κανείς; — Ευθεία, μερικής αγνοίας (ποῖ)· εκφορά: απορηματική υποτακτική (πρακτέο)."},{"gr":"Πῶς γάρ ἄν τις ἄρξαι καλῶς μή ἐπιστάμενος;","an":"(τύπου Ξεν.) Πώς δηλαδή θα μπορούσε κανείς να άρχει καλά, αν δεν γνωρίζει; — Ευθεία (ρητορική), μερικής αγνοίας (πῶς)· εκφορά: δυνητική ευκτική (δυνατό)."}],"note":"Τα ἆρ' οὐ / οὔκουν / οὐκοῦν προϊδεάζουν για ΚΑΤΑΦΑΤΙΚΗ απάντηση («δεν είναι έτσι;»), ενώ τα μή / ἆρα μή / μῶν για ΑΡΝΗΤΙΚΗ («μήπως…;»). Η ρητορική ερώτηση είναι τυπικά ερώτηση που δεν ζητά απάντηση αλλά ισοδυναμεί με έντονη βεβαίωση/άρνηση."},{"h":"Ως προς το ποιόν (τη μορφή): καταφατικές και αποφατικές","body":"<p>Με κριτήριο την παρουσία ή απουσία άρνησης, οι προτάσεις διακρίνονται σε:</p><ul><li><b>Καταφατικές</b>: δεν περιέχουν άρνηση· βεβαιώνουν κάτι. <i>π.χ. ὁ Σωκράτης σοφός ἐστιν.</i></li><li><b>Αποφατικές (αρνητικές)</b>: περιέχουν άρνηση· αναιρούν κάτι. <i>π.χ. ὁ Σωκράτης οὐ σοφός ἐστιν.</i></li></ul><h3>Ο θεμελιώδης κανόνας: οὐ έναντι μή</h3><p>Η επιλογή της άρνησης ΔΕΝ είναι τυχαία· εξαρτάται από το είδος της πρότασης (το περιεχόμενο):</p><ul><li><b>οὐ</b> (οὐκ / οὐχ): άρνηση των προτάσεων <b>κρίσεως</b> (του πραγματικού, της σκέψης). Συνοδεύει οριστική, δυνητική οριστική, δυνητική ευκτική.</li><li><b>μή</b>: άρνηση των προτάσεων <b>επιθυμίας</b> (της θέλησης, της ευχής, της υπόθεσης, του σκοπού). Συνοδεύει προστακτική, υποτακτική, ευχετική ευκτική, καθώς και απαρέμφατα/μετοχές με βουλητικό-υποθετικό χαρακτήρα.</li></ul><h3>Άθροισμα και επίταση αρνήσεων</h3><p>Όταν σε μία πρόταση υπάρχουν <b>δύο αρνήσεις</b>, ισχύει:</p><ul><li><b>απλή + σύνθετη</b> ίδιου είδους (π.χ. οὐ … οὐδείς, μή … μηδείς): η άρνηση <i>επιτείνεται</i> (παραμένει αρνητική): <i>οὐδείς οὐκ ἔπασχε = κανείς δεν έμενε απαθής.</i></li><li><b>σύνθετη + απλή</b> ίδιου είδους (π.χ. οὐδείς οὐ): οι αρνήσεις <i>αλληλοαναιρούνται</i> και προκύπτει έντονη <i>κατάφαση</i>: <i>οὐδείς οὐκ ἀπέθανεν = όλοι πέθαναν.</i></li></ul>","table":{"title":"Επιλογή άρνησης κατά είδος","cols":["Άρνηση","Είδος πρότασης / περιβάλλον","Εγκλίσεις-τύποι"],"rows":[["οὐ, οὐκ, οὐχ","κρίσεως (πραγματικό, δυνατό)","οριστική, δυνητική οριστική, δυνητική ευκτική"],["μή","επιθυμίας (θέληση, ευχή, υπόθεση, σκοπός, φόβος)","προστακτική, υποτακτική, ευχετική ευκτική"],["μή + ρηματικός τύπος","βουλητικό/υποθετικό απαρέμφατο & μετοχή","απαρέμφατο, μετοχή"]]},"examples":[{"gr":"Τήν τοιαύτην δύναμιν ἀνδρείαν ἐγώ καλῶ.","an":"Αυτή τη δύναμη εγώ την ονομάζω ανδρεία. — Καταφατική (καμία άρνηση)."},{"gr":"Οὐ παραιτοῦμαι τόν θάνατον.","an":"Δεν αποφεύγω τον θάνατο. — Αποφατική· άρνηση οὐ (πρόταση κρίσεως)."},{"gr":"Μή ποιήσῃς ἀδικίαν.","an":"Μην κάνεις αδικία. — Αποφατική· άρνηση μή (πρόταση επιθυμίας)."},{"gr":"Οὐδείς οὐκ ἐπείσθη τοῖς λόγοις.","an":"Κανείς δεν έμεινε απείστος στους λόγους (= όλοι πείστηκαν). — Σύνθετη άρνηση πριν από απλή ίδιου είδους → ισχυρή κατάφαση."},{"gr":"Οὐ γάρ ᾔδη.","an":"Λυσ. 1.41 — Γιατί δεν (το) ήξερα. — Αποφατική, κρίσεως· άρνηση οὐ + οριστική."},{"gr":"Οὐδείς πώποτε ταῦτα οὐκ ἐπῄνεσεν.","an":"Κανείς ποτέ δεν παρέλειψε να τα επαινέσει αυτά (= όλοι τα επαίνεσαν). — Σύνθετη (οὐδείς) + απλή άρνηση (οὐκ) → κατάφαση."},{"gr":"Οὐκ ἄν δυναίμην μή γελῶν εἰπεῖν.","an":"(τύπου κωμωδίας) Δεν θα μπορούσα να (το) πω χωρίς να γελώ. — Στην κύρια οὐ (κρίσεως, δυνητική ευκτική)· στη μετοχή μή (βουλητικού/υποθετικού χαρακτήρα)."}],"note":"Κλασική παγίδα: το «μή» σε ΕΡΩΤΗΣΗ ολικής αγνοίας (μή/μῶν = «μήπως;») ΔΕΝ είναι άρνηση αλλά ερωτηματικό μόριο που υποδηλώνει αναμενόμενη αρνητική απάντηση. Επίσης το «οὐ μή + υποτακτική/μέλλοντα» εκφράζει έντονη άρνηση/απαγόρευση (οὐ μή ποιήσῃς = μην τυχόν κάνεις)."},{"h":"Ως προς τη σχέση: κύριες και δευτερεύουσες (με τον πλήρη χάρτη των δευτερευουσών)","body":"<p>Με κριτήριο αν μια πρόταση στέκεται νοηματικά μόνη της:</p><ul><li><b>Κύριες (ανεξάρτητες)</b>: εκφράζουν αυτοτελές νόημα και δεν χρειάζονται άλλη πρόταση για να σταθούν. Σε κάθε περίοδο υπάρχει <i>τουλάχιστον μία</i>.</li><li><b>Δευτερεύουσες (εξαρτημένες)</b>: δεν στέκονται μόνες· λειτουργούν ως όρος (υποκείμενο, αντικείμενο, προσδιορισμός) μιας άλλης πρότασης από την οποία εξαρτώνται. <b>Εισάγονται πάντοτε με μια εισαγωγική λέξη</b>: υποτακτικό σύνδεσμο, αναφορική αντωνυμία/επίρρημα, ή ερωτηματική αντωνυμία/επίρρημα.</li></ul><h3>Πώς αναγνωρίζω δευτερεύουσα</h3><p>Από την <b>εισαγωγική λέξη</b>. Οι δευτερεύουσες εισάγονται με: <i>υποτακτικούς συνδέσμους</i> (ὅτι, ὡς, ἵνα, ὅπως, ἐάν, εἰ, ἐπεί, ὅτε, ὥστε, διότι…), <i>αναφορικές αντωνυμίες</i> (ὅς, ὅστις, ὅσος, οἷος), <i>αναφορικά επιρρήματα</i> (οὗ, ὅθεν, ὡς, ὅπως, ἔνθα), ή <i>ερωτηματικές λέξεις</i> σε πλάγιο λόγο (τίς, εἰ, πότερον…ἤ…).</p><h3>Οι δύο μεγάλες οικογένειες δευτερευουσών</h3><p>Ανάλογα με τον συντακτικό ρόλο που παίζουν:</p><ul><li><b>Ονοματικές</b>: λειτουργούν ως όνομα (υποκείμενο, αντικείμενο, επεξήγηση). Περιλαμβάνουν: <i>ειδικές</i> (ὅτι, ὡς — «ότι…»), <i>βουλητικές</i> (ἵνα, ὅπως, ὡς + θέληση), <i>ενδοιαστικές</i> (μή, μή οὐ — φόβος), <i>πλάγιες ερωτηματικές</i> (εἰ, τίς, πότερον…ἤ), <i>αναφορικές ονοματικές</i> (ὅς, ὅστις).</li><li><b>Επιρρηματικές</b>: λειτουργούν ως επιρρηματικός προσδιορισμός. Περιλαμβάνουν: <i>αιτιολογικές</i> (ὅτι, διότι, ἐπεί), <i>τελικές</i> (ἵνα, ὅπως, ὡς — σκοπός), <i>αποτελεσματικές/συμπερασματικές</i> (ὥστε, ὡς), <i>υποθετικές</i> (εἰ, ἐάν), <i>εναντιωματικές/παραχωρητικές</i> (εἰ καί, καί εἰ, ἐάν καί), <i>χρονικές</i> (ὅτε, ἐπεί, ἕως, πρίν), <i>αναφορικές επιρρηματικές</i> (οὗ, ἔνθα, ὡς).</li></ul>","table":{"title":"Χάρτης των δευτερευουσών προτάσεων","cols":["Οικογένεια","Είδος","Τυπική εισαγωγή"],"rows":[["Ονοματικές","ειδικές","ὅτι, ὡς"],["Ονοματικές","βουλητικές","ἵνα, ὅπως, ὡς (+ θέληση)"],["Ονοματικές","ενδοιαστικές","μή (φόβος μη γίνει), μή οὐ (φόβος μη δεν γίνει)"],["Ονοματικές","πλάγιες ερωτηματικές","εἰ· τίς, πόσος…· πότερον…ἤ"],["Ονοματικές","αναφορικές ονοματικές","ὅς, ὅστις, ὅσος, οἷος"],["Επιρρηματικές","αιτιολογικές","ὅτι, διότι, ἐπεί, ὡς"],["Επιρρηματικές","τελικές","ἵνα, ὅπως, ὡς (σκοπός)"],["Επιρρηματικές","συμπερασματικές (αποτελέσματος)","ὥστε, ὡς"],["Επιρρηματικές","υποθετικές","εἰ, ἐάν (ἄν, ἤν)"],["Επιρρηματικές","εναντιωματικές / παραχωρητικές","εἰ καί, καί εἰ, ἐάν καί, καί ἐάν"],["Επιρρηματικές","χρονικές","ὅτε, ὁπότε, ἐπεί, ἐπειδή, ἕως, ἔστε, πρίν"],["Επιρρηματικές","αναφορικές επιρρηματικές","οὗ, ὅθεν, ἔνθα, ὡς, ὅπως"]]},"examples":[{"gr":"Ἡ χιών ἐκάλυψε πᾶν τό πεδίον.","an":"Το χιόνι κάλυψε όλη την πεδιάδα. — Κύρια (ανεξάρτητη): στέκεται μόνη."},{"gr":"Λέγω ὅτι ἀληθῆ εἰσι ταῦτα.","an":"Λέω ότι αυτά είναι αληθινά. — Κύρια: Λέγω· δευτερεύουσα ονοματική ειδική (ὅτι…) ως αντικείμενο του Λέγω."},{"gr":"Φοβοῦμαι μή οἱ πολέμιοι ἔλθωσιν.","an":"Φοβάμαι μήπως έρθουν οι εχθροί. — Δευτερεύουσα ονοματική ενδοιαστική (μή…) ως αντικείμενο του Φοβοῦμαι."},{"gr":"Ἐπεί ἐνίκησαν, οἴκαδε ἀπῆλθον.","an":"Αφού νίκησαν, έφυγαν για το σπίτι. — Δευτερεύουσα επιρρηματική χρονική (Ἐπεί…) + κύρια (οἴκαδε ἀπῆλθον)."},{"gr":"Ἦλθον ἵνα μάθω τήν ἀλήθειαν.","an":"Ήρθα για να μάθω την αλήθεια. — Δευτερεύουσα επιρρηματική τελική (ἵνα…) που δηλώνει σκοπό."},{"gr":"Ἐνταῦθα ἔμεινεν ἡμέρας τρεῖς· καί ἧκε Τισσαφέρνης.","an":"(τύπου Ξεν. Ἀνάβ.) Εκεί έμεινε τρεις μέρες· και έφτασε ο Τισσαφέρνης. — Δύο κύριες προτάσεις, καθεμία στέκεται μόνη της."},{"gr":"Οἶδα ὅτι οὐδέν οἶδα.","an":"Γνωρίζω ότι δεν γνωρίζω τίποτε (νεοελλ. απόδοση γνωστού πλατωνικού νοήματος). — Κύρια: Οἶδα· δευτ. ονοματική ειδική (ὅτι…) ως αντικείμενο."},{"gr":"Ταῦτα ἐποίει ὥστε πάντες ἐθαύμαζον.","an":"Αυτά έκανε, ώστε όλοι θαύμαζαν. — Κύρια (Ταῦτα ἐποίει) + δευτ. επιρρηματική συμπερασματική (ὥστε…) πραγματικού αποτελέσματος."}],"note":"Μην μπερδεύεις την εισαγωγική λέξη ὡς: εισάγει ειδικές, βουλητικές, τελικές, αιτιολογικές, συμπερασματικές, χρονικές ΚΑΙ αναφορικές — η σημασία κρίνεται από τα συμφραζόμενα και την εκφορά. Επίσης το εἰ είναι υποθετικό στις υποθετικές, αλλά εισάγει και πλάγια ερωτηματική ολικής αγνοίας («αν / κατά πόσον»)."},{"h":"Ως προς τους όρους: απλές, σύνθετες, ελλειπτικές, επαυξημένες","body":"<p>Με κριτήριο το πλήθος και το είδος των όρων που απαρτίζουν την πρόταση:</p><h3>α) Απλές</h3><p>Αποτελούνται <b>μόνο από τους κύριους όρους</b>: υποκείμενο και κατηγόρημα (ρήμα ή ρήμα + κατηγορούμενο/αντικείμενο), χωρίς προσδιορισμούς. Είναι ο «γυμνός σκελετός» της πρότασης.</p><h3>β) Σύνθετες</h3><p>Έχουν <b>περισσότερους από έναν ομοιόλεκτους κύριους όρους</b> (π.χ. δύο υποκείμενα, δύο αντικείμενα, δύο κατηγορούμενα) συνδεδεμένους <i>παρατακτικά</i> (με καί, τε…καί, ἤ, ἀλλά). Δεν πρόκειται για δύο προτάσεις, αλλά για μία με πολλαπλό όρο.</p><h3>γ) Ελλειπτικές</h3><p><b>Παραλείπεται ένας ή περισσότεροι κύριοι όροι</b> (υποκείμενο, ρήμα, αντικείμενο) επειδή εύκολα εννοούνται από τα συμφραζόμενα, από τη γραμματική (π.χ. το προσωπικό υποκείμενο που δηλώνεται από την κατάληξη) ή από τη συνήθεια (γνωμικά, παροιμίες, επιγραφές, επιφωνήματα).</p><h3>δ) Επαυξημένες</h3><p>Περιλαμβάνουν, εκτός από τους κύριους όρους, και <b>δευτερεύοντες όρους – προσδιορισμούς</b>. Οι προσδιορισμοί διακρίνονται σε <i>ονοματικούς</i> (προσδιορίζουν ονόματα: επιθετικός, κατηγορηματικός, παράθεση, επεξήγηση, ετερόπτωτοι/γενική–δοτική) και <i>επιρρηματικούς</i> (προσδιορίζουν ρήματα: τόπος, χρόνος, τρόπος, αιτία, σκοπός, όργανο…).</p>","table":{"title":"Οι τέσσερις τύποι κατά τους όρους","cols":["Τύπος","Ορισμός","Παράδειγμα"],"rows":[["Απλή","μόνο κύριοι όροι","Τό φρούριον ἐφυλάττετο."],["Σύνθετη","πολλαπλός ομοιόλεκτος όρος, παρατακτικά","Κάστωρ καί Πολυδεύκης ἐκλήθησαν Διόσκουροι."],["Ελλειπτική","λείπει εννοούμενος κύριος όρος","Ἀγαθός εἶ. [ενν. σύ]"],["Επαυξημένη","κύριοι όροι + προσδιορισμοί","Δαρεῖος ὁ βασιλεύς εὐθύς ἀπεχώρει."]]},"examples":[{"gr":"Τό φρούριον ἐφυλάττετο.","an":"Το φρούριο φυλασσόταν. — Απλή: υποκείμενο + ρήμα, χωρίς προσδιορισμούς."},{"gr":"Κάστωρ καί Πολυδεύκης ἐκλήθησαν Διόσκουροι.","an":"Ο Κάστωρ και ο Πολυδεύκης ονομάστηκαν Διόσκουροι. — Σύνθετη: δύο υποκείμενα (Κάστωρ, Πολυδεύκης) με καί."},{"gr":"Ὡς καλός μοι ὁ πάππος!","an":"Πόσο όμορφος είναι ο παππούς μου! — Ελλειπτική (παραλείπεται το ἐστί) και συγχρόνως επιφωνηματική."},{"gr":"Δαρεῖος ὁ βασιλεύς εὐθύς ἀπεχώρει ἐπί τά ὄρη.","an":"Ο Δαρείος, ο βασιλιάς, αμέσως αποχωρούσε προς τα βουνά. — Επαυξημένη: παράθεση (ὁ βασιλεύς), επιρρ. χρόνου (εὐθύς), επιρρ. τόπου (ἐπί τά ὄρη)."},{"gr":"Ἐνταῦθα Κῦρος ἔμεινεν ἡμέρας τριάκοντα.","an":"(τύπου Ξεν. Ἀνάβ.) Εκεί ο Κύρος έμεινε τριάντα μέρες. — Επαυξημένη: επιρρ. τόπου (Ἐνταῦθα), αιτιατική χρόνου (ἡμέρας τριάκοντα)."},{"gr":"Χαλεπά τά καλά.","an":"Δύσκολα (επιτυγχάνονται) τα ωραία (παροιμιακό). — Ελλειπτική: παραλείπεται το ρήμα (ἐστί)· τυπική γνωμική/παροιμιακή σύνταξη."},{"gr":"Οἱ στρατιῶται καί οἱ ἱππεῖς τόν ποταμόν καί τήν γέφυραν διέβησαν.","an":"Οι πεζοί και οι ιππείς πέρασαν το ποτάμι και τη γέφυρα. — Σύνθετη: διπλό υποκείμενο και διπλό αντικείμενο (παρατακτικά με καί)."}],"note":"Η «σύνθετη» ως προς τους όρους ΔΕΝ ταυτίζεται με τη «σύνθετη/περίπλοκη περίοδο» πολλών προτάσεων: εδώ έχουμε μία μόνο πρόταση με πολλαπλό όρο. Επίσης μια πρόταση μπορεί να είναι ταυτόχρονα ελλειπτική και επαυξημένη (λείπει το ρήμα αλλά υπάρχουν προσδιορισμοί)."},{"h":"Σύνθεση και μεθοδολογία: πλήρης χαρακτηρισμός μιας πρότασης","body":"<p>Στην εξεταστική πράξη, ο «πλήρης χαρακτηρισμός» μιας πρότασης απαντά διαδοχικά και στα τέσσερα κριτήρια, και — αν είναι δευτερεύουσα ή ερωτηματική — προσθέτει <b>είδος, εισαγωγή, εκφορά, συντακτικό ρόλο</b>.</p><h3>Βήματα ανάλυσης</h3><ol><li><b>Βρες τα ρήματα</b> → όρισε τα όρια κάθε πρότασης (τόσες προτάσεις όσα τα ρήματα προσωπικής έγκλισης).</li><li><b>Σχέση</b>: κύρια ή δευτερεύουσα; (κοίτα την εισαγωγική λέξη).</li><li><b>Περιεχόμενο</b>: κρίσεως, επιθυμίας, επιφωνηματική ή ερωτηματική; (κοίτα την έγκλιση και την άρνηση).</li><li><b>Ποιόν</b>: καταφατική ή αποφατική; (υπάρχει οὐ ή μή;).</li><li><b>Όροι</b>: απλή, σύνθετη, ελλειπτική, επαυξημένη;</li><li>Αν δευτερεύουσα/ερωτηματική: δήλωσε <b>είδος</b> (π.χ. ειδική, τελική, πλάγια ερωτηματική), <b>εισαγωγή</b> (με ποια λέξη), <b>εκφορά</b> (έγκλιση + γιατί), και <b>συντακτική θέση</b> (υποκείμενο/αντικείμενο/προσδιορισμός τίνος).</li></ol><h3>Πρότυπα διατύπωσης</h3><p>«Κύρια πρόταση κρίσεως, καταφατική, επαυξημένη.» — «Δευτερεύουσα ονοματική ειδική πρόταση, εισάγεται με τον σύνδεσμο ὅτι, εκφέρεται με οριστική (δηλώνει το πραγματικό), λειτουργεί ως αντικείμενο του ρήματος λέγω.»</p>","examples":[{"gr":"Οἶδα ὅτι οὐδέν οἶδα.","an":"Γνωρίζω ότι δεν γνωρίζω τίποτε. — Κύρια: Οἶδα (κρίσεως, καταφατική, απλή). Δευτ. ονοματική ειδική: ὅτι οὐδέν οἶδα — εισαγωγή ὅτι, εκφορά οριστική (πραγματικό), αρνητική (οὐδέν), αντικείμενο του Οἶδα."},{"gr":"Εἰ τοῦτο ἀληθές ἐστιν, οὐκ οἶδα.","an":"Αν αυτό είναι αληθινό, δεν το ξέρω. — Δευτ. ονοματική πλάγια ερωτηματική ολικής αγνοίας (Εἰ…), αντικείμενο· κύρια: οὐκ οἶδα (κρίσεως, αρνητική)."},{"gr":"Σπεύδωμεν, ἵνα μή ὑστερήσωμεν τῆς μάχης.","an":"Ας σπεύσουμε, για να μη φτάσουμε αργά στη μάχη. — Κύρια: Σπεύδωμεν (επιθυμίας, προτρεπτική υποτακτική). Δευτ. επιρρ. τελική: ἵνα μή… — εισαγωγή ἵνα, εκφορά υποτακτική, αρνητική (μή)."},{"gr":"Πότερον δίκαιόν ἐστιν ἤ οὔ;","an":"Είναι δίκαιο ή όχι; — Κύρια ευθεία ερωτηματική, ολικής αγνοίας, διμελής (πότερον…ἤ), κρίσεως, εκφορά οριστική."},{"gr":"Ἐνθάδε ἥκω, ἵνα ὑμᾶς πείσω μή ταῦτα ποιεῖν.","an":"(τύπου ρητορικού) Ήρθα εδώ, για να σας πείσω να μην τα κάνετε αυτά. — Κύρια: ἥκω (κρίσεως, καταφατική, επαυξημένη). Δευτ. επιρρ. τελική (ἵνα…πείσω), εκφορά υποτακτική· το μή ταῦτα ποιεῖν είναι απαρ. βουλητικού χαρακτήρα (άρνηση μή)."},{"gr":"Λέγουσιν ὅτι Κῦρος ἀπέθανεν ἐν τῇ μάχῃ.","an":"Λένε ότι ο Κύρος πέθανε στη μάχη. — Κύρια: Λέγουσιν (κρίσεως, καταφατική). Δευτ. ονοματική ειδική (ὅτι…), εισαγωγή ὅτι, εκφορά οριστική (πραγματικό), αντικείμενο του Λέγουσιν."}],"note":"Χρυσός κανόνας μνήμης για το περιεχόμενο και την άρνηση: ΟΡΙΣΤΙΚΗ/ΔΥΝΗΤΙΚΗ + οὐ = κρίσεως· ΠΡΟΣΤΑΚΤΙΚΗ/ΥΠΟΤΑΚΤΙΚΗ/ΕΥΧΕΤΙΚΗ ΕΥΚΤΙΚΗ + μή = επιθυμίας· ΘΑΥΜΑΣΤΙΚΟ = επιφωνηματική· ΕΡΩΤΗΜΑΤΙΚΟ = ερωτηματική. Πάντα έλεγχε ΕΙΣΑΓΩΓΗ και ΕΚΦΟΡΑ — είναι οι λέξεις που δίνουν τους βαθμούς."}]);
  T("syn-ypokeimeno", [{"h":"Ορισμός, πτώση και ρόλος του υποκειμένου","body":"<p><b>Υποκείμενο</b> ονομάζεται ο όρος της πρότασης για τον οποίο γίνεται λόγος· είναι το πρόσωπο, το ζώο ή το πράγμα που <i>ενεργεί</i> (όταν το ρήμα είναι ενεργητικής διάθεσης), που <i>δέχεται την ενέργεια</i> (παθητική διάθεση) ή που <i>βρίσκεται σε μια κατάσταση</i> (μέση/ουδέτερη διάθεση). Μαζί με το ρήμα (το <i>κατηγόρημα</i>) αποτελεί τον πυρήνα της πρότασης· χωρίς αυτά τα δύο δεν υπάρχει πρόταση.</p><h3>Η πτώση του υποκειμένου</h3><p>Το υποκείμενο του <b>ρήματος μιας πρότασης</b> τίθεται <b>πάντοτε σε πτώση ονομαστική</b>, τόσο στα αρχαία όσο και στα νέα ελληνικά. Αυτός είναι ο πιο ασφαλής κανόνας αναγνώρισης: αν ο όρος για τον οποίο μιλάμε δεν είναι σε ονομαστική, δεν είναι υποκείμενο ρήματος.</p><p>Προσοχή όμως: ο κανόνας αφορά το υποκείμενο του <i>ρήματος</i>. Όπως θα δούμε χωριστά, το υποκείμενο του <b>απαρεμφάτου</b> μπορεί να μπει σε <i>αιτιατική</i> (ετεροπροσωπία), και το υποκείμενο της <b>μετοχής</b> ακολουθεί την πτώση της μετοχής. Ο κανόνας «πάντοτε ονομαστική» ισχύει απαρέγκλιτα μόνο για το ρηματικό υποκείμενο.</p><h3>Συμφωνία υποκειμένου - ρήματος</h3><p>Το ρήμα συμφωνεί με το υποκείμενό του κατά το <b>πρόσωπο</b> και τον <b>αριθμό</b>: <i>ὁ στρατιώτης μάχεται</i> (γ΄ ενικό), <i>οἱ στρατιῶται μάχονται</i> (γ΄ πληθυντικό). Από τη βασική αυτή συμφωνία υπάρχουν δύο σημαντικές, χαρακτηριστικά αρχαιοελληνικές αποκλίσεις (αττική σύνταξη και σχήμα κατά το νοούμενο), που εξετάζονται σε ξεχωριστή ενότητα.</p>","examples":[{"gr":"Ὁ Ἀγησίλαος ἐδίωκε τούς πολεμίους.","an":"Υποκείμενο του ρήματος <i>ἐδίωκε</i> είναι το <i>ὁ Ἀγησίλαος</i> (ονομαστική). Δηλώνει ποιος ενεργεί."},{"gr":"Οἱ ἵπποι φέρουσι τάς ἁμάξας.","an":"Υποκείμενο το <i>οἱ ἵπποι</i> (ονομαστική πληθυντικού)· το ρήμα <i>φέρουσι</i> συμφωνεί σε γ΄ πληθυντικό."},{"gr":"Ὁ διδάσκαλος ἐπαινεῖται ὑπό τῶν μαθητῶν.","an":"Παθητική διάθεση: το υποκείμενο <i>ὁ διδάσκαλος</i> δεν ενεργεί αλλά δέχεται την ενέργεια του επαίνου· παραμένει όμως σε ονομαστική."},{"gr":"Κῦρος ἁθροίζει στράτευμα.","an":"Ξεν. Ἀνάβ. 1.1 (τύπου) — Υποκείμενο του <i>ἁθροίζει</i> το <i>Κῦρος</i> (ονομαστική, ενεργεί)· αντικείμενο <i>στράτευμα</i> (αιτιατική)."},{"gr":"Οἱ στρατιῶται ἐπαύσαντο τῆς μάχης.","an":"Υποκείμενο <i>οἱ στρατιῶται</i> (ονομαστική πληθ.)· μέση διάθεση, το υποκείμενο ενεργεί προς όφελός του και το ρήμα συμφωνεί σε γ΄ πληθυντικό."}],"note":"Μην συγχέεις το υποκείμενο με το αντικείμενο: το υποκείμενο είναι σε ονομαστική, το (άμεσο) αντικείμενο τυπικά σε αιτιατική. Στην παθητική σύνταξη ο «δράστης» εκφράζεται με εμπρόθετο ποιητικό αίτιο (ὑπό + γενική), όχι ως υποκείμενο."},{"h":"Εύρεση του υποκειμένου κατά πρόσωπο","body":"<p>Ο τρόπος που εντοπίζουμε το υποκείμενο εξαρτάται από το <b>πρόσωπο</b> του ρήματος.</p><h3>α΄ και β΄ πρόσωπο</h3><p>Στο <b>α΄ και β΄ πρόσωπο</b> (ενικού και πληθυντικού) το υποκείμενο είναι η αντίστοιχη <b>προσωπική αντωνυμία</b>: <i>ἐγώ, σύ, ἡμεῖς, ὑμεῖς</i>. Η αντωνυμία αυτή τις περισσότερες φορές <b>παραλείπεται</b>, γιατί το πρόσωπο φανερώνεται ήδη από την κατάληξη του ρήματος· τη γράφουμε ρητά μόνο όταν υπάρχει έμφαση ή αντιδιαστολή.</p><h3>γ΄ πρόσωπο</h3><p>Στο <b>γ΄ πρόσωπο</b> ρωτάμε με το ρήμα <b>«ποιος / ποια / ποιο;»</b> (ή στον πληθυντικό «ποιοι / ποιες / ποια;»). Η απάντηση που δίνεται σε ονομαστική είναι το υποκείμενο.</p><p>Παράδειγμα: <i>Ὁ Κῦρος συνέλεξε στράτευμα.</i> — Ρωτάμε «ποιος συνέλεξε;» → <i>ὁ Κῦρος</i>. Άρα υποκείμενο είναι το <i>ὁ Κῦρος</i>.</p>","examples":[{"gr":"Γράφομεν ἐπιστολήν.","an":"Ρήμα α΄ πληθυντικού· υποκείμενο η εννοούμενη αντωνυμία <i>ἡμεῖς</i>. Η αντωνυμία παραλείπεται, αφού δηλώνεται από την κατάληξη <i>-ομεν</i>."},{"gr":"Σύ μέν γράφεις, ἐγώ δέ ἀναγιγνώσκω.","an":"Εδώ οι αντωνυμίες <i>σύ</i> και <i>ἐγώ</i> τίθενται ρητά λόγω αντιδιαστολής (μέν... δέ): η έμφαση δικαιολογεί τη μη παράλειψη."},{"gr":"Ἀφίκοντο οἱ πρέσβεις εἰς τάς Ἀθήνας.","an":"γ΄ πληθυντικό· ρωτάμε «ποιοι αφίκοντο;» → <i>οἱ πρέσβεις</i>. Αυτό είναι το υποκείμενο (ονομαστική πληθυντικού)."},{"gr":"Ἐγώ δέ τοῦτο οὐ ποιήσω.","an":"Ρήμα α΄ ενικού· η αντωνυμία <i>ἐγώ</i> δηλώνεται ρητά για έμφαση/αντιδιαστολή («εγώ τουλάχιστον»)· υποκείμενο το <i>ἐγώ</i>."},{"gr":"Ὁ Κῦρος συνέλεξε στράτευμα.","an":"γ΄ ενικό· ρωτάμε «ποιος συνέλεξε;» → <i>ὁ Κῦρος</i> (ονομαστική), που είναι το υποκείμενο· <i>στράτευμα</i> αντικείμενο."}],"note":"Η ερώτηση «ποιος;» απαντάται σε ονομαστική και δίνει το υποκείμενο· η ερώτηση «ποιον;» απαντάται σε αιτιατική και δίνει το αντικείμενο. Μην τις μπερδεύεις."},{"h":"Τι μπορεί να λειτουργήσει ως υποκείμενο (μέρη του λόγου)","body":"<p>Υποκείμενο δεν είναι μόνο το ουσιαστικό. Ως υποκείμενο μπορεί να λειτουργήσει οποιαδήποτε λέξη, φράση ή και ολόκληρη πρόταση που έχει <b>ουσιαστική αξία</b> (έχει δηλαδή <i>ουσιαστικοποιηθεί</i>, συνήθως με τη βοήθεια του άρθρου).</p><h3>Ονοματικά υποκείμενα</h3><ul><li><b>Ουσιαστικό</b>: <i>Ὁ Φίλιππος ἀπέθανε.</i></li><li><b>Επίθετο</b> (ουσιαστικοποιημένο): <i>Οἱ ἀγαθοί τιμῶνται.</i></li><li><b>Αντωνυμία</b>: <i>Οὗτος ἀδικεῖ.</i></li><li><b>Αριθμητικό</b>: <i>Οἱ τριάκοντα ἦρξαν.</i></li><li><b>Μετοχή</b> (έναρθρη, επιθετική): <i>Οἱ φεύγοντες ἐσώθησαν.</i></li><li><b>Απαρέμφατο</b> (έναρθρο ή άναρθρο): <i>Τό λακωνίζειν ἐστί φιλοσοφεῖν.</i></li><li><b>Εμπρόθετος / επίρρημα</b> με άρθρο: <i>Οἱ ἐκ τῆς πόλεως ἔφυγον· οἱ πάλαι ἀνδρεῖοι ἦσαν.</i></li><li><b>Οποιαδήποτε ουσιαστικοποιημένη λέξη/φράση</b>: <i>Τό γνῶθι σαυτόν χρήσιμόν ἐστιν.</i></li></ul><h3>Πρόταση ως υποκείμενο</h3><p>Υποκείμενο μπορεί να είναι και <b>ολόκληρη δευτερεύουσα πρόταση</b> — αναφορική, ειδική, βουλητική, ενδοιαστική ή πλάγια ερωτηματική — ιδίως όταν εξαρτάται από <b>απρόσωπο ρήμα ή απρόσωπη έκφραση</b>: <i>Δῆλόν ἐστιν ὅτι ψεύδεται.</i></p>","table":{"title":"Μορφές που λειτουργούν ως υποκείμενο","cols":["Μέρος του λόγου / μορφή","Παράδειγμα (αρχαία)","Νεοελληνική απόδοση"],"rows":[["Ουσιαστικό","Ὁ στρατηγός νικᾷ.","Ο στρατηγός νικά."],["Επίθετο (ουσιαστικοπ.)","Οἱ σοφοί εὐδαιμονοῦσιν.","Οι σοφοί ευτυχούν."],["Αντωνυμία","Ἐκεῖνος ἔπραξε ταῦτα.","Εκείνος τα έπραξε αυτά."],["Αριθμητικό","Οἱ δέκα ἀπέθανον.","Οι δέκα σκοτώθηκαν."],["Μετοχή έναρθρη","Οἱ παρόντες ἐσιώπων.","Οι παρόντες σιωπούσαν."],["Απαρέμφατο","Τό ἀδικεῖν αἰσχρόν ἐστιν.","Το να αδικεί κανείς είναι αισχρό."],["Εμπρόθετος + άρθρο","Οἱ ἀμφί τόν Κῦρον ἔμενον.","Οι περί τον Κύρο έμεναν."],["Δευτερεύουσα πρόταση","Δῆλόν ἐστιν ὅτι σφάλλεται.","Είναι φανερό ότι σφάλλει."]]},"examples":[{"gr":"Τό λακωνίζειν ἐστί φιλοσοφεῖν.","an":"Υποκείμενο του <i>ἐστί</i> είναι το έναρθρο απαρέμφατο <i>τό λακωνίζειν</i>· το <i>φιλοσοφεῖν</i> (άναρθρο απαρέμφατο) είναι κατηγορούμενο."},{"gr":"Οἱ φεύγοντες πρός τά ὄρη ὥρμησαν.","an":"Η έναρθρη επιθετική μετοχή <i>οἱ φεύγοντες</i> έχει ουσιαστική αξία και λειτουργεί ως υποκείμενο του <i>ὥρμησαν</i>."},{"gr":"Ὅσοι ἐβούλοντο ἀπῆλθον.","an":"Ως υποκείμενο του <i>ἀπῆλθον</i> λειτουργεί η αναφορική πρόταση <i>ὅσοι ἐβούλοντο</i> (= οι όσοι ήθελαν)."},{"gr":"Οἱ ἀμφί τόν Κῦρον ἔμενον.","an":"Ως υποκείμενο του <i>ἔμενον</i> λειτουργεί ο εμπρόθετος με άρθρο <i>οἱ ἀμφί τόν Κῦρον</i> (= οι περί τον Κύρο), ουσιαστικοποιημένος."},{"gr":"Δῆλόν ἐστιν ὅτι οὐ ψεύδεται.","an":"Υποκείμενο της απρόσωπης έκφρασης <i>δῆλόν ἐστιν</i> είναι ολόκληρη η ειδική πρόταση <i>ὅτι οὐ ψεύδεται</i>."}],"note":"Όταν υποκείμενο είναι απαρέμφατο ή ουδέτερο, το κατηγορούμενο/επίθετο που το συνοδεύει μπαίνει σε ουδέτερο γένος: <i>τό ἀδικεῖν αἰσχρόν (ἐστιν)</i>."},{"h":"Το εννοούμενο / παραλειπόμενο υποκείμενο","body":"<p>Θεμελιώδης αρχή: <b>κάθε ρήμα έχει υποκείμενο</b>. Άλλοτε το υποκείμενο είναι <i>εκπεφρασμένο / ρητό</i> (γράφεται), άλλοτε <b>εννοείται (παραλείπεται)</b> αλλά υπάρχει πάντα νοητά. Στην ανάλυση οφείλουμε να το αποκαθιστούμε. Οι κύριες περιπτώσεις παράλειψης είναι οι εξής:</p><h3>α) Στο α΄ και β΄ πρόσωπο</h3><p>Παραλείπεται η προσωπική αντωνυμία (<i>ἐγώ, σύ, ἡμεῖς, ὑμεῖς</i>), γιατί δηλώνεται από την κατάληξη: <i>Πιστεύω</i> (ὑποκ.: <i>ἐγώ</i>), <i>θαυμάζομεν τόν γεωργόν</i> (ὑποκ.: <i>ἡμεῖς</i>).</p><h3>β) Όταν εννοείται από τα συμφραζόμενα</h3><p>Σε περιόδους με πολλές προτάσεις, αν το υποκείμενο είναι ήδη γνωστό από προηγούμενη πρόταση, παραλείπεται στις επόμενες: <i>Ὁ Κῦρος ἀνέβη ἐπί τά ὄρη καί (ἐνν. ὁ Κῦρος) εἶδε τό στράτευμα.</i></p><h3>γ) Σύστοιχο / ομόρριζο υποκείμενο</h3><p>Σε ορισμένα ρήματα το υποκείμενο εννοείται γιατί είναι ομόρριζο (της ίδιας ρίζας) με το ρήμα — το λεγόμενο <b>σύστοιχο υποκείμενο</b>: <i>ἐσάλπιγξε</i> (ὑποκ.: <i>ὁ σαλπιγκτής</i>), <i>ἐκήρυξε</i> (ὑποκ.: <i>ὁ κῆρυξ</i>).</p><h3>δ) Στα λέγουσι / φασί κ.τ.ό.</h3><p>Στα ρήματα του «λέγειν» στο γ΄ πληθυντικό χωρίς ρητό υποκείμενο, εννοείται γενικό-αόριστο υποκείμενο, η λέξη <b>ἄνθρωποι</b> (= «λένε», «οι άνθρωποι»): <i>φασί τόν Κῦρον δίκαιον εἶναι.</i></p><h3>ε) Στα δηλωτικά φυσικών φαινομένων</h3><p>Σε ρήματα όπως <i>ὕει</i> (βρέχει), <i>νίφει</i> (χιονίζει), <i>βροντᾷ, ἀστράπτει, σείει</i>, εννοείται ως υποκείμενο ο <b>θεός / Ζεύς</b>: <i>ὕει</i> = <i>ὁ Ζεύς / ὁ θεός ὕει</i>.</p>","examples":[{"gr":"Θαυμάζομεν τήν τοῦ ἀνδρός ἀνδρείαν.","an":"Υποκείμενο εννοούμενο <i>ἡμεῖς</i> (α΄ πληθυντικό)· αντικείμενο <i>τήν ἀνδρείαν</i>."},{"gr":"Ἐπεί ἐσάλπιγξε, προῆλθον οἱ ὁπλῖται.","an":"Στο <i>ἐσάλπιγξε</i> το υποκείμενο εννοείται σύστοιχο: <i>ὁ σαλπιγκτής</i>."},{"gr":"Λέγουσι τόν Σόλωνα σοφόν γενέσθαι.","an":"Εννοούμενο γενικό υποκείμενο <i>ἄνθρωποι</i>· το <i>τόν Σόλωνα... γενέσθαι</i> είναι ειδικό απαρέμφατο ως αντικείμενο."},{"gr":"Ἐν τοῖς ὄρεσιν ὕει.","an":"Φυσικό φαινόμενο· εννοούμενο υποκείμενο <i>ὁ Ζεύς / ὁ θεός</i>."},{"gr":"Ἐπεί δέ ἐσήμηνε, ἀνέστησαν.","an":"Σύστοιχο εννοούμενο υποκείμενο: στο <i>ἐσήμηνε</i> εννοείται <i>ὁ σαλπιγκτής</i> (αυτός που έδωσε το σύνθημα)· υποκ. του <i>ἀνέστησαν</i> εννοείται από τα συμφραζόμενα (οι στρατιώτες)."},{"gr":"Ὕει τε καί βροντᾷ.","an":"Δύο δηλωτικά φυσικών φαινομένων· σε αμφότερα (<i>ὕει</i>, <i>βροντᾷ</i>) εννοείται ως υποκείμενο <i>ὁ Ζεύς / ὁ θεός</i>."}],"note":"Παγίδα: το «εννοούμενο» υποκείμενο δεν σημαίνει «ανύπαρκτο». Στην πλήρη συντακτική ανάλυση πρέπει πάντοτε να το αποκαθιστάς ρητά. Διαφορετική περίπτωση είναι τα γνήσια απρόσωπα ρήματα (δεῖ, χρή), όπου υποκείμενο δεν εννοείται πρόσωπο αλλά είναι το απαρέμφατο — βλ. επόμενη ενότητα."},{"h":"Προσωπική και απρόσωπη σύνταξη","body":"<p>Ανάλογα με το είδος του υποκειμένου διακρίνουμε δύο συντάξεις.</p><h3>Προσωπική σύνταξη</h3><p><b>Προσωπική</b> είναι η σύνταξη όταν το ρήμα έχει ως υποκείμενο ένα <b>ορισμένο πρόσωπο ή πράγμα σε ονομαστική</b> (οποιοδήποτε από τα πρόσωπα). Είναι η συνηθισμένη, «κανονική» σύνταξη: <i>ὁ Σωκράτης διδάσκει</i>.</p><h3>Απρόσωπη σύνταξη</h3><p><b>Απρόσωπη</b> είναι η σύνταξη όταν το ρήμα χρησιμοποιείται μόνο στο <b>γ΄ ενικό πρόσωπο</b> και <u>δεν έχει ως υποκείμενο πρόσωπο ή πράγμα σε ονομαστική</u>, αλλά υποκείμενό του είναι ένα <b>απαρέμφατο</b> ή μια <b>δευτερεύουσα ονοματική πρόταση</b> (ειδική, βουλητική, ενδοιαστική, πλάγια ερωτηματική). Το χαρακτηριστικό κλειδί: <b>στην απρόσωπη σύνταξη δεν υπάρχει ποτέ ονομαστική υποκειμένου.</b></p><h3>Απρόσωπα ρήματα</h3><p>Άλλα είναι <b>καθαρά / γνήσια απρόσωπα</b> (απαντούν μόνο απρόσωπα): <i>δεῖ, χρή</i> (πρέπει), <i>ἔξεστι, πάρεστι, ἔνεστι</i> (είναι δυνατόν / επιτρέπεται), <i>μέλει</i> (ενδιαφέρει), <i>μέλλει, προσήκει, πρέπει</i>. Άλλα είναι <b>προσωπικά ρήματα που χρησιμοποιούνται και απρόσωπα</b>: <i>δοκεῖ</i> (φαίνεται καλό / αποφασίζεται), <i>συμβαίνει, συμφέρει, λέγεται, ἀγγέλλεται, ὁμολογεῖται, φαίνεται, ἐνδέχεται, ἐγχωρεῖ, ἀρκεῖ</i>.</p><h3>Απρόσωπες εκφράσεις</h3><p>Σχηματίζονται κυρίως με δύο τρόπους: (1) <b>ουδέτερο επιθέτου / αφηρημένο ουσιαστικό + ἐστί</b>: <i>ἀναγκαῖόν (ἐστι), δίκαιόν (ἐστι), δῆλόν (ἐστι), εἰκός (ἐστι), δέον (ἐστι), αἰσχρόν (ἐστι), χαλεπόν (ἐστι), ὥρα (ἐστί), ἀνάγκη (ἐστί)·</i> (2) <b>επίρρημα + ἔχει</b>: <i>καλῶς ἔχει, εὖ ἔχει, ῥᾳδίως ἔχει</i>.</p>","table":{"title":"Προσωπική vs Απρόσωπη σύνταξη","cols":["Γνώρισμα","Προσωπική","Απρόσωπη"],"rows":[["Ονομαστική υποκειμένου","Υπάρχει (ρητή ή εννοούμενη)","Δεν υπάρχει ποτέ"],["Υποκείμενο ρήματος","Πρόσωπο / πράγμα σε ονομαστική","Απαρέμφατο ή δευ/σα πρόταση"],["Πρόσωπο ρήματος","Όλα τα πρόσωπα","Μόνο γ΄ ενικό"],["Δοτική προσωπική","Όχι κατ' ανάγκην","Συχνά (= λογικό υποκείμενο)"]]},"examples":[{"gr":"Δεῖ τούς πολίτας πείθεσθαι τοῖς νόμοις.","an":"Απρόσωπη σύνταξη. Υποκείμενο του <i>δεῖ</i> είναι το απαρέμφατο <i>πείθεσθαι</i>· <i>τούς πολίτας</i> είναι υποκείμενο του απαρεμφάτου σε αιτιατική (ετεροπροσωπία)."},{"gr":"Δῆλόν ἐστιν ὅτι οἱ πολέμιοι φεύγουσιν.","an":"Απρόσωπη έκφραση <i>δῆλόν ἐστιν</i>· υποκείμενό της η ειδική πρόταση <i>ὅτι... φεύγουσιν</i>."},{"gr":"Ἔδοξε τῇ βουλῇ ψηφίσασθαι τόν νόμον.","an":"Απρόσωπο <i>ἔδοξε</i>· υποκείμενο το απαρέμφατο <i>ψηφίσασθαι</i>· η <i>τῇ βουλῇ</i> είναι δοτική προσωπική (το λογικό «υποκείμενο»: αυτός που αποφασίζει)."},{"gr":"Καλῶς ἔχει τό σιγᾶν ἐν καιρῷ.","an":"Απρόσωπη έκφραση <i>καλῶς ἔχει</i>· υποκείμενο το έναρθρο απαρέμφατο <i>τό σιγᾶν</i>."},{"gr":"Γράμματα μαθεῖν δεῖ.","an":"Μενάνδρου (τύπου) — Απρόσωπο <i>δεῖ</i>· υποκείμενο το απαρέμφατο <i>μαθεῖν</i>, με αντικείμενο <i>γράμματα</i>· καμία ονομαστική υποκειμένου."},{"gr":"Ἔξεστι τοῖς πολίταις ἐκκλησιάζειν.","an":"Γνήσια απρόσωπο <i>ἔξεστι</i> (= είναι δυνατόν)· υποκείμενο το απαρέμφατο <i>ἐκκλησιάζειν</i>· <i>τοῖς πολίταις</i> δοτική προσωπική."}],"note":"Προσοχή στη διπλή χρήση: το ίδιο ρήμα μπορεί να είναι προσωπικό ή απρόσωπο ανάλογα με το αν έχει ονομαστική. <i>Σωκράτης δοκεῖ σοφός εἶναι</i> = προσωπική (υποκ. <i>Σωκράτης</i>, «ο Σ. φαίνεται σοφός»). <i>Δοκεῖ μοι ἀπιέναι</i> = απρόσωπη (υποκ. το απαρ. <i>ἀπιέναι</i>). Κανόνας ασφαλείας: αν βρεις ονομαστική, η σύνταξη είναι προσωπική."},{"h":"Ταυτοπροσωπία και ετεροπροσωπία (το υποκείμενο του απαρεμφάτου)","body":"<p>Όταν από ένα ρήμα εξαρτάται απαρέμφατο, το απαρέμφατο έχει και αυτό δικό του υποκείμενο. Η σχέση του υποκειμένου του απαρεμφάτου με το υποκείμενο του ρήματος εξάρτησης ορίζει δύο φαινόμενα.</p><h3>Ταυτοπροσωπία</h3><p><b>Ταυτοπροσωπία</b> έχουμε όταν το υποκείμενο του απαρεμφάτου <b>ταυτίζεται</b> με το υποκείμενο του ρήματος εξάρτησης. Τότε το υποκείμενο του απαρεμφάτου <b>παραλείπεται</b> και, αν χρειαστεί να δηλωθεί (π.χ. επειδή συνοδεύεται από κατηγορούμενο), μπαίνει σε <b>ονομαστική</b>, σε συμφωνία με το υποκείμενο του ρήματος.</p><p><i>Ὁ Κῦρος νομίζει σοφός εἶναι.</i> — «Ο Κύρος νομίζει ότι είναι σοφός.» Υποκείμενο του <i>νομίζει</i> και του <i>εἶναι</i> είναι το ίδιο (<i>ὁ Κῦρος / ἐκεῖνος</i>)· γι' αυτό το κατηγορούμενο <i>σοφός</i> είναι σε <b>ονομαστική</b>.</p><h3>Ετεροπροσωπία</h3><p><b>Ετεροπροσωπία</b> έχουμε όταν το υποκείμενο του απαρεμφάτου είναι <b>διαφορετικό</b> από το υποκείμενο του ρήματος εξάρτησης. Τότε το υποκείμενο του απαρεμφάτου δηλώνεται ρητά και μπαίνει σε <b>αιτιατική</b> (και τα τυχόν κατηγορούμενα/προσδιορισμοί του ακολουθούν σε αιτιατική).</p><p><i>Ὁ Κῦρος νομίζει τούς στρατιώτας ἀνδρείους εἶναι.</i> — «Ο Κύρος νομίζει ότι οι στρατιώτες είναι ανδρείοι.» Εδώ το υποκείμενο του <i>εἶναι</i> (<i>τούς στρατιώτας</i>) διαφέρει από το υποκείμενο του <i>νομίζει</i> (<i>ὁ Κῦρος</i>)· γι' αυτό μπαίνει σε <b>αιτιατική</b>, όπως και το κατηγορούμενο <i>ἀνδρείους</i>.</p><h3>Σύνδεση με την απρόσωπη σύνταξη</h3><p>Στην <b>απρόσωπη σύνταξη υπάρχει πάντα ετεροπροσωπία</b>: αφού το απρόσωπο ρήμα δεν έχει δικό του υποκείμενο σε ονομαστική, το υποκείμενο του απαρεμφάτου (που είναι το ίδιο το υποκείμενο του απρόσωπου ρήματος ή χωριστό πρόσωπο) μπαίνει σε <b>αιτιατική</b>: <i>δεῖ τούς νέους πονεῖν</i>.</p>","table":{"title":"Ταυτοπροσωπία vs Ετεροπροσωπία","cols":["","Ταυτοπροσωπία","Ετεροπροσωπία"],"rows":[["Σχέση υποκειμένων","Ίδιο υποκ. ρήματος & απαρεμφάτου","Διαφορετικά υποκείμενα"],["Δήλωση υποκ. απαρεμφάτου","Παραλείπεται","Δηλώνεται ρητά"],["Πτώση υποκ. απαρεμφάτου","Ονομαστική","Αιτιατική"],["Πτώση κατηγορουμένου","Ονομαστική","Αιτιατική"]]},"examples":[{"gr":"Βούλομαι εἶναι δίκαιος.","an":"Ταυτοπροσωπία: υποκ. του <i>βούλομαι</i> και του <i>εἶναι</i> είναι το ίδιο (<i>ἐγώ</i>). Γι' αυτό το κατηγορούμενο <i>δίκαιος</i> μπαίνει σε ονομαστική."},{"gr":"Βούλομαι σέ εἶναι δίκαιον.","an":"Ετεροπροσωπία: υποκ. του <i>βούλομαι</i> είναι το <i>ἐγώ</i>, αλλά υποκ. του <i>εἶναι</i> είναι το <i>σέ</i> (αιτιατική)· το κατηγορούμενο <i>δίκαιον</i> ακολουθεί σε αιτιατική."},{"gr":"Νομίζω τούς θεούς πάντα ὁρᾶν.","an":"Ετεροπροσωπία: υποκ. του <i>νομίζω</i> = <i>ἐγώ</i>· υποκ. του απαρεμφάτου <i>ὁρᾶν</i> = <i>τούς θεούς</i> (αιτιατική)."},{"gr":"Δεῖ ἡμᾶς ἀνδρείους εἶναι.","an":"Απρόσωπο <i>δεῖ</i> → υποχρεωτική ετεροπροσωπία· υποκ. του απαρεμφάτου <i>ἡμᾶς</i> σε αιτιατική, κατηγ. <i>ἀνδρείους</i> σε αιτιατική."},{"gr":"Φησί σοφός εἶναι.","an":"Ταυτοπροσωπία: υποκ. του <i>φησί</i> και του ειδικού απαρεμφάτου <i>εἶναι</i> ταυτίζονται (<i>ἐκεῖνος</i>)· παραλείπεται, και το κατηγορούμενο <i>σοφός</i> μπαίνει σε ονομαστική."},{"gr":"Οἱ στρατιῶται ἔφασαν τόν στρατηγόν προδότην εἶναι.","an":"Ετεροπροσωπία: υποκ. του <i>ἔφασαν</i> = <i>οἱ στρατιῶται</i>, αλλά υποκ. του <i>εἶναι</i> = <i>τόν στρατηγόν</i> (αιτιατική)· κατηγ. <i>προδότην</i> σε αιτιατική."}],"note":"Διάγνωση πτώσης κατηγορουμένου: αν το κατηγορούμενο/επιθετικός προσδιορισμός που πάει με το απαρέμφατο είναι σε ονομαστική → ταυτοπροσωπία· αν είναι σε αιτιατική → ετεροπροσωπία. Αυτό λειτουργεί ως «δείκτης» όταν το υποκείμενο παραλείπεται."},{"h":"Ειδικές περιπτώσεις συμφωνίας: αττική σύνταξη και σχήμα κατά το νοούμενο","body":"<p>Πέρα από την κανονική συμφωνία υποκειμένου-ρήματος, η αρχαία ελληνική παρουσιάζει δύο χαρακτηριστικές αποκλίσεις, καθώς και ορισμένες ιδιαιτερότητες συμφωνίας.</p><h3>1) Αττική σύνταξη</h3><p>Όταν το υποκείμενο είναι <b>ουδετέρου γένους και πληθυντικού αριθμού</b>, το ρήμα τίθεται κανονικά στο <b>γ΄ ενικό</b> πρόσωπο (όχι πληθυντικό). Αυτό είναι το λεγόμενο <b>«αττικό σχήμα» / αττική σύνταξη</b>: <i>τά ζῷα τρέχει</i> (όχι «τρέχουσι»), <i>τά παιδία παίζει</i>. Η εξήγηση είναι ότι το ουδέτερο πληθυντικό γινόταν αντιληπτό ως ενιαίο σύνολο. (Στους ποιητές και σε υποκείμενα που δηλώνουν έμψυχα/πρόσωπα συναντάται και πληθυντικός ρήματος.)</p><h3>2) Σχήμα κατά το νοούμενο (κατά σύνεσιν)</h3><p>Όταν το υποκείμενο είναι <b>περιληπτικό ουσιαστικό</b> ενικού (<i>ὁ ὄχλος, τό πλῆθος, τό στρατόπεδον, ἡ πόλις, ἡ βουλή</i>), το ρήμα ή τα συμφωνούμενα μπορούν να τεθούν σε <b>πληθυντικό</b>, γιατί η συμφωνία γίνεται κατά το <i>νόημα</i> (πολλά άτομα) και όχι κατά τον γραμματικό τύπο (ενικός): <i>τό πλῆθος ἐψηφίσαντο πολεμεῖν</i>.</p><h3>3) Σχήμα Πινδαρικό / αρχαιοπρεπή</h3><p>Σε αρχαϊκό/ποιητικό λόγο, με δύο ή περισσότερα υποκείμενα συνδεδεμένα, το ρήμα μπορεί να συμφωνεί μόνο με το ένα (το κοντινότερο) ή να μπαίνει σε ενικό (<b>σχήμα Πινδαρικό</b>): <i>ἦν δ' αὐτῷ... ἵππος καί ὅπλα</i>.</p><h3>Συμφωνία με πολλά υποκείμενα</h3><p>Με <b>πολλά υποκείμενα</b> το ρήμα μπαίνει κανονικά σε πληθυντικό· ως προς το πρόσωπο προτιμάται το α΄ από το β΄ και το β΄ από το γ΄ (<i>ἐγώ καί σύ γράφομεν</i>). Όταν τα υποκείμενα είναι πράγματα, το ρήμα μπορεί να συμφωνεί με το πλησιέστερο.</p>","table":{"title":"Αποκλίσεις συμφωνίας υποκειμένου - ρήματος","cols":["Φαινόμενο","Συνθήκη","Συμφωνία ρήματος"],"rows":[["Αττική σύνταξη","Υποκ. ουδέτερο πληθυντικού","γ΄ ενικό (τά ζῷα τρέχει)"],["Κατά το νοούμενο","Περιληπτικό υποκ. ενικού","Πληθυντικός (τό πλῆθος ἦλθον)"],["Σχήμα Πινδαρικό","Πολλά υποκ. (ποιητ.)","Ενικός / με το πλησιέστερο"],["Πολλά πρόσωπα","α΄+β΄+γ΄","Επικρατεί το α΄, μετά το β΄"]]},"examples":[{"gr":"Τά ζῷα τρέχει.","an":"Αττική σύνταξη: ουδέτερο πληθυντικό υποκείμενο <i>τά ζῷα</i> με ρήμα σε γ΄ ενικό <i>τρέχει</i>."},{"gr":"Τό στρατόπεδον ἐν φόβῳ ἦσαν.","an":"Σχήμα κατά το νοούμενο: περιληπτικό <i>τό στρατόπεδον</i> (ενικός) με ρήμα <i>ἦσαν</i> σε πληθυντικό, γιατί νοείται ως πλήθος στρατιωτών."},{"gr":"Ὁ δῆμος ἐψηφίσαντο πολεμεῖν.","an":"Κατά σύνεσιν: <i>ὁ δῆμος</i> ενικός, αλλά το ρήμα <i>ἐψηφίσαντο</i> σε πληθυντικό (πολλοί πολίτες)."},{"gr":"Ἐγώ καί σύ ταῦτα πράττομεν.","an":"Δύο υποκείμενα α΄ και β΄ προσώπου· επικρατεί το α΄, ρήμα σε α΄ πληθυντικό <i>πράττομεν</i>."},{"gr":"Τά τέλη τῶν Λακεδαιμονίων αὐτόν ἐξέπεμψαν.","an":"Θουκ. 4.88 (πβ. Smyth §959) — Ουδέτερο πληθυντικό υποκείμενο <i>τά τέλη</i> (= οι άρχοντες) με ρήμα σε πληθυντικό <i>ἐξέπεμψαν</i>, γιατί τονίζεται ότι πρόκειται για πρόσωπα· εξαίρεση στην αττική σύνταξη."},{"gr":"Τό πλῆθος ἐβόων κελεύοντες ἀναβαίνειν.","an":"Σχήμα κατά το νοούμενο: το περιληπτικό <i>τό πλῆθος</i> (ενικός) συντάσσεται με ρήμα <i>ἐβόων</i> και μετοχή <i>κελεύοντες</i> σε πληθυντικό (κατά σύνεσιν)."}],"note":"Η αττική σύνταξη (ουδ. πληθ. → ρήμα ενικό) και το σχήμα κατά το νοούμενο (περιληπτικό ενικ. → ρήμα πληθ.) είναι αντίστροφα φαινόμενα και αγαπημένο θέμα εξετάσεων· να τα αναγνωρίζεις και να τα ονομάζεις σωστά στην ανάλυση."}]);
  T("syn-katigoroumeno", [{"h":"Ορισμός — Τι είναι το κατηγορούμενο","body":"<p><b>Κατηγορούμενο</b> είναι το <b>όνομα</b> (ουσιαστικό ή επίθετο, και κατ' επέκταση μετοχή, αντωνυμία, αριθμητικό, απαρέμφατο ή και ολόκληρη πρόταση) που, <b>μέσω ενός συνδετικού (ή και άλλου) ρήματος</b>, αποδίδει μια <i>ιδιότητα, ποιότητα ή κατάσταση</i> στο υποκείμενο ή στο αντικείμενο του ρήματος. Με άλλα λόγια, το κατηγορούμενο «κατηγορεί» κάτι για ένα όνομα — λέει <i>τι είναι</i> ή <i>τι λογής είναι</i> αυτό το όνομα.</p><p>Η λέξη προέρχεται από το ρήμα <i>κατηγορῶ</i> με την αρχική του σημασία «λέω/αποδίδω κάτι για κάποιον» (όχι «κατηγορώ» = ψέγω). Στη λογική του Αριστοτέλη το κατηγόρημα είναι ό,τι αποδίδεται (κατηγορείται) για ένα υποκείμενο.</p><p><b>Βασική προϋπόθεση:</b> το κατηγορούμενο δεν εκφράζει αυθύπαρκτη ενέργεια· για να υπάρξει χρειάζεται <b>πάντοτε ρήμα</b> που να «γεφυρώνει» το όνομα με την ιδιότητα. Στην τυπική περίπτωση το ρήμα αυτό είναι <b>συνδετικό</b> (κυρίως το <i>εἰμί</i> και τα συνώνυμά του). Η ίδια ιδιότητα, όταν αποδίδεται <i>χωρίς</i> ρήμα, δεν είναι κατηγορούμενο αλλά <b>προσδιορισμός</b> (βλ. το αντίστοιχο κεφάλαιο για τη διάκριση).</p><p><b>Συμφωνία:</b> κατά κανόνα το κατηγορούμενο συμφωνεί με τον όρο που χαρακτηρίζει (υποκείμενο ή αντικείμενο) στην <b>πτώση</b>· όταν είναι επίθετο/μετοχή, συμφωνεί επιπλέον στο <b>γένος</b> και στον <b>αριθμό</b>· όταν είναι ουσιαστικό, μπορεί να διαφέρει στο γένος και στον αριθμό (συμφωνία μόνο στην πτώση).</p>","examples":[{"gr":"Ὁ Σωκράτης ἐστί σοφός.","an":"Ὁ Σωκράτης = υποκ., ἐστί = συνδετικό ρ., σοφός = κατηγορούμενο του υποκ. (ονομαστική, συμφωνεί σε πτώση-γένος-αριθμό). Ερώτηση: «τι λογής εἶναι ο Σωκράτης;» → σοφός. «Ο Σωκράτης είναι σοφός.»"},{"gr":"Ὁ Ἀριστείδης ἦν δίκαιος.","an":"δίκαιος = κατηγορούμενο (επίθετο) του υποκ. Ἀριστείδης μέσω του συνδετικού ἦν. «Ο Αριστείδης ήταν δίκαιος.»"},{"gr":"Ἡ ἀρετή καλόν ἐστιν.","an":"καλόν (ουδ.) = κατηγορούμενο· εδώ το ουδέτερο επιθέτου χρησιμοποιείται γενικευτικά («κάτι ωραίο»). «Η αρετή είναι (κάτι) ωραίο.»"},{"gr":"Ξενοφῶν ἦν Ἀθηναῖος.","an":"(τύπου) — Ξενοφῶν = υποκ., ἦν = συνδετικό, Ἀθηναῖος = κατηγ. υποκ. (ονομ.), συμφωνεί σε πτώση. «Ο Ξενοφών ήταν Αθηναίος.»"},{"gr":"Πλάτων ἔφη τόν θεόν γεωμετρεῖν.","an":"(τύπου Πλάτ.) — δείχνει την αρχική σημασία του «λέω/αποδίδω»· εδώ όμως το κατηγ. φαίνεται καθαρά στο: Ὁ νόμος ἐστί βασιλεύς (νόμος = υποκ., βασιλεύς = κατηγ. υποκ., ονομ.). «Ο νόμος είναι βασιλιάς.»"}],"note":"Προσοχή στη σημασία του όρου: «κατηγορώ» στο συντακτικό σημαίνει «αποδίδω/λέω για», όχι «μέμφομαι». Το κατηγορούμενο απαντά στο ερώτημα «τι / τι λογής + ρήμα + υποκείμενο;»."},{"h":"Τα συνδετικά ρήματα — πλήρης κατάλογος","body":"<p><b>Συνδετικά</b> (ή <i>συνδετικά–κατηγορηματικά</i>) ονομάζονται τα ρήματα που από μόνα τους έχουν ασθενές ή ελλιπές νόημα και απλώς «συνδέουν» το υποκείμενο (ή το αντικείμενο) με το κατηγορούμενο, χωρίς το οποίο η πρόταση μένει νοηματικά ατελής. Διακρίνονται στις εξής κατηγορίες:</p><h3>α) Το <i>εἰμί</i> και τα συνώνυμά του («είμαι / γίνομαι / αποδεικνύομαι»)</h3><p><i>εἰμί, γίγνομαι, καθίσταμαι, ὑπάρχω, πέλω/πέλομαι, τυγχάνω, διατελῶ, ἔφυν, πέφυκα, ἀποβαίνω, ἐκβαίνω</i> (καθώς και <i>γίγνομαι/κυρῶ, φαίνομαι, δοκῶ</i>). Πολλά από αυτά κρατούν και κάποια δική τους σημασία (π.χ. <i>τυγχάνω</i> = «είμαι τυχαία», <i>διατελῶ</i> = «είμαι συνεχώς»), η οποία προστίθεται στη σχέση υποκειμένου–κατηγορουμένου.</p><h3>β) Δοξαστικά (γνώμης/κρίσης)</h3><p>Ενεργητικά: <i>νομίζω, ἡγοῦμαι, κρίνω, ὑπολαμβάνω, οἴομαι/οἶμαι, ἡγοῦμαι</i> (δίνουν <b>κατηγορούμενο του αντικειμένου</b>). Παθητικά / αμετάβατα: <i>φαίνομαι, δοκῶ, νομίζομαι, κρίνομαι</i> (δίνουν <b>κατηγορούμενο του υποκειμένου</b>).</p><h3>γ) Κλητικά (ονομασίας)</h3><p>Ενεργητικά: <i>καλῶ, λέγω, ὀνομάζω, προσαγορεύω, ἀποκαλῶ</i>. Παθητικά: <i>καλοῦμαι, λέγομαι, ὀνομάζομαι, προσαγορεύομαι, ἀκούω</i> (=ακούγομαι ότι είμαι).</p><h3>δ) Εκλογής / ανάδειξης (διορισμού)</h3><p>Ενεργητικά: <i>αἱροῦμαι (=εκλέγω), χειροτονῶ, ἀποδείκνυμι, ἀποφαίνω, καθίστημι, ποιῶ</i>. Παθητικά: <i>αἱροῦμαι (=εκλέγομαι), χειροτονοῦμαι, λαγχάνω, ἀποδείκνυμαι, καθίσταμαι, ἀποφαίνομαι</i>.</p><p><b>Σημαντικός κανόνας:</b> τα ρήματα των κατηγοριών β, γ, δ είναι <b>δίπτωτα</b> στην ενεργητική φωνή (παίρνουν αντικείμενο + κατηγορούμενο του αντικειμένου, και τα δύο σε <b>αιτιατική</b>). Στην παθητική φωνή το αντικείμενο γίνεται υποκείμενο και το κατηγορούμενο γίνεται κατηγορούμενο του υποκειμένου (<b>ονομαστική</b>).</p>","table":{"title":"Κατηγορίες συνδετικών ρημάτων","cols":["Κατηγορία","Ενεργητικά (→ κατηγ. αντικειμένου, αιτ.)","Παθητικά/αμετάβατα (→ κατηγ. υποκειμένου, ονομ.)"],"rows":[["εἰμί & συνώνυμα","—","εἰμί, γίγνομαι, καθίσταμαι, ὑπάρχω, τυγχάνω, διατελῶ, πέφυκα, ἔφυν, ἀποβαίνω, ἐκβαίνω"],["Δοξαστικά","νομίζω, ἡγοῦμαι, κρίνω, ὑπολαμβάνω, οἴομαι","φαίνομαι, δοκῶ, νομίζομαι, κρίνομαι"],["Κλητικά","καλῶ, λέγω, ὀνομάζω, προσαγορεύω","καλοῦμαι, λέγομαι, ὀνομάζομαι, ἀκούω"],["Εκλογής/διορισμού","αἱροῦμαι, χειροτονῶ, ἀποδείκνυμι, ποιῶ, καθίστημι","αἱροῦμαι, χειροτονοῦμαι, λαγχάνω, ἀποδείκνυμαι, καθίσταμαι"]]},"examples":[{"gr":"Κῦρος βασιλεύς κατέστη.","an":"κατέστη (συνώνυμο του γίγνομαι) = συνδετικό· βασιλεύς = κατηγ. υποκ. «Ο Κύρος έγινε βασιλιάς.»"},{"gr":"Οὗτος ἀνήρ ἀγαθός ἔφυ.","an":"ἔφυ (= είναι εκ φύσεως) = συνδετικό· ἀγαθός = κατηγ. υποκ. «Αυτός είναι εκ φύσεως ενάρετος.»"},{"gr":"Ὁ Περικλῆς ἐτύγχανε στρατηγός ὤν.","an":"ἐτύγχανε...ὤν = συνδετικό (τυγχάνω + μετοχή ὤν)· στρατηγός = κατηγ. υποκ. «Ο Περικλής έτυχε να είναι στρατηγός.»"},{"gr":"Ὁ ἀνήρ ὠνομάζετο σοφιστής.","an":"ὠνομάζετο (παθητ. κλητικό) = συνδετικό· σοφιστής = κατηγ. υποκ. (ονομ.) — παθητική σύνταξη κλητικού ρήματος. «Ο άνδρας ονομαζόταν σοφιστής.»"},{"gr":"Ἐκ τούτου ἡ Ἑλλάς ἤδη πάντα ἀσφαλέστερα κατέστη.","an":"(τύπου Θουκ.) — κατέστη (= γίγνομαι) = συνδετικό· ἀσφαλέστερα = κατηγ. υποκ. (ονομ. πληθ. ουδ.). «Από τότε όλα στην Ελλάδα έγιναν ασφαλέστερα.»"}],"note":"Όταν λείπει το συνδετικό ρήμα (συνήθως το ἐστί / εἰσί), εννοείται· π.χ. «μέτρον ἄριστον» = (ἐστί) μέτρον ἄριστον. Το κατηγορούμενο εξακολουθεί να υπάρχει με εννοούμενο συνδετικό."},{"h":"Κατηγορούμενο του υποκειμένου","body":"<p>Λέγεται έτσι το κατηγορούμενο που, μέσω <b>μονόπτωτου συνδετικού</b> ρήματος (εἰμί και συνώνυμα, ή παθητικά δοξαστικά/κλητικά/εκλογής), αποδίδει ιδιότητα στο <b>υποκείμενο</b>. Τίθεται σε <b>ονομαστική</b> πτώση (ή σε πτώση που επιβάλλει ο τύπος του υποκειμένου, π.χ. αιτιατική στο υποκείμενο ειδικού/τελικού απαρεμφάτου).</p><h3>Μέρη του λόγου ως κατηγορούμενο υποκειμένου</h3><ul><li><b>Επίθετο:</b> <i>Ὁ Ἀριστείδης ἦν δίκαιος.</i></li><li><b>Ουσιαστικό:</b> <i>Ἡ πόλις φρούριον κατέστη.</i></li><li><b>Μετοχή:</b> <i>Εἰμί τυράννῳ ἐοικώς.</i> (= μοιάζω με τύραννο)</li><li><b>Απαρέμφατο:</b> <i>Τό λακωνίζειν ἐστί φιλοσοφεῖν.</i></li><li><b>Αντωνυμία / αριθμητικό / επίρρημα / ολόκληρη πρόταση.</b></li></ul><h3>Ταυτοπροσωπία στο απαρέμφατο</h3><p>Όταν το υποκείμενο του ρήματος εξάρτησης ταυτίζεται με το (εννοούμενο) υποκείμενο του ειδικού απαρεμφάτου (<b>ταυτοπροσωπία</b>), το κατηγορούμενο μπαίνει σε <b>ονομαστική</b>· σε <b>ετεροπροσωπία</b> μπαίνει σε <b>αιτιατική</b>, συμφωνώντας με το αιτιατικό υποκείμενο του απαρεμφάτου.</p>","examples":[{"gr":"Ἡ πόλις φρούριον κατέστη.","an":"Ἡ πόλις = υποκ., κατέστη = συνδετικό, φρούριον (ουσιαστ., ονομ. ουδ.) = κατηγ. υποκ. — συμφωνεί μόνο σε πτώση. «Η πόλη έγινε φρούριο.»"},{"gr":"Οὗτος ὁ ἀνήρ νομίζεται σοφός.","an":"νομίζεται (παθητ. δοξαστικό) = συνδετικό· σοφός = κατηγ. υποκ. (ονομ.). «Αυτός ο άνδρας θεωρείται σοφός.»"},{"gr":"Νομίζω σοφός εἶναι.","an":"Ταυτοπροσωπία: το υποκ. του νομίζω (εγώ) = υποκ. του εἶναι. Άρα σοφός σε ονομαστική = κατηγ. υποκ. του απαρεμφάτου. «Νομίζω ότι είμαι σοφός.»"},{"gr":"Νομίζω Σωκράτη σοφόν εἶναι.","an":"Ετεροπροσωπία: Σωκράτη (αιτ.) = υποκ. του εἶναι· σοφόν (αιτ.) = κατηγ. υποκ., συμφωνεί με το αιτ. υποκείμενο. «Νομίζω ότι ο Σωκράτης είναι σοφός.»"},{"gr":"Ὁ ἀνήρ ὠνομάζετο σοφιστής.","an":"ὠνομάζετο (παθητ. κλητικό, μονόπτωτο) = συνδετικό· σοφιστής = κατηγ. υποκ. (ονομ.). «Ο άνδρας ονομαζόταν σοφιστής.»"},{"gr":"Δαρείου καί Παρυσάτιδος γίγνονται παῖδες δύο.","an":"Ξεν. Ἀνάβ. 1.1.1 — γίγνονται = συνδετικό· παῖδες δύο = κατηγ. υποκ. (ονομ. πληθ.), συμφωνεί σε πτώση. «Από τον Δαρείο και την Παρύσατι γεννιούνται δύο παιδιά.»"}],"note":"Το κατηγορούμενο υποκειμένου ΔΕΝ παίρνει ποτέ άρθρο όταν λειτουργεί ως κατηγορούμενο (το άρθρο θα το έκανε υποκείμενο ή επιθετικό προσδιορισμό). Π.χ. «Ὁ Σωκράτης ἐστί ὁ σοφός» = ταυτότητα/υποκείμενο, όχι απλό κατηγορούμενο."},{"h":"Κατηγορούμενο του αντικειμένου","body":"<p>Λέγεται έτσι το κατηγορούμενο που αποδίδει ιδιότητα στο <b>αντικείμενο</b> του ρήματος, μέσω ενός <b>δίπτωτου</b> ρήματος (κλητικού, δοξαστικού ή εκλογής σε ενεργητική φωνή). Το ρήμα αυτό παίρνει ταυτόχρονα <b>αντικείμενο σε αιτιατική</b> και <b>κατηγορούμενο σε αιτιατική</b>· τα δύο συμφωνούν μεταξύ τους σε πτώση (και, αν είναι επίθετο, σε γένος-αριθμό).</p><p>Με τη μετατροπή της πρότασης στην <b>παθητική σύνταξη</b>, το αντικείμενο γίνεται υποκείμενο (ονομαστική) και, αντίστοιχα, το κατηγορούμενο του αντικειμένου γίνεται κατηγορούμενο του υποκειμένου (ονομαστική). Η παρατήρηση αυτή είναι το ασφαλέστερο τεστ αναγνώρισης.</p><h3>Ρήματα που παίρνουν κατηγορούμενο αντικειμένου</h3><ul><li><b>Κλητικά:</b> καλῶ, ὀνομάζω, λέγω, προσαγορεύω, ἀποκαλῶ — «αποκαλώ κάποιον κάτι».</li><li><b>Δοξαστικά:</b> νομίζω, ἡγοῦμαι, κρίνω, ὑπολαμβάνω, οἴομαι — «θεωρώ κάποιον κάτι».</li><li><b>Εκλογής/διορισμού:</b> αἱροῦμαι (εκλέγω), χειροτονῶ, ἀποδείκνυμι, ποιῶ, καθίστημι, ἀποφαίνω — «εκλέγω/καθιστώ κάποιον κάτι».</li><li><b>Ρήματα του «έχω/κρατώ ως»:</b> ἔχω, παρέχω, παρέχομαι (+ κατηγ. αντικειμένου).</li></ul>","examples":[{"gr":"Οὗτοι καλοῦσιν αὐτούς νομοθέτας.","an":"καλοῦσιν (κλητικό, ενεργ.) = ρ.· αὐτούς (αιτ.) = αντικ.· νομοθέτας (αιτ.) = κατηγ. αντικειμένου. «Αυτοί τους αποκαλούν νομοθέτες.» Παθητικά: οὗτοι καλοῦνται νομοθέται."},{"gr":"Τόν Σωκράτη πάντες σοφόν ἐνόμιζον.","an":"ἐνόμιζον (δοξαστικό) = ρ.· τόν Σωκράτη = αντικ. (αιτ.)· σοφόν (αιτ.) = κατηγ. αντικειμένου. «Όλοι θεωρούσαν τον Σωκράτη σοφό.»"},{"gr":"Οἱ Ἀθηναῖοι Περικλέα στρατηγόν εἵλοντο.","an":"εἵλοντο (αἱροῦμαι = εκλέγω, εκλογής) = ρ.· Περικλέα = αντικ.· στρατηγόν = κατηγ. αντικειμένου. «Οι Αθηναίοι εξέλεξαν τον Περικλή στρατηγό.»"},{"gr":"Τήν πόλιν ἐλευθέραν ἐποίησαν.","an":"ἐποίησαν (= κατέστησαν) = ρ.· τήν πόλιν = αντικ.· ἐλευθέραν (επίθ., αιτ. θηλ.) = κατηγ. αντικειμένου, συμφωνεί σε πτώση-γένος-αριθμό. «Έκαναν την πόλη ελεύθερη.»"},{"gr":"Οἱ στρατιῶται εἵλοντο Ξενοφῶντα στρατηγόν.","an":"(τύπου Ξεν. Ἀνάβ. 3.1.47) — εἵλοντο (εκλογής) = ρ.· Ξενοφῶντα = αντικ. (αιτ.)· στρατηγόν = κατηγ. αντικειμένου (αιτ.). «Οι στρατιώτες εξέλεξαν τον Ξενοφώντα στρατηγό.»"},{"gr":"Οἱ Ἕλληνες ὠνόμαζον τάς Ἀθήνας ἄστυ.","an":"ὠνόμαζον (κλητικό) = ρ.· τάς Ἀθήνας = αντικ. (αιτ.)· ἄστυ = κατηγ. αντικειμένου (αιτ. ουδ.). «Οι Έλληνες ονόμαζαν την Αθήνα “άστυ”.»"}],"note":"Διάκριση από τη διπλή αιτιατική προσώπου-πράγματος (π.χ. διδάσκω τινά τι): εκεί έχουμε δύο διαφορετικά αντικείμενα, όχι αντικείμενο + κατηγορούμενο. Στο κατηγορούμενο αντικειμένου οι δύο αιτιατικές αναφέρονται στο ΙΔΙΟ πρόσωπο/πράγμα."},{"h":"Γενική κατηγορηματική","body":"<p><b>Γενική κατηγορηματική</b> είναι μια <b>γενική ουσιαστικού</b> που, μέσω συνδετικού ρήματος (κυρίως <i>εἰμί, γίγνομαι, ποιοῦμαι, νομίζω</i> κ.λπ.), λειτουργεί ως κατηγορούμενο — δηλαδή αποδίδει στο υποκείμενο (ή αντικείμενο) μια ιδιότητα που, αντί για ονομαστική, εκφέρεται με γενική. Είναι το «κατηγορούμενο σε πτώση γενική». Συνηθέστατα μεταφράζεται με «ανήκω σε / είμαι μέρος / αξίζω / αποτελούμαι από / έχω ηλικία».</p><p>Αναγνωρίζεται με την ερώτηση «<i>τι / τι λογής + ρήμα + υποκείμενο;</i>» όπως και το κανονικό κατηγορούμενο — η απάντηση όμως δίνεται σε γενική.</p><h3>Είδη της γενικής κατηγορηματικής</h3><ul><li><b>Κτητική</b> (κατοχή, σε ποιον ανήκει): <i>Ὁ ἀγρός ἐστι Τιμοξένου.</i></li><li><b>Διαιρετική</b> (μέρος ενός συνόλου): <i>Ἀγησίλαος ἦν τῶν στρατηγῶν.</i></li><li><b>Ύλης</b> (από τι υλικό): <i>Ὁ στέφανός ἐστι χρυσοῦ.</i></li><li><b>Ιδιότητας</b> (χαρακτηριστικό γνώρισμα / γνώμη): <i>Πολλοί ἦσαν τῆς αὐτῆς γνώμης.</i></li><li><b>Αξίας</b> (πόσο αξίζει): <i>Ὁ σῖτος ἦν ταλάντου.</i></li><li><b>Καταγωγής</b> (από ποιον προέρχεται): <i>τοιούτων ἐστέ προγόνων.</i></li><li><b>Ηλικίας</b> (πόσων ετών): <i>Ὁ παῖς ἦν δέκα ἐτῶν.</i></li></ul>","table":{"title":"Είδη γενικής κατηγορηματικής","cols":["Είδος","Δηλώνει","Παράδειγμα","Μετάφραση"],"rows":[["Κτητική","κατοχή / σε ποιον ανήκει","Ὁ ἀγρός ἐστι Τιμοξένου","Ο αγρός ανήκει στον Τιμόξενο"],["Διαιρετική","μέρος συνόλου","Ἀγησίλαος ἦν τῶν στρατηγῶν","Ο Αγησίλαος ήταν ένας από τους στρατηγούς"],["Ύλης","υλικό σύστασης","Ὁ στέφανός ἐστι χρυσοῦ","Το στεφάνι είναι από χρυσό"],["Ιδιότητας","γνώρισμα / γνώμη","Πολλοί ἦσαν τῆς αὐτῆς γνώμης","Πολλοί είχαν την ίδια γνώμη"],["Αξίας","τιμή / αξία","Ὁ σῖτος ἦν ταλάντου","Το σιτάρι άξιζε ένα τάλαντο"],["Καταγωγής","προέλευση","Τοιούτων ἐστέ προγόνων","Είστε απόγονοι τέτοιων προγόνων"],["Ηλικίας","ηλικία","Ὁ παῖς ἦν δέκα ἐτῶν","Το παιδί ήταν δέκα ετών"]]},"examples":[{"gr":"Ἡ νῆσος ἦν τῶν Ἀθηναίων.","an":"τῶν Ἀθηναίων = γενική κατηγορηματική κτητική (μέσω του ἦν). «Το νησί ανήκε στους Αθηναίους.»"},{"gr":"Σόλων τῶν ἑπτά σοφῶν ἐνομίζετο.","an":"τῶν ἑπτά σοφῶν = γεν. κατηγ. διαιρετική (μέσω παθ. δοξαστικού ἐνομίζετο). «Ο Σόλων θεωρούνταν ένας από τους επτά σοφούς.»"},{"gr":"Τό τεῖχος ἦν λίθων.","an":"λίθων = γεν. κατηγ. ύλης. «Το τείχος ήταν από πέτρες.»"},{"gr":"Ἦν δέ καί ὁ Μένων τῶν στρατηγῶν.","an":"(τύπου Ξεν. Ἀνάβ.) — τῶν στρατηγῶν = γεν. κατηγ. διαιρετική (μέσω ἦν). «Ήταν και ο Μένων ένας από τους στρατηγούς.»"},{"gr":"Ὁ παῖς ἦν περί τά δέκα ἔτη γεγονώς.","an":"(τύπου) — δηλώνει ηλικία· πρβλ. γεν. κατηγ. ηλικίας: ἦν ἐτῶν τεσσαράκοντα (= ήταν σαράντα ετών). «Το παιδί ήταν περίπου δέκα ετών.»"}],"note":"Διάκριση από τη γενική ως απλό ονοματικό προσδιορισμό: στη γενική κατηγορηματική υπάρχει ΡΗΜΑ (συνδετικό) που γεφυρώνει τη γενική με το υποκείμενο. Σύγκρινε: «ὁ τοῦ Τιμοξένου ἀγρός» (κτητική γενική ως επιθετικός προσδ., χωρίς ρήμα) ≠ «ὁ ἀγρός ἐστι Τιμοξένου» (γεν. κατηγορηματική κτητική)."},{"h":"Επιρρηματικό κατηγορούμενο","body":"<p><b>Επιρρηματικό κατηγορούμενο</b> είναι το κατηγορούμενο που <b>δεν εξαρτάται από συνδετικό ρήμα</b>, αλλά από ρήμα <b>κίνησης, ενέργειας ή σκόπιμης πράξης</b> (και γενικά από οποιοδήποτε ρήμα με πλήρες νόημα). Αν και τυπικά είναι κατηγορούμενο (επίθετο που συμφωνεί με το υποκείμενο σε πτώση-γένος-αριθμό), νοηματικά λειτουργεί σαν <b>επιρρηματικός προσδιορισμός</b> του ρήματος — γι' αυτό και μεταφράζεται συνήθως με επίρρημα ή εμπρόθετο.</p><p>Π.χ. στο «<i>ὁ ἄγγελος ἀφίκετο τριταῖος</i>» το <i>τριταῖος</i> τυπικά χαρακτηρίζει τον άγγελο, αλλά νοηματικά δηλώνει τον χρόνο της άφιξης («την τρίτη μέρα»). Αυτό το διπλό χαρακτηριστικό (επίθετο που λειτουργεί ως επίρρημα) είναι το ιδιαίτερο γνώρισμά του.</p><h3>Σημασιολογικές κατηγορίες (και τα τυπικά επίθετα)</h3><ul><li><b>Τρόπου:</b> ἑκών / ἑκούσιος, ἄκων / ἀκούσιος, ἄσμενος, ἀθρόος, ἐθελοντής, ἐναντίος, ὑπόσπονδος, ὅρκιος.</li><li><b>Τόπου:</b> ὑπαίθριος, πελάγιος, μετέωρος, ἐφέστιος, θυραῖος, χερσαῖος.</li><li><b>Χρόνου:</b> ὄρθιος (= το πρωί), σκοταῖος (= μέσα στο σκοτάδι), ἡμερήσιος, ἑσπέριος, χθεσινός, τριταῖος.</li><li><b>Σκοπού:</b> βοηθός, φύλαξ, διδάσκαλος, δικαστής, πρεσβευτής, σύμμαχος.</li><li><b>Τάξης / σειράς:</b> πρῶτος, δεύτερος, τελευταῖος, ὕστατος, τριταῖος.</li></ul>","table":{"title":"Επιρρηματικό κατηγορούμενο — κατηγορίες","cols":["Σημασία","Τυπικά επίθετα","Παράδειγμα"],"rows":[["Τρόπου","ἑκών, ἄκων, ἄσμενος, ἀθρόος, ἐθελοντής","Δημαγόρας ἐστράτευσεν ἐθελοντής"],["Τόπου","ὑπαίθριος, πελάγιος, μετέωρος, θυραῖος","Οἱ στρατιῶται ἐσκήνουν ὑπαίθριοι"],["Χρόνου","ὄρθιος, σκοταῖος, ἑσπέριος, τριταῖος","Ὁ ἄγγελος ἀφίκετο τριταῖος"],["Σκοπού","βοηθός, φύλαξ, σύμμαχος, πρεσβευτής","Ἦλθον σύμμαχοι τοῖς Ἀθηναίοις"],["Τάξης","πρῶτος, δεύτερος, τελευταῖος, ὕστατος","Πρῶτος ἀφίκετο εἰς τήν πόλιν"]]},"examples":[{"gr":"Ὁ ἄγγελος ἀφίκετο τριταῖος.","an":"ἀφίκετο = ρ. κίνησης (όχι συνδετικό)· τριταῖος = επιρρ. κατηγ. χρόνου, συμφωνεί με τον άγγελο αλλά μεταφράζεται επιρρηματικά. «Ο αγγελιαφόρος έφτασε την τρίτη μέρα.»"},{"gr":"Οἱ στρατιῶται ἐσκήνουν ὑπαίθριοι.","an":"ὑπαίθριοι = επιρρ. κατηγ. τόπου. «Οι στρατιώτες στρατοπέδευαν στο ύπαιθρο.»"},{"gr":"Σωκράτης ἑκών ἀπέθανεν.","an":"ἑκών = επιρρ. κατηγ. τρόπου (= θεληματικά). «Ο Σωκράτης πέθανε με τη θέλησή του.»"},{"gr":"Πρῶτος ὁ Μιλτιάδης δρόμῳ ἐπέδραμεν.","an":"πρῶτος = επιρρ. κατηγ. τάξης. «Πρώτος ο Μιλτιάδης όρμησε τρέχοντας.»"},{"gr":"Κῦρος ἄσμενος ἑώρα τούς Ἕλληνας νικῶντας.","an":"(τύπου Ξεν.) — ἑώρα = ρ. πλήρους σημασίας· ἄσμενος = επιρρ. κατηγ. τρόπου (= με ευχαρίστηση), συμφωνεί με το Κῦρος. «Ο Κύρος έβλεπε με ευχαρίστηση τους Έλληνες να νικούν.»"},{"gr":"Σωκράτης καί Πρωταγόρας ἀντίοι ἐκάθηντο.","an":"(τύπου Πλάτ.) — ἐκάθηντο = ρ. ενέργειας· ἀντίοι = επιρρ. κατηγ. τόπου/τρόπου (= αντικριστά). «Ο Σωκράτης και ο Πρωταγόρας κάθονταν αντικριστά.»"}],"note":"Τεστ: αν αφαιρέσεις το επίθετο, το ρήμα στέκει νοηματικά μόνο του (ρήμα πλήρους σημασίας) → επιρρηματικό κατηγορούμενο. Αν το ρήμα είναι συνδετικό και χωρίς το όνομα μένει ατελές → κανονικό κατηγορούμενο. Επίσης: αν το επίθετο γίνεται εύκολα επίρρημα (ἑκών→ἑκουσίως), συνήθως είναι επιρρηματικό κατηγορούμενο."},{"h":"Προληπτικό κατηγορούμενο","body":"<p><b>Προληπτικό</b> (ή <b>κατηγορούμενο του αποτελέσματος</b>) είναι το κατηγορούμενο που αποδίδει στο υποκείμενο μια ιδιότητα την οποία αυτό <b>δεν έχει ακόμη</b> τη στιγμή της ενέργειας, αλλά θα την <b>αποκτήσει ως αποτέλεσμα</b> της ενέργειας του ρήματος. Λέγεται «προληπτικό» γιατί ο ομιλητής «προλαμβάνει» (προαναγγέλλει) το τελικό αποτέλεσμα, σαν να έχει ήδη συμβεί.</p><p>Συντάσσεται κυρίως με ρήματα που δηλώνουν <b>εξέλιξη, αύξηση, ανατροφή, καλλιέργεια, κατασκευή</b>. Στη μετάφραση αναλύεται με <b>συμπερασματική / αποτελεσματική πρόταση</b> («<i>ώστε να γίνει…</i>») ή με «<i>έτσι που να καταντήσει…</i>».</p><h3>Τυπικά ρήματα</h3><p><i>αἴρομαι / αἴρω (=υψώνω), αὔξομαι / αὐξάνω, τρέφω / τρέφομαι, μεγαλύνομαι, παιδεύω, διδάσκω, κτίζω / οἰκοδομῶ, παρασκευάζω, ποιῶ, πνέω, ῥέω</i> (για ποτάμια/ανέμους που «φουσκώνουν»).</p>","examples":[{"gr":"Ὁ ποταμός ῥεῖ μέγας.","an":"ῥεῖ = ρ. εξέλιξης· μέγας = προληπτικό κατηγ. (το ποτάμι κυλάει ΚΑΙ γίνεται/καταλήγει μεγάλο). «Το ποτάμι κυλάει έτσι που να γίνεται μεγάλο / φουσκώνει.»"},{"gr":"Εἷς τις ὑπό τοῦ δήμου ἐτράφη μέγας.","an":"ἐτράφη (τρέφομαι) = ρ. ανατροφής· μέγας = προληπτικό κατηγ. «Κάποιος ανατράφηκε από τον λαό ώστε να γίνει μεγάλος/ισχυρός.»"},{"gr":"Τό τῆς πόλεως τεῖχος ἐκτίσθη ὑψηλόν.","an":"ἐκτίσθη (κτίζω) = ρ. κατασκευής· ὑψηλόν = προληπτικό κατηγ. «Το τείχος της πόλης χτίστηκε ώστε να είναι ψηλό.»"},{"gr":"Τό Ἀλεξάνδρου ὄνομα ηὐξήθη μέγιστον.","an":"ηὐξήθη (αὐξάνομαι) = ρ. εξέλιξης· μέγιστον = προληπτικό κατηγ. «Το όνομα του Αλεξάνδρου μεγάλωσε ώστε να γίνει μέγιστο.»"},{"gr":"Τό Κύρου ὄνομα ηὔξετο μέγα.","an":"(τύπου Ξεν.) — ηὔξετο (αὐξάνομαι) = ρ. εξέλιξης· μέγα = προληπτικό κατηγ. (το όνομα αυξανόταν ΩΣΤΕ να γίνει μεγάλο). «Το όνομα του Κύρου μεγάλωνε ώστε να γίνει μέγα.»"},{"gr":"Καί ᾔρετο τό ὕψος τοῦ τείχους μέγα.","an":"(τύπου Θουκ.) — ᾔρετο (αἴρομαι = υψώνομαι) = ρ. εξέλιξης· μέγα = προληπτικό κατηγ. «Και το ύψος του τείχους ανέβαινε ώστε να γίνει μεγάλο.»"}],"note":"Διαφορά προληπτικού από κανονικό κατηγορούμενο: στο κανονικό η ιδιότητα ΥΠΑΡΧΕΙ ήδη (Σωκράτης ἐστί σοφός)· στο προληπτικό η ιδιότητα ΘΑ ΠΡΟΚΥΨΕΙ από την ενέργεια (ηὐξήθη μέγας = έγινε μεγάλος ως αποτέλεσμα). Κλειδί η σημασία «εξέλιξης» του ρήματος."},{"h":"Διάκριση κατηγορουμένου από επιθετικό & κατηγορηματικό προσδιορισμό","body":"<p>Η συχνότερη δυσκολία είναι η σύγχυση του κατηγορουμένου με τους <b>ομοιόπτωτους ονοματικούς προσδιορισμούς</b> (επιθετικό και κατηγορηματικό). Και τα τρία είναι επίθετα/μετοχές που συμφωνούν με ένα ουσιαστικό· διαφέρουν όμως ριζικά στη λειτουργία και στη θέση τους ως προς το άρθρο.</p><h3>1. Επιθετικός προσδιορισμός</h3><p>Αποδίδει ένα <b>μόνιμο, ουσιώδες</b> γνώρισμα και βρίσκεται <b>μέσα στο άρθρο</b> (άρθρο + επίθετο + ουσιαστικό, ή άρθρο + ουσιαστικό + άρθρο + επίθετο). <b>Δεν υπάρχει συνδετικό ρήμα.</b> Π.χ. <i>ὁ σοφός Σωκράτης</i> / <i>ὁ Σωκράτης ὁ σοφός</i> = «ο σοφός Σωκράτης».</p><h3>2. Κατηγορηματικός προσδιορισμός</h3><p>Αποδίδει ένα <b>παροδικό, περιστασιακό</b> γνώρισμα και βρίσκεται <b>έξω από το άρθρο</b> (επίθετο + άρθρο + ουσιαστικό, ή άρθρο + ουσιαστικό + επίθετο). Πάλι <b>χωρίς συνδετικό ρήμα</b>, αλλά κατά κανόνα με <b>ρήμα κίνησης/ενέργειας</b> στην πρόταση. Π.χ. <i>ἄκρα ἡ χείρ</i> / <i>ἡ χείρ ἄκρα</i> = «η άκρη του χεριού»· <i>ὁ Σωκράτης ἀπῆλθε μόνος</i> (κατηγορηματικός με μόνος, πᾶς, ὅλος, αὐτός, ἄκρος, μέσος, ἔσχατος).</p><h3>3. Κατηγορούμενο</h3><p>Αποδίδει ιδιότητα <b>μέσω συνδετικού ρήματος</b>, χωρίς ποτέ άρθρο. Π.χ. <i>ὁ Σωκράτης ἐστί σοφός</i>.</p><p><b>Το αποφασιστικό κριτήριο</b> είναι το ρήμα: <b>συνδετικό ρήμα ⇒ κατηγορούμενο</b>· <b>απουσία συνδετικού + θέση μέσα στο άρθρο ⇒ επιθετικός</b>· <b>απουσία συνδετικού + θέση έξω από το άρθρο (με ρήμα ενέργειας) ⇒ κατηγορηματικός</b>.</p>","table":{"title":"Συγκριτικός πίνακας διάκρισης","cols":["Κριτήριο","Επιθετικός","Κατηγορηματικός","Κατηγορούμενο"],"rows":[["Συνδετικό ρήμα;","Όχι","Όχι (ρ. ενέργειας)","Ναι (πάντοτε)"],["Θέση ως προς άρθρο","Μέσα στο άρθρο","Έξω από το άρθρο","Χωρίς άρθρο"],["Γνώρισμα","Μόνιμο/ουσιώδες","Παροδικό/περιστασιακό","Αποδιδόμενο μέσω ρήματος"],["Παράδειγμα","ὁ σοφός Σωκράτης","ἄκρα ἡ χείρ","ὁ Σωκράτης ἐστί σοφός"],["Μετάφραση","ο σοφός Σ.","η άκρη του χεριού","ο Σ. είναι σοφός"]]},"examples":[{"gr":"Ὁ ἀγαθός ἀνήρ ὠφελεῖ τήν πόλιν.","an":"ἀγαθός = επιθετικός προσδ. (μέσα στο άρθρο, χωρίς συνδετικό). «Ο ενάρετος άνδρας ωφελεί την πόλη.»"},{"gr":"Ὁ ἀνήρ ἀγαθός ἐστιν.","an":"ἀγαθός = κατηγορούμενο (συνδετικό ἐστιν). «Ο άνδρας είναι ενάρετος.»"},{"gr":"Μέσην τήν πόλιν διέρχεται ὁ ποταμός.","an":"μέσην = κατηγορηματικός προσδ. (έξω από το άρθρο, ρ. κίνησης διέρχεται). «Ο ποταμός διασχίζει το μέσο της πόλης.»"},{"gr":"Πᾶσα ἡ πόλις ἐξῆλθεν.","an":"πᾶσα = κατηγορηματικός προσδ. (πᾶς πάντοτε έξω από το άρθρο). «Όλη η πόλη βγήκε.»"},{"gr":"Μέσον ἡμέρας διά τοῦ πεδίου ἤλαυνεν.","an":"(τύπου Ξεν.) — μέσον = κατηγορηματικός προσδ. (έξω από το άρθρο, με ρ. κίνησης ἤλαυνεν). «Κατά το μέσο της ημέρας προχωρούσε μέσα από την πεδιάδα.»"},{"gr":"Ὁ νεανίας μόνος ἀπῆλθεν.","an":"μόνος = κατηγορηματικός προσδ. (έξω από το άρθρο, με ρ. ενέργειας ἀπῆλθεν)· πρβλ. κατηγορούμενο: ὁ νεανίας ἦν μόνος. «Ο νεαρός έφυγε μόνος.»"}],"note":"Μνημονικό: τα επίθετα μόνος, πᾶς, ὅλος, ἅπας, αὐτός (=ο ίδιος), ἄκρος, μέσος, ἔσχατος μπαίνουν κανονικά ως ΚΑΤΗΓΟΡΗΜΑΤΙΚΟΙ προσδιορισμοί (έξω από το άρθρο). Αν δεις άρθρο γύρω τους, αλλάζει η σημασία (ἡ μέση πόλις = η μεσαία πόλη, επιθετικός· μέση ἡ πόλις = το μέσο της πόλης, κατηγορηματικός)."}]);
  T("syn-antikeimeno-basika", [{"h":"Ορισμός του αντικειμένου","body":"<p><b>Αντικείμενο</b> ονομάζεται ο όρος της πρότασης που φανερώνει το <i>πρόσωπο, το ζώο ή το πράγμα στο οποίο μεταβαίνει (κατευθύνεται) ή στο οποίο αναφέρεται η ενέργεια του υποκειμένου</b></i>. Με άλλα λόγια, το αντικείμενο δηλώνει τον <b>αποδέκτη</b> ή τον <b>στόχο</b> της ρηματικής ενέργειας. Είναι ένας από τους <b>κύριους όρους</b> της πρότασης, μαζί με το υποκείμενο, το ρήμα και (όπου υπάρχει) το κατηγορούμενο.</p><h3>Πώς το αναγνωρίζουμε</h3><p>Το αντικείμενο απαντά στις ερωτήσεις που σχηματίζουμε με το ρήμα: <b>τι;</b> (για πράγματα), <b>ποιον / ποια / ποιους;</b> (για πρόσωπα), <b>σε ποιον; / τίνος; / σε τι;</b> (για το έμμεσο αντικείμενο). Π.χ. στην πρόταση <i>«Ὁ Ἡρακλῆς ἀποκτείνει τόν λέοντα»</i> ρωτάμε «ποιον/τι σκοτώνει ο Ηρακλής;» και η απάντηση <i>τόν λέοντα</i> είναι το αντικείμενο.</p><h3>Σε ποια πτώση βρίσκεται</h3><p>Το αντικείμενο, σε αντίθεση με το υποκείμενο που μπαίνει πάντοτε σε <b>ονομαστική</b>, μπαίνει σε <b>πλάγια πτώση</b> — δηλαδή σε <b>αιτιατική</b> (η συνηθέστερη), σε <b>γενική</b> ή σε <b>δοτική</b>. Αυτό είναι και το πιο σίγουρο εξωτερικό κριτήριο για να ξεχωρίσουμε το υποκείμενο από το αντικείμενο: το υποκείμενο = ονομαστική, το αντικείμενο = γενική / δοτική / αιτιατική.</p><h3>Μέθοδος αναγνώρισης (βήμα-βήμα)</h3><ol><li>Βρίσκω το <b>ρήμα</b> της πρότασης.</li><li>Βρίσκω το <b>υποκείμενο</b> ρωτώντας «ποιος / ποιοι;».</li><li>Ελέγχω αν το ρήμα είναι <b>ενεργητικό μεταβατικό</b> (αν η ενέργειά του μπορεί να περάσει σε άλλον όρο).</li><li>Ρωτάω <b>«τι; / ποιον; / σε ποιον;»</b> και η απάντηση είναι το αντικείμενο.</li></ol>","examples":[{"gr":"Ὁ Ἡρακλῆς ἀποκτείνει τόν λέοντα.","an":"Υποκ.: ὁ Ἡρακλῆς (ονομ.). Ρήμα: ἀποκτείνει (ενεργ. μεταβ.). «Ποιον/τι σκοτώνει;» → τόν λέοντα = αντικείμενο (αιτιατική). Η ενέργεια του Ηρακλή μεταβαίνει στο λιοντάρι."},{"gr":"Οἱ ἵπποι φέρουσι τούς καρπούς ἐκ τοῦ ἀγροῦ.","an":"Υποκ.: οἱ ἵπποι. Ρήμα: φέρουσι. «Τι φέρουν;» → τούς καρπούς = αντικείμενο (αιτιατική). Το ἐκ τοῦ ἀγροῦ είναι εμπρόθετος προσδιορισμός, όχι αντικείμενο."},{"gr":"Ὁ Ἀγησίλαος ἐδίωκεν ἐκείνους.","an":"Υποκ.: ὁ Ἀγησίλαος. «Ποιον/ποιους εδίωκε;» → ἐκείνους = αντικείμενο (αιτιατική, δεικτική αντωνυμία)."},{"gr":"Κῦρος συλλέγει στράτευμα.","an":"Ξεν. Ἀνάβ. 1.1 (τύπου) — Υποκ.: Κῦρος. «Τι συγκεντρώνει;» → στράτευμα = αντικείμενο (αιτιατική)· εσωτερικό/αποτέλεσμα της ενέργειας."},{"gr":"Οἱ στρατιῶται ἐφίλουν τόν στρατηγόν.","an":"«Ποιον αγαπούσαν;» → τόν στρατηγόν = αντικείμενο (αιτιατική). Το φιλῶ είναι ενεργ. μεταβ. και η ενέργεια μεταβαίνει στο πρόσωπο."}],"note":"ΠΡΟΣΟΧΗ: Δεν μπαίνει σε πλάγια πτώση μόνο το αντικείμενο. Σε γενική, δοτική ή αιτιατική μπαίνουν και πολλοί άλλοι προσδιορισμοί (γενική κτητική, δοτική του τρόπου, αιτιατική του χρόνου κ.λπ.). Αντικείμενο έχουμε ΜΟΝΟ όταν η πλάγια πτώση εξαρτάται άμεσα από μεταβατικό ρήμα ως αποδέκτης της ενέργειας."},{"h":"Μεταβατικά και αμετάβατα ρήματα — η προϋπόθεση του αντικειμένου","body":"<p>Το αν μια πρόταση μπορεί να έχει αντικείμενο εξαρτάται από το <b>είδος του ρήματος</b>. Τα ρήματα διακρίνονται ως προς τη σύνταξη σε <b>μεταβατικά</b> και <b>αμετάβατα</b>.</p><h3>Μεταβατικά ρήματα</h3><p><b>Μεταβατικά</b> λέγονται τα ρήματα των οποίων η ενέργεια <i>μεταβαίνει (περνά) σε ένα άλλο πρόσωπο, ζώο ή πράγμα</i>· γι' αυτό και <b>δέχονται αντικείμενο</b>. Τέτοια είναι κατεξοχήν τα <b>ενεργητικά μεταβατικά</b> ρήματα. Π.χ. <i>γράφω (ἐπιστολήν), λύω (τόν ἵππον), παιδεύω (τούς νέους)</i>.</p><h3>Αμετάβατα ρήματα</h3><p><b>Αμετάβατα</b> λέγονται τα ρήματα των οποίων η ενέργεια <i>δεν μεταβαίνει σε άλλον όρο</i> αλλά μένει στο υποκείμενο· γι' αυτό και <b>δεν δέχονται αντικείμενο</b>. Στα αμετάβατα ανήκουν:</p><ul><li><b>Τα ουδέτερα (αμετάβατα) ρήματα</b>, που δηλώνουν κατάσταση ή κίνηση του ίδιου του υποκειμένου: <i>τρέχω, βαδίζω, κάθημαι, κοιμῶμαι, ζῶ, εἰμί</i>.</li><li><b>Τα παθητικά</b>, όπου το υποκείμενο δέχεται την ενέργεια: <i>οὗτοι ἐπαιδεύθησαν</i>.</li><li><b>Πολλά μέσα</b>, όπου η ενέργεια επιστρέφει στο υποκείμενο: <i>λούομαι, γυμνάζομαι</i>.</li></ul><h3>Το ίδιο ρήμα — άλλοτε μεταβατικό, άλλοτε αμετάβατο</h3><p>Πολλά ρήματα μπορούν να χρησιμοποιηθούν και με τις δύο συντάξεις, ανάλογα με τα συμφραζόμενα. Π.χ. το <i>ἄγω</i> ως μεταβατικό = «οδηγώ (κάποιον)» (<i>ἄγω τόν ἵππον</i>), αλλά αμετάβατο = «προχωρώ» (<i>ἄγωμεν</i> = ας προχωρήσουμε). Έτσι, η μεταβατικότητα είναι ιδιότητα της <b>χρήσης</b> του ρήματος μέσα στην πρόταση, όχι απόλυτη ιδιότητα του λεξήματος.</p>","table":{"title":"Διάθεση ρήματος και αντικείμενο","cols":["Διάθεση / είδος","Σχέση ενέργειας","Δέχεται αντικείμενο;","Παράδειγμα"],"rows":[["Ενεργητική μεταβατική","Η ενέργεια περνά σε άλλον","ΝΑΙ","Οἱ πολέμιοι ἐδῄουν τήν χώραν"],["Μέση (αυτοπαθής)","Η ενέργεια επιστρέφει στο υποκ.","Όχι (ή σύστοιχο)","Οἱ Κερκυραῖοι ἐτάξαντο"],["Παθητική","Το υποκ. δέχεται την ενέργεια","Όχι (έχει ποιητ. αίτιο)","Οὗτοι ἐπαιδεύθησαν ὑπό τῶν πατέρων"],["Ουδέτερη (αμετάβατη)","Το υποκ. βρίσκεται σε κατάσταση","Όχι","Οὗτοι ἡδέως ἐκοιμήθησαν"]]},"examples":[{"gr":"Οἱ πολέμιοι ἐδῄουν τήν χώραν.","an":"Ενεργητικό μεταβατικό (ἐδῄουν = λεηλατούσαν). Η ενέργεια μεταβαίνει στη χώρα → τήν χώραν = αντικείμενο (αιτιατική)."},{"gr":"Οὗτοι ἐπαιδεύθησαν ὑπό τῶν πατέρων.","an":"Παθητικό ρήμα, αμετάβατη σύνταξη. Δεν υπάρχει αντικείμενο· το ὑπό τῶν πατέρων είναι ποιητικό αίτιο."},{"gr":"Ὁ στρατιώτης ἔτρεχε ταχέως.","an":"Ουδέτερο (αμετάβατο) ρήμα: η ενέργεια μένει στο υποκείμενο. Δεν δέχεται αντικείμενο· το ταχέως είναι επιρρηματικός προσδιορισμός τρόπου."},{"gr":"Οἱ βάρβαροι ἔτεμνον τήν γῆν τῶν Ἀθηναίων.","an":"Ενεργ. μεταβατικό (τέμνω = λεηλατώ/καταστρέφω). «Τι λεηλατούσαν;» → τήν γῆν = αντικείμενο (αιτ.)· τῶν Ἀθηναίων = γενική κτητική, όχι αντικείμενο. (Θουκ., τύπου)"},{"gr":"Ὁ Σωκράτης διελέγετο τοῖς νέοις.","an":"Αμετάβατη/μέση σύνταξη (διαλέγομαι): δεν υπάρχει αντικείμενο σε αιτιατική· το τοῖς νέοις είναι δοτική (αντικείμ. ρήματος επικοινωνίας — βλ. δοτική). Δείχνει ότι αμετάβατο ως προς αιτιατική."},{"gr":"Ἦγε τό στράτευμα διά τῆς χώρας.","an":"ἄγω ως μεταβατικό: «οδηγώ» → τό στράτευμα = αντικείμενο (αιτ.). Πρβλ. αμετάβατο ἄγωμεν = «ας προχωρήσουμε»."}],"note":"ΠΑΓΙΔΑ: Ένα ενεργητικό ρήμα ΔΕΝ έχει υποχρεωτικά αντικείμενο. Στο «ὁ παῖς γράφει» το ρήμα είναι ενεργητικό αλλά χρησιμοποιείται απόλυτα (αμετάβατα). Αντικείμενο υπάρχει μόνο αν η ενέργεια όντως περνά σε κάποιον όρο της πρότασης."},{"h":"Οι πτώσεις του αντικειμένου — γιατί άλλοτε αιτιατική, άλλοτε γενική, άλλοτε δοτική","body":"<p>Σε αντίθεση με τη νέα ελληνική, όπου το (άμεσο) αντικείμενο μπαίνει σχεδόν πάντα σε αιτιατική, στην αρχαία ελληνική το αντικείμενο μπαίνει και στις <b>τρεις πλάγιες πτώσεις</b>. Ποια πτώση θα πάρει το ρήμα <b>δεν είναι τυχαίο</b>: καθορίζεται από τη <b>σημασία</b> και την παράδοση σύνταξης κάθε ρήματος. Γι' αυτό κάθε ρήμα πρέπει να το μαθαίνουμε <i>μαζί με την πτώση που συντάσσεται</i>.</p><h3>1. Αντικείμενο σε αιτιατική</h3><p>Είναι το <b>πιο συχνό</b>. Δηλώνει τον άμεσο αποδέκτη μιας ενέργειας που τον επηρεάζει πλήρως. Τα περισσότερα μεταβατικά ρήματα δράσης (ποιῶ, γράφω, λύω, παιδεύω, διώκω, ὠφελῶ, βλάπτω, ὁρῶ, φιλῶ) συντάσσονται με αιτιατική.</p><h3>2. Αντικείμενο σε γενική</h3><p>Με γενική συντάσσονται ρήματα ορισμένων σημασιολογικών κατηγοριών, όπου η ενέργεια αφορά <i>μέρος</i> ή <i>επαφή/αναφορά</i> προς κάτι και όχι την πλήρη κατάληψή του. Κύριες κατηγορίες:</p><ul><li>Μνήμης / λήθης: <i>μέμνημαι, μιμνῄσκομαι, ἐπιλανθάνομαι</i>.</li><li>Φροντίδας / επιμέλειας / αμέλειας: <i>ἐπιμελοῦμαι, φροντίζω, ἀμελῶ, φείδομαι</i>.</li><li>Επιθυμίας / ορμής: <i>ἐπιθυμῶ, ἐρῶ, ὀρέγομαι</i>.</li><li>Απόλαυσης / μετοχής / πληρότητας/ στέρησης: <i>ἀπολαύω, μετέχω, γέμω, δέομαι, στεροῦμαι</i>.</li><li>Αίσθησης (ιδίως ακοής/αφής) και αρχής: <i>ἀκούω, ἅπτομαι, ἄρχω, κρατῶ, βασιλεύω</i>.</li></ul><h3>3. Αντικείμενο σε δοτική</h3><p>Με δοτική συντάσσονται ρήματα που δηλώνουν <i>σχέση, επικοινωνία ή διάθεση</i> προς πρόσωπο. Κύριες κατηγορίες:</p><ul><li>Πειθαρχίας / ακολουθίας / προσέγγισης: <i>πείθομαι, ἕπομαι, ἀκολουθῶ, πλησιάζω</i>.</li><li>Βοήθειας / φιλίας / έχθρας: <i>βοηθῶ, ἀρήγω, φθονῶ, ὀργίζομαι, πολεμῶ</i>.</li><li>Συνομιλίας / συμφωνίας / διαφωνίας: <i>ὁμιλῶ, διαλέγομαι, συμφωνῶ, ἐρίζω, μάχομαι</i>.</li><li>Ομοιότητας / ισότητας / καταλληλότητας: <i>ἔοικα, ὁμοιοῦμαι, ἰσοῦμαι, ἁρμόττει, πρέπει</i>.</li><li>Χρήσης / συναναστροφής: <i>χρῶμαι, ἐντυγχάνω</i>.</li></ul>","table":{"title":"Οι τρεις πτώσεις του αντικειμένου — σημασιολογικές κατηγορίες","cols":["Πτώση","Τυπική σημασία ρημάτων","Παραδείγματα ρημάτων"],"rows":[["Αιτιατική","Άμεση, πλήρης ενέργεια σε αποδέκτη","ποιῶ, γράφω, λύω, διώκω, ὁρῶ, ὠφελῶ, παιδεύω"],["Γενική","Μνήμη, φροντίδα, επιθυμία, μετοχή, αφή/ακοή, αρχή","μέμνημαι, ἐπιμελοῦμαι, ἐπιθυμῶ, ἀκούω, ἅπτομαι, ἄρχω"],["Δοτική","Σχέση/επικοινωνία προς πρόσωπο","πείθομαι, ἕπομαι, βοηθῶ, χρῶμαι, ἔοικα, μάχομαι"]]},"examples":[{"gr":"Οἱ Ἀθηναῖοι ἐπολέμησαν τούς Πέρσας.","an":"Αντικείμενο σε ΑΙΤΙΑΤΙΚΗ (τούς Πέρσας). Εδώ το πολεμῶ + αιτιατική = «πολεμώ εναντίον (κάποιου)»."},{"gr":"Οἱ Ἀθηναῖοι ἐπιμελοῦντο τῆς πόλεως.","an":"Αντικείμενο σε ΓΕΝΙΚΗ (τῆς πόλεως). Το ἐπιμελοῦμαι (φροντίδα) συντάσσεται κανονικά με γενική."},{"gr":"Οἱ Ἀθηναῖοι ἐπείθοντο τοῖς νόμοις.","an":"Αντικείμενο σε ΔΟΤΙΚΗ (τοῖς νόμοις). Το πείθομαι (πειθαρχία) συντάσσεται με δοτική."},{"gr":"Μέμνησο τῶν ἀπόντων φίλων.","an":"Το μέμνημαι (μνήμη) + ΓΕΝΙΚΗ: τῶν ἀπόντων φίλων = αντικείμενο."},{"gr":"Πλησίαζε τοῖς ἀγαθοῖς.","an":"Το πλησιάζω (προσέγγιση) + ΔΟΤΙΚΗ: τοῖς ἀγαθοῖς = αντικείμενο."},{"gr":"Ἐπεθύμει τῆς ἐλευθερίας.","an":"ΓΕΝΙΚΗ ως αντικείμενο: το ἐπιθυμῶ (επιθυμία) + γεν. → τῆς ἐλευθερίας. (Ξεν./Πλάτ., τύπου)"},{"gr":"Ἤκουον τοῦ διδασκάλου.","an":"ΓΕΝΙΚΗ προσώπου ως αντικείμενο: ἀκούω τινός = «ακούω/υπακούω κάποιον (που μιλά)» (Smyth §1361 κ.εξ.)."},{"gr":"Ὁ Ἀγησίλαος ἐβοήθει τοῖς συμμάχοις.","an":"ΔΟΤΙΚΗ ως αντικείμενο: βοηθῶ (βοήθεια) + δοτ. → τοῖς συμμάχοις. (Ξεν., τύπου)"},{"gr":"Χρῶ τοῖς φίλοις ὡς ἀγαθοῖς.","an":"ΔΟΤΙΚΗ ως αντικείμενο: χρῶμαι (χρήση/συναναστροφή) + δοτ. → τοῖς φίλοις (το ὡς ἀγαθοῖς = κατηγορούμενο)."}],"note":"ΣΗΜΑΝΤΙΚΟ: Το ίδιο ρήμα μπορεί να αλλάζει σημασία ανάλογα με την πτώση. Π.χ. ἀκούω + γενική = «ακούω (κάποιον να μιλά / υπακούω)», ἀκούω + αιτιατική = «ακούω (κάτι, π.χ. έναν ήχο, λόγια)»· ἄρχω + γενική = «εξουσιάζω», ἄρχομαι + γενικής = «αρχίζω». Πάντα ελέγχουμε σημασία ΚΑΙ πτώση μαζί."},{"h":"Μονόπτωτα και δίπτωτα ρήματα","body":"<p>Τα μεταβατικά ρήματα, ανάλογα με το <b>πόσα αντικείμενα</b> δέχονται, διακρίνονται σε <b>μονόπτωτα</b> και <b>δίπτωτα</b>.</p><h3>Μονόπτωτα ρήματα</h3><p><b>Μονόπτωτα</b> λέγονται τα ρήματα που δέχονται <b>ένα μόνο αντικείμενο</b> — σε μία πτώση. Η συντριπτική πλειονότητα των μεταβατικών ρημάτων είναι μονόπτωτα. Το μοναδικό τους αντικείμενο μπορεί να είναι σε αιτιατική, σε γενική ή σε δοτική (βλ. προηγούμενο κεφάλαιο).</p><p><i>Σημείωση:</i> Ένα ρήμα παραμένει μονόπτωτο ακόμη και αν συνοδεύεται από <b>πολλά όμοια αντικείμενα στην ίδια πτώση</b> (συνδεμένα παρατακτικά), π.χ. <i>«φέρουσι τούς καρπούς καί τά ξύλα»</i>: δύο αντικείμενα ίδιας ποιότητας, σε αιτιατική — το ρήμα είναι μονόπτωτο.</p><h3>Δίπτωτα ρήματα</h3><p><b>Δίπτωτα</b> λέγονται τα ρήματα που δέχονται <b>δύο διαφορετικά αντικείμενα</b> — ένα <b>άμεσο</b> και ένα <b>έμμεσο</b>. Τα δύο αντικείμενα είναι:</p><ul><li>είτε σε <b>διαφορετικές πτώσεις</b> (π.χ. αιτιατική + δοτική, αιτιατική + γενική, γενική + δοτική),</li><li>είτε στην <b>ίδια πτώση (διπλή αιτιατική)</b> αλλά <b>διαφορετικής ποιότητας</b> — το ένα δηλώνει πρόσωπο, το άλλο πράγμα.</li></ul><p>Κρίσιμο: δύο αντικείμενα στην ίδια πτώση κάνουν το ρήμα δίπτωτο μόνο όταν διαφέρουν ως προς τη σημασία (πρόσωπο vs πράγμα). Π.χ. <i>«Σωκράτης ἐδίδασκε τούς παῖδας τήν ἀρετήν»</i> — δύο αιτιατικές, αλλά τούς παῖδας = πρόσωπο, τήν ἀρετήν = πράγμα → δίπτωτο.</p>","table":{"title":"Συνδυασμοί πτώσεων στα δίπτωτα ρήματα","cols":["Συνδυασμός","Σημασιολογική ομάδα ρημάτων","Παράδειγμα ρήματος","Παράδειγμα"],"rows":[["Αιτιατική + Δοτική","Δόση, λόγος, υπόσχεση","δίδωμι, λέγω, ὑπισχνοῦμαι","δίδωμι χρυσίον τῷ φίλῳ"],["Αιτιατική + Γενική","Πλήρωση, ακρόαση, στέρηση, αλλαγή","γεμίζω, ἀκούω, ἀπαλλάττω, ἀντικαταλλάττω","ἐγέμισε τήν ναῦν ξύλων"],["Γενική + Δοτική","Μετοχή, παραχώρηση, φθόνος","μεταδίδωμι, παραχωρῶ, φθονῶ","μή φθονήσῃς τοῦ μαθήματος αὐτῷ"],["Διπλή Αιτιατική (πρόσ.+πράγμα)","Διδαχή, απόκρυψη, ένδυση, αφαίρεση","διδάσκω, κρύπτω, ἐνδύω, ἀφαιροῦμαι","ἐδίδασκε τούς παῖδας τήν ἀρετήν"]]},"examples":[{"gr":"Φέρουσι τούς καρπούς.","an":"ΜΟΝΟΠΤΩΤΟ: ένα αντικείμενο σε αιτιατική (τούς καρπούς)."},{"gr":"Οἱ παῖδες φέρουσι πέπλον τῇ Ἀθηνᾷ.","an":"ΔΙΠΤΩΤΟ (αιτ.+δοτ.): πέπλον (αιτιατική) = άμεσο αντικείμενο· τῇ Ἀθηνᾷ (δοτική) = έμμεσο αντικείμενο."},{"gr":"Σωκράτης ἐδίδασκε τούς παῖδας τήν ἀρετήν.","an":"ΔΙΠΤΩΤΟ με ΔΙΠΛΗ ΑΙΤΙΑΤΙΚΗ: τούς παῖδας (πρόσωπο) = άμεσο· τήν ἀρετήν (πράγμα) = έμμεσο. Διαφέρουν ως προς την ποιότητα, γι' αυτό το ρήμα είναι δίπτωτο."},{"gr":"Ἐγέμισε τήν ναῦν ξύλων.","an":"ΔΙΠΤΩΤΟ (αιτ.+γεν.): τήν ναῦν (αιτιατική) = άμεσο· ξύλων (γενική, του περιεχομένου) = έμμεσο."},{"gr":"Κῦρος δίδωσι τοῖς στρατιώταις μισθόν.","an":"ΔΙΠΤΩΤΟ (αιτ.+δοτ.): μισθόν (αιτ.) = άμεσο· τοῖς στρατιώταις (δοτ.) = έμμεσο. (Ξεν. Ἀνάβ., τύπου)"},{"gr":"Ὁ Φωκικός πόλεμος δεκέτης γεγονώς ἀείμνηστον παιδείαν αὐτούς ἐπαίδευσε.","an":"Αἰσχίν. Κατά Κτησ. 3.148 — ΔΙΠΤΩΤΟ με ΔΙΠΛΗ ΑΙΤΙΑΤΙΚΗ: αὐτούς (πρόσωπο) = άμεσο· ἀείμνηστον παιδείαν (πράγμα, σύστοιχο) = έμμεσο."},{"gr":"Ἀπεστέρησαν τόν δῆμον τῆς ἐλευθερίας.","an":"ΔΙΠΤΩΤΟ (αιτ.+γεν.): τόν δῆμον (αιτ.) = άμεσο· τῆς ἐλευθερίας (γεν. του χωρισμού/στέρησης) = έμμεσο. (ρητορ., τύπου)"}],"note":"Μην μπερδεύεις τα πολλά ΟΜΟΙΑ αντικείμενα (ίδια πτώση + ίδια ποιότητα → μονόπτωτο) με τη διπλή αιτιατική (ίδια πτώση + διαφορετική ποιότητα → δίπτωτο)."},{"h":"Άμεσο και έμμεσο αντικείμενο — ο κανόνας διάκρισης","body":"<p>Όταν ένα δίπτωτο ρήμα έχει δύο αντικείμενα, τα διακρίνουμε σε <b>άμεσο</b> και <b>έμμεσο</b>:</p><ul><li><b>Άμεσο αντικείμενο</b>: αυτό στο οποίο <i>μεταβαίνει αμέσως</i> η ενέργεια του ρήματος (ο κύριος, πληρέστερα επηρεαζόμενος αποδέκτης).</li><li><b>Έμμεσο αντικείμενο</b>: αυτό στο οποίο η ενέργεια φτάνει <i>έμμεσα</i>, μέσω του άμεσου (συνήθως το πρόσωπο προς όφελος/βλάβη του οποίου γίνεται η πράξη, ή το αντικείμενο μιας δευτερεύουσας σχέσης).</li></ul><h3>Ο πρακτικός κανόνας</h3><p>Για να ξεχωρίσουμε άμεσο από έμμεσο, εφαρμόζουμε δύο κανόνες, με τη σειρά:</p><ol><li><b>Αν τα δύο αντικείμενα είναι σε διαφορετικές πτώσεις</b>: άμεσο είναι αυτό που βρίσκεται σε <b>αιτιατική</b>· το άλλο (γενική ή δοτική) είναι έμμεσο. <i>Αν κανένα δεν είναι σε αιτιατική</i> (συνδυασμός γενικής + δοτικής), τότε άμεσο θεωρείται αυτό που βρίσκεται σε <b>γενική</b>.</li><li><b>Αν και τα δύο είναι σε αιτιατική</b> (διπλή αιτιατική): άμεσο είναι αυτό που φανερώνει <b>πρόσωπο</b>· το άλλο (που φανερώνει πράγμα) είναι έμμεσο.</li></ol><p>Διαισθητικά: το έμμεσο αντικείμενο συχνά μπορεί να αντικατασταθεί από εμπρόθετο με «σε / προς» (π.χ. «δίνω χρυσάφι <i>στον</i> Κλέαρχο»). Στη νέα ελληνική, το έμμεσο αντικείμενο αποδίδεται κατά κανόνα με «σε + αιτιατική» ή με γενική προσωπικής αντωνυμίας («του δίνω»).</p>","table":{"title":"Αναγνώριση άμεσου / έμμεσου ανά συνδυασμό","cols":["Συνδυασμός πτώσεων","Άμεσο αντικείμενο","Έμμεσο αντικείμενο"],"rows":[["Αιτιατική + Δοτική","η αιτιατική","η δοτική"],["Αιτιατική + Γενική","η αιτιατική","η γενική"],["Γενική + Δοτική (καμία αιτιατική)","η γενική","η δοτική"],["Αιτιατική + Αιτιατική (διπλή)","η αιτιατική του προσώπου","η αιτιατική του πράγματος"]]},"examples":[{"gr":"Κῦρος ἔδωκε Κλεάρχῳ χρυσίον.","an":"Δίπτωτο (αιτ.+δοτ.). χρυσίον (αιτιατική) = ΑΜΕΣΟ αντικείμενο· Κλεάρχῳ (δοτική) = ΕΜΜΕΣΟ. «Δίνω κάτι (άμεσο) σε κάποιον (έμμεσο)»."},{"gr":"Διδάσκουσι τούς παῖδας σωφροσύνην.","an":"Διπλή αιτιατική. τούς παῖδας (πρόσωπο) = ΑΜΕΣΟ· σωφροσύνην (πράγμα) = ΕΜΜΕΣΟ."},{"gr":"Λέγω Σωκράτει τήν ἀλήθειαν.","an":"Δίπτωτο (αιτ.+δοτ.). τήν ἀλήθειαν (αιτιατική) = άμεσο· Σωκράτει (δοτική) = έμμεσο. (Στη ν.ε.: «λέω την αλήθεια στον Σωκράτη».)"},{"gr":"Μή φθονήσῃς τοῦ μαθήματος αὐτῷ.","an":"Δίπτωτο (γεν.+δοτ., καμία αιτιατική). τοῦ μαθήματος (γενική) = άμεσο· αὐτῷ (δοτική) = έμμεσο."},{"gr":"Ὑπέσχετο τῷ Κύρῳ συμμαχίαν.","an":"Δίπτωτο (αιτ.+δοτ.): συμμαχίαν (αιτ.) = άμεσο· τῷ Κύρῳ (δοτ.) = έμμεσο. (Ξεν., τύπου)"},{"gr":"Μετέδωκε τοῖς φίλοις τοῦ σίτου.","an":"Δίπτωτο (γεν.+δοτ., καμία αιτιατική): τοῦ σίτου (γεν. του διαιρεμένου όλου) = άμεσο· τοῖς φίλοις (δοτ.) = έμμεσο."}],"note":"Στη μετατροπή στην παθητική φωνή, συνήθως το ΑΜΕΣΟ αντικείμενο γίνεται υποκείμενο του παθητικού ρήματος (π.χ. «τό χρυσίον ἐδόθη Κλεάρχῳ»). Αυτό είναι ένα χρήσιμο τεστ επιβεβαίωσης ποιο είναι το άμεσο."},{"h":"Το σύστοιχο αντικείμενο","body":"<p><b>Σύστοιχο αντικείμενο</b> ονομάζεται το αντικείμενο που <i>έχει την ίδια ρίζα ή συγγενική / συνώνυμη σημασία με το ρήμα</i> από το οποίο εξαρτάται. Λέγεται «σύστοιχο» (από το <i>στοῖχος</i> = σειρά, οικογένεια λέξεων) γιατί ανήκει στην ίδια ετυμολογική «σειρά» με το ρήμα.</p><h3>Δύο μορφές</h3><ul><li><b>Ομόρριζο</b> (ίδια ρίζα): <i>ἀγωνίζομαι ἀγῶνα, νοσῶ νόσον, βουλεύω βουλήν, μάχην μάχομαι</i>.</li><li><b>Συνώνυμο</b> (διαφορετική ρίζα, ίδια όμως έννοια): <i>θηρεύω θῆρας, νικῶ μάχην</i> (= κερδίζω μάχη).</li></ul><h3>Ιδιαίτερο χαρακτηριστικό: ο προσδιορισμός</h3><p>Το σύστοιχο αντικείμενο, επειδή συχνά απλώς επαναλαμβάνει την έννοια του ρήματος, σχεδόν πάντοτε <b>συνοδεύεται από επιθετικό προσδιορισμό</b> που προσθέτει το νόημα. Π.χ. <i>«ἔζη βίον εὐδαίμονα»</i> (έζησε ευτυχισμένη ζωή): η ουσιαστική πληροφορία βρίσκεται στο επίθετο <i>εὐδαίμονα</i>.</p><p>Πολύ συχνά μάλιστα <b>το ουσιαστικό παραλείπεται</b> και μένει μόνο το επίθετο/η αντωνυμία σε αιτιατική (ουδ. εν. ή πληθ.), που τότε ισοδυναμεί με επίρρημα: <i>«πολλά ἥμαρτε»</i> (= έσφαλε πολύ), <i>«παῖσον διπλῆν»</i> (= χτύπησε διπλά, εννοείται «πληγήν»). Αυτές οι αιτιατικές αναλύονται ως σύστοιχα αντικείμενα με παραλειπόμενο ουσιαστικό και στη νέα ελληνική αποδίδονται με επίρρημα.</p><h3>Σε ποια ρήματα εμφανίζεται</h3><p>Σύστοιχο αντικείμενο μπορούν να πάρουν ακόμη και <b>αμετάβατα</b> ρήματα (π.χ. <i>ζῶ, νοσῶ, χαίρω</i>), όχι μόνο τα μεταβατικά — γι' αυτό το σύστοιχο θεωρείται ειδική, «εσωτερική» κατηγορία αντικειμένου. Πολύ συχνά το παίρνουν τα <i>δρῶ, ποιῶ, ἐργάζομαι, ἀγορεύω, λέγω, ἀγωνίζομαι, μάχομαι, νοσῶ, ζῶ</i>.</p>","table":{"title":"Παραδείγματα σύστοιχου αντικειμένου","cols":["Ρήμα","Σύστοιχο αντικείμενο","Είδος","Μετάφραση"],"rows":[["ἀγωνίζομαι","ἀγῶνα (καλόν)","ομόρριζο","αγωνίζομαι (καλόν) αγώνα"],["νοσῶ","νόσον (χαλεπήν)","ομόρριζο","πάσχω (βαριά) αρρώστια"],["θηρεύω","θῆρας","συνώνυμο","κυνηγώ θηράματα"],["ζῶ","βίον (εὐδαίμονα)","συνώνυμο","ζω (ευτυχισμένη) ζωή"],["ἁμαρτάνω","πολλά (εννοείται: ἁμαρτήματα)","επίθ. μόνο","σφάλλω πολύ"]]},"examples":[{"gr":"Ἀγωνίζομαι τοῦτον τόν ἀγῶνα.","an":"Σύστοιχο αντικείμενο ΟΜΟΡΡΙΖΟ: τόν ἀγῶνα (ίδια ρίζα με ἀγωνίζομαι), σε αιτιατική."},{"gr":"Κροῖσος ἔζη βίον εὐδαίμονα.","an":"Σύστοιχο ΣΥΝΩΝΥΜΟ: βίον (συγγενές με ζῶ), με επιθ. προσδ. εὐδαίμονα που φέρει το ουσιαστικό νόημα."},{"gr":"Σωκράτης θυσίας ἔθυε.","an":"Σύστοιχο ομόρριζο: θυσίας / ἔθυε (ίδια ρίζα θυ-). Αιτιατική, πληθυντικός."},{"gr":"Ἀλκιβιάδης πολλά ἥμαρτε.","an":"Σύστοιχο με παράλειψη ουσιαστικού: πολλά = «πολλά (αμαρτήματα)» ≈ επίρρημα «πολύ». Αναλύεται ως σύστοιχο αντικείμενο."},{"gr":"Νόσον νοσεῖ χαλεπήν.","an":"Σύστοιχο ΟΜΟΡΡΙΖΟ (νόσον / νοσεῖ): η έννοια προσδιορίζεται από το χαλεπήν. Το νοσῶ είναι αμετάβατο, κι όμως δέχεται σύστοιχο."},{"gr":"Μάχην ἐνίκων τήν ἐν Μαραθῶνι.","an":"Σύστοιχο ΣΥΝΩΝΥΜΟ: μάχην (συγγενές προς νικῶ) σε αιτιατική, με προσδιορισμό τήν ἐν Μαραθῶνι."}],"note":"Το σύστοιχο αντικείμενο βρίσκεται ΠΑΝΤΑ σε αιτιατική, ακόμη και με αμετάβατα ρήματα. Αν δεις αμετάβατο ρήμα (ζῶ, νοσῶ, χαίρω) να συνοδεύεται από ομόρριζη/συνώνυμη αιτιατική, σχεδόν σίγουρα πρόκειται για σύστοιχο αντικείμενο, όχι για κανονικό αντικείμενο."},{"h":"Εξωτερικό και εσωτερικό αντικείμενο","body":"<p>Μια θεμελιώδης σημασιολογική διάκριση αφορά τη <b>σχέση του αντικειμένου με την ύπαρξή του πριν και μετά την ενέργεια</b>. Διακρίνουμε <b>εξωτερικό</b> και <b>εσωτερικό</b> αντικείμενο.</p><h3>Εξωτερικό αντικείμενο</h3><p><b>Εξωτερικό</b> λέγεται το αντικείμενο που <i>προϋπάρχει</i> της ρηματικής ενέργειας — υπάρχει ανεξάρτητα και η ενέργεια του ρήματος απλώς το <b>επηρεάζει</b> (ή και δεν το μεταβάλλει καθόλου). Δηλώνει ένα ον/πράγμα «έξω» από το ρήμα, στο οποίο φτάνει η ενέργεια. Π.χ. στο <i>«ὁ ἥλιος θερμαίνει τήν γῆν»</i> η γη υπάρχει ήδη· ο ήλιος απλώς τη θερμαίνει. Τα περισσότερα κοινά αντικείμενα είναι εξωτερικά.</p><h3>Εσωτερικό αντικείμενο</h3><p><b>Εσωτερικό</b> λέγεται το αντικείμενο που <i>δεν προϋπάρχει</i>, αλλά <b>δημιουργείται / παράγεται από την ίδια την ενέργεια</b> του ρήματος — είναι το αποτέλεσμα της πράξης. Π.χ. στο <i>«γράφω ἐπιστολήν»</i> η επιστολή δεν υπάρχει πριν· γεννιέται από την πράξη του γραψίματος. Το <b>σύστοιχο αντικείμενο είναι η τυπικότερη περίπτωση εσωτερικού αντικειμένου</b>, αφού η «νόσος» στο <i>νοσῶ νόσον</i> ή ο «αγώνας» στο <i>ἀγωνίζομαι ἀγῶνα</i> δεν προϋπάρχει αλλά είναι το ίδιο το περιεχόμενο της ενέργειας.</p><h3>Πρακτικό κριτήριο</h3><p>Ρωτάμε: «Υπάρχει το αντικείμενο <i>πριν</i> αρχίσει η ενέργεια;» — Αν ναι → <b>εξωτερικό</b>. Αν προκύπτει <i>ως αποτέλεσμα</i> της ενέργειας → <b>εσωτερικό</b>.</p>","table":{"title":"Εξωτερικό vs εσωτερικό αντικείμενο","cols":["Κριτήριο","Εξωτερικό","Εσωτερικό"],"rows":[["Ύπαρξη πριν την ενέργεια","Προϋπάρχει","Δεν προϋπάρχει"],["Σχέση με την ενέργεια","Επηρεάζεται / δέχεται","Δημιουργείται / παράγεται"],["Τυπικό παράδειγμα","θερμαίνω τήν γῆν","γράφω ἐπιστολήν"],["Συγγενής κατηγορία","κοινό αντικείμενο","σύστοιχο αντικείμενο"]]},"examples":[{"gr":"Ὁ ἥλιος θερμαίνει τήν γῆν.","an":"ΕΞΩΤΕΡΙΚΟ αντικείμενο: η γη προϋπάρχει, η ενέργεια απλώς την επηρεάζει (τη θερμαίνει)."},{"gr":"Ἐγώ γράφω ἐπιστολήν.","an":"ΕΣΩΤΕΡΙΚΟ αντικείμενο: η ἐπιστολή δεν υπάρχει πριν· δημιουργείται από την ίδια την ενέργεια του γράφειν."},{"gr":"Οἱ Ἀθηναῖοι οἰκοδομοῦσι τεῖχος.","an":"ΕΣΩΤΕΡΙΚΟ: το τεῖχος παράγεται ως αποτέλεσμα της οικοδόμησης."},{"gr":"Ὁ τέκτων ἔτεμνε τά ξύλα.","an":"ΕΞΩΤΕΡΙΚΟ: τα ξύλα προϋπάρχουν· η ενέργεια (κόψιμο) τα επηρεάζει."},{"gr":"Ποιεῖ νόμους τῇ πόλει.","an":"ΕΣΩΤΕΡΙΚΟ: οι νόμοι δεν προϋπάρχουν· παράγονται από την ενέργεια του ποιεῖν (νομοθετώ)."},{"gr":"Ὁ γεωργός ἤροσε τόν ἀγρόν.","an":"ΕΞΩΤΕΡΙΚΟ: ο αγρός προϋπάρχει· η ενέργεια (όργωμα) τον επηρεάζει χωρίς να τον δημιουργεί."}],"note":"Σύνδεση κατηγοριών: κάθε σύστοιχο αντικείμενο είναι εσωτερικό· δεν είναι όμως κάθε εσωτερικό αντικείμενο σύστοιχο (π.χ. «γράφω ἐπιστολήν» — εσωτερικό αλλά όχι ομόρριζο/σύστοιχο)."},{"h":"Τι μπορεί να λειτουργήσει ως αντικείμενο — οι μορφές","body":"<p>Αντικείμενο δεν είναι μόνο το ουσιαστικό. Στη θέση του αντικειμένου μπορεί να βρεθεί οποιοσδήποτε όρος έχει <b>ονοματική αξία</b> (δηλαδή λειτουργεί σαν όνομα). Οι κύριες μορφές είναι:</p><ul><li><b>Ουσιαστικό</b> (η συνηθέστερη μορφή): <i>Ὁρῶ τόν ἄνδρα.</i></li><li><b>Επίθετο / μετοχή ή αντωνυμία ουσιαστικοποιημένη</b>: <i>Μίσει τούς δειλούς</i> (επίθ.)· <i>Ταῦτα ἐποίουν</i> (αντων.).</li><li><b>Αριθμητικό</b>: <i>Κῦρος ἔτρεψε τούς ἑξακισχιλίους.</i></li><li><b>Μετοχή (επιθετική/ουσιαστικοποιημένη)</b>: <i>Οἱ Ἕλληνες οὐκ ἐγίγνωσκον τά ποιούμενα.</i></li><li><b>Απαρέμφατο</b> (ως αντικείμενο ρημάτων βούλησης, δύναμης κ.λπ.): <i>Οὐκ ἐδύναντο ἐλθεῖν.</i></li><li><b>Εμπρόθετο / επίρρημα ουσιαστικοποιημένο με άρθρο</b>: <i>Οἱ Ἕλληνες οὐχ ἑώρων τούς πέραν τοῦ ποταμοῦ.</i></li><li><b>Δευτερεύουσα ονοματική πρόταση</b> (ειδική, πλάγια ερωτηματική, ενδοιαστική) ως αντικείμενο: <i>Οὗτοι ἔλεγον ὅτι πρός ἑσπέραν ἥξοι τό στράτευμα.</i></li></ul><p>Όταν αντικείμενο είναι απαρέμφατο, μιλάμε για <b>ειδικό απαρέμφατο</b> (μετά από λεκτικά/γνωστικά ρήματα: «λέω ότι...») ή <b>τελικό απαρέμφατο</b> (μετά από ρήματα βούλησης/δύναμης). Όταν αντικείμενο είναι ολόκληρη πρόταση, μιλάμε για <b>δευτερεύουσα ονοματική πρόταση ως αντικείμενο</b> του ρήματος εξάρτησης.</p><h3>Συνοπτικά: το αντικείμενο μέσα στην πρόταση</h3><p>Το αντικείμενο είναι ο όρος που ολοκληρώνει το νόημα ενός μεταβατικού ρήματος, δηλώνοντας τον αποδέκτη της ενέργειας. Για την πλήρη ανάλυσή του προσδιορίζουμε: (α) την <b>πτώση</b> του, (β) αν το ρήμα είναι <b>μονόπτωτο ή δίπτωτο</b>, (γ) αν είναι <b>άμεσο ή έμμεσο</b>, (δ) αν είναι <b>σύστοιχο</b>, και (ε) αν είναι <b>εξωτερικό ή εσωτερικό</b>.</p>","examples":[{"gr":"Ὁρῶ τόν ἄνδρα.","an":"Αντικείμενο = ουσιαστικό (τόν ἄνδρα, αιτιατική)."},{"gr":"Μίσει τούς δειλούς.","an":"Αντικείμενο = ουσιαστικοποιημένο επίθετο (τούς δειλούς)."},{"gr":"Οὐκ ἐδύναντο ἐλθεῖν.","an":"Αντικείμενο = τελικό απαρέμφατο (ἐλθεῖν), αντικείμενο του δύναμαι."},{"gr":"Οὗτοι ἔλεγον ὅτι πρός ἑσπέραν ἥξοι τό στράτευμα.","an":"Αντικείμενο = δευτερεύουσα ειδική πρόταση (ὅτι...), αντικείμενο του ἔλεγον."},{"gr":"Κῦρος ἔτρεψε τούς ἑξακισχιλίους.","an":"Αντικείμενο = αριθμητικό ουσιαστικοποιημένο (τούς ἑξακισχιλίους)."},{"gr":"Βούλομαι σωθῆναι.","an":"Αντικείμενο = τελικό απαρέμφατο (σωθῆναι), αντικείμενο του βούλομαι (ρήμα βούλησης)."},{"gr":"Οὐκ οἶδα ὅ τι λέγεις.","an":"Αντικείμενο = δευτερεύουσα πλάγια ερωτηματική πρόταση (ὅ τι λέγεις), αντικείμενο του οἶδα."}],"note":"Όταν το αντικείμενο είναι απαρέμφατο ή δευτερεύουσα πρόταση, ΔΕΝ έχει πτώση — γι' αυτό η ερώτηση «τι;» απαντάται με ολόκληρη φράση/πρόταση. Η αναγνώριση γίνεται από το ότι το ρήμα είναι μεταβατικό και ζητά συμπλήρωμα."}]);
  T("syn-monoptota-rimata", [{"h":"Τι είναι τα μονόπτωτα ρήματα — ορισμός και θέση στο σύστημα του αντικειμένου","body":"<p>Πριν μιλήσουμε για τα μονόπτωτα ρήματα, πρέπει να θυμηθούμε τι είναι το <b>αντικείμενο</b>: είναι η λέξη (ουσιαστικό, αντωνυμία, επίθετο, μετοχή, απαρέμφατο, αριθμητικό ή ολόκληρη πρόταση) που <i>δέχεται</i> ή <i>συμπληρώνει</i> την ενέργεια ενός <b>μεταβατικού ρήματος</b>. Λέγεται «μεταβατικό» επειδή η ενέργειά του «μεταβαίνει» (περνά) από το υποκείμενο σε ένα άλλο πρόσωπο ή πράγμα (π.χ. <i>ὁ στρατηγός νικᾷ τούς πολεμίους</i>).</p><h3>Ο ορισμός των μονόπτωτων</h3><p><b>Μονόπτωτα</b> ονομάζονται τα μεταβατικά ρήματα που συντάσσονται με <b>ένα μόνο αντικείμενο σε μία μόνο πτώση</b>. Στον ορισμό αυτόν περιλαμβάνονται και οι περιπτώσεις όπου το ρήμα δέχεται <i>περισσότερα από ένα αντικείμενα, αλλά όλα της ίδιας ποιότητας και στην ίδια πτώση</i> (π.χ. <i>φιλῶ τόν πατέρα καί τήν μητέρα</i> — δύο αντικείμενα, αλλά και τα δύο αιτιατικές της ίδιας λειτουργίας· το ρήμα παραμένει μονόπτωτο).</p><p>Αντίθετα, τα <b>δίπτωτα</b> ρήματα συντάσσονται με <b>δύο αντικείμενα διαφορετικής ποιότητας σε δύο διαφορετικές πτώσεις</b> (π.χ. <i>διδάσκω τούς παῖδας γράμματα</i> — αιτιατική προσώπου + αιτιατική πράγματος· <i>δίδωμί σοι τό βιβλίον</i> — δοτική + αιτιατική).</p><h3>Σε ποιες πτώσεις τίθεται το αντικείμενο των μονόπτωτων;</h3><p>Στην αρχαία ελληνική το αντικείμενο των μονόπτωτων ρημάτων μπορεί να βρίσκεται σε <b>τρεις πλάγιες πτώσεις</b>:</p><ul><li><b>Αιτιατική</b> — η συνηθέστερη, η «κατεξοχήν» πτώση του αντικειμένου.</li><li><b>Γενική</b> — δηλώνει συχνά μερική σχέση, αφαίρεση, εξάρτηση ή επαφή.</li><li><b>Δοτική</b> — δηλώνει συχνά τον δέκτη της ενέργειας, την κατεύθυνση προς πρόσωπο ή τη συνύπαρξη.</li></ul><p>Η <b>ονομαστική</b> και η <b>κλητική</b> δεν λειτουργούν ποτέ ως αντικείμενα. Το μεγάλο διδακτικό βάρος του κεφαλαίου πέφτει στα ρήματα της γενικής και της δοτικής, γιατί στη νέα ελληνική σχεδόν όλα τα αντικείμενα είναι αιτιατικές· έτσι ο μαθητής πρέπει να μάθει συστηματικά ποια αρχαία ρήματα «θέλουν» γενική και ποια δοτική.</p>","examples":[{"gr":"Κῦρος ἐθήρευεν κάπρους.","an":"Ο Κύρος κυνηγούσε αγριογούρουνα. — Μονόπτωτο με <b>αιτιατική</b> (<i>κάπρους</i>): ένα αντικείμενο, μία πτώση."},{"gr":"Μέμνησο τῶν ἀπόντων φίλων.","an":"Να θυμάσαι τους απόντες φίλους. — Μονόπτωτο με <b>γενική</b> (<i>τῶν φίλων</i>), γιατί το <i>μέμνημαι</i> δηλώνει μνήμη."},{"gr":"Ὁ νεανίας εἵπετο τῷ λοχαγῷ.","an":"Ο νέος ακολουθούσε τον λοχαγό. — Μονόπτωτο με <b>δοτική</b> (<i>τῷ λοχαγῷ</i>), γιατί το <i>ἕπομαι</i> δηλώνει ακολουθία."},{"gr":"Φιλῶ τόν πατέρα καί τήν μητέρα.","an":"Αγαπώ τον πατέρα και τη μητέρα. — Δύο αντικείμενα, αλλά ίδιας ποιότητας και στην ίδια πτώση (αιτιατική)· το ρήμα παραμένει μονόπτωτο."},{"gr":"Ὁ στρατηγός νικᾷ τούς πολεμίους.","an":"Ο στρατηγός νικά τους εχθρούς. — Τυπικό μονόπτωτο με μία <b>αιτιατική</b> (<i>τούς πολεμίους</i>): η ενέργεια «μεταβαίνει» από το υποκείμενο στο αντικείμενο."},{"gr":"Διδάσκω τούς παῖδας γράμματα.","an":"Διδάσκω στα παιδιά γράμματα. — Αντιπαράδειγμα: <b>δίπτωτο</b> (αιτ. προσώπου <i>τούς παῖδας</i> + αιτ. πράγματος <i>γράμματα</i>, διαφορετικής ποιότητας)."}],"table":{"title":"Μονόπτωτα και δίπτωτα — η βασική διάκριση","cols":["Είδος","Αριθμός / ποιότητα αντικειμένων","Παράδειγμα"],"rows":[["Μονόπτωτο","ένα αντικείμενο σε μία πτώση","νικῶ <b>τούς πολεμίους</b> (αιτ.)"],["Μονόπτωτο","πολλά αντικ. ίδιας ποιότητας, ίδια πτώση","ἀγαπῶ <b>τόν φίλον καί τόν ἀδελφόν</b> (αιτ.+αιτ.)"],["Δίπτωτο","δύο αντικ. διαφορετικής ποιότητας/πτώσης","διδάσκω <b>τούς παῖδας</b> (αιτ.) <b>μουσικήν</b> (αιτ. πράγματος)"],["Δίπτωτο","γενική + αιτιατική","ἀποστερῶ <b>τινα</b> (αιτ.) <b>χρημάτων</b> (γεν.)"]]},"note":"Προσοχή στην παγίδα: «πολλά αντικείμενα» δεν σημαίνει αυτομάτως «δίπτωτο». Κρίσιμη είναι η ΠΟΙΟΤΗΤΑ. Δύο αιτιατικές ίδιας λειτουργίας = μονόπτωτο· αιτιατική προσώπου + αιτιατική πράγματος (διαφορετικής ποιότητας) = δίπτωτο."},{"h":"Μονόπτωτα με ΓΕΝΙΚΗ — η λογική της πτώσης","body":"<p>Η γενική ως αντικείμενο εκφράζει σχεδόν πάντα μια σχέση <b>μερική, αφαιρετική ή εξαρτητική</b>: το υποκείμενο αγγίζει, θυμάται, επιθυμεί, μετέχει, εξουσιάζει ή απομακρύνεται από κάτι — δηλαδή σχετίζεται με ένα <i>μέρος</i> ή με την <i>περιοχή</i> του αντικειμένου, όχι με το σύνολό του «κατά μέτωπο» όπως κάνει η αιτιατική. Γι' αυτό λέμε ότι η γενική του αντικειμένου είναι κατά βάθος <b>γενική διαιρετική</b> (μερική) ή <b>γενική αφαιρετική / χωριστική</b>.</p><p>Παράδειγμα της λεπτής αυτής διαφοράς: <i>ἀκούω τήν φωνήν</i> (αιτ.) = ακούω ολόκληρο τον ήχο, τον αντιλαμβάνομαι ως σύνολο/περιεχόμενο· αλλά <i>ἀκούω τοῦ λέγοντος</i> (γεν.) = ακούω τον ομιλητή, στρέφω την ακοή μου προς αυτόν (μερική επαφή με την πηγή του ήχου). Η ίδια λογική φωτίζει όλες τις σημασιολογικές ομάδες που ακολουθούν.</p><h3>Οι μεγάλες σημασιολογικές ομάδες</h3><p>Παρακάτω δίνονται οι κύριες κατηγορίες ρημάτων που συντάσσονται με γενική. Δεν χρειάζεται να αποστηθίσει κανείς τυφλά τους καταλόγους· πολύ πιο γόνιμο είναι να συλλάβει τη <i>σημασιολογική λογική</i> κάθε ομάδας, ώστε να αναγνωρίζει και άγνωστα ρήματα.</p>","examples":[{"gr":"Ἐπεμελοῦντο τῆς πόλεως.","an":"Φρόντιζαν για την πόλη. — <i>ἐπιμελοῦμαι</i> (φροντίδας) + γενική <i>τῆς πόλεως</i>."},{"gr":"Κριτίας ἐπεθύμησε τῆς σωφροσύνης.","an":"Ο Κριτίας επιθύμησε τη σωφροσύνη. — <i>ἐπιθυμῶ</i> (επιθυμίας) + γενική."},{"gr":"Οἱ πατέρες ἡμῶν Μήδων ἐκράτησαν.","an":"Οι πρόγονοί μας νίκησαν / κυριάρχησαν επί των Μήδων. — <i>κρατῶ</i> (εξουσίας) + γενική <i>Μήδων</i>."},{"gr":"Πατρός ἀγαθοῦ πέφυκα.","an":"Κατάγομαι από ενάρετο πατέρα. — <i>πέφυκα</i> (καταγωγής) + γενική προέλευσης <i>πατρός</i>."},{"gr":"Φρονήσεως δέ καί ἀληθείας καί τῆς ψυχῆς οὐκ ἐπιμελῇ;","an":"Πλ. Ἀπολ. 29e — «Δεν φροντίζεις για τη φρόνηση και την αλήθεια και την ψυχή σου;» <i>ἐπιμελοῦμαι</i> (φροντίδας) + γενική <i>φρονήσεως, ἀληθείας, ψυχῆς</i>."},{"gr":"Ἤκουσε θορύβου.","an":"Ξεν. Ἀνάβ. 1.8.16 (τύπου) — «Άκουσε θόρυβο.» <i>ἀκούω</i> (αίσθηση) + γενική <i>θορύβου</i>: στρέφει την ακοή προς την πηγή του ήχου."}],"note":"Πολλά ρήματα συντάσσονται και με γενική και με αιτιατική, με σημασιολογική διαφορά (βλ. ακούω παραπάνω, ή γεύομαι/ἅπτομαι). Η αλλαγή πτώσης συχνά αλλάζει την απόχρωση: μερική επαφή (γεν.) έναντι ολικής κατάληψης (αιτ.)."},{"h":"Κατάλογος ρημάτων με ΓΕΝΙΚΗ — πλήρης ανά σημασιολογική ομάδα","body":"<p>Ο πίνακας που ακολουθεί συγκεντρώνει τις δεκαέξι βασικές ομάδες ρημάτων που στην αττική σύνταξη συντάσσονται με αντικείμενο σε γενική. Είναι το «εργαλείο αναφοράς» του κεφαλαίου: όταν σε ένα κείμενο συναντάς γενική μετά από ρήμα, ελέγχεις σε ποια ομάδα ανήκει το ρήμα και επιβεβαιώνεις ότι πρόκειται για αντικείμενο.</p><p>Παρατήρησε ότι πολλές ομάδες εκφράζουν <b>επαφή ή μέθεξη</b> (αίσθηση, απόλαυση, μετοχή, πλησμονή) και άλλες <b>αφαίρεση ή απόσταση</b> (στέρηση, χωρισμός, σύγκριση, καταγωγή). Αυτές οι δύο μεγάλες «οικογένειες» νοημάτων δικαιολογούν τη γενική: η πρώτη ως διαιρετική, η δεύτερη ως αφαιρετική.</p>","table":{"title":"Ρήματα με αντικείμενο σε γενική","cols":["Σημασιολογική ομάδα","Κύρια ρήματα","Παράδειγμα"],"rows":[["Μνήμη / λήθη","μέμνημαι, μιμνήσκομαι, μνημονεύω, ἐπιλανθάνομαι, ἀμνημονῶ","μέμνησο <b>τῶν φίλων</b>"],["Φροντίδα / επιμέλεια","ἐπιμελοῦμαι, φροντίζω, προνοῶ, κήδομαι, μεταμέλομαι, ἀμελῶ, ὀλιγωρῶ","ἐπεμελοῦντο <b>τῆς πόλεως</b>"],["Φειδώ","φείδομαι, ἀφειδῶ","οὐκ ἐφείδετο <b>χρημάτων</b>"],["Επιθυμία / έρωτας","ἐπιθυμῶ, ἐρῶ, ἐφίεμαι, ὀρέγομαι, γλίχομαι","ἐπεθύμησε <b>τῆς σωφροσύνης</b>"],["Απόλαυση","ἀπολαύω, ὀνίναμαι","ἀπολαύουσι <b>τῶν ἀγαθῶν</b>"],["Μετοχή / συμμετοχή","μετέχω, μεταλαμβάνω, κοινωνῶ, κληρονομῶ","μετέσχον <b>πόνων</b>"],["Πλησμονή / αφθονία","γέμω, πίμπλαμαι, βρίθω, εὐπορῶ, πλήθω","ὁ λιμήν ἔγεμε <b>πλοίων</b>"],["Στέρηση / έλλειψη","δέομαι, χρῄζω, ἀπορῶ, σπανίζω, στέρομαι","δεῖται <b>βοηθείας</b>"],["Αίσθηση / επαφή","ἅπτομαι, ψαύω, θιγγάνω, γεύομαι, ὀσφραίνομαι, ἀκούω, ἀκροῶμαι","ἀκούετε <b>τῶν μαρτύρων</b>"],["Απόπειρα / επιτυχία-αποτυχία","πειρῶμαι, τυγχάνω, ἐφικνοῦμαι, ἀποτυγχάνω, ἁμαρτάνω","<b>νίκης</b> τετυχήκαμεν"],["Έναρξη / λήξη","ἄρχομαι, λήγω, παύομαι","ἄρχονται <b>τῆς φυγῆς</b>"],["Αρχή / εξουσία","ἄρχω, κρατῶ, βασιλεύω, ἡγεμονεύω, δεσπόζω, τυραννῶ","ἐκράτησαν <b>Μήδων</b>"],["Χωρισμός / απομάκρυνση","χωρίζομαι, ἀπέχω, διέχω, παραχωρῶ, ἀπαλλάττομαι, ἐλευθερῶ, λύομαι","παραχωροῦσι <b>ὁδοῦ</b>"],["Καταγωγή","εἰμί, γίγνομαι, ἔφυν, πέφυκα","<b>πατρός</b> ἀγαθοῦ πέφυκα"],["Σύγκριση / διαφορά","ἡττῶμαι, λείπομαι, ὑστερῶ, διαφέρω, προέχω, πλεονεκτῶ, μειονεκτῶ","μειονεκτῶ <b>τῶν ἰδιωτῶν</b>"],["Σύνθετα με ἀπό/ἐκ/πρό/ὑπέρ/κατά","ἀφίσταμαι, ἐκβάλλω, προκινδυνεύω, προτιμῶ, καταγελῶ, ὑπερέχω","προκινδυνεύουσι <b>τῶν πολιτῶν</b>"]]},"examples":[{"gr":"Ἤσθοντο τῆς κραυγῆς.","an":"Αντιλήφθηκαν την κραυγή. — αίσθηση (<i>αἰσθάνομαι</i>) + γενική."},{"gr":"Ὁ λιμήν ἔγεμε πλοίων.","an":"Το λιμάνι ήταν γεμάτο πλοία. — πλησμονή/αφθονία (<i>γέμω</i>) + γενική."},{"gr":"Οἱ κακοί ἄρχονται τῆς φυγῆς.","an":"Οι δειλοί ξεκινούν τη φυγή. — έναρξη (<i>ἄρχομαι</i>) + γενική."},{"gr":"Προκινδυνεύουσι τῶν πολιτῶν.","an":"Διακινδυνεύουν / πολεμούν για χάρη των πολιτών. — σύνθετο με πρό + γενική."},{"gr":"Χρημάτων ἐπιθυμεῖ.","an":"Ξεν. Ἀνάβ. (τύπου) — «Επιθυμεί χρήματα.» επιθυμία (<i>ἐπιθυμῶ</i>) + γενική <i>χρημάτων</i>."},{"gr":"Οὐδείς γάρ τῶν παρόντων ἀντέλεγεν.","an":"μετοχή / συμμετοχή (τύπου): πρβ. <i>μετέχω, κοινωνῶ</i> + γενική· εδώ η γενική <i>τῶν παρόντων</i> δηλώνει το σύνολο μέσα στο οποίο εντάσσεται το υποκείμενο (γεν. διαιρετική)."}],"note":"Διάκρισε προσεκτικά: ἄρχω + γενική = εξουσιάζω, κυβερνώ· ἄρχομαι + γενικής = αρχίζω κάτι. Ίδια ρίζα, αντίθετη φωνή, εντελώς διαφορετική σημασία — αλλά και οι δύο θέλουν γενική."},{"h":"Μονόπτωτα με ΔΟΤΙΚΗ — η λογική της πτώσης","body":"<p>Η δοτική ως αντικείμενο εκφράζει τυπικά τον <b>δέκτη ή τον αποδέκτη</b> της ενέργειας, την <b>κατεύθυνση προς ένα πρόσωπο</b> ή τη <b>συνύπαρξη / επαφή</b> με αυτό. Πρόκειται κατά βάθος για δοτικές <i>χαριστικές</i> (υπέρ κάποιου), <i>αντιχαριστικές</i> (εις βάρος κάποιου), <i>του ποιητικού αιτίου</i> ή <i>της συνοδείας/κοινωνίας</i>, παγιωμένες ως αντικείμενο συγκεκριμένων ρημάτων.</p><p>Στην αρχαία ελληνική η δοτική είναι πολύ ζωντανή πτώση που στη νέα γλώσσα έχει χαθεί (την αντικατέστησαν το «σε + αιτιατική» ή η γενική). Γι' αυτό ο μαθητής πρέπει να μάθει συνειδητά τις ομάδες· διαφορετικά θα μπει στον πειρασμό να αποδώσει με αιτιατική αυτό που η αρχαία θέλει σε δοτική (π.χ. <i>βοηθῶ τῇ πόλει</i>, όχι «τήν πόλιν»).</p><h3>Η σημασιολογική «οικογένεια» της δοτικής</h3><p>Σχεδόν όλες οι ομάδες περιγράφουν <b>σχέση μεταξύ προσώπων</b>: ακολουθώ κάποιον, πειθαρχώ σε κάποιον, βοηθώ ή πολεμώ κάποιον, μοιάζω με κάποιον, συμφωνώ ή φιλονικώ με κάποιον, συνυπάρχω με κάποιον. Αυτή η κοινή ιδέα της <i>διαπροσωπικής κατεύθυνσης</i> είναι το κλειδί για να θυμάσαι ποια ρήματα θέλουν δοτική.</p>","examples":[{"gr":"Πλησίαζε τοῖς ἀγαθοῖς.","an":"Να συναναστρέφεσαι τους καλούς ανθρώπους. — προσέγγιση (<i>πλησιάζω</i>) + δοτική."},{"gr":"Ἀμύνω τῇ πόλει.","an":"Υπερασπίζομαι / βοηθώ την πόλη. — βοήθεια (<i>ἀμύνω</i>) + δοτική χαριστική."},{"gr":"Φιλοσόφῳ ἔοικας, ὦ νεανίσκε.","an":"Μοιάζεις με φιλόσοφο, νεαρέ. — ομοιότητα (<i>ἔοικα</i>) + δοτική."},{"gr":"Ἐμμείνατε τοῖς ὅρκοις.","an":"Μείνετε πιστοί στους όρκους. — σύνθετο με ἐν (<i>ἐμμένω</i>) + δοτική."},{"gr":"Πείσομαι μᾶλλον τῷ θεῷ ἤ ὑμῖν.","an":"Πλ. Ἀπολ. 29d (τύπου) — «Θα υπακούσω στον θεό μάλλον παρά σε εσάς.» πειθαρχία (<i>πείθομαι</i>) + δοτική <i>τῷ θεῷ, ὑμῖν</i>."},{"gr":"Ἀκολουθεῖ τῷ ἡγουμένῳ.","an":"Ακολουθεί αυτόν που οδηγεί. — ακολουθία (<i>ἀκολουθῶ</i>) + δοτική <i>τῷ ἡγουμένῳ</i> (δοτ. συνοδείας)."}],"note":"Μην συγχέεις το αντικείμενο σε δοτική με τη ΔΟΤΙΚΗ ΠΡΟΣΩΠΙΚΗ. Το αντικείμενο εξαρτάται μόνο από το ρήμα και απαιτείται από τη σύνταξή του· η δοτική προσωπική (χαριστική, ηθική κ.λπ.) είναι προαιρετική και αναφέρεται στο νόημα όλης της πρότασης (π.χ. <i>ταῦτά μοι λέλεκται</i> = αυτά έχουν ειπωθεί από εμένα)."},{"h":"Κατάλογος ρημάτων με ΔΟΤΙΚΗ — πλήρης ανά σημασιολογική ομάδα","body":"<p>Ο επόμενος πίνακας συγκεντρώνει τις βασικές ομάδες ρημάτων που συντάσσονται με αντικείμενο σε δοτική. Όπως και στη γενική, η αξία του είναι διπλή: λειτουργεί ως κατάλογος αναφοράς, αλλά κυρίως αποκαλύπτει το κοινό σημασιολογικό νήμα — τη <b>σχέση προς πρόσωπο</b> (ευνοϊκή, εχθρική, ισότητας, ομοιότητας, ακολουθίας, επικοινωνίας).</p>","table":{"title":"Ρήματα με αντικείμενο σε δοτική","cols":["Σημασιολογική ομάδα","Κύρια ρήματα","Παράδειγμα"],"rows":[["Πρέπει / αρμόζει","δεῖ, ἁρμόττει, προσήκει, πρέπει","ὁ κόθορνος ἁρμόττει <b>τοῖς ποσίν</b>"],["Προσέγγιση / συνάντηση","πλησιάζω, πελάζω, ἐντυγχάνω, συντυγχάνω","πλησίαζε <b>τοῖς ἀγαθοῖς</b>"],["Ακολουθία","ἀκολουθῶ, ἕπομαι","εἵπετο <b>τῷ λοχαγῷ</b>"],["Πειθαρχία / υπακοή","πείθομαι, πειθαρχῶ, ὑπακούω, ὑπείκω, εἴκω","πείθομαι <b>τοῖς νόμοις</b>"],["Επικοινωνία / ένωση","ὁμιλῶ, χρῶμαι, μείγνυμαι, κεράννυμι","χρῶνται <b>τοῖς ἐφήβοις</b>"],["Φιλική διάθεση / βοήθεια","εὐνοῶ, βοηθῶ, ἀρήγω, ἀμύνω, χαρίζομαι, ἀρέσκω, λυσιτελῶ","ἀμύνω <b>τῇ πόλει</b>"],["Εχθρική διάθεση","φθονῶ, ἐνοχλῶ, μάχομαι, πολεμῶ, ἐπιτιμῶ, μέμφομαι","ἐπολέμουν <b>τοῖς Ἀθηναίοις</b>"],["Άμιλλα","ἁμιλλῶμαι, ἐρίζω","ἡμιλλῶντο <b>τοῖς ἵπποις</b>"],["Έριδα / συμφιλίωση","διαφέρομαι, σπένδομαι, διαλλάττομαι, καταλλάττομαι","σπένδεται <b>Μαντινεῦσιν</b>"],["Ισότητα","ἰσοῦμαι","μναῖ ἰσοῦνται <b>ταλάντῳ</b>"],["Ομοιότητα","ἔοικα, ὁμοιάζω, προσέοικα","<b>φιλοσόφῳ</b> ἔοικας"],["Συμφωνία","συμφωνῶ, ὁμολογῶ, ὁμονοῶ, συνᾴδω, συναρμόττω","τά ἔργα οὐ συμφωνεῖ <b>τοῖς λόγοις</b>"],["Σύνθετα με ἐν/σύν/ἐπί/περί/παρά/ὑπό/πρός","ἐμμένω, σύνειμι, συνοικῶ, ἐπιτίθεμαι, περιπίπτω, παραγίγνομαι, ὑπόκειμαι","συνῇσαν <b>Σωκράτει</b>"]]},"examples":[{"gr":"Τά ἔργα ὑμῶν οὐ συμφωνεῖ τοῖς λόγοις.","an":"Τα έργα σας δεν συμφωνούν με τα λόγια σας. — συμφωνία (<i>συμφωνῶ</i>) + δοτική."},{"gr":"Δημοσθένης σπένδεται Μαντινεῦσιν.","an":"Ο Δημοσθένης συνάπτει συνθήκη με τους Μαντινείς. — συμφιλίωση (<i>σπένδομαι</i>) + δοτική."},{"gr":"Περιπέσομεν κινδύνοις.","an":"Θα περιπέσουμε σε κινδύνους. — σύνθετο με περί (<i>περιπίπτω</i>) + δοτική."},{"gr":"Ἑξήκοντα μναῖ ἰσοῦνται ταλάντῳ.","an":"Εξήντα μνες ισοδυναμούν με ένα τάλαντο. — ισότητα (<i>ἰσοῦμαι</i>) + δοτική."},{"gr":"Κύρῳ πειθαρχεῖν ἐθέλουσιν.","an":"Ξεν. (τύπου) — «Θέλουν να πειθαρχούν στον Κύρο.» πειθαρχία (<i>πειθαρχῶ</i>) + δοτική <i>Κύρῳ</i>."},{"gr":"Οἱ πολλοί φθονοῦσι τοῖς εὐτυχοῦσιν.","an":"Οι πολλοί φθονούν αυτούς που ευτυχούν. — εχθρική διάθεση (<i>φθονῶ</i>) + δοτική <i>τοῖς εὐτυχοῦσιν</i>· στα νέα ελληνικά «φθονώ κάποιον» (αιτ.)."}],"note":"Πολλά «εχθρικά» ρήματα μπορεί να μπερδέψουν: πολεμῶ, μάχομαι, ἐπιτιμῶ θέλουν ΔΟΤΙΚΗ (πολεμῶ τινι = πολεμώ εναντίον κάποιου), ενώ στη νέα ελληνική θα λέγαμε «πολεμώ ΚΑΠΟΙΟΝ» (αιτιατική). Είναι κλασική παγίδα μετάφρασης."},{"h":"Μονόπτωτα με ΑΙΤΙΑΤΙΚΗ — και η διάκριση εξωτερικού / εσωτερικού αντικειμένου","body":"<p>Η <b>αιτιατική</b> είναι η φυσική, η κατεξοχήν πτώση του αντικειμένου: δηλώνει το πρόσωπο ή το πράγμα που δέχεται <i>κατά μέτωπο και στο σύνολό του</i> την ενέργεια του ρήματος. Η συντριπτική πλειονότητα των μεταβατικών ρημάτων (γράφω, ποιῶ, νικῶ, ὁρῶ, φιλῶ...) είναι μονόπτωτα με αιτιατική. Το ενδιαφέρον εδώ δεν είναι τόσο οι κατάλογοι, όσο μια θεμελιώδης θεωρητική διάκριση που πρέπει να κατέχει κάθε μαθητής.</p><h3>Εξωτερικό και εσωτερικό αντικείμενο</h3><p>Το αντικείμενο σε αιτιατική διακρίνεται σε δύο μεγάλα είδη ανάλογα με τη σχέση του με το ρήμα:</p><ul><li><b>Εξωτερικό αντικείμενο:</b> δηλώνει πρόσωπο ή πράγμα που <i>προϋπάρχει</i> και είναι ανεξάρτητο από την ενέργεια του ρήματος. Η ενέργεια απλώς το βρίσκει «έτοιμο» και πέφτει επάνω του. Π.χ. <i>ὁ τέκτων κατασκευάζει</i> — ο ξυλουργός δουλεύει πάνω σε ξύλα που ήδη υπάρχουν.</li><li><b>Εσωτερικό αντικείμενο:</b> δεν προϋπάρχει· <i>παράγεται, δημιουργείται από την ίδια την ενέργεια</i> του ρήματος. Διακρίνεται σε δύο υποπεριπτώσεις:<ul><li><b>(α) του αποτελέσματος:</b> είναι το προϊόν της ενέργειας (<i>ὁ τέκτων κατασκευάζει οἰκίαν</i> — το σπίτι προκύπτει από το χτίσιμο).</li><li><b>(β) σύστοιχο:</b> προέρχεται από την <i>ίδια ρίζα</i> με το ρήμα (ή από συγγενική ρίζα) και απλώς επαναλαμβάνει/εξειδικεύει το περιεχόμενό του.</li></ul></li></ul><h3>Το σύστοιχο αντικείμενο</h3><p>Το <b>σύστοιχο αντικείμενο</b> (accusative of the inner / cognate object, κατά τον Smyth) είναι ένα από τα πιο χαρακτηριστικά φαινόμενα της αρχαίας ελληνικής. Συνήθως συνοδεύεται από <i>επιθετικό προσδιορισμό</i> που φέρει το πραγματικό νόημα (π.χ. <i>νοσῶ νόσον χαλεπήν</i> = αρρωσταίνω με βαριά αρρώστια). Μάλιστα και <b>αμετάβατα ρήματα</b> μπορούν να πάρουν σύστοιχο αντικείμενο, γι' αυτό το θέμα συνδέεται στενά με την επόμενη ενότητα.</p>","examples":[{"gr":"Κλέαρχος ὠφέλει τούς Ἕλληνας.","an":"Ο Κλέαρχος ωφελούσε τους Έλληνες. — μονόπτωτο με αιτιατική (εξωτερικό αντικείμενο)· οι Έλληνες προϋπάρχουν."},{"gr":"Ὁ τέκτων οἰκοδομεῖ οἰκίαν.","an":"Ο οικοδόμος χτίζει σπίτι. — εσωτερικό αντικείμενο του ΑΠΟΤΕΛΕΣΜΑΤΟΣ· η οικία δημιουργείται από την ενέργεια."},{"gr":"Νοσῶ νόσον χαλεπήν.","an":"Πάσχω από βαριά αρρώστια. — ΣΥΣΤΟΙΧΟ αντικείμενο (<i>νόσον</i> από ίδια ρίζα με το <i>νοσῶ</i>)· το νόημα το κουβαλά το επίθετο <i>χαλεπήν</i>."},{"gr":"Μάχην ἐμαχέσαντο καρτεράν.","an":"Έδωσαν σφοδρή μάχη. — σύστοιχο αντικείμενο (<i>μάχην</i> ↔ <i>μάχομαι</i>) με επίθετο <i>καρτεράν</i>."},{"gr":"Τήν ἐν Σαλαμῖνι ναυμαχίαν ναυμαχήσαντες.","an":"Θουκ. (τύπου) — «Αφού έδωσαν τη ναυμαχία στη Σαλαμίνα.» ΣΥΣΤΟΙΧΟ αντικείμενο (<i>ναυμαχίαν</i> ↔ <i>ναυμαχῶ</i>) εξειδικευμένο με επιθετικό προσδιορισμό."},{"gr":"Πολλήν φλυαρίαν φλυαρεῖ.","an":"Πλ. (τύπου) — «Λέει πολλές ανοησίες.» ΣΥΣΤΟΙΧΟ αντικείμενο (<i>φλυαρίαν</i> ↔ <i>φλυαρῶ</i>) με ποσοτικό προσδιορισμό <i>πολλήν</i>."}],"table":{"title":"Είδη αντικειμένου σε αιτιατική","cols":["Είδος","Σχέση με το ρήμα","Παράδειγμα"],"rows":[["Εξωτερικό","προϋπάρχει της ενέργειας","νικῶ <b>τούς πολεμίους</b>"],["Εσωτερικό (αποτελέσματος)","δημιουργείται από την ενέργεια","γράφω <b>ἐπιστολήν</b>"],["Εσωτερικό (σύστοιχο)","ίδια/συγγενική ρίζα με το ρήμα","νοσῶ <b>νόσον</b>, ζῶ <b>βίον</b>"]]},"note":"Το σύστοιχο αντικείμενο σπάνια στέκεται «γυμνό»· σχεδόν πάντα φέρει προσδιορισμό (νόσον χαλεπήν, βίον μακάριον). Χωρίς προσδιορισμό θεωρείται περιττό (ταυτολογικό) και αποφεύγεται — αυτή είναι η συνηθέστερη εξεταστική ερώτηση πάνω του."},{"h":"Κατάλογος ρημάτων με ΑΙΤΙΑΤΙΚΗ — ειδικές κατηγορίες και αμετάβατα ως μεταβατικά","body":"<p>Πέρα από τα αμέτρητα «κανονικά» μεταβατικά ρήματα με αιτιατική, η σχολική παράδοση επισημαίνει ορισμένες <b>ειδικές κατηγορίες</b> που αξίζει να γνωρίζει κανείς, καθώς εμφανίζουν ιδιαιτερότητες σημασίας ή μετάφρασης.</p><h3>Αμετάβατα ρήματα που λειτουργούν ως μεταβατικά</h3><p>Η πιο ενδιαφέρουσα κατηγορία: ρήματα που κανονικά είναι <b>αμετάβατα</b> (δηλώνουν ψυχική κατάσταση, συναίσθημα ή κίνηση) αποκτούν μεταβατική χρήση και παίρνουν αιτιατική. Έτσι <i>φοβοῦμαι, αἰσχύνομαι, αἰδοῦμαι, εὐλαβοῦμαι, φυλάττομαι, δέδοικα, κλαίω, δακρύω, πενθῶ, ποθῶ, ἀλγῶ</i> συντάσσονται με αιτιατική του προσώπου ή του πράγματος που προκαλεί το συναίσθημα. Π.χ. <i>φοβοῦμαι τόν θάνατον</i> = φοβάμαι τον θάνατο.</p><p>Παρόμοια, ρήματα κίνησης ή μονιμότητας όπως <i>οἰκῶ, μένω, περιμένω</i> μπορούν να πάρουν αιτιατική (<i>οἰκῶ τήν πόλιν</i> = κατοικώ την πόλη), και ρήματα όπως <i>φθάνω, λανθάνω</i> συντάσσονται με αιτιατική + κατηγορηματική μετοχή.</p>","table":{"title":"Ειδικές ομάδες ρημάτων με αιτιατική","cols":["Σημασιολογική ομάδα","Κύρια ρήματα","Παράδειγμα"],"rows":[["Ωφέλεια / βλάβη","ὠφελῶ, εὐεργετῶ, εὖ ποιῶ, βλάπτω, ἀδικῶ, κολακεύω","ὠφέλει <b>τούς Ἕλληνας</b>"],["Δίωξη / αποφυγή","θηρῶ, διώκω, ἐνεδρεύω, φεύγω, ἀποδιδράσκω, ζηλῶ","ἐθήρευεν <b>κάπρους</b>"],["Συναισθήματα (αμετάβ. → μεταβ.)","φοβοῦμαι, δέδοικα, αἰσχύνομαι, αἰδοῦμαι, εὐλαβοῦμαι, φυλάττομαι, κλαίω, πενθῶ, ποθῶ, ἀλγῶ","αἰσχύνῃ <b>τούς λόγους</b>"],["Διαμονή / στάση","οἰκῶ, μένω, περιμένω","οἰκῶμεν <b>τήν πόλιν</b>"],["Προτεραιότητα / λανθάνειν","φθάνω, λανθάνω","ἔφθασε <b>τούς πολεμίους</b>"],["Διάφορα","κελεύω, ὄμνυμι, ἐπιορκῶ, σπεύδω, θαρρῶ, σιγῶ","ἐκέλευσεν <b>τούς ἕνδεκα</b>"]]},"examples":[{"gr":"Νῦν δέ οὔτε ἐκείνους τούς λόγους αἰσχύνῃ.","an":"Τώρα όμως δεν ντρέπεσαι ούτε εκείνα τα λόγια. — αμετάβατο <i>αἰσχύνομαι</i> με αιτιατική (μεταβατική χρήση)."},{"gr":"Οὕτως οἰκῶμεν τήν πόλιν.","an":"Έτσι ας κατοικούμε / διοικούμε την πόλη. — <i>οἰκῶ</i> + αιτιατική."},{"gr":"Ἐκέλευσεν ὁ κῆρυξ τούς ἕνδεκα.","an":"Ο κήρυκας διέταξε τους έντεκα. — <i>κελεύω</i> + αιτιατική προσώπου."},{"gr":"Φοβοῦμαι τόν θάνατον.","an":"Φοβάμαι τον θάνατο. — αμετάβατο συναίσθημα με αιτιατική του προκαλούντος."},{"gr":"Οὕς ἐγώ μᾶλλον φοβοῦμαι ἤ τούς ἀμφί Ἄνυτον.","an":"Πλ. Ἀπολ. (τύπου) — «Τους οποίους εγώ φοβάμαι περισσότερο από τον Άνυτο και τους περί αυτόν.» <i>φοβοῦμαι</i> + αιτιατική (αναφορική αντωνυμία <i>οὕς</i>)."},{"gr":"Ἔφθασαν τούς πολεμίους ἐπί τῷ ἄκρῳ γενόμενοι.","an":"Ξεν. (τύπου) — «Πρόλαβαν τους εχθρούς φτάνοντας στην κορυφή.» <i>φθάνω</i> + αιτιατική <i>τούς πολεμίους</i> + κατηγορηματική μετοχή <i>γενόμενοι</i>."}],"note":"Παγίδα: τα συναισθηματικά ρήματα μπορεί να συντάσσονται ΚΑΙ με γενική της αιτίας ή με εμπρόθετο (φοβοῦμαι ὑπέρ τινος = φοβάμαι για κάποιον). Κρίνε από το νόημα: αιτιατική = το αντικείμενο του φόβου· γενική/εμπρόθετο = η αιτία ή το πρόσωπο για το οποίο φοβάσαι."},{"h":"Σύνοψη, μεθοδολογία αναγνώρισης και συχνές παγίδες","body":"<p>Έχοντας δει αναλυτικά τις τρεις πτώσεις, κλείνουμε με μια <b>πρακτική μέθοδο</b> για να αναγνωρίζεις και να αναλύεις σωστά τα μονόπτωτα ρήματα σε άγνωστο κείμενο, καθώς και με τις παγίδες που πέφτουν συχνότερα οι μαθητές.</p><h3>Βήματα αναγνώρισης</h3><ol><li><b>Βρες το ρήμα</b> και διαπίστωσε αν είναι μεταβατικό (αν «ζητά» συμπλήρωμα).</li><li><b>Εντόπισε την πτώση</b> της λέξης που το συμπληρώνει: αιτιατική, γενική ή δοτική;</li><li><b>Έλεγξε τη σημασιολογική ομάδα</b> του ρήματος (μνήμης; βοήθειας; εξουσίας;) για να επιβεβαιώσεις ότι η πτώση είναι όντως αντικείμενο και όχι κάποιος επιρρηματικός προσδιορισμός.</li><li><b>Μέτρησε τα αντικείμενα</b>: ένα (ή πολλά της ίδιας ποιότητας/πτώσης) ⇒ μονόπτωτο· δύο διαφορετικής ποιότητας/πτώσης ⇒ δίπτωτο.</li></ol><h3>Οι πιο επικίνδυνες παγίδες</h3><ul><li><b>Γενική/δοτική που ΜΟΙΑΖΕΙ με προσδιορισμό αλλά είναι αντικείμενο:</b> π.χ. στο <i>ἄρχω τῆς πόλεως</i> η γενική δεν είναι κτητική («της πόλης») αλλά αντικείμενο («εξουσιάζω την πόλη»).</li><li><b>Μετάφραση που «προδίδει» την πτώση:</b> πολλά αρχαία ρήματα με γενική/δοτική αποδίδονται στα νέα ελληνικά με αιτιατική (βοηθῶ τῇ πόλει → «βοηθώ την πόλη»). Στην ανάλυση όμως μετράει η <i>αρχαία</i> πτώση.</li><li><b>Ρήματα με διπλή σύνταξη:</b> ἀκούω, γεύομαι, ἅπτομαι κ.ά. αλλάζουν απόχρωση ανάλογα με γενική ή αιτιατική.</li><li><b>Σύστοιχο vs εξωτερικό αντικείμενο:</b> πάντα ψάξε αν η αιτιατική προέρχεται από την ίδια ρίζα με το ρήμα.</li><li><b>Αντικείμενο vs δοτική προσωπική:</b> η δοτική προσωπική είναι προαιρετική και αφορά όλη την πρόταση· το αντικείμενο σε δοτική απαιτείται από το ρήμα.</li></ul><h3>Γιατί έχει σημασία η σωστή κατάταξη</h3><p>Η αναγνώριση μονόπτωτου/δίπτωτου και της πτώσης του αντικειμένου δεν είναι «τυπολατρία»: καθορίζει τη <b>μετάφραση</b> (ποια απόχρωση δίνει η γενική έναντι της αιτιατικής), τη <b>μετατροπή ενεργητικής ↔ παθητικής σύνταξης</b> (μόνο το αντικείμενο σε αιτιατική γίνεται ομαλά υποκείμενο της παθητικής· τα ρήματα με γενική/δοτική σχηματίζουν προσωπική παθητική μόνο κατ' εξαίρεση) και τη συνολική κατανόηση της δομής της πρότασης.</p>","examples":[{"gr":"Ἄρχω τῆς πόλεως.","an":"Εξουσιάζω / κυβερνώ την πόλη. — η γενική <i>τῆς πόλεως</i> είναι ΑΝΤΙΚΕΙΜΕΝΟ (όχι κτητικός προσδιορισμός)."},{"gr":"Βοηθῶ τῇ πόλει.","an":"Βοηθώ την πόλη. — στα νέα ελληνικά «την πόλη» (αιτ.), αλλά στα αρχαία ΔΟΤΙΚΗ· στην ανάλυση γράφουμε «αντικείμενο σε δοτική»."},{"gr":"Ἀκούω τοῦ διδασκάλου.","an":"Ακούω / υπακούω τον δάσκαλο (στρέφω σ' αυτόν την προσοχή μου). — γενική· πρβ. ἀκούω τήν φωνήν (αιτ.) = ακούω τον ήχο ως σύνολο."},{"gr":"Ὁ νόμος ὑπό πάντων τιμᾶται.","an":"Ο νόμος τιμάται από όλους. — παθητική σύνταξη όπου το αρχικό αντικείμενο σε αιτιατική (τόν νόμον) έγινε υποκείμενο· γι' αυτό μετράει η πτώση."},{"gr":"Μέμνημαι τῶν λόγων οὕς εἶπες.","an":"Θυμάμαι τα λόγια που είπες. — η γενική <i>τῶν λόγων</i> είναι ΑΝΤΙΚΕΙΜΕΝΟ του <i>μέμνημαι</i> (μνήμης), όχι προσδιορισμός· κλασικός έλεγχος σημασιολογικής ομάδας."},{"gr":"Ἐπιθυμῶ τῆς εἰρήνης.","an":"Επιθυμώ την ειρήνη. — στα νέα ελληνικά αιτιατική, στα αρχαία ΓΕΝΙΚΗ (επιθυμίας)· η μετάφραση «προδίδει» την αρχαία πτώση."}],"note":"Χρυσός κανόνας: στη μετατροπή σε παθητική φωνή, ομαλό υποκείμενο γίνεται μόνο το αντικείμενο που ήταν σε ΑΙΤΙΑΤΙΚΗ. Τα μονόπτωτα της γενικής/δοτικής συνήθως σχηματίζουν μόνο απρόσωπη παθητική (π.χ. βοηθεῖται τῇ πόλει → «παρέχεται βοήθεια στην πόλη»), κάτι που εξετάζεται συχνά."}]);
  T("syn-energitiki-pathitiki", [{"h":"Τι είναι ενεργητική και τι παθητική σύνταξη","body":"<p>Με τους όρους <b>ενεργητική</b> και <b>παθητική σύνταξη</b> δεν εννοούμε απλώς τη φωνή ενός ρήματος, αλλά δύο διαφορετικούς τρόπους με τους οποίους η γλώσσα παρουσιάζει το <i>ίδιο</i> γεγονός. Η ίδια πραγματικότητα μπορεί να ειπωθεί με δύο «οπτικές γωνίες»: άλλοτε βάζουμε στο προσκήνιο αυτόν που <i>ενεργεί</i> (δράστη) και άλλοτε αυτόν που <i>δέχεται</i> την ενέργεια (πάσχοντα).</p><p><b>Ενεργητική σύνταξη</b> έχουμε όταν το <b>υποκείμενο του ρήματος ενεργεί</b>, δηλαδή κάνει κάτι, και η ενέργειά του (όταν το ρήμα είναι μεταβατικό) μεταβαίνει σε ένα <b>αντικείμενο</b>. Σχηματικά: <i>Υποκείμενο (δράστης) → Ρήμα ενεργητικό → Αντικείμενο (πάσχον)</i>.</p><p><b>Παθητική σύνταξη</b> έχουμε όταν το <b>υποκείμενο του ρήματος πάσχει</b>, δηλαδή δέχεται μια ενέργεια που προέρχεται από αλλού. Αυτός που τώρα ενεργεί δεν είναι πια το υποκείμενο, αλλά εκφράζεται με ιδιαίτερο όρο, το λεγόμενο <b>ποιητικό αίτιο</b>. Σχηματικά: <i>Υποκείμενο (πάσχον) ← Ρήμα παθητικό ← Ποιητικό αίτιο (δράστης)</i>.</p><h3>Η σχέση των δύο συντάξεων</h3><p>Οι δύο συντάξεις είναι <b>ισοδύναμες ως προς το νόημα</b>: περιγράφουν το ίδιο πράγμα. Γι' αυτό μπορούμε να <b>μετατρέπουμε</b> τη μία στην άλλη χωρίς να αλλάζει η ουσία. Αυτό που αλλάζει είναι η <i>έμφαση</i>: η ενεργητική τονίζει τον δράστη, η παθητική τον πάσχοντα ή το ίδιο το αποτέλεσμα. Προϋπόθεση για να υπάρχει παθητική σύνταξη είναι το ρήμα να είναι <b>μεταβατικό</b> και να έχει (στην ενεργητική) αντικείμενο σε <b>αιτιατική</b>· μόνο τότε υπάρχει «πάσχον» που μπορεί να γίνει υποκείμενο του παθητικού ρήματος.</p>","examples":[{"gr":"Ὁ διδάσκαλος παιδεύει τόν μαθητήν.","an":"Ενεργητική σύνταξη: υποκείμενο «ὁ διδάσκαλος» (δράστης), ρήμα ενεργητικό «παιδεύει», αντικείμενο «τόν μαθητήν» (πάσχον). Ο δάσκαλος εκπαιδεύει τον μαθητή."},{"gr":"Ὁ μαθητής παιδεύεται ὑπό τοῦ διδασκάλου.","an":"Παθητική σύνταξη του ίδιου νοήματος: υποκείμενο «ὁ μαθητής» (πάσχον), ρήμα παθητικό «παιδεύεται», ποιητικό αίτιο «ὑπό τοῦ διδασκάλου» (δράστης). Ο μαθητής εκπαιδεύεται από τον δάσκαλο."},{"gr":"Οἱ Λακεδαιμόνιοι ἐνίκησαν τούς Ἀθηναίους.","an":"Ενεργητική: «οἱ Λακεδαιμόνιοι» υποκ. (δράστης), «ἐνίκησαν» ρήμα ενεργ., «τούς Ἀθηναίους» αντικ. σε αιτιατική. Οι Λακεδαιμόνιοι νίκησαν τους Αθηναίους."},{"gr":"Οἱ Ἀθηναῖοι ἐνικήθησαν ὑπό τῶν Λακεδαιμονίων.","an":"Παθητική του ίδιου: «οἱ Ἀθηναῖοι» υποκ. (πάσχον), «ἐνικήθησαν» ρήμα παθ., «ὑπό τῶν Λακεδαιμονίων» ποιητικό αίτιο. Οι Αθηναίοι νικήθηκαν από τους Λακεδαιμονίους."},{"gr":"Φύσει γάρ, ὦ Σώκρατες, δοκεῖ μοι σοφία τις εἶναι, ἥν ἔχουσιν οἱ ἀγαθοί. (τύπου Πλάτ.)","an":"Ενεργητική σύνταξη με μεταβατικό «ἔχουσιν» + αντικ. «ἥν»: «οἱ ἀγαθοί» υποκ.-δράστης. Παρατηρούμε τη βασική δομή «υποκ. (δράστης) → ρήμα → αντικ.», προτού δούμε τη μετατροπή της σε παθητική."},{"gr":"Ἡ ἀρετή τούς ἀνθρώπους εὐδαίμονας ποιεῖ. → Οἱ ἄνθρωποι ὑπό τῆς ἀρετῆς εὐδαίμονες ποιοῦνται.","an":"Δύο ισοδύναμες οπτικές του ίδιου νοήματος: ενεργ. «ἡ ἀρετή» δράστης → παθ. «οἱ ἄνθρωποι» πάσχον + ποιητικό αίτιο «ὑπό τῆς ἀρετῆς». Δείχνει τη μετατόπιση της έμφασης από τον δράστη στον πάσχοντα."}],"note":"Προσοχή στην ορολογία: «ενεργητική/παθητική σύνταξη» αφορά τη συντακτική δομή της πρότασης· δεν ταυτίζεται απόλυτα με τη «φωνή». Υπάρχουν ρήματα μέσης φωνής με ενεργητική σύνταξη και ρηματικοί τύποι που δίνουν παθητική σύνταξη χωρίς να είναι «παθητική φωνή»."},{"h":"Το ποιητικό αίτιο: ορισμός και βασική εκφορά (ὑπό + γενική)","body":"<p><b>Ποιητικό αίτιο</b> ονομάζεται ο όρος που, στην παθητική σύνταξη, φανερώνει το <b>πρόσωπο ή το πράγμα από το οποίο προέρχεται (ποιεῖται) η ενέργεια</b> την οποία δέχεται το υποκείμενο του παθητικού ρήματος. Με άλλα λόγια, το ποιητικό αίτιο είναι ο <i>πραγματικός δράστης</i> της ενέργειας, ο οποίος όμως δεν βρίσκεται πια στη θέση του υποκειμένου.</p><h3>Η κανονική εκφορά: ὑπό + γενική (έμψυχο/άμεσος δράστης)</h3><p>Όταν το ποιητικό αίτιο είναι <b>έμψυχο</b> (πρόσωπο που ενεργεί συνειδητά και άμεσα), εκφέρεται κανονικά <b>εμπρόθετα με ὑπό + γενική</b>. Αυτή είναι η συνηθέστερη και «τυπική» μορφή του ποιητικού αιτίου, που πρέπει να θεωρείται η προεπιλογή στη μετατροπή.</p><ul><li><i>ὑπό + γενική προσώπου</i> → δηλώνει τον άμεσο, ζωντανό δράστη.</li><li>Συντάσσεται με ρήμα παθητικής φωνής οποιουδήποτε χρόνου.</li></ul><h3>Άψυχο ποιητικό αίτιο</h3><p>Όταν το ποιητικό αίτιο είναι <b>άψυχο</b> αλλά νοείται ως αυτό που ασκεί την ενέργεια (φυσική δύναμη, αφηρημένη έννοια), συχνά διατηρείται και πάλι το <b>ὑπό + γενική</b> (π.χ. <i>ὑπό τοῦ ψύχους</i>, «από το κρύο»). Όταν όμως το άψυχο εννοείται μάλλον ως <b>μέσο/όργανο</b> παρά ως αυτουργός, χρησιμοποιείται η <b>απλή δοτική</b> (βλ. επόμενο κεφάλαιο).</p>","examples":[{"gr":"Ἡ πόλις ἐπολιορκεῖτο ὑπό τῶν πολεμίων.","an":"«ὑπό τῶν πολεμίων» = ποιητικό αίτιο (έμψυχο, ὑπό + γενική). Η πόλη πολιορκούνταν από τους εχθρούς. Δράστης οι εχθροί, πάσχον η πόλη."},{"gr":"Ἀθηναῖοι ὑπό τῶν Ἑλλήνων ᾑρέθησαν ἡγεμόνες τοῦ ναυτικοῦ.","an":"«ὑπό τῶν Ἑλλήνων» = ποιητικό αίτιο. Οι Αθηναίοι εκλέχθηκαν από τους Έλληνες αρχηγοί του στόλου. (Παράδειγμα της σχολικής γραμματικής· πρόσεξε και το κατηγορούμενο «ἡγεμόνες».)"},{"gr":"Τά δένδρα ὑπό τοῦ ἀνέμου ἐσείετο.","an":"«ὑπό τοῦ ἀνέμου» = ποιητικό αίτιο, αλλά άψυχο που νοείται ως δρώσα φυσική δύναμη· γι' αυτό διατηρείται το ὑπό + γενική. Τα δέντρα σείονταν από τον άνεμο."},{"gr":"Ἐτιμᾶτο ὁ στρατηγός ὑπό πάντων τῶν πολιτῶν.","an":"«ὑπό πάντων τῶν πολιτῶν» = έμψυχο ποιητικό αίτιο. Ο στρατηγός τιμούνταν από όλους τους πολίτες."},{"gr":"Στρατηγός ὑπ' αὐτῶν ᾑρέθη Χειρίσοφος. (τύπου Ξεν. Ἀνάβ. — αἱροῦμαι στρατηγόν)","an":"«ὑπ' αὐτῶν» = έμψυχο ποιητικό αίτιο σε ὑπό + γενική (ενεστ. προσωπ. αντωνυμίας). «ᾑρέθη» παθ. αόρ. του αἱροῦμαι. Ο Χειρίσοφος εκλέχθηκε στρατηγός από αυτούς. Τυπική στρατιωτική φράση του Ξενοφώντος."},{"gr":"Ταῦτα ἐπαινεῖται ὑπό τῶν σοφῶν ἀνδρῶν.","an":"«ὑπό τῶν σοφῶν ἀνδρῶν» = έμψυχο ποιητικό αίτιο (ὑπό + γενική). Αυτά επαινούνται από τους σοφούς άνδρες· κανονική εκφορά με ρήμα κρίσης/επαίνου σε παθητική."}],"table":{"title":"Σύνοψη: πότε ὑπό + γενική","cols":["Φύση του δράστη","Εκφορά ποιητικού αιτίου","Παράδειγμα"],"rows":[["Έμψυχο (πρόσωπο)","ὑπό + γενική","ὑπό τοῦ διδασκάλου"],["Άψυχο ως δρώσα δύναμη","ὑπό + γενική","ὑπό τοῦ ἀνέμου, ὑπό τοῦ ψύχους"],["Άψυχο ως μέσο/όργανο","απλή δοτική (βλ. επόμ.)","τοῖς βέλεσι, τῷ λιμῷ"]]},"note":"Το ποιητικό αίτιο απαντά και κοντά σε παθητικά ρηματικά επίθετα σε -τός και -τέος και σε παθητικές μετοχές, όχι μόνο σε προσωπικά παθητικά ρήματα."},{"h":"Οι άλλες μορφές του ποιητικού αιτίου: δοτική και άλλοι εμπρόθετοι","body":"<p>Πέρα από το τυπικό <b>ὑπό + γενική</b>, η αρχαία ελληνική διαθέτει αρκετές ακόμη μορφές για το ποιητικό αίτιο. Η σωστή επιλογή εξαρτάται από τη <i>φύση του δράστη</i> (έμψυχο/άψυχο), από τον <i>χρόνο</i> του ρήματος (συντελικός ή όχι) και από τη <i>σημασία</i> του ρήματος.</p><h3>1. Απλή δοτική (δοτική του ποιητικού αιτίου / οργανική)</h3><p>Όταν το ποιητικό αίτιο είναι <b>άψυχο</b> και νοείται ως <b>μέσο ή όργανο</b> με το οποίο γίνεται η ενέργεια, εκφέρεται με <b>απλή (οργανική) δοτική</b>, χωρίς πρόθεση. Είναι, ουσιαστικά, μια δοτική του οργάνου που λειτουργεί ως ποιητικό αίτιο.</p><h3>2. Δοτική προσωπική του ενεργούντος προσώπου</h3><p>Όταν το παθητικό ρήμα βρίσκεται σε <b>συντελικό χρόνο</b> (παρακείμενο, υπερσυντέλικο, συντελεσμένο μέλλοντα) ή είναι <b>ρηματικό επίθετο σε -τέος</b>, το ποιητικό αίτιο εκφέρεται κανονικά με <b>απλή δοτική προσώπου ή αντωνυμίας</b>: αυτή λέγεται <b>δοτική προσωπική του ενεργούντος προσώπου</b>. Είναι η αναμενόμενη μορφή στις περιφράσεις του τύπου «πεπρακται μοι» και στα -τέος («ποιητέον ἐστί ἡμῖν»).</p><h3>3. Άλλοι εμπρόθετοι: παρά / πρός / ἐκ (ἀπό) + γενική</h3><p>Σπανιότερα, αντί για ὑπό + γενική, το (συνήθως έμψυχο) ποιητικό αίτιο εκφέρεται με άλλες προθέσεις + γενική, με ελαφρές αποχρώσεις σημασίας:</p><ul><li><b>παρά + γενική</b>: τονίζει την προέλευση «εκ μέρους» κάποιου· συχνά με ρήματα δόσεως/αποστολής (δίδομαι, πέμπομαι, ὁμολογεῖται).</li><li><b>πρός + γενική</b>: δηλώνει τον δράστη κυρίως με ρήματα ομολογίας/κρίσης/αναγνώρισης (ὁμολογεῖται, λέγεται).</li><li><b>ἐκ / ἀπό + γενική</b>: δηλώνει την πηγή ή την αφετηρία της ενέργειας («από», «εκ μέρους»).</li></ul>","examples":[{"gr":"Ὁ ἵππος ἐβλήθη τοῖς βέλεσιν.","an":"«τοῖς βέλεσιν» = ποιητικό αίτιο άψυχο/μέσο σε απλή (οργανική) δοτική. Το άλογο χτυπήθηκε με τα βέλη. (Ο άνθρωπος που έριξε είναι ο πραγματικός δράστης, αλλά εδώ τονίζεται το όργανο.)"},{"gr":"Πολλοί τῷ λιμῷ διεφθάρησαν.","an":"«τῷ λιμῷ» = δοτική του ποιητικού αιτίου (άψυχο/μέσο). Πολλοί καταστράφηκαν από την πείνα."},{"gr":"Ταῦτα πέπρακται ἡμῖν.","an":"Συντελικός χρόνος (παρακείμενος «πέπρακται») → ποιητικό αίτιο σε δοτική προσωπική του ενεργούντος προσώπου «ἡμῖν». Αυτά έχουν γίνει από εμάς. Ισοδυναμεί με ενεργητικό «ταῦτα πεποιήκαμεν»."},{"gr":"Πάντα μοι πεποίηται.","an":"«πεποίηται» παρακείμενος παθ. → «μοι» δοτική προσωπική του ενεργούντος προσώπου = ποιητικό αίτιο. Όλα έχουν γίνει από εμένα."},{"gr":"Ὠφελητέα σοι ἡ πόλις ἐστίν.","an":"Ρηματικό επίθετο σε -τέος («ὠφελητέα») → ποιητικό αίτιο σε δοτική προσωπική «σοι». Πρέπει να ωφεληθεί η πόλη από εσένα / εσύ οφείλεις να ωφελήσεις την πόλη."},{"gr":"Αἵρεσις αὐτῇ ἐδόθη παρά τοῦ πατρός.","an":"«παρά τοῦ πατρός» = ποιητικό αίτιο με παρά + γενική (ρήμα δόσεως «ἐδόθη»). Της δόθηκε η δυνατότητα επιλογής από τον πατέρα."},{"gr":"Κῦρος ὁμολογεῖται πρός πάντων κράτιστος γενέσθαι. (τύπου)","an":"«πρός πάντων» = ποιητικό αίτιο με πρός + γενική (ρήμα κρίσης/ομολογίας). Ο Κύρος ομολογείται από όλους ότι υπήρξε άριστος."},{"gr":"Ἐκείνῳ ἡ χώρα δῶρον ἐκ βασιλέως ἐδόθη.","an":"«ἐκ βασιλέως» = ποιητικό αίτιο με ἐκ + γενική (πηγή της δόσης). Σ' εκείνον δόθηκε η χώρα ως δώρο από τον βασιλιά."},{"gr":"Ὁμολογεῖται τήν πόλιν ἡμῶν ἀρχαιοτάτην εἶναι παρά πᾶσιν ἀνθρώποις. (τύπου Ἰσοκρ.)","an":"«παρά πᾶσιν ἀνθρώποις» = ποιητικό αίτιο σε παρά + δοτική (εκ μέρους/κατά την κρίση όλων) με ρήμα ομολογίας. Δείχνει την απόχρωση «κατά την κοινή παραδοχή»· συχνός τύπος στον Ισοκράτη."},{"gr":"Ταῦτα μοι πέπρακται καί λέλεκται πρός ὑμᾶς. (τύπου Δημ.)","an":"Δύο παρακείμενοι παθ. «πέπρακται», «λέλεκται» → κοινό ποιητικό αίτιο σε δοτική προσωπική «μοι». Αυτά έχουν πραχθεί και ειπωθεί από εμένα προς εσάς· τυπικό ρητορικό κλείσιμο λόγου (πρβλ. Δημοσθένη)."}],"table":{"title":"Πίνακας μορφών του ποιητικού αιτίου","cols":["Μορφή","Πότε χρησιμοποιείται","Παράδειγμα"],"rows":[["ὑπό + γενική","έμψυχο / άμεσος δράστης (κανονική μορφή)","ὑπό τῶν Λακεδαιμονίων"],["απλή (οργανική) δοτική","άψυχο που νοείται ως μέσο/όργανο","τοῖς βέλεσιν, τῷ λιμῷ"],["δοτική προσωπική ενεργούντος προσώπου","ρήμα συντελικού χρόνου ή -τέος","πέπρακται ἡμῖν· ποιητέον σοι"],["παρά + γενική","εκ μέρους κάποιου· ρήμ. δόσεως/αποστολής","παρά τοῦ πατρός"],["πρός + γενική","ρήματα ομολογίας/κρίσης","πρός πάντων"],["ἐκ / ἀπό + γενική","πηγή/αφετηρία της ενέργειας","ἐκ βασιλέως, ἀφ' ἑκατέρων"]]},"note":"Στη μετατροπή ασκήσεων, αν δεν υπάρχει ειδικός λόγος, βάζουμε ὑπό + γενική για έμψυχα. Δοτική επιλέγουμε για άψυχα-μέσα και υποχρεωτικά σε συντελικούς χρόνους + -τέος (δοτική προσωπική του ενεργούντος προσώπου)."},{"h":"Μετατροπή ενεργητικής σε παθητική: τα βήματα (μονόπτωτα ρήματα)","body":"<p>Η μετατροπή της ενεργητικής σύνταξης σε παθητική γίνεται με <b>τρία σταθερά βήματα</b>, που πρέπει να εκτελούνται με τη σειρά. Ξεκινάμε από τα <b>μονόπτωτα μεταβατικά ρήματα</b> (ρήματα με <i>ένα</i> αντικείμενο σε αιτιατική), που είναι η βασική περίπτωση.</p><h3>Τα τρία βήματα</h3><ul><li><b>Βήμα 1 — Αντικείμενο → Υποκείμενο.</b> Το αντικείμενο (αιτιατική) του ενεργητικού ρήματος γίνεται <b>υποκείμενο</b> (ονομαστική) του παθητικού.</li><li><b>Βήμα 2 — Υποκείμενο → Ποιητικό αίτιο.</b> Το υποκείμενο (ονομαστική) του ενεργητικού γίνεται <b>ποιητικό αίτιο</b> (κανονικά ὑπό + γενική για έμψυχα· δοτική για άψυχα-μέσα).</li><li><b>Βήμα 3 — Ρήμα → Παθητική φωνή.</b> Το ενεργητικό ρήμα μετατρέπεται σε <b>παθητικό</b> στον <i>ίδιο χρόνο, έγκλιση και αριθμό</i>, αλλά το <b>πρόσωπο/αριθμός του παθητικού ρήματος συμφωνεί με το νέο υποκείμενο</b> (το παλιό αντικείμενο).</li></ul><h3>Προσοχή στη συμφωνία</h3><p>Το νέο ρήμα συμφωνεί στο <b>πρόσωπο και τον αριθμό</b> με το νέο υποκείμενο. Π.χ. αν το αντικείμενο ήταν πληθυντικού, το παθητικό ρήμα μπαίνει στο γ΄ πληθυντικό. Ο <b>χρόνος</b> και η <b>έγκλιση</b> μένουν αμετάβλητα (ενεστώτας→ενεστώτας, αόριστος→αόριστος κ.λπ.).</p>","examples":[{"gr":"Ὁ στρατηγός λύει τούς αἰχμαλώτους. → Οἱ αἰχμάλωτοι λύονται ὑπό τοῦ στρατηγοῦ.","an":"Βήμα 1: «τούς αἰχμαλώτους» (αντικ.) → «οἱ αἰχμάλωτοι» (υποκ., ονομ. πληθ.). Βήμα 2: «ὁ στρατηγός» (υποκ.) → «ὑπό τοῦ στρατηγοῦ» (ποιητ. αίτιο). Βήμα 3: «λύει» (ενεστ. γ΄ εν.) → «λύονται» (παθ. ενεστ. γ΄ πληθ., συμφωνία με νέο υποκείμενο)."},{"gr":"Οἱ πολέμιοι κατέσκαψαν τά τείχη. → Τά τείχη κατεσκάφη ὑπό τῶν πολεμίων.","an":"Αόριστος. «τά τείχη» αντικ.→ υποκ. (ουδέτ. πληθ.). «οἱ πολέμιοι» υποκ.→ «ὑπό τῶν πολεμίων». «κατέσκαψαν» (ενεργ. αόρ.)→ «κατεσκάφη» (παθ. αόρ. β΄, γ΄ εν., αφού ουδέτ. πληθ. παίρνει ρήμα στον ενικό κατά το αττικό συντακτικό)."},{"gr":"Ὁ Σωκράτης ἐπαίδευσε τόν Πλάτωνα. → Ὁ Πλάτων ἐπαιδεύθη ὑπό τοῦ Σωκράτους.","an":"«τόν Πλάτωνα» → «ὁ Πλάτων» (υποκ.). «ὁ Σωκράτης» → «ὑπό τοῦ Σωκράτους». «ἐπαίδευσε» (αόρ. ενεργ.) → «ἐπαιδεύθη» (αόρ. παθ. γ΄ εν.)."},{"gr":"Οἱ νόσοι φθείρουσι τά σώματα. → Τά σώματα φθείρεται ὑπό τῶν νόσων.","an":"Άψυχο υποκείμενο «οἱ νόσοι» που δρα ως δύναμη → διατηρεί ὑπό + γενική «ὑπό τῶν νόσων». «τά σώματα» → υποκ. ουδ. πληθ. → ρήμα «φθείρεται» στον ενικό."},{"gr":"Ὁ θόρυβος ἐτάραξε τούς στρατιώτας. → Οἱ στρατιῶται ἐταράχθησαν τῷ θορύβῳ.","an":"Άψυχο ποιητικό αίτιο που νοείται ως μέσο → απλή δοτική «τῷ θορύβῳ» (όχι ὑπό). «τούς στρατιώτας» → «οἱ στρατιῶται»· «ἐτάραξε» → «ἐταράχθησαν» (γ΄ πληθ.)."},{"gr":"Οἱ πολῖται τιμῶσι τούς ἀγαθούς ἄνδρας. → Οἱ ἀγαθοί ἄνδρες τιμῶνται ὑπό τῶν πολιτῶν.","an":"Μονόπτωτο «τιμῶ» + αιτ. Βήμα 1: «τούς ἀγαθούς ἄνδρας» → υποκ. «οἱ ἀγαθοί ἄνδρες» (ονομ. πληθ.). Βήμα 2: «οἱ πολῖται» → «ὑπό τῶν πολιτῶν». Βήμα 3: «τιμῶσι» (ενεστ. γ΄ πληθ.) → «τιμῶνται» (παθ. ενεστ. γ΄ πληθ.)."},{"gr":"Οἱ θεοί φιλοῦσι τούς δικαίους. → Οἱ δίκαιοι φιλοῦνται ὑπό τῶν θεῶν.","an":"«τούς δικαίους» → υποκ. «οἱ δίκαιοι»· «οἱ θεοί» (έμψυχα-δρώντες) → «ὑπό τῶν θεῶν»· «φιλοῦσι» → «φιλοῦνται» (γ΄ πληθ.). Διατήρηση χρόνου (ενεστώτας) και έγκλισης."}],"note":"Χρυσός κανόνας στη συμφωνία: το παθητικό ρήμα «κοιτάζει» πάντα το ΝΕΟ υποκείμενο (το πρώην αντικείμενο). Μην ξεχνάς τον αττικό κανόνα «ουδέτερο πληθυντικό → ρήμα στον ενικό»."},{"h":"Δίπτωτα ρήματα στη μετατροπή και το κατηγορούμενο","body":"<p>Τα <b>δίπτωτα ρήματα</b> έχουν στην ενεργητική <b>δύο αντικείμενα</b>: ένα <b>άμεσο</b> (συνήθως αιτιατική προσώπου ή πράγματος) και ένα <b>έμμεσο</b> (σε αιτιατική, γενική ή δοτική). Στη μετατροπή προς παθητική, ο κανόνας είναι:</p><ul><li><b>Άμεσο αντικείμενο → Υποκείμενο</b> του παθητικού.</li><li><b>Έμμεσο αντικείμενο → μένει ως έχει</b> (διατηρεί την πτώση του ως αντικείμενο του παθητικού ρήματος).</li><li><b>Υποκείμενο → Ποιητικό αίτιο.</b></li></ul><h3>Εξαιρέσεις στα δίπτωτα</h3><p>Σε ορισμένες κατηγορίες ρημάτων, <b>το έμμεσο</b> (και όχι το άμεσο) αντικείμενο γίνεται υποκείμενο του παθητικού:</p><ul><li>Ρήματα με σημασία <b>«αἰτῶ»</b> (ζητώ): το πρόσωπο (έμμεσο) γίνεται υποκείμενο. <i>αἰτῶ τινά τι → αἰτοῦμαί τι.</i></li><li>Ρήματα όπως <b>ἐπιτάσσω, ἐπιτρέπω, πιστεύω</b>: το έμμεσο αντικείμενο (σε δοτική/γενική) μπορεί να γίνει υποκείμενο του παθητικού.</li></ul><h3>Κατηγορούμενο του αντικειμένου</h3><p>Σε ρήματα που, εκτός από αντικείμενο, παίρνουν και <b>κατηγορούμενο του αντικειμένου</b> (αἱροῦμαι, ὀνομάζω, ποιῶ, νομίζω, ἡγοῦμαι κ.ά.), στη μετατροπή το <b>κατηγορούμενο του αντικειμένου γίνεται κατηγορούμενο του υποκειμένου</b> (περνά από αιτιατική σε ονομαστική, σε συμφωνία με το νέο υποκείμενο).</p><h3>Σύστοιχο αντικείμενο</h3><p>Στα μονόπτωτα, το <b>σύστοιχο αντικείμενο</b> γίνεται <b>σύστοιχο υποκείμενο</b>. Στα δίπτωτα, το σύστοιχο αντικείμενο <b>παραμένει αντικείμενο</b> του παθητικού.</p>","examples":[{"gr":"Ὁ πατήρ δίδωσι τῷ παιδί δῶρον. → Τό δῶρον δίδοται τῷ παιδί ὑπό τοῦ πατρός.","an":"Δίπτωτο «δίδωμι». Άμεσο «δῶρον» (αιτ.) → υποκ. «τό δῶρον». Έμμεσο «τῷ παιδί» (δοτ.) → μένει αμετάβλητο. Υποκ. «ὁ πατήρ» → «ὑπό τοῦ πατρός». Ρήμα «δίδωσι» → «δίδοται»."},{"gr":"Οἱ πολῖται ἐνεχείρισαν τῷ στρατηγῷ τήν ἀρχήν. → Ἡ ἀρχή ἐνεχειρίσθη τῷ στρατηγῷ ὑπό τῶν πολιτῶν.","an":"Άμεσο «τήν ἀρχήν» → υποκ. «ἡ ἀρχή». Έμμεσο «τῷ στρατηγῷ» (δοτ.) → μένει. Υποκ. «οἱ πολῖται» → «ὑπό τῶν πολιτῶν». «ἐνεχείρισαν» → «ἐνεχειρίσθη»."},{"gr":"Κῦρος ᾔτησε τούς Λακεδαιμονίους ναῦς. → Οἱ Λακεδαιμόνιοι ᾐτήθησαν ναῦς ὑπό Κύρου.","an":"Εξαίρεση «αἰτῶ»: εδώ το ΕΜΜΕΣΟ-πρόσωπο «τούς Λακεδαιμονίους» γίνεται υποκείμενο «οἱ Λακεδαιμόνιοι», ενώ το πράγμα «ναῦς» μένει αντικείμενο. Οι Λακεδαιμόνιοι ζητήθηκαν πλοία από τον Κύρο."},{"gr":"Οἱ στρατιῶται εἵλοντο τόν Ξενοφῶντα στρατηγόν. → Ὁ Ξενοφῶν ᾑρέθη στρατηγός ὑπό τῶν στρατιωτῶν.","an":"Ρήμα με κατηγορούμενο αντικειμένου. Αντικ. «τόν Ξενοφῶντα» → υποκ. «ὁ Ξενοφῶν». Κατηγ. αντικ. «στρατηγόν» (αιτ.) → κατηγ. υποκ. «στρατηγός» (ονομ.). «εἵλοντο» → «ᾑρέθη». (Πρβλ. Ξεν. Ἀνάβ., εκλογή στρατηγών μετά τον θάνατο των παλαιών.)"},{"gr":"Ἐνίκησαν οἱ Ἕλληνες νίκην καλήν. → Ἐνικήθη νίκη καλή ὑπό τῶν Ἑλλήνων.","an":"Σύστοιχο αντικείμενο «νίκην» σε μονόπτωτο → γίνεται σύστοιχο υποκείμενο «νίκη». Το επίθετο «καλήν»→«καλή» συμφωνεί. (Παράδειγμα της σχολικής παράδοσης για το σύστοιχο.)"},{"gr":"Ὁ δῆμος ἐπέτρεψε τοῖς στρατηγοῖς τήν φυλακήν. → Οἱ στρατηγοί ἐπετράπησαν τήν φυλακήν ὑπό τοῦ δήμου.","an":"Εξαίρεση «ἐπιτρέπω»: το ΕΜΜΕΣΟ «τοῖς στρατηγοῖς» (δοτ. προσώπου) γίνεται υποκείμενο «οἱ στρατηγοί», ενώ το άμεσο «τήν φυλακήν» μένει αντικείμενο. «ἐπέτρεψε» → «ἐπετράπησαν» (γ΄ πληθ.). Στους στρατηγούς ανατέθηκε η φύλαξη από τον δήμο."},{"gr":"Οἱ Ἀθηναῖοι ὠνόμασαν τόν Ἀριστείδην δίκαιον. → Ὁ Ἀριστείδης ὠνομάσθη δίκαιος ὑπό τῶν Ἀθηναίων.","an":"Ρήμα κλήσεως με κατηγ. αντικειμένου. Άμεσο «τόν Ἀριστείδην» → υποκ. «ὁ Ἀριστείδης»· κατηγ. αντικ. «δίκαιον» (αιτ.) → κατηγ. υποκ. «δίκαιος» (ονομ.)· «ὠνόμασαν» → «ὠνομάσθη». Δύο όροι αλλάζουν μαζί σε ονομαστική."}],"table":{"title":"Μετατροπή δίπτωτων: τι γίνεται ο κάθε όρος","cols":["Κατηγορία ρήματος","Άμεσο αντικ.","Έμμεσο αντικ.","Υποκείμενο"],"rows":[["Κανονικά δίπτωτα (δίδωμι, ἐγχειρίζω)","→ υποκείμενο","μένει ως αντικ.","→ ποιητικό αίτιο"],["Σημασίας «αἰτῶ»","μένει ως αντικ.","→ υποκείμενο","→ ποιητικό αίτιο"],["ἐπιτάσσω, ἐπιτρέπω, πιστεύω","→ υποκείμενο","→ μπορεί να γίνει υποκείμενο","→ ποιητικό αίτιο"],["Με κατηγ. αντικειμένου (αἱροῦμαι κ.ά.)","→ υποκείμενο (+ κατηγ.→κατηγ. υποκ.)","—","→ ποιητικό αίτιο"]]},"note":"Στα ρήματα με κατηγορούμενο, θυμήσου ότι ΔΥΟ όροι αλλάζουν πτώση μαζί: αντικείμενο→ονομαστική (υποκ.) ΚΑΙ κατηγορούμενο αντικειμένου→ονομαστική (κατηγ. υποκ.)."},{"h":"Απρόσωπη παθητική σύνταξη και ρήματα που δεν μετατρέπονται","body":"<p>Δεν μετατρέπονται όλα τα ενεργητικά ρήματα σε προσωπική παθητική σύνταξη. Υπάρχουν δύο σημαντικές ειδικές περιπτώσεις: η <b>απρόσωπη παθητική σύνταξη</b> και τα <b>αμετάβατα ρήματα</b> που δεν μετατρέπονται καθόλου.</p><h3>Απρόσωπη παθητική σύνταξη</h3><p>Όταν το ρήμα είναι <b>αμετάβατο</b> ή έχει αντικείμενο που <b>δεν είναι σε αιτιατική</b> (αλλά σε γενική ή δοτική), δεν υπάρχει «πάσχον» σε αιτιατική για να γίνει υποκείμενο. Σε αυτές τις περιπτώσεις η μετατροπή γίνεται με <b>απρόσωπη παθητική σύνταξη</b>: το παθητικό ρήμα μπαίνει στο <b>γ΄ ενικό πρόσωπο</b> και λειτουργεί <i>απρόσωπα</i>, ενώ ο δράστης γίνεται ποιητικό αίτιο. Το πρώην έμμεσο αντικείμενο (γενική/δοτική) <b>διατηρεί την πτώση του</b>.</p><ul><li><i>βοηθοῦσι τοῖς συμμάχοις → βοηθεῖται τοῖς συμμάχοις</i> (απρόσωπη: «παρέχεται βοήθεια στους συμμάχους»).</li><li>Χαρακτηριστικά με ρήματα που συντάσσονται με γενική/δοτική: ἄρχω, βοηθῶ, φθονῶ, ἐπιβουλεύω, καταγελῶ κ.ά.</li></ul><h3>Αμετάβατα ρήματα: δεν μετατρέπονται</h3><p>Τα <b>αμετάβατα ρήματα</b> (που δεν έχουν αντικείμενο) δεν έχουν παθητική σύνταξη, γιατί δεν υπάρχει ενέργεια που να μεταβαίνει σε κάποιον. Π.χ. <i>τρέχω, βαδίζω, μένω, εἰμί, γίγνομαι, ζῶ, ἀποθνῄσκω</i>. Δεν μπορούμε να πούμε «τρέχεται ὑπό τινος».</p><h3>Περιφραστική / λεξιλογική παθητική (ενεργητικά χωρίς παθητικό)</h3><p>Μερικά ενεργητικά ρήματα <b>δεν έχουν δικό τους παθητικό τύπο</b> και η «παθητική» τους έννοια δηλώνεται με <b>άλλο ρήμα</b> (λεξιλογικό παθητικό) ή με περίφραση:</p><ul><li><b>ἀποκτείνω</b> (σκοτώνω) → παθητικό: <b>ἀποθνῄσκω ὑπό τινος</b> (πεθαίνω από κάποιον / φονεύομαι).</li><li><b>εὖ/κακῶς ποιῶ τινα</b> → <b>εὖ/κακῶς πάσχω ὑπό τινος</b>.</li><li><b>διώκω</b> (καταδιώκω/μηνύω) → ως παθητικό «κατηγοροῦμαι/φεύγω» κατά περίσταση.</li></ul>","examples":[{"gr":"Οἱ Ἀθηναῖοι ἐβοήθουν τοῖς συμμάχοις. → Ἐβοηθεῖτο τοῖς συμμάχοις ὑπό τῶν Ἀθηναίων.","an":"Το «βοηθῶ» συντάσσεται με δοτική, όχι αιτιατική → απρόσωπη παθητική. Ρήμα γ΄ εν. «ἐβοηθεῖτο», το «τοῖς συμμάχοις» διατηρεί τη δοτική, υποκ.-δράστης → «ὑπό τῶν Ἀθηναίων». Παρεχόταν βοήθεια στους συμμάχους από τους Αθηναίους."},{"gr":"Πάντες κατεγέλων τοῦ ἀνθρώπου. → Κατεγελᾶτο τοῦ ἀνθρώπου ὑπό πάντων.","an":"«καταγελῶ» + γενική → απρόσωπη παθητική γ΄ εν. «κατεγελᾶτο»· η γενική «τοῦ ἀνθρώπου» μένει· δράστης «ὑπό πάντων». Όλοι περιγελούσαν τον άνθρωπο."},{"gr":"Οἱ πολῖται ἐφθόνουν τῷ πλουσίῳ. → Ἐφθονεῖτο τῷ πλουσίῳ ὑπό τῶν πολιτῶν.","an":"«φθονῶ» + δοτική → απρόσωπη παθητική. Φθονούσαν τον πλούσιο οι πολίτες."},{"gr":"Οἱ πολέμιοι ἀπέκτειναν τόν στρατηγόν. → Ὁ στρατηγός ἀπέθανεν ὑπό τῶν πολεμίων.","an":"Λεξιλογικό παθητικό: το «ἀποκτείνω» δεν έχει εύχρηστο παθητικό· χρησιμοποιείται «ἀποθνῄσκω» με ποιητικό αίτιο. Ο στρατηγός σκοτώθηκε / φονεύθηκε από τους εχθρούς."},{"gr":"Ὁ φίλος εὖ ἐποίει ἐμέ. → Ἐγώ εὖ ἔπασχον ὑπό τοῦ φίλου.","an":"«εὖ ποιῶ τινα» → παθητικό «εὖ πάσχω ὑπό τινος». Ευεργετούμουν από τον φίλο."},{"gr":"Οἱ σύμμαχοι ἐπεβούλευον τῇ πόλει. → Ἐπεβουλεύετο τῇ πόλει ὑπό τῶν συμμάχων.","an":"«ἐπιβουλεύω» + δοτική → απρόσωπη παθητική γ΄ εν. «ἐπεβουλεύετο»· το «τῇ πόλει» μένει σε δοτική· δράστης «ὑπό τῶν συμμάχων». (Πρβλ. θουκυδίδειες περιγραφές συνωμοσιών κατά πόλεων.)"},{"gr":"Πολλοί ἄρχουσι τῶν βαρβάρων. → Ἄρχεται τῶν βαρβάρων ὑπό πολλῶν.","an":"«ἄρχω» + γενική → απρόσωπη παθητική· η γενική «τῶν βαρβάρων» διατηρείται, ρήμα γ΄ εν. «ἄρχεται», δράστης «ὑπό πολλῶν». Δείχνει ότι ρήμα με γενική αντικ. δεν δίνει προσωπική παθητική."}],"table":{"title":"Πότε ΔΕΝ έχουμε κανονική (προσωπική) παθητική","cols":["Περίπτωση","Τι συμβαίνει","Παράδειγμα"],"rows":[["Ρήμα + γενική/δοτική (όχι αιτ.)","απρόσωπη παθητική, γ΄ εν.","βοηθῶ→βοηθεῖται· φθονῶ→φθονεῖται"],["Αμετάβατο ρήμα","δεν μετατρέπεται","τρέχω, βαδίζω, εἰμί, ζῶ"],["Ενεργ. χωρίς παθ. τύπο","λεξιλογικό/περιφραστικό παθ.","ἀποκτείνω→ἀποθνῄσκω ὑπό τινος"],["εὖ/κακῶς ποιῶ","αλλάζει ρήμα","→ εὖ/κακῶς πάσχω ὑπό τινος"]]},"note":"Στην απρόσωπη παθητική σύνταξη δεν υπάρχει υποκείμενο σε ονομαστική· το ρήμα μένει στο γ΄ ενικό και ο όρος σε γενική/δοτική διατηρεί την πτώση του."},{"h":"Μετατροπή παθητικής σε ενεργητική και συνολική μεθοδολογία","body":"<p>Η αντίστροφη πορεία, από <b>παθητική σε ενεργητική</b>, ακολουθεί τα ίδια βήματα αντεστραμμένα. Είναι εξίσου σημαντική στις σχολικές ασκήσεις.</p><h3>Τα βήματα (παθητική → ενεργητική)</h3><ul><li><b>Βήμα 1 — Ποιητικό αίτιο → Υποκείμενο.</b> Το ποιητικό αίτιο (ὑπό + γεν., δοτική κ.λπ.) γίνεται <b>υποκείμενο</b> (ονομαστική) του ενεργητικού ρήματος.</li><li><b>Βήμα 2 — Υποκείμενο → Αντικείμενο.</b> Το υποκείμενο του παθητικού (ονομαστική) γίνεται <b>αντικείμενο</b> (αιτιατική) του ενεργητικού.</li><li><b>Βήμα 3 — Ρήμα → Ενεργητική φωνή</b>, στον ίδιο χρόνο/έγκλιση, σε συμφωνία με το νέο υποκείμενο (το πρώην ποιητικό αίτιο).</li></ul><p>Αν δεν δηλώνεται ποιητικό αίτιο, στην ενεργητική προσθέτουμε ένα γενικό/αόριστο υποκείμενο (π.χ. <i>τις, οἱ ἄνθρωποι, πάντες</i>). Στην απρόσωπη παθητική, το έμμεσο (γεν./δοτ.) ξαναγίνεται αντικείμενο του ενεργητικού ρήματος.</p><h3>Πρακτική μεθοδολογία (check-list)</h3><ul><li><b>1.</b> Εντόπισε ρήμα, φωνή, χρόνο, έγκλιση.</li><li><b>2.</b> Βρες υποκείμενο και αντικείμενο/-α (πτώση καθενός).</li><li><b>3.</b> Έλεγξε αν υπάρχει αντικείμενο σε αιτιατική (→ προσωπική παθ.) ή σε γεν./δοτ. (→ απρόσωπη παθ.).</li><li><b>4.</b> Εφάρμοσε τα τρία βήματα· διάλεξε σωστή μορφή ποιητικού αιτίου (έμψυχο: ὑπό+γεν.· άψυχο-μέσο: δοτ.· συντελικός/-τέος: δοτ. προσωπική).</li><li><b>5.</b> Ρύθμισε τη <b>συμφωνία</b> του ρήματος με το νέο υποκείμενο (πρόσωπο, αριθμός· αττικός κανόνας ουδ. πληθ.).</li><li><b>6.</b> Μετάφερε κατηγορούμενα/επιθετικούς προσδιορισμούς στη νέα πτώση.</li></ul>","examples":[{"gr":"Ὁ Πλάτων ἐπαιδεύθη ὑπό τοῦ Σωκράτους. → Ὁ Σωκράτης ἐπαίδευσε τόν Πλάτωνα.","an":"Ποιητ. αίτιο «ὑπό τοῦ Σωκράτους» → υποκ. «ὁ Σωκράτης». Υποκ. «ὁ Πλάτων» → αντικ. «τόν Πλάτωνα». «ἐπαιδεύθη» (παθ. αόρ.) → «ἐπαίδευσε» (ενεργ. αόρ. γ΄ εν.)."},{"gr":"Τά δῶρα ἐπέμφθη παρά τοῦ βασιλέως. → Ὁ βασιλεύς ἔπεμψε τά δῶρα.","an":"Ποιητ. αίτιο «παρά τοῦ βασιλέως» → υποκ. «ὁ βασιλεύς». «τά δῶρα» (υποκ.) → αντικ. «τά δῶρα» (αιτ., ίδιος τύπος ουδ.). «ἐπέμφθη» → «ἔπεμψε»."},{"gr":"Ταῦτα πέπρακται ἡμῖν. → Ταῦτα πεποιήκαμεν ἡμεῖς.","an":"Δοτ. προσωπική ενεργ. προσώπου «ἡμῖν» → υποκ. «ἡμεῖς». Συντελικός παθ. «πέπρακται» → ενεργ. παρακείμενος «πεποιήκαμεν». «ταῦτα» μένει αντικείμενο."},{"gr":"Ἐβοηθεῖτο τοῖς συμμάχοις ὑπό τῶν Ἀθηναίων. → Οἱ Ἀθηναῖοι ἐβοήθουν τοῖς συμμάχοις.","an":"Από απρόσωπη παθ. σε ενεργ.: ποιητ. αίτιο «ὑπό τῶν Ἀθηναίων» → υποκ. «οἱ Ἀθηναῖοι»· το «τοῖς συμμάχοις» μένει αντικ. σε δοτική· «ἐβοηθεῖτο»→«ἐβοήθουν»."},{"gr":"Ἡ πόλις ἐπολιορκεῖτο. → Οἱ πολέμιοι (τις) ἐπολιόρκουν τήν πόλιν.","an":"Χωρίς δηλωμένο ποιητ. αίτιο: στην ενεργ. προσθέτουμε γενικό υποκ. («οἱ πολέμιοι» ή «τις»). «ἡ πόλις» (υποκ.) → «τήν πόλιν» (αντικ.). «ἐπολιορκεῖτο»→«ἐπολιόρκουν»."},{"gr":"Ὁ Ἀριστείδης ὠνομάσθη δίκαιος ὑπό τῶν Ἀθηναίων. → Οἱ Ἀθηναῖοι ὠνόμασαν τόν Ἀριστείδην δίκαιον.","an":"Με κατηγορούμενο: ποιητ. αίτιο «ὑπό τῶν Ἀθηναίων» → υποκ. «οἱ Ἀθηναῖοι»· υποκ. «ὁ Ἀριστείδης» → αντικ. «τόν Ἀριστείδην»· κατηγ. υποκ. «δίκαιος» → κατηγ. αντικ. «δίκαιον» (ονομ.→αιτ.). «ὠνομάσθη»→«ὠνόμασαν»."},{"gr":"Οἱ ἀγαθοί τιμῶνται ὑπό πάντων. → Πάντες τιμῶσι τούς ἀγαθούς.","an":"Ποιητ. αίτιο «ὑπό πάντων» → υποκ. «πάντες»· υποκ. «οἱ ἀγαθοί» → αντικ. «τούς ἀγαθούς»· «τιμῶνται» (παθ. ενεστ.) → «τιμῶσι» (ενεργ. ενεστ. γ΄ πληθ., συμφωνία με «πάντες»). Διατήρηση χρόνου/εγκλίσεως."}],"note":"Συνοπτικός χρυσός κανόνας και των δύο κατευθύνσεων: ΔΡΑΣΤΗΣ και ΠΑΣΧΟΝ παραμένουν τα ίδια πρόσωπα/πράγματα· αλλάζει μόνο ΠΟΙΟΣ μπαίνει στη θέση του υποκειμένου. Διατήρησε πάντα ίδιο χρόνο, έγκλιση και νόημα."}]);
  T("syn-euthys-plagios", [{"h":"Τι είναι ο ευθύς και τι ο πλάγιος λόγος","body":"<p><b>Ευθύς λόγος</b> (<i>oratio recta</i>) ονομάζεται η αυτούσια, αυτοτελής διατύπωση μιας σκέψης, ενός λόγου ή μιας ερώτησης, όπως ακριβώς εκφωνήθηκε από το πρόσωπο που μιλά. Στον ευθύ λόγο η πρόταση στέκεται μόνη της, χωρίς να εξαρτάται από κανένα ρήμα: <i>«βοηθήσω»</i>, <i>«ἴθι»</i>, <i>«ποῦ ἐστιν ὁ Κῦρος;»</i>.</p><p><b>Πλάγιος λόγος</b> (<i>oratio obliqua</i>) ονομάζεται η μεταφορά του ίδιου περιεχομένου όχι αυτούσια, αλλά <b>έμμεσα</b>, ως <b>εξάρτηση</b> από ένα ρήμα (το λεγόμενο <b>ρήμα εξαρτήσεως</b>). Δηλαδή αναφέρουμε τα λόγια κάποιου ενσωματώνοντάς τα στη δική μας πρόταση: <i>ἔφη ὅτι βοηθήσοι</i> («είπε ότι θα βοηθήσει»).</p><p>Η μετατροπή του ευθέος σε πλάγιο λόγο δεν είναι μηχανική· απαιτεί να αναγνωρίσουμε <b>(α)</b> το είδος της κύριας πρότασης του ευθέος λόγου, <b>(β)</b> το ρήμα εξαρτήσεως που θα προσθέσουμε και τη σύνταξη που αυτό απαιτεί, και <b>(γ)</b> τον χρόνο του ρήματος εξαρτήσεως (αρκτικός ή ιστορικός), από τον οποίο κρίνεται αν θα εμφανιστεί η <b>ευκτική του πλαγίου λόγου</b>.</p><p>Αντίστροφα, για να μετατρέψουμε πλάγιο σε ευθύ λόγο, απομονώνουμε το εξαρτημένο τμήμα, αφαιρούμε το ρήμα εξαρτήσεως και επαναφέρουμε την αρχική, αυτοτελή έγκλιση.</p>","examples":[{"gr":"Ευθύς: «βοηθήσω». — Πλάγιος: ἔφη βοηθήσειν.","an":"Κύρια πρόταση κρίσεως με οριστική μέλλοντα μετατρέπεται σε ειδικό απαρέμφατο μέλλοντα, εξαρτημένο από το ρήμα λεκτικό ἔφη."},{"gr":"Ευθύς: «ποῦ ἐστιν ὁ Κῦρος;». — Πλάγιος: ἠρώτα ποῦ εἴη ὁ Κῦρος.","an":"Ευθεία ερώτηση μερικής αγνοίας γίνεται πλάγια ερωτηματική πρόταση· η οριστική ἐστιν, ύστερα από ιστορικό χρόνο (ἠρώτα), γίνεται ευκτική του πλαγίου λόγου εἴη."},{"gr":"Κῦρος ἔλεγεν ὅτι ἡ ὁδός ἔσοιτο πρός βασιλέα.","an":"Ξεν. Ἀνάβ. 1.4.11 — λεκτικό ρήμα ιστορικού χρόνου (ἔλεγεν) + ειδική πρόταση· η οριστική μέλλοντα του ευθέος (ἔσται) γίνεται ευκτική π.λ. μέλλοντα ἔσοιτο."},{"gr":"Ἧκεν ἄγγελος λέγων ὅτι λελοιπώς εἴη Συέννεσις τά ἄκρα.","an":"Ξεν. Ἀνάβ. 1.2.21 — ειδική πρόταση εξαρτημένη από αφηγηματικό παρελθόν· η οριστική παρακειμένου του ευθέος (λέλοιπε) αποδίδεται περιφραστικά με ευκτική π.λ. λελοιπώς εἴη."}],"note":"Κλειδί ολόκληρης της ύλης: η μετατροπή κρίνεται πάντοτε από δύο πράγματα — το ΕΙΔΟΣ της κύριας πρότασης (κρίσεως / επιθυμίας / ερώτηση / επιφωνηματική) και τον ΧΡΟΝΟ του ρήματος εξαρτήσεως (αρκτικός ή ιστορικός)."},{"h":"Τα ρήματα εξαρτήσεως — η αφετηρία του πλαγίου λόγου","body":"<p>Κάθε πλάγιος λόγος προϋποθέτει ένα <b>ρήμα εξαρτήσεως</b>, από το οποίο αναρτάται το εξαρτημένο τμήμα. Το είδος αυτού του ρήματος καθορίζει σε μεγάλο βαθμό τη σύνταξη που θα ακολουθήσει (ειδική πρόταση, ειδικό απαρέμφατο, κατηγορηματική μετοχή, πλάγια ερώτηση κ.λπ.). Τα ρήματα εξαρτήσεως ομαδοποιούνται ως εξής:</p><ul><li><b>Λεκτικά</b> (του <i>λέγειν</i>): λέγω, φημί, εἶπον, ἀποκρίνομαι, διηγοῦμαι, ἀγγέλλω, δηλῶ, φράζω, ὁμολογῶ.</li><li><b>Γνωστικά / δοξαστικά</b> (του γιγνώσκειν και νομίζειν): γιγνώσκω, οἶδα, ἐπίσταμαι, μανθάνω, νομίζω, ἡγοῦμαι, οἴομαι, ἐλπίζω, ὑπολαμβάνω.</li><li><b>Αισθητικά</b> (της αντίληψης): αἰσθάνομαι, ὁρῶ, ἀκούω, πυνθάνομαι, αἰσθάνομαι.</li><li><b>Δεικτικά / αποδεικτικά</b>: δείκνυμι, δηλῶ, ἀποφαίνω, ἐλέγχω.</li><li><b>Ρήματα βουλήσεως / προτροπής</b> (για κύριες επιθυμίας): κελεύω, παραγγέλλω, προστάττω, συμβουλεύω, δέομαι, αἰτῶ, εὔχομαι, βούλομαι.</li><li><b>Ρήματα ερωτήσεως / απορίας</b> (για ερωτήσεις): ἐρωτῶ, πυνθάνομαι, ἀπορῶ, σκοπῶ, βουλεύομαι, οὐκ οἶδα, θαυμάζω.</li></ul><p>Ορισμένα ρήματα δέχονται περισσότερες από μία συντάξεις με διαφορά σημασίας. Χαρακτηριστικό το <b>οἶδα / αἰσθάνομαι / ἀκούω</b>: με <b>κατηγορηματική μετοχή</b> δηλώνουν βεβαιότητα για πραγματικό γεγονός (<i>οἶδα θνητός ὤν</i> = ξέρω καλά ότι είμαι θνητός), ενώ με <b>ειδικό απαρέμφατο</b> δηλώνουν γνώμη/μάθηση κανόνα (<i>οἶδα θνητός εἶναι</i>). Παρομοίως το <b>λέγω</b>: + ειδικό απαρέμφατο = ισχυρίζομαι· + τελικό απαρέμφατο = προστάζω.</p>","examples":[{"gr":"ἔλεξαν ὅτι πέμψειε σφᾶς ὁ βασιλεύς.","an":"Λεκτικό ρήμα ιστορικού χρόνου (ἔλεξαν) + ειδική πρόταση με ευκτική του πλαγίου λόγου (πέμψειε). Ευθύς: «ἔπεμψεν ἡμᾶς ὁ βασιλεύς»."},{"gr":"Κῦρος ἐπυνθάνετο αὐτῶν ὁπόσην ὁδόν διήλασαν.","an":"Αισθητικό/ερωτηματικό ρήμα (ἐπυνθάνετο) + πλάγια ερωτηματική πρόταση. Η οριστική αορίστου διήλασαν διατηρείται. Ευθύς: «πόσην ὁδόν διηλάσατε;»."},{"gr":"Ὁ δέ ἀπεκρίνατο ὅτι πυνθάνοιτο τούς πολεμίους οὐ πρόσω εἶναι.","an":"(τύπου Ξεν. Ἀνάβ.) Λεκτικό ἀπεκρίνατο + ειδική με ευκτική π.λ. πυνθάνοιτο, η οποία με τη σειρά της εξαρτά ειδικό απαρέμφατο (εἶναι): αλυσιδωτός πλάγιος λόγος."},{"gr":"οἶδα ὑμᾶς εὔνους ὄντας.","an":"(τύπου Ξενοφῶντος) Γνωστικό οἶδα + κατηγορηματική μετοχή (ὄντας) για πραγματικό γεγονός· δηλώνει βεβαιότητα, όχι απλή γνώμη."}],"table":{"title":"Ρήματα εξαρτήσεως και η τυπική τους σύνταξη","cols":["Κατηγορία","Παραδείγματα ρημάτων","Συνηθέστερη εκφορά του πλαγίου"],"rows":[["Λεκτικά","λέγω, φημί, εἶπον, ἀγγέλλω, ἀποκρίνομαι","ειδική πρόταση (ὅτι/ὡς) ή ειδικό απαρέμφατο"],["Γνωστικά/δοξαστικά","γιγνώσκω, οἶδα, νομίζω, ἡγοῦμαι, ἐλπίζω","ειδικό απαρέμφατο ή κατηγορηματική μετοχή / ειδική πρόταση"],["Αισθητικά","αἰσθάνομαι, ὁρῶ, ἀκούω, πυνθάνομαι","κατηγορηματική μετοχή (πραγματικό) / ειδική πρόταση"],["Βουλήσεως-προτροπής","κελεύω, προστάττω, συμβουλεύω, δέομαι, εὔχομαι","τελικό απαρέμφατο","ερώτησης-απορίας"],["Ερώτησης/απορίας","ἐρωτῶ, πυνθάνομαι, ἀπορῶ, σκοπῶ","πλάγια ερωτηματική πρόταση"]]},"note":"Επειδή η σύνταξη εξαρτάται από το ρήμα, ΠΡΩΤΑ διαλέγουμε σωστό ρήμα εξαρτήσεως και ΥΣΤΕΡΑ μετατρέπουμε την πρόταση. Λάθος ρήμα οδηγεί σε λάθος εκφορά."},{"h":"Κύρια πρόταση ΚΡΙΣΕΩΣ → ειδική πρόταση / ειδικό απαρέμφατο / κατηγορηματική μετοχή","body":"<p>Οι κύριες προτάσεις <b>κρίσεως</b> του ευθέος λόγου (αυτές που δηλώνουν κρίση, βεβαίωση, γνώμη και έχουν <b>οριστική</b> ή <b>δυνητική έγκλιση</b>) μετατρέπονται στον πλάγιο λόγο με <b>τρεις</b> ισοδύναμους τρόπους, ανάλογα με το ρήμα εξαρτήσεως:</p><ul><li><b>(α) Ειδική πρόταση</b>, εισαγόμενη με <b>ὅτι</b> (αντικειμενική κρίση) ή <b>ὡς</b> (υποκειμενική κρίση). Εκφορά: <b>οριστική</b> (αν θέλουμε να τονίσουμε το πραγματικό) ή <b>ευκτική του πλαγίου λόγου</b> (μόνο ύστερα από ιστορικό χρόνο).</li><li><b>(β) Ειδικό απαρέμφατο</b>, στον <b>χρόνο</b> της αρχικής οριστικής (ενεστ.→ενεστ., αόρ.→αόρ., μέλλ.→μέλλ.). Δέχονται κυρίως τα λεκτικά και δοξαστικά.</li><li><b>(γ) Κατηγορηματική μετοχή</b>, στον χρόνο της αρχικής οριστικής. Δέχονται κυρίως τα αισθητικά και γνωστικά (οἶδα, αἰσθάνομαι, ὁρῶ, ἀκούω, δείκνυμι).</li></ul><p>Ισχύει ο κανόνας: <b>«ό,τι ισχύει για το ειδικό απαρέμφατο ισχύει και για την κατηγορηματική μετοχή του πλαγίου λόγου»</b> — και οι δύο ακολουθούν τον χρόνο της αρχικής οριστικής.</p><p><b>Δυνητική έγκλιση:</b> Αν η κύρια πρόταση κρίσεως έχει <b>δυνητική οριστική</b> ή <b>δυνητική ευκτική</b> (με <b>ἄν</b>), τότε:</p><ul><li>Στην ειδική πρόταση διατηρείται η δυνητική έγκλιση με το <b>ἄν</b> (το ἄν ΠΟΤΕ δεν χάνεται).</li><li>Στο απαρέμφατο/μετοχή προκύπτει <b>δυνητικό απαρέμφατο</b> ή <b>δυνητική μετοχή</b>, πάλι με το ἄν: <i>«οὐκ ἄν δυναίμην» → ἔφη οὐκ ἄν δύνασθαι</i>.</li></ul>","examples":[{"gr":"Ευθύς: «βοηθήσω». — Πλάγιος: ἔφη βοηθήσειν / ἔφη ὅτι βοηθήσοι.","an":"Οριστική μέλλοντα → ειδικό απαρέμφατο μέλλοντα (βοηθήσειν) ΟΛΟΣ ή ειδική πρόταση με ευκτική π.λ. μέλλοντα (βοηθήσοι), αφού ἔφη = ιστορικός χρόνος."},{"gr":"Ευθύς: «οὐκ ἄν δυναίμην». — Πλάγιος: ἔφη οὐκ ἄν δύνασθαι.","an":"Δυνητική ευκτική → δυνητικό ειδικό απαρέμφατο· το ἄν διατηρείται υποχρεωτικά."},{"gr":"Ευθύς: «οἱ ἐναντίοι παρασκευάζονται». — Πλάγιος: ᾔσθετο τούς ἐναντίους παρασκευαζομένους.","an":"Οριστική ενεστώτα → κατηγορηματική μετοχή ενεστώτα, εξαρτημένη από αισθητικό ρήμα (ᾔσθετο). Η μετοχή ακολουθεί τον χρόνο της οριστικής."},{"gr":"Ευθύς: «Κῦρος τέθνηκεν». — Πλάγιος: ἤγγειλεν ὅτι Κῦρος τεθνηκώς εἴη / ἔφη Κῦρον τεθνηκέναι.","an":"Παρακείμενος → ειδική πρόταση με ευκτική π.λ. παρακειμένου (περιφραστικά τεθνηκώς εἴη) ή απαρέμφατο παρακειμένου (τεθνηκέναι)."},{"gr":"ἔλεγον ὅτι Κῦρος μέν τέθνηκεν, Ἀριαῖος δέ πεφευγώς εἴη.","an":"Ξεν. Ἀνάβ. 2.1.3 — δύο ειδικές: η μία διατηρεί παρακείμενο οριστικής (τέθνηκεν) για ζωντάνια, η άλλη τρέπεται σε ευκτική π.λ. (πεφευγώς εἴη) — δείγμα συνύπαρξης οριστικής και ευκτικής π.λ."}],"table":{"title":"Μετατροπή κύριας πρότασης κρίσεως","cols":["Ευθύς λόγος (κύρια κρίσεως)","Πλάγιος λόγος","Εκφορά"],"rows":[["Οριστική (π.χ. βοηθήσω)","ειδικό απαρέμφατο","στον χρόνο της οριστικής (βοηθήσειν)"],["Οριστική","κατηγορηματική μετοχή","στον χρόνο της οριστικής (βοηθήσων)"],["Οριστική","ειδική πρόταση (ὅτι/ὡς)","οριστική ή ευκτική π.λ. (μετά ιστ. χρόνο)"],["Δυνητική ευκτική (οὐκ ἄν δυναίμην)","δυνητικό απαρέμφατο / δυν. μετοχή / ειδική","με το ἄν να διατηρείται πάντα"],["Δυνητική οριστική (ἐποίησεν ἄν)","δυνητικό απαρέμφατο / ειδική","με το ἄν να διατηρείται πάντα"]]},"note":"Το ειδικό απαρέμφατο και η κατηγορηματική μετοχή δεν παίρνουν ΠΟΤΕ ευκτική του πλαγίου λόγου — η ευκτική π.λ. εμφανίζεται μόνο σε ΠΡΟΤΑΣΕΙΣ (ειδικές, πλάγιες ερωτηματικές, δευτερεύουσες)."},{"h":"Κύρια πρόταση ΕΠΙΘΥΜΙΑΣ → τελικό απαρέμφατο (και τελική / ενδοιαστική)","body":"<p>Οι κύριες προτάσεις <b>επιθυμίας</b> του ευθέος λόγου είναι όσες εκφράζουν προσταγή, προτροπή, αποτροπή, ευχή ή απαγόρευση. Στον ευθύ λόγο εκφέρονται με:</p><ul><li><b>προστακτική</b> (προσταγή): «ἴθι»,</li><li><b>προτρεπτική υποτακτική</b> (α΄ πληθ.): «ἴωμεν»,</li><li><b>ευχετική ευκτική</b> (ευχή): «ἴοις»,</li><li><b>απαγορευτική / αποτρεπτική υποτακτική ή προστακτική</b> (με μή): «μή ἔλθῃς».</li></ul><p>Όλες αυτές μετατρέπονται στον πλάγιο λόγο κατά κανόνα σε <b>τελικό απαρέμφατο</b>, εξαρτημένο από ρήμα βουλήσεως ή προτροπής (κελεύω, προστάττω, συμβουλεύω, δέομαι, εὔχομαι κ.λπ.). Η άρνηση του τελικού απαρεμφάτου είναι <b>μή</b> (όχι οὐ).</p><p>Το τελικό απαρέμφατο τίθεται στον χρόνο που αντιστοιχεί στο ποιόν ενεργείας της αρχικής έγκλισης (ενεστ. για εξακολούθηση, αόρ. για στιγμιαίο), <b>όχι</b> με χρονική σημασία.</p><p>Εναλλακτικά, αντί τελικού απαρεμφάτου, μια κύρια επιθυμίας μπορεί να αποδοθεί και με <b>τελική πρόταση</b> (ἵνα/ὅπως/ὡς + υποτακτική ή ευκτική π.λ.) όταν δηλώνεται σκοπός, ή με <b>ενδοιαστική πρόταση</b> (μή / μή οὐ + υποτακτική ή ευκτική π.λ.) όταν στον ευθύ λόγο υπάρχει φόβος ή δισταγμός (π.χ. «φοβοῦμαι μή ἔλθῃ»).</p>","examples":[{"gr":"Ευθύς: «ἴθι». — Πλάγιος: κελεύω σε ἰέναι.","an":"Προστακτική ενεστώτα → τελικό απαρέμφατο ενεστώτα (ἰέναι), εξάρτηση από κελεύω."},{"gr":"Ευθύς: «ἴοις». — Πλάγιος: εὔχομαι σε ἰέναι.","an":"Ευχετική ευκτική → τελικό απαρέμφατο, εξάρτηση από εὔχομαι."},{"gr":"Ευθύς: «μή ἔλθῃς». — Πλάγιος: συμβουλεύω σοι μή ἐλθεῖν.","an":"Αποτρεπτική υποτακτική → αρνητικό τελικό απαρέμφατο (μή ἐλθεῖν)· η άρνηση μή διατηρείται."},{"gr":"Ευθύς: «φοβοῦμαι· μή ἔλθῃ ὁ πολέμιος». — Πλάγιος: ἐφοβεῖτο μή ἔλθοι ὁ πολέμιος.","an":"Ενδοιαστική σημασία· η υποτακτική ἔλθῃ γίνεται ευκτική π.λ. ἔλθοι, αφού το ρήμα εξαρτήσεως είναι ιστορικού χρόνου (ἐφοβεῖτο)."},{"gr":"Κῦρος ἐκέλευσε τούς στρατιώτας τά ὅπλα λαβεῖν.","an":"(τύπου Ξεν. Ἀνάβ.) Κύρια επιθυμίας του ευθέος («λάβετε τά ὅπλα») → τελικό απαρέμφατο αορίστου λαβεῖν, εξάρτηση από κελεύω."},{"gr":"παρήγγειλαν τοῖς στρατιώταις μή ἀπολείπεσθαι τῶν τάξεων.","an":"(τύπου Θουκυδίδου) Απαγορευτική κύρια επιθυμίας → αρνητικό τελικό απαρέμφατο με μή· εξάρτηση από ρήμα προτροπής παρήγγειλαν."}],"table":{"title":"Μετατροπή κύριας πρότασης επιθυμίας","cols":["Ευθύς λόγος (έγκλιση)","Σημασία","Πλάγιος λόγος"],"rows":[["προστακτική: ἴθι","προσταγή","τελικό απαρέμφατο: (κελεύω) ἰέναι"],["προτρεπτική υποτ.: ἴωμεν","προτροπή","τελικό απαρέμφατο: ἰέναι"],["ευχετική ευκτ.: ἴοις","ευχή","τελικό απαρέμφατο: (εὔχομαι) ἰέναι"],["απαγορευτική: μή ἔλθῃς","απαγόρευση/αποτροπή","αρνητικό τελ. απαρ.: μή ἐλθεῖν"],["φοβοῦμαι μή ἔλθῃ","φόβος/δισταγμός","ενδοιαστική: (μή + υποτ./ευκτ. π.λ.)"]]},"note":"Διάκριση ζωτικής σημασίας: ΟΡΙΣΤΙΚΗ/δυνητική κύρια = ΚΡΙΣΕΩΣ → ειδικό απαρέμφατο. ΠΡΟΣΤΑΚΤΙΚΗ/υποτ./ευχ. ευκτ. κύρια = ΕΠΙΘΥΜΙΑΣ → τελικό απαρέμφατο. Λάθος είδος απαρεμφάτου = λάθος μετατροπή."},{"h":"Ευθεία ερώτηση → πλάγια ερωτηματική πρόταση","body":"<p>Η <b>ευθεία ερώτηση</b> του ευθέος λόγου μετατρέπεται σε <b>πλάγια ερωτηματική πρόταση</b>, εξαρτημένη από ρήμα ερωτήσεως, απορίας, σκέψης ή άγνοιας (ἐρωτῶ, πυνθάνομαι, ἀπορῶ, σκοπῶ, οὐκ οἶδα). Διακρίνουμε δύο μεγάλες κατηγορίες ανάλογα με τον τύπο της αρχικής ερώτησης:</p><h3>1. Ερωτήσεις ΜΕΡΙΚΗΣ αγνοίας</h3><p>Στον ευθύ λόγο αρχίζουν με <b>ερωτηματική αντωνυμία ή επίρρημα</b> (τίς, πόσος, ποῦ, πότε, πῶς, διά τί). Στον πλάγιο λόγο εισάγονται:</p><ul><li>είτε με την ίδια <b>ευθεία ερωτηματική λέξη</b> (τίς, ποῦ…),</li><li>είτε, συχνότερα, με την αντίστοιχη <b>πλάγια / αναφορική-ερωτηματική λέξη</b>: τίς→ὅστις, ποῦ→ὅπου, πῶς→ὅπως, πόσος→ὁπόσος, πότε→ὁπότε.</li></ul><h3>2. Ερωτήσεις ΟΛΙΚΗΣ αγνοίας</h3><p>Στον ευθύ λόγο δεν έχουν ερωτηματική λέξη (ζητούν απάντηση ναι/όχι). Στον πλάγιο λόγο εισάγονται με <b>εἰ</b> (= αν) στη μονομελή, και με <b>εἰ… ἤ / πότερον… ἤ</b> στη διμελή.</p><p><b>Εκφορά:</b> Ύστερα από <b>αρκτικό</b> χρόνο διατηρείται η αρχική έγκλιση. Ύστερα από <b>ιστορικό</b> χρόνο η οριστική γίνεται κατά κανόνα <b>ευκτική του πλαγίου λόγου</b>, και η <b>απορηματική υποτακτική</b> γίνεται <b>ευκτική του πλαγίου λόγου</b> (αλλά μπορεί και να διατηρηθεί η υποτακτική). Δυνητική ευκτική/οριστική διατηρούνται με το ἄν.</p>","examples":[{"gr":"Ευθύς: «ποῦ ἐστιν ὁ Κῦρος;». — Πλάγιος: ἠρώτα ποῦ εἴη (ὅπου εἴη) ὁ Κῦρος.","an":"Ερώτηση μερικής αγνοίας· οριστική ἐστιν → ευκτική π.λ. εἴη μετά τον ιστορικό ἠρώτα. Το ποῦ μπορεί να γίνει ὅπου."},{"gr":"Ευθύς: «διά τί αἱ θύραι νύκτωρ ἐψόφουν;». — Πλάγιος: ἠρόμην διά τί αἱ θύραι νύκτωρ ψοφοῖεν.","an":"Παρατατικός του ευθέος (ἐψόφουν) αντιστοιχεί στην ευκτική π.λ. ενεστώτα ψοφοῖεν: η ευκτική π.λ. ενεστώτα μπορεί να αντιπροσωπεύει ενεστώτα Ή παρατατικό."},{"gr":"Ευθύς: «τί πάθω;». — Πλάγιος: ἠπόρει τί πάθοι.","an":"Απορηματική υποτακτική (πάθω) → ευκτική π.λ. αορίστου (πάθοι) μετά τον ιστορικό ἠπόρει."},{"gr":"Ευθύς: «οἰκεῖται ἡ χώρα;». — Πλάγιος: ἐπυνθάνετο εἰ οἰκοῖτο ἡ χώρα.","an":"Ερώτηση ολικής αγνοίας → πλάγια με εἰ· οριστική οἰκεῖται → ευκτική π.λ. οἰκοῖτο μετά τον ιστορικό ἐπυνθάνετο."},{"gr":"Κῦρος ἐπυνθάνετο αὐτῶν ὁπόσην ὁδόν διήλασαν.","an":"Ξεν. Ἀνάβ. 1.5.1 — πλάγια ερωτηματική μερικής αγνοίας· εδώ η οριστική αορίστου διήλασαν ΔΙΑΤΗΡΕΙΤΑΙ (η ευκτική π.λ. δεν είναι υποχρεωτική). Το ὁπόσην = πλάγιο του πόσην."},{"gr":"ἤρετο εἰ βούλοιντο ἀκοῦσαι.","an":"(τύπου Πλάτωνος) Ερώτηση ολικής αγνοίας → πλάγια με εἰ· η οριστική/υποτακτική του ευθέος («βούλεσθε ἀκοῦσαι;») γίνεται ευκτική π.λ. βούλοιντο μετά τον ιστορικό ἤρετο."}],"table":{"title":"Εισαγωγή πλάγιων ερωτηματικών προτάσεων","cols":["Είδος ερώτησης","Ευθύς λόγος","Εισαγωγή στον πλάγιο"],"rows":[["Μερικής αγνοίας","τίς, πόσος, ποῦ, πῶς, πότε, διά τί","ίδια λέξη ή ὅστις, ὁπόσος, ὅπου, ὅπως, ὁπότε"],["Ολικής μονομελής","(χωρίς ερωτ. λέξη)","εἰ"],["Ολικής διμελής","πότερον… ἤ…","εἰ… ἤ… / πότερον… ἤ…"]]},"note":"Στις πλάγιες ερωτηματικές η οριστική ιστορικού χρόνου ΔΙΑΤΗΡΕΙΤΑΙ (δεν τρέπεται σε ευκτική): ἐπυνθάνετο ὁπόσην ὁδόν διήλασαν."},{"h":"Επιφωνηματική κύρια πρόταση και ειδικές περιπτώσεις","body":"<p>Η <b>επιφωνηματική</b> κύρια πρόταση του ευθέος λόγου (που εκφράζει θαυμασμό, αγανάκτηση ή έκπληξη: «ὡς καλός ὁ παῖς!», «οἷον ποιεῖς!») μετατρέπεται στον πλάγιο λόγο κατά δύο τρόπους:</p><ul><li><b>(α)</b> σε <b>ειδική πρόταση</b> (με ὅτι/ὡς), όταν εξαρτάται από ρήμα που δηλώνει αίσθημα/κρίση (θαυμάζω, ἀγανακτῶ): <i>«ὡς καλός ὁ παῖς!» → ἐθαύμαζεν ὡς καλός εἴη ὁ παῖς</i>.</li><li><b>(β)</b> σε <b>πλάγια ερωτηματική πρόταση</b> με τις αναφορικές-ποσοτικές/ποιοτικές λέξεις (ὅσος, οἷος, ὡς): <i>«οἷον ποιεῖς!» → ἐθαύμαζεν οἷον ποιοίη</i>.</li></ul><p>Η εκφορά ακολουθεί τους ίδιους κανόνες: ευκτική του πλαγίου λόγου μετά από ιστορικό χρόνο.</p><h3>Άλλες κύριες προτάσεις</h3><p><b>Αιτιολογική σημασία:</b> Μια αιτιολογική κύρια ή προβολή αιτίας μπορεί στον πλάγιο λόγο να αποδοθεί με <b>αιτιολογική πρόταση</b> (ὅτι/ὡς + οριστική ή ευκτική π.λ. μετά ιστ. χρόνο). Οι αιτιολογικές με ὅτι/ὡς συμπεριφέρονται όπως οι <b>ειδικές</b> (τρέπουν και την οριστική αορίστου σε ευκτική π.λ.).</p><p><b>Χρονική σημασία:</b> Σπανιότερα και η χρονική πρόταση με <b>ἐπεί</b> μπορεί να τρέψει την οριστική αορίστου σε ευκτική π.λ. (ακολουθεί τις ειδικές/αιτιολογικές).</p>","examples":[{"gr":"Ευθύς: «ὡς ἀνδρεῖοι οἱ στρατιῶται!». — Πλάγιος: ἐθαύμαζεν ὡς ἀνδρεῖοι εἶεν οἱ στρατιῶται.","an":"Επιφωνηματική → ειδική με ὡς· οριστική εἰσίν → ευκτική π.λ. εἶεν μετά τον ιστορικό ἐθαύμαζεν."},{"gr":"Ευθύς: «οἷα πάσχω!». — Πλάγιος: ὠδύρετο οἷα πάσχοι.","an":"Επιφωνηματική με οἷα → πλάγια ερωτηματική· οριστική πάσχω → ευκτική π.λ. πάσχοι."},{"gr":"ὁ ἄγγελος ἔλεγεν ὅτι Κῦρος λελοιπώς εἴη τά ἄκρα, ἐπεί αἴσθοιτο τοῦτο.","an":"Η χρονική με ἐπεί ακολουθεί τις ειδικές: η οριστική αορίστου ᾔσθετο τρέπεται σε ευκτική π.λ. αἴσθοιτο. Ευθύς: «Κῦρος λέλοιπε τά ἄκρα, ἐπεί ᾔσθετο τοῦτο»."},{"gr":"ἐθαύμαζον ὅσον τό πλῆθος εἴη τῶν πολεμίων.","an":"(τύπου Ξενοφῶντος) Επιφωνηματική («ὅσον τό πλῆθος!») → πλάγια ερωτηματική με ποσοτικό ὅσον· οριστική ἐστί → ευκτική π.λ. εἴη μετά τον ιστορικό ἐθαύμαζον."}],"note":"Η επιφωνηματική είναι σπάνια στις σχολικές ασκήσεις, αλλά πρέπει να γνωρίζεται: αναγνωρίζεται από επιφωνηματικές λέξεις (ὡς, οἷος, ὅσος) και θαυμαστικό τόνο στον ευθύ λόγο."},{"h":"Η ευκτική του πλαγίου λόγου — ο πυρήνας του φαινομένου","body":"<p>Η <b>ευκτική του πλαγίου λόγου</b> (<i>obliqua optativa</i>) είναι η σημαντικότερη μεταβολή της έγκλισης στον πλάγιο λόγο. Είναι μια ευκτική που εμφανίζεται <b>ΜΟΝΟ</b> στον πλάγιο λόγο και <b>ΜΟΝΟ</b> ύστερα από ρήμα εξαρτήσεως <b>ιστορικού χρόνου</b> (παρατατικός, αόριστος, υπερσυντέλικος, και ο γνωμικός/ιστορικός αόριστος).</p><h3>Πότε χρησιμοποιείται</h3><p>Ύστερα από ιστορικό χρόνο, σε <b>προτάσεις</b> του πλαγίου λόγου (ειδικές, πλάγιες ερωτηματικές, ενδοιαστικές, τελικές, και τις περισσότερες δευτερεύουσες), τρέπονται σε ευκτική του πλαγίου λόγου:</p><ul><li>η <b>οριστική</b> (αρκτικού χρόνου) της κύριας κρίσεως,</li><li>η <b>υποτακτική</b> (απορηματική, βουλητική, υποτακτική δευτερευουσών),</li><li>η <b>απορηματική υποτακτική</b> των ερωτήσεων.</li></ul><h3>Πότε ΔΕΝ χρησιμοποιείται — διατήρηση της αρχικής έγκλισης</h3><p>Η ευκτική του πλαγίου λόγου είναι <b>προαιρετική</b>: ο συγγραφέας μπορεί, για ζωντάνια/παραστατικότητα, να διατηρήσει την αρχική έγκλιση ακόμη και μετά από ιστορικό χρόνο. Επιπλέον ΔΕΝ μπαίνει ποτέ:</p><ul><li>ύστερα από <b>αρκτικό</b> χρόνο (εκεί διατηρείται πάντα η αρχική έγκλιση)·</li><li>στη θέση <b>οριστικής ιστορικού χρόνου</b> των δευτερευουσών προτάσεων (παρατατικός, αόριστος, υπερσυντέλικος διατηρούνται)·</li><li>στη θέση <b>δυνητικής</b> έγκλισης (η δυνητική ευκτ./οριστ. διατηρείται με το ἄν)·</li><li>στη θέση <b>ευκτικής της ευχής/δυνατότητας</b> που υπήρχε ήδη στον ευθύ λόγο (διατηρείται).</li></ul><h3>Χρονική αντιστοιχία</h3><p>Η ευκτική του πλαγίου λόγου <b>δεν</b> δηλώνει χρόνο αλλά ποιόν ενεργείας. Έτσι η <b>ευκτική π.λ. ενεστώτα</b> μπορεί να αντιστοιχεί σε ενεστώτα Ή παρατατικό του ευθέος, και η <b>ευκτική π.λ. αορίστου</b> σε αόριστο (ή σε απορηματική υποτακτική αορίστου).</p>","examples":[{"gr":"Ευθύς: «εἰσήγγειλα». — Πλάγιος: ἔφη ὅτι εἰσαγγείλειε.","an":"Οριστική αορίστου κύριας κρίσεως → ευκτική π.λ. αορίστου (εἰσαγγείλειε) μετά τον ιστορικό ἔφη."},{"gr":"Οἱ στρατηγοί διηγοῦντο ὅτι αὐτοί μέν ἐπί τούς πολεμίους πλέοιεν, τήν δέ ἀναίρεσιν τῶν ναυαγῶν προστάξαιεν.","an":"Δύο ειδικές με ευκτική π.λ.: πλέοιεν (ενεστ., από οριστ. ενεστ. πλέομεν) και προστάξαιεν (αόρ., από οριστ. αορ. προσετάξαμεν). Εξάρτηση από ιστορικό διηγοῦντο."},{"gr":"Ευθύς: «οἱ ἐναντίοι παρασκευάζονται». — Πλάγιος (διατήρηση): οἱ Ἀθηναῖοι ἐνόμιζον ὅτι οἱ ἐναντίοι παρεσκευάζοντο.","an":"Αντί ευκτικής π.λ. (παρασκευάζοιντο), ο συγγραφέας διατηρεί παρατατικό (παρεσκευάζοντο) που αντιστοιχεί σε ενεστώτα του ευθέος — δείγμα παραστατικής διατήρησης."},{"gr":"λέγοι ὅτι ταύτην μέν τήν ἡμέραν περιμενοῖεν αὐτούς, τῇ δέ ἄλλῃ ἀπιέναι φαίη.","an":"Ξεν. Ἀνάβ. 2.1.3 — αλυσιδωτός πλάγιος λόγος μετά ιστορικό χρόνο: ευκτικές π.λ. (λέγοι, περιμενοῖεν μέλλ., φαίη) εξαρτημένες η μία από την άλλη· δείχνει την ευκτική π.λ. σε όλους τους χρόνους."}],"table":{"title":"Έγκλιση ευθέος → πλαγίου ανάλογα με τον χρόνο εξαρτήσεως","cols":["Έγκλιση στον ευθύ (πρόταση)","Μετά ΑΡΚΤΙΚΟ χρόνο","Μετά ΙΣΤΟΡΙΚΟ χρόνο"],"rows":[["Οριστική αρκτικού χρόνου","διατηρείται οριστική","ευκτική π.λ. (ή διατηρείται)"],["Οριστική ιστορικού χρόνου (δευτ.)","διατηρείται","διατηρείται (ΟΧΙ ευκτική π.λ.)"],["Απορηματική υποτακτική","διατηρείται υποτακτική","ευκτική π.λ. (ή υποτακτική)"],["Δυνητική ευκτ./οριστ. (+ἄν)","διατηρείται με ἄν","διατηρείται με ἄν"],["Ευχετική ευκτική","διατηρείται","διατηρείται"]]},"note":"Συνοπτικός κανόνας-κλειδί: «Ευκτική του πλαγίου λόγου ΜΟΝΟ μετά από ιστορικό χρόνο, ΜΟΝΟ σε προτάσεις, ΠΟΤΕ στη θέση οριστικής ιστορικού χρόνου, ΠΟΤΕ στη θέση δυνητικής έγκλισης (που κρατά το ἄν)»."},{"h":"Δευτερεύουσες προτάσεις μέσα στον πλάγιο λόγο","body":"<p>Όταν ο ευθύς λόγος περιέχει και <b>δευτερεύουσες</b> προτάσεις (αναφορικές, χρονικές, υποθετικές, τελικές, αιτιολογικές κ.λπ.), αυτές μεταφέρονται κι αυτές στον πλάγιο λόγο, με τους εξής κανόνες (όταν το ρήμα εξαρτήσεως είναι <b>ιστορικού</b> χρόνου):</p><ul><li><b>Οριστική αρκτικού χρόνου</b> (ενεστ., μέλλ., παρακ.) και <b>υποτακτική</b> → <b>ευκτική του πλαγίου λόγου</b> (στον αντίστοιχο χρόνο). Όταν το ἄν συνόδευε την υποτακτική (π.χ. ὅταν, ἐάν), στην ευκτική π.λ. το ἄν χάνεται και οι σύνδεσμοι επανέρχονται στην απλή τους μορφή: ὅταν→ὅτε, ἐάν→εἰ, ὅς ἄν→ὅς.</li><li><b>Οριστική ιστορικού χρόνου</b> (παρατ., αόρ., υπερσ.) → <b>διατηρείται</b> αμετάβλητη (δεν γίνεται ευκτική π.λ.).</li></ul><p><b>Εξαίρεση:</b> Οι <b>αιτιολογικές</b> προτάσεις με <b>ὅτι/ὡς</b> ακολουθούν τις ειδικές, δηλαδή τρέπουν και την οριστική αορίστου σε ευκτική π.λ.· πιο σπάνια το ίδιο κάνουν και οι <b>χρονικές</b> με <b>ἐπεί</b>.</p><p>Ειδικά για τον <b>πλάγιο υποθετικό λόγο</b>: η υπόθεση (εἰ/ἐάν + ρήμα) και η απόδοση μεταφέρονται ολόκληρες. Στην απόδοση, η κύρια κρίσεως γίνεται συνήθως <b>απαρέμφατο</b> (ή ειδική με ευκτική π.λ.)· στην υπόθεση, η υποτακτική με ἐάν γίνεται <b>ευκτική π.λ.</b> με εἰ.</p>","examples":[{"gr":"Οἱ Ἀθηναῖοι ἐνόμισαν ὅτι οἱ ἐναντίοι παρεσκευάζοντο ἵνα ἐπίοιεν.","an":"Δευτ. τελική με υποτακτική ἐπίωσι → ευκτική π.λ. ἐπίοιεν μετά τον ιστορικό ἐνόμισαν. Ευθύς: «οἱ ἐναντίοι παρασκευάζονται ἵνα ἐπίωσι»."},{"gr":"ὁ ἄγγελος ἔλεγεν ὅτι Κῦρος λελοιπώς εἴη τά ἄκρα, ἐπεί αἴσθοιτο τοῦτο.","an":"Χρονική με ἐπεί που, κατ’ εξαίρεση, τρέπει την οριστ. αορ. ᾔσθετο σε ευκτική π.λ. αἴσθοιτο (ακολουθεί τις αιτιολογικές/ειδικές)."},{"gr":"Πλάγιος υποθετικός: ἐλογίζοντο ὡς, εἰ νικήσειαν τό περί τόν βασιλέα, τό ἄλλο πᾶν εὐχείρωτον ἔσοιτο.","an":"Ευθύς (προσδοκώμενο): «ἐάν νικήσωμεν τό περί τόν βασιλέα, τό ἄλλο πᾶν εὐχείρωτον ἔσται». Η υπόθ. υποτακτική νικήσωμεν → ευκτ. π.λ. νικήσειαν (ἐάν→εἰ)· η απόδ. οριστ. μέλλ. ἔσται → ευκτ. π.λ. μέλλ. ἔσοιτο."},{"gr":"Πλάγιος υποθετικός: Οἱ Λακεδαιμόνιοι ἐνόμιζον, εἰ τήν γῆν τέμνοιεν, καθαιρήσειν τήν τῶν Ἀθηναίων δύναμιν.","an":"Ευθύς: «ἐάν τήν γῆν τέμνωμεν, καθαιρήσομεν τήν τῶν Ἀθηναίων δύναμιν». Υπόθ. τέμνωμεν → ευκτ. π.λ. τέμνοιεν· απόδοση οριστ. μέλλ. → απαρέμφατο μέλλ. καθαιρήσειν (γιατί κύρια κρίσεως μετά νομίζω)."},{"gr":"Ἀγαπήσειν με ἔφασκεν εἰ τό σῶμα σώσω.","an":"Λυσ. 12.11 — πλάγιος υποθετικός λόγος: η απόδοση γίνεται ειδικό απαρέμφατο μέλλοντα (ἀγαπήσειν) μετά το λεκτικό ἔφασκεν, ενώ η υποθετική με εἰ διατηρεί την έγκλισή της. Ευθύς: «ἀγαπήσεις εἰ τό σῶμα σώσεις»."}],"table":{"title":"Δευτερεύουσες προτάσεις μετά από ΙΣΤΟΡΙΚΟ χρόνο","cols":["Έγκλιση στον ευθύ","Στον πλάγιο","Παρατήρηση"],"rows":[["οριστική αρκτικού χρόνου","ευκτική π.λ.","ή διατηρείται"],["υποτακτική (+ ἄν)","ευκτική π.λ. (χωρίς ἄν)","ὅταν→ὅτε, ἐάν→εἰ, ὅς ἄν→ὅς"],["οριστική ιστορικού χρόνου","διατηρείται","ΟΧΙ ευκτική π.λ."],["αιτιολογική ὅτι/ὡς + οριστ. αορ.","ευκτική π.λ.","εξαίρεση: ακολουθεί τις ειδικές"],["χρονική ἐπεί + οριστ. αορ.","(σπ.) ευκτική π.λ.","σπάνια εξαίρεση"]]},"note":"Στις δευτερεύουσες ο μετασχηματισμός των συνδέσμων είναι κρίσιμος: όταν φεύγει το ἄν (γιατί η υποτακτική γίνεται ευκτική π.λ.), ΠΡΕΠΕΙ να φύγει και από τον σύνδεσμο (ὅταν→ὅτε, ἐάν→εἰ)."},{"h":"Μεταβολές προσώπων, αντωνυμιών, δεικτικών και επιρρημάτων","body":"<p>Πέρα από τις εγκλίσεις, ο πλάγιος λόγος απαιτεί προσαρμογή του <b>πλαισίου εκφώνησης</b>: επειδή μιλά πλέον ο αφηγητής (όχι το αρχικό πρόσωπο) και από άλλο χρονικό/τοπικό σημείο, αλλάζουν τα πρόσωπα, οι αντωνυμίες, τα δεικτικά και τα δεικτικά επιρρήματα.</p><h3>1. Μεταβολή προσώπων</h3><p>Το <b>α΄ πρόσωπο</b> του ευθέος (ο ομιλητής) γίνεται κατά κανόνα <b>γ΄ πρόσωπο</b> στον πλάγιο, και αντικαθίσταται από <b>αυτοπαθή/έμμεσα αυτοπαθή</b> τύπους (οὗ, οἷ, ἕ, σφεῖς, σφᾶς) που αναφέρονται στο υποκείμενο του ρήματος εξαρτήσεως. Το <b>β΄ πρόσωπο</b> (ο ακροατής) γίνεται γ΄ πρόσωπο ή προσαρμόζεται κατά περίπτωση. Παράδειγμα: «βοηθήσω» (α΄) → ἔφη βοηθήσειν (το υποκ. του απαρ. = ο ίδιος).</p><h3>2. Μεταβολή δεικτικών αντωνυμιών</h3><p>Η αντωνυμία του κοντινού (<b>ὅδε, οὗτος</b>) γίνεται συχνά αντωνυμία του μακρινού (<b>ἐκεῖνος</b>), γιατί ο αφηγητής αναφέρεται σε κάτι απομακρυσμένο από το «εδώ-τώρα» του.</p><h3>3. Μεταβολή δεικτικών επιρρημάτων</h3><p>Τα τοπικά και χρονικά επιρρήματα μετατοπίζονται από το παρόν/εδώ του ομιλητή στο παρελθόν/εκεί της αφήγησης:</p><ul><li><b>ἐνταῦθα / ἐνθάδε</b> (εδώ) → <b>ἐκεῖ</b> (εκεί)</li><li><b>νῦν</b> (τώρα) → <b>τότε</b> (τότε)</li><li><b>τήμερον</b> (σήμερα) → <b>ἐκείνῃ τῇ ἡμέρᾳ</b></li><li><b>αὔριον</b> (αύριο) → <b>τῇ ὑστεραίᾳ</b></li><li><b>χθές</b> (χθες) → <b>τῇ προτεραίᾳ</b></li></ul>","examples":[{"gr":"Ευθύς: «ἐγώ νῦν ἐνταῦθα μένω». — Πλάγιος: ἔφη ἑαυτόν τότε ἐκεῖ μένειν.","an":"α΄ πρόσ. (ἐγώ μένω) → γ΄ με αυτοπαθή (ἑαυτόν μένειν)· νῦν→τότε, ἐνταῦθα→ἐκεῖ."},{"gr":"Ευθύς: «οὗτος ὁ ἀνήρ ἀδικεῖ με». — Πλάγιος: ἔλεγεν ὅτι ἐκεῖνος ὁ ἀνήρ ἑαυτόν ἀδικοίη.","an":"οὗτος→ἐκεῖνος (απομάκρυνση)· με→ἑαυτόν (α΄→γ΄ αυτοπαθές)· οριστ. ἀδικεῖ → ευκτ. π.λ. ἀδικοίη μετά τον ιστορικό ἔλεγεν."},{"gr":"Ευθύς: «αὔριον ἀφίξομαι». — Πλάγιος: ὑπέσχετο τῇ ὑστεραίᾳ ἀφίξεσθαι.","an":"αὔριον → τῇ ὑστεραίᾳ· οριστ. μέλλ. (κύρια κρίσεως, εδώ μάλλον υπόσχεση) → απαρέμφατο μέλλοντα ἀφίξεσθαι."},{"gr":"τῇ δέ ἄλλῃ ἀπιέναι φαίη.","an":"Ξεν. Ἀνάβ. 2.1.3 — μέσα στον πλάγιο λόγο ο χρονικός προσδιορισμός μετατοπίζεται από το «εδώ-τώρα» του ομιλητή (τῇ δ’ αὔριον) στο πλαίσιο της αφήγησης (τῇ δέ ἄλλῃ = την επόμενη ημέρα)."}],"table":{"title":"Μετατοπίσεις πλαισίου εκφώνησης","cols":["Ευθύς λόγος","Πλάγιος λόγος","Κατηγορία"],"rows":[["ἐγώ / α΄ πρόσωπο","γ΄ πρόσωπο, οὗ/οἷ/ἕ/σφεῖς","πρόσωπο/αντωνυμία"],["οὗτος, ὅδε","ἐκεῖνος","δεικτική αντωνυμία"],["νῦν","τότε","χρονικό επίρρημα"],["ἐνταῦθα, ἐνθάδε","ἐκεῖ","τοπικό επίρρημα"],["τήμερον / αὔριον / χθές","ἐκείνῃ τῇ ἡμέρᾳ / τῇ ὑστεραίᾳ / τῇ προτεραίᾳ","χρονικός προσδιορισμός"]]},"note":"Οι μεταβολές πλαισίου ΔΕΝ είναι μηχανικές: εξαρτώνται από το αν ο αφηγητής βρίσκεται στον ίδιο τόπο/χρόνο. Αν π.χ. ο τόπος δεν έχει αλλάξει, το ἐνταῦθα μπορεί και να διατηρηθεί."},{"h":"Συγκεντρωτικός πίνακας μετατροπών και μεθοδολογία","body":"<p>Συνοψίζουμε ολόκληρο το σύστημα του πλαγίου λόγου σε έναν πίνακα και σε μια σταθερή μεθοδολογία επίλυσης ασκήσεων.</p><h3>Βήματα μετατροπής ΕΥΘΥΣ → ΠΛΑΓΙΟΣ</h3><ul><li><b>1.</b> Αναγνωρίζω το <b>είδος</b> κάθε κύριας πρότασης (κρίσεως / επιθυμίας / ερώτηση / επιφωνηματική).</li><li><b>2.</b> Διαλέγω κατάλληλο <b>ρήμα εξαρτήσεως</b> και σημειώνω αν είναι <b>αρκτικού ή ιστορικού</b> χρόνου.</li><li><b>3.</b> Μετατρέπω την κύρια στην αντίστοιχη εκφορά (ειδική/απαρ./μετοχή ή τελικό απαρ. ή πλάγια ερωτηματική).</li><li><b>4.</b> Εφαρμόζω την <b>ευκτική του πλαγίου λόγου</b> μόνο μετά από ιστορικό χρόνο και μόνο σε προτάσεις.</li><li><b>5.</b> Μεταφέρω τις <b>δευτερεύουσες</b> (διατηρώ οριστική ιστ. χρόνου· τρέπω υποτακτική/οριστ. αρκτ. σε ευκτ. π.λ.· διορθώνω συνδέσμους ὅταν→ὅτε, ἐάν→εἰ).</li><li><b>6.</b> Διατηρώ το <b>δυνητικό ἄν</b> όπου υπάρχει.</li><li><b>7.</b> Προσαρμόζω <b>πρόσωπα, αντωνυμίες, δεικτικά, επιρρήματα</b> (νῦν→τότε, ἐνταῦθα→ἐκεῖ).</li></ul><h3>Βήματα μετατροπής ΠΛΑΓΙΟΣ → ΕΥΘΥΣ</h3><ul><li><b>1.</b> Βρίσκω και αφαιρώ το <b>ρήμα εξαρτήσεως</b>.</li><li><b>2.</b> Μετατρέπω το εξαρτημένο τμήμα σε <b>αυτοτελή</b> κύρια (απαρ./μετοχή/ειδική → οριστική κρίσεως· τελικό απαρ. → προστακτική/υποτ.· πλάγια ερωτ. → ευθεία).</li><li><b>3.</b> Επαναφέρω <b>ευκτική π.λ. → οριστική ή υποτακτική</b> (κατά το ποιόν), επαναφέρω ἐάν/ὅταν.</li><li><b>4.</b> Επαναφέρω <b>α΄/β΄ πρόσωπα</b>, νῦν, ἐνταῦθα, οὗτος.</li></ul>","examples":[{"gr":"Ευθύς: «βοηθήσω καί νικήσω». — Πλάγιος: ἔφη βοηθήσειν καί νικήσειν.","an":"Δύο κύριες κρίσεως (οριστ. μέλλ.) → δύο ειδικά απαρέμφατα μέλλοντα, εξάρτηση από ἔφη."},{"gr":"Ευθύς: «ἀπέλθετε καί μή μένετε». — Πλάγιος: ἐκέλευσεν αὐτούς ἀπελθεῖν καί μή μένειν.","an":"Δύο κύριες επιθυμίας (προστακτική + απαγορευτική) → δύο τελικά απαρέμφατα (το β΄ αρνητικό με μή)."},{"gr":"Πλάγιος: ἠρώτησεν εἰ ἀφίκοιτο ὁ ἄγγελος. — Ευθύς: «ἀφίκετο ὁ ἄγγελος;»","an":"Αντίστροφη: αφαιρώ το ἠρώτησεν, η πλάγια ερωτηματική ολικής αγνοίας (εἰ) ξαναγίνεται ευθεία· ευκτ. π.λ. αορ. ἀφίκοιτο → οριστ. αορ. ἀφίκετο."},{"gr":"Ξεν. Ἀνάβ. 2.1.3: ἔλεγον ὅτι Κῦρος μέν τέθνηκεν, Ἀριαῖος δέ πεφευγώς εἴη καί λέγοι ὅτι... τῇ δέ ἄλλῃ ἀπιέναι φαίη.","an":"Σύνθετο αυθεντικό παράδειγμα όπου συνυπάρχουν: διατήρηση οριστικής (τέθνηκεν), ευκτική π.λ. παρακειμένου (πεφευγώς εἴη), αλυσιδωτές ευκτικές π.λ. (λέγοι, φαίη) και απαρέμφατο (ἀπιέναι) — ολόκληρη η μεθοδολογία σε λειτουργία."}],"table":{"title":"ΓΕΝΙΚΟΣ ΠΙΝΑΚΑΣ: είδος κύριας → εκφορά στον πλάγιο","cols":["Κύρια πρόταση ευθέος (έγκλιση)","Είδος","Εκφορά στον πλάγιο λόγο"],"rows":[["οριστική / δυνητική","κρίσεως","ειδική (ὅτι/ὡς) / ειδικό απαρ. / κατηγ. μετοχή"],["προστακτική / προτρ. υποτ. / ευχ. ευκτ. / απαγόρευση","επιθυμίας","τελικό απαρέμφατο (αρν. μή) / τελική / ενδοιαστική"],["ερώτηση μερικής αγνοίας (τίς, ποῦ…)","ερώτηση","πλάγια ερωτηματική (τίς/ὅστις, ποῦ/ὅπου…)"],["ερώτηση ολικής αγνοίας","ερώτηση","πλάγια ερωτηματική με εἰ / εἰ…ἤ"],["επιφωνηματική (ὡς, οἷος, ὅσος)","επιφωνηματική","ειδική (ὅτι/ὡς) ή πλάγια ερωτηματική"]]},"note":"Χρυσός κανόνας ελέγχου: μετά τη μετατροπή, διάβασε ξανά τον πλάγιο λόγο και έλεγξε ένα-ένα: σωστό είδος απαρεμφάτου; σωστή έγκλιση ως προς τον χρόνο εξαρτήσεως; διατηρήθηκε το ἄν; διορθώθηκαν σύνδεσμοι/πρόσωπα/επιρρήματα;"}]);
  T("syn-diptota-rimata", [{"h":"Τι είναι τα δίπτωτα ρήματα — ορισμός και θεμελιώδεις έννοιες","body":"<p>Τα <b>μεταβατικά ρήματα</b> (αυτά που η ενέργειά τους μεταβαίνει σε ένα πρόσωπο ή πράγμα έξω από το υποκείμενο) διακρίνονται, ανάλογα με το πλήθος των αντικειμένων που δέχονται, σε <b>μονόπτωτα</b> και <b>δίπτωτα</b>.</p><p><b>Μονόπτωτα</b> λέγονται τα ρήματα που δέχονται <i>ένα μόνο</i> αντικείμενο (σε γενική, δοτική ή αιτιατική ανάλογα με τη σημασία τους): <i>ἐθήρευον ζῷα</i>, <i>ἐπίστευον τοῖς συμμάχοις</i>, <i>μέμνησο τῶν φίλων</i>.</p><p><b>Δίπτωτα</b> (από το <i>δίς + πτῶσις</i>, «με δύο πτώσεις») λέγονται τα ρήματα που δέχονται <i>δύο</i> αντικείμενα. Τα δύο αυτά αντικείμενα είναι:</p><ul><li><b>α)</b> σε <i>διαφορετική πτώση</i> το καθένα (π.χ. μία αιτιατική και μία δοτική, ή μία αιτιατική και μία γενική, ή μία γενική και μία δοτική), ή</li><li><b>β)</b> στην <i>ίδια πτώση</i> (δύο αιτιατικές), αλλά διαφορετικής σημασίας/ποιότητας (το ένα δηλώνει πρόσωπο και το άλλο πράγμα).</li></ul><p>Το ένα από τα δύο αντικείμενα λέγεται <b>άμεσο</b> και το άλλο <b>έμμεσο</b>. Η διάκριση είναι ουσιώδης για τη σωστή σύνταξη:</p><h3>Κανόνας αναγνώρισης άμεσου / έμμεσου αντικειμένου</h3><ul><li>Όταν τα δύο αντικείμενα είναι σε <b>διαφορετική πτώση</b>, <b>άμεσο</b> είναι αυτό που βρίσκεται σε <i>αιτιατική</i> και <b>έμμεσο</b> το άλλο (σε γενική ή δοτική ή εμπρόθετο). Π.χ. <i>Κῦρος ἔδωκε Κλεάρχῳ χρυσίον</i>: άμεσο <i>χρυσίον</i> (αιτ.), έμμεσο <i>Κλεάρχῳ</i> (δοτ.).</li><li>Όταν και τα δύο αντικείμενα είναι σε <b>αιτιατική</b>, <b>άμεσο</b> είναι αυτό που δηλώνει το <i>πρόσωπο</i> και <b>έμμεσο</b> αυτό που δηλώνει το <i>πράγμα</i>. Π.χ. <i>ἐδίδασκον τούς παῖδας τήν μουσικήν</i>: άμεσο <i>τούς παῖδας</i> (πρόσωπο), έμμεσο <i>τήν μουσικήν</i> (πράγμα).</li><li>Στα ρήματα γενικής+δοτικής, <b>άμεσο</b> θεωρείται το αντικείμενο σε <i>γενική</i> και <b>έμμεσο</b> αυτό σε <i>δοτική</i> (π.χ. <i>μεταδίδωμί σοι τῆς ἀρχῆς</i>).</li></ul><p>Στις επόμενες ενότητες παρουσιάζονται αναλυτικά οι τέσσερις βασικοί τύποι σύνταξης, με πλήρεις ομάδες ρημάτων και παραδείγματα, καθώς και η κρίσιμη διάκριση ανάμεσα στο <i>δεύτερο αντικείμενο</i> και στο <i>κατηγορούμενο του αντικειμένου</i>.</p>","examples":[{"gr":"Κῦρος ἔδωκε Κλεάρχῳ χρυσίον.","an":"Δίπτωτο (αιτ.+δοτ.): υποκ. <i>Κῦρος</i>, ρ. <i>ἔδωκε</i>, άμεσο αντ. <i>χρυσίον</i> (αιτ. — πράγμα), έμμεσο αντ. <i>Κλεάρχῳ</i> (δοτ. — πρόσωπο). «Ο Κύρος έδωσε στον Κλέαρχο χρυσάφι.»"},{"gr":"ἐδίδασκον τούς παῖδας τήν μουσικήν.","an":"Δίπτωτο με δύο αιτιατικές: άμεσο <i>τούς παῖδας</i> (πρόσωπο), έμμεσο <i>τήν μουσικήν</i> (πράγμα). «Δίδασκαν στα παιδιά τη μουσική.»"},{"gr":"ἡ μοῖρα ποιήσει κακόν σοι.","an":"Δίπτωτο (αιτ.+δοτ.): άμεσο <i>κακόν</i> (αιτ.), έμμεσο <i>σοι</i> (δοτ.). «Η μοίρα θα σου προξενήσει κακό.»"},{"gr":"τοῦτόν σοι ἔπεμψε.","an":"Δίπτωτο (αιτ.+δοτ.): άμεσο <i>τοῦτον</i> (αιτ.), έμμεσο <i>σοι</i> (δοτ. προσώπου), ρ. αποστολής <i>ἔπεμψε</i>. «Αυτόν τον έστειλε σε σένα.» (τύπου· πβ. τα μηνύματα δωροδοσίας του Κύρου, Ξεν. Ἀνάβ. 1.9.25-26)"},{"gr":"Κῦρον ᾔτουν πλοῖα.","an":"Ξεν. Ἀνάβ. 1.3.14 (τύπου) — δίπτωτο με δύο αιτιατικές: άμεσο <i>Κῦρον</i> (πρόσωπο), έμμεσο <i>πλοῖα</i> (πράγμα). Δείχνει πως σε δύο αιτιατικές άμεσο είναι το πρόσωπο. «Ζητούσαν από τον Κύρο πλοία.»"}]},{"h":"Τύπος Α: ρήματα με αιτιατική + δοτική","body":"<p>Είναι ο πιο συνηθισμένος και «κανονικός» τύπος δίπτωτης σύνταξης. Το ρήμα δέχεται ένα <b>άμεσο αντικείμενο σε αιτιατική</b> (συνήθως το πράγμα/η ενέργεια) και ένα <b>έμμεσο αντικείμενο σε δοτική</b> (συνήθως το πρόσωπο που ωφελείται, βλάπτεται ή προς το οποίο κατευθύνεται η ενέργεια — δοτική προσωπική / έμμεσο αντικείμενο).</p><h3>Σημασιολογικές ομάδες ρημάτων</h3><ul><li><b>Λέγω / αναγγέλλω / αποκρίνομαι:</b> λέγω, εἶπον, φράζω, ἀγγέλλω, ἀπαγγέλλω, δηλῶ, μηνύω, ἀποκρίνομαι, ὁμολογῶ.</li><li><b>Δίνω / προσφέρω / στέλνω:</b> δίδωμι, παρέχω, χαρίζομαι, νέμω, πέμπω, ἀποστέλλω, φέρω, προσφέρω.</li><li><b>Δείχνω / υπόσχομαι:</b> δείκνυμι, ἐπιδείκνυμι, ὑπισχνοῦμαι, ἐπαγγέλλομαι.</li><li><b>Συμβουλεύω / παραγγέλλω:</b> παραινῶ, συμβουλεύω, παρακελεύομαι, ἐπιστέλλω, προστάττω.</li><li><b>Αντιτάσσω / εξισώνω / αναμειγνύω:</b> ἀντιτάττω, ἐξισῶ, ὁμοιῶ, κεράννυμι, συναλλάσσω, μείγνυμι.</li><li><b>Προξενώ (κακό/καλό):</b> ποιῶ (κακόν/ἀγαθόν τινι), ἐργάζομαι (κακά τινι).</li></ul><p>Πρόκειται κατ' ουσίαν για ρήματα <i>δόσεως</i>, <i>επικοινωνίας</i> και <i>συμβουλής/εντολής</i> — δηλαδή ρήματα όπου εννοιολογικά κάποιος «μεταβιβάζει» κάτι σε κάποιον.</p>","examples":[{"gr":"λέγω τήν ἀλήθειαν τοῖς δικασταῖς.","an":"Άμεσο <i>τήν ἀλήθειαν</i> (αιτ.), έμμεσο <i>τοῖς δικασταῖς</i> (δοτ. προσώπου). «Λέω την αλήθεια στους δικαστές.»"},{"gr":"ὁ θεός δίδωσι τοῖς ἀνθρώποις τά ἀγαθά.","an":"Άμεσο <i>τά ἀγαθά</i>, έμμεσο <i>τοῖς ἀνθρώποις</i>. Τυπικό ρήμα δόσεως. «Ο θεός δίνει στους ανθρώπους τα αγαθά.»"},{"gr":"Σωκράτης ἀπεκρίνατο τῷ Μελήτῳ ταῦτα.","an":"Άμεσο <i>ταῦτα</i> (αιτ.), έμμεσο <i>τῷ Μελήτῳ</i> (δοτ.). «Ο Σωκράτης απάντησε αυτά στον Μέλητο.»"},{"gr":"συμβουλεύω σοι ταῦτα πράττειν.","an":"Έμμεσο <i>σοι</i> (δοτ.), άμεσο το <i>ταῦτα πράττειν</i> (απαρ. ως αντικ.). Ρήμα συμβουλής. «Σε συμβουλεύω να τα πράττεις αυτά.»"},{"gr":"παρέχω τοῖς στρατιώταις σῖτον.","an":"Άμεσο <i>σῖτον</i> (αιτ.), έμμεσο <i>τοῖς στρατιώταις</i> (δοτ.). «Παρέχω στους στρατιώτες τροφή.»"},{"gr":"Κῦρος δίδωσιν αὐτῷ μυρίους δαρεικούς.","an":"Ξεν. Ἀνάβ. (τύπου, ρ. δόσεως) — άμεσο <i>μυρίους δαρεικούς</i> (αιτ. πράγματος), έμμεσο <i>αὐτῷ</i> (δοτ. προσώπου). «Ο Κύρος του δίνει δέκα χιλιάδες δαρεικούς.»"},{"gr":"ὑπισχνοῦμαι ὑμῖν χάριν.","an":"Ρ. υπόσχεσης (αιτ.+δοτ.): άμεσο <i>χάριν</i> (αιτ.), έμμεσο <i>ὑμῖν</i> (δοτ. προσώπου). «Σας υπόσχομαι ευγνωμοσύνη.»"}]},{"h":"Τύπος Β: ρήματα με αιτιατική + γενική","body":"<p>Στα ρήματα αυτά το <b>άμεσο αντικείμενο</b> είναι σε <b>αιτιατική</b> και το <b>έμμεσο</b> σε <b>γενική</b>. Η γενική εδώ δεν είναι τυχαία: εκφράζει συγκεκριμένες σημασιολογικές σχέσεις (χωρισμό/στέρηση, πλήρωση, αξία/τίμημα, αιτία ψυχικού πάθους κ.ά.), κληρονομημένες από τις βασικές χρήσεις της γενικής πτώσης.</p><h3>Σημασιολογικές ομάδες (με τη χροιά της γενικής)</h3><ul><li><b>Γενική του χωρισμού / στέρησης</b> — ρήματα που σημαίνουν <i>στερώ, απαλλάσσω, εμποδίζω, χωρίζω, παύω</i>: ἀποστερῶ, στερίσκω, ἀπαλλάσσω, ἀπολύω, παύω, ἐλευθερῶ, εἴργω, κωλύω, ἀφαιροῦμαι. <i>(π.χ. ἀποστερῶ τινα χρημάτων.)</i></li><li><b>Γενική της πλήρωσης</b> — ρήματα που σημαίνουν <i>γεμίζω, αδειάζω</i> (το περιεχόμενο μπαίνει σε γενική): πληρῶ, γεμίζω, μεστῶ, πίμπλημι· και αντίθετα κενῶ. <i>(π.χ. ἐγέμισε τήν ναῦν ξύλων.)</i></li><li><b>Γενική της αξίας / τιμήματος</b> — ρήματα <i>αγοράζω, πωλώ, ανταλλάσσω, εκτιμώ</i>: ἀγοράζω, πωλῶ, ὠνοῦμαι, ἀνταλλάσσω, ἀλλάττομαι, τιμῶμαι (= προτείνω ποινή/τίμημα). <i>(π.χ. ἐπριάμην τόν ἵππον πολλοῦ ἀργυρίου.)</i></li><li><b>Γενική της αιτίας — ρήματα ψυχικού πάθους / αξιολόγησης:</b> θαυμάζω, ἄγαμαι, ζηλῶ, μακαρίζω, οἰκτίρω, ἐπαινῶ, εὐδαιμονίζω (θαυμάζω/μακαρίζω/οικτίρω κάποιον <i>για</i> κάτι). <i>(π.χ. ἐθαύμαζον αὐτούς τῆς τόλμης.)</i></li><li><b>Δικανικά ρήματα (κατηγορίας / δίωξης):</b> αἰτιῶμαι, γράφομαι, διώκω, κρίνω, τιμωροῦμαι, εἰσάγω (κατηγορώ κάποιον <i>για</i> ένα αδίκημα — γενική του εγκλήματος). <i>(π.χ. γράφομαί τινα κλοπῆς.)</i></li><li><b>Ρήματα αντίληψης (ακοής/μάθησης) με γενική προσώπου:</b> ἀκούω, πυνθάνομαι, μανθάνω (ακούω <i>κάτι</i> [αιτ.] <i>από κάποιον</i> [γεν. προσώπου]). <i>(π.χ. ἀκούω τι τοῦ ἀγγέλου.)</i></li></ul><p>Η αναγνώριση της <i>χροιάς</i> της γενικής (στέρησης, πλήρωσης, αξίας, αιτίας, εγκλήματος) είναι ζητούμενο της εξέτασης· γι' αυτό μάθε τις ομάδες μαζί με τη σημασία τους.</p>","examples":[{"gr":"ἀπεστέρησαν τούς πολίτας τῆς ἐλευθερίας.","an":"Άμεσο <i>τούς πολίτας</i> (αιτ.), έμμεσο <i>τῆς ἐλευθερίας</i> (γεν. στέρησης/χωρισμού). «Στέρησαν από τους πολίτες την ελευθερία.»"},{"gr":"ἐγέμισε τήν ναῦν ξύλων.","an":"Άμεσο <i>τήν ναῦν</i> (αιτ.), έμμεσο <i>ξύλων</i> (γεν. πλήρωσης — το περιεχόμενο). «Γέμισε το πλοίο με ξύλα.»"},{"gr":"ἐθαύμαζον αὐτούς τῆς τόλμης.","an":"Άμεσο <i>αὐτούς</i> (αιτ. προσώπου), έμμεσο <i>τῆς τόλμης</i> (γεν. της αιτίας του πάθους). «Τους θαύμαζαν για την τόλμη τους.»"},{"gr":"Μέλητος ἐγράψατο Σωκράτη ἀσεβείας.","an":"Δικανικό: άμεσο <i>Σωκράτη</i> (αιτ. προσώπου), έμμεσο <i>ἀσεβείας</i> (γεν. του εγκλήματος). «Ο Μέλητος κατηγόρησε τον Σωκράτη για ασέβεια.»"},{"gr":"ἤκουσα τοῦ ἀγγέλου τά γεγενημένα.","an":"Άμεσο <i>τά γεγενημένα</i> (αιτ. πράγματος), έμμεσο <i>τοῦ ἀγγέλου</i> (γεν. προσώπου/πηγής). «Άκουσα από τον αγγελιοφόρο τα όσα είχαν γίνει.»"},{"gr":"τά ἡμέτερ' ἡμᾶς ἀποστερεῖ.","an":"Δημ. Α΄ Φιλιππ. 50 — άμεσο <i>ἡμᾶς</i> (αιτ. προσώπου), έμμεσο <i>τά ἡμέτερα</i> (εδώ ως δεύτερη αιτιατική του πράγματος· εναλλάσσεται με γεν. στέρησης, π.χ. <i>ἀποστερεῖ ἡμᾶς τῶν ἡμετέρων</i>). «Μας στερεί τα δικά μας.»"},{"gr":"ἐπριάμην τόν ἵππον πολλοῦ ἀργυρίου.","an":"Γεν. της αξίας/τιμήματος: άμεσο <i>τόν ἵππον</i> (αιτ.), έμμεσο <i>πολλοῦ ἀργυρίου</i> (γεν. τιμήματος). «Αγόρασα το άλογο με πολλά χρήματα.»"}]},{"h":"Τύπος Γ: ρήματα με δύο αιτιατικές (προσώπου + πράγματος)","body":"<p>Ορισμένα ρήματα δέχονται δύο αντικείμενα στην <b>ίδια πτώση, την αιτιατική</b>: το ένα δηλώνει το <b>πρόσωπο</b> και το άλλο το <b>πράγμα</b>. Σύμφωνα με τον κανόνα, <b>άμεσο</b> είναι η αιτιατική του <i>προσώπου</i> και <b>έμμεσο</b> η αιτιατική του <i>πράγματος</i>.</p><p>Προσοχή: εδώ <i>και τα δύο</i> είναι πραγματικά αντικείμενα (δεύτερο αντικείμενο), σε αντίθεση με τον Τύπο Δ (κατηγορούμενο του αντικειμένου), όπου το δεύτερο όνομα <i>δεν</i> είναι αντικείμενο αλλά αποδίδει ιδιότητα στο πρώτο. Η διάκριση αναλύεται στην επόμενη ενότητα.</p><h3>Σημασιολογικές ομάδες ρημάτων</h3><ul><li><b>Διδάσκω / υπενθυμίζω:</b> διδάσκω, παιδεύω, ἀναμιμνῄσκω, ὑπομιμνῄσκω. <i>(διδάσκω τινά τι.)</i></li><li><b>Ζητώ / απαιτώ / εισπράττω:</b> αἰτῶ, ἀπαιτῶ, εἰσπράττω, πράττω (= εισπράττω). <i>(αἰτῶ σε ἄρτον.)</i></li><li><b>Ρωτώ:</b> ἐρωτῶ, ἐπερωτῶ, ἀνερωτῶ. <i>(ἐρωτῶ σε τοῦτο.)</i></li><li><b>Στερώ / κρύβω:</b> ἀποστερῶ, ἀφαιροῦμαι, κρύπτω, ἀποκρύπτομαι. <i>(κρύπτω τινά τι = κρύβω από κάποιον κάτι.)</i></li><li><b>Ντύνω / γδύνω / αλείφω:</b> ἐνδύω, ἐκδύω, ἀμφιέννυμι, περιβάλλω. <i>(ἐνδύω τόν παῖδα χιτῶνα.)</i></li><li><b>Κάνω καλό/κακό — δράση επί προσώπου:</b> ποιῶ / δρῶ / ἐργάζομαι (ἀγαθά ἤ κακά τινα): <i>ἀγαθά ποιῶ τήν πόλιν</i> = ευεργετώ την πόλη.</li></ul><p>Εννοιολογικά είναι κι αυτά ρήματα «μεταβίβασης»: κάποιος διδάσκει/ζητά/αφαιρεί <i>κάτι</i> (πράγμα) <i>σε/από κάποιον</i> (πρόσωπο).</p>","examples":[{"gr":"ἐδίδασκε τούς παῖδας τήν ἀρετήν.","an":"Άμεσο <i>τούς παῖδας</i> (αιτ. προσώπου), έμμεσο <i>τήν ἀρετήν</i> (αιτ. πράγματος). «Δίδασκε στα παιδιά την αρετή.»"},{"gr":"Κῦρον ᾔτουν πλοῖα.","an":"Παράδειγμα τύπου Smyth (πβ. Ξεν. Ἀνάβ. 1.3.14): άμεσο <i>Κῦρον</i> (αιτ. προσώπου), έμμεσο <i>πλοῖα</i> (αιτ. πράγματος). «Ζητούσαν από τον Κύρο πλοία.»"},{"gr":"Διογείτων ἔκρυπτε τήν θυγατέρα τόν θάνατον.","an":"Άμεσο <i>τήν θυγατέρα</i> (πρόσωπο), έμμεσο <i>τόν θάνατον</i> (πράγμα). «Ο Διογείτων έκρυβε από την κόρη του τον θάνατο.»"},{"gr":"ἀνέμνησα αὐτούς τούς προγόνων κινδύνους.","an":"Άμεσο <i>αὐτούς</i> (πρόσωπο), έμμεσο <i>τούς κινδύνους</i> (πράγμα). «Τους θύμισα τους κινδύνους των προγόνων.»"},{"gr":"ἀγαθά πολλά τήν πόλιν ἐποίησεν.","an":"Άμεσο <i>τήν πόλιν</i> (πρόσωπο/φορέας), έμμεσο <i>ἀγαθά πολλά</i> (πράγμα). «Ευεργέτησε πολύ την πόλη.»"},{"gr":"ἀναμνήσω ὑμᾶς καί τούς τῶν προγόνων κινδύνους.","an":"Ξεν. Ἀνάβ. 3.2.11 — ρ. υπενθύμισης με δύο αιτ.: άμεσο <i>ὑμᾶς</i> (πρόσωπο), έμμεσο <i>τούς κινδύνους</i> (πράγμα). «Θα σας θυμίσω και τους κινδύνους των προγόνων.»"},{"gr":"ὁ πόλεμος ἀείμνηστον παιδείαν αὐτούς ἐπαίδευσε.","an":"Αἰσχίν. Κατά Κτησ. 3.148 — ρ. <i>παιδεύω</i> με δύο αιτ.: άμεσο <i>αὐτούς</i> (πρόσωπο), έμμεσο <i>ἀείμνηστον παιδείαν</i> (αιτ. πράγματος, εδώ και σύστοιχη). «Ο πόλεμος τούς δίδαξε αξέχαστο μάθημα.»"}]},{"h":"Τύπος Δ: δύο αιτιατικές — η μία ως κατηγορούμενο του αντικειμένου","body":"<p>Υπάρχει μια ξεχωριστή κατηγορία ρημάτων που συντάσσονται μεν με <b>δύο αιτιατικές</b>, αλλά η δεύτερη αιτιατική <b>δεν είναι δεύτερο αντικείμενο</b>: είναι <b>κατηγορούμενο του αντικειμένου</b>, δηλαδή αποδίδει μια <i>ιδιότητα, χαρακτηρισμό ή αξίωμα</i> στο αντικείμενο. Ανάμεσα στις δύο αιτιατικές υπάρχει σχέση <i>υποκειμένου–κατηγορουμένου</i> (νοητό «εἶναι»): <i>καλοῦσιν αὐτόν βασιλέα</i> = «τον αποκαλούν (ως) βασιλιά», δηλ. «αυτός [είναι] βασιλιάς».</p><h3>Ρήματα που παίρνουν κατηγορούμενο του αντικειμένου</h3><ul><li><b>Κλητικά (ονομάζω/αποκαλώ):</b> καλῶ, ὀνομάζω, λέγω, προσαγορεύω, ἐπονομάζω.</li><li><b>Ρήματα του «κάνω/καθιστώ»:</b> ποιῶ, τίθημι, καθίστημι, ἀποδείκνυμι, ἀποφαίνω, παρέχω (ἑαυτόν).</li><li><b>Εκλογικά / διοριστικά:</b> αἱροῦμαι, ἐκλέγομαι, χειροτονῶ, ἀποδείκνυμι (διορίζω).</li><li><b>Δοξαστικά / νομιστικά:</b> νομίζω, ἡγοῦμαι, κρίνω, ὑπολαμβάνω, οἴομαι, ποιοῦμαι (θεωρώ).</li><li><b>Ρήματα του «έχω / θεωρώ ως»:</b> ἔχω (τινά φίλον), νομίζω/ἄγω (θεούς), λαμβάνω.</li></ul><h3>Πώς ξεχωρίζω το κατηγορούμενο του αντικειμένου από το δεύτερο αντικείμενο</h3><p>Το ζευγάρι κριτηρίων:</p><ul><li><b>Νόημα:</b> Αν ανάμεσα στις δύο αιτιατικές μπορεί να παρεμβληθεί το «ως / σαν / ότι είναι», τότε η δεύτερη είναι <b>κατηγορούμενο</b> (<i>καλῶ αὐτόν [ὡς] φίλον</i>). Αν τα δύο είναι ξεχωριστά πρόσωπα/πράγματα που και τα δύο δέχονται την ενέργεια, είναι <b>δύο αντικείμενα</b> (<i>αἰτῶ σε ἄρτον</i> — το ψωμί δεν «είναι» εσύ).</li><li><b>Πρόσωπο/πράγμα:</b> Στο δεύτερο αντικείμενο, το ένα είναι πρόσωπο και το άλλο πράγμα (διαφορετικής φύσης). Στο κατηγορούμενο, και οι δύο αιτιατικές αναφέρονται στην <i>ίδια</i> οντότητα.</li><li><b>Συμφωνία:</b> Το κατηγορούμενο συχνά συμφωνεί σε γένος/αριθμό με το αντικείμενο (όταν είναι επίθετο): <i>ἐποίησε τούς συμμάχους προθύμους</i>.</li></ul><p>Στην παθητική, το κατηγορούμενο του αντικειμένου μετατρέπεται σε <b>κατηγορούμενο του υποκειμένου</b>: <i>οὗτος βασιλεύς καλεῖται</i> («αυτός αποκαλείται βασιλιάς»).</p>","examples":[{"gr":"καλοῦσιν αὐτούς νομοθέτας.","an":"Αντικείμενο <i>αὐτούς</i> (αιτ.), κατηγ. του αντικειμένου <i>νομοθέτας</i> (αιτ., κλητικό ρ.). «Τους αποκαλούν νομοθέτες.» (αὐτοί = νομοθέται)"},{"gr":"ἐποίησε τούς συμμάχους προθύμους.","an":"Αντικείμενο <i>τούς συμμάχους</i>, κατηγ. του αντικειμένου <i>προθύμους</i> (επίθ. που συμφωνεί). Ρ. «κάνω/καθιστώ». «Έκανε τους συμμάχους πρόθυμους.»"},{"gr":"τοῦτον νομίζω φίλον.","an":"Αντικείμενο <i>τοῦτον</i>, κατηγ. του αντικειμένου <i>φίλον</i> (δοξαστικό ρ.). «Αυτόν τον θεωρώ φίλο.» (νοητό «εἶναι»)"},{"gr":"εἵλοντο αὐτόν στρατηγόν.","an":"Αντικείμενο <i>αὐτόν</i>, κατηγ. του αντικειμένου <i>στρατηγόν</i> (εκλογικό ρ. αἱροῦμαι). «Τον εξέλεξαν στρατηγό.»"},{"gr":"ὁ νόμος βασιλέα τόν ἄρχοντα ἀποδείκνυσιν.","an":"Αντικείμενο <i>τόν ἄρχοντα</i>, κατηγ. του αντικειμένου <i>βασιλέα</i>. «Ο νόμος αναδεικνύει τον άρχοντα βασιλιά.»"},{"gr":"στρατηγόν αὐτόν ἀπέδειξε.","an":"Ξεν. Ἀνάβ. 1.1.2 — διοριστικό ρ. <i>ἀποδείκνυμι</i>: αντικ. <i>αὐτόν</i>, κατηγ. του αντικειμένου <i>στρατηγόν</i> (ίδια οντότητα). «Τον διόρισε στρατηγό.»"},{"gr":"τόν ἄνδρα τόν ἀγαθόν εὐδαίμονα εἶναί φημι.","an":"Πλάτ. Γοργ. 470e (τύπου) — δοξαστικό· <i>τόν ἄνδρα</i> αντικ., <i>εὐδαίμονα</i> κατηγ. (μέσω νοητού/ρητού «εἶναι»). Δείχνει τη σχέση υποκ.–κατηγ. ανάμεσα στις αιτιατικές. «Ισχυρίζομαι ότι ο ενάρετος είναι ευτυχισμένος.»"}]},{"h":"Τύπος Ε: ρήματα με γενική + δοτική (και λοιποί σπανιότεροι συνδυασμοί)","body":"<p>Μικρότερη αλλά υπαρκτή ομάδα δίπτωτων ρημάτων συντάσσεται με <b>γενική + δοτική</b>. Εδώ <b>άμεσο</b> αντικείμενο θεωρείται το αντικείμενο σε <b>γενική</b> και <b>έμμεσο</b> το αντικείμενο σε <b>δοτική</b> (συνήθως δοτική προσώπου).</p><h3>Σημασιολογικές ομάδες</h3><ul><li><b>Μετοχής / κοινωνίας (μερισμού):</b> μετέχω, μεταλαμβάνω, κοινωνῶ, μεταδίδωμι, μέτεστι (απρόσ.). Η γενική δηλώνει το <i>όλον</i> από το οποίο μετέχει κανείς (γενική διαιρετική/του μέρους), η δοτική το πρόσωπο. <i>(μεταδίδωμί σοι τῆς ἀρχῆς.)</i></li><li><b>Παραχώρησης / φθόνου:</b> παραχωρῶ, εἴκω, φθονῶ (φθονώ σε κάποιον για κάτι). <i>(φθονῶ σοι τῆς εὐτυχίας.)</i></li><li><b>Δικανικό «τιμῶ/τιμῶμαι» (πρόταση ποινής):</b> τιμῶ / τιμῶμαι (= ορίζω/προτείνω ποινή): γενική της ποινής + δοτική προσώπου. <i>(τιμῶμαί σοι θανάτου.)</i></li></ul><h3>Άλλοι/μεικτοί συνδυασμοί που πρέπει να γνωρίζεις</h3><ul><li><b>Δοτική + γενική</b> με ρήματα όπως διαλέγομαι, ή ρήματα όπου το ένα αντικείμενο είναι εμπρόθετο.</li><li><b>Εμπρόθετο αντικείμενο</b> αντί απλής πτώσης: πολλά δίπτωτα εκφέρουν το έμμεσο αντικείμενο εμπρόθετα — <i>πρός / εἰς + αιτ.</i> (κατεύθυνση), <i>παρά / ἐκ + γεν.</i> (πηγή/προέλευση), <i>σύν + δοτ.</i> Π.χ. <i>αἰτῶ τι παρά τινος</i> δίπλα στο <i>αἰτῶ τινά τι</i>.</li></ul>","examples":[{"gr":"μεταδίδωμί σοι τῆς ἀρχῆς.","an":"Άμεσο <i>τῆς ἀρχῆς</i> (γεν. — το όλον από το οποίο δίνεται μερίδιο), έμμεσο <i>σοι</i> (δοτ. προσώπου). «Σου δίνω μερίδιο από την εξουσία.»"},{"gr":"μετέχω τοῖς πολίταις τῶν κινδύνων.","an":"Άμεσο <i>τῶν κινδύνων</i> (γεν.), έμμεσο <i>τοῖς πολίταις</i> (δοτ.). «Συμμετέχω μαζί με τους πολίτες στους κινδύνους.»"},{"gr":"φθονῶ σοι τῆς εὐτυχίας.","an":"Άμεσο <i>τῆς εὐτυχίας</i> (γεν. αιτίας), έμμεσο <i>σοι</i> (δοτ. προσώπου). «Σε φθονώ για την ευτυχία σου.»"},{"gr":"τιμῶμαι τῷ φεύγοντι θανάτου.","an":"Δικανικό: άμεσο <i>θανάτου</i> (γεν. της ποινής), έμμεσο <i>τῷ φεύγοντι</i> (δοτ. προσώπου). «Προτείνω για τον κατηγορούμενο την ποινή του θανάτου.»"},{"gr":"ᾔτησα ἀργύριον παρά τῶν φίλων.","an":"Άμεσο <i>ἀργύριον</i> (αιτ.), έμμεσο εμπρόθετο <i>παρά τῶν φίλων</i> (παρά+γεν. πηγής, αντί απλής γενικής/δεύτερης αιτιατικής). «Ζήτησα χρήματα από τους φίλους.»"},{"gr":"μεταδίδωμι τοῖς πένησι τῶν χρημάτων.","an":"Ρ. μερισμού (γεν.+δοτ.): άμεσο <i>τῶν χρημάτων</i> (γεν. διαιρετική — το όλον), έμμεσο <i>τοῖς πένησι</i> (δοτ. προσώπου). «Δίνω στους φτωχούς μερίδιο από τα χρήματα.»"},{"gr":"οὐ μεταδίδοτε ἡμῖν τῆς πολιτείας.","an":"(τύπου ρητορικού) ρ. μερισμού: άμεσο <i>τῆς πολιτείας</i> (γεν.), έμμεσο <i>ἡμῖν</i> (δοτ. προσώπου). «Δεν μας δίνετε μερίδιο στην πολιτεία.»"}]},{"h":"Παγίδες, εναλλακτικές συντάξεις και παθητική μετατροπή","body":"<p>Η ενότητα αυτή συγκεντρώνει τα συχνότερα λάθη και τις «κινητές» περιπτώσεις, ώστε η ανάλυσή σου να είναι ασφαλής σε κάθε κείμενο.</p><h3>1. Το ίδιο ρήμα σε δύο συντάξεις</h3><p>Πολλά ρήματα μετακινούνται ανάμεσα στους τύπους ανάλογα με το νόημα:</p><ul><li><b>ποιῶ:</b> <i>ἀγαθά ποιῶ τινα</i> (δύο αντικ.) ≠ <i>στρατηγόν ποιῶ τινα</i> (κατηγ. αντικ.).</li><li><b>λέγω/καλῶ:</b> <i>λέγω τι τινι</i> (αιτ.+δοτ.) ≠ <i>καλῶ τινα φίλον</i> (κατηγ. αντικ.).</li><li><b>ἀποστερῶ:</b> <i>ἀποστερῶ τινα χρημάτων</i> (αιτ.+γεν.) ≈ <i>ἀποστερῶ τινά τι</i> (δύο αιτ.) — και οι δύο σωστές.</li></ul><h3>2. Έμμεσο αντικείμενο vs δοτική προσωπική / γενική κτητική</h3><p>Όχι κάθε δοτική ή γενική δίπλα σε μεταβατικό ρήμα είναι έμμεσο αντικείμενο. Η <i>δοτική χαριστική/αντιχαριστική</i> ή η <i>γενική κτητική</i> μπορεί να είναι απλός προσδιορισμός: στο <i>λύω τῷ φίλῳ τόν ἵππον</i>, το <i>τῷ φίλῳ</i> μπορεί να είναι έμμεσο αντικ. (λύνω για τον φίλο) ή δοτική χαριστική. Κρίνε από το ρήμα και το συγκείμενο.</p><h3>3. Παθητική σύνταξη των δίπτωτων</h3><ul><li><b>Αιτ.+δοτ.</b>: υποκείμενο γίνεται το άμεσο (αιτ.), η δοτική μένει: <i>δῶρον ἐδόθη τῷ παιδί</i>.</li><li><b>Δύο αιτ. (πρόσ.+πράγμα)</b>: υποκείμενο γίνεται το πρόσωπο, το πράγμα μένει σε αιτιατική: <i>οἱ παῖδες ἐδιδάχθησαν τήν μουσικήν</i>.</li><li><b>Κατηγ. αντικ.</b>: γίνεται κατηγ. υποκειμένου: <i>ᾑρέθη στρατηγός</i>.</li><li><b>Αιτ.+γεν. στέρησης</b>: υποκ. το πρόσωπο, η γενική μένει: <i>ἀπεστερήθην τῶν χρημάτων</i>.</li></ul><h3>4. Σύστοιχο αντικείμενο και δίπτωτα</h3><p>Όταν ένα δίπτωτο συνοδεύεται και από σύστοιχο αντικείμενο, αυτό μετριέται ως ένα από τα αντικείμενα: <i>πολλά ἀδικήματα ἀδικεῖ τήν πόλιν</i> (σύστοιχο <i>ἀδικήματα</i> + αντικ. <i>τήν πόλιν</i>).</p>","examples":[{"gr":"δῶρα ἐδόθη τοῖς νικήσασιν.","an":"Παθητική του αιτ.+δοτ.: υποκ. <i>δῶρα</i> (πρώην άμεσο), δοτ. <i>τοῖς νικήσασιν</i> μένει. «Δόθηκαν δώρα στους νικητές.»"},{"gr":"οἱ νέοι ἐπαιδεύθησαν τά προσήκοντα.","an":"Παθητική των δύο αιτιατικών: υποκ. το πρόσωπο <i>οἱ νέοι</i>, αιτ. πράγματος <i>τά προσήκοντα</i> διατηρείται. «Οι νέοι διδάχθηκαν τα πρέποντα.»"},{"gr":"Περικλῆς ᾑρέθη στρατηγός.","an":"Παθητική του κατηγ. αντικειμένου: <i>στρατηγός</i> γίνεται κατηγ. του υποκειμένου <i>Περικλῆς</i>. «Ο Περικλής εκλέχθηκε στρατηγός.»"},{"gr":"ἀπεστερήθησαν τῆς πατρίδος.","an":"Παθητική του αιτ.+γεν.: υποκ. το πρόσωπο, γεν. στέρησης <i>τῆς πατρίδος</i> μένει. «Στερήθηκαν την πατρίδα τους.»"},{"gr":"ταῦτα ἐδιδάχθην ὑπό τοῦ πατρός.","an":"Παθητική των δύο αιτ.: υποκ. το πρώην πρόσωπο (εγώ), η αιτ. πράγματος <i>ταῦτα</i> επιζεί, ποιητ. αίτιο <i>ὑπό τοῦ πατρός</i>. Κλασική «επιζώσα» αιτιατική. «Αυτά τα διδάχθηκα από τον πατέρα μου.»"},{"gr":"οὗτος ὑπό πάντων βασιλεύς καλεῖται.","an":"Παθητική του κατηγ. αντικειμένου: <i>βασιλεύς</i> γίνεται κατηγ. του υποκειμένου <i>οὗτος</i>. «Αυτός αποκαλείται από όλους βασιλιάς.»"}]},{"h":"Συνοπτικός πίνακας όλων των δίπτωτων — γρήγορη αναφορά","body":"<p>Ο πίνακας που ακολουθεί συγκεντρώνει όλους τους τύπους δίπτωτης σύνταξης με τις αντίστοιχες ομάδες ρημάτων, ώστε να λειτουργεί ως φύλλο γρήγορης αναφοράς για επανάληψη. Συνδύασέ τον με τους αναλυτικούς πίνακες των προηγούμενων ενοτήτων.</p><h3>Μεθοδολογικό βήμα-βήμα</h3><ol><li><b>Είναι μεταβατικό;</b> Αν όχι, δεν έχει αντικείμενο.</li><li><b>Πόσα αντικείμενα;</b> Ένα → μονόπτωτο· δύο → δίπτωτο.</li><li><b>Ποιες πτώσεις;</b> Αναγνώρισε τον συνδυασμό (αιτ.+δοτ. / αιτ.+γεν. / δύο αιτ. / γεν.+δοτ.).</li><li><b>Άμεσο / έμμεσο;</b> Εφάρμοσε τον κανόνα του Τύπου.</li><li><b>Δεύτερο αντικείμενο ή κατηγορούμενο;</b> (μόνο για δύο αιτιατικές) — τεστ του «εἶναι/ὡς».</li><li><b>Είδος γενικής/δοτικής;</b> (στέρησης, πλήρωσης, αξίας, αιτίας, μερισμού, προσώπου).</li></ol><p>Με αυτό το πλέγμα κανόνων μπορείς να αναλύσεις με βεβαιότητα οποιοδήποτε δίπτωτο ρήμα συναντήσεις στα αρχαία κείμενα — από τον Ξενοφώντα και τον Θουκυδίδη ως τους ρήτορες.</p>","examples":[{"gr":"ὑπέσχετο τοῖς στρατιώταις μισθόν.","an":"Αιτ.+δοτ. (ρ. υπόσχεσης): άμεσο <i>μισθόν</i>, έμμεσο <i>τοῖς στρατιώταις</i>. «Υποσχέθηκε μισθό στους στρατιώτες.»"},{"gr":"ἀφείλοντο τούς συμμάχους τήν αὐτονομίαν.","an":"Δύο αιτ. (ρ. αφαίρεσης): άμεσο <i>τούς συμμάχους</i> (πρόσωπο), έμμεσο <i>τήν αὐτονομίαν</i> (πράγμα). «Αφαίρεσαν από τους συμμάχους την αυτονομία.»"},{"gr":"ἡγοῦντο τόν Κῦρον βασιλέα.","an":"Κατηγ. αντικ. (δοξαστικό): αντικ. <i>τόν Κῦρον</i>, κατηγ. <i>βασιλέα</i>. «Θεωρούσαν τον Κύρο βασιλιά.»"},{"gr":"ἀπεστέρησαν αὐτόν τῶν χρημάτων.","an":"Αιτ.+γεν. στέρησης: άμεσο <i>αὐτόν</i> (αιτ.), έμμεσο <i>τῶν χρημάτων</i> (γεν.). Συνοψίζει τον Τύπο Β. «Τον στέρησαν από τα χρήματά του.»"},{"gr":"μετέδωκε τοῖς συμμάχοις τῆς νίκης.","an":"Γεν.+δοτ. μερισμού (Τύπος Ε): άμεσο <i>τῆς νίκης</i> (γεν. του όλου), έμμεσο <i>τοῖς συμμάχοις</i> (δοτ. προσώπου). «Έδωσε στους συμμάχους μερίδιο από τη νίκη.»"}]}]);
  T("syn-systoicho-antikeimeno", [{"h":"Τι είναι το σύστοιχο αντικείμενο","body":"<p>Το <b>σύστοιχο</b> (ή <b>εσωτερικό</b>, λατ. <i>obiectum internum</i>) αντικείμενο είναι ένα ιδιότυπο είδος αντικειμένου που δεν δηλώνει —όπως το κανονικό αντικείμενο— ένα <i>εξωτερικό</i> πρόσωπο ή πράγμα στο οποίο μεταβαίνει η ενέργεια του ρήματος, αλλά <b>επαναλαμβάνει και προσδιορίζει την ίδια την έννοια του ρήματος</b>. Με άλλα λόγια, το σύστοιχο αντικείμενο δεν προσθέτει κάτι έξω από το ρήμα· εκφράζει το <i>περιεχόμενο</i> της ίδιας της ρηματικής ενέργειας, γι' αυτό και ονομάζεται «εσωτερικό».</p><p>Ονομάζεται <b>σύστοιχο</b> ακριβώς επειδή «στοιχεί» (αντιστοιχεί, συμβαδίζει) με το ρήμα ως προς τη σημασία. Η σχέση αυτή μπορεί να είναι δύο ειδών:</p><ul><li><b>ομόρριζο</b> κατά την προέλευση: το αντικείμενο παράγεται από την <b>ίδια ρίζα</b> με το ρήμα (π.χ. <i>νοσῶ νόσον</i>, <i>μάχομαι μάχην</i>, <i>βουλεύω βουλήν</i>)·</li><li><b>συγγενικό</b> κατά τη σημασία: το αντικείμενο δεν είναι ομόρριζο, αλλά έχει <b>συγγενική / συνώνυμη σημασία</b> με το ρήμα, ώστε ουσιαστικά να επαναλαμβάνει την έννοιά του (π.χ. <i>νοσῶ ἀσθένειαν</i>, <i>καθεύδω ὕπνον</i>, <i>θύω θυσίαν</i>).</li></ul><p>Και στις δύο περιπτώσεις ο πυρήνας είναι ο ίδιος: μεταξύ ρήματος και αντικειμένου υπάρχει <b>ετυμολογική ή σημασιολογική ταυτότητα</b>. Το σύστοιχο αντικείμενο τίθεται πάντοτε σε <b>πτώση αιτιατική</b>, όπως και το κανονικό αντικείμενο των μεταβατικών ρημάτων (βλ. αναλυτικά παρακάτω).</p><p>Σπουδαίο χαρακτηριστικό: το σύστοιχο αντικείμενο, όταν στέκεται <i>γυμνό</i> (χωρίς προσδιορισμό), είναι σημασιολογικά σχεδόν <b>περιττό</b> — δεν προσθέτει νέα πληροφορία, αφού απλώς επαναλαμβάνει το ρήμα. Πραγματική αξία αποκτά όταν συνοδεύεται από <b>επιθετικό προσδιορισμό</b> (π.χ. <i>βίον εὐδαίμονα ζῶ</i>), ο οποίος και φέρει το ουσιαστικό νόημα της πρότασης. Στο φαινόμενο αυτό αφιερώνεται χωριστή ενότητα.</p>","examples":[{"gr":"Οὗτοι ἐθήρευον <b>θῆρας</b>.","an":"Σύστοιχο: <i>θῆρας</i> (ομόρριζο του <i>θηρεύω</i>). Κανονικά «θηρεύω θηρία» = επαναλαμβάνω την έννοια του ρήματος. Μτφρ.: «Αυτοί κυνηγούσαν θηρία.» (τύπου, ομόρριζο σύστοιχο)"},{"gr":"Σωκράτης <b>θυσίας</b> ἔθυε.","an":"Σύστοιχο: <i>θυσίας</i> (ομόρριζο του <i>θύω</i>). Δεν δηλώνει εξωτερικό αντικείμενο αλλά το ίδιο το περιεχόμενο της πράξης «θύω». Μτφρ.: «Ο Σωκράτης πρόσφερε θυσίες.» (τύπου)"},{"gr":"Νοσῶ <b>ἀσθένειαν</b>.","an":"Σύστοιχο συγγενικό κατά σημασία: το <i>ἀσθένεια</i> δεν είναι ομόρριζο του <i>νοσῶ</i>, αλλά συνώνυμο. Μτφρ.: «Πάσχω από αρρώστια / αρρωσταίνω.» (τύπου)"},{"gr":"Καθεύδω βαθύν <b>ὕπνον</b>.","an":"Σύστοιχο συγγενικό: <i>ὕπνον</i> (συνώνυμο του <i>καθεύδω</i>), με επιθετικό προσδ. <i>βαθύν</i>. Μτφρ.: «Κοιμάμαι βαθύ ύπνο.» (τύπου)"},{"gr":"Πολλήν <b>φλυαρίαν</b> φλυαροῦντα.","an":"Πλάτ. Ἀπολ. 19c — ομόρριζο σύστοιχο <i>φλυαρίαν</i> ← <i>φλυαρῶ</i>, με επιθ. προσδ. <i>πολλήν</i>. Μτφρ.: «(εμένα) που λέω πολλές ανοησίες.»"},{"gr":"Τήν ἐν Σαλαμῖνι <b>ναυμαχίαν</b> ναυμαχήσαντες.","an":"Δημοσθ. 59.97 — ομόρριζο σύστοιχο <i>ναυμαχίαν</i> ← <i>ναυμαχῶ</i>. Μτφρ.: «αφού έδωσαν τη ναυμαχία στη Σαλαμίνα.»"}]},{"h":"Οι δύο κατηγορίες: ομόρριζο και συγγενικό κατά σημασία","body":"<p>Όλη η θεωρία του σύστοιχου αντικειμένου οργανώνεται γύρω από δύο βασικές κατηγορίες, που αντιστοιχούν στους δύο τρόπους με τους οποίους ένα αντικείμενο μπορεί να «στοιχεί» με το ρήμα.</p><h3>1. Ομόρριζο σύστοιχο αντικείμενο</h3><p>Ρήμα και αντικείμενο έχουν την <b>ίδια ρίζα / θέμα</b>. Πρόκειται για τη «γνήσια» μορφή του φαινομένου, όπου η ετυμολογική συγγένεια είναι ολοφάνερη: <i>βουλεύω βουλήν, μάχομαι μάχην, πομπεύω πομπήν, κινδυνεύω κίνδυνον, νικῶ νίκην, ἁμαρτάνω ἁμαρτίαν</i>. Το ουσιαστικό είναι συνήθως <b>παράγωγο της ίδιας ρίζας</b> με το ρήμα (ρηματικό ουσιαστικό σε -ή, -σις, -μα, -ος κ.λπ.).</p><h3>2. Συγγενικό κατά σημασία σύστοιχο αντικείμενο</h3><p>Ρήμα και αντικείμενο <b>δεν έχουν κοινή ρίζα</b>, αλλά το αντικείμενο είναι <b>συνώνυμο ή σημασιολογικά συγγενές</b> με το ρήμα, ώστε να επαναλαμβάνει ισοδύναμα την έννοιά του: <i>νοσῶ ἀσθένειαν, καθεύδω ὕπνον, νικῶ μάχην, θηρῶ ἄγραν</i> (αλλά συχνά και ομόρριζα παράλληλα). Εδώ η σχέση δεν φαίνεται στη μορφή της λέξης αλλά στο νόημα.</p><p>Και οι δύο κατηγορίες λειτουργούν συντακτικά με τον ίδιο τρόπο: τίθενται σε <b>αιτιατική</b> και αναγνωρίζονται ως <b>σύστοιχο αντικείμενο</b> του ρήματος.</p>","examples":[{"gr":"Μάχην ἐμαχέσαντο καρτεράν.","an":"Ομόρριζο: <i>μάχην</i> ← <i>μάχομαι</i>. Με επιθ. προσδ. <i>καρτεράν</i> («σφοδρή»). Μτφρ.: «Έδωσαν σφοδρή μάχη.» (τύπου)"},{"gr":"Νίκην ἐνίκησε καλλίστην.","an":"Ομόρριζο: <i>νίκην</i> ← <i>νικῶ</i>, με επιθ. προσδ. <i>καλλίστην</i>. Μτφρ.: «Κέρδισε λαμπρότατη νίκη.» (τύπου)"},{"gr":"Ὀλύμπια <b>νικᾶν</b>.","an":"Συγγενικό/εξειδικευτικό σύστοιχο (Smyth): <i>Ὀλύμπια</i> = τους Ολυμπιακούς αγώνες. Μτφρ.: «να νικήσει στα Ολύμπια / Ολυμπιακή νίκη.»"},{"gr":"Ἀσθένειαν νοσεῖ χαλεπήν.","an":"Συγγενικό κατά σημασία: <i>ἀσθένεια</i> συνώνυμο του <i>νοσῶ</i>· επιθ. προσδ. <i>χαλεπήν</i>. Μτφρ.: «Πάσχει από βαριά αρρώστια.» (τύπου)"},{"gr":"Ἥδιστον ὕπνον <b>καθεύδει</b>.","an":"Συγγενικό: <i>ὕπνον</i> συνώνυμο του <i>καθεύδω</i>· επιθ. προσδ. <i>ἥδιστον</i>. Μτφρ.: «Κοιμάται γλυκύτατο ύπνο.» (τύπου)"},{"gr":"Τόν ἱερόν καλούμενον <b>πόλεμον</b> ἐστράτευσαν.","an":"Θουκ. 1.112 — συγγενικό κατά σημασία: <i>πόλεμον</i> σε αιτ. δίπλα στο <i>στρατεύω</i> (διαφορετική ρίζα, συγγενική σημασία), με προσδ. <i>ἱερόν</i>. Μτφρ.: «διεξήγαγαν τον λεγόμενο Ιερό Πόλεμο.»"},{"gr":"Ἐξῆλθον ἄλλας <b>ἐξόδους</b>.","an":"Ξεν. Ἑλλ. 1.2.17 — ομόρριζο σύστοιχο σε ρήμα κίνησης: <i>ἐξόδους</i> («εκστρατείες») ← <i>ἐξέρχομαι</i>, με προσδ. <i>ἄλλας</i>. Μτφρ.: «εξήλθαν σε άλλες εκστρατείες.»"}],"table":{"title":"Συχνά σύστοιχα αντικείμενα (ρήμα → σύστοιχο σε αιτιατική)","cols":["Ρήμα","Σύστοιχο αντικείμενο","Είδος","Παράδειγμα"],"rows":[["μάχομαι","μάχην","ομόρριζο","μάχην μάχομαι"],["νικῶ","νίκην / Ὀλύμπια","ομόρριζο / συγγ.","νίκην νικῶ"],["βουλεύω","βουλήν","ομόρριζο","βουλήν βουλεύω"],["κινδυνεύω","κίνδυνον","ομόρριζο","κίνδυνον κινδυνεύω"],["πομπεύω","πομπήν","ομόρριζο","πομπήν πομπεύω"],["ἁμαρτάνω","ἁμαρτίαν","ομόρριζο","ἁμαρτίαν ἁμαρτάνω"],["θύω","θυσίαν","ομόρριζο","θυσίαν θύω"],["νοσῶ","νόσον / ἀσθένειαν","ομόρρ. / συγγ.","νόσον νοσῶ"],["καθεύδω","ὕπνον","συγγενικό","ὕπνον καθεύδω"],["ζῶ","βίον","συγγενικό","βίον ζῶ"],["χαίρω","χαράν / ἡδονήν","ομόρρ. / συγγ.","χαράν χαίρω"],["γράφω","γράμματα","ομόρριζο","γράμματα γράφω"]]},"note":"Πολλά ρήματα δέχονται και τα δύο: π.χ. <i>νικῶ νίκην</i> (ομόρριζο) ή <i>νικῶ μάχην / Ὀλύμπια</i> (συγγενικό). Η διάκριση γίνεται με κριτήριο τη ρίζα: ίδια ρίζα = ομόρριζο· διαφορετική ρίζα αλλά ίδια/συγγενική σημασία = συγγενικό κατά σημασία."},{"h":"Πτώση αιτιατική — και σύστοιχο σε αμετάβατα ρήματα","body":"<p>Το σύστοιχο αντικείμενο, όπως κάθε αντικείμενο που δηλώνει το άμεσο περιεχόμενο της ενέργειας, τίθεται κατά κανόνα σε <b>πτώση αιτιατική</b> (αιτιατική του συστοίχου / εσωτερικού αντικειμένου). Η αιτιατική είναι η πτώση που εκφράζει το «τι» της ρηματικής ενέργειας, και εδώ το «τι» ταυτίζεται με την ίδια την ενέργεια.</p><h3>Το πιο σπουδαίο γνώρισμα: συντάσσεται και με ΑΜΕΤΑΒΑΤΑ ρήματα</h3><p>Εδώ βρίσκεται η μεγάλη ιδιομορφία του φαινομένου. Ενώ το <b>κανονικό</b> αντικείμενο σε αιτιατική απαιτεί <b>μεταβατικό</b> ρήμα (μόνο τα μεταβατικά μεταβιβάζουν την ενέργεια σε εξωτερικό αντικείμενο), το <b>σύστοιχο</b> αντικείμενο μπορεί να σταθεί ΚΑΙ δίπλα σε ρήματα που κανονικά είναι <b>αμετάβατα</b> — ακόμη και ρήματα κίνησης, στάσης, πάθους ή κατάστασης. Ο λόγος είναι ότι το σύστοιχο δεν είναι πραγματικό «εξωτερικό» αντικείμενο: δεν δέχεται την ενέργεια, αλλά την <i>επαναλαμβάνει</i>. Έτσι ένα αμετάβατο ρήμα δεν χάνει τον αμετάβατο χαρακτήρα του· απλώς προσδιορίζεται ως προς το είδος ή τον τρόπο της ενέργειάς του.</p><p>Γι' αυτό ρήματα όπως <i>ζῶ, νοσῶ, καθεύδω, χαίρω, μάχομαι, κινδυνεύω, ἁμαρτάνω, νικῶ</i> — πολλά από τα οποία είναι αμετάβατα ή μέσα/παθητικά — δέχονται κανονικά σύστοιχο αντικείμενο σε αιτιατική. Στην ποίηση (Smyth) η σύνταξη επεκτείνεται ακόμη και σε ρήματα στάσης όπως <i>κεῖσθαι, στῆναι, καθίζειν</i>.</p><h3>Όλες οι διαθέσεις δέχονται σύστοιχο</h3><p>Αξιοσημείωτο είναι ότι σύστοιχο αντικείμενο μπορεί να πάρει <b>οποιοδήποτε ρήμα οποιασδήποτε διάθεσης</b> — ενεργητικό, μέσο, παθητικό, ουδέτερο/αμετάβατο. Αυτό το ξεχωρίζει από το κοινό αντικείμενο, που το ζητούν μόνο τα ενεργητικά μεταβατικά (και τα αντίστοιχα μέσα/παθητικά).</p><h3>Σπανιότερη εκφορά: σε άλλη πτώση</h3><p>Κατ' εξαίρεση, και κυρίως όταν παρεμβάλλεται η σημασία ρήματος που συντάσσεται με γενική (π.χ. ρήματα μνήμης, ακρόασης), το «εσωτερικό» περιεχόμενο μπορεί να εκφραστεί και σε <b>γενική</b> (π.χ. <i>γενναίας μνήμης μνημονεύω</i>). Η κανονική όμως και σχολικά απαιτούμενη εκφορά είναι η <b>αιτιατική</b>.</p>","examples":[{"gr":"Κροῖσος ἔζη <b>βίον</b> εὐδαίμονα.","an":"Το <i>ζῶ</i> είναι αμετάβατο· δέχεται όμως σύστοιχο <i>βίον</i> (συγγενικό) σε αιτιατική, με επιθ. προσδ. <i>εὐδαίμονα</i>. Μτφρ.: «Ο Κροίσος ζούσε ευτυχισμένη ζωή.» (τύπου)"},{"gr":"Μεγάλους <b>κινδύνους</b> ἐκινδύνευσαν.","an":"Το <i>κινδυνεύω</i> αμετάβατο· σύστοιχο ομόρριζο <i>κινδύνους</i> σε αιτιατική, επιθ. προσδ. <i>μεγάλους</i>. Μτφρ.: «Διέτρεξαν μεγάλους κινδύνους.» (τύπου)"},{"gr":"Πάσχω <b>πάθη</b> δεινά.","an":"Το <i>πάσχω</i> αμετάβατο (παθητικής σημασίας)· σύστοιχο ομόρριζο <i>πάθη</i> σε αιτιατική, επιθ. προσδ. <i>δεινά</i>. Μτφρ.: «Υφίσταμαι φοβερά παθήματα.» (τύπου)"},{"gr":"Νόσον νοσεῖ ὁ Φιλοκτήτης ἀνίατον.","an":"Αμετάβατο <i>νοσῶ</i> + ομόρριζο σύστοιχο <i>νόσον</i> (αιτ.) + επιθ. προσδ. <i>ἀνίατον</i>. Μτφρ.: «Ο Φιλοκτήτης πάσχει από ανίατη αρρώστια.» (τύπου)"},{"gr":"Κινδυνεύων τόν ἔσχατον <b>κίνδυνον</b>.","an":"Πλάτ. Ἀπολ. 34c — αμετάβατο <i>κινδυνεύω</i> + ομόρριζο σύστοιχο <i>κίνδυνον</i> σε αιτ., με προσδ. <i>τόν ἔσχατον</i>. Μτφρ.: «διατρέχοντας τον έσχατο κίνδυνο.»"},{"gr":"Στρατηγήσοντα ταύτην τήν <b>στρατηγίαν</b>.","an":"Ξεν. Ἀνάβ. 1.3.15 — αμετάβατο <i>στρατηγῶ</i> + ομόρριζο σύστοιχο <i>στρατηγίαν</i> (αιτ.) με δεικτ. προσδ. <i>ταύτην</i>. Μτφρ.: «(εμένα) που θα ηγηθεί αυτής της εκστρατείας.»"}],"note":"ΠΑΓΙΔΑ: μην το συγχέετε με την <i>αιτιατική της αναφοράς</i> ή την <i>αιτιατική του χρόνου</i>. Κριτήριο: αν το ουσιαστικό σε αιτιατική είναι ομόρριζο ή συνώνυμο του ρήματος και επαναλαμβάνει την έννοιά του → σύστοιχο αντικείμενο. Επίσης: αμετάβατο ρήμα + κανονικό εξωτερικό αντικείμενο σε αιτιατική είναι ΑΔΥΝΑΤΟ· μόνο το σύστοιχο επιτρέπεται σε αμετάβατα."},{"h":"Ο ρόλος του επιθετικού προσδιορισμού — η «ψυχή» του σύστοιχου","body":"<p>Όπως είδαμε, το γυμνό σύστοιχο αντικείμενο είναι σχεδόν περιττό: το <i>μάχην μάχομαι</i> δεν λέει τίποτε περισσότερο από το <i>μάχομαι</i>. Η <b>πραγματική σημασία</b> του φαινομένου αναδεικνύεται όταν το σύστοιχο φέρει <b>επιθετικό προσδιορισμό</b>. Τότε ο προσδιορισμός γίνεται ο φορέας της ουσιαστικής πληροφορίας — δηλώνει το <i>είδος</i>, την <i>ποιότητα</i>, την <i>ένταση</i> ή τον <i>τρόπο</i> της ενέργειας.</p><p>Στο <i>βίον εὐδαίμονα ζῶ</i> το βάρος δεν πέφτει στο <i>βίον</i> (που απλώς επαναλαμβάνει το <i>ζῶ</i>) αλλά στο <i>εὐδαίμονα</i>: «ζω <b>ευτυχισμένα</b>». Έτσι το σύστοιχο + επιθετικός προσδ. ισοδυναμεί λειτουργικά με <b>τροπικό επιρρηματικό προσδιορισμό</b>.</p><h3>Η αποβολή του σύστοιχου — μένει μόνο ο προσδιορισμός</h3><p>Επειδή το ουσιαστικό είναι περιττό, η γλώσσα συχνά το <b>παραλείπει</b> και διατηρεί <b>μόνο τον επιθετικό προσδιορισμό</b>. Ο προσδιορισμός τότε:</p><ul><li>είτε μένει σε <b>αιτιατική</b> (συμφωνώντας με το εννοούμενο σύστοιχο),</li><li>είτε —πολύ συχνά— τρέπεται σε <b>ουδέτερο, κατά κανόνα πληθυντικού</b>, και παίρνει τη θέση του σύστοιχου αντικειμένου.</li></ul><p>Έτσι το <i>πολλάς ἁμαρτίας ἁμαρτάνω</i> γίνεται <i>πολλά ἁμαρτάνω</i> («σφάλλω πολύ»), και το <i>μεγάλα πάθη πάσχω</i> γίνεται <i>μεγάλα πάσχω</i>. Το <i>πολλά / μεγάλα / ταῦτα</i> εξακολουθεί να αναλύεται ως σύστοιχο αντικείμενο (με εννοούμενο το ουσιαστικό).</p><h3>Σύνδεση με τα Νέα Ελληνικά</h3><p>Αυτή ακριβώς η εξέλιξη γέννησε πλήθος <b>τροπικών επιρρημάτων</b> των Νέων Ελληνικών. Ο αρχαίος επιθετικός προσδιορισμός του σύστοιχου (σε ουδέτερο, ή το αρχαίο επίρρημα σε -ως) εξελίχθηκε στα νεοελληνικά επιρρήματα σε <b>-α</b>: <i>βαδίζει καμαρωτά, ζούσε ήσυχα, μιλάει δυνατά</i>. Πίσω από κάθε τέτοιο επίρρημα κρύβεται ένα παλιό σύστοιχο αντικείμενο.</p>","examples":[{"gr":"Ἀλκιβιάδης <b>πολλά</b> ἥμαρτεν.","an":"< <i>πολλάς ἁμαρτίας ἥμαρτεν</i>. Το σύστοιχο <i>ἁμαρτίας</i> αποβλήθηκε· έμεινε ο προσδ. σε ουδέτ. πληθ. <i>πολλά</i> = σύστοιχο αντικείμενο. Μτφρ.: «Ο Αλκιβιάδης έσφαλε πολύ.» (τύπου)"},{"gr":"Πάσχουσι <b>μεγάλα</b>.","an":"< <i>μεγάλα πάθη πάσχουσι</i>. Σύστοιχο σε ουδέτ. πληθ. <i>μεγάλα</i>. Μτφρ.: «Υποφέρουν πολύ / παθαίνουν μεγάλα δεινά.» (τύπου)"},{"gr":"Παῖσον <b>διπλῆν</b>.","an":"< <i>παῖσον διπλῆν πληγήν</i>. Το σύστοιχο <i>πληγήν</i> παραλείπεται· μένει ο προσδ. σε αιτιατική <i>διπλῆν</i> = σύστοιχο. Μτφρ.: «Χτύπησε διπλά / δώσε διπλό χτύπημα.» (τύπου)"},{"gr":"Ταῦτα <b>ἁμαρτάνεις</b>.","an":"< <i>ταύτας τάς ἁμαρτίας ἁμαρτάνεις</i>. Δεικτική αντωνυμία σε ουδέτ. πληθ. <i>ταῦτα</i> ως σύστοιχο. Μτφρ.: «Αυτά τα σφάλματα κάνεις.» (τύπου)"},{"gr":"Μέγα <b>βοᾷ</b>.","an":"< <i>μεγάλην βοήν βοᾷ</i>. Σύστοιχο σε ουδέτ. <i>μέγα</i>· ισοδυναμεί με τροπικό «δυνατά». Μτφρ.: «Φωνάζει δυνατά.» (τύπου)"},{"gr":"Ἄλλην <b>ἀρχήν</b> οὐδεμίαν πώποτε ἦρξα.","an":"Πλάτ. Ἀπολ. 32b — ομόρριζο σύστοιχο <i>ἀρχήν</i> ← <i>ἄρχω</i>, με προσδ. <i>ἄλλην ... οὐδεμίαν</i> που φέρει το νόημα. Μτφρ.: «Καμία άλλη αρχή (αξίωμα) δεν άσκησα ποτέ.»"}],"note":"Σημαντικό για την ανάλυση: όταν συναντάτε ουδέτερα όπως <i>πολλά, μεγάλα, δεινά, ταῦτα, τοσαῦτα, οὐδέν, μηδέν, τι</i> δίπλα σε αμετάβατο ή σε ρήμα που δεν δέχεται κανονικό αντικείμενο, εξετάστε μήπως πρόκειται για σύστοιχο αντικείμενο (επιθετικός προσδ. εννοούμενου σύστοιχου). Π.χ. <i>οὐδέν ἀδικῶ</i> = «δεν διαπράττω καμία αδικία»."},{"h":"Αναγνώριση, σύνοψη και τυπικά λάθη","body":"<p>Συγκεντρώνουμε εδώ τα κριτήρια αναγνώρισης και τις συχνότερες παγίδες, ώστε ο μαθητής να εντοπίζει και να αναλύει με ασφάλεια το σύστοιχο αντικείμενο.</p><h3>Βήματα αναγνώρισης</h3><ol><li>Εντοπίζω ουσιαστικό (ή ουδέτερο επιθέτου/αντωνυμίας) σε <b>αιτιατική</b> κοντά στο ρήμα.</li><li>Ελέγχω αν είναι <b>ομόρριζο</b> με το ρήμα (ίδια ρίζα) ή <b>συνώνυμο / συγγενικό κατά σημασία</b>.</li><li>Αν ναι, και αν το αντικείμενο <i>επαναλαμβάνει την έννοια</i> του ρήματος (δεν δηλώνει εξωτερικό πρόσωπο/πράγμα), τότε είναι <b>σύστοιχο αντικείμενο</b>.</li><li>Ελέγχω τυχόν <b>επιθετικό προσδιορισμό</b>: συχνά αυτός φέρει το κύριο νόημα· αν λείπει το ουσιαστικό, ο προσδ. (συχνά ουδέτ. πληθ.) είναι ο ίδιος το σύστοιχο.</li></ol><h3>Διαφορά από το κανονικό αντικείμενο</h3><p>Το <b>κανονικό</b> αντικείμενο δηλώνει κάτι <i>έξω</i> από το ρήμα και απαιτεί <b>μεταβατικό</b> ρήμα (<i>φέρω λίθον</i>). Το <b>σύστοιχο</b> δηλώνει το <i>περιεχόμενο</i> του ρήματος και μπορεί να σταθεί και σε <b>αμετάβατο</b> (<i>βίον ζῶ</i>). Ένα ρήμα μπορεί να πάρει και τα δύο μαζί: <i>διδάσκω τούς παῖδας</i> (κανονικό) <i>μαθήματα</i> (σύστοιχο) — «διδάσκω στα παιδιά μαθήματα».</p>","table":{"title":"Κανονικό vs Σύστοιχο αντικείμενο","cols":["Κριτήριο","Κανονικό αντικείμενο","Σύστοιχο (εσωτερικό) αντικείμενο"],"rows":[["Τι δηλώνει","Εξωτερικό πρόσωπο/πράγμα δέκτη","Το ίδιο το περιεχόμενο της ενέργειας"],["Σχέση με ρήμα","Καμία ετυμολογική","Ομόρριζο ή συγγενικό κατά σημασία"],["Πτώση","Αιτ. (ή γεν./δοτ. κατά ρήμα)","Κατά κανόνα αιτιατική"],["Είδος ρήματος","Μόνο μεταβατικά","Και αμετάβατα, κάθε διάθεσης"],["Σημασιολογικό βάρος","Στο ίδιο το αντικείμενο","Στον επιθετικό προσδιορισμό"],["Παράδειγμα","γράφω ἐπιστολήν","βίον ζῶ εὐδαίμονα"]]},"examples":[{"gr":"Διδάσκω τούς νέους <b>καλά μαθήματα</b>.","an":"Δίπτωτο: <i>τούς νέους</i> = κανονικό (άμεσο) αντικείμενο· <i>μαθήματα</i> = σύστοιχο ομόρριζο του <i>διδάσκω</i>, με επιθ. προσδ. <i>καλά</i>. Μτφρ.: «Διδάσκω στους νέους καλά μαθήματα.» (τύπου)"},{"gr":"Οὐδέν <b>ἀδικῶ</b>.","an":"<i>οὐδέν</i> = ουδέτ. ως σύστοιχο (< <i>οὐδεμίαν ἀδικίαν</i>). Το <i>ἀδικῶ</i> εδώ χωρίς εξωτερικό αντικείμενο. Μτφρ.: «Δεν διαπράττω καμία αδικία.» (τύπου)"},{"gr":"Καλόν ἀγῶνα <b>ἀγωνίζομαι</b>.","an":"Μέσο ρήμα <i>ἀγωνίζομαι</i> + ομόρριζο σύστοιχο <i>ἀγῶνα</i> + επιθ. προσδ. <i>καλόν</i>: αποδεικνύει ότι σύστοιχο παίρνουν και τα μέσα. Μτφρ.: «Δίνω καλό αγώνα.» (τύπου)"},{"gr":"Ἐνίκησε τούς πολεμίους <b>καλήν νίκην</b>.","an":"Συνύπαρξη: <i>τούς πολεμίους</i> κανονικό αντικείμενο· <i>νίκην</i> σύστοιχο ομόρριζο + προσδ. <i>καλήν</i>. Μτφρ.: «Νίκησε τους εχθρούς με λαμπρή νίκη.» (τύπου)"},{"gr":"Ἡ αἰτία ἥν <b>αἰτιῶνται</b>.","an":"Ἀντιφῶν 6.27 — ομόρριζο σύστοιχο: η αναφορική <i>ἥν</i> (= <i>αἰτίαν</i>) σε αιτ. δίπλα στο <i>αἰτιῶμαι</i>. Δείχνει το σύστοιχο σε αναφορική σύνταξη. Μτφρ.: «η κατηγορία την οποία απαγγέλλουν.»"}],"note":"ΣΥΧΝΑ ΛΑΘΗ: (1) Να θεωρηθεί σύστοιχο κάθε ομόρριζο σε αιτιατική — όχι· πρέπει να επαναλαμβάνει την έννοια του ρήματος. (2) Να μη γίνει αντιληπτό ότι ουδέτερα όπως <i>πολλά, ταῦτα</i> κρύβουν εννοούμενο σύστοιχο. (3) Να συγχυστεί με αιτιατική αναφοράς. (4) Να ξεχαστεί ότι το σύστοιχο επιτρέπεται σε αμετάβατα — που είναι και το πιο ιδιαίτερο γνώρισμά του."}]);
  T("syn-epirrimatikoi-basika", [{"h":"Τι είναι οι επιρρηματικοί προσδιορισμοί","body":"<p>Ο <b>επιρρηματικός προσδιορισμός</b> είναι ένας προσδιορισμός που, όπως φανερώνει και το όνομά του, παίζει μέσα στην πρόταση ρόλο ανάλογο με αυτόν του <i>επιρρήματος</i>: προσδιορίζει <b>κυρίως το ρήμα</b>, αλλά μπορεί να προσδιορίζει και άλλα μέρη του λόγου (επίθετο, άλλο επίρρημα, ολόκληρη πρόταση). Δηλώνει δηλαδή <b>τις περιστάσεις μέσα στις οποίες γίνεται μια ενέργεια ή υπάρχει μια κατάσταση</b>: πού, πότε, πώς, πόσο, γιατί, για ποιον σκοπό κ.λπ.</p><p>Σε αντιδιαστολή με τους <i>ονοματικούς</i> προσδιορισμούς (επιθετικό, κατηγορηματικό, παράθεση, επεξήγηση, γενική) που προσδιορίζουν ένα <b>όνομα</b>, ο επιρρηματικός προσδιορισμός απαντά στις ερωτήσεις <b>πού; πότε; πώς; πόσο; γιατί; με τι; με ποιον; για ποιο σκοπό;</b> κ.ο.κ.</p><h3>Δύο οπτικές γωνίες</h3><p>Το σχολικό συντακτικό εξετάζει τους επιρρηματικούς προσδιορισμούς από δύο σκοπιές, που πρέπει να τις διακρίνουμε καθαρά:</p><ul><li><b>Κατά τον τρόπο εκφοράς</b> (το <i>πώς</i> εκφέρονται): με επίρρημα, με πλάγια πτώση ονόματος, με εμπρόθετο σύνολο, με κατηγορηματική/επιρρηματική μετοχή, με δευτερεύουσα επιρρηματική πρόταση.</li><li><b>Κατά τη σχέση</b> (τι <i>σημαίνουν</i>): τόπο, χρόνο, τρόπο, ποσό, αιτία, σκοπό, αναφορά, μέσο/όργανο, συνοδεία, ποινή, αξία, αναγκαστικό αίτιο, προϋπόθεση κ.ά.</li></ul><p>Η ίδια σχέση μπορεί να εκφραστεί με πολλούς τρόπους, και ο ίδιος τρόπος εκφοράς μπορεί να δηλώνει πολλές σχέσεις· γι' αυτό η ανάλυση γίνεται πάντοτε σε <b>δύο επίπεδα</b> (π.χ. \"επιρρηματικός προσδιορισμός <i>του τόπου</i>, εκφερόμενος <i>με εμπρόθετο σύνολο</i>\").</p>","examples":[{"gr":"Οὗτος ἐνθάδε μένει.","an":"\"Αυτός μένει εδώ.\" Το <i>ἐνθάδε</i> (επίρρημα τόπου) είναι επιρρηματικός προσδιορισμός του τόπου στο ρήμα <i>μένει</i> και απαντά στο \"πού;\"."},{"gr":"Νυκτός ἀφίκοντο εἰς τό στρατόπεδον.","an":"\"Έφτασαν στο στρατόπεδο τη νύχτα.\" Δύο επιρρηματικοί προσδιορισμοί: <i>νυκτός</i> (γενική του χρόνου, σχέση χρόνου) και <i>εἰς τό στρατόπεδον</i> (εμπρόθετο, σχέση τόπου / κίνηση προς)."},{"gr":"Ἐντεῦθεν ἐξελαύνει διά τῆς Βαβυλωνίας σταθμούς τρεῖς παρασάγγας δώδεκα.","an":"Ξεν. Ἀνάβ. 1.7.1 — \"Από εκεί προελαύνει μέσα από τη Βαβυλωνία τρεις σταθμούς, δώδεκα παρασάγγες.\" <i>ἐντεῦθεν</i> = επίρρ. προσδ. τόπου (κίνηση από)· <i>σταθμούς τρεῖς</i> / <i>παρασάγγας δώδεκα</i> = αιτιατικές της έκτασης (τόπου)."},{"gr":"Ταῦτα εἰπών ἐσιώπησεν.","an":"(τύπου Ξεν.) \"Αφού τα είπε αυτά, σώπασε.\" Η μετοχή <i>εἰπών</i> ισοδυναμεί με επιρρηματικό προσδιορισμό του χρόνου — δείγμα εκφοράς με μετοχή."}],"note":"Προσοχή στη διπλή ανάλυση: ποτέ δεν λέμε απλώς \"επιρρηματικός προσδιορισμός\". Πάντοτε δηλώνουμε ΚΑΙ τη σχέση (τόπου, χρόνου...) ΚΑΙ, όταν ζητείται, τον τρόπο εκφοράς (επίρρημα / πλάγια πτώση / εμπρόθετο)."},{"h":"Οι τρόποι εκφοράς — επισκόπηση","body":"<p>Πριν εξετάσουμε κάθε σχέση χωριστά, ας δούμε συγκεντρωτικά <b>με ποιες μορφές</b> μπορεί να εμφανιστεί ένας επιρρηματικός προσδιορισμός στα Αρχαία Ελληνικά. Είναι πέντε βασικοί τρόποι:</p><h3>1. Καθαρώς επιρρηματικός προσδιορισμός (επίρρημα)</h3><p>Ένα <b>επίρρημα</b> (τόπου, χρόνου, τρόπου, ποσού) προσδιορίζει το ρήμα: <i>ἐκεῖ, νῦν, καλῶς, σφόδρα</i>. Αυτή είναι η \"καθαρότερη\" μορφή, γιατί το επίρρημα από τη φύση του είναι επιρρηματικό.</p><h3>2. Πλάγια πτώση ονόματος</h3><p>Ένα όνομα σε <b>γενική, δοτική ή αιτιατική</b> (χωρίς πρόθεση) λειτουργεί επιρρηματικά: <i>νυκτός</i> (γεν. χρόνου), <i>βίᾳ</i> (δοτ. τρόπου), <i>τρία ἔτη</i> (αιτ. χρόνου).</p><h3>3. Εμπρόθετος προσδιορισμός (πρόθεση + πτώση)</h3><p>Μια <b>πρόθεση μαζί με όνομα σε πλάγια πτώση</b> σχηματίζει ένα ενιαίο σύνολο: <i>ἐν Ἀθήναις, διά τόν φόβον, σύν τοῖς συμμάχοις</i>. Είναι ο πιο παραγωγικός τρόπος και καλύπτει σχεδόν όλες τις σχέσεις.</p><h3>4. Επιρρηματική / κατηγορηματική μετοχή</h3><p>Μια μετοχή μπορεί να δηλώσει χρόνο, αιτία, σκοπό, υπόθεση, εναντίωση, τρόπο: <i>ταῦτα εἰπών ἀπῆλθεν</i> (χρονική), <i>φοβούμενος ἔφυγεν</i> (αιτιολογική).</p><h3>5. Δευτερεύουσα επιρρηματική πρόταση</h3><p>Ολόκληρη πρόταση (χρονική, αιτιολογική, τελική, υποθετική, εναντιωματική, αποτελεσματική, παραβολική): <i>ὅτε ἦλθεν, ἐχάρημεν</i>.</p><p>Στην ενότητα αυτή εστιάζουμε στους <b>τρεις πρώτους</b> (επίρρημα, πλάγια πτώση, εμπρόθετο), που είναι το \"βασικό\" επίπεδο· οι μετοχές και οι προτάσεις εξετάζονται αναλυτικά σε ξεχωριστά κεφάλαια.</p>","table":{"title":"Οι πέντε τρόποι εκφοράς με παράδειγμα","cols":["Τρόπος εκφοράς","Παράδειγμα","Σχέση"],"rows":[["Επίρρημα","ἐκεῖ ἔμεινεν","τόπου"],["Πλάγια πτώση (γενική)","νυκτός ἀφίκετο","χρόνου"],["Πλάγια πτώση (δοτική)","βίᾳ εἰσῆλθεν","τρόπου"],["Πλάγια πτώση (αιτιατική)","τρία ἔτη ἔμεινεν","χρόνου (διάρκεια)"],["Εμπρόθετο","διά τόν φόβον ἔφυγεν","αιτίας"],["Μετοχή","ταῦτα ἀκούσας ἀπῆλθεν","χρόνου"],["Δευτερεύουσα πρόταση","ἐπεί ἦλθεν, ἀπήλθομεν","χρόνου"]]},"examples":[{"gr":"Καλῶς καί ἀνδρείως ἐμαχέσαντο.","an":"\"Πολέμησαν καλά και γενναία.\" Δύο καθαρώς επιρρηματικοί προσδιορισμοί του τρόπου (επιρρήματα σε -ως) στο ρήμα <i>ἐμαχέσαντο</i>."},{"gr":"Ἐνταῦθα ἔμεινεν ἡμέρας ἑπτά.","an":"(τύπου Ξεν. Ἀνάβ.) \"Εκεί έμεινε εφτά ημέρες.\" Τρεις τρόποι σε αντιδιαστολή: <i>ἐνταῦθα</i> = επίρρημα (τόπου)· <i>ἡμέρας ἑπτά</i> = πλάγια πτώση, αιτιατική (χρόνου-διάρκεια)."},{"gr":"Διά τόν χειμῶνα ἐν Ἀθήναις ἔμενον.","an":"\"Εξαιτίας της κακοκαιρίας έμεναν στην Αθήνα.\" Δύο εμπρόθετα: <i>διά τόν χειμῶνα</i> (αιτίας) και <i>ἐν Ἀθήναις</i> (τόπου-στάση) — δείγμα του εμπρόθετου τρόπου εκφοράς."},{"gr":"Ἐπεί δέ ἐτελεύτησεν ὁ πατήρ, ἀπῆλθεν οἴκαδε.","an":"\"Όταν πέθανε ο πατέρας, έφυγε για το σπίτι.\" Η χρονική πρόταση <i>ἐπεί... ἐτελεύτησεν</i> = επιρρηματικός προσδ. του χρόνου με δευτερεύουσα πρόταση· <i>οἴκαδε</i> = επίρρημα τόπου (κίνηση προς)."}],"note":"Ένας εμπρόθετος προσδιορισμός αναλύεται ΠΑΝΤΑ ως ενιαίο σύνολο: δεν χωρίζουμε την πρόθεση από το όνομα. Λέμε \"εμπρόθετος προσδιορισμός του τόπου\", όχι \"η πρόθεση ἐν + δοτική Ἀθήναις\"."},{"h":"Καθαρώς επιρρηματικοί προσδιορισμοί — τα επιρρήματα","body":"<p>Όταν ο επιρρηματικός προσδιορισμός είναι <b>επίρρημα</b>, μιλάμε για <i>καθαρώς (ή απλώς) επιρρηματικό προσδιορισμό</i>. Τα επιρρήματα αυτά κατατάσσονται σε τέσσερις μεγάλες σημασιολογικές ομάδες — <b>χρόνου, τόπου, τρόπου, ποσού</b> — και τα επιρρήματα τόπου διακρίνονται περαιτέρω ανάλογα με το αν δηλώνουν στάση, κίνηση προς ή κίνηση από τόπο.</p><h3>Επιρρήματα χρόνου</h3><p>Δηλώνουν πότε ή πόσο συχνά γίνεται κάτι: <i>ἀεί (αἰεί), νῦν, τότε, ἤδη, ἄρτι, πάλαι, χθές, σήμερον, αὔριον, πρῴ, ὀψέ, ἔτι, οὔπω, οὔποτε, πολλάκις, ἐνίοτε</i>.</p><h3>Επιρρήματα τόπου</h3><p>Σχηματίζουν χαρακτηριστικές τριάδες ανάλογα με τη λήξη:</p><ul><li><b>Στάση σε τόπο</b> (πού;) — λήξη συχνά σε <i>-ου, -οι, -σι</i>: <i>ἐκεῖ, ἐνθάδε, αὐτοῦ, ἔνδον, ἔξω, οἴκοι, πανταχοῦ, Ἀθήνησι</i>.</li><li><b>Κίνηση προς τόπο</b> (προς τα πού;) — λήξη σε <i>-δε, -σε, -ζε</i>: <i>δεῦρο, ἐκεῖσε, οἴκαδε, Ἀθήναζε, ἐνθάδε</i>.</li><li><b>Κίνηση από τόπο</b> (από πού;) — λήξη σε <i>-θεν</i>: <i>ἐκεῖθεν, οἴκοθεν, ἔξωθεν, Ἀθήνηθεν, πανταχόθεν</i>.</li></ul><h3>Επιρρήματα τρόπου</h3><p>Είναι κυρίως τα παράγωγα σε <b>-ως</b> (από επίθετα): <i>καλῶς, κακῶς, δικαίως, σαφῶς, οὕτω(ς), ὧδε, ὁμοίως</i>· επίσης τα σε <b>-δην/-δον/-ί</b>: <i>κρύβδην, τροχάδην, ἀναφανδόν, ἀμαχητί</i>.</p><h3>Επιρρήματα ποσού</h3><p>Δηλώνουν ποσότητα, βαθμό ή συχνότητα: <i>πάνυ, σφόδρα, λίαν, ἄγαν, μάλα, μᾶλλον, μάλιστα, πολύ, ὀλίγον, ἅπαξ, δίς, τρίς, πολλάκις</i>.</p>","table":{"title":"Επιρρήματα τόπου — η τριάδα στάση / προς / από","cols":["Στάση (πού;)","Κίνηση προς (πού;)","Κίνηση από (πόθεν;)"],"rows":[["ἐνθάδε / αὐτοῦ","ἐνθάδε / δεῦρο","ἐνθένδε"],["ἐκεῖ","ἐκεῖσε","ἐκεῖθεν"],["οἴκοι","οἴκαδε","οἴκοθεν"],["Ἀθήνησι","Ἀθήναζε","Ἀθήνηθεν"],["πανταχοῦ","πανταχόσε","πανταχόθεν"],["ποῦ;","ποῖ;","πόθεν;"]]},"examples":[{"gr":"Ἡ μέν δή Ἀθήνησι στάσις οὕτως ἐτελεύτησεν.","an":"\"Έτσι λοιπόν τελείωσε η στάση στην Αθήνα.\" <i>Ἀθήνησι</i> = επίρρημα τόπου (στάση), προσδ. τόπου· <i>οὕτως</i> = επίρρημα τρόπου, προσδ. τρόπου."},{"gr":"Χρήματα πάνυ πολλά ἡ στρατιά ἔλαβεν.","an":"\"Ο στρατός πήρε πάρα πολλά χρήματα.\" Το <i>πάνυ</i> (επίρρημα ποσού) προσδιορίζει το επίθετο <i>πολλά</i> — επιρρηματικός προσδ. του ποσού (δηλώνει βαθμό)."},{"gr":"Νῦν δέ οὐκέτι οἷόν τέ ἐστιν.","an":"\"Τώρα όμως δεν είναι πια δυνατόν.\" <i>Νῦν</i> = επίρρημα χρόνου· <i>οὐκέτι</i> = επίρρημα χρόνου (άρνηση + χρόνος)."},{"gr":"Δεῦρο νῦν, ὦ παῖ.","an":"(τύπου Πλάτ.) \"Έλα εδώ τώρα, παιδί μου.\" <i>δεῦρο</i> = επίρρημα τόπου (κίνηση προς)· <i>νῦν</i> = επίρρημα χρόνου — δύο καθαρώς επιρρηματικοί προσδιορισμοί."},{"gr":"Πανταχόθεν συνέρρεον οἱ πολῖται.","an":"\"Από παντού συνέρρεαν οι πολίτες.\" <i>πανταχόθεν</i> = επίρρημα τόπου σε -θεν (κίνηση από / αφετηρία)."}],"note":"Τα επιρρήματα τόπου σε -θεν δηλώνουν ΑΦΕΤΗΡΙΑ (κίνηση από)· σε -δε/-σε/-ζε δηλώνουν ΚΑΤΕΥΘΥΝΣΗ (κίνηση προς). Το ἐνθάδε χρησιμοποιείται και για στάση και για κίνηση προς — το ξεχωρίζει το ρήμα."},{"h":"Η γενική ως επιρρηματικός προσδιορισμός","body":"<p>Η <b>γενική</b> χωρίς πρόθεση μπορεί να λειτουργήσει επιρρηματικά. Οι κύριες επιρρηματικές χρήσεις της είναι:</p><h3>α) Γενική του χρόνου</h3><p>Δηλώνει το <b>χρονικό διάστημα μέσα στο οποίο</b> γίνεται κάτι (όχι τη διάρκεια — αυτή θέλει αιτιατική). Συνηθισμένες λέξεις: <i>ἡμέρας, νυκτός, δείλης, ἔαρος, θέρους, χειμῶνος, μεσημβρίας</i>.</p><h3>β) Γενική της αιτίας</h3><p>Προσδιορίζει ρήματα <b>ψυχικού πάθους</b> και <b>δικανικής (νομικής) σημασίας</b>, δηλώνοντας την αιτία. Ρήματα: <i>θαυμάζω, ἄγαμαι, ζηλῶ, χαίρω, ἀγανακτῶ, οἰκτίρω</i> (ψυχικού πάθους)· <i>κατηγορῶ, αἰτιῶμαι, διώκω, γράφομαι, κρίνω</i> (δικανικά).</p><h3>γ) Γενική της αξίας ή του ποσού</h3><p>Με ρήματα <b>αγοραπωλησίας και αποτίμησης</b>: <i>ἀγοράζω, ὠνοῦμαι, πιπράσκω, πωλῶ, τιμῶμαι, ἄξιός εἰμι</i>.</p><h3>δ) Γενική της ποινής</h3><p>Με ρήματα δικανικά που δηλώνουν καταδίκη/τιμωρία, η ποινή τίθεται σε γενική: <i>τιμῶμαι, κρίνω, ὑπάγω</i>.</p><h3>ε) Γενική του τόπου</h3><p>Σπανιότερη, ποιητικότερη χρήση· δηλώνει τον τόπο μέσα στον οποίο γίνεται κίνηση (\"διά μέσου\"): <i>τοῦ πεδίου ἐπορεύοντο</i>.</p>","table":{"title":"Οι επιρρηματικές χρήσεις της γενικής","cols":["Είδος","Σχέση","Με ποια ρήματα/λέξεις"],"rows":[["Γενική του χρόνου","χρόνου","ἡμέρας, νυκτός, θέρους, χειμῶνος"],["Γενική της αιτίας","αιτίας","ψυχικού πάθους & δικανικά (θαυμάζω, κατηγορῶ)"],["Γενική της αξίας","αξίας/ποσού","αγοραπωλησίας (ὠνοῦμαι, πωλῶ, τιμῶμαι)"],["Γενική της ποινής","ποινής","δικανικά καταδίκης (τιμῶμαι, κρίνω)"],["Γενική του τόπου","τόπου","ρήματα κίνησης (πορεύομαι)"]]},"examples":[{"gr":"Ἐπιγίγνεται τῆς νυκτός χιών παμπληθής.","an":"\"Μέσα στη νύχτα πέφτει χιόνι πάρα πολύ.\" <i>τῆς νυκτός</i> = γενική του χρόνου, επιρρηματικός προσδ. του χρόνου (το διάστημα μέσα στο οποίο)."},{"gr":"Σέ τῆς τόλμης θαυμάζω.","an":"\"Σε θαυμάζω για την τόλμη σου.\" <i>τῆς τόλμης</i> = γενική της αιτίας στο ρήμα ψυχικού πάθους <i>θαυμάζω</i> — προσδ. της αιτίας."},{"gr":"Ἐπρίατο τόν ἵππον πολλοῦ ἀργυρίου.","an":"\"Αγόρασε το άλογο με πολλά χρήματα.\" <i>πολλοῦ ἀργυρίου</i> = γενική της αξίας με ρήμα αγοραπωλησίας — προσδ. της αξίας."},{"gr":"Ἐξῆν σοι φυγῆς τιμήσασθαι.","an":"\"Μπορούσες να προτείνεις για τον εαυτό σου την ποινή της εξορίας.\" <i>φυγῆς</i> = γενική της ποινής στο δικανικό <i>τιμῶμαι</i>."},{"gr":"Ταύτης τῆς ἡμέρας ηὐλίσθησαν αὐτοῦ.","an":"(τύπου Ξεν. Ἀνάβ.) \"Εκείνη την ημέρα στρατοπέδευσαν εκεί.\" <i>ταύτης τῆς ἡμέρας</i> = γενική του χρόνου (το διάστημα μέσα στο οποίο)· <i>αὐτοῦ</i> = επίρρ. τόπου (στάση)."},{"gr":"Μέμνησθε... καί ἐμοῦ ἀπιόντος μή καταγελάσητε.","an":"(τύπου δικανικού) Γενική προσώπου με ρήμα μνήμης· πρβλ. τη γενική της αιτίας: <i>τούτων ἀγανακτῶ</i> = \"γι' αυτά αγανακτώ\" (αιτία στο ρήμα ψυχ. πάθους)."}],"note":"Διάκριση-παγίδα: η γενική του χρόνου (νυκτός = \"κατά τη διάρκεια / μέσα στη νύχτα\") δηλώνει το ΠΛΑΙΣΙΟ· η αιτιατική του χρόνου (νύκτα/τρεῖς νύκτας) δηλώνει τη ΔΙΑΡΚΕΙΑ· η δοτική του χρόνου (τῇ νυκτί) δηλώνει το ΣΗΜΕΙΟ. Τρεις πτώσεις, τρεις διαφορετικές χρονικές αποχρώσεις."},{"h":"Η δοτική ως επιρρηματικός προσδιορισμός","body":"<p>Η <b>δοτική</b> είναι η πλουσιότερη πτώση σε επιρρηματικές χρήσεις. Από τις τρεις αρχικές πτώσεις που συγχωνεύτηκαν σε αυτήν (καθαυτό δοτική, οργανική, τοπική) προέρχονται οι ποικίλες σημασίες της. Οι κύριες είναι:</p><h3>α) Δοτική του τόπου</h3><p>Δηλώνει στάση σε τόπο, κυρίως με <b>τοπωνύμια</b> και με δοτικοφανή επιρρήματα: <i>Ἐλευσῖνι, Μαραθῶνι, Δελφοῖς, Ἰσθμοῖ, Σαλαμῖνι, κύκλῳ, ταύτῃ, ᾗ</i>.</p><h3>β) Δοτική του χρόνου</h3><p>Δηλώνει το <b>ορισμένο χρονικό σημείο</b>· κυρίως με ονόματα εορτών και χρονικές διαιρέσεις: <i>τῇ ἡμέρᾳ, νυκτί, μηνί, ἔτει, Παναθηναίοις, Διονυσίοις</i>.</p><h3>γ) Δοτική του τρόπου</h3><p>Πολλά <b>δοτικοφανή επιρρήματα τρόπου</b>: <i>βίᾳ, σιγῇ, σπουδῇ, δρόμῳ, πεζῇ, δημοσίᾳ, κοινῇ, ἰδίᾳ, ἔργῳ, λόγῳ, φύσει, τῷ ὄντι</i>.</p><h3>δ) Δοτική του οργάνου ή μέσου</h3><p>Δηλώνει το <b>εργαλείο ή το μέσο</b> με το οποίο γίνεται κάτι: <i>τοῖς ὅπλοις, λίθοις, τοῖς ὀφθαλμοῖς ὁρῶ</i>.</p><h3>ε) Δοτική της αιτίας</h3><p>Με ρήματα <b>ψυχικού πάθους</b>: <i>ἥδομαι, χαίρω, ἄχθομαι, λυποῦμαι, ἀγάλλομαι</i>.</p><h3>στ) Δοτική της συνοδείας (κοινωνική)</h3><p>Δηλώνει το πρόσωπο/πράγμα που <b>συνοδεύει</b>, κυρίως με ρήματα κίνησης· συχνά με <i>αὐτός</i> (\"δοτική του ποιητικού όλου\"): <i>στρατῷ, ναυσί, ἵππῳ, ὁπλίταις, αὐτοῖς ἀνδράσιν</i>.</p><h3>ζ) Δοτική του ποσού (μέτρου διαφοράς)</h3><p>Με <b>συγκριτικά</b>, δηλώνει κατά πόσο διαφέρει κάτι: <i>πολλῷ, ὀλίγῳ, μακρῷ, τοσούτῳ ... ὅσῳ</i>.</p><h3>η) Δοτική της αναφοράς</h3><p>Δηλώνει ως προς τι ισχύει κάτι, με ρήματα/επίθετα σύγκρισης-διαφοράς: <i>διαφέρω, πλεονεκτῶ, λείπομαι</i>.</p>","table":{"title":"Οι οκτώ επιρρηματικές χρήσεις της δοτικής","cols":["Είδος","Σχέση","Τυπικά παραδείγματα"],"rows":[["Δοτική του τόπου","τόπου","Μαραθῶνι, κύκλῳ, ταύτῃ"],["Δοτική του χρόνου","χρόνου","τῇ ἡμέρᾳ, Παναθηναίοις, ἔτει"],["Δοτική του τρόπου","τρόπου","βίᾳ, σιγῇ, πεζῇ, δημοσίᾳ"],["Δοτική του οργάνου/μέσου","μέσου","τοῖς ὅπλοις, λίθοις, ὀφθαλμοῖς"],["Δοτική της αιτίας","αιτίας","ψυχικού πάθους (χαίρω, ἥδομαι)"],["Δοτική της συνοδείας","συνοδείας","στρατῷ, ναυσί, αὐτοῖς ἀνδράσιν"],["Δοτική του ποσού","ποσού (διαφοράς)","πολλῷ, ὀλίγῳ + συγκριτικό"],["Δοτική της αναφοράς","αναφοράς","διαφέρω, πλεονεκτῶ + δοτική"]]},"examples":[{"gr":"Ἐπορεύοντο πεζῇ ἐς Τάναγραν.","an":"\"Πορεύονταν πεζοί προς την Τάναγρα.\" <i>πεζῇ</i> = δοτική του τρόπου· <i>ἐς Τάναγραν</i> = εμπρόθετος προσδ. του τόπου (κίνηση προς)."},{"gr":"Στρατεύουσιν ἐπ' αὐτούς τεσσαράκοντα ναυσί.","an":"\"Εκστρατεύουν εναντίον τους με σαράντα πλοία.\" <i>τεσσαράκοντα ναυσί</i> = δοτική της συνοδείας με ρήμα κίνησης (το μέσο/συνοδεία της εκστρατείας)."},{"gr":"Πολλῷ μείζων ἐγίγνετο ἡ βοή.","an":"\"Κατά πολύ δυνατότερη γινόταν η κραυγή.\" <i>πολλῷ</i> = δοτική του ποσού (μέτρου διαφοράς) στο συγκριτικό <i>μείζων</i>."},{"gr":"Ὑμεῖς χρήμασι καί τιμαῖς τούτων ἐπλεονεκτεῖτε.","an":"\"Εσείς τους ξεπερνούσατε σε χρήματα και τιμές.\" <i>χρήμασι, τιμαῖς</i> = δοτικές της αναφοράς στο <i>ἐπλεονεκτεῖτε</i> (ως προς τι)."},{"gr":"Ὡπλισμένοι ἦσαν θώραξι χαλκοῖς.","an":"\"Ήταν οπλισμένοι με χάλκινους θώρακες.\" <i>θώραξι χαλκοῖς</i> = δοτική του οργάνου/μέσου."},{"gr":"Πολλῇ βοῇ προσέκειντο.","an":"Θουκ. (τύπου) \"Επιτίθονταν με δυνατές κραυγές.\" <i>πολλῇ βοῇ</i> = δοτική του τρόπου (πβ. Smyth: ο τρόπος με τον οποίο γίνεται μια πράξη)."},{"gr":"Τῇ αὐτῇ ἡμέρᾳ ἀφίκοντο.","an":"(τύπου Θουκ.) \"Την ίδια ημέρα έφτασαν.\" <i>τῇ αὐτῇ ἡμέρᾳ</i> = δοτική του χρόνου (ορισμένο χρονικό σημείο)."},{"gr":"Μαραθῶνι κρατήσαντες τούς βαρβάρους.","an":"(τύπου) \"Νικώντας τους βαρβάρους στον Μαραθώνα.\" <i>Μαραθῶνι</i> = δοτική του τόπου (στάση, με τοπωνύμιο)."}],"note":"Παγίδα διάκρισης: δοτική ΟΡΓΑΝΟΥ (άψυχο εργαλείο: λίθοις) vs δοτική ΣΥΝΟΔΕΙΑΣ (έμψυχα ή στρατιωτικές μονάδες σε κίνηση: στρατῷ, ναυσί). Η συνοδεία απαντά συχνά με σύν + δοτική, ενώ καθαρή δοτική συνοδείας προτιμάται με αὐτός (αὐτοῖς ἀνδράσι = \"μαζί με τους ίδιους τους άντρες\")."},{"h":"Η αιτιατική ως επιρρηματικός προσδιορισμός","body":"<p>Η <b>αιτιατική</b> χωρίς πρόθεση λειτουργεί επιρρηματικά σε αρκετές περιπτώσεις. Η πιο χαρακτηριστική είναι η <i>αιτιατική της αναφοράς</i>, αλλά υπάρχουν και άλλες:</p><h3>α) Αιτιατική της αναφοράς</h3><p>Δηλώνει <b>ως προς τι</b> ισχύει μια ιδιότητα ή ενέργεια· μεταφράζεται \"ως προς...\". Τυπικές λέξεις: <i>τό γένος, τήν φύσιν, τό μέγεθος, τό εἶδος, τό ὄνομα, τά ὄμματα, τόν ἀριθμόν</i>· συχνά με <i>πᾶς / οὐδέν / τι</i>.</p><h3>β) Αιτιατική του χρόνου (διάρκεια)</h3><p>Δηλώνει <b>πόσο χρόνο διαρκεί</b> μια ενέργεια: <i>τρία ἔτη, πολύν χρόνον, τήν νύκτα, τό πάλαι, πᾶσαν τήν ἡμέραν</i>.</p><h3>γ) Αιτιατική του τόπου (έκταση/απόσταση)</h3><p>Δηλώνει την <b>έκταση ή απόσταση</b> στον χώρο: <i>ἀπέχει εἴκοσι σταδίους, ὁδόν τριῶν ἡμερῶν</i>.</p><h3>δ) Αιτιατική του τρόπου</h3><p>Παγιωμένες εκφράσεις: <i>δίκην (= κατά τον τρόπο), τρόπον, προῖκα (= δωρεάν), τήν ταχίστην (= το ταχύτερο), χάριν</i>.</p><h3>ε) Αιτιατική της αιτίας</h3><p>Με ρήματα δικανικής σημασίας ή που απαιτούν αιτιολόγηση· συχνά ουδέτερο αντωνυμίας: <i>τί; (= γιατί;), τοῦτο, ταῦτα</i>.</p><h3>στ) Αιτιατική του σκοπού</h3><p>Με ρήματα κίνησης, κυρίως ουδέτερη αντωνυμία: <i>τί ἦλθες; (= για ποιο σκοπό;)</i>.</p><h3>ζ) Αιτιατική της ποινής</h3><p>Σπανιότερη, με ρήματα καταδίκης· η ποινή σε αιτιατική: <i>θάνατον κατεψηφίσαντο</i>.</p>","table":{"title":"Οι επιρρηματικές χρήσεις της αιτιατικής","cols":["Είδος","Σχέση","Τυπικά παραδείγματα"],"rows":[["Αιτιατική της αναφοράς","αναφοράς","τήν φύσιν, τό γένος, τό μέγεθος"],["Αιτιατική του χρόνου","χρόνου (διάρκεια)","τρία ἔτη, πολύν χρόνον"],["Αιτιατική του τόπου","τόπου (έκταση)","εἴκοσι σταδίους, ὁδόν τριῶν ἡμερῶν"],["Αιτιατική του τρόπου","τρόπου","δίκην, προῖκα, τήν ταχίστην"],["Αιτιατική της αιτίας","αιτίας","τί;, ταῦτα + δικανικά"],["Αιτιατική του σκοπού","σκοπού","τί ἦλθες; + ρήμα κίνησης"],["Αιτιατική της ποινής","ποινής","θάνατον (κατεψηφίσαντο)"]]},"examples":[{"gr":"Διαφέρει γυνή ἀνδρός τήν φύσιν.","an":"\"Η γυναίκα διαφέρει από τον άντρα ως προς τη φύση.\" <i>τήν φύσιν</i> = αιτιατική της αναφοράς (ως προς τι διαφέρει)."},{"gr":"Πέπαυμαι τρέφων τρίτον ἔτος τουτί.","an":"\"Έχω σταματήσει να τρέφω εδώ και τρία ολόκληρα χρόνια.\" <i>τρίτον ἔτος</i> = αιτιατική του χρόνου (διάρκεια)."},{"gr":"Ἀπέχει ἡ Πλάταια τῶν Θηβῶν σταδίους ἑβδομήκοντα.","an":"\"Η Πλάταια απέχει από τη Θήβα εβδομήντα στάδια.\" <i>σταδίους ἑβδομήκοντα</i> = αιτιατική του τόπου (απόσταση/έκταση)."},{"gr":"Τί τηνικάδε ἀφῖξαι, ὦ Κρίτων;","an":"Πλάτ. Κρίτων 43a — \"Για ποιο σκοπό ήρθες τέτοια ώρα, Κρίτωνα;\" <i>τί</i> = αιτιατική του σκοπού με ρήμα κίνησης (= γιατί / για ποιον λόγο)."},{"gr":"Δωρεάν / προῖκα ταῦτα ἔδωκεν.","an":"\"Τα έδωσε δωρεάν.\" <i>προῖκα</i> = αιτιατική του τρόπου (παγιωμένη επιρρηματική χρήση)."},{"gr":"Τυφλός τά τ' ὦτα τόν τε νοῦν τά τ' ὄμματ' εἶ.","an":"Σοφ. Οἰδ. Τύρ. 371 — \"Είσαι τυφλός και στα αυτιά και στον νου και στα μάτια.\" <i>τά ὦτα, τόν νοῦν, τά ὄμματα</i> = αιτιατικές της αναφοράς (ως προς τι)."},{"gr":"Ἔμεινεν ἡμέρας τέτταρας.","an":"(τύπου Ξεν. Ἀνάβ.) \"Έμεινε τέσσερις ημέρες.\" <i>ἡμέρας τέτταρας</i> = αιτιατική του χρόνου (διάρκεια) — αντιδιαστολή προς τη γενική (διάστημα) και τη δοτική (σημείο)."}],"note":"Η αιτιατική της αναφοράς είναι το \"σήμα κατατεθέν\" της αιτιατικής: όταν βλέπεις ουδέτερο ονόματος/επιθέτου σε αιτιατική δίπλα σε ρήμα/επίθετο που \"χρειάζεται περιορισμό\" (διαφέρω, ἀγαθός τήν ψυχήν), σκέψου πρώτα αναφορά."},{"h":"Οι εμπρόθετοι επιρρηματικοί προσδιορισμοί","body":"<p>Ο πιο εκφραστικός και παραγωγικός τρόπος δήλωσης επιρρηματικών σχέσεων είναι ο <b>εμπρόθετος προσδιορισμός</b>: μια <b>πρόθεση + όνομα σε πλάγια πτώση</b>, που λειτουργούν ως ένα ενιαίο σύνολο. Στα Αρχαία Ελληνικά οι προθέσεις διακρίνονται σε:</p><ul><li><b>Κύριες (γνήσιες) προθέσεις</b> (18): μπαίνουν και ως πρώτο συνθετικό σε σύνθετες λέξεις. Είναι οι: <i>ἀμφί, ἀνά, ἀντί, ἀπό, διά, εἰς, ἐκ/ἐξ, ἐν, ἐπί, κατά, μετά, παρά, περί, πρό, πρός, σύν, ὑπέρ, ὑπό</i>.</li><li><b>Καταχρηστικές (νόθες) προθέσεις</b>: δεν συντίθενται· συντάσσονται κατά κανόνα με γενική: <i>ἄνευ, ἄχρι(ς), μέχρι(ς), ἕνεκα/ἕνεκεν, χάριν, πλήν, χωρίς, δίχα, ὡς</i> (+ αιτ., μόνο για πρόσωπα).</li></ul><h3>Πτώση και σημασία</h3><p>Πολλές κύριες προθέσεις συντάσσονται με <b>περισσότερες πτώσεις</b>, και η πτώση αλλάζει τη σημασία. Γενικός κανόνας-οδηγός:</p><ul><li>με <b>γενική</b> κυριαρχεί η ιδέα της <i>απομάκρυνσης / προέλευσης / υπέρ</i>·</li><li>με <b>δοτική</b> κυριαρχεί η ιδέα της <i>στάσης / θέσης σε τόπο</i>·</li><li>με <b>αιτιατική</b> κυριαρχεί η ιδέα της <i>κίνησης / κατεύθυνσης / έκτασης</i>.</li></ul><p>Παράδειγμα με <i>παρά</i>: <i>παρά Κύρου</i> (από κοντά από — γεν.), <i>παρά Κύρῳ</i> (κοντά σε, στάση — δοτ.), <i>παρά Κῦρον</i> (προς τον Κύρο — αιτ.).</p>","table":{"title":"Κύριες προθέσεις: πτώσεις & βασικές σχέσεις","cols":["Πρόθεση","Πτώση(εις)","Κύριες σχέσεις"],"rows":[["ἀντί","γεν.","αντί / αντίθεση / αιτία"],["ἀπό","γεν.","αφετηρία, προέλευση, αιτία, ύλη"],["ἐκ/ἐξ","γεν.","έξοδος, καταγωγή, αιτία, ύλη"],["πρό","γεν.","τόπος/χρόνος (πριν), υπεράσπιση"],["σύν/ξύν","δοτ.","συνοδεία, μέσο, τρόπος"],["ἐν","δοτ.","στάση σε τόπο, χρόνος, τρόπος/μέσο"],["εἰς/ἐς","αιτ.","κίνηση προς, χρόνος, σκοπός, αναφορά"],["ἀνά","αιτ. (δοτ.)","τόπος, χρόνος, διανομή, τρόπος"],["διά","γεν./αιτ.","γεν.: μέσο, δίοδος / αιτ.: αιτία"],["μετά","γεν./αιτ.","γεν.: συνοδεία / αιτ.: μετά (χρόνο/τόπο)"],["κατά","γεν./αιτ.","εναντίον, καθοδικά / κατά, αναφορά, διανομή"],["ὑπέρ","γεν./αιτ.","υπέρ, υπεράσπιση, αιτία / πάνω από, υπέρβαση"],["ὑπό","γεν./δοτ./αιτ.","ποιητικό αίτιο, αιτία / υποταγή / κάτω από"],["ἐπί","γεν./δοτ./αιτ.","τόπος/χρόνος / αιτία, σκοπός / κίνηση προς"],["περί","γεν./δοτ./αιτ.","αναφορά (γύρω από) / τόπος, χρόνος"],["πρός","γεν./δοτ./αιτ.","προς, αναφορά, σκοπός, φιλικό/εχθρικό"],["παρά","γεν./δοτ./αιτ.","από / κοντά (στάση) / προς, παρά (εναντίωση)"],["ἀμφί","γεν./δοτ./αιτ.","γύρω από, αναφορά, χρόνος (περίπου)"]]},"examples":[{"gr":"Ἡ ἐν Μαραθῶνι μάχη.","an":"\"Η μάχη στον Μαραθώνα.\" <i>ἐν Μαραθῶνι</i> = εμπρόθετος προσδ. του τόπου (στάση). Εδώ ο εμπρόθετος προσδιορίζει το όνομα <i>μάχη</i> ως επιθετικός κατά θέση, αλλά διατηρεί επιρρηματική (τοπική) σημασία."},{"gr":"Διά τόν χειμῶνα οὐκ ἐξέπλευσαν.","an":"\"Εξαιτίας της κακοκαιρίας δεν απέπλευσαν.\" <i>διά τόν χειμῶνα</i> (διά + αιτιατική) = εμπρόθετος προσδ. της αιτίας."},{"gr":"Εἰρήνην ἐποιησάμεθα διά Νικίου.","an":"\"Κάναμε ειρήνη με τη μεσολάβηση του Νικία.\" <i>διά Νικίου</i> (διά + γενική) = εμπρόθετος προσδ. του μέσου. Σύγκρινε με το προηγούμενο: ίδια πρόθεση, άλλη πτώση, άλλη σχέση."},{"gr":"Φαρνάβαζος σύν δώδεκα τριήρεσιν ἧκεν.","an":"\"Ο Φαρνάβαζος ήρθε με δώδεκα τριήρεις.\" <i>σύν δώδεκα τριήρεσιν</i> = εμπρόθετος προσδ. της συνοδείας."},{"gr":"Ὑπέρ τῆς πατρίδος μάχονται.","an":"\"Μάχονται για χάρη της πατρίδας.\" <i>ὑπέρ τῆς πατρίδος</i> (ὑπέρ + γεν.) = εμπρόθετος προσδ. της υπεράσπισης / σκοπού (\"χάριν, υπέρ\")."},{"gr":"Κῦρος... ἐξελαύνει διά τῆς Λυδίας σταθμούς τρεῖς.","an":"Ξεν. Ἀνάβ. 1.2.5 — \"Ο Κύρος προελαύνει μέσα από τη Λυδία τρεις σταθμούς.\" <i>διά τῆς Λυδίας</i> (διά + γεν.) = εμπρόθετος προσδ. του τόπου (δίοδος / διά μέσου)."},{"gr":"Ὑπό τῶν πολεμίων ἀπέθανεν.","an":"(τύπου ιστορ.) \"Σκοτώθηκε από τους εχθρούς.\" <i>ὑπό τῶν πολεμίων</i> (ὑπό + γεν.) = εμπρόθετος του ποιητικού αιτίου — πβ. ὑπό + αιτ. = κίνηση κάτω από."}],"note":"Κλειδί επιτυχίας στους εμπρόθετους: ΠΡΩΤΑ κοίτα την πτώση, ΥΣΤΕΡΑ το νόημα. Η ίδια πρόθεση (διά, κατά, ὑπό, παρά, ἐπί, μετά) αλλάζει σημασία ανάλογα με την πτώση. Π.χ. ὑπό+γεν.=ποιητικό αίτιο/αιτία, ὑπό+δοτ.=υποταγή/κάτω, ὑπό+αιτ.=κίνηση κάτω από."},{"h":"Οι καταχρηστικές προθέσεις και οι ειδικές σχέσεις","body":"<p>Οι <b>καταχρηστικές (νόθες) προθέσεις</b> δεν χρησιμοποιούνται ως α΄ συνθετικό σύνθετων λέξεων και συντάσσονται σχεδόν πάντα με <b>γενική</b>. Είναι σημαντικές γιατί δηλώνουν με ακρίβεια ορισμένες σχέσεις που οι κύριες προθέσεις δηλώνουν λιγότερο καθαρά — κυρίως <b>σκοπό, αιτία, εξαίρεση, όριο</b>.</p><h3>Σκοπού & αιτίας</h3><ul><li><i>ἕνεκα / ἕνεκεν</i> (+ γεν.): δηλώνει <b>σκοπό</b> ή <b>αιτία</b> — <i>τιμῆς ἕνεκα</i> (για χάρη της τιμής).</li><li><i>χάριν</i> (+ γεν.): δηλώνει κυρίως <b>σκοπό</b> — <i>τοῦ μαθεῖν χάριν</i> (με σκοπό να μάθει).</li></ul><h3>Ορίου (τόπου/χρόνου)</h3><ul><li><i>μέχρι(ς), ἄχρι(ς)</i> (+ γεν.): δηλώνουν <b>όριο</b> στον χώρο ή στον χρόνο — <i>μέχρι τοῦ ποταμοῦ</i>, <i>ἄχρι τῆς ἡμέρας</i>.</li></ul><h3>Εξαίρεσης / αποχωρισμού</h3><ul><li><i>ἄνευ</i> (+ γεν.): <b>χωρίς</b> — <i>ἄνευ τῶν συμμάχων</i>.</li><li><i>χωρίς</i> (+ γεν.): <b>χωριστά / εκτός</b>.</li><li><i>πλήν</i> (+ γεν. ή ομοιόπτωτα): <b>εκτός</b> — <i>πλήν ἑνός</i>.</li><li><i>δίχα</i> (+ γεν.): <b>χωρίς / ξεχωριστά</b>.</li></ul><h3>Ειδικές επιρρηματικές σχέσεις</h3><p>Πέρα από τις βασικές, το συντακτικό αναγνωρίζει και ορισμένες πιο εξειδικευμένες σχέσεις, που εκφράζονται κυρίως με εμπρόθετα ή μετοχές/προτάσεις:</p><ul><li><b>Αναγκαστικό αίτιο</b>: η <i>εσωτερική ορμή/συναίσθημα</i> που σπρώχνει σε πράξη — δοτική αιτίας (<i>φόβῳ</i>) ή ὑπό + γεν. (<i>ὑπό τοῦ φόβου</i>).</li><li><b>Προϋπόθεση / όρος</b>: εκφράζεται με <i>ἐπί / ἐφ' ᾧ / ἐφ' ᾧτε</i> + απαρ. ή με υποθετική πρόταση — <i>ἐπί τούτοις</i> (\"με αυτούς τους όρους\").</li><li><b>Εναντίωση / παραχώρηση</b>: <i>παρά</i> + αιτ. (<i>παρά τήν δόξαν</i> = αντίθετα στην προσδοκία), ή εναντιωματική πρόταση/μετοχή.</li><li><b>Αποτέλεσμα</b>: εκφράζεται με <i>ὥστε</i> + απαρ./οριστική (αποτελεσματική πρόταση).</li><li><b>Συμφωνία / κανόνας</b>: <i>κατά</i> + αιτ. (<i>κατά τούς νόμους</i> = σύμφωνα με τους νόμους).</li></ul>","table":{"title":"Καταχρηστικές προθέσεις (+ γενική)","cols":["Πρόθεση","Σχέση","Παράδειγμα"],"rows":[["ἕνεκα/ἕνεκεν","αιτία / σκοπός","τιμῆς ἕνεκα"],["χάριν","σκοπός","τοῦ μαθεῖν χάριν"],["μέχρι(ς)","όριο τόπου/χρόνου","μέχρι τοῦ Ἰσθμοῦ"],["ἄχρι(ς)","όριο τόπου/χρόνου","ἄχρι τῆς Μαλέας"],["ἄνευ","εξαίρεση / χωρίς","ἄνευ τῆς ψήφου"],["χωρίς","εξαίρεση / αποχωρισμός","χωρίς ἀνδρείας"],["πλήν","εξαίρεση","πλήν ἑνός"],["ὡς (+ αιτ.)","κίνηση προς πρόσωπο","ὡς βασιλέα"]]},"examples":[{"gr":"Ἰδίας ἔχθρας ἕνεκα ταῦτα ποιοῦσιν.","an":"\"Τα κάνουν αυτά εξαιτίας προσωπικής έχθρας.\" <i>ἔχθρας ἕνεκα</i> = εμπρόθετος (καταχρηστικός) προσδ. της αιτίας."},{"gr":"Οἱ ξύμμαχοι μέχρι τοῦ Ἰσθμοῦ ἦλθον.","an":"\"Οι σύμμαχοι έφτασαν μέχρι τον Ισθμό.\" <i>μέχρι τοῦ Ἰσθμοῦ</i> = εμπρόθετος προσδ. του τόπου (όριο)."},{"gr":"Οὐδείς ἀποθνῄσκει ἄνευ τῆς ὑμετέρας ψήφου.","an":"\"Κανείς δεν θανατώνεται χωρίς τη δική σας ψήφο.\" <i>ἄνευ τῆς ψήφου</i> = εμπρόθετος προσδ. της εξαίρεσης / προϋπόθεσης (χωρίς)."},{"gr":"Ἐπί τούτοις τήν εἰρήνην ἐποιήσαντο.","an":"\"Με αυτούς τους όρους έκαναν την ειρήνη.\" <i>ἐπί τούτοις</i> = εμπρόθετος προσδ. της προϋπόθεσης (όρου)."},{"gr":"Ὑπό τοῦ φόβου ἔφυγον.","an":"\"Από τον φόβο τους τράπηκαν σε φυγή.\" <i>ὑπό τοῦ φόβου</i> = εμπρόθετος προσδ. του αναγκαστικού αιτίου (το συναίσθημα που τους ώθησε)."},{"gr":"Ἦλθον ὡς βασιλέα οἱ πρέσβεις.","an":"(τύπου ιστορ.) \"Οι πρέσβεις πήγαν στον βασιλιά.\" <i>ὡς βασιλέα</i> = εμπρόθετος (καταχρηστικός) προσδ. του τόπου (κίνηση προς πρόσωπο — μόνο με πρόσωπα)."},{"gr":"Τοῦ σώματος ἕνεκα τῆς ὑγιείας γυμνάζονται.","an":"(τύπου) \"Γυμνάζονται για χάρη της υγείας του σώματος.\" <i>τῆς ὑγιείας ἕνεκα</i> = εμπρόθετος προσδ. του σκοπού (ἕνεκα + γεν.)."}],"note":"Διάκριση εξωτερικού-εσωτερικού αιτίου: η ΑΙΤΙΑ είναι εξωτερικός λόγος (διά τόν χειμῶνα)· το ΑΝΑΓΚΑΣΤΙΚΟ ΑΙΤΙΟ είναι εσωτερική ψυχική ορμή (ὑπό φόβου, χαρᾷ). Η δοτική αιτίας σε ρήματα ψυχικού πάθους είναι το πιο τυπικό αναγκαστικό αίτιο."},{"h":"Συγκεντρωτικός πίνακας: όλες οι σχέσεις × όλοι οι τρόποι","body":"<p>Ο παρακάτω πίνακας συγκεφαλαιώνει ολόκληρο το κεφάλαιο: για κάθε <b>επιρρηματική σχέση</b> δίνει τους κύριους <b>τρόπους εκφοράς</b> (επίρρημα / πλάγια πτώση / εμπρόθετο), ώστε στην ανάλυση να μπορείς αμέσως να συνδυάσεις τα δύο επίπεδα. Είναι το εργαλείο που πρέπει να έχεις μπροστά σου σε κάθε άσκηση αναγνώρισης.</p><h3>Πώς να αναλύεις βήμα-βήμα</h3><ol><li><b>Βρες το ρήμα</b> (ή τη λέξη) που προσδιορίζεται.</li><li><b>Κάνε την ερώτηση</b>: πού; πότε; πώς; πόσο; γιατί; για ποιον σκοπό; με τι; με ποιον; ως προς τι; — αυτό δίνει τη <i>σχέση</i>.</li><li><b>Δες τη μορφή</b>: επίρρημα, σκέτη πλάγια πτώση, ή πρόθεση + πτώση; — αυτό δίνει τον <i>τρόπο εκφοράς</i>.</li><li><b>Διατύπωσε</b>: \"επιρρηματικός προσδιορισμός <i>της X σχέσης</i>, εκφερόμενος <i>με Y</i>\".</li></ol><p>Με αυτόν τον πίνακα και τη μεθοδολογία, ο μαθητής μπορεί να αναγνωρίσει και να αιτιολογήσει κάθε επιρρηματικό προσδιορισμό που θα συναντήσει σε αττικό κείμενο.</p>","table":{"title":"Συγκεντρωτικός πίνακας επιρρηματικών σχέσεων","cols":["Σχέση","Επίρρημα","Πλάγια πτώση","Εμπρόθετο"],"rows":[["Τόπος (στάση)","ἐκεῖ, οἴκοι","δοτ. τόπου (Μαραθῶνι)","ἐν+δοτ., ἐπί+γεν."],["Τόπος (κίνηση προς)","ἐκεῖσε, οἴκαδε","αιτ. (σπάνια)","εἰς+αιτ., πρός+αιτ., ἐπί+αιτ."],["Τόπος (κίνηση από)","ἐκεῖθεν, οἴκοθεν","γεν. (σπάνια)","ἐκ/ἐξ+γεν., ἀπό+γεν., παρά+γεν."],["Χρόνος","νῦν, τότε, ἀεί","γεν. (νυκτός), δοτ. (τῇ ἡμέρᾳ), αιτ. (τρία ἔτη)","ἐν+δοτ., διά+γεν., εἰς+αιτ., πρό+γεν."],["Τρόπος","καλῶς, οὕτω","δοτ. (βίᾳ), αιτ. (δίκην)","σύν+δοτ., μετά+γεν., κατά+αιτ."],["Ποσό / μέτρο","πάνυ, σφόδρα, λίαν","γεν. (αξίας), δοτ. (πολλῷ)","περί+αιτ. (περίπου)"],["Αιτία","—","γεν. αιτίας, δοτ. αιτίας","διά+αιτ., ὑπό+γεν., ἕνεκα+γεν."],["Σκοπός","—","αιτ. σκοπού (τί;), γεν. έναρθρου απαρ.","εἰς+αιτ., ἐπί+δοτ., ἕνεκα/χάριν+γεν."],["Αναφορά","—","αιτ. αναφοράς (τήν φύσιν), δοτ. αναφοράς","κατά+αιτ., περί+γεν., πρός+αιτ."],["Όργανο / μέσο","—","δοτ. οργάνου (λίθοις)","διά+γεν., ἐκ+γεν."],["Συνοδεία","—","δοτ. συνοδείας (στρατῷ)","σύν+δοτ., μετά+γεν."],["Ποινή","—","γεν. ποινής, αιτ. ποινής","—"],["Αξία","—","γεν. αξίας (πολλοῦ)","ἀντί+γεν., περί+γεν."],["Αναγκαστικό αίτιο","—","δοτ. αιτίας (φόβῳ)","ὑπό+γεν. (ὑπό φόβου)"],["Προϋπόθεση / όρος","—","—","ἐπί+δοτ. (ἐπί τούτοις)"],["Εναντίωση","—","—","παρά+αιτ. (παρά δόξαν)"],["Συμφωνία / κανόνας","—","—","κατά+αιτ. (κατά τούς νόμους)"]]},"examples":[{"gr":"Κατά τούς νόμους τήν δίκην ἔκριναν.","an":"\"Έκριναν τη δίκη σύμφωνα με τους νόμους.\" <i>κατά τούς νόμους</i> = εμπρόθετος προσδ. της συμφωνίας / του κανόνα (κατά + αιτ.)."},{"gr":"Παρά τήν δόξαν ἐνίκησαν.","an":"\"Νίκησαν αντίθετα προς την προσδοκία.\" <i>παρά τήν δόξαν</i> = εμπρόθετος προσδ. της εναντίωσης (παρά + αιτ.)."},{"gr":"Τοῦ μαθεῖν χάριν ἦλθεν εἰς Ἀθήνας.","an":"Σύνθετη ανάλυση: <i>τοῦ μαθεῖν χάριν</i> = εμπρόθετος προσδ. του σκοπού (χάριν + γεν. έναρθρου απαρ.)· <i>εἰς Ἀθήνας</i> = εμπρόθετος προσδ. του τόπου (κίνηση προς). Ένα ρήμα, δύο επιρρηματικοί προσδιορισμοί διαφορετικής σχέσης."},{"gr":"Νυκτός βίᾳ διά τοῦ πεδίου ἐς τήν πόλιν εἰσῆλθον.","an":"Σύνθετη ανάλυση τεσσάρων σχέσεων: <i>νυκτός</i> = γεν. χρόνου· <i>βίᾳ</i> = δοτ. τρόπου· <i>διά τοῦ πεδίου</i> = εμπρόθ. τόπου (δίοδος)· <i>ἐς τήν πόλιν</i> = εμπρόθ. τόπου (κίνηση προς)."},{"gr":"Πολλῷ θᾶττον ἤ ἤλπιζον ἀφίκοντο.","an":"\"Έφτασαν πολύ γρηγορότερα απ' ό,τι περίμεναν.\" <i>πολλῷ</i> = δοτ. ποσού (μέτρου διαφοράς) στο συγκριτικό επίρρημα <i>θᾶττον</i> (τρόπου)."}],"note":"Η ίδια σχέση εκφράζεται με πολλούς τρόπους (π.χ. ο τόπος-στάση: ἐκεῖ / Μαραθῶνι / ἐν Ἀθήναις) και ο ίδιος τύπος καλύπτει πολλές σχέσεις (π.χ. η αιτιατική: αναφορά, χρόνο, τόπο, τρόπο, αιτία, σκοπό, ποινή). Γι' αυτό η ασφαλής μέθοδος είναι ΠΑΝΤΑ: πρώτα η ερώτηση (σχέση), μετά η μορφή (τρόπος)."}]);
  T("syn-emprothetoi", [{"h":"Τι είναι ο εμπρόθετος προσδιορισμός — η έννοια και η δομή του","body":"<p><b>Εμπρόθετος προσδιορισμός</b> ονομάζεται ο επιρρηματικός προσδιορισμός που σχηματίζεται από μια <b>πρόθεση</b> μαζί με μια λέξη σε <b>πλάγια πτώση</b> (γενική, δοτική ή αιτιατική). Το σύνολο «πρόθεση + όνομα/αντωνυμία/μετοχή» λειτουργεί ως μία ενιαία συντακτική μονάδα και προσδιορίζει συνήθως το ρήμα, σπανιότερα όμως και όνομα ή επίθετο.</p><h3>Από τι αποτελείται</h3><p>Η λέξη που ακολουθεί την πρόθεση (ο λεγόμενος <i>όρος της πρόθεσης</i> ή <i>αντικείμενο της πρόθεσης</i>) μπορεί να είναι:</p><ul><li><b>ουσιαστικό</b>: <i>ἐν τῇ πόλει</i></li><li><b>αντωνυμία</b>: <i>περί τούτων</i>, <i>πρός ἐμέ</i></li><li><b>επίθετο / μετοχή ουσιαστικοποιημένη</b>: <i>ἐκ τῶν παρόντων</i></li><li><b>επίρρημα</b> (σπάνια): <i>ἐς αὔριον</i>, <i>ἐκ τοῦ ἐναντίον</i></li></ul><h3>Τι σημαίνει «πρόθεση»</h3><p>Οι <b>προθέσεις</b> είναι άκλιτες λέξεις που, κατά την προέλευσή τους, ήταν <i>τοπικά επιρρήματα</i>. Από τη βασική τοπική σημασία τους αναπτύχθηκαν, με μεταφορά, και οι αφηρημένες σχέσεις (χρόνος, αιτία, σκοπός, τρόπος, μέσο κ.λπ.). Γι' αυτό για κάθε πρόθεση πρέπει να γνωρίζουμε τρία πράγματα: <b>(α)</b> ποια/ές πτώση/εις συντάσσεται, <b>(β)</b> ποια η βασική (τοπική) της σημασία, <b>(γ)</b> ποιες επιρρηματικές σχέσεις εκφράζει.</p><h3>Εισαγωγή & εκφορά — η ορολογία</h3><p>Στη σχολική ανάλυση λέμε ότι ο εμπρόθετος <b>εισάγεται</b> με την πρόθεση και <b>εκφέρεται</b> με τη συγκεκριμένη πτώση. Π.χ. στο <i>διά τόν πόλεμον</i> ο εμπρόθετος <i>εισάγεται</i> με το <i>διά</i> και <i>εκφέρεται</i> με αιτιατική, δηλώνοντας αιτία.</p>","examples":[{"gr":"Ἡ ἐν Σαλαμῖνι ναυμαχία ἐγένετο.","an":"Εμπρόθετος <i>ἐν Σαλαμῖνι</i> (πρόθεση <i>ἐν</i> + δοτική) ως επιθετικός προσδιορισμός στο <i>ναυμαχία</i> = δηλώνει στάση σε τόπο: «η ναυμαχία στη Σαλαμίνα»."},{"gr":"Ἀλκιβιάδης ἔπλευσεν εἰς Σάμον.","an":"Εμπρόθετος <i>εἰς Σάμον</i> (<i>εἰς</i> + αιτιατική) ως επιρρηματικός προσδιορισμός της κίνησης σε τόπο στο <i>ἔπλευσεν</i> = «έπλευσε προς τη Σάμο»."},{"gr":"Διά τόν πόλεμον οἱ Ἀθηναῖοι ἐδυστύχησαν.","an":"<i>Διά τόν πόλεμον</i> (<i>διά</i> + αιτιατική) = εμπρόθετος της αιτίας: «εξαιτίας του πολέμου»."},{"gr":"Ὁρμώμενοι ἐκ Χερρονήσου ἐστράτευον.","an":"(τύπου Θουκ.) <i>ἐκ Χερρονήσου</i> (<i>ἐκ</i> + γεν.) = εμπρόθετος της τοπικής αφετηρίας στο ρήμα· ο όρος της πρόθεσης είναι ουσιαστικό-τοπωνύμιο."},{"gr":"Περί τούτων πρός ἐμέ διελέχθη.","an":"Δύο εμπρόθετοι με αντωνυμία ως όρο: <i>περί τούτων</i> (<i>περί</i> + γεν.) = αναφορά, <i>πρός ἐμέ</i> (<i>πρός</i> + αιτ.) = κατεύθυνση/σχέση προς πρόσωπο."}],"note":"Προσοχή στη διαφορά από τον απλό (όχι εμπρόθετο) επιρρηματικό προσδιορισμό: όταν η πλάγια πτώση δεν συνοδεύεται από πρόθεση (π.χ. <i>νυκτός</i> = «τη νύχτα», γενική του χρόνου), μιλάμε για <b>μονολεκτικό</b> επιρρηματικό προσδιορισμό, όχι για εμπρόθετο."},{"h":"Κατηγορίες προθέσεων: κύριες & καταχρηστικές — μονόπτωτες, δίπτωτες, τρίπτωτες","body":"<h3>Α. Κύριες προθέσεις (18)</h3><p>Κύριες λέγονται οι προθέσεις που χρησιμοποιούνται <b>και στη σύνταξη</b> (μπροστά από πλάγια πτώση) <b>και στη σύνθεση</b> (ως α΄ συνθετικό σύνθετων λέξεων, κυρίως ρημάτων). Π.χ. <i>ἐκ</i> → <i>ἐκβάλλω</i>· <i>πρός</i> → <i>προσφέρω</i>.</p><ul><li><b>Μονοσύλλαβες:</b> ἐν, εἰς (ἐς), ἐκ (ἐξ), πρό, πρός, σύν (ξύν)</li><li><b>Δισύλλαβες:</b> ἀνά, διά, κατά, μετά, παρά, ἀμφί, ἀντί, ἐπί, περί, ἀπό, ὑπό, ὑπέρ</li></ul><h3>Β. Καταχρηστικές προθέσεις</h3><p>Καταχρηστικές λέγονται οι προθέσεις που χρησιμοποιούνται <b>μόνο στη σύνταξη</b>, ποτέ στη σύνθεση. Είναι: <i>ἄνευ, ἄχρι(ς), ἕνεκα/ἕνεκεν, μέχρι(ς), πλήν, χάριν, χωρίς, δίχα, ἄντικρυς, ὡς</i> και τα μοριακά <i>νή, μά</i> (στους όρκους). Όλες συντάσσονται με γενική, εκτός από το <i>ὡς</i> (+ αιτιατική, μόνο για πρόσωπα).</p><h3>Διάκριση κύριων προθέσεων ως προς τις πτώσεις</h3><p>Οι κύριες προθέσεις ταξινομούνται και ανάλογα με το πλήθος των πτώσεων που δέχονται:</p><ul><li><b>Μονόπτωτες</b> (μία πτώση): ἀντί, ἀπό, ἐκ, πρό, σύν, ἐν, εἰς</li><li><b>Δίπτωτες</b> (δύο πτώσεις): ἀνά, διά, κατά, ὑπέρ, μετά</li><li><b>Τρίπτωτες</b> (τρεις πτώσεις): ἀμφί, ἐπί, παρά, περί, πρός, ὑπό</li></ul><p>Κανόνας-κλειδί: η <b>γενική</b> δηλώνει συχνά απομάκρυνση/προέλευση («από»), η <b>δοτική</b> στάση/συνύπαρξη («σε/μαζί»), η <b>αιτιατική</b> κίνηση/κατεύθυνση/έκταση («προς»). Αυτή η «λογική των πτώσεων» εξηγεί την πολυσημία των δίπτωτων και τρίπτωτων.</p>","table":{"title":"Συνοπτική ταξινόμηση όλων των κύριων προθέσεων","cols":["Κατηγορία","Προθέσεις","Πτώση/-εις"],"rows":[["Μονόπτωτες με γενική","ἀντί, ἀπό, ἐκ/ἐξ, πρό","γενική"],["Μονόπτωτη με δοτική","ἐν, σύν","δοτική"],["Μονόπτωτη με αιτιατική","εἰς/ἐς","αιτιατική"],["Δίπτωτες (γεν. + αιτ.)","διά, κατά, ὑπέρ, μετά","γενική, αιτιατική"],["Δίπτωτη (αιτ., σπάν. δοτ.)","ἀνά","αιτιατική (δοτ. ποιητ.)"],["Τρίπτωτες (γεν., δοτ., αιτ.)","ἀμφί, ἐπί, παρά, περί, πρός, ὑπό","γενική, δοτική, αιτιατική"],["Καταχρηστικές","ἄνευ, ἄχρι, ἕνεκα, μέχρι, πλήν, χάριν, χωρίς, δίχα","γενική"],["Καταχρηστική","ὡς","αιτιατική (πρόσωπα)"]]},"note":"Μνημονικός κανόνας: σύν + δοτική, ἐν + δοτική (στάση/συνύπαρξη)· εἰς + αιτιατική (κίνηση)· οι τέσσερις «-ό/-ί» μονόπτωτες της απομάκρυνσης (ἀντί, ἀπό, πρό, ἐκ) θέλουν πάντοτε γενική."},{"h":"Οι μονόπτωτες κύριες προθέσεις: ἀντί, ἀπό, ἐκ, πρό (+ γενική)","body":"<p>Οι τέσσερις αυτές μονόπτωτες δέχονται πάντοτε <b>γενική</b> και η βασική τους σημασία συνδέεται με την έννοια της προέλευσης, της απομάκρυνσης ή του «μπροστά / αντί».</p><h3>ἀντί + γενική</h3><p>Βασική σημασία: «απέναντι». Σχέσεις: <b>αντί / αντικατάσταση</b> (το συχνότερο), <b>εναντίωση</b>, <b>ισότητα/αντιστοιχία</b>, <b>αιτία</b>.</p><h3>ἀπό + γενική</h3><p>Βασική σημασία: «από (μακριά από την επιφάνεια)». Σχέσεις: <b>τόπος-απομάκρυνση/προέλευση/απόσταση</b>, <b>χρόνος</b> (αφετηρία), <b>αιτία</b>, <b>ύλη</b>, <b>μέσο/όργανο</b>, <b>τρόπος</b>, <b>καταγωγή</b>, <b>διαιρεμένο όλο</b>, σπάνια <b>ποιητικό αίτιο</b>.</p><h3>ἐκ / ἐξ + γενική</h3><p>(τύπος <i>ἐξ</i> πριν από φωνήεν). Βασική σημασία: «από μέσα προς τα έξω». Σχέσεις: <b>τόπος-προέλευση/έξοδος</b>, <b>χρόνος</b> (αφετηρία, «αμέσως μετά»), <b>αιτία</b>, <b>ύλη</b>, <b>καταγωγή</b>, <b>μέσο</b>, <b>τρόπος</b>, <b>σύμφωνα με</b>, <b>διαιρεμένο όλο</b>.</p><h3>πρό + γενική</h3><p>Βασική σημασία: «μπροστά από». Σχέσεις: <b>τόπος</b> (εμπρός από), <b>χρόνος</b> (πριν), <b>υπεράσπιση / υπέρ</b>, <b>προτίμηση</b> (προτιμώ κάτι πριν/αντί από).</p>","examples":[{"gr":"Πολέμιος ἀντί φίλου κατέστη.","an":"<i>ἀντί φίλου</i> (ἀντί + γεν.) = αντί/αντικατάσταση: «έγινε εχθρός αντί φίλου»."},{"gr":"Ἀντί πολλῶν χρημάτων τήν ἀρετήν αἱροῦνται.","an":"<i>ἀντί πολλῶν χρημάτων</i> = αντιστοιχία/ανταλλαγή: «προτιμούν την αρετή αντί για πολλά χρήματα»."},{"gr":"Ἐκ τούτου διαβαίνουσι τόν ποταμόν εἰς τό Βυζάντιον.","an":"<i>ἐκ τούτου</i> = τόπος-αφετηρία/προέλευση («από εκεί»)· πρβλ. <i>εἰς τό Βυζάντιον</i> = κίνηση-τέρμα."},{"gr":"Ἀπό τούτου τοῦ τολμήματος ἐπῃνέθη.","an":"<i>ἀπό τούτου τοῦ τολμήματος</i> (ἀπό + γεν.) = αιτία: «για/εξαιτίας αυτού του τολμηρού έργου επαινέθηκε»."},{"gr":"Πρό τῶν πυλῶν ἐτάχθησαν οἱ ὁπλῖται.","an":"<i>πρό τῶν πυλῶν</i> (πρό + γεν.) = τόπος: «μπροστά από τις πύλες»."},{"gr":"Πρό τῆς μάχης θύουσι τοῖς θεοῖς.","an":"<i>πρό τῆς μάχης</i> = χρόνος (το πρότερο): «πριν από τη μάχη»."},{"gr":"Ἀντί πολέμου εἰρήνην εἱλόμεθα.","an":"(τύπου Ἰσοκρ.) <i>ἀντί πολέμου</i> (ἀντί + γεν.) = αντικατάσταση/εναλλαγή: «αντί για πόλεμο διαλέξαμε ειρήνη»."},{"gr":"Ἀπό τῆς θαλάττης οὐ πολύ ἀπέχει ἡ πόλις.","an":"(τύπου Ξεν.· πρβλ. Smyth §1684 «at a distance from the sea») <i>ἀπό τῆς θαλάττης</i> (ἀπό + γεν.) = απόσταση/απομάκρυνση: «η πόλη δεν απέχει πολύ από τη θάλασσα»."},{"gr":"Ἐκ παίδων εὐθύς ἐπαιδεύθη.","an":"(πρβλ. Smyth, «ἐκ παιδός / ἐκ παίδων = from boyhood») <i>ἐκ παίδων</i> (ἐκ + γεν.) = χρονική αφετηρία: «από την παιδική του ηλικία»."},{"gr":"Πρό τῆς πατρίδος ἀποθνῄσκειν καλόν ἐστιν.","an":"<i>πρό τῆς πατρίδος</i> (πρό + γεν.) = υπεράσπιση/υπέρ: «είναι ωραίο να πεθαίνει κανείς για την πατρίδα»."}],"note":"Μην συγχέεις το ἀπό (απομάκρυνση από επιφάνεια/εξωτερικό σημείο) με το ἐκ (έξοδος από το εσωτερικό): <i>ἀπό τῆς τραπέζης</i> «από (πάνω από) το τραπέζι», αλλά <i>ἐκ τῆς οἰκίας</i> «από (μέσα από) το σπίτι». Επίσης η καταγωγή λέγεται και με τα δύο: <i>ἐκ βασιλέων</i> / <i>ἀπό γένους</i>."},{"h":"Οι μονόπτωτες ἐν, σύν (+ δοτική) και εἰς (+ αιτιατική)","body":"<p>Εδώ φαίνεται καθαρά η αντίθεση <b>δοτική = στάση/συνύπαρξη</b> ↔ <b>αιτιατική = κίνηση</b>.</p><h3>ἐν + δοτική</h3><p>Βασική σημασία: «μέσα σε, σε». Σχέσεις: <b>τόπος-στάση</b> (μέσα, ανάμεσα, κοντά, πάνω σε), <b>χρόνος</b> (μέσα σε χρονικό διάστημα), <b>όργανο/μέσο</b>, <b>τρόπος</b>, <b>συνοδεία/μαζί με</b>, <b>αναφορά</b>, <b>κατάσταση</b>, <b>εξάρτηση</b> («εξαρτάται από»).</p><h3>σύν (ξύν) + δοτική</h3><p>Βασική σημασία: «μαζί με». Σχέσεις: <b>συνοδεία / συνεργασία</b>, <b>τρόπος</b>, <b>μέσο</b>, <b>σύμφωνα με / με τη βοήθεια</b>. Στην πεζογραφία είναι σπανιότερη από το <i>μετά + γενική</i>· συχνή σε Ξενοφώντα και ποίηση. Χαρακτηριστική η φράση <i>σύν θεῷ / σύν θεοῖς</i> «με τη βοήθεια του θεού».</p><h3>εἰς / ἐς + αιτιατική</h3><p>Βασική σημασία: «προς το εσωτερικό, σε». Σχέσεις: <b>τόπος-κίνηση/κατεύθυνση</b> (μέσα, προς, ανάμεσα, ως όριο), <b>χρόνος</b> (όριο, «μέχρι / για»), <b>εχθρική κατεύθυνση</b> (εναντίον), <b>αναφορά / σχέση</b>, <b>σκοπός</b>, <b>ποσό / αριθμός κατά προσέγγιση</b>, <b>κατάσταση</b>, <b>διανομή</b> («κατά»).</p>","examples":[{"gr":"Ἦσαν ἐν τῷ στρατοπέδῳ.","an":"<i>ἐν τῷ στρατοπέδῳ</i> (ἐν + δοτ.) = στάση σε τόπο: «ήταν στο στρατόπεδο»."},{"gr":"Ἐν πέντε ἡμέραις ἀφίκετο.","an":"<i>ἐν πέντε ἡμέραις</i> = χρόνος (μέσα σε διάστημα): «έφτασε μέσα σε πέντε ημέρες»."},{"gr":"Ἐν τοῖς θεοῖς ἐστι τό τέλος.","an":"<i>ἐν τοῖς θεοῖς</i> = εξάρτηση: «το τέλος (της υπόθεσης) εξαρτάται από τους θεούς»."},{"gr":"Σύν τοῖς ὅπλοις ἐχώρουν.","an":"<i>σύν τοῖς ὅπλοις</i> (σύν + δοτ.) = συνοδεία/τρόπος: «προχωρούσαν με τα όπλα τους»."},{"gr":"Σύν θεῷ εἰρήσεται.","an":"<i>σύν θεῷ</i> = μέσο/βοήθεια: «θα ειπωθεί με τη βοήθεια του θεού»."},{"gr":"Ἀφίκοντο εἰς τάς Ἀθήνας.","an":"<i>εἰς τάς Ἀθήνας</i> (εἰς + αιτ.) = κίνηση-τέρμα: «έφτασαν στην Αθήνα»."},{"gr":"Παρεσκευάζοντο εἰς τόν πόλεμον.","an":"<i>εἰς τόν πόλεμον</i> = σκοπός/αναφορά: «προετοιμάζονταν για τον πόλεμο»."},{"gr":"Ἐν τῷ ποταμῷ ἔπεσον.","an":"(τύπου Ξεν.) <i>ἐν τῷ ποταμῷ</i> (ἐν + δοτ.) = τόπος-στάση («μέσα στο ποτάμι»): «έπεσαν στο ποτάμι»."},{"gr":"Ἐπορεύοντο εἰς Σάρδεις.","an":"(τύπου Ξεν.) <i>εἰς Σάρδεις</i> (εἰς + αιτ.) = κίνηση-κατεύθυνση: «βάδιζαν προς τις Σάρδεις»."},{"gr":"Σύν τοῖς θεοῖς πειρασόμεθα ἀμύνασθαι.","an":"(τύπου Ξεν.) <i>σύν τοῖς θεοῖς</i> (σύν + δοτ.) = μέσο/βοήθεια: «με τη βοήθεια των θεών θα προσπαθήσουμε να αμυνθούμε» — χαρακτηριστικό του Ξενοφώντα, που προτιμά το σύν."}],"note":"Στην αρχαία αττική το ἐν δηλώνει <b>μόνο στάση</b> (ποτέ κίνηση «μέσα σε»)· για την κίνηση χρησιμοποιείται πάντοτε το εἰς. Αυτό αντιστρέφεται στα νέα ελληνικά (όπου το «σε» καλύπτει και τα δύο), και είναι κλασική παγίδα μετάφρασης."},{"h":"Οι δίπτωτες: διά, κατά, ὑπέρ — πολυσημία ανά πτώση","body":"<p>Στις δίπτωτες η <b>πτώση αλλάζει τη σημασία</b>. Γενικός οδηγός: γενική → προέλευση/διαμέσου/υπέρ· αιτιατική → κίνηση/έκταση/αιτία.</p><h3>διά</h3><p><b>+ γενική:</b> τόπος (διαμέσου, «μέσα από»), <b>χρόνος</b> (διάρκεια ή διάστημα «κάθε τόσο»), <b>μέσο/όργανο</b> («με τη μεσολάβηση»), <b>τρόπος</b>, <b>απόσταση/μεσοδιάστημα</b>. <b>+ αιτιατική:</b> <b>αιτία</b> (το κατεξοχήν!), σπανιότερα <b>σκοπός</b>, και (στον Όμηρο) τοπικό «διαμέσου».</p><h3>κατά</h3><p><b>+ γενική:</b> τόπος (κίνηση από πάνω προς τα κάτω «κάτω από», ή «πάνω σε»), <b>εναντίωση</b> (εναντίον — π.χ. <i>λέγω κατά τινος</i>), <b>αναφορά</b> («για»). <b>+ αιτιατική:</b> τόπος (κατά μήκος, καθ' όλη την έκταση, αντικρύ), <b>χρόνος</b> (κατά τη διάρκεια / περίπου), <b>τρόπος</b>, <b>διανομή / κατανομή</b> (<i>καθ' ἡμέραν</i>), <b>συμφωνία</b> (κατά / σύμφωνα με), <b>αναφορά</b>, <b>αιτία/σκοπός</b>, <b>ποσό κατά προσέγγιση</b>.</p><h3>ὑπέρ</h3><p><b>+ γενική:</b> τόπος (πάνω από, ψηλότερα), <b>υπεράσπιση / υπέρ</b> (το συχνότερο: «για χάρη / για το συμφέρον»), <b>αντί / εκ μέρους</b>, <b>αιτία</b>, <b>αναφορά</b> («για»). <b>+ αιτιατική:</b> τόπος (πάνω από, πέρα από), <b>υπέρβαση ορίου / μέτρου</b> (περισσότερο από).</p>","table":{"title":"Πολυσημία των δίπτωτων ανά πτώση","cols":["Πρόθεση","+ Γενική","+ Αιτιατική"],"rows":[["διά","διαμέσου, χρόνος-διάρκεια, μέσο, τρόπος","αιτία (κυρίως), σκοπός"],["κατά","κάτω από / πάνω σε, εναντίον, αναφορά","κατά μήκος, χρόνος~, τρόπος, διανομή, συμφωνία, αναφορά, αιτία"],["ὑπέρ","πάνω από, υπέρ/υπεράσπιση, αιτία, αναφορά","πάνω/πέρα από, υπέρβαση μέτρου"]]},"examples":[{"gr":"Ἐπορεύοντο διά τῆς πολεμίας.","an":"<i>διά τῆς πολεμίας</i> (διά + γεν.) = τόπος-διαμέσου: «προχωρούσαν μέσα από την εχθρική χώρα»."},{"gr":"Διά νυκτός ἐπορεύοντο.","an":"<i>διά νυκτός</i> (διά + γεν.) = χρόνος-διάρκεια: «βάδιζαν όλη τη νύχτα / κατά τη διάρκεια της νύχτας»."},{"gr":"Δι' ἀγγέλου ἐδήλωσε.","an":"<i>δι' ἀγγέλου</i> (διά + γεν.) = μέσο: «το φανέρωσε με αγγελιαφόρο»."},{"gr":"Διά τόν χειμῶνα οὐκ ἀπέπλευσαν.","an":"<i>διά τόν χειμῶνα</i> (διά + αιτ.) = αιτία: «εξαιτίας της κακοκαιρίας δεν απέπλευσαν»."},{"gr":"Κατά τῶν πετρῶν ἐρρίπτουν ἑαυτούς.","an":"<i>κατά τῶν πετρῶν</i> (κατά + γεν.) = τόπος (από πάνω προς τα κάτω): «ρίχνονταν από τους βράχους»."},{"gr":"Δημοσθένης εἶπε κατά Φιλίππου.","an":"<i>κατά Φιλίππου</i> (κατά + γεν.) = εναντίωση: «μίλησε εναντίον του Φιλίππου»."},{"gr":"Καθ' ἡμέραν ταῦτα ποιοῦσιν.","an":"<i>καθ' ἡμέραν</i> (κατά + αιτ.) = διανομή/χρόνος: «καθημερινά / κάθε μέρα»."},{"gr":"Ὑπέρ τῆς πατρίδος μάχονται.","an":"<i>ὑπέρ τῆς πατρίδος</i> (ὑπέρ + γεν.) = υπεράσπιση/υπέρ: «αγωνίζονται για την πατρίδα»."},{"gr":"Ὑπέρ τετταράκοντα ἔτη γεγονώς.","an":"<i>ὑπέρ τετταράκοντα ἔτη</i> (ὑπέρ + αιτ.) = υπέρβαση μέτρου: «που έχει περάσει τα σαράντα χρόνια»."},{"gr":"Ἤλπιζον ὡς διά φιλίας τῆς χώρας πορεύσεσθαι.","an":"Ξεν. Ἀνάβ. (περί Καρδούχων) — <i>διά φιλίας (χώρας)</i> (διά + γεν.) = τρόπος/τόπος-διαμέσου: «έλπιζαν να περάσουν σαν μέσα από φιλική χώρα»."},{"gr":"Κατά Ἐρατοσθένους ὁ λόγος ἐγράφη.","an":"(Λυσ. «Κατά Ἐρατοσθένους») <i>κατά Ἐρατοσθένους</i> (κατά + γεν.) = εναντίωση: τίτλος δικανικού λόγου «εναντίον του Ερατοσθένη»."},{"gr":"Ὑπέρ τῶν στρατιωτῶν ἀπελογήσατο.","an":"(τύπου δικαν.· πρβλ. <i>ὑπέρ τῶν...</i> = «εκ μέρους / για χάρη») <i>ὑπέρ τῶν στρατιωτῶν</i> (ὑπέρ + γεν.) = υπεράσπιση/εκ μέρους: «μίλησε υπερασπιζόμενος τους στρατιώτες»."}],"note":"Κλασική παγίδα: <i>κατά + γενική</i> = «εναντίον» (εχθρικό), ενώ <i>ὑπέρ + γενική</i> = «υπέρ / για χάρη» (ευνοϊκό). Είναι το αντιθετικό ζεύγος των δικανικών λόγων: <i>λόγος κατά Ἐρατοσθένους</i> ↔ <i>λόγος ὑπέρ τῶν στρατιωτῶν</i>."},{"h":"Η δίπτωτη ἀνά και η τρίπτωτη μετά","body":"<h3>ἀνά + αιτιατική</h3><p>(στους ποιητές και + δοτική, με σημασία «πάνω σε»). Βασική σημασία: «προς τα πάνω». Σχέσεις με αιτιατική: <b>τόπος</b> (προς τα πάνω, καθ' όλη την έκταση «σε όλο»), <b>χρόνος</b> (διάρκεια, <i>ἀνά πᾶσαν ἡμέραν</i>), <b>τρόπος</b>, <b>διανομή / κατανομή</b> (<i>ἀνά ἑκατόν</i> «ανά εκατό»).</p><h3>μετά (τρίπτωτη)</h3><p><b>+ γενική:</b> τόπος (ανάμεσα, μεταξύ), <b>χρόνος</b> (το σύγχρονο, «κατά τη διάρκεια»), <b>συνοδεία / συμμετοχή / μαζί με</b> (η κατεξοχήν σημασία στην πεζογραφία — αντικαθιστά το <i>σύν</i>), <b>τρόπος</b> (<i>μετά σπουδῆς</i> «βιαστικά»). <b>+ δοτική:</b> τόπος (ανάμεσα) — <b>μόνο ποιητικό</b>, σπάνιο. <b>+ αιτιατική:</b> <b>χρόνος</b> (το ύστερο, «μετά / έπειτα από» — η κατεξοχήν σημασία!), <b>τόπος</b> (πίσω από / ανάμεσα), <b>σειρά / τάξη</b> (<i>μετά τούς θεούς</i> «αμέσως μετά τους θεούς»).</p>","table":{"title":"Πολυσημία της μετά ανά πτώση","cols":["Πτώση","Κύριες σχέσεις","Παράδειγμα"],"rows":[["+ γενική","συνοδεία/μαζί με, σύγχρονος χρόνος, τρόπος","μετά τῶν φίλων = μαζί με τους φίλους"],["+ δοτική (ποιητ.)","τόπος: ανάμεσα","μετά ἀθανάτοισι = ανάμεσα στους αθανάτους"],["+ αιτιατική","ύστερος χρόνος (μετά), σειρά/τάξη","μετά τήν μάχην = μετά τη μάχη"]]},"examples":[{"gr":"Ἀνά τό στρατόπεδον σιγή πολλή ἦν.","an":"<i>ἀνά τό στρατόπεδον</i> (ἀνά + αιτ.) = τόπος (σε όλη την έκταση): «σε όλο το στρατόπεδο επικρατούσε μεγάλη σιγή»."},{"gr":"Ἔταξεν αὐτούς ἀνά ἑκατόν.","an":"<i>ἀνά ἑκατόν</i> (ἀνά + αιτ.) = διανομή: «τους παρέταξε ανά εκατό»."},{"gr":"Μετά τῶν συμμάχων ἐστράτευσαν.","an":"<i>μετά τῶν συμμάχων</i> (μετά + γεν.) = συνοδεία: «εκστράτευσαν μαζί με τους συμμάχους»."},{"gr":"Μετά σπουδῆς ἐβάδιζον.","an":"<i>μετά σπουδῆς</i> (μετά + γεν.) = τρόπος: «βάδιζαν βιαστικά»."},{"gr":"Μετά τήν ἐν Σαλαμῖνι ναυμαχίαν.","an":"<i>μετά τήν ναυμαχίαν</i> (μετά + αιτ.) = χρόνος (ύστερο): «μετά τη ναυμαχία στη Σαλαμίνα»."},{"gr":"Μετά τούς θεούς τούς γονέας τιμῶμεν.","an":"<i>μετά τούς θεούς</i> (μετά + αιτ.) = σειρά/τάξη: «αμέσως μετά τους θεούς (τιμούμε τους γονείς)»."},{"gr":"Πατηγύας, ἀνήρ Πέρσης τῶν ἀμφί Κῦρον χρηστός, προφαίνεται ἐλαύνων ἀνά κράτος ἱδροῦντι τῷ ἵππῳ.","an":"Ξεν. Ἀνάβ. 1.8.1 — <i>ἀνά κράτος</i> (ἀνά + αιτ.) = τρόπος: «κάλπαζε ολοταχώς»· πρβλ. <i>τῶν ἀμφί Κῦρον</i> = περίφραση για τη συνοδεία του Κύρου."},{"gr":"Ἀνά πᾶσαν τήν ἡμέραν ἐμάχοντο.","an":"(τύπου Ξεν.) <i>ἀνά πᾶσαν τήν ἡμέραν</i> (ἀνά + αιτ.) = χρόνος-διάρκεια: «μάχονταν σε όλη τη διάρκεια της ημέρας»."},{"gr":"Μετά ταῦτα ἐπορεύοντο διά τῆς Ἀρμενίας.","an":"Ξεν. Ἀνάβ. (τύπου) — <i>μετά ταῦτα</i> (μετά + αιτ.) = χρόνος (ύστερο): «έπειτα από αυτά»· συχνότατη μεταβατική φράση της αφήγησης."}],"note":"Μεγάλη παγίδα: <i>μετά + γενική</i> = «μαζί με» (συνοδεία), αλλά <i>μετά + αιτιατική</i> = «μετά / ύστερα από» (χρόνος). Η ίδια πρόθεση δίνει εντελώς διαφορετικό νόημα ανάλογα με την πτώση: <i>μετά τῶν φίλων</i> «με τους φίλους» ≠ <i>μετά τούς φίλους</i> «μετά τους φίλους»."},{"h":"Οι τρίπτωτες ἐπί, παρά, πρός — πλήρης πολυσημία","body":"<p>Οι τρίπτωτες διακρίνουν σαφώς: <b>γενική</b> = γενικός/στατικός χώρος ή «πάνω σε / κοντά», <b>δοτική</b> = στάση «πάνω σε / κοντά / επιπλέον», <b>αιτιατική</b> = κίνηση/κατεύθυνση/σκοπός.</p><h3>ἐπί — η πιο πολύσημη πρόθεση</h3><p><b>+ γενική:</b> τόπος (πάνω σε, κοντά, αντίκρυ), <b>χρόνος</b> (επί τινος = στην εποχή του), <b>εξουσία / αρχηγία</b> (<i>ὁ ἐπί τῶν ὅπλων</i>), <b>αναφορά</b>. <b>+ δοτική:</b> τόπος (πάνω σε, κοντά, επιπλέον), <b>χρόνος</b> (αμέσως μετά), <b>αιτία</b>, <b>σκοπός</b> (<i>ἐπί τούτῳ</i> «γι' αυτόν τον σκοπό»), <b>εξουσία</b>, <b>όρος / προϋπόθεση</b> (<i>ἐπί τούτοις</i> «με αυτούς τους όρους»), <b>επίταξη/προσθήκη</b>. <b>+ αιτιατική:</b> τόπος-κίνηση (προς, πάνω, εναντίον), <b>έκταση</b>, <b>χρόνος-διάρκεια</b>, <b>σκοπός</b>, <b>αναφορά</b>.</p><h3>παρά</h3><p><b>+ γενική:</b> τόπος (από κοντά / από το πλάι — απομάκρυνση), <b>προέλευση / αφετηρία προσώπου</b> (<i>παρά βασιλέως</i> «από τον βασιλιά»), <b>ποιητικό αίτιο</b> (από πρόσωπο). <b>+ δοτική:</b> τόπος-στάση (κοντά σε / δίπλα σε — μόνο πρόσωπα συνήθως), <b>κρίση / γνώμη</b> (<i>παρ' ἐμοί</i> «κατά τη γνώμη μου»). <b>+ αιτιατική:</b> τόπος (κοντά / δίπλα, και κίνηση προς πρόσωπο), <b>χρόνος-διάρκεια</b>, <b>παραβολή / σύγκριση</b> (<i>παρά τά ἄλλα</i>), <b>αντίθεση / παράβαση</b> (<i>παρά τούς νόμους</i> «παρά τους νόμους»), <b>εξαίρεση</b>, <b>αιτία</b>.</p><h3>πρός</h3><p><b>+ γενική:</b> τόπος (προς το μέρος / από την πλευρά), <b>καταγωγή / προέλευση</b>, <b>αναφορά</b>, <b>συμφέρον</b> (<i>πρός τινός ἐστι</i> «είναι προς το συμφέρον»), <b>ποιητικό αίτιο</b>, <b>όρκος / επίκληση</b> (<i>πρός θεῶν</i> «για τους θεούς»). <b>+ δοτική:</b> τόπος-στάση (κοντά σε / πλάι), <b>ασχολία</b> (<i>πρός τῷ ἔργῳ</i> «απασχολημένος με το έργο»), <b>προσθήκη</b> (<i>πρός τούτοις</i> «επιπλέον»). <b>+ αιτιατική:</b> τόπος-κίνηση/κατεύθυνση (προς), <b>εχθρική κατεύθυνση</b> (εναντίον), <b>χρόνος</b> (περίπου), <b>φιλική/εχθρική διάθεση</b>, <b>αναφορά / σχέση</b>, <b>σύγκριση</b>, <b>σκοπός</b>, <b>τρόπος</b>, <b>συμφωνία</b> (<i>πρός βίαν</i> «με τη βία»).</p>","table":{"title":"Πολυσημία ἐπί / παρά / πρός ανά πτώση","cols":["Πρόθ.","+ Γενική","+ Δοτική","+ Αιτιατική"],"rows":[["ἐπί","πάνω/κοντά/αντίκρυ, εποχή, εξουσία","πάνω/κοντά, αιτία, σκοπός, όρος, προσθήκη","κίνηση προς/εναντίον, έκταση, διάρκεια, σκοπός"],["παρά","από κοντά/προέλευση προσώπου, ποιητ. αίτιο","κοντά σε (πρόσωπο), κατά τη γνώμη","κοντά/προς, διάρκεια, σύγκριση, αντίθεση/παράβαση, εξαίρεση, αιτία"],["πρός","προς το μέρος, καταγωγή, συμφέρον, όρκος","κοντά, ασχολία, προσθήκη","κίνηση/κατεύθυνση, διάθεση, αναφορά, σκοπός, τρόπος"]]},"examples":[{"gr":"Ἐκάθηντο ἐπί τῶν βωμῶν.","an":"<i>ἐπί τῶν βωμῶν</i> (ἐπί + γεν.) = τόπος-στάση «πάνω σε»: «κάθονταν πάνω στους βωμούς»."},{"gr":"Ἐπί Κύρου βασιλεύοντος.","an":"<i>ἐπί Κύρου</i> (ἐπί + γεν.) = χρόνος-εποχή: «στην εποχή που βασίλευε ο Κύρος»."},{"gr":"Ἐπί τούτοις συνέβησαν.","an":"<i>ἐπί τούτοις</i> (ἐπί + δοτ.) = όρος/προϋπόθεση: «συμφώνησαν με αυτούς τους όρους»."},{"gr":"Ἐπορεύετο ἐπί τήν Ὄλυνθον.","an":"<i>ἐπί τήν Ὄλυνθον</i> (ἐπί + αιτ.) = κίνηση-κατεύθυνση (εχθρική): «βάδιζε εναντίον της Ολύνθου»."},{"gr":"Παρά βασιλέως ἧκεν ἄγγελος.","an":"<i>παρά βασιλέως</i> (παρά + γεν.) = προέλευση από πρόσωπο: «ήρθε αγγελιαφόρος από τον βασιλιά»."},{"gr":"Παρ' ἐμοί οὗτος δίκαιός ἐστιν.","an":"<i>παρ' ἐμοί</i> (παρά + δοτ.) = κρίση/γνώμη: «κατά τη γνώμη μου αυτός είναι δίκαιος»."},{"gr":"Παρά τούς νόμους ἔπραξαν.","an":"<i>παρά τούς νόμους</i> (παρά + αιτ.) = αντίθεση/παράβαση: «ενήργησαν παράνομα / αντίθετα προς τους νόμους»."},{"gr":"Πρός θεῶν, μή ποιήσῃς τοῦτο.","an":"<i>πρός θεῶν</i> (πρός + γεν.) = όρκος/επίκληση: «για τους θεούς, μην το κάνεις αυτό»."},{"gr":"Πρός τῷ ποταμῷ ἐστρατοπεδεύσαντο.","an":"<i>πρός τῷ ποταμῷ</i> (πρός + δοτ.) = τόπος-στάση «κοντά σε»: «στρατοπέδευσαν κοντά στον ποταμό»."},{"gr":"Πρός τούς πολεμίους ἐχώρουν.","an":"<i>πρός τούς πολεμίους</i> (πρός + αιτ.) = εχθρική κατεύθυνση: «προχωρούσαν εναντίον των εχθρών»."},{"gr":"Εἶχε γάρ Κῦρον παρ' ἑαυτῷ.","an":"Ξεν. Ἀνάβ. 1.1.5 (τύπου) — <i>παρ' ἑαυτῷ</i> (παρά + δοτ.) = τόπος-στάση κοντά σε πρόσωπο: «τον είχε κοντά του / στην υπηρεσία του»."},{"gr":"Πρός Κῦρον ἀπέπεμψε τόν ἄνδρα.","an":"Ξεν. Ἀνάβ. (τύπου, πρβλ. 1.9) — <i>πρός Κῦρον</i> (πρός + αιτ.) = κίνηση/κατεύθυνση προς πρόσωπο: «έστειλε τον άνδρα στον Κύρο»."},{"gr":"Πρός τῷ ἔργῳ ὄντες οὐκ ᾐσθάνοντο.","an":"(τύπου Πλάτ.) <i>πρός τῷ ἔργῳ</i> (πρός + δοτ.) = ασχολία: «καθώς ήταν απασχολημένοι με το έργο, δεν αντιλαμβάνονταν»."}],"note":"Η ἐπί είναι η δυσκολότερη: το ίδιο <i>ἐπί τούτῳ</i> μπορεί κατά περίσταση να σημαίνει αιτία («γι' αυτό»), σκοπό («για τον σκοπό αυτό») ή όρο («με την προϋπόθεση αυτή») — το νόημα κρίνεται από τα συμφραζόμενα και το ρήμα."},{"h":"Οι τρίπτωτες περί, ὑπό και η ἀμφί","body":"<h3>περί</h3><p><b>+ γενική:</b> τόπος (γύρω από), <b>αναφορά</b> (η κατεξοχήν σημασία: «για / σχετικά με» — <i>περί τούτων λέγω</i>), <b>αιτία</b>, <b>σκοπός</b>, <b>αξία / προτίμηση</b> (<i>περί πολλοῦ ποιοῦμαι</i> «θεωρώ πολύ σημαντικό»). <b>+ δοτική:</b> τόπος (γύρω από — συχνά για ενδύματα/όπλα), <b>αιτία / αναφορά</b>, <b>φόβος για κάτι</b> (<i>δέδοικα περί σοι</i>). <b>+ αιτιατική:</b> τόπος (γύρω από), <b>χρόνος</b> (περίπου), <b>ποσό</b> (περίπου), <b>αναφορά</b>, <b>ασχολία</b> (<i>οἱ περί τήν θήραν</i> «όσοι ασχολούνται με το κυνήγι»).</p><h3>ὑπό</h3><p><b>+ γενική:</b> τόπος (κάτω από), <b>ποιητικό αίτιο</b> (η κατεξοχήν σημασία στην παθητική σύνταξη! <i>ἐτιμήθη ὑπό τοῦ δήμου</i>), <b>αιτία</b>, <b>συνοδεία/μέσο</b> (<i>ὑπ' αὐλητῶν</i> «με συνοδεία αυλητών»), <b>τρόπος</b>. <b>+ δοτική:</b> τόπος-στάση (κάτω από), <b>υποταγή / εξουσία</b> (<i>ὑπό βασιλεῖ εἶναι</i> «είναι υπό την εξουσία του βασιλιά»), <b>εποπτεία</b>. <b>+ αιτιατική:</b> τόπος (κάτω από — με κίνηση ή έκταση), <b>χρόνος</b> (κατά τη διάρκεια, <i>ὑπό νύκτα</i> «κατά τη νύχτα»), <b>υποταγή</b>.</p><h3>ἀμφί (τρίπτωτη, σπάνια στην πεζογραφία)</h3><p><b>+ γενική:</b> αναφορά («για»). <b>+ δοτική:</b> τόπος (γύρω από), αιτία. <b>+ αιτιατική</b> (το συχνότερο): τόπος (γύρω από), <b>περίπου</b> (χρόνος/ποσό — <i>ἀμφί τά πεντήκοντα ἔτη</i>), <b>ασχολία</b> (<i>οἱ ἀμφί τόν Κῦρον</i> «ο Κύρος και οι περί αυτόν»).</p>","table":{"title":"Πολυσημία περί / ὑπό / ἀμφί ανά πτώση","cols":["Πρόθ.","+ Γενική","+ Δοτική","+ Αιτιατική"],"rows":[["περί","γύρω από, αναφορά, αιτία, αξία","γύρω από, αναφορά, φόβος","γύρω από, χρόνος~, ποσό~, ασχολία"],["ὑπό","κάτω από, ποιητικό αίτιο, αιτία, μέσο","κάτω από, υποταγή, εποπτεία","κάτω από (κίνηση), χρόνος, υποταγή"],["ἀμφί","αναφορά","γύρω από, αιτία","γύρω από, περίπου, ασχολία"]]},"examples":[{"gr":"Περί τῆς εἰρήνης βουλεύονται.","an":"<i>περί τῆς εἰρήνης</i> (περί + γεν.) = αναφορά: «συσκέπτονται για την ειρήνη»."},{"gr":"Περί πολλοῦ ποιοῦμαι τήν φιλίαν.","an":"<i>περί πολλοῦ</i> (περί + γεν.) = αξία: «θεωρώ πολύ σημαντική τη φιλία»."},{"gr":"Περί μέσας νύκτας ἀφίκοντο.","an":"<i>περί μέσας νύκτας</i> (περί + αιτ.) = χρόνος (κατά προσέγγιση): «έφτασαν γύρω στα μεσάνυχτα»."},{"gr":"Ὁ Σωκράτης ἐτιμήθη ὑπό τῶν μαθητῶν.","an":"<i>ὑπό τῶν μαθητῶν</i> (ὑπό + γεν.) = ποιητικό αίτιο (παθητική σύνταξη): «ο Σωκράτης τιμήθηκε από τους μαθητές»."},{"gr":"Ὑπό βασιλεῖ ἦσαν.","an":"<i>ὑπό βασιλεῖ</i> (ὑπό + δοτ.) = υποταγή: «ήταν υπό την εξουσία του βασιλιά»."},{"gr":"Ὑπό νύκτα προσέβαλον.","an":"<i>ὑπό νύκτα</i> (ὑπό + αιτ.) = χρόνος: «επιτέθηκαν κατά τη διάρκεια της νύχτας»."},{"gr":"Οἱ ἀμφί τόν Κῦρον ἔφυγον.","an":"<i>οἱ ἀμφί τόν Κῦρον</i> (ἀμφί + αιτ.) = περίφραση/ασχολία: «ο Κύρος και οι σύντροφοί του»."},{"gr":"Περί Πελοποννήσου τῷ Ἀγησιλάῳ ἐδέδοκτο πολεμεῖν.","an":"(τύπου Ξεν.) <i>περί Πελοποννήσου</i> (περί + γεν.) = αναφορά: «είχε αποφασιστεί από τον Αγησίλαο να πολεμήσει για την Πελοπόννησο»."},{"gr":"Ἀμφί τά πεντήκοντα ἔτη γεγονώς ἦν.","an":"(τύπου Ξεν.) <i>ἀμφί τά πεντήκοντα ἔτη</i> (ἀμφί + αιτ.) = ποσό/ηλικία κατά προσέγγιση: «ήταν περίπου πενήντα ετών»."},{"gr":"Πολλά ἔπαθον ὑπό τῶν πολεμίων.","an":"(τύπου) <i>ὑπό τῶν πολεμίων</i> (ὑπό + γεν.) = ποιητικό αίτιο: «έπαθαν πολλά από τους εχθρούς»."}],"note":"Το ποιητικό αίτιο (ο «δράστης» στην παθητική φωνή) εκφέρεται κανονικά με <b>ὑπό + γενική</b> όταν είναι έμψυχο/πρόσωπο (<i>ὑπό τοῦ δήμου</i>)· για άψυχο/ακούσιο αίτιο χρησιμοποιούνται και τα <i>ἀπό, ἐκ, διά, παρά, πρός + γενική</i>."},{"h":"Καταχρηστικές προθέσεις, αναστροφή και πρακτική μεθοδολογία ανάλυσης","body":"<h3>Α. Οι καταχρηστικές προθέσεις (όλες + γενική, πλην ὡς)</h3><ul><li><b>ἄνευ + γεν.</b> = «χωρίς», εξαίρεση/έλλειψη: <i>ἄνευ τῆς ψήφου</i></li><li><b>χωρίς / δίχα + γεν.</b> = «χωρίς, ξεχωριστά από»</li><li><b>ἄχρι(ς) / μέχρι(ς) + γεν.</b> = όριο τόπου ή χρόνου, «έως / μέχρι»: <i>μέχρι τοῦ Ἰσθμοῦ</i></li><li><b>ἕνεκα / ἕνεκεν + γεν.</b> = αιτία ή σκοπός, «εξαιτίας / για χάρη»: <i>ἀρετῆς ἕνεκα</i></li><li><b>χάριν + γεν.</b> = σκοπός / χάρη, «για χάρη»: <i>τοῦ μαθεῖν χάριν</i></li><li><b>πλήν + γεν.</b> = εξαίρεση, «εκτός»: <i>πλήν ἑνός</i></li><li><b>ὡς + αιτ.</b> (μόνο πρόσωπα) = κίνηση προς πρόσωπο: <i>ἦλθεν ὡς βασιλέα</i> «πήγε στον βασιλιά»</li></ul><h3>Β. Αναστροφή (ἀναστροφή) και αναβιβασμός τόνου</h3><p>Κανονικά η πρόθεση προηγείται του ονόματος. Όταν όμως <b>ακολουθεί</b> το όνομα, έχουμε <b>αναστροφή</b> (συχνή με <i>περί, ἕνεκα, χάριν, ἄνευ</i>). Τότε η πρόθεση, αν τονιζόταν στη λήγουσα, ανεβάζει τον τόνο στην παραλήγουσα (<b>ἀναβιβασμός / ὀρθοτόνηση</b>): <i>τούτων πέρι</i> αντί <i>περί τούτων</i>. Εξαιρούνται η <i>ἀμφί</i> και η <i>ἀντί</i>, που δεν αναβιβάζουν τόνο.</p><h3>Γ. Μεθοδολογία αναγνώρισης ενός εμπροθέτου — 4 βήματα</h3><ol><li><b>Εντόπισε την πρόθεση</b> και την πτώση του ονόματος που ακολουθεί.</li><li><b>Βρες τι προσδιορίζει</b>: ρήμα (επιρρηματικός), όνομα (επιθετικός), ή λειτουργεί ως κατηγορούμενο.</li><li><b>Όρισε τη σχέση</b> με βάση το νόημα ΚΑΙ την πτώση (η ίδια πρόθεση αλλάζει σημασία με την πτώση — βλ. μετά, διά, ἐπί).</li><li><b>Διατύπωσε:</b> «εμπρόθετος προσδιορισμός [της σχέσης] στο [προσδιοριζόμενο]».</li></ol>","examples":[{"gr":"Μέχρι τοῦ Ἰσθμοῦ ἦλθον οἱ σύμμαχοι.","an":"<i>μέχρι τοῦ Ἰσθμοῦ</i> (καταχρ. μέχρι + γεν.) = εμπρόθετος του τόπου-όριο: «έφτασαν ως τον Ισθμό»."},{"gr":"Ἀρετῆς ἕνεκα τιμῶνται.","an":"<i>ἀρετῆς ἕνεκα</i> (καταχρ. ἕνεκα + γεν., με αναστροφή) = αιτία: «τιμούνται για/εξαιτίας της αρετής τους»."},{"gr":"Ἅπαντες ἀπέθανον πλήν ἑνός.","an":"<i>πλήν ἑνός</i> (καταχρ. πλήν + γεν.) = εξαίρεση: «πέθαναν όλοι εκτός από έναν»."},{"gr":"Οὐδείς ἀποθνῄσκει ἄνευ τῆς ὑμετέρας ψήφου.","an":"<i>ἄνευ τῆς ὑμετέρας ψήφου</i> (καταχρ. ἄνευ + γεν.) = έλλειψη/εξαίρεση: «κανείς δεν θανατώνεται χωρίς τη δική σας ψήφο»."},{"gr":"Ἦλθεν ὡς βασιλέα.","an":"<i>ὡς βασιλέα</i> (καταχρ. ὡς + αιτ., μόνο πρόσωπο) = κίνηση προς πρόσωπο: «πήγε στον βασιλιά»."},{"gr":"Τούτων πέρι πολλά εἴρηται.","an":"<i>τούτων πέρι</i> = αναστροφή του <i>περί τούτων</i> με αναβιβασμό τόνου (πέρι): αναφορά, «γι' αυτά έχουν ειπωθεί πολλά»."},{"gr":"Τοῦ μαθεῖν χάριν πάντα ὑπομένουσιν.","an":"<i>τοῦ μαθεῖν χάριν</i> (καταχρ. χάριν + γεν., με αναστροφή) = σκοπός: «τα υπομένουν όλα για να μάθουν / χάριν της μάθησης»."},{"gr":"Ἄχρι τῆς νυκτός ἐμάχοντο.","an":"(τύπου) <i>ἄχρι τῆς νυκτός</i> (καταχρ. ἄχρι + γεν.) = χρονικό όριο: «μάχονταν μέχρι τη νύχτα»."}],"note":"Συχνά λάθη: (1) Το <i>ἕνεκα/χάριν</i> τίθενται κατά κανόνα <b>μετά</b> τη γενική (αναστροφή) — μην τα περάσεις για κανονική σειρά. (2) Το <i>ὡς</i> ως πρόθεση δέχεται <b>μόνο αιτιατική προσώπου</b> (όχι πράγματος): λέμε <i>ὡς τόν στρατηγόν</i> αλλά ΟΧΙ *ὡς τήν πόλιν (για τόπο χρησιμοποιούμε εἰς/πρός). (3) Η σημασία κρίνεται πάντα από πρόθεση + πτώση + συμφραζόμενα μαζί, ποτέ από την πρόθεση μόνη."}]);
  T("syn-egliseis", [{"h":"Τι είναι η έγκλιση — οι τέσσερις εγκλίσεις","body":"<p><b>Έγκλιση</b> ονομάζεται ο γραμματικός τρόπος με τον οποίο ο ομιλητής παρουσιάζει το περιεχόμενο του ρήματος: ως κάτι <i>πραγματικό</i>, ως <i>επιθυμητό / προσδοκώμενο</i>, ως <i>δυνατό / ενδεχόμενο</i> ή ως <i>προσταγή</i>. Με άλλα λόγια, η έγκλιση δείχνει τη <b>στάση / υποκειμενική θεώρηση</b> του ομιλητή απέναντι σε αυτό που λέει.</p><p>Η αρχαία ελληνική έχει τέσσερις εγκλίσεις:</p><ul><li><b>Οριστική</b> — η έγκλιση του πραγματικού και του βεβαίου.</li><li><b>Υποτακτική</b> — του προσδοκώμενου, της προτροπής και της απορίας.</li><li><b>Ευκτική</b> — της ευχής και του δυνατού (με τη βοήθεια του <i>ἄν</i>).</li><li><b>Προστακτική</b> — της προσταγής, της παράκλησης και της απαγόρευσης.</li></ul><p>Κάθε έγκλιση έχει μια <b>βασική σημασία στις κύριες (ανεξάρτητες) προτάσεις</b> — αυτό εξετάζει το κεφάλαιο αυτό — και επιπλέον <b>ειδικές χρήσεις στις δευτερεύουσες</b> προτάσεις (βλ. τελικές, ενδοιαστικές, υποθετικές, πλάγιος λόγος κ.λπ.).</p>","examples":[{"gr":"Ὁ στρατηγός νικᾷ.","an":"Οριστική — δηλώνεται ένα γεγονός ως πραγματικό και βέβαιο."},{"gr":"Ἴωμεν πρός τούς πολεμίους.","an":"Υποτακτική (προτρεπτική) — προτροπή: «ας προχωρήσουμε»."},{"gr":"Εἴθε σωθείημεν.","an":"Ευκτική (ευχετική) — ευχή για το μέλλον: «μακάρι να σωθούμε»."},{"gr":"Λέγε τήν ἀλήθειαν.","an":"Προστακτική — προσταγή προς το β΄ πρόσωπο."},{"gr":"Φέρε δή ἴδωμεν.","an":"Υποτακτική (προτρεπτική, τύπου Πλάτ.) — α΄ πληθ.: «εμπρός λοιπόν, ας δούμε»· δείγμα της σημασίας «προτροπή»."},{"gr":"Τίς οὐκ ἄν ὁμολογήσειεν;","an":"Δυνητική ευκτική (Smyth) — δηλώνει το δυνατό/πιθανό: «ποιος δεν θα συμφωνούσε;»."}]},{"h":"Η οριστική — και η δυνητική οριστική","body":"<p>Η <b>οριστική</b> είναι η έγκλιση με την οποία παρουσιάζουμε κάτι ως <b>πραγματικό, βέβαιο ή αντικειμενικό</b>. Είναι η πιο «ουδέτερη» έγκλιση και η συνηθέστερη στον λόγο.</p><h3>Δυνητική οριστική</h3><p>Όταν η <b>οριστική ιστορικού χρόνου</b> (παρατατικός, αόριστος, υπερσυντέλικος) συνοδεύεται από το δυνητικό μόριο <b>ἄν</b>, σχηματίζεται η <b>δυνητική οριστική</b>, που δηλώνει:</p><ul><li>το <b>δυνατό στο παρελθόν</b> (κάτι που θα μπορούσε να είχε γίνει), ή</li><li>το <b>μη πραγματικό / αντίθετο του πραγματικού</b> (κάτι που θα γινόταν, αλλά δεν έγινε).</li></ul><p>Η δυνητική οριστική είναι και η <b>απόδοση</b> του υποθετικού λόγου του «αντίθετου του πραγματικού».</p>","examples":[{"gr":"Οἱ Ἀθηναῖοι τούς Πέρσας ἐνίκησαν.","an":"Απλή οριστική — βεβαιωμένο ιστορικό γεγονός."},{"gr":"Ἐβουλόμην ἄν σε παρεῖναι.","an":"Δυνητική οριστική (παρατ. + ἄν) — «θα ήθελα να ήσουν παρών» (μη πραγματικό)."},{"gr":"Ταῦτα οὐκ ἄν ἐγένετο, εἰ μή σύ ἐκώλυσας.","an":"Δυνητική οριστική στην απόδοση υποθετικού λόγου αντίθετου του πραγματικού: «δεν θα είχαν γίνει αυτά, αν δεν τα εμπόδιζες»."},{"gr":"Εἰ κερδαίνειν ἐβούλου, τότ᾽ ἄν πλεῖστον ἔλαβες.","an":"Λυσ. 7.20 — δυνητική οριστική (ἔλαβες + ἄν) στην απόδοση αντίθετου του πραγματικού: «αν ήθελες να κερδίσεις, τότε θα είχες πάρει τα περισσότερα»."},{"gr":"Οὐκ ἄν ἐποίησεν Σωκράτης τοῦτο.","an":"Δυνητική οριστική (αόρ. + ἄν), άρνηση οὐ — μη πραγματικό στο παρελθόν: «δεν θα το είχε κάνει ο Σωκράτης»."},{"gr":"Τίς γάρ ἄν ᾤετο ταῦτα γενέσθαι;","an":"Δυνητική οριστική (παρατ. ᾤετο + ἄν, τύπου Δημ.) — «ποιος θα φανταζόταν ότι θα γίνονταν αυτά;»."}],"note":"Άρνηση της οριστικής (και της δυνητικής οριστικής): οὐ. Το ἄν της δυνητικής δεν παραλείπεται και δεν συγχέεται με το αοριστολογικό ἄν των δευτερευουσών."},{"h":"Η υποτακτική στις κύριες προτάσεις","body":"<p>Η <b>υποτακτική</b> στις κύριες προτάσεις παρουσιάζει κάτι ως <b>προσδοκώμενο, επιθυμητό ή υπό συζήτηση</b>. Έχει τρεις κύριες χρήσεις:</p><ul><li><b>Προτρεπτική υποτακτική</b>: σε α΄ πρόσωπο (συνήθως πληθυντικού)· εκφράζει <i>προτροπή / παρόρμηση</i> προς τον εαυτό μας ή την ομάδα. Π.χ. <i>ἴωμεν</i> = ας πάμε, <i>σκεψώμεθα</i> = ας σκεφτούμε.</li><li><b>Απορηματική (διστακτική) υποτακτική</b>: σε ερωτήσεις απορίας, κυρίως α΄ προσώπου· ο ομιλητής διερωτάται τι να κάνει. Π.χ. <i>τί ποιῶμεν;</i> = τι να κάνουμε; <i>ποῖ τράπωμαι;</i> = πού να στραφώ;</li><li><b>Αποτρεπτική / απαγορευτική υποτακτική</b>: σε β΄ ή γ΄ πρόσωπο <b>αορίστου</b> με άρνηση <b>μή</b>· εκφράζει <i>απαγόρευση στιγμιαία</i>. Π.χ. <i>μή ποιήσῃς τοῦτο</i> = μην το κάνεις (αυτό).</li></ul>","examples":[{"gr":"Φέρε ἴδωμεν τί λέγει.","an":"Προτρεπτική υποτακτική (α΄ πληθ.): «ας δούμε»."},{"gr":"Εἴπωμεν ἤ σιγῶμεν;","an":"Απορηματική υποτακτική: «να μιλήσουμε ή να σωπάσουμε;»."},{"gr":"Μή θαυμάσῃς.","an":"Αποτρεπτική υποτακτική αορίστου + μή: «μην απορήσεις»."},{"gr":"Δεῦρο ἐξαναστῶμεν εἰς τήν αὐλήν, εἶτα ἴωμεν.","an":"Ξεν. Ἀνάβ. (τύπου) — προτρεπτική υποτακτική (ἐξαναστῶμεν, ἴωμεν): «ας σηκωθούμε να βγούμε στην αυλή, έπειτα ας πάμε»."},{"gr":"Πῶς οὖν περί τούτων ποιῶμεν;","an":"Απορηματική (διστακτική) υποτακτική: «πώς λοιπόν να ενεργήσουμε γι᾽ αυτά;»."},{"gr":"Μή φοβηθῇς τόν θάνατον.","an":"Αποτρεπτική υποτακτική αορίστου + μή — στιγμιαία απαγόρευση: «μη φοβηθείς τον θάνατο»."}],"note":"Άρνηση της υποτακτικής σε όλες αυτές τις χρήσεις: μή. Η αποτρεπτική υποτακτική (μή + αόριστος) λειτουργεί ως απαγόρευση δίπλα στην προστακτική."},{"h":"Η ευκτική στις κύριες προτάσεις","body":"<p>Η <b>ευκτική</b> στις κύριες προτάσεις έχει δύο βασικές, καθαρά διακριτές χρήσεις:</p><ul><li><b>Ευχετική ευκτική</b>: εκφράζει <i>ευχή πραγματοποιήσιμη</i> για το μέλλον. Συχνά εισάγεται με τα μόρια <b>εἴθε</b> ή <b>εἰ γάρ</b> (= μακάρι). Π.χ. <i>εἴθε σωθείη ἡ πόλις</i> = μακάρι να σωθεί η πόλη. Άρνηση: <b>μή</b> (<i>μή γένοιτο</i> = μη γένοιτο, ας μη γίνει).</li><li><b>Δυνητική ευκτική</b>: συνοδεύεται <b>πάντοτε από το ἄν</b> και δηλώνει το <i>δυνατό ή πιθανό</i> στο παρόν και το μέλλον — μια συγκρατημένη, ευγενική διατύπωση. Π.χ. <i>λέγοι ἄν τις</i> = θα μπορούσε να πει κανείς. Άρνηση: <b>οὐ</b>.</li></ul><p>Η δυνητική ευκτική είναι και η <b>απόδοση</b> του υποθετικού λόγου της «απλής σκέψης».</p>","examples":[{"gr":"Εἴθε οἱ θεοί ἡμῖν βοηθήσειαν.","an":"Ευχετική ευκτική με εἴθε: «μακάρι να μας βοηθήσουν οι θεοί»."},{"gr":"Οὐκ ἄν δικαίως δυστυχοίην.","an":"Δυνητική ευκτική + ἄν, άρνηση οὐ: «δεν θα ήταν δίκαιο να δυστυχώ»."},{"gr":"Μή γένοιτο.","an":"Ευχετική ευκτική, άρνηση μή: «ας μη γίνει»."},{"gr":"Εἴθε φίλος ἡμῖν γένοιο.","an":"Smyth — ευχετική ευκτική με εἴθε: «μακάρι να γινόσουν φίλος μας»."},{"gr":"Λέγοις ἄν τήν δέησιν.","an":"Πλάτ. Παρμ. (τύπου) — δυνητική ευκτική + ἄν με σημασία ευγενικής προτροπής: «θα μπορούσες να πεις το αίτημά σου»."},{"gr":"Τίς ἄν τοῦτο πιστεύσειεν;","an":"Δυνητική ευκτική + ἄν: «ποιος θα το πίστευε αυτό;»· συγκρατημένη/δυνατή διατύπωση."}],"note":"Κλειδί διάκρισης: η ευχετική ευκτική δεν παίρνει ἄν (και συχνά έχει εἴθε/εἰ γάρ)· η δυνητική ευκτική παίρνει πάντα ἄν. Από αυτό κρίνεται και η άρνηση (μή στην ευχετική, οὐ στη δυνητική)."},{"h":"Η προστακτική — προσταγή και απαγόρευση","body":"<p>Η <b>προστακτική</b> εκφράζει <b>προσταγή, παράκληση, προτροπή ή ευχή-εντολή</b> και απευθύνεται κανονικά στο β΄ (και γ΄) πρόσωπο. Π.χ. <i>λέγε</i> = λέγε, <i>ἀκουσάτω</i> = ας ακούσει.</p><h3>Η απαγόρευση</h3><p>Για να εκφράσει <b>απαγόρευση</b> («μην…»), η αρχαία ελληνική <b>δεν</b> χρησιμοποιεί προστακτική αορίστου· χρησιμοποιεί:</p><ul><li><b>μή + προστακτική ενεστώτα</b> → απαγόρευση <i>διαρκής / γενική</i>: <i>μή κλαῖε</i> = μην κλαις (γενικά).</li><li><b>μή + υποτακτική αορίστου</b> → απαγόρευση <i>στιγμιαία / συγκεκριμένη</i>: <i>μή κλαύσῃς</i> = μην κλάψεις (τώρα).</li></ul>","examples":[{"gr":"Πείθου τοῖς νόμοις.","an":"Προστακτική — εντολή: «να υπακούς στους νόμους»."},{"gr":"Μή ποίει τοῦτο.","an":"μή + προστακτική ενεστώτα — διαρκής απαγόρευση: «μην το κάνεις (γενικά)»."},{"gr":"Μή ποιήσῃς τοῦτο.","an":"μή + υποτακτική αορίστου — στιγμιαία απαγόρευση: «μην το κάνεις (τώρα)»."},{"gr":"Ἀκουσάτω πᾶς ὁ δῆμος.","an":"Προστακτική γ΄ προσώπου: «ας ακούσει όλος ο λαός»· προσταγή στο γ΄ πρόσωπο."},{"gr":"Μή θορυβεῖτε, ὦ ἄνδρες Ἀθηναῖοι.","an":"Πλάτ. (τύπου) — μή + προστακτική ενεστώτα: διαρκής απαγόρευση: «μη θορυβείτε»."},{"gr":"Λέγε μοι τήν ἀλήθειαν.","an":"Προστακτική ενεστώτα — παράκληση/εντολή προς β΄ πρόσωπο: «πες μου την αλήθεια»."}],"note":"Άρνηση της προστακτικής (και της απαγόρευσης): μή. Δεν υπάρχει απαγόρευση με «μή + προστακτική αορίστου» στην κλασική αττική."},{"h":"Συγκεντρωτικός πίνακας: έγκλιση — σημασία — άρνηση","body":"<p>Ο παρακάτω πίνακας συνοψίζει τις βασικές σημασίες των εγκλίσεων στις κύριες προτάσεις, μαζί με την άρνηση που παίρνει η καθεμιά. Ο κανόνας της άρνησης είναι σταθερός: <b>οὐ</b> για το πραγματικό και το δυνατό (οριστική, δυνητικές)· <b>μή</b> για το επιθυμητό και το προστακτικό (προτρεπτική/απορηματική/αποτρεπτική υποτακτική, ευχετική ευκτική, προστακτική).</p>","table":{"title":"Οι εγκλίσεις στις κύριες προτάσεις","cols":["Έγκλιση / χρήση","Σημασία","Άρνηση","Παράδειγμα"],"rows":[["Οριστική","πραγματικό, βέβαιο","οὐ","γράφει"],["Δυνητική οριστική (+ ἄν)","μη πραγματικό / δυνατό στο παρελθόν","οὐ","ἐποίησεν ἄν"],["Υποτακτική προτρεπτική","προτροπή (α΄ πρόσ.)","μή","ἴωμεν"],["Υποτακτική απορηματική","απορία (τι να κάνω;)","μή","τί ποιῶμεν;"],["Υποτακτική αποτρεπτική (μή + αόρ.)","στιγμιαία απαγόρευση","μή","μή ποιήσῃς"],["Ευχετική ευκτική (εἴθε/εἰ γάρ)","ευχή πραγματοποιήσιμη","μή","εἴθε γένοιτο"],["Δυνητική ευκτική (+ ἄν)","δυνατό / πιθανό (παρόν-μέλλον)","οὐ","λέγοι ἄν"],["Προστακτική","προσταγή, παράκληση","μή","λέγε"]]},"note":"Πρακτικός κανόνας: «οὐ → πραγματικό/δυνατό· μή → επιθυμητό/προστακτικό». Η άρνηση είναι συχνά το ασφαλέστερο κριτήριο για να αναγνωρίσεις τη σημασία μιας έγκλισης."},{"h":"Το ἄν και η διάκριση των δυνητικών","body":"<p>Το μόριο <b>ἄν</b> είναι καθοριστικό για τις εγκλίσεις. Στις κύριες προτάσεις το <b>δυνητικό ἄν</b> συνοδεύει:</p><ul><li>την <b>οριστική ιστορικού χρόνου</b> → δυνητική οριστική (μη πραγματικό / δυνατό στο παρελθόν), και</li><li>την <b>ευκτική</b> → δυνητική ευκτική (δυνατό / πιθανό στο παρόν-μέλλον).</li></ul><p>Έτσι, η ίδια έννοια της «δυνατότητας» εκφράζεται με <b>δύο</b> δυνητικές μορφές, που χωρίζονται χρονικά: η δυνητική <i>οριστική</i> αναφέρεται στο <b>παρελθόν</b> (ή στο μη πραγματικό), η δυνητική <i>ευκτική</i> στο <b>παρόν και μέλλον</b>.</p><p><b>Προσοχή:</b> το δυνητικό ἄν των κύριων προτάσεων δεν πρέπει να συγχέεται με το <b>αοριστολογικό ἄν</b> (= ἐάν/ὅταν) που εισάγει ή συνοδεύει την υποτακτική σε δευτερεύουσες (υποθετικές, χρονικές, αναφορικές) με σημασία αόριστης επανάληψης.</p>","examples":[{"gr":"Ἡδέως ἄν ἐροίμην σε.","an":"Δυνητική ευκτική (παρόν-μέλλον): «ευχαρίστως θα σε ρωτούσα»."},{"gr":"Τότε δή ἔγνως ἄν τήν ἀλήθειαν.","an":"Δυνητική οριστική (παρελθόν): «τότε θα είχες καταλάβει την αλήθεια»."},{"gr":"Ὅταν ἔλθῃ, χαιρήσομεν.","an":"Εδώ το ἄν (μέσα στο ὅταν = ὅτε + ἄν) είναι αοριστολογικό, όχι δυνητικό — δευτερεύουσα χρονική."},{"gr":"Οὐκ ἄν ἐδυνήθημεν ταῦτα ποιῆσαι.","an":"Δυνητική οριστική (αόρ. + ἄν, παρελθόν), άρνηση οὐ: «δεν θα μπορούσαμε να τα κάνουμε αυτά»."},{"gr":"Λέγοι ἄν τις ὅτι ἀδικεῖ.","an":"Δυνητική ευκτική + ἄν (παρόν-μέλλον): «θα μπορούσε να πει κανείς ότι αδικεί»."},{"gr":"Ἐάν τις τοῦτο πράξῃ, ζημιωθήσεται.","an":"Αοριστολογικό ἄν (ἐάν = εἰ + ἄν) + υποτακτική σε δευτερεύουσα υποθετική — όχι δυνητικό ἄν."}],"note":"Δύο διαφορετικά ἄν: (1) δυνητικό (κύριες προτάσεις, + οριστ./ευκτ.)· (2) αοριστολογικό (δευτερεύουσες, + υποτακτική, στους τύπους ἐάν, ὅταν, ἐπειδάν, ὅς ἄν). Η αναγνώρισή τους κρίνεται από την πρόταση και την έγκλιση."}]);
  T("syn-moria", [{"h":"Τι είναι τα μόρια — ορισμός, φύση, θέση στον λόγο","body":"<p><b>Μόρια</b> ονομάζονται μικρές <b>άκλιτες</b> λέξεις (οι περισσότερες μονοσύλλαβες) που δεν ανήκουν κανονικά σε ένα ορισμένο, αυτοτελές μέρος του λόγου, αλλά <b>συνοδεύουν</b> άλλες λέξεις, φράσεις ή ολόκληρες προτάσεις για να προσδώσουν στον λόγο ποικίλες <i>σημασιολογικές</i> και <i>συναισθηματικές αποχρώσεις</i>: βεβαίωση, έμφαση, περιορισμό, αμφιβολία, δυνατότητα, αοριστία, προτροπή, αντίθεση, συμπέρασμα κ.ά.</p><p>Το μόριο σπάνια μεταφράζεται με μία σταθερή λέξη· συχνότερα <b>χρωματίζει</b> τη φράση και πολλές φορές αποδίδεται περιφραστικά ή μένει αμετάφραστο. Γι' αυτό η μελέτη των μορίων είναι κατεξοχήν μελέτη <i>λειτουργίας</i> μέσα στα συμφραζόμενα, όχι απομνημόνευσης μεταφράσεων.</p><h3>Βασικά γνωρίσματα</h3><ul><li><b>Ακλισία</b>: δεν κλίνονται ποτέ.</li><li><b>Εξάρτηση</b>: δεν στέκουν μόνα τους ως όροι της πρότασης· προσδιορίζουν.</li><li><b>Θέση</b>: πολλά είναι <b>εγκλιτικά</b> (π.χ. <i>γε, τοι, περ, πω, νυν</i>) και τοποθετούνται αμέσως μετά τη λέξη που τονίζουν· άλλα μπαίνουν δεύτερα στην πρόταση (κανόνας του Wackernagel: <i>μέν, δέ, γάρ, οὖν, τοίνυν, ἄρα</i> τείνουν στη 2η θέση).</li><li><b>Πολυλειτουργικότητα</b>: η ίδια μορφή μπορεί να έχει πολλές χρήσεις (π.χ. <i>δή</i> βεβαιωτικό ή προτρεπτικό· <i>ἄν</i> δυνητικό ή αοριστολογικό).</li></ul><p>Επειδή πολλά μόρια είναι <b>ομώνυμα</b> ή σχεδόν ομόηχα (<i>ἄρα/ἆρα, ἤ/ἦ, ἤ/ᾗ, νυν/νῦν</i>), η ορθή <b>τονική και διακριτική γραφή</b> (πνεύμα, τόνος) είναι αυτή που δηλώνει τη σημασία· γι' αυτό η προσοχή στο σημείο του τόνου είναι ουσιώδης για την ερμηνεία.</p>","examples":[{"gr":"πάντες δή ταῦτα ἴσασιν.","an":"Όλοι βέβαια τα γνωρίζουν αυτά. (το <i>δή</i> βεβαιώνει — δεν είναι όρος, μόνο χρωματίζει.)"},{"gr":"ἔγωγε οὐκ οἶδα.","an":"Εγώ τουλάχιστον δεν ξέρω. (το εγκλιτικό <i>γε</i> κολλά στο <i>ἐγώ</i> και το περιορίζει/τονίζει.)"},{"gr":"ἦ καλῶς λέγεις.","an":"Πραγματικά καλά μιλάς. (το βεβαιωτικό <i>ἦ</i> δίνει έμφαση σε όλη τη φράση.)"},{"gr":"οἱ μέν ἔφευγον, οἱ δέ ἐδίωκον.","an":"Εδώ τα <i>μέν...δέ</i> δεν είναι όροι της πρότασης· απλώς αντιδιαστέλλουν τις δύο φράσεις (κανόνας Wackernagel: 2η θέση)."},{"gr":"σύ νυν λέγε.","an":"Εσύ λοιπόν μίλα. (το άτονο εγκλιτικό <i>νυν</i> — όχι το χρονικό <i>νῦν</i> — χρωματίζει συμπερασματικά την προτροπή.)"}],"note":"Διάκριση-κλειδί: «μόριο» (χρωματίζει) ≠ «σύνδεσμος» (συνδέει προτάσεις) ≠ «επίρρημα» (προσδιορίζει ρήμα). Η ίδια λέξη (π.χ. <i>ὡς</i>) μπορεί κατά περίσταση να λειτουργεί και ως μόριο και ως σύνδεσμος και ως πρόθεση — κρίνεται πάντα από τα συμφραζόμενα."},{"h":"Κατάταξη των μορίων κατά λειτουργία — γενικός πίνακας","body":"<p>Τα μόρια ταξινομούνται κατά τη λειτουργία τους μέσα στον λόγο. Η σχολική παράδοση (ΟΕΔΒ/ΙΕΠ) και οι μεγάλες γραμματικές (Smyth) συγκλίνουν στις παρακάτω κατηγορίες. Ένα μόριο μπορεί να ανήκει σε <b>περισσότερες</b> κατηγορίες ανάλογα με τη χρήση.</p><h3>Οι κύριες κατηγορίες</h3><ul><li><b>Βεβαιωτικά</b> (επιβεβαιώνουν): <i>ναί, δή, δῆτα, δήπου, γε, ἦ, μήν, τοι, που, νυν, οὖν, ἄρα</i>.</li><li><b>Δυνητικό</b> (δηλώνει το δυνατόν / υποθετικό): <i>ἄν</i> (και τα ποιητικά <i>κε(ν)</i>).</li><li><b>Αοριστολογικό</b> (δηλώνει αοριστία): <i>ἄν</i> με υποτακτική σε δευτερεύουσες.</li><li><b>Προτρεπτικά / παρακελευσματικά</b> (προτρέπουν): <i>ἄγε, φέρε, ἴθι, δεῦρο</i> (συχνά + <i>δή</i>).</li><li><b>Ευχετικά</b> (εισάγουν ευχή): <i>εἴθε, εἰ γάρ, ὡς</i>.</li><li><b>Επιτατικά / εμφατικά</b> (επιτείνουν): <i>γε, δή, καί δή, περ, ὡς</i>.</li><li><b>Περιοριστικά</b> (περιορίζουν): <i>γε, περ</i>.</li><li><b>Αιτιολογικά</b> (δηλώνουν αιτία, με μετοχή): <i>ἅτε, οἷον (δή), οἷα (δή), ὡς</i>.</li><li><b>Ερωτηματικά</b> (εισάγουν ερώτηση): <i>ἆρα, ἦ, μῶν, οὐ, μή, ἄρα</i>.</li><li><b>Αρνητικά</b> (αρνούνται): <i>οὐ (οὐκ, οὐχ), μή</i>.</li><li><b>Δηκτικά / δεικτικά</b> (αχώριστα, δηλώνουν δείξη): <i>-δε, -ί</i> (ὅ-δε, οὑτοσ-ί).</li><li><b>Αχώριστα προθηματικά</b> (μόνο σε σύνθεση): <i>ἀ- (στερητικό), νη-, δυσ-, ἀρι-/ἐρι-, ζα-, ἀγα-</i>.</li></ul><p>Στην πράξη, στα κείμενα του σχολείου τα συχνότερα προς αναγνώριση είναι το <b>ἄν</b> (δυνητικό/αοριστολογικό) και το <b>ὡς</b> (πολυλειτουργικό). Στα επόμενα μπλοκ αναλύονται ένα προς ένα.</p>","table":{"title":"Συνοπτικός πίνακας μορίων κατά λειτουργία","cols":["Κατηγορία","Μόρια","Λειτουργία / σημασία"],"rows":[["Βεβαιωτικά","ναί, δή, δῆτα, δήπου, γε, ἦ, μήν, τοι, νυν, οὖν, ἄρα","πράγματι, βέβαια, ασφαλώς"],["Δυνητικό","ἄν (κε/κεν)","το δυνατόν, το υπό προϋπόθεση («θα»)"],["Αοριστολογικό","ἄν + υποτακτική","αοριστία (όποιος, όποτε, όπου τυχόν)"],["Προτρεπτικά","ἄγε, φέρε, ἴθι, δεῦρο (+δή)","εμπρός, έλα, άντε"],["Ευχετικά","εἴθε, εἰ γάρ, ὡς","μακάρι"],["Επιτατικά","γε, δή, καί δή, περ, ὡς","ακριβώς, μάλιστα, και δη"],["Περιοριστικά","γε, περ","τουλάχιστον, μόνο"],["Αιτιολογικά (+μετοχή)","ἅτε, οἷον (δή), οἷα (δή), ὡς","επειδή / με την ιδέα ότι"],["Ερωτηματικά","ἆρα, ἦ, μῶν, ἄρα, οὐ, μή","άραγε; μήπως;"],["Αρνητικά","οὐ(κ/χ), μή","δεν, μην"],["Δηκτικά (αχώριστα)","-δε, -ί","δείξη: ὅδε, οὑτοσί, ὡδί"]]},"examples":[{"gr":"ἴθι δή λέγε.","an":"Έλα λοιπόν, μίλα. (<i>ἴθι</i> προτρεπτικό + <i>δή</i> επιτατικό — η συνηθέστερη σύζευξη.)"},{"gr":"ἅτε παῖς ὤν, ἔχαιρε.","an":"Επειδή ήταν παιδί, χαιρόταν. (<i>ἅτε</i> αιτιολογικό μόριο με αιτιολογική μετοχή· δηλώνει αιτία πραγματική.)"},{"gr":"ἆρα δικαίως ἄν ἀπολοίμην;","an":"Άραγε δίκαια θα χανόμουν; (ερωτηματικό <i>ἆρα</i> + δυνητικό <i>ἄν</i> — δύο μόρια διαφορετικών κατηγοριών σε μία πρόταση.)"},{"gr":"οἷα δή παῖς, ἐδάκρυσεν.","an":"Όπως ήταν φυσικό για παιδί, δάκρυσε. (<i>οἷα δή</i> αιτιολογικό μόριο + μετοχή· αιτία θεωρούμενη πραγματική.)"}],"note":"Προσοχή στη διαφορά αιτιολογικών μορίων: <i>ἅτε / οἷον / οἷα</i> δηλώνουν αιτία που ο ομιλητής θεωρεί <b>πραγματική</b>· αντίθετα το <i>ὡς</i> + μετοχή δηλώνει αιτία <b>υποκειμενική</b> (κατά τη γνώμη του υποκειμένου, «με την ιδέα ότι»)."},{"h":"Το δυνητικό ἄν — η σημαντικότερη χρήση","body":"<p>Το <b>δυνητικό ἄν</b> είναι μόριο που, σε συνδυασμό με ορισμένες εγκλίσεις, δηλώνει ότι μια ενέργεια είναι <b>δυνατή, πιθανή ή εξαρτημένη από προϋπόθεση</b> (= το αγγλικό «would/could», το νεοελληνικό «θα»). Δεν μεταφράζεται μόνο του· συγχωνεύεται με το ρήμα στη μετάφραση («θα ...»).</p><h3>Με ποιες εγκλίσεις συντάσσεται</h3><p>Το δυνητικό <i>ἄν</i> συνοδεύει <b>τέσσερις</b> ρηματικούς τύπους και σχηματίζει αντίστοιχα:</p><ul><li><b>Δυνητική οριστική</b>: <i>ἄν</i> + οριστική <b>ιστορικού χρόνου</b> (παρατατικού, αορίστου, σπανιότ. υπερσυντελίκου). Δηλώνει το <b>μη πραγματικό / αντίθετο προς την πραγματικότητα</b> στο παρελθόν ή το δυνατό στο παρελθόν. Απόδοση: «θα + παρατατικό/συντελ.».</li><li><b>Δυνητική ευκτική</b>: <i>ἄν</i> + ευκτική (κάθε χρόνου <b>πλην μέλλοντα</b>). Δηλώνει το <b>δυνατό ή πιθανό στο παρόν/μέλλον</b>, με ευγενική ή διστακτική χροιά. Απόδοση: «θα + παρατατικό», «θα μπορούσε».</li><li><b>Δυνητικό απαρέμφατο</b>: <i>ἄν</i> + απαρέμφατο (όχι μέλλοντα). Στον πλάγιο λόγο ισοδυναμεί με δυνητική οριστική ή ευκτική.</li><li><b>Δυνητική μετοχή</b>: <i>ἄν</i> + μετοχή (όχι τελική/υποθετική). Ισοδυναμεί με δυνητική έγκλιση.</li></ul><h3>Εκφορά — θέση του ἄν</h3><p>Κανονικά το <i>ἄν</i> μπαίνει <b>μετά</b> το ρήμα ή κοντά του. Προτάσσεται όμως όταν στην πρόταση προηγείται <b>ερωτηματική λέξη, άρνηση</b> ή λέξη με έμφαση (π.χ. <i>οὐκ ἄν, τίς ἄν, πῶς ἄν</i>). Σε μακρά περίοδο το <i>ἄν</i> μπορεί να επαναλαμβάνεται για έμφαση/σαφήνεια.</p>","examples":[{"gr":"οὐκ ἄν ἐποίησα τοῦτο.","an":"Δεν θα έκανα / δεν θα είχα κάνει αυτό. (δυνητική οριστική αορίστου· το αντίθετο του πραγματικού στο παρελθόν· πρόταξη λόγω της άρνησης <i>οὐκ</i>.)"},{"gr":"ἡδέως ἄν ἀκούσαιμι.","an":"Ευχαρίστως θα άκουγα. (δυνητική ευκτική αορίστου· δυνατό/πιθανό στο παρόν–μέλλον, ευγενική διατύπωση· τύπου συνήθους αττικής φράσης.)"},{"gr":"τίς ἄν τοῦτο πιστεύσειεν;","an":"Ποιος θα το πίστευε αυτό; (δυνητική ευκτική σε ερώτηση· το <i>ἄν</i> προτάσσεται μετά το ερωτηματικό <i>τίς</i>.)"},{"gr":"νομίζω αὐτόν ἄν ἐλθεῖν.","an":"Νομίζω ότι αυτός θα ερχόταν. (δυνητικό απαρέμφατο αορίστου στον πλάγιο λόγο = δυνητική ευκτική «ἔλθοι ἄν».)"},{"gr":"ῥᾳδίως ἄν νικήσαντες ἀπῆλθον.","an":"Αφού θα νικούσαν εύκολα, έφυγαν. (δυνητική μετοχή· η μετοχή + <i>ἄν</i> ισοδυναμεί με δυνητική έγκλιση.)"},{"gr":"πάνυ γάρ ἡδέως ἄν τοῦτο ἀκούσαιμι.","an":"Διότι πολύ ευχαρίστως θα το άκουγα αυτό. (Ξεν. Ἀπομν. 3.6.10 — δυνητική ευκτική αορίστου με ευγενική χροιά.)"},{"gr":"οὐκ ἄν δικαίως οὗτος ὠφεληθείη.","an":"Δεν θα ωφελούνταν δίκαια αυτός. (τύπου ρητορικού λόγου — δυνητική ευκτική αορίστου με πρόταξη λόγω της άρνησης <i>οὐκ</i>.)"}],"note":"Μνημονικός κανόνας: δυνητικό <i>ἄν</i> → πάντα με οριστική <b>ιστορικού</b> χρόνου, ευκτική (όχι μέλλοντα), απαρέμφατο ή μετοχή. ΠΟΤΕ με υποτακτική στον δυνητικό ρόλο, ΠΟΤΕ με οριστική μέλλοντα, ΠΟΤΕ με ευκτική μέλλοντα."},{"h":"Το αοριστολογικό ἄν και η διάκρισή του από το δυνητικό","body":"<p>Το <b>αοριστολογικό ἄν</b> (λέγεται και αναφορικό-υποθετικό ή «ἄν της αοριστίας») είναι παραλλαγή του ίδιου μορίου, αλλά με <b>εντελώς διαφορετική λειτουργία</b>: δεν δηλώνει το δυνατό, αλλά την <b>αοριστία</b> — ότι το πρόσωπο, το πράγμα, ο χρόνος ή ο τρόπος μένουν αόριστα («όποιος τυχόν», «όποτε τυχόν», «όπου τυχόν»). Συχνά μένει αμετάφραστο ή αποδίδεται με το «τυχόν / αν».</p><h3>Πού εμφανίζεται — εισαγωγή & εκφορά</h3><p>Το αοριστολογικό <i>ἄν</i> βρίσκεται σε <b>δευτερεύουσες προτάσεις</b> και συντάσσεται <b>πάντα με υποτακτική</b>. Ακολουθεί αμέσως μετά τη λέξη που εισάγει την πρόταση:</p><ul><li><b>Αναφορικές</b> (αναφορικές αντωνυμίες/επιρρήματα): <i>ὅς ἄν, ὅστις ἄν, ὅπου ἄν, ὅπως ἄν</i>.</li><li><b>Χρονικές–υποθετικές</b>: <i>ὅτε ἄν, ὁπότε ἄν, ἐπεί ἄν, ἐπειδάν</i>.</li><li><b>Υποθετικές</b>: το <i>ἄν</i> εδώ συγχωνεύεται στον υποθετικό σύνδεσμο → <i>εἰ + ἄν = ἐάν / ἤν / ἄν</i>.</li></ul><h3>Συγχωνεύσεις (κράσεις) — να τις αναγνωρίζετε</h3><p><i>ὅτε + ἄν = ὅταν· ὁπότε + ἄν = ὁπόταν· ἐπεί + ἄν = ἐπάν / ἐπήν· ἐπειδή + ἄν = ἐπειδάν· εἰ + ἄν = ἐάν (ἤν, ἄν)</i>. Σε όλα αυτά το ενσωματωμένο <i>ἄν</i> είναι αοριστολογικό.</p>","examples":[{"gr":"ὅς ἄν ταῦτα ποιῇ, τιμᾶται.","an":"Όποιος τυχόν τα κάνει αυτά, τιμάται. (αοριστολογικό <i>ἄν</i> σε αναφορική + υποτακτική <i>ποιῇ</i>· δηλώνει αόριστο πρόσωπο.)"},{"gr":"ὅταν βούλωνται, ἀπέρχονται.","an":"Όποτε τυχόν θέλουν, φεύγουν. (<i>ὅταν = ὅτε + ἄν</i>· αοριστολογικό, με υποτακτική <i>βούλωνται</i>· αόριστος χρόνος-περίσταση.)"},{"gr":"ἐάν τοῦτο πράξῃς, εὖ ἕξει.","an":"Αν τυχόν το κάνεις αυτό, θα είναι καλά. (<i>ἐάν = εἰ + ἄν</i>· υποθετική με υποτακτική <i>πράξῃς</i>.)"},{"gr":"ὅστις ἄν ἔλθῃ, δεχόμεθα.","an":"Όποιος τυχόν έρθει, τον δεχόμαστε. (αοριστολογικό <i>ἄν</i> σε αναφορική αοριστολογική + υποτακτική αορίστου <i>ἔλθῃ</i>.)"},{"gr":"ἐπειδάν πάντα ἀκούσητε, κρίνατε.","an":"Όταν τυχόν τα ακούσετε όλα, κρίνετε. (<i>ἐπειδάν = ἐπειδή + ἄν</i>· χρονικοϋποθετική με υποτακτική <i>ἀκούσητε</i>.)"}],"table":{"title":"Δυνητικό ἄν vs Αοριστολογικό ἄν — η κρίσιμη διάκριση","cols":["Κριτήριο","Δυνητικό ἄν","Αοριστολογικό ἄν"],"rows":[["Σημασία","το δυνατό / υποθετικό («θα»)","αοριστία («όποιος/όποτε/όπου τυχόν»)"],["Έγκλιση","οριστ. ιστορικού, ευκτική, απαρέμφ., μετοχή","ΠΑΝΤΑ υποτακτική"],["Πρόταση","κύρια (και πλάγιος λόγος)","δευτερεύουσα (αναφορ./χρον./υποθετ.)"],["Θέση","μετά/κοντά στο ρήμα","αμέσως μετά τη λέξη εισαγωγής"],["Συγχωνεύσεις","—","ὅταν, ὁπόταν, ἐπάν, ἐπειδάν, ἐάν"],["Μετάφραση","«θα + ρήμα»","«τυχόν / αν» ή αμετάφραστο"]]},"note":"Πρακτικός κανόνας αναγνώρισης: βρες πρώτα την έγκλιση. Υποτακτική → αοριστολογικό. Οριστική ιστορικού χρόνου ή ευκτική (όχι μέλλ.) → δυνητικό. Μετά έλεγξε τη θέση: μετά από αναφορική/χρονική λέξη σε δευτερεύουσα → αοριστολογικό."},{"h":"Βεβαιωτικά και επιτατικά–περιοριστικά μόρια: δή, δῆτα, δήπου, γε, μήν, τοι, νυν, περ","body":"<p>Η μεγαλύτερη ομάδα μορίων χρωματίζει τη φράση δηλώνοντας <b>βεβαίωση, έμφαση, επίταση ή περιορισμό</b>. Η μετάφρασή τους είναι λεπτή· σπάνια αποδίδονται με μία λέξη.</p><h3>Βεβαιωτικά / εμφατικά</h3><ul><li><b>δή</b>: «βέβαια, πράγματι, λοιπόν». Βεβαιώνει και επιτείνει. Συχνά συνοδεύει προτρεπτικά (<i>ἄγε δή, ἴθι δή, φέρε δή</i>) ή δεικτικά (<i>καί δή</i>). Τίθεται μετά τη λέξη που τονίζει.</li><li><b>δῆτα</b>: ενισχυμένος τύπος του <i>δή</i> («ασφαλώς, βεβαιότατα»)· συχνά σε απαντήσεις, ερωτήσεις και αρνήσεις (<i>οὐ δῆτα</i> = όχι βέβαια).</li><li><b>δήπου</b>: «προφανώς, υποθέτω, φαντάζομαι» — βεβαίωση με μια απόχρωση <i>πιθανολογίας / επιφύλαξης</i> (από <i>δή + που</i>).</li><li><b>μήν</b>: ισχυρό βεβαιωτικό («αλήθεια, βέβαια»), συχνά <i>καί μήν</i> (= και όμως / και μάλιστα), <i>ἀλλά μήν</i>, <i>οὐ μήν ἀλλά</i> (= όμως, εντούτοις).</li><li><b>τοι</b>: εγκλιτικό βεβαιωτικό («βεβαίως, ξέρεις»), με χροιά απεύθυνσης στον ακροατή· από αυτό παράγονται <i>τοίνυν, τοιγαροῦν, καίτοι, μέντοι</i>.</li><li><b>νυν</b> (εγκλιτικό, χωρίς περισπωμένη — διαφορετικό από το χρονικό <i>νῦν</i>): συμπερασματικό-βεβαιωτικό «λοιπόν» σε προτροπές.</li></ul><h3>Επιτατικά–περιοριστικά</h3><ul><li><b>γε</b>: εγκλιτικό, διπλής χρήσης. <b>Επιτατικό</b> («ακριβώς, μάλιστα») όταν τονίζει· <b>περιοριστικό</b> («τουλάχιστον, μόνο») όταν περιορίζει. Κολλά στη λέξη που εξαίρει (<i>ἔγωγε</i> = εγώ τουλάχιστον).</li><li><b>περ</b>: εγκλιτικό επιτατικό-περιοριστικό («ακριβώς, μολονότι»). Προσκολλάται σε αναφορικά/μετοχές: <i>ὅσπερ</i> (= αυτός ακριβώς που), <i>καίπερ</i> (+ εναντιωματική μετοχή = αν και).</li></ul>","examples":[{"gr":"οὗτος δή ἐστιν ὁ ἀνήρ.","an":"Αυτός είναι ασφαλώς ο άνδρας. (<i>δή</i> βεβαιωτικό-εμφατικό, μετά το δεικτικό.)"},{"gr":"οὐ δῆτα.","an":"Όχι βέβαια. (<i>δῆτα</i> ενισχύει την άρνηση σε απάντηση.)"},{"gr":"οἶσθα δήπου τόν ἄνδρα.","an":"Ξέρεις, φαντάζομαι, τον άνδρα. (<i>δήπου</i> = βεβαίωση με ελαφρά επιφύλαξη.)"},{"gr":"καί μήν ἀληθῆ λέγω.","an":"Και όμως αλήθεια λέω. (<i>καί μήν</i> ισχυρό βεβαιωτικό, εισάγει νέο επιχείρημα.)"},{"gr":"ἔγωγε οὐ φοβοῦμαι.","an":"Εγώ τουλάχιστον δεν φοβάμαι. (<i>γε</i> περιοριστικό, κολλημένο στο <i>ἐγώ</i>.)"},{"gr":"καίπερ νέος ὤν, σοφός ἐστιν.","an":"Αν και είναι νέος, είναι σοφός. (<i>καίπερ</i> = <i>καί + περ</i>, με εναντιωματική μετοχή.)"},{"gr":"τοῦτο μέν τοι σαφές ἐστιν.","an":"Αυτό βεβαίως είναι σαφές. (εγκλιτικό βεβαιωτικό <i>τοι</i> με χροιά απεύθυνσης στον ακροατή — «να ξέρεις».)"},{"gr":"ἀλλά μήν καί τοῦτο δίκαιον.","an":"Και όμως και αυτό είναι δίκαιο. (<i>ἀλλά μήν</i> ισχυρό βεβαιωτικό σε μετάβαση/προσθήκη επιχειρήματος.)"},{"gr":"πῶς γάρ οὔ;","an":"Πώς όχι δηλαδή; (το <i>γε/γάρ</i> τύπου επιβεβαιωτικής ρητορικής ερώτησης — «ασφαλώς ναι».)"}],"note":"Το <i>γε</i> δεν είναι ποτέ όρος της πρότασης: αλλάζει μόνο την έμφαση. Στη μετάφραση κρίνε από τα συμφραζόμενα αν τονίζει (επιτατικό «ακριβώς») ή αν περιορίζει (περιοριστικό «τουλάχιστον»)."},{"h":"Προτρεπτικά, ευχετικά και συμπερασματικά–μεταβατικά μόρια: ἄγε/φέρε/ἴθι, εἴθε, οὖν/τοίνυν/ἄρα","body":"<p>Άλλη μεγάλη λειτουργική ομάδα είναι όσα μόρια <b>κινητοποιούν</b> (προτροπή), <b>εκφράζουν ευχή</b> ή <b>συνδέουν λογικά</b> τον λόγο (συμπέρασμα, μετάβαση).</p><h3>Προτρεπτικά / παρακελευσματικά</h3><p>Είναι κατά βάση παγιωμένες προστακτικές που λειτουργούν ως μόρια προτροπής, σχεδόν πάντα + <i>δή</i> και μια προστακτική/υποτακτική: <b>ἄγε (δή)</b>, <b>φέρε (δή)</b>, <b>ἴθι (δή)</b>, <b>δεῦρο</b>. Σημασία: «εμπρός, άντε, έλα». Η σύνταξη δεν αλλάζει στον αριθμό (λέμε <i>ἄγε</i> ακόμη και σε πολλούς).</p><h3>Ευχετικά</h3><p><b>εἴθε</b> και <b>εἰ γάρ</b> εισάγουν ευχετική ευκτική (πραγματοποιήσιμη ευχή) ή ευχετική οριστική ιστορικού χρόνου (ανεκπλήρωτη ευχή)· σημασία «μακάρι». Το <b>ὡς</b> επίσης εισάγει ευχή.</p><h3>Συμπερασματικά / μεταβατικά</h3><ul><li><b>οὖν</b>: «λοιπόν, επομένως» — συμπερασματικό και μεταβατικό· τίθεται 2ο στην πρόταση. Σε ενώσεις: <i>μέν οὖν</i> (= βέβαια / μάλλον), <i>δ' οὖν</i> (= εν πάση περιπτώσει), <i>ἄρ' οὖν</i>.</li><li><b>τοίνυν</b> (από <i>τοι + νυν</i>): «λοιπόν, επομένως» — συμπερασματικό-μεταβατικό, συχνά σε επιχειρηματολογία.</li><li><b>ἄρα</b> (με ψιλή + οξεία): <b>συμπερασματικό / συνειρμικό</b> «λοιπόν, άρα, ώστε». Δηλώνει λογικό συμπέρασμα ή ξαφνική διαπίστωση («τελικά»). ΔΕΝ είναι ερωτηματικό — αυτό είναι το <i>ἆρα</i> (βλ. επόμενο μπλοκ).</li></ul>","examples":[{"gr":"ἄγε δή, σκόπει.","an":"Εμπρός λοιπόν, εξέτασε. (<i>ἄγε δή</i> προτρεπτικό + επιτατικό <i>δή</i> + προστακτική.)"},{"gr":"φέρε δή ἴδωμεν.","an":"Έλα λοιπόν να δούμε. (<i>φέρε δή</i> + προτρεπτική υποτακτική <i>ἴδωμεν</i>.)"},{"gr":"εἴθε γένοιτο.","an":"Μακάρι να γινόταν. (ευχετικό <i>εἴθε</i> + ευχετική ευκτική — πραγματοποιήσιμη ευχή.)"},{"gr":"εἴθε μή ἀπέθανεν.","an":"Μακάρι να μην είχε πεθάνει. (<i>εἴθε</i> + οριστική ιστορικού χρόνου — ανεκπλήρωτη ευχή.)"},{"gr":"πάντες ἄρα θνητοί ἐσμεν.","an":"Άρα όλοι είμαστε θνητοί. (συμπερασματικό <i>ἄρα</i> — εξάγει λογικό συμπέρασμα.)"},{"gr":"οὐκ ἦν ἄρα σοφός.","an":"Δεν ήταν τελικά σοφός. (<i>ἄρα</i> ξαφνικής διαπίστωσης — «όπως αποδείχθηκε».)"},{"gr":"ἀθάνατος τοίνυν ἡ ψυχή.","an":"Επομένως η ψυχή είναι αθάνατη. (συμπερασματικό-μεταβατικό <i>τοίνυν</i> σε επιχειρηματολογία, 2η θέση.)"},{"gr":"εἰ γάρ μοι γένοιτο τοῦτο.","an":"Μακάρι να μου συνέβαινε αυτό. (ευχετικό <i>εἰ γάρ</i> + ευχετική ευκτική — πραγματοποιήσιμη ευχή.)"},{"gr":"τί οὖν ποιῶμεν;","an":"Τι λοιπόν να κάνουμε; (μεταβατικό-συμπερασματικό <i>οὖν</i> σε απορηματική υποτακτική.)"}],"note":"Μην συγχέεις: <i>νῦν</i> (περισπωμένη) = χρονικό επίρρημα «τώρα»· <i>νυν</i> (εγκλιτικό, άτονο/οξεία) = συμπερασματικό «λοιπόν». Ομοίως <i>τοίνυν</i> (συμπερασματικό) ≠ <i>τοι + νῦν</i>."},{"h":"Διάκριση ομώνυμων μορίων (ἄρα/ἆρα, ἤ/ἦ) και το πολυλειτουργικό ὡς","body":"<p>Πολλά μόρια ξεχωρίζουν <b>μόνο από τον τόνο/πνεύμα</b>. Η σωστή γραφή είναι αυτή που αποκαλύπτει τη σημασία. Αυτή είναι από τα πιο εξεταζόμενα σημεία.</p><h3>ἄρα vs ἆρα</h3><ul><li><b>ἄρα</b> (ψιλή + οξεία, 2η θέση): <b>συμπερασματικό/βεβαιωτικό</b> «λοιπόν, άρα, τελικά». Δεν εισάγει ερώτηση.</li><li><b>ἆρα</b> (ψιλή + περισπωμένη, αρχή πρότασης): <b>ερωτηματικό</b> «άραγε;». Ουδέτερο ως προς την απάντηση· <i>ἆρ' οὐ</i> περιμένει «ναι», <i>ἆρα μή</i> περιμένει «όχι».</li></ul><h3>ἤ vs ἦ</h3><ul><li><b>ἤ</b> (οξεία): <b>διαζευκτικός σύνδεσμος</b> «ή» (ή συγκριτικό «παρά»: <i>μᾶλλον ἤ</i>).</li><li><b>ἦ</b> (περισπωμένη): <b>βεβαιωτικό</b> μόριο «πράγματι, αλήθεια»· σε ερώτηση <i>ἦ;</i> = «άραγε;» (παλαιότερο ερωτηματικό). Πβ. <i>ἦ μήν</i> = «αληθώς» (όρκος), <i>ἦ που</i> = «ασφαλώς».</li></ul><h3>Το μόριο/λέξη ὡς — όλες οι χρήσεις</h3><p>Το <b>ὡς</b> είναι η πιο πολυλειτουργική λέξη· κρίνεται από τα συμφραζόμενα:</p><ul><li><b>Σύνδεσμος</b>: ειδικός («ότι»), αιτιολογικός («επειδή»), τελικός («για να»), συμπερασματικός («ώστε»), χρονικός («μόλις, όταν»), πλάγιος ερωτηματικός («πώς»).</li><li><b>Με μετοχή</b>: αιτιολογική υποκειμενική («με την ιδέα ότι») ή τελική (+ μέλλοντα: «για να»).</li><li><b>Επιτατικό μόριο</b>: + υπερθετικό = «όσο το δυνατόν» (<i>ὡς τάχιστα</i> = όσο γίνεται γρηγορότερα).</li><li><b>Καταχρηστική πρόθεση</b>: + αιτιατική προσώπου = «προς» (<i>ὡς βασιλέα</i>)· + αριθμητικό = «περίπου» (<i>ὡς διακοσίους</i>).</li><li><b>Επιφωνηματικό</b>: «πόσο!» (<i>ὡς καλόν!</i>).</li><li><b>Ευχετικό</b> και <b>δεικτικό επίρρημα</b> («έτσι»).</li></ul>","examples":[{"gr":"ἆρα μανθάνεις;","an":"Άραγε καταλαβαίνεις; (ερωτηματικό <i>ἆρα</i> — περισπωμένη, αρχή πρότασης.)"},{"gr":"ἀθάνατος ἄρα ἡ ψυχή.","an":"Άρα η ψυχή είναι αθάνατη. (συμπερασματικό <i>ἄρα</i> — οξεία, 2η θέση.)"},{"gr":"ἦ καλῶς ἔλεξας.","an":"Πράγματι μίλησες καλά. (βεβαιωτικό <i>ἦ</i> — περισπωμένη.)"},{"gr":"βούλει τοῦτο ἤ ἐκεῖνο;","an":"Θέλεις αυτό ή εκείνο; (διαζευκτικό <i>ἤ</i> — οξεία.)"},{"gr":"λέγει ὡς οὐδέν οἶδεν.","an":"Λέει ότι δεν ξέρει τίποτα. (<i>ὡς</i> ειδικός σύνδεσμος.)"},{"gr":"ὡς τάχιστα ἀπῆλθον.","an":"Έφυγαν όσο το δυνατόν γρηγορότερα. (<i>ὡς</i> επιτατικό + υπερθετικό.)"},{"gr":"ἐπορεύετο ὡς βασιλέα.","an":"Πορευόταν προς τον βασιλιά. (<i>ὡς</i> καταχρηστική πρόθεση + αιτιατική προσώπου.)"},{"gr":"ἆρ' οὐ δίκαιόν ἐστι;","an":"Δεν είναι άραγε δίκαιο; (<i>ἆρ' οὐ</i> ερωτηματικό που περιμένει καταφατική απάντηση «ναι».)"},{"gr":"συνέλαβον ὡς ἀδικοῦντα.","an":"Τον συνέλαβαν με την ιδέα ότι αδικεί. (<i>ὡς</i> + μετοχή = αιτιολογία υποκειμενική, κατά τη γνώμη του υποκειμένου.)"}],"table":{"title":"Ομώνυμα μόρια — διακριτική γραφή","cols":["Τύπος","Γραφή","Λειτουργία","Σημασία"],"rows":[["ἄρα","ψιλή + οξεία, 2η θέση","συμπερασματικό/βεβαιωτικό","λοιπόν, άρα, τελικά"],["ἆρα","ψιλή + περισπωμένη, αρχή","ερωτηματικό","άραγε;"],["ἤ","οξεία","διαζευκτ./συγκριτ. σύνδεσμος","ή / παρά"],["ἦ","περισπωμένη","βεβαιωτικό / ερωτημ.","πράγματι / άραγε;"],["νῦν","περισπωμένη","χρονικό επίρρημα","τώρα"],["νυν","εγκλιτικό","συμπερασματικό μόριο","λοιπόν"],["που","εγκλιτικό","βεβαιωτικό-διστακτικό","ίσως, υποθέτω"],["ποῦ","περισπωμένη","ερωτηματικό επίρρημα","πού;"]]},"note":"Κανόνας γραφής της σχολής (και της παρούσας θεωρίας): χρησιμοποιούμε ΟΞΕΙΑ, ποτέ βαρεία. Η περισπωμένη μένει μόνο εκεί που τη ζητά ο τύπος (ἆρα, ἦ, νῦν, ποῦ). Για τα μέν...δέ, πω/πώποτε και τα αχώριστα, βλ. το επόμενο μπλοκ."},{"h":"μέν...δέ, τα αρνητικά (οὐ/μή), πω/πώποτε και τα αχώριστα μόρια","body":"<p>Ολοκληρώνουμε με τέσσερις ακόμη ενότητες που συμπληρώνουν την πλήρη εικόνα.</p><h3>Το ζεύγος μέν ... δέ</h3><p>Το <b>μέν</b> και το <b>δέ</b> είναι μόρια <b>αντιδιαστολής/εξισορρόπησης</b> που τίθενται 2α στην πρότασή τους. Το <i>μέν</i> προαναγγέλλει ότι θα ακολουθήσει αντίθεση· το <i>δέ</i> την εισάγει. Σημασία: «από τη μια ... από την άλλη», «αφενός ... αφετέρου». Συχνά μένουν αμετάφραστα και αποδίδονται μόνο με τη στίξη. Μεμονωμένο <i>δέ</i> = «και / αλλά» (μεταβατικό–αντιθετικό). Το <i>μέν</i> μπορεί να σταθεί και μόνο του (<i>μέν δή, μέν οὖν</i>) ως βεβαιωτικό.</p><h3>Αρνητικά: οὐ και μή</h3><ul><li><b>οὐ (οὐκ / οὐχ)</b>: <b>αντικειμενική</b> άρνηση — αρνείται πραγματικά γεγονότα και κρίσεις· συντάσσεται με οριστική (και δυνητική ευκτική). <i>οὐκ</i> πριν από φωνήεν με ψιλή, <i>οὐχ</i> πριν από δασυνόμενο.</li><li><b>μή</b>: <b>υποκειμενική</b> άρνηση — σε ευχές, προστακτικές, υποθέσεις, τελικές, ενδοιαστικές, με υποτακτική/προστακτική/ευκτική ευχετική, απαρέμφατο και μετοχή υποθετική.</li></ul><p>Διπλές αρνήσεις: <i>οὐ ... οὐδείς</i> (όμοιες) → ενισχύεται η άρνηση· <i>οὐδείς ... οὐ</i> ή <i>οὐ μή</i> (+ υποτ./μελλ.) → ισχυρή άρνηση/απαγόρευση· <i>μή οὐ</i> → μετά από φόβο/άρνηση.</p><h3>πω / πώποτε</h3><p><b>πω</b> (εγκλιτικό) σε αρνητικά συμφραζόμενα = «ακόμη» (<i>οὔπω</i> = όχι ακόμη, <i>μήπω</i>). <b>πώποτε</b> = «ποτέ ως τώρα» (<i>οὐ πώποτε</i> = ποτέ μέχρι σήμερα).</p><h3>Αχώριστα μόρια</h3><ul><li><b>Δηκτικά/δεικτικά</b>: <i>-δε</i> (ὅδε, τοιόσδε, ἐνθάδε) και <i>-ί</i> (οὑτοσί, ὡδί, νυνί) — δηλώνουν ζωηρή δείξη («αυτός εδώ»).</li><li><b>Προθηματικά (μόνο σε σύνθεση)</b>: <i>ἀ-/ἀν-</i> στερητικό (ἄδικος), <i>νη-</i> στερητικό (νήποινος), <i>δυσ-</i> (δυστυχής), <i>ἀρι-/ἐρι-</i> επιτατικά (ἀρίδηλος, ἐρισθενής), <i>ζα-</i> επιτατικό (ζάπλουτος), <i>ἀγα-</i> (ἀγακλυτός).</li></ul>","examples":[{"gr":"οἱ μέν ἔφευγον, οἱ δέ ἐδίωκον.","an":"Άλλοι έφευγαν και άλλοι κατεδίωκαν. (<i>μέν ... δέ</i> αντιδιαστολή· αποδίδεται με «άλλοι ... άλλοι».)"},{"gr":"ἐγώ μέν οἶμαι, σύ δέ οὔ.","an":"Εγώ νομίζω, εσύ όμως όχι. (<i>μέν</i> προαναγγέλλει, <i>δέ</i> εισάγει την αντίθεση.)"},{"gr":"οὐκ ἔστι ταῦτα ἀληθῆ.","an":"Δεν είναι αυτά αληθινά. (<i>οὐκ</i> αντικειμενική άρνηση + οριστική.)"},{"gr":"μή ποίει τοῦτο.","an":"Μην το κάνεις αυτό. (<i>μή</i> υποκειμενική άρνηση + προστακτική — απαγόρευση.)"},{"gr":"οὐ πώποτε εἶδον τοιοῦτον.","an":"Ποτέ ως τώρα δεν είδα τέτοιον. (<i>πώποτε</i> σε άρνηση = «ποτέ μέχρι τώρα».)"},{"gr":"οὗτος ὁ ἀνήρ οὑτοσί.","an":"Αυτός εδώ ο άνδρας. (αχώριστο δηκτικό <i>-ί</i> για ζωηρή δείξη.)"},{"gr":"οὐδείς πώποτε τοῦτο ἐποίησεν.","an":"Κανείς ποτέ ως τώρα δεν το έκανε αυτό. (διπλή ομοειδής άρνηση <i>οὐδείς ... πώποτε</i> → ενισχυμένη άρνηση.)"},{"gr":"φοβοῦμαι μή οὐ δυνώμεθα.","an":"Φοβάμαι μήπως δεν μπορέσουμε. (ενδοιαστική + <i>μή οὐ</i> = «μήπως δεν», μετά από φόβο, με υποτακτική.)"},{"gr":"τοιόσδε ὁ λόγος ἦν.","an":"Τέτοιος (να, αυτός εδώ) ήταν ο λόγος. (αχώριστο δεικτικό <i>-δε</i> με προαναγγελτική δείξη — «ο εξής».)"}],"table":{"title":"οὐ vs μή — αντικειμενική και υποκειμενική άρνηση","cols":["Άρνηση","Είδος","Εγκλίσεις / θέσεις","Παράδειγμα"],"rows":[["οὐ (οὐκ/οὐχ)","αντικειμενική","οριστική, δυνητ. ευκτική, κρίσεις","οὐκ οἶδα = δεν ξέρω"],["μή","υποκειμενική","ευχές, προστ., υποθ., τελικές, ενδοιαστ.","μή φοβοῦ = μη φοβάσαι"],["οὐ μή","ισχυρή άρνηση/απαγόρευση","+ υποτακτική ή μέλλ.","οὐ μή ποιήσῃς = με κανέναν τρόπο μην κάνεις"],["μή οὐ","μετά από φόβο/άρνηση","+ υποτ. ή απαρέμφ.","φοβοῦμαι μή οὐ δύνωμαι"]]},"note":"Σύνοψη: η ορθή ανάγνωση κάθε μορίου περνά από τρία βήματα — (1) γραφή/τόνος (διακρίνει ομώνυμα), (2) έγκλιση & σύνταξη του ρήματος που το συνοδεύει (διακρίνει δυνητικό/αοριστολογικό ἄν, οὐ/μή), (3) θέση στην πρόταση και τα συμφραζόμενα (διακρίνει επιτατικό/περιοριστικό γε, συμπερασματικό/ερωτηματικό ἄρα/ἆρα). Με αυτά τα τρία κλειδιά κανένα μόριο δεν μένει αδιάγνωστο."}]);
  T("syn-prosdiorismoi-basika", [{"h":"Τι είναι ο προσδιορισμός · Κύριοι και δευτερεύοντες όροι της πρότασης","body":"<p><b>Προσδιορισμός</b> ονομάζεται κάθε λέξη (ή σύνολο λέξεων) που <b>προσδιορίζει</b>, δηλαδή συμπληρώνει, περιορίζει ή διασαφηνίζει, τη σημασία ενός άλλου όρου της πρότασης. Ο όρος που δέχεται τον προσδιορισμό λέγεται <b>προσδιοριζόμενος</b>· ο όρος που τον αποδίδει λέγεται <b>προσδιοριστικός</b> (ο προσδιορισμός).</p><h3>Οι όροι της πρότασης</h3><p>Για να κατανοήσουμε τη θέση των προσδιορισμών, πρέπει πρώτα να ξεχωρίσουμε τα είδη των όρων μέσα στην πρόταση. Οι όροι διακρίνονται σε δύο μεγάλες ομάδες:</p><ul><li><b>Κύριοι όροι</b> (τα συστατικά που στηρίζουν τον σκελετό της πρότασης): το <b>υποκείμενο</b>, το <b>ρήμα (κατηγόρημα)</b>, το <b>αντικείμενο</b> και το <b>κατηγορούμενο</b>. Χωρίς αυτούς η πρόταση δεν στέκεται νοηματικά.</li><li><b>Δευτερεύοντες όροι</b> (οι <i>προσδιορισμοί</i>): δεν είναι απαραίτητοι για να υπάρξει η πρόταση, αλλά <i>εμπλουτίζουν</i> και <i>συγκεκριμενοποιούν</i> το νόημα. Π.χ. στο «ὁ <i>σοφός</i> ἀνήρ λέγει», το «σοφός» είναι δευτερεύων όρος (προσδιορισμός): αν λείψει, η πρόταση («ὁ ἀνήρ λέγει») στέκεται ακόμη.</li></ul><h3>Δύο μεγάλες κατηγορίες προσδιορισμών</h3><p>Ανάλογα με το <b>τι προσδιορίζουν</b>, οι προσδιορισμοί χωρίζονται σε:</p><ul><li><b>Ονοματικοί προσδιορισμοί</b>: προσδιορίζουν ένα <i>όνομα</i> (ουσιαστικό, ή λέξη με θέση ονόματος). Είναι κι αυτοί ονόματα (ουσιαστικά, επίθετα, αντωνυμίες, μετοχές, αριθμητικά).</li><li><b>Επιρρηματικοί προσδιορισμοί</b>: προσδιορίζουν κυρίως το <i>ρήμα</i> (ή ένα επίθετο/επίρρημα), φανερώνοντας μια επιρρηματική σχέση (τόπο, χρόνο, τρόπο, αιτία, σκοπό κ.λπ.).</li></ul><p>Οι ονοματικοί υποδιαιρούνται περαιτέρω σε <b>ομοιόπτωτους</b> (βρίσκονται στην ίδια πτώση με τον προσδιοριζόμενο) και <b>ετερόπτωτους</b> (βρίσκονται σε διαφορετική, πλάγια πτώση). Αυτή τη διαίρεση θα αναπτύξουμε στις επόμενες ενότητες.</p>","examples":[{"gr":"Ὁ <b>σοφός</b> ἀνήρ τόν <b>ἑαυτοῦ</b> βίον εὖ διάγει.","an":"«σοφός» = επιθετικός προσδιορισμός (ονοματικός, ομοιόπτωτος) στο «ἀνήρ»· «ἑαυτοῦ» = γενική κτητική (ονοματικός, ετερόπτωτος) στο «βίον»· «εὖ» = επιρρηματικός προσδιορισμός του τρόπου στο ρήμα «διάγει». Κύριοι όροι: ἀνήρ (Υ), διάγει (Ρ), βίον (Α)."},{"gr":"Οἱ Ἀθηναῖοι <b>ἐν τῇ νυκτί</b> τήν πόλιν κατέλαβον.","an":"«ἐν τῇ νυκτί» = εμπρόθετος επιρρηματικός προσδιορισμός του χρόνου στο ρήμα «κατέλαβον». Δευτερεύων όρος: η πρόταση «οἱ Ἀθηναῖοι τήν πόλιν κατέλαβον» στέκεται και χωρίς αυτόν."},{"gr":"Ἐντεῦθεν ἐξελαύνει <b>σταθμούς τρεῖς</b> παρασάγγας <b>εἴκοσι καί δύο</b>.","an":"Τύπου Ξεν. Ἀνάβ. (φόρμουλα πορείας): «τρεῖς» επιθετικός προσδιορισμός (ομοιόπτωτος) στο «σταθμούς»· «εἴκοσι καί δύο» στο «παρασάγγας»· τα ίδια τα «σταθμούς / παρασάγγας» αιτιατικές της έκτασης (επιρρηματικός προσδ.). Δείχνει πώς προσδιορισμοί διαφορετικού τύπου συνυπάρχουν."},{"gr":"Ἐνταῦθα Κῦρος <b>βασίλεια</b> εἶχε καί παράδεισον <b>μέγαν</b>.","an":"Τύπου Ξεν. Ἀνάβ. 1.2: «μέγαν» επιθετικός προσδιορισμός (δευτερεύων όρος) στο «παράδεισον»· κύριοι όροι Κῦρος (Υ), εἶχε (Ρ), βασίλεια/παράδεισον (Α). Χωρίς το «μέγαν» η πρόταση στέκεται."}],"table":{"title":"Κύριοι vs δευτερεύοντες όροι","cols":["Όρος","Κατηγορία","Ρόλος"],"rows":[["Υποκείμενο","Κύριος","Ποιος ενεργεί / για ποιον γίνεται λόγος"],["Ρήμα (κατηγόρημα)","Κύριος","Η ενέργεια ή κατάσταση"],["Αντικείμενο","Κύριος","Δέχεται την ενέργεια του μεταβατικού ρήματος"],["Κατηγορούμενο","Κύριος","Αποδίδει ιδιότητα στο Υ ή στο Α μέσω συνδετικού ρ."],["Προσδιορισμός (ονοματικός / επιρρηματικός)","Δευτερεύων","Συμπληρώνει / περιορίζει / διασαφηνίζει άλλον όρο"]]},"note":"Προσοχή στη διαφορά κατηγορουμένου και κατηγορηματικού προσδιορισμού: το κατηγορούμενο είναι κύριος όρος και απαιτεί συνδετικό ρήμα («ὁ ἀνήρ ἐστί σοφός»), ενώ ο κατηγορηματικός προσδιορισμός είναι δευτερεύων όρος που συνοδεύει άναρθρα το όνομα δίπλα σε οποιοδήποτε ρήμα («μόνος ὁ ἀνήρ ἦλθεν»)."},{"h":"Ονοματικοί προσδιορισμοί · ομοιόπτωτοι (1): παράθεση και επεξήγηση","body":"<p>Οι <b>ομοιόπτωτοι ονοματικοί προσδιορισμοί</b> είναι ονόματα (ή λέξεις με θέση ονόματος) που προσδιορίζουν ένα άλλο όνομα και βρίσκονται στην <b>ίδια πτώση</b> με αυτό. Όταν ο προσδιορισμός είναι <i>ουσιαστικό</i>, έχουμε <b>παράθεση</b> ή <b>επεξήγηση</b>· όταν είναι <i>επίθετο</i> (ή επιθετική λέξη), έχουμε <b>επιθετικό</b> ή <b>κατηγορηματικό προσδιορισμό</b> (επόμενη ενότητα).</p><h3>Α. Παράθεση</h3><p>Η <b>παράθεση</b> είναι ένα ουσιαστικό που τίθεται δίπλα σε ένα άλλο ουσιαστικό (στην ίδια πτώση) και του αποδίδει ένα <b>γνωστό, μόνιμο και ευρύτερο (γενικότερο) γνώρισμα</b>. Προχωρά δηλαδή από το <i>ειδικότερο</i> (το προσδιοριζόμενο, συχνά κύριο όνομα) στο <i>γενικότερο</i>.</p><ul><li>Αναλύεται σε <b>αναφορική πρόταση</b>: «Ἀρχίδαμος ὁ βασιλεύς» = Ἀρχίδαμος, <i>ὅς ἦν βασιλεύς</i>.</li><li>Μεταφράζεται συχνά με το «που είναι…».</li></ul><h3>Β. Επεξήγηση</h3><p>Η <b>επεξήγηση</b> είναι κι αυτή ουσιαστικό ομοιόπτωτο, αλλά λειτουργεί <b>αντίστροφα</b> από την παράθεση: <i>διασαφηνίζει</i> μια αόριστη ή γενική έννοια, κατονομάζοντας τη συγκεκριμένη περίπτωση. Προχωρά δηλαδή από το <i>γενικότερο</i> προς το <i>ειδικότερο</i> (μερικότερη έννοια).</p><ul><li>Μεταφράζεται με το <b>«δηλαδή»</b>.</li><li>Στον γραπτό λόγο συχνά προηγείται κόμμα ή άνω τελεία πριν την επεξήγηση.</li></ul><p><b>Πρακτικός κανόνας διάκρισης:</b> αν ο προσδιορισμός μεταφράζεται «που είναι» και είναι ευρύτερος ⇒ <i>παράθεση</i>· αν μεταφράζεται «δηλαδή» και είναι ειδικότερος/διευκρινιστικός ⇒ <i>επεξήγηση</i>.</p>","examples":[{"gr":"Ἀρχίδαμος <b>ὁ βασιλεύς</b> αὐτῶν ἔλεξε τοιάδε.","an":"Παράθεση: «ὁ βασιλεύς» (ονομαστική, ίδια πτώση με «Ἀρχίδαμος»). Αναλύεται: Ἀρχίδαμος, ὅς ἦν βασιλεύς. Αποδίδει γνωστή, ευρύτερη ιδιότητα."},{"gr":"Ἔχομεν ἡμεῖς <b>οἱ Πέρσαι</b> ὅπλα.","an":"Παράθεση στο «ἡμεῖς»: «οἱ Πέρσαι» (= εμείς, που είμαστε Πέρσες)."},{"gr":"Ὁ βασιλεύς <b>Παυσανίας</b> ἐπορεύετο εἰς τήν Βοιωτίαν.","an":"Επεξήγηση: το κύριο όνομα «Παυσανίας» διασαφηνίζει ποιος είναι ο γενικός όρος «ὁ βασιλεύς» (= ο βασιλιάς, δηλαδή ο Παυσανίας)."},{"gr":"Ἀνέβησαν ἐς τό ὄρος <b>τήν Ἰστώνην</b>.","an":"Τύπου Θουκ. (πρβλ. Θουκ. 3.85.3: «ἐς τό ὄρος τήν Ἰστώνην»): επεξήγηση στο «τό ὄρος» — κατονομάζει το συγκεκριμένο βουνό (= στο βουνό, δηλαδή την Ιστώνη). Ομοιόπτωτη (αιτιατική)."},{"gr":"Κῦρος <b>ὁ τῶν Περσῶν βασιλεύς</b> ἐστράτευσεν ἐπί τήν Ἑλλάδα.","an":"Παράθεση στο «Κῦρος»: «ὁ … βασιλεύς» (ονομαστική, γνωστή/ευρύτερη ιδιότητα· αναλύεται «ὅς ἦν βασιλεύς»). Εντός της η γενική «τῶν Περσῶν» = κτητική."},{"gr":"Ξενοφῶν δέ, <b>ἀνήρ Ἀθηναῖος</b>, συνεστράτευεν.","an":"Τύπου Ξεν. Ἀνάβ. 3.1.4: παράθεση στο «Ξενοφῶν» — «ἀνήρ Ἀθηναῖος» (ονομαστική, ευρύτερο γνώρισμα: άνδρας Αθηναίος)."}],"note":"Προεξαγγελτική παράθεση: ορισμένες ουδέτερες φράσεις (τό λεγόμενον, τό μέγιστον, ὅ δέ δεινότατον, τό κεφάλαιον) μπαίνουν ως παράθεση όχι σε μία λέξη αλλά σε ολόκληρη την πρόταση που ακολουθεί: «Καί <i>τό λεγόμενον</i>, τά καλά τῷ ὄντι χαλεπά»."},{"h":"Ονοματικοί προσδιορισμοί · ομοιόπτωτοι (2): επιθετικός και κατηγορηματικός προσδιορισμός","body":"<p>Όταν ο ομοιόπτωτος προσδιορισμός είναι <b>επίθετο</b> (ή επιθετική λέξη: μετοχή, αντωνυμία, αριθμητικό), διακρίνεται σε <b>επιθετικό</b> και <b>κατηγορηματικό</b>. Η κρίσιμη διαφορά είναι η <b>θέση ως προς το άρθρο</b> και η <b>φύση της ιδιότητας</b> (μόνιμη ή παροδική).</p><h3>Α. Επιθετικός προσδιορισμός</h3><p>Αποδίδει στο ουσιαστικό μια <b>μόνιμη, σταθερή ιδιότητα</b> και βρίσκεται σε <b>επιθετική θέση</b>, δηλαδή είναι κανονικά <b>έναρθρος</b> (ανάμεσα στο άρθρο και το ουσιαστικό, ή με επανάληψη του άρθρου):</p><ul><li><b>ὁ σοφός ἀνήρ</b> (άρθρο – επίθετο – ουσιαστικό), ή</li><li><b>ὁ ἀνήρ ὁ σοφός</b> (ουσιαστικό με δικό του άρθρο, μετά επίθετο με επαναλαμβανόμενο άρθρο).</li></ul><p>Διακρίνει ένα πρόσωπο/πράγμα από άλλα ομοειδή και συμφωνεί σε <i>γένος, αριθμό και πτώση</i> με το προσδιοριζόμενο. Ως επιθετικοί προσδιορισμοί λειτουργούν επίθετα, αντωνυμίες (οἱ ὑμέτεροι ἄνδρες), αριθμητικά (οἱ ἐννέα ἄρχοντες), μετοχές έναρθρες (οἱ χειροτονούμενοι στρατηγοί), εθνικά ουσιαστικά (ἄνδρες Ἀθηναῖοι) και γενικές σε επιθετική θέση (ὁ τῶν ἱππέων ἄρχων).</p><h3>Β. Κατηγορηματικός προσδιορισμός</h3><p>Αποδίδει μια <b>παροδική, προσωρινή ιδιότητα ή κατάσταση</b> που ισχύει τη στιγμή της ενέργειας του ρήματος. Βρίσκεται σε <b>κατηγορηματική θέση</b>, δηλαδή είναι <b>άναρθρος</b>, και το προσδιοριζόμενο ουσιαστικό κανονικά έχει άρθρο. Συντακτικά πλησιάζει το κατηγορούμενο (γι’ αυτό το όνομά του), αλλά παραμένει δευτερεύων όρος.</p><ul><li><b>ἐρήμην</b> τήν πόλιν κατέλαβον = κατέλαβαν την πόλη <i>ενώ ήταν έρημη</i> (κατάσταση τη στιγμή της κατάληψης), όχι «κατέλαβαν την έρημη πόλη».</li></ul><p>Ορισμένα επίθετα/αντωνυμίες, όταν είναι <b>άναρθρα δίπλα σε έναρθρο ουσιαστικό</b>, λειτουργούν πάντοτε ως κατηγορηματικοί προσδιορισμοί: <b>πᾶς, ἅπας, σύμπας, ὅλος, μόνος, αὐτός (=ίδιος), ἕκαστος, ἑκάτερος, ἄκρος, μέσος, ἔσχατος</b>. Σημασιολογικά εδώ αλλάζει το νόημα: «μέσος ὁ ποταμός» = το μέσο του ποταμού· «ὁ μέσος ποταμός» = ο μεσαίος (από τρεις) ποταμός.</p>","examples":[{"gr":"Πλεῖστοι καί <b>μέγιστοι</b> ποταμοί ῥέουσι διά τῆς χώρας.","an":"Επιθετικοί προσδιορισμοί «πλεῖστοι», «μέγιστοι» στο «ποταμοί» (μόνιμη ιδιότητα, επιθετική θέση)."},{"gr":"Κατέλαβον τήν πόλιν <b>ἐρήμην</b>.","an":"Κατηγορηματικός προσδιορισμός: «ἐρήμην» (άναρθρο, έναρθρο ουσιαστικό «τήν πόλιν»). Δηλώνει παροδική κατάσταση: η πόλη ήταν έρημη τη στιγμή της κατάληψης."},{"gr":"<b>Ἐλευθέραις</b> ταῖς ψυχαῖς ἐπολιτεύοντο.","an":"Κατηγορηματικός προσδιορισμός «ἐλευθέραις» στο έναρθρο «ταῖς ψυχαῖς» (= πολιτεύονταν έχοντας ελεύθερες τις ψυχές)."},{"gr":"<b>Μόνος</b> ὁ Σωκράτης οὐκ ἀπέφυγεν.","an":"Κατηγορηματικός προσδιορισμός «μόνος» (άναρθρο επίθετο της κλειστής ομάδας, έναρθρο ουσιαστικό): μόνος ο Σωκράτης, δηλαδή κανείς άλλος."},{"gr":"<b>Πᾶσαν</b> τήν νύκτα ἐπορεύοντο.","an":"Κατηγορηματικός προσδιορισμός «πᾶσαν» (άναρθρο «πᾶς» δίπλα σε έναρθρο «τήν νύκτα»): = ολόκληρη τη νύχτα. Πρβλ. Ξεν. Ἀνάβ. (φόρμουλα νυχτερινής πορείας)."},{"gr":"Οἱ <b>ἐννέα</b> ἄρχοντες τόν ὅρκον ὤμοσαν.","an":"Επιθετικός προσδιορισμός (αριθμητικό σε επιθετική θέση): «οἱ ἐννέα» έναρθρο, μόνιμη/σταθερή διάκριση (οι εννέα άρχοντες της Αθήνας)."},{"gr":"<b>Ἄκραν</b> τήν χεῖρα ἔτεμεν.","an":"Κατηγορηματικός προσδιορισμός «ἄκραν»: = την άκρη του χεριού (όχι «το ακραίο χέρι»). Αντιπαραβ. «ἡ ἄκρα χείρ» = επιθετικός."}],"table":{"title":"Επιθετικός vs κατηγορηματικός προσδιορισμός","cols":["Κριτήριο","Επιθετικός","Κατηγορηματικός"],"rows":[["Άρθρο (θέση)","Έναρθρος (ὁ σοφός ἀνήρ / ὁ ἀνήρ ὁ σοφός)","Άναρθρος δίπλα σε έναρθρο ουσ. (σοφός ὁ ἀνήρ)"],["Ιδιότητα","Μόνιμη, σταθερή","Παροδική, προσωρινή (τη στιγμή της ενέργειας)"],["Λειτουργία","Διακρίνει πρόσωπο/πράγμα από ομοειδή","Διακρίνει κατάσταση από κατάσταση"],["Συγγένεια","—","Πλησιάζει το κατηγορούμενο"]]},"note":"Παγίδα: η ίδια λέξη αλλάζει σημασία με/χωρίς άρθρο. «ἄκρα ἡ χείρ» = η άκρη του χεριού (κατηγορηματικός)· «ἡ ἄκρα χείρ» = το ακραίο χέρι (επιθετικός). Ομοίως μέσος/ὅλος/πᾶς. Πάντα ελέγχουμε τη θέση ως προς το άρθρο πριν χαρακτηρίσουμε."},{"h":"Ονοματικοί προσδιορισμοί · ετερόπτωτοι (1): η γενική","body":"<p>Οι <b>ετερόπτωτοι ονοματικοί προσδιορισμοί</b> είναι ονόματα (ή αντωνυμίες) που προσδιορίζουν ένα άλλο όνομα βρισκόμενα σε <b>διαφορετική, πλάγια πτώση</b> (γενική, δοτική ή αιτιατική). Η <b>γενική</b> είναι η πλουσιότερη: φανερώνει πλήθος σχέσεων ανάμεσα στις δύο έννοιες.</p><h3>Τα κυριότερα είδη της προσδιοριστικής γενικής</h3><ul><li><b>Κτητική</b> (και συγγένειας/καταγωγής): δηλώνει σε ποιον ανήκει κάτι — «οἱ τοῦ πατρός φίλοι».</li><li><b>Του δημιουργού</b>: ο δημιουργός/συντάκτης — «τά τοῦ Ἡρακλέους ἔργα».</li><li><b>Διαιρετική (του όλου)</b>: το όλο, από το οποίο το προσδιοριζόμενο δηλώνει μέρος· συχνά με υπερθετικά, αόριστες/ερωτηματικές αντωνυμίες — «οἱ νέοι τῶν ὁπλιτῶν», «οἱ μέγιστοι τῶν ποταμῶν».</li><li><b>Της ύλης</b>: το υλικό κατασκευής — «ἀσπίς χρυσοῦ».</li><li><b>Του περιεχομένου</b>: με περιεκτικές λέξεις (ἀγέλη, ὄχλος, πλῆθος, σωρός) — «ἀγέλη βοῶν», «ὁ ὄχλος τῶν στρατιωτῶν».</li><li><b>Της ιδιότητας</b>: ηλικία, μέγεθος, διάρκεια — «ὁδός πέντε ἡμερῶν».</li><li><b>Της αξίας / τιμήματος</b>: υλική ή ηθική αξία — «οἶκος ὀκτώ ταλάντων», «δέκα μνῶν χωρίον».</li><li><b>Της αιτίας</b>: με ουσιαστικά/επίθετα δικανικής ή ψυχικού πάθους σημασίας — «γραφή ἀσεβείας», «γραφή ὕβρεως».</li></ul><h3>Υποκειμενική και αντικειμενική γενική</h3><p>Όταν το προσδιοριζόμενο όνομα προέρχεται από ρήμα (ρηματικό ουσιαστικό), η γενική είναι:</p><ul><li><b>Υποκειμενική</b>, αν δηλώνει αυτόν που <i>ενεργεί</i> (= θα ήταν υποκείμενο του αντίστοιχου ρήματος): «ἡ νίκη τῶν Ἀθηναίων» (οι Αθηναίοι νικούν).</li><li><b>Αντικειμενική</b>, αν δηλώνει αυτόν που <i>δέχεται</i> την ενέργεια (= θα ήταν αντικείμενο): «ὁ φόβος τῶν πολεμίων» (φοβούμαστε τους εχθρούς), «ὁ διδάσκαλος τῶν παίδων».</li></ul><p><b>Διάκριση:</b> πολλές φορές η ίδια φράση είναι αμφίσημη. «ὁ φόβος τῶν πολεμίων» μπορεί να σημαίνει «ο φόβος που νιώθουν οι εχθροί» (υποκειμενική) ή «ο φόβος που νιώθουμε για τους εχθρούς» (αντικειμενική)· το κρίνει το νόημα του συμφραζομένου.</p>","examples":[{"gr":"Οἱ <b>τοῦ πατρός</b> φίλοι ἐβοήθησαν.","an":"Γενική κτητική στο «φίλοι»: δηλώνει σε ποιον ανήκουν οι φίλοι (= οι φίλοι του πατέρα)."},{"gr":"Οἱ μέγιστοι <b>τῶν ποταμῶν</b> διά τῆς χώρας ῥέουσιν.","an":"Γενική διαιρετική (του όλου) στο υπερθετικό «οἱ μέγιστοι»: το σύνολο των ποταμών, από το οποίο ξεχωρίζουν οι μεγαλύτεροι."},{"gr":"Ἡ νίκη <b>τῶν Ἀθηναίων</b> ἐγένετο λαμπρά.","an":"Γενική υποκειμενική στο ρηματικό «νίκη» (νικῶ): οι Αθηναίοι είναι αυτοί που νικούν (θα ήταν υποκείμενο: οἱ Ἀθηναῖοι ἐνίκησαν)."},{"gr":"Ὁ διδάσκαλος <b>τῶν παίδων</b> ἐπαινεῖται.","an":"Γενική αντικειμενική στο «διδάσκαλος»: τα παιδιά δέχονται τη διδασκαλία (θα ήταν αντικείμενο: διδάσκει τούς παῖδας)."},{"gr":"Γραφή <b>ἀσεβείας</b> κατά Σωκράτους ἐγράφη.","an":"Γενική της αιτίας σε δικανικό όνομα «γραφή» (μήνυση): δηλώνει το αδίκημα για το οποίο γίνεται η κατηγορία (κατηγορία για ασέβεια)."},{"gr":"Ὁ <b>τῶν βαρβάρων</b> φόβος τούς Ἕλληνας οὐ κατέσχεν.","an":"Πρβλ. Smyth §1331 (τῶν βαρβάρων φόβος): γενική υποκειμενική στο «φόβος» — οι βάρβαροι είναι αυτοί που φοβούνται (οἱ βάρβαροι φοβοῦνται). Αντιπαραβάλλεται με την αντικειμενική («ο φόβος προς τους βαρβάρους»)."},{"gr":"Ἀσπίδα <b>χρυσοῦ</b> καί στέφανον εἶχεν.","an":"Γενική της ύλης στο «ἀσπίδα»: από τι υλικό (= ασπίδα από χρυσό)."},{"gr":"Ὁδόν <b>πέντε ἡμερῶν</b> διῆλθον.","an":"Γενική της ιδιότητας (διάρκειας) στο «ὁδόν»: ορίζει την έκταση/διάρκεια του δρόμου (= πορεία πέντε ημερών). Τύπου Ξεν. Ἀνάβ."}],"table":{"title":"Είδη προσδιοριστικής γενικής","cols":["Είδος γενικής","Σημασία / σχέση","Παράδειγμα"],"rows":[["Κτητική","Σε ποιον ανήκει","οἱ τοῦ πατρός φίλοι"],["Του δημιουργού","Ποιος δημιούργησε","τά τοῦ Ἡρακλέους ἔργα"],["Διαιρετική (του όλου)","Το όλο / μέρος-όλο","οἱ νέοι τῶν ὁπλιτῶν"],["Της ύλης","Από τι υλικό","ἀσπίς χρυσοῦ"],["Του περιεχομένου","Τι περιέχει","ἀγέλη βοῶν"],["Της ιδιότητας","Ηλικία/μέγεθος/διάρκεια","ὁδός πέντε ἡμερῶν"],["Αξίας / τιμήματος","Πόσο αξίζει","οἶκος ὀκτώ ταλάντων"],["Της αιτίας","Αδίκημα/πάθος","γραφή ἀσεβείας"],["Υποκειμενική","Ποιος ενεργεί","ἡ νίκη τῶν Ἀθηναίων"],["Αντικειμενική","Ποιος δέχεται","ὁ φόβος τῶν πολεμίων"],["Συγκριτική","Β’ όρος σύγκρισης","κρείττων χρημάτων"]]},"note":"Η γενική με υπερθετικό (οἱ μέγιστοι τῶν ποταμῶν) είναι διαιρετική· η γενική με συγκριτικό (μείζων τῶν ἄλλων) είναι συγκριτική. Όταν όμως υπερθετικό συγκρίνεται με σύνολο διαφορετικού είδους («ναυμαχία μεγίστη τῶν πρό αὑτῆς»), η γενική θεωρείται συγκριτική, όχι διαιρετική."},{"h":"Ονοματικοί προσδιορισμοί · ετερόπτωτοι (2): η συγκριτική γενική, η δοτική και η αιτιατική","body":"<h3>Α. Γενική συγκριτική</h3><p>Δηλώνει τον <b>β’ όρο της σύγκρισης</b> και τίθεται κοντά σε επίθετα/επιρρήματα συγκριτικού βαθμού (αντί για «ἤ + ομοιόπτωτο»). Συντάσσεται επίσης με ρήματα και επίθετα που εκφράζουν υπεροχή ή διαφορά.</p><ul><li>«Πολλῶν χρημάτων κρείττων ὁ ἔπαινος» = ο έπαινος είναι ανώτερος από πολλά χρήματα.</li></ul><h3>Β. Η δοτική ως ετερόπτωτος προσδιορισμός</h3><p>Η προσδιοριστική δοτική εμφανίζεται σε δύο κυρίως είδη:</p><p><b>1. Δοτική αντικειμενική.</b> Δηλώνει το αντικείμενο της σχέσης και συνοδεύει επίθετα (συχνά σύνθετα ή με αντίστοιχα ρήματα δοτικής) που σημαίνουν:</p><ul><li>ωφέλεια / βλάβη: ὠφέλιμος, βλαβερός, λυσιτελής — «βλαβερά τῇ πόλει»</li><li>φιλία / έχθρα: φίλος, ἐχθρός, εὔνους, πολέμιος — «ἐχθρός τῇ ἐλευθερίᾳ»</li><li>ευπείθεια / υποταγή: πιστός, εὐπειθής, ὑπήκοος — «πιστός τῷ δήμῳ»</li><li>ακολουθία / διαδοχή: ἀκόλουθος, διάδοχος — «διάδοχος Κλεάνδρῳ»</li><li>προσέγγιση / γειτνίαση: γείτων, πλησίος, ὅμορος — «γείτων τῇ Ἑλλάδι»</li><li>ομοιότητα / ισότητα / συμφωνία: ὅμοιος, ἴσος, σύμφωνος — «ὅμοιος ταῖς δούλαις», «σύμφωνος τῷ ὀνόματι»</li><li>καταλληλότητα: ἁρμόδιος, πρέπων, προσήκων</li></ul><p><b>2. Δοτική της αναφοράς.</b> Προσδιορίζει επίθετα δηλώνοντας <i>ως προς τι</i> ισχύει η ιδιότητα — «ἀσθενής τῷ σώματι», «ταχύς τοῖς ποσί».</p><h3>Γ. Η αιτιατική ως ετερόπτωτος προσδιορισμός</h3><p>Η <b>αιτιατική της αναφοράς</b> δηλώνει <i>ως προς τι</i> ισχύει μια ιδιότητα ή ενέργεια (μεταφράζεται «ως προς», «στο»). Συνηθίζεται με λέξεις που δηλώνουν διάσταση: <b>τό μῆκος, τό εὖρος (πλάτος), τό ὕψος, τό βάθος, τό μέγεθος, τό γένος, τό ὄνομα</b>.</p>","examples":[{"gr":"Πολλῶν <b>χρημάτων</b> κρείττων ὁ ἔπαινος.","an":"Γενική συγκριτική στο συγκριτικό «κρείττων»: β’ όρος σύγκρισης (= ανώτερος από χρήματα). Ισοδυναμεί με «ἤ πολλά χρήματα»."},{"gr":"Τά τοιαῦτα βλαβερά <b>τῇ πόλει</b> ἐστίν.","an":"Δοτική αντικειμενική στο επίθετο «βλαβερά» (σημασία βλάβης): δηλώνει σε ποιον είναι βλαβερά (= για την πόλη)."},{"gr":"Ἐγώ γείτων οἰκῶ <b>τῇ Ἑλλάδι</b>.","an":"Δοτική αντικειμενική στο «γείτων» (προσέγγιση): δηλώνει σε σχέση με ποιον είναι γείτονας (= της Ελλάδας)."},{"gr":"Ἀσθενής ἦν <b>τῷ σώματι</b>, ἰσχυρός δέ <b>τῇ γνώμῃ</b>.","an":"Δοτικές της αναφοράς στα επίθετα «ἀσθενής», «ἰσχυρός»: ως προς τι ισχύει η ιδιότητα (= αδύναμος ως προς το σώμα, δυνατός ως προς τη σκέψη)."},{"gr":"Τυφλός <b>τά τ’ ὦτα τόν τε νοῦν τά τ’ ὄμματ’</b> εἶ.","an":"Σοφ. Οἰδ. Τύρ. 371: αιτιατικές της αναφοράς στο «τυφλός» — τυφλός ως προς τα αυτιά, τον νου και τα μάτια."},{"gr":"Πύργος ἦν στερεός, σταδίου <b>τό μῆκος</b> καί <b>τό εὖρος</b>.","an":"Αιτιατικές της αναφοράς «τό μῆκος», «τό εὖρος»: ορίζουν τη διάσταση (= ένα στάδιο ως προς το μήκος και το πλάτος)."},{"gr":"Ἀνήρ ἀγαθός <b>τά πολεμικά</b> ἐγένετο.","an":"Αιτιατική της αναφοράς «τά πολεμικά» στο «ἀγαθός»: ως προς τι ήταν ικανός (= γενναίος στα πολεμικά). Τύπου Ξεν."},{"gr":"Ποταμός <b>εὖρος</b> δύο πλέθρων.","an":"Τύπου Ξεν. Ἀνάβ. (φόρμουλα ποταμών): αιτιατική της αναφοράς «εὖρος» (= ποταμός πλάτους δύο πλέθρων ως προς το πλάτος)· δίπλα γενική ιδιότητας «δύο πλέθρων»."}],"table":{"title":"Ετερόπτωτοι: δοτική και αιτιατική","cols":["Πτώση","Είδος","Σημασία","Παράδειγμα"],"rows":[["Δοτική","Αντικειμενική","Αντικείμενο σχέσης (ωφέλεια, φιλία, ομοιότητα κ.λπ.)","βλαβερά τῇ πόλει"],["Δοτική","Αναφοράς","Ως προς τι ισχύει η ιδιότητα","ἀσθενής τῷ σώματι"],["Αιτιατική","Αναφοράς","Ως προς τι (διαστάσεις, ιδιότητες)","σταδίου τό μῆκος"]]},"note":"Η δοτική αντικειμενική συνδέεται με συγκεκριμένες σημασιολογικές ομάδες επιθέτων (τα ίδια που και ως ρήματα συντάσσονται με δοτική). Αν αμφιβάλλεις, έλεγξε αν το επίθετο ανήκει στις ομάδες ωφέλειας/φιλίας/ομοιότητας/προσέγγισης/υποταγής."},{"h":"Επιρρηματικοί προσδιορισμοί · σημασίες (κατά σχέση)","body":"<p>Οι <b>επιρρηματικοί προσδιορισμοί</b> προσδιορίζουν κυρίως το <b>ρήμα</b> (σπανιότερα ένα επίθετο ή επίρρημα) και φανερώνουν μια <b>επιρρηματική σχέση</b>: πού, πότε, πώς, πόσο, γιατί, για ποιον σκοπό κ.λπ. Κατατάσσονται με δύο κριτήρια: (α) <b>κατά σχέση</b> (τι σημασία εκφράζουν — αυτή η ενότητα) και (β) <b>κατά τρόπο εκφοράς</b> (με ποια γραμματική μορφή — επόμενη ενότητα).</p><h3>Οι βασικές επιρρηματικές σχέσεις</h3><ul><li><b>Τόπου</b>: στάση σε τόπο (ποῦ;), κίνηση προς/από τόπο, κίνηση διά μέσου — «ἐνταῦθα», «οἴκαδε», «ἐκ τῆς πόλεως».</li><li><b>Χρόνου</b>: πότε, πόσο διάστημα, μέσα σε πόσο — «νῦν», «τῆς νυκτός», «ἐν τρισίν ἡμέραις».</li><li><b>Τρόπου</b>: με ποιον τρόπο — «οὕτως», «σιγῇ», «μετά σπουδῆς».</li><li><b>Ποσού / μέτρου</b>: πόσο, σε ποιον βαθμό — «πολύ», «μικρόν», «τρίς».</li><li><b>Αιτίας</b>: γιατί, εξαιτίας τίνος — «διά τοῦτο», «φόβῳ», «ἀσθενείας ἕνεκα».</li><li><b>Σκοπού</b>: για ποιον σκοπό — «ἕνεκα σωτηρίας», «ἐπί θήραν».</li><li><b>Αναφοράς</b>: ως προς τι — «κατά τοῦτο», «πρός ταῦτα».</li><li><b>Μέσου / οργάνου</b>: με τι — «λίθοις», «τόξῳ».</li><li><b>Συνοδείας</b>: μαζί με ποιον — «μετά τῶν στρατιωτῶν», «σύν θεοῖς».</li><li><b>Ποσότητας/συμφωνίας, εναντίωσης, προϋπόθεσης</b> κ.ά. (συνήθως με δευτερεύουσες προτάσεις ή μετοχές): καίτοι ἀσθενής ἦν…, εἰ τοῦτο γένοιτο…</li></ul><p>Η ίδια σχέση μπορεί να εκφραστεί με πολλούς τρόπους — επίρρημα, πλάγια πτώση, εμπρόθετο, μετοχή, πρόταση, απαρέμφατο. Γι’ αυτό η σωστή ανάλυση απαιτεί να αναγνωρίζουμε <i>και</i> τη σημασία <i>και</i> τη μορφή.</p>","examples":[{"gr":"Οἱ στρατιῶται <b>τῆς νυκτός</b> ἀπεχώρησαν.","an":"Επιρρηματικός προσδιορισμός του χρόνου (γενική του χρόνου, διάρκεια/μέσα σε): πότε αποχώρησαν."},{"gr":"<b>Φόβῳ</b> ἔφυγον ἐκ τῆς μάχης.","an":"Επιρρηματικός προσδιορισμός της αιτίας (δοτική της αιτίας): γιατί έφυγαν (= από φόβο)."},{"gr":"Ἐπορεύοντο <b>ἐπί θήραν</b>.","an":"Επιρρηματικός προσδιορισμός του σκοπού (εμπρόθετος): για ποιον σκοπό προχωρούσαν (= για κυνήγι)."},{"gr":"Ἔβαλλον τούς πολεμίους <b>λίθοις</b>.","an":"Επιρρηματικός προσδιορισμός του μέσου/οργάνου (δοτική οργανική): με τι χτυπούσαν (= με πέτρες)."},{"gr":"<b>Σύν τοῖς συμμάχοις</b> ἐστράτευσαν.","an":"Επιρρηματικός προσδιορισμός της συνοδείας (εμπρόθετος): μαζί με ποιους εκστράτευσαν."},{"gr":"<b>Ἐνταῦθα</b> ἔμεινεν ἡμέρας ἑπτά.","an":"Τύπου Ξεν. Ἀνάβ.: «ἐνταῦθα» επιρρηματικός προσδ. του τόπου (στάση)· «ἡμέρας ἑπτά» αιτιατική του χρόνου (διάρκεια)."},{"gr":"<b>Διά τόν χειμῶνα</b> οὐκ ἐδύναντο πορεύεσθαι.","an":"Εμπρόθετος επιρρηματικός προσδιορισμός της αιτίας: γιατί δεν μπορούσαν να βαδίσουν (= εξαιτίας του χειμώνα/της κακοκαιρίας)."},{"gr":"<b>Σιγῇ</b> ἐδείπνουν οἱ νέοι.","an":"Τύπου Ξεν. (πρβλ. Λακ. Πολ. / Κύρ. Παιδ.): δοτική του τρόπου «σιγῇ» = επιρρηματικός προσδ. του τρόπου (έτρωγαν σιωπηλά)."}],"note":"Μην συγχέεις τη σχέση με τη μορφή. Η «δοτική» δεν είναι σχέση· είναι μορφή που μπορεί να εκφράσει αιτία (φόβῳ), όργανο (λίθοις), τρόπο (σιγῇ) ή χρόνο (τῇ ὑστεραίᾳ). Πάντα ρωτάμε «τι δηλώνει;» για τη σχέση και «με τι μορφή;» για την εκφορά."},{"h":"Επιρρηματικοί προσδιορισμοί · μορφές (κατά τρόπο εκφοράς) και συνολικός πίνακας","body":"<p>Κατά τη <b>μορφή (εκφορά)</b> τους, οι επιρρηματικοί προσδιορισμοί εμφανίζονται ως:</p><ul><li><b>Επιρρήματα</b> (καθαροί επιρρηματικοί): νῦν, ἐνταῦθα, οὕτως, σφόδρα.</li><li><b>Πλάγιες πτώσεις χωρίς πρόθεση</b> (γενική, δοτική, αιτιατική με επιρρηματική σημασία): τῆς νυκτός (χρόνου), λίθοις (μέσου), τήν ταχίστην (τρόπου).</li><li><b>Εμπρόθετοι προσδιορισμοί</b> (πρόθεση + πτώση): ἐν τῇ πόλει, διά τόν φόβον, εἰς τήν ἀγοράν, σύν θεοῖς.</li><li><b>Επιρρηματικές μετοχές</b> (χρονική, αιτιολογική, τελική, υποθετική, εναντιωματική, τροπική): ταῦτα ἀκούσας ἀπῆλθεν (χρονική/αιτιολ.).</li><li><b>Απαρέμφατο του σκοπού/της αναφοράς</b>: ἧκον ἀγγεῖλαι (= για να αναγγείλω).</li><li><b>Επιρρηματικές δευτερεύουσες προτάσεις</b> (χρονικές, αιτιολογικές, τελικές, υποθετικές, εναντιωματικές, αποτελεσματικές): ἐπεί ἦλθεν…, ἵνα μάθῃ…, εἰ τοῦτο ποιήσεις…</li><li><b>Επιρρηματικό / προληπτικό κατηγορούμενο</b>: πρῶτος ἀφίκετο (= έφτασε πρώτος).</li></ul><h3>Συνολική εικόνα — ο πλήρης πίνακας των προσδιορισμών</h3><p>Ο παρακάτω πίνακας συνοψίζει όλη τη διδαχθείσα ύλη: από τον γενικό ορισμό μέχρι το τελευταίο υποείδος. Είναι το «χάρτη» με τον οποίο αναλύουμε κάθε προσδιορισμό: πρώτα ρωτάμε <i>ονοματικός ή επιρρηματικός;</i>· αν ονοματικός, <i>ομοιόπτωτος ή ετερόπτωτος;</i>· έπειτα προσδιορίζουμε το ακριβές υποείδος.</p>","examples":[{"gr":"Ταῦτα <b>ἀκούσας</b> ὁ Κῦρος ἀπῆλθεν.","an":"Επιρρηματική μετοχή (χρονική/αιτιολογική) ως επιρρηματικός προσδιορισμός: εκφορά με μετοχή, σχέση χρόνου/αιτίας (= όταν/επειδή τα άκουσε)."},{"gr":"Ἧκον <b>ἀγγεῖλαι</b> τά γεγενημένα.","an":"Απαρέμφατο του σκοπού ως επιρρηματικός προσδιορισμός: εκφορά με απαρέμφατο, σχέση σκοπού (= για να αναγγείλω)."},{"gr":"<b>Ἐπεί ἐτελεύτησε Δαρεῖος</b>, Ἀρταξέρξης ἐβασίλευσεν.","an":"Δευτερεύουσα χρονική πρόταση ως επιρρηματικός προσδιορισμός του χρόνου: εκφορά με πρόταση (= όταν πέθανε ο Δαρείος)."},{"gr":"<b>Πρῶτος</b> ὁ Μιλτιάδης εἰσῆλθεν.","an":"Επιρρηματικό (προληπτικό) κατηγορούμενο «πρῶτος»: δηλώνει τη σειρά/τρόπο της ενέργειας (= μπήκε πρώτος)."},{"gr":"<b>Ἵνα μάθῃ</b>, ἤρετο τόν διδάσκαλον.","an":"Δευτερεύουσα τελική πρόταση ως επιρρηματικός προσδιορισμός του σκοπού: εκφορά με πρόταση, σχέση σκοπού (= για να μάθει)."},{"gr":"<b>Καίπερ ἀσθενής ὤν</b>, εἵπετο τῷ στρατεύματι.","an":"Εναντιωματική μετοχή «καίπερ … ὤν» ως επιρρηματικός προσδιορισμός της εναντίωσης: εκφορά με μετοχή (= αν και ήταν ασθενής)."},{"gr":"<b>Νῦν</b> δέ ταῦτα πράττειν δεῖ.","an":"Επίρρημα «νῦν» ως καθαρός επιρρηματικός προσδιορισμός του χρόνου: η απλούστερη μορφή εκφοράς."},{"gr":"<b>Εἰ τοῦτο ποιήσεις</b>, ἁμαρτήσῃ.","an":"Δευτερεύουσα υποθετική πρόταση ως επιρρηματικός προσδιορισμός της προϋπόθεσης: εκφορά με πρόταση (= αν το κάνεις αυτό)."}],"table":{"title":"Πλήρης πίνακας ειδών προσδιορισμών","cols":["Μεγάλη κατηγορία","Υποκατηγορία","Είδη / μορφές"],"rows":[["Ονοματικοί — Ομοιόπτωτοι","Με ουσιαστικό","Παράθεση, Επεξήγηση"],["Ονοματικοί — Ομοιόπτωτοι","Με επίθετο","Επιθετικός, Κατηγορηματικός"],["Ονοματικοί — Ετερόπτωτοι","Γενική","Κτητική, δημιουργού, διαιρετική, ύλης, περιεχομένου, ιδιότητας, αξίας/τιμήματος, αιτίας, υποκειμενική, αντικειμενική, συγκριτική"],["Ονοματικοί — Ετερόπτωτοι","Δοτική","Αντικειμενική, αναφοράς"],["Ονοματικοί — Ετερόπτωτοι","Αιτιατική","Αναφοράς"],["Επιρρηματικοί — κατά σχέση","Σημασίες","Τόπου, χρόνου, τρόπου, ποσού, αιτίας, σκοπού, αναφοράς, μέσου, οργάνου, συνοδείας, εναντίωσης, προϋπόθεσης"],["Επιρρηματικοί — κατά εκφορά","Μορφές","Επιρρήματα, πλάγιες πτώσεις, εμπρόθετοι, επιρρηματικές μετοχές, απαρέμφατο σκοπού, επιρρηματικές προτάσεις, επιρρηματικό/προληπτικό κατηγορούμενο"]]},"note":"Μέθοδος ανάλυσης (πάντα με τη σειρά): 1) Τι προσδιορίζει; (όνομα ⇒ ονοματικός / ρήμα ⇒ επιρρηματικός). 2) Αν ονοματικός: ίδια πτώση; ⇒ ομοιόπτωτος (με/χωρίς άρθρο για επιθετικό-κατηγορηματικό)· διαφορετική; ⇒ ετερόπτωτος. 3) Αν επιρρηματικός: ποια σχέση (σημασία) και ποια μορφή (εκφορά). Έτσι κανένας προσδιορισμός δεν μένει αχαρακτήριστος."}]);
  T("syn-epithetikos", [{"h":"Ορισμός και θέση στο σύστημα των προσδιορισμών","body":"<p>Ο <b>επιθετικός προσδιορισμός</b> είναι ένας <b>ονοματικός ομοιόπτωτος προσδιορισμός</b>: μια λέξη (συνήθως επίθετο) που <b>συμφωνεί</b> με το ουσιαστικό το οποίο προσδιορίζει σε <b>γένος, αριθμό και πτώση</b> και του αποδίδει μια <b>μόνιμη, σταθερή ιδιότητα</b>. Λέγεται «ομοιόπτωτος» ακριβώς επειδή βρίσκεται στην <i>ίδια πτώση</i> με τον προσδιοριζόμενο όρο.</p><p>Για να τοποθετήσουμε σωστά τον επιθετικό προσδιορισμό, χρειάζεται να δούμε ολόκληρο το σύστημα. Οι <b>ονοματικοί προσδιορισμοί</b> χωρίζονται σε:</p><ul><li><b>Ομοιόπτωτους</b> (στην ίδια πτώση με το προσδιοριζόμενο): <i>παράθεση, επεξήγηση</i> (από ουσιαστικά) και <i>επιθετικός, κατηγορηματικός</i> (από επίθετα).</li><li><b>Ετερόπτωτους</b> (σε διαφορετική πτώση, κυρίως γενική ή δοτική): π.χ. ἡ βουλή <i>τῶν Ἑλλήνων</i>.</li></ul><p>Ο επιθετικός προσδιορισμός είναι λοιπόν: <b>προσδιορισμός &gt; ονοματικός &gt; ομοιόπτωτος &gt; επιθετικός</b>. Η ουσία του είναι ότι περιορίζει ή χαρακτηρίζει την έννοια του ουσιαστικού <b>χωρίς τη μεσολάβηση ρήματος</b> και δηλώνει ιδιότητα που θεωρείται <b>διαρκής/εγγενής</b>, όχι περιστασιακή.</p><h3>Μόνιμη ιδιότητα — το κλειδί της σημασίας</h3><p>Όταν λέμε ὁ <b>ἀγαθός</b> ἀνήρ, η αγαθότητα παρουσιάζεται ως σταθερό γνώρισμα του άνδρα. Αυτή η «μονιμότητα» είναι που χωρίζει τον επιθετικό από τον κατηγορηματικό προσδιορισμό (παροδική ιδιότητα) και από το κατηγορούμενο (ιδιότητα που αποδίδεται <i>μέσω ρήματος</i>).</p>","examples":[{"gr":"τήν δέ ἑλληνικήν δύναμιν ἤθροιζεν","an":"\"συγκέντρωνε την ελληνική δύναμη\" — ἑλληνικήν: επιθετικός προσδιορισμός στο δύναμιν (αιτ. εν. θηλ.), δηλώνει μόνιμο εθνικό χαρακτηρισμό."},{"gr":"ὁ ἀγαθός ἀνήρ τοῖς νόμοις πείθεται","an":"ἀγαθός: επιθετικός προσδιορισμός στο ἀνήρ· σταθερή ηθική ιδιότητα, χωρίς ρήμα-σύνδεσμο."},{"gr":"ἐν τῇ καλῇ πόλει","an":"καλῇ: επιθετικός προσδιορισμός στο πόλει (δοτ.)· συμφωνεί σε γένος-αριθμό-πτώση."},{"gr":"ἐνταῦθα Κύρῳ βασίλεια ἦν καί παράδεισος μέγας ἀγρίων θηρίων πλήρης","an":"Ξεν. Ἀνάβ. 1.2.7 — μέγας: επιθετικός προσδ. στο παράδεισος (ονομ. εν. αρσ.)· συμφωνεί σε γένος-αριθμό-πτώση και αποδίδει μόνιμη ιδιότητα (το μέγεθος)."},{"gr":"ἄνδρα ἀγαθόν καί δίκαιον ἐπιθυμῶ γενέσθαι","an":"Πλάτ. (τύπου Γοργ.) — ἀγαθόν, δίκαιον: δύο επιθετικοί προσδ. στο ἄνδρα (αιτ.), δηλώνουν διαρκείς ηθικές ιδιότητες."}],"note":"Προσοχή στον όρο: «ομοιόπτωτος» ΔΕΝ σημαίνει απλώς «επίθετο». Σημαίνει «στην ίδια πτώση». Γι' αυτό και ουσιαστικά (παράθεση/επεξήγηση) είναι κι αυτά ομοιόπτωτοι προσδιορισμοί, αν και δεν είναι επιθετικοί."},{"h":"Η επιθετική θέση — όλες οι θέσεις του άρθρου","body":"<p>Το πιο αξιόπιστο εξωτερικό κριτήριο για να αναγνωρίσουμε επιθετικό προσδιορισμό είναι η <b>επιθετική θέση</b> (attributive position): ο τρόπος που τοποθετείται το επίθετο σε σχέση με το <b>άρθρο</b> και το ουσιαστικό. Κανόνας του Smyth: <i>κάθε λέξη ή ομάδα λέξεων που στέκεται ανάμεσα στο άρθρο και το ουσιαστικό του —ή αμέσως μετά από επαναλαμβανόμενο άρθρο— είναι επιθετικός προσδιορισμός.</i></p><h3>1η επιθετική θέση: ἄρθρο + επίθετο + ουσιαστικό</h3><p><b>ὁ σοφός ἀνήρ</b> — η συνηθέστερη. Το επίθετο «κλείνεται» ανάμεσα στο άρθρο και το ουσιαστικό. Δίνει <b>έμφαση στο επίθετο</b> (στην ιδιότητα).</p><h3>2η επιθετική θέση: ἄρθρο + ουσιαστικό + ἄρθρο + επίθετο</h3><p><b>ὁ ἀνήρ ὁ σοφός</b> — το επίθετο ακολουθεί, με <b>επανάληψη του άρθρου</b>. Δίνει <b>έμφαση στο ουσιαστικό</b> (το ήδη γνωστό/ορισμένο), και προσθέτει το επίθετο επεξηγηματικά.</p><h3>3η επιθετική θέση: ουσιαστικό (άναρθρο) + ἄρθρο + επίθετο</h3><p><b>ἀνήρ ὁ σοφός</b> — όταν το ουσιαστικό θα ήταν έτσι κι αλλιώς άναρθρο, το επίθετο τίθεται με δικό του άρθρο, σαν επεξηγηματική προσθήκη: «άνδρας, εννοώ ο σοφός».</p><h3>Παραλλαγή με τη γενική (έναρθρη γενική σε επιθετική θέση)</h3><p>Η έναρθρη γενική κτητική/υποκειμενική κ.λπ. μπαίνει επίσης σε επιθετική θέση και λειτουργεί ως (ετερόπτωτος) προσδιορισμός με τα ίδια σχήματα: <b>ὁ τοῦ βασιλέως θρόνος</b> / <b>ὁ θρόνος ὁ τοῦ βασιλέως</b> / <b>τοῦ βασιλέως ὁ θρόνος</b>.</p>","examples":[{"gr":"ὁ σοφός ἀνήρ","an":"1η θέση· έμφαση στη σοφία. Πλήρης ανάλυση: σοφός = επιθετικός προσδ. στο ἀνήρ (ονομ. εν. αρσ.)."},{"gr":"ὁ ἀνήρ ὁ σοφός","an":"2η θέση· επανάληψη άρθρου· έμφαση στο ἀνήρ ως γνωστό πρόσωπο, ο σοφός προστίθεται επεξηγηματικά."},{"gr":"τῇ πρώτῃ ἡμέρᾳ","an":"1η θέση· πρώτῃ (αριθμητικό-τακτικό) = επιθετικός προσδ. στο ἡμέρᾳ (δοτ. χρόνου)."},{"gr":"τό στράτευμα τό τῶν Ἀθηναίων","an":"2η θέση με γενική· τό τῶν Ἀθηναίων = έναρθρη γενική κτητική σε επιθετική θέση στο στράτευμα."},{"gr":"τῆς νίκης τό μέγεθος","an":"προτασσόμενη γενική (τοῦ πατρός τό βιβλίον-τύπος)· δίνει έμφαση στη γενική τῆς νίκης."},{"gr":"οἱ τῶν Περσῶν βασιλεῖς","an":"Ξεν. (τύπου Κύρ. Παιδ.) — 1η θέση με γενική· τῶν Περσῶν = έναρθρη γενική κτητική ανάμεσα σε άρθρο και ουσιαστικό βασιλεῖς."},{"gr":"ἡ ἀρχή ἡ Λακεδαιμονίων","an":"Θουκ. (τύπου) — 2η θέση· επανάληψη του άρθρου ἡ ... ἡ, η γενική Λακεδαιμονίων προσδιορίζει επιθετικά το ἀρχή."},{"gr":"ὁ δίκαιος ἀνήρ καί ἡ δικαία πόλις","an":"Πλάτ. (τύπου Πολιτείας) — 1η θέση δύο φορές· δίκαιος, δικαία = επιθετικοί προσδ. σε επιθετική θέση, με έμφαση στην ιδιότητα."}],"table":{"title":"Οι θέσεις του επιθέτου (σχήμα άρθρου)","cols":["Θέση","Σχήμα","Παράδειγμα","Έμφαση"],"rows":[["1η επιθετική","ἄρθρο + επίθ. + ουσ.","ὁ σοφός ἀνήρ","στο επίθετο / ιδιότητα"],["2η επιθετική","ἄρθρο + ουσ. + ἄρθρο + επίθ.","ὁ ἀνήρ ὁ σοφός","στο ουσιαστικό"],["3η επιθετική","ουσ. (άναρθρο) + ἄρθρο + επίθ.","ἀνήρ ὁ σοφός","επεξηγηματική προσθήκη"],["Κατηγορηματική","ἄρθρο + ουσ. + επίθ. (άναρθρο)","ὁ ἀνήρ σοφός","παροδική ιδιότητα / κατηγ. προσδ."]]},"note":"Μνημονικό: το επίθετο που βρίσκεται «μέσα στην αγκαλιά» του άρθρου (ανάμεσα σε άρθρο και ουσιαστικό, ή με δικό του άρθρο) είναι ΕΠΙΘΕΤΙΚΟ. Το άναρθρο επίθετο «έξω από την αγκαλιά» (ὁ ἀνήρ σοφός / σοφός ὁ ἀνήρ) είναι ΚΑΤΗΓΟΡΗΜΑΤΙΚΟ."},{"h":"Τι λειτουργεί ως επιθετικός προσδιορισμός","body":"<p>Επιθετικός προσδιορισμός δεν είναι μόνο το «καθαρό» επίθετο. Σε επιθετική θέση μπορούν να λειτουργήσουν πολλές κατηγορίες λέξεων και φράσεων, αρκεί να αποδίδουν μόνιμη ιδιότητα και να συμφωνούν πτωτικά (όπου κλίνονται):</p><h3>α) Επίθετο (έναρθρο)</h3><p>Η τυπική περίπτωση: ὁ <b>δίκαιος</b> κριτής, αἱ <b>καλαί</b> πράξεις.</p><h3>β) Αντωνυμία</h3><p>Κυρίως οι <b>κτητικές</b> (ἐμός, σός, ἡμέτερος, ὑμέτερος, σφέτερος) και αόριστες/άλλες: ὁ <b>ἡμέτερος</b> φίλος, ἡ <b>σή</b> γνώμη, <b>ἄλλη</b> ὁδός.</p><h3>γ) Αριθμητικό</h3><p>Απόλυτα και τακτικά: <b>τρεῖς</b> ἄνδρες, ἡ <b>πρώτη</b> μάχη.</p><h3>δ) Επιθετική (αναφορική) μετοχή</h3><p>Έναρθρη μετοχή με επιθετική σημασία (βλ. επόμενη ενότητα): ὁ <b>φεύγων</b> κίνδυνος.</p><h3>ε) Ουσιαστικό που δηλώνει ηλικία, εθνικότητα, επάγγελμα, αξίωμα, ιδιότητα</h3><p>Δύο ουσιαστικά στην ίδια πτώση, όπου το ένα χαρακτηρίζει μόνιμα το άλλο: ἀνήρ <b>στρατηγός</b>, ἄνδρες <b>Ἀθηναῖοι</b>, ἀνήρ <b>μάντις</b>. (Αυτά τα διακρίνουμε από την παράθεση, που είναι ουσιαστικό-ουσιαστικό αλλά με χωριστή, επεξηγηματική λειτουργία.)</p><h3>στ) Γεωγραφικό κύριο όνομα με άρθρο</h3><p>ἡ πόλις <b>αἱ Ἀθῆναι</b> (συμφωνία στο γένος όπου γίνεται).</p><h3>ζ) Επίρρημα ή εμπρόθετο σύνολο με άρθρο</h3><p>Σε επιθετική θέση: <b>οἱ νῦν</b> ἄνθρωποι, <b>οἱ ἐν τῇ πόλει</b> (πολῖται), ἡ <b>ἐν Σικελίᾳ</b> κακοπραγία.</p><h3>η) Έναρθρη γενική</h3><p>ὁ <b>τοῦ βασιλέως</b> θρόνος (αν και πτωτικά ετερόπτωτος, λειτουργικά μπαίνει σε επιθετική θέση).</p><h3>θ) Δευτερεύουσα αναφορική πρόταση</h3><p>Λειτουργεί ως «αναπτυγμένος» επιθετικός προσδιορισμός: ὁ ἀνήρ <b>ὅς ταῦτα ἔπραξεν</b>.</p>","examples":[{"gr":"ἄνδρες Ἀθηναῖοι","an":"Ἀθηναῖοι = επιθετικός προσδ. (εθνικότητα) στο ἄνδρες· μόνιμη ιδιότητα της καταγωγής."},{"gr":"ὁ ἡμέτερος στρατηγός ἀνδρεῖος ἦν","an":"ἡμέτερος = κτητική αντωνυμία ως επιθετικός προσδ. στο στρατηγός (έναρθρος). (Το ἀνδρεῖος εδώ είναι κατηγορούμενο μέσω του ἦν.)"},{"gr":"οἱ νῦν ἄνθρωποι","an":"νῦν = επίρρημα σε επιθετική θέση (ἄρθρο + επίρρ. + ουσ.) = επιθετικός προσδ. «οι σημερινοί άνθρωποι»."},{"gr":"ἡ ἐν Σικελίᾳ κακοπραγία","an":"ἐν Σικελίᾳ = εμπρόθετο σύνολο σε επιθετική θέση = επιθετικός προσδ. στο κακοπραγία."},{"gr":"ἀνήρ μάντις προσῆλθεν","an":"μάντις = ουσιαστικό (επάγγελμα) ως επιθετικός προσδ. στο ἀνήρ."},{"gr":"εἶχε δέ τούς μετ' αὐτοῦ βαρβάρους","an":"Ξεν. (τύπου Ἀνάβ.) — οἱ μετ' αὐτοῦ = εμπρόθετο σύνολο σε επιθετική θέση (ἄρθρο + εμπρόθ. + ουσ.) ως επιθετικός προσδ. στο βαρβάρους."},{"gr":"τρισχίλιοι ὁπλῖται παρῆσαν","an":"Θουκ. (τύπου) — τρισχίλιοι = αριθμητικό (απόλυτο) ως επιθετικός προσδ. στο ὁπλῖται, συμφωνεί σε γένος-αριθμό-πτώση."},{"gr":"οἱ τότε ἄνθρωποι ἀνδρειότεροι ἦσαν","an":"τότε = επίρρημα σε επιθετική θέση = επιθετικός προσδ. «οι τότε / οι παλιοί άνθρωποι»."}],"note":"Διάκριση από την παράθεση: στο ἀνήρ στρατηγός το δεύτερο ουσιαστικό αποδίδει μόνιμη ιδιότητα/αξίωμα και λειτουργεί επιθετικά. Στην παράθεση (Φίλιππος, ὁ βασιλεύς) το ουσιαστικό αναφέρεται σε γενικότερη κατηγορία και χωρίζεται νοηματικά (συχνά με κόμμα/άρθρο)."},{"h":"Η επιθετική (αναφορική) μετοχή","body":"<p>Η <b>επιθετική μετοχή</b> είναι μετοχή που λειτουργεί ακριβώς σαν επίθετο, δηλαδή ως <b>επιθετικός προσδιορισμός</b>. Λέγεται και <b>αναφορική</b>, γιατί <b>αναλύεται σε αναφορική πρόταση</b>. Σχεδόν πάντα είναι <b>έναρθρη</b> και βρίσκεται σε επιθετική θέση.</p><h3>Μορφή και αναγνώριση</h3><p>Αναγνωρίζεται κυρίως από το <b>άρθρο</b> που τη συνοδεύει σε επιθετική θέση: ὁ <b>φεύγων</b>, οἱ <b>βουλόμενοι</b>, τά <b>γιγνόμενα</b>. Αν αφαιρέσουμε τη μετοχή, μένει το ουσιαστικό· αν την αναλύσουμε, παίρνουμε αναφορική πρόταση: <i>ὁ φεύγων κίνδυνος → ὁ κίνδυνος ὅς φεύγει/ἀποφεύγεται</i>.</p><h3>Ανάλυση σε αναφορική πρόταση</h3><p>Η επιθετική μετοχή αναλύεται με αναφορική αντωνυμία + ρήμα στον αντίστοιχο χρόνο: ενεστ. μτχ. → ενεστ./παρατ., αορ. μτχ. → αόριστο/παρακείμενο κ.ο.κ., με αναφορά στο χρόνο του ρήματος της πρότασης.</p><h3>Ονοματική (ουσιαστικοποιημένη) χρήση</h3><p>Πολύ συχνά το ουσιαστικό <b>παραλείπεται</b> και η έναρθρη μετοχή <b>ουσιαστικοποιείται</b>, παίρνοντας τη συντακτική θέση ουσιαστικού (υποκείμενο, αντικείμενο κ.λπ.): <b>ὁ βουλόμενος</b> «όποιος θέλει», <b>οἱ φεύγοντες</b> «οι εξόριστοι/οι φυγάδες», <b>οἱ ἄρχοντες</b>. Το <b>ουδέτερο ενικού</b> έναρθρης μετοχής/επιθέτου χρησιμοποιείται ως <b>αφηρημένο ουσιαστικό</b>: <b>τό δίκαιον</b> «η δικαιοσύνη», <b>τό συμφέρον</b> «το συμφέρον».</p>","examples":[{"gr":"ὁ φεύγων πόνους φεύγει τιμάς","an":"ὁ φεύγων = έναρθρη επιθετική μετοχή ουσιαστικοποιημένη = υποκείμενο· «αυτός που αποφεύγει τους κόπους». Ανάλυση: ὁ ἀνήρ ὅς φεύγει..."},{"gr":"οἱ νόμοι τό δίκαιον καί τό συμφέρον βούλονται","an":"τό δίκαιον, τό συμφέρον = ουδέτερα έναρθρα (μετοχή/επίθ.) ως αφηρημένα ουσιαστικά-αντικείμενα."},{"gr":"τόν ἐφεστηκότα κίνδυνον τῇ πόλει","an":"ἐφεστηκότα = επιθετική (αναφορική) μετοχή σε επιθετική θέση = επιθετικός προσδ. στο κίνδυνον· ανάλυση: τόν κίνδυνον ὅς ἐφέστηκε τῇ πόλει."},{"gr":"οἱ βουλόμενοι ταῦτα πράττειν","an":"οἱ βουλόμενοι = ουσιαστικοποιημένη επιθετική μετοχή = υποκείμενο· «όσοι θέλουν»."},{"gr":"ἡ τῶν τεθνεώτων ἀρετή","an":"τῶν τεθνεώτων = ουσιαστικοποιημένη επιθετική μετοχή σε γενική· «η αρετή των νεκρών»."},{"gr":"οἱ φεύγοντες κατῆλθον εἰς τήν πόλιν","an":"Ξεν. (τύπου Ἑλλ.) — οἱ φεύγοντες = ουσιαστικοποιημένη επιθετική μετοχή = υποκείμενο· «οι εξόριστοι/φυγάδες». Ανάλυση: οἱ ἄνδρες οἵ ἔφευγον."},{"gr":"τά γιγνόμενα ἐν τῇ πόλει","an":"τά γιγνόμενα = ουδέτ. πληθ. ουσιαστικοποιημένη επιθετική μετοχή· «όσα συμβαίνουν / τα γεγονότα». Ανάλυση: ταῦτα ἅ γίγνεται."},{"gr":"ὁ τήν πόλιν προδούς ἀπέθανεν","an":"Λυσ. (τύπου) — ὁ προδούς = έναρθρη αοριστική επιθετική μετοχή ουσιαστικοποιημένη = υποκείμενο· «αυτός που πρόδωσε». Ανάλυση: ὁ ἀνήρ ὅς προέδωκε τήν πόλιν."}],"note":"Διάκριση από την επιρρηματική μετοχή: η επιθετική μετοχή είναι (σχεδόν πάντα) ΕΝΑΡΘΡΗ και ισοδυναμεί με αναφορική πρόταση. Η επιρρηματική (χρονική, αιτιολογική, υποθετική κ.λπ.) είναι ΑΝΑΡΘΡΗ και ισοδυναμεί με επιρρηματική πρόταση. Το άρθρο είναι το πρώτο σημάδι."},{"h":"Διάκριση επιθετικού από κατηγορηματικό προσδιορισμό","body":"<p>Η σημαντικότερη παγίδα του κεφαλαίου είναι η διάκριση <b>επιθετικού</b> από <b>κατηγορηματικό</b> προσδιορισμό. Και οι δύο είναι ομοιόπτωτοι προσδιορισμοί από επίθετο· διαφέρουν στη <b>θέση (άρθρο)</b> και στη <b>σημασία (μονιμότητα)</b>.</p><h3>Εσωτερικό κριτήριο — σημασία</h3><ul><li><b>Επιθετικός</b>: <b>μόνιμη</b>, διαρκής ιδιότητα. ὁ ἀγαθός ἀνήρ = ο εκ φύσεως αγαθός.</li><li><b>Κατηγορηματικός</b>: <b>παροδική</b> ιδιότητα, κατάσταση τη συγκεκριμένη στιγμή. κατέλαβον τήν πόλιν <b>ἐρήμην</b> = κατέλαβαν την πόλη ενώ ήταν (τότε) έρημη.</li></ul><h3>Εξωτερικό κριτήριο — άρθρο/θέση</h3><p>Ο κατηγορηματικός προσδιορισμός είναι <b>άναρθρο επίθετο</b> που συνοδεύει <b>έναρθρο ουσιαστικό</b> και βρίσκεται σε <b>κατηγορηματική θέση</b> (έξω από το «άρθρο+ουσιαστικό»): <b>ὁ ἀνήρ σοφός</b> ή <b>σοφός ὁ ἀνήρ</b>. Αντίθετα, το έναρθρο επίθετο σε επιθετική θέση είναι επιθετικός.</p><h3>Λέξεις που τυπικά δίνουν κατηγορηματικό προσδιορισμό (όταν είναι άναρθρες)</h3><p>πᾶς, ἅπας, σύμπας, ὅλος, ἄκρος, μέσος, ἔσχατος, αὐτός, μόνος, ἕκαστος. Όταν οι ίδιες λέξεις γίνουν <b>έναρθρες</b> και μπουν σε επιθετική θέση, αλλάζουν σημασία και γίνονται <b>επιθετικοί</b>.</p><p>Κλασικό ζεύγος: <b>μέση ἡ ὁδός / ἡ ὁδός μέση</b> = «η μέση της οδού, το μέσον του δρόμου» (κατηγορηματικός), ενώ <b>ἡ μέση ὁδός</b> = «ο μεσαίος δρόμος» (επιθετικός). Όμοια: <b>ἄκρα ἡ χείρ</b> = «η άκρη του χεριού», <b>ἡ ἄκρα χείρ</b> = «το άκρο χέρι».</p>","examples":[{"gr":"κατέλαβον τήν πόλιν ἐρήμην","an":"ἐρήμην = κατηγορηματικός προσδ. (άναρθρο επίθ. + έναρθρο ουσ., παροδική κατάσταση): «κατέλαβαν την πόλη ενώ ήταν έρημη»."},{"gr":"πᾶσα ἡ πόλις / ἡ πᾶσα πόλις","an":"πᾶσα ἡ πόλις = «όλη η πόλη» (κατηγ. προσδ.)· ἡ πᾶσα πόλις = «η πόλη ως σύνολο/ολόκληρη» (επιθετικός, έναρθρο)."},{"gr":"μέσην τήν νύκτα / ἡ μέση νύξ","an":"μέσην τήν νύκτα = «στο μέσο της νύχτας» (κατηγ.)· ἡ μέση νύξ = «η μεσαία νύχτα» (επιθετικός)."},{"gr":"αὐτός ὁ βασιλεύς","an":"αὐτός σε κατηγορηματική θέση = «ο ίδιος ο βασιλιάς» (κατηγ. προσδ.)· ενώ ὁ αὐτός βασιλεύς = «ο ίδιος (ο αυτός = ο γνωστός) βασιλιάς» (επιθετικός)."},{"gr":"ἐπί ἄκρον τό ὄρος ἀνέβησαν","an":"Ξεν. (τύπου Ἀνάβ.) — ἄκρον = κατηγορηματικός προσδ. (άναρθρο, σε κατηγ. θέση): «στην κορυφή του βουνού»· ενώ τό ἄκρον ὄρος θα ήταν «το ψηλό βουνό» (επιθετικός)."},{"gr":"μόνος ὁ στρατηγός παρέμεινεν","an":"μόνος = κατηγορηματικός προσδ. σε κατηγ. θέση: «μόνος ο στρατηγός / ο στρατηγός μοναχός του»· ενώ ὁ μόνος στρατηγός = «ο μοναδικός στρατηγός» (επιθετικός)."}],"table":{"title":"Επιθετικός vs Κατηγορηματικός — γρήγορος πίνακας","cols":["Κριτήριο","Επιθετικός","Κατηγορηματικός"],"rows":[["Σημασία ιδιότητας","μόνιμη / διαρκής","παροδική / στιγμιαία"],["Άρθρο επιθέτου","έναρθρο (συνήθως)","άναρθρο"],["Ουσιαστικό","έναρθρο ή άναρθρο","κατά κανόνα έναρθρο"],["Θέση","επιθετική (μέσα στο άρθρο)","κατηγορηματική (έξω)","-"],["Τυπικές λέξεις","κανονικά επίθετα","πᾶς, ὅλος, μέσος, ἄκρος, αὐτός, μόνος"]]},"note":"Ο πίνακας έχει μια γραμμή με extra κελί — αγνόησέ το· το ουσιώδες είναι: έναρθρο μέσα στο άρθρο = επιθετικός, άναρθρο έξω = κατηγορηματικός."},{"h":"Διάκριση από κατηγορούμενο και πρακτική μεθοδολογία","body":"<p>Τελευταία και πιο λεπτή διάκριση: <b>κατηγορηματικός προσδιορισμός</b> έναντι <b>κατηγορουμένου</b>. Και τα δύο είναι άναρθρα επίθετα με έναρθρο ουσιαστικό — αλλά:</p><ul><li><b>Κατηγορηματικός προσδιορισμός</b>: εμφανίζεται με <b>μεταβατικό/κοινό ρήμα</b> και αποδίδει ιδιότητα <b>χωρίς συνδετικό ρήμα</b>. <i>κατέλαβον τήν πόλιν ἐρήμην</i> (ρήμα: κατέλαβον, μεταβατικό).</li><li><b>Κατηγορούμενο</b>: εμφανίζεται με <b>συνδετικό ρήμα</b> (εἰμί, γίγνομαι, καθίσταμαι, φαίνομαι κ.λπ.) και αποδίδει την ιδιότητα <b>μέσω αυτού</b>. <i>ἡ πόλις ἦν ἐρήμη</i> (ρήμα: ἦν, συνδετικό).</li></ul><h3>Αντίστοιχα ο επιθετικός vs το κατηγορούμενο</h3><p>Ο επιθετικός προσδ. αποδίδει την ιδιότητα <b>απευθείας</b>, μέσα στην ονοματική φράση (ὁ <b>γελαστός</b> ἄνθρωπος), ενώ το κατηγορούμενο τη συνδέει με το υποκείμενο/αντικείμενο <b>διά μέσου ρήματος</b> (ὁ ἄνθρωπος <b>ἐστί γελαστός</b>).</p><h3>Βήματα αναγνώρισης — «αλγόριθμος»</h3><ol><li>Είναι το επίθετο σε <b>επιθετική θέση</b> (μέσα στο άρθρο / με δικό του άρθρο); → <b>επιθετικός προσδιορισμός</b>.</li><li>Είναι <b>άναρθρο</b> με <b>έναρθρο ουσιαστικό</b> και υπάρχει <b>συνδετικό ρήμα</b>; → <b>κατηγορούμενο</b>.</li><li>Είναι <b>άναρθρο</b> με <b>έναρθρο ουσιαστικό</b> αλλά <b>μη συνδετικό ρήμα</b> (ή καθόλου ρήμα-σύνδεσμος); → <b>κατηγορηματικός προσδιορισμός</b> (συνήθως πᾶς, ὅλος, μόνος, μέσος, ἄκρος, αὐτός...).</li><li>Πάντα έλεγξε τη <b>σημασία</b>: μόνιμη → κλίνει προς επιθετικό· παροδική → προς κατηγορηματικό.</li></ol>","examples":[{"gr":"ὁ Γεώργιος γελαστός / ὁ Γεώργιος ἐστί γελαστός","an":"Χωρίς ρήμα (ή με μη-συνδετικό): κατηγορηματικός. Με συνδετικό ἐστί: κατηγορούμενο. Η ίδια λέξη, διαφορετική λειτουργία λόγω ρήματος."},{"gr":"ἡ πόλις ἦν ἐρήμη","an":"ἐρήμη = κατηγορούμενο (μέσω του συνδετικού ἦν), σε αντίθεση με το κατέλαβον τήν πόλιν ἐρήμην (κατηγορηματικός)."},{"gr":"οἱ στρατιῶται μόνοι ἀπῆλθον","an":"μόνοι = κατηγορηματικός προσδ. (άναρθρο, μη συνδετικό ρήμα ἀπῆλθον): «μόνοι τους έφυγαν»."},{"gr":"ὁ σοφός διδάσκαλος ἐπαινεῖται","an":"σοφός = επιθετικός προσδ. (επιθετική θέση, έναρθρο), ανεξάρτητα από το ρήμα ἐπαινεῖται."},{"gr":"ὁ ἀνήρ ἀγαθός γίγνεται","an":"ἀγαθός = κατηγορούμενο (μέσω του συνδετικού γίγνεται)· συγκρ. ὁ ἀγαθός ἀνήρ (επιθετικός) και ὁ ἀνήρ ἀγαθός χωρίς ρήμα (κατηγ. προσδ.)."},{"gr":"εὕρομεν τάς θύρας κεκλεισμένας","an":"Λυσ. (τύπου) — κεκλεισμένας = κατηγορηματικός προσδ. (άναρθρη μτχ., μη συνδετικό ρήμα εὕρομεν): «βρήκαμε τις πόρτες κλειστές (τη στιγμή εκείνη)»· παροδική κατάσταση."}],"note":"Συχνό λάθος: να θεωρηθεί κατηγορούμενο ένα άναρθρο επίθετο που όμως δεν έχει συνδετικό ρήμα. Χωρίς συνδετικό ρήμα ΔΕΝ υπάρχει κατηγορούμενο — είναι κατηγορηματικός προσδιορισμός. Και αντίστροφα: έναρθρο επίθετο σε επιθετική θέση δεν γίνεται ποτέ κατηγορούμενο, ακόμη κι αν υπάρχει εἰμί στην πρόταση."}]);
  T("syn-katigorimatikos", [{"h":"Ορισμός και ουσία του κατηγορηματικού προσδιορισμού","body":"<p>Ο <b>κατηγορηματικός προσδιορισμός</b> είναι <b>ομοιόπτωτος ονοματικός προσδιορισμός</b>: συμφωνεί δηλαδή με τον προσδιοριζόμενο όρο σε <i>πτώση, γένος και αριθμό</i>, ακριβώς όπως ο επιθετικός προσδιορισμός και η παράθεση/επεξήγηση. Εκφέρεται κατά κανόνα με <b>άναρθρο επίθετο</b> (σπανιότερα με μετοχή ή αντωνυμία) και αποδίδει στο ουσιαστικό μια <b>παροδική, πρόσκαιρη, περιστασιακή ιδιότητα</b> — μια ιδιότητα που το ουσιαστικό έχει <i>τη συγκεκριμένη στιγμή της πράξης</i> και όχι μόνιμα.</p><p>Εδώ βρίσκεται η καρδιά της έννοιας. Ο επιθετικός προσδιορισμός δηλώνει <b>μόνιμη / σταθερή ιδιότητα</b> («το ψυχρό ύδωρ» = το νερό που από τη φύση του είναι ψυχρό), ενώ ο κατηγορηματικός δηλώνει <b>κατάσταση κατά τη στιγμή του ρήματος</b> («ψυχρόν τό ύδωρ πίνω» = πίνω το νερό <i>όντας αυτό κρύο τώρα</i>). Γι' αυτό και ονομάστηκε «κατηγορηματικός»: λειτουργεί σαν ένα <b>συντομευμένο κατηγορούμενο</b>, σαν να υπολανθάνει ένα «ων / οντα» (= όντας). Π.χ. <i>κατέλαβον τήν πόλιν ἐρήμην</i> ισοδυναμεί νοηματικά με <i>κατέλαβον τήν πόλιν ἐρήμην <b>οὖσαν</b></i> (κατέλαβαν την πόλη <i>ενώ ήταν</i> έρημη — όχι μόνιμα έρημη).</p><p>Το κρίσιμο τυπικό γνώρισμα είναι η <b>κατηγορηματική θέση</b> (βλ. επόμενο κεφάλαιο): ο κατηγορηματικός προσδιορισμός βρίσκεται <i>έξω</i> από το σύμπλεγμα άρθρου–ουσιαστικού, δηλαδή <b>πριν από το άρθρο</b> ή <b>μετά το ουσιαστικό</b>, ποτέ ανάμεσά τους με δικό του άρθρο.</p>","examples":[{"gr":"Κατέλαβον τήν πόλιν ἐρήμην.","an":"<i>ἐρήμην</i> = κατηγορηματικός προσδιορισμός στο <i>τήν πόλιν</i>. Δηλώνει παροδική κατάσταση: η πόλη ήταν έρημη <b>τη στιγμή που την κατέλαβαν</b>, όχι από τη φύση της. Ισοδυναμεί με «τήν πόλιν ἐρήμην οὖσαν». Αντιπαραβάλετε με τον επιθετικό «τήν ἐρήμην πόλιν / τήν πόλιν τήν ἐρήμην» = την (μονίμως) έρημη πόλη."},{"gr":"Ψυχρόν τό ὕδωρ πίνουσιν.","an":"<i>ψυχρόν</i> (άναρθρο, πριν το άρθρο) = κατηγορηματικός στο <i>τό ὕδωρ</i>. Πίνουν το νερό <b>ενώ είναι κρύο</b> (πρόσκαιρη ιδιότητα της στιγμής). Πρβλ. επιθετικό «τό ψυχρόν ὕδωρ» = το (εκ φύσεως) κρύο νερό."},{"gr":"Γυμνήν εἶδε τήν ἀλήθειαν.","an":"<i>γυμνήν</i> = κατηγορηματικός στο <i>τήν ἀλήθειαν</i>. Είδε την αλήθεια <b>γυμνή</b> — όπως αυτή παρουσιάστηκε εκείνη τη στιγμή. Νοηματικά: «τήν ἀλήθειαν γυμνήν οὖσαν»."},{"gr":"Κῦρος ψιλήν ἔχων τήν κεφαλήν εἰς τήν μάχην καθίστατο.","an":"Ξεν. Ἀνάβ. 1.8.6 — <i>ψιλήν</i> = κατηγορηματικός προσδ. στο <i>τήν κεφαλήν</i>: «έχοντας ακάλυπτο/γυμνό το κεφάλι» (κατάσταση της στιγμής, όχι μόνιμη ιδιότητα). Δέχεται νοητό «οὖσαν»."},{"gr":"Τάς τριήρεις ἀφείλκυσαν κενάς.","an":"Θουκ. 2.93.2 — <i>κενάς</i> = κατηγορηματικός στο <i>τάς τριήρεις</i>: «τράβηξαν τα πλοία (μακριά) άδεια (χωρίς πληρώματα)». Παροδική κατάσταση τη στιγμή της ενέργειας· ισοδ. «κενάς οὔσας»."},{"gr":"Ἀθάνατον τήν περί αὑτῶν μνήμην καταλείψουσιν.","an":"Ἰσοκρ. 9.3 (Εὐαγόρας) — <i>ἀθάνατον</i> (άναρθρο, πριν το άρθρο) = κατηγορηματικός στο <i>τήν μνήμην</i>: «θα αφήσουν τη μνήμη τους αθάνατη». Το επίθετο δηλώνει την ιδιότητα όπως προκύπτει από την πράξη."}],"note":"Μνημονικός κανόνας: αν μπορείς να προσθέσεις νοητά «ὤν / οὖσα / ὄν (= όντας)» δίπλα στο επίθετο και το νόημα στέκει, τότε πρόκειται για κατηγορηματικό προσδιορισμό. «τήν πόλιν ἐρήμην (οὖσαν)» → ναι, κατηγορηματικός."},{"h":"Η κατηγορηματική θέση (vs επιθετική θέση)","body":"<p>Η θέση του προσδιορισμού ως προς το άρθρο είναι το <b>αποφασιστικό κριτήριο</b> για να ξεχωρίσουμε επιθετικό από κατηγορηματικό. Η ελληνική γλώσσα κωδικοποιεί τη διαφορά <i>θέσης = σημασίας</i> με μεγάλη ακρίβεια (Smyth §1168 κ.εξ.).</p><h3>Επιθετική θέση (επιθετικός προσδιορισμός)</h3><p>Το επίθετο βρίσκεται <b>μέσα στο σύμπλεγμα άρθρου–ουσιαστικού</b>, δηλαδή <i>ανάμεσα στο άρθρο και το ουσιαστικό</i>, ή επαναλαμβάνεται με δικό του άρθρο μετά το ουσιαστικό:</p><ul><li><i>ὁ σοφός ἀνήρ</i> (άρθρο – επίθετο – ουσιαστικό)</li><li><i>ὁ ἀνήρ ὁ σοφός</i> (άρθρο – ουσιαστικό – άρθρο – επίθετο)</li></ul><p>Σημασία: μόνιμη ιδιότητα — «ο σοφός άνδρας».</p><h3>Κατηγορηματική θέση (κατηγορηματικός προσδιορισμός)</h3><p>Το επίθετο είναι <b>άναρθρο</b> και βρίσκεται <i>έξω</i> από το σύμπλεγμα — <b>πριν από το άρθρο</b> ή <b>μετά το (έναρθρο) ουσιαστικό</b>:</p><ul><li><i>σοφός ὁ ἀνήρ</i> (επίθετο – άρθρο – ουσιαστικό)</li><li><i>ὁ ἀνήρ σοφός</i> (άρθρο – ουσιαστικό – επίθετο)</li></ul><p>Σημασία: παροδική ιδιότητα / κατηγόρηση — «ο άνδρας (είναι/ως) σοφός».</p><p>Προσοχή στη λεπτή αλλά καίρια διαφορά: το <b>έναρθρο</b> ουσιαστικό + <b>άναρθρο</b> επίθετο εκτός συμπλέγματος = κατηγορηματικός. Αν λείπει το άρθρο από το ουσιαστικό (και τα δύο άναρθρα), τότε έχουμε απλό επιθετικό: <i>σοφός ἀνήρ</i> = «(ένας) σοφός άνδρας».</p>","table":{"title":"Θέση άρθρου / επιθέτου → είδος προσδιορισμού","cols":["Σχηματισμός","Παράδειγμα","Είδος","Σημασία"],"rows":[["άρθρο + επίθ. + ουσ.","ὁ σοφός ἀνήρ","Επιθετικός","ο σοφός άνδρας (μόνιμα)"],["άρθρο + ουσ. + άρθρο + επίθ.","ὁ ἀνήρ ὁ σοφός","Επιθετικός","ο σοφός άνδρας (μόνιμα)"],["επίθ. (άναρθρο) + άρθρο + ουσ.","σοφός ὁ ἀνήρ","Κατηγορηματικός","ο άνδρας (ως/όντας) σοφός"],["άρθρο + ουσ. + επίθ. (άναρθρο)","ὁ ἀνήρ σοφός","Κατηγορηματικός","ο άνδρας (ως/όντας) σοφός"],["επίθ. (άναρθρο) + ουσ. (άναρθρο)","σοφός ἀνήρ","Επιθετικός (απλός)","(ένας) σοφός άνδρας"]]},"examples":[{"gr":"ὁ ἀγαθός πολίτης / ἀγαθός ὁ πολίτης.","an":"<b>ὁ ἀγαθός πολίτης</b> (επιθετική θέση) = ο (μονίμως) καλός πολίτης. <b>ἀγαθός ὁ πολίτης</b> (κατηγορηματική θέση, άναρθρο επίθ. πριν το άρθρο) = ο πολίτης (είναι/φέρεται ως) αγαθός. Ίδιες λέξεις, μόνο η θέση αλλάζει τη σημασία."},{"gr":"τά καλά ἔργα / καλά τά ἔργα.","an":"<b>τά καλά ἔργα</b> = τα ωραία/ενάρετα έργα (επιθετικός, μόνιμη ιδιότητα). <b>καλά τά ἔργα</b> = τα έργα (είναι) καλά (κατηγορηματικός / κατηγόρηση)."},{"gr":"σοφός ὁ ἀνήρ / ὁ ἀνήρ σοφός.","an":"Σχολικό υπόδειγμα του Smyth (§1168) για την κατηγορηματική θέση: και στους δύο σχηματισμούς το άναρθρο <i>σοφός</i> στέκει έξω από το σύμπλεγμα άρθρου–ουσιαστικού → «ο άνδρας (είναι/ως) σοφός». Πρβλ. επιθετικά <i>ὁ σοφός ἀνήρ</i>."},{"gr":"Ἀτελεῖ τῇ νίκῃ ἀνέστησαν.","an":"Θουκ. 8.27.6 — <i>ἀτελεῖ</i> (άναρθρο, πριν το έναρθρο ουσ.) σε κατηγορηματική θέση: «αποχώρησαν με ατελή/μισοτελειωμένη τη νίκη». Δείχνει την κατάσταση της νίκης εκείνη τη στιγμή."}],"note":"Παγίδα: η κατηγορηματική θέση δεν προϋποθέτει συνδετικό ρήμα. «ὁ ἀνήρ σοφός» μέσα σε πρόταση με άλλο ρήμα έχει κατηγορηματικό προσδιορισμό· μόνο αν προστεθεί συνδετικό («ὁ ἀνήρ ἐστι σοφός») το <i>σοφός</i> γίνεται κατηγορούμενο. Δες το ξεχωριστό κεφάλαιο για τη διάκριση."},{"h":"Οι ειδικές λέξεις: πᾶς, ἅπας, σύμπας, ὅλος, μόνος, αὐτός, ἕκαστος","body":"<p>Μια ομάδα λέξεων χρησιμοποιείται <b>κατεξοχήν</b> ως κατηγορηματικός προσδιορισμός. Αυτές είναι: <b>πᾶς, ἅπας, σύμπας, ὅλος, μόνος, αὐτός, ἕκαστος</b> (και οι ποσοτικές/τοπικές <i>ἄκρος, μέσος, ἔσχατος</i> — βλ. επόμενο κεφάλαιο). Το χαρακτηριστικό τους είναι ότι <b>αλλάζουν σημασία ανάλογα με τη θέση τους</b> ως προς το άρθρο: σε <i>κατηγορηματική θέση</i> (άναρθρες, εκτός συμπλέγματος) έχουν τη μια σημασία· σε <i>επιθετική θέση</i> (έναρθρες, μέσα στο σύμπλεγμα) έχουν άλλη.</p><h3>πᾶς / ἅπας / σύμπας</h3><p>Σε <b>κατηγορηματική θέση</b> = «όλος, ο σύνολος, στο σύνολό του» (το σύνολο ως αθροισμα μερών): <i>πᾶσα ἡ πόλις</i> / <i>ἡ πόλις πᾶσα</i> = ολόκληρη η πόλη / όλη η πόλη μαζί. Σε <b>επιθετική θέση</b> = «το σύνολο ως ολότητα, ο καθένας, κάθε»: <i>ἡ πᾶσα πόλις</i> = η πόλη στο σύνολό της / η συνολική πόλη. Άναρθρο και μόνο του = «κάθε»: <i>πᾶς ἀνήρ</i> = κάθε άνδρας· πληθυντικός <i>πάντες ἄνδρες</i> = όλοι (οι) άνδρες.</p><h3>ὅλος</h3><p>Σε <b>κατηγορηματική θέση</b> = «ολόκληρος, στο σύνολό του»: <i>ὅλη ἡ πόλις</i> / <i>ἡ πόλις ὅλη</i> = ολόκληρη η πόλη. Σε <b>επιθετική θέση</b> <i>ἡ ὅλη πόλις</i> = το όλον/σύνολο (φιλοσοφικά: «το όλον» ως οντότητα).</p><h3>μόνος</h3><p>Σε <b>κατηγορηματική θέση</b> = «μόνος του, μοναχός, χωρίς άλλον» (επιρρηματικά): <i>μόνος ὁ παῖς</i> / <i>ὁ παῖς μόνος</i> = το παιδί μόνο του. Σε <b>επιθετική θέση</b> = «ο μοναδικός»: <i>ὁ μόνος παῖς</i> = ο μοναχογιός / ο μοναδικός γιος.</p><h3>αὐτός</h3><p>Σε <b>κατηγορηματική θέση</b> = «ο ίδιος, αυτοπροσώπως» (επιτατική/οριστική): <i>αὐτός ὁ ἀνήρ</i> / <i>ὁ ἀνήρ αὐτός</i> = ο ίδιος ο άνδρας. Σε <b>επιθετική θέση</b> = «ο ίδιος, ο αυτός» (ταυτότητα): <i>ὁ αὐτός ἀνήρ</i> = ο ίδιος (ταυτόσημος) άνδρας. <i>Σημ.:</i> Όταν το <b>αὐτός</b> είναι άναρθρο και δεν συνοδεύει έναρθρο όνομα, είναι προσωπική αντωνυμία γ΄ προσώπου (πλάγιες πτώσεις) ή επιτατικός σε ονομαστική («εγώ ο ίδιος»).</p><h3>ἕκαστος</h3><p>Κανονικά σε <b>κατηγορηματική θέση</b> = «ο καθένας (χωριστά)»: <i>ἕκαστος ὁ ἀνήρ</i> / συνηθέστερα <i>ἕκαστοι</i> = ο καθένας τους.</p>","table":{"title":"Σημασία ανά θέση (οι ειδικές λέξεις)","cols":["Λέξη","Κατηγορηματική θέση (άναρθρη)","Επιθετική θέση (έναρθρη)"],"rows":[["πᾶς / ἅπας / σύμπας","πᾶσα ἡ πόλις = ολόκληρη / όλη η πόλη","ἡ πᾶσα πόλις = η πόλη στο σύνολό της"],["ὅλος","ὅλη ἡ πόλις = ολόκληρη η πόλη","ἡ ὅλη πόλις = το όλον / σύνολο"],["μόνος","μόνος ὁ παῖς = το παιδί μόνο του","ὁ μόνος παῖς = ο μοναδικός / μοναχογιός"],["αὐτός","αὐτός ὁ ἀνήρ = ο ίδιος ο άνδρας","ὁ αὐτός ἀνήρ = ο ίδιος (ταυτόσημος)"],["ἕκαστος","ἕκαστος ὁ ἀνήρ = ο καθένας ξεχωριστά","(σπάνια έναρθρο)"]]},"examples":[{"gr":"Πᾶσα ἡ Ἑλλάς ἐκινήθη.","an":"<i>πᾶσα</i> (κατηγορηματική θέση, πριν το άρθρο) = κατηγορηματικός προσδιορισμός: «ολόκληρη / όλη η Ελλάδα κινητοποιήθηκε» — το σύνολο ως άθροισμα."},{"gr":"Αὐτός ὁ βασιλεύς παρῆν.","an":"<i>αὐτός</i> σε κατηγορηματική θέση = «ο ίδιος ο βασιλιάς (αυτοπροσώπως) ήταν παρών». Διαφέρει ριζικά από το <i>ὁ αὐτός βασιλεύς</i> = «ο ίδιος (ο αυτός, ο προηγουμένως αναφερθείς) βασιλιάς»."},{"gr":"Ὁ παῖς μόνος ἀπῆλθεν.","an":"<i>μόνος</i> σε κατηγορηματική θέση (μετά το έναρθρο ουσ.) = «το παιδί έφυγε μόνο του». Πρβλ. <i>ὁ μόνος παῖς</i> = ο μοναχογιός."},{"gr":"Ὅλην τήν νύκτα ἐμάχοντο.","an":"<i>ὅλην</i> = κατηγορηματικός: «μάχονταν ολόκληρη τη νύχτα». Συχνότατο σε χρονικές εκφράσεις (όλη την ημέρα/νύχτα/χρονιά). Πρβλ. <i>τήν νύκτα ὅλην</i> = «όλη τη νύχτα»."},{"gr":"Πάντες οἱ πολῖται μετεῖχον τῆς ἑορτῆς.","an":"<i>πάντες</i> (κατηγορηματική θέση, πριν το άρθρο) = «όλοι οι πολίτες (ο καθένας ξεχωριστά) μετείχαν στη γιορτή». Πρβλ. επιθετικό <i>οἱ πάντες πολῖται</i> (τύπου) = το σύνολο των πολιτών ως σώμα."},{"gr":"Ὅλον τό στράτευμα διέβη τόν ποταμόν.","an":"<i>ὅλον</i> (κατηγορηματική θέση) = «ολόκληρο το στράτευμα πέρασε τον ποταμό». Κατηγορ. <i>ὅλον τό στράτευμα</i> = «ο στρατός στο σύνολό του», έναντι επιθ. <i>τό ὅλον στράτευμα</i> = «το όλον στράτευμα»."}],"note":"Σημαντική παγίδα: το <b>αὐτός</b> έχει ΤΡΕΙΣ χρήσεις — (1) κατηγορηματική θέση = «ο ίδιος» (επιτατικός κατηγορ. προσδ.)· (2) επιθετική θέση = «ο αυτός / ο ίδιος» (ταυτότητα)· (3) άναρθρο σε πλάγια πτώση = προσωπική αντωνυμία «αυτόν, αυτής...». Πάντα ελέγξτε θέση και πτώση."},{"h":"Οι τοπικές/μεριστικές λέξεις: ἄκρος, μέσος, ἔσχατος","body":"<p>Οι λέξεις <b>ἄκρος, μέσος, ἔσχατος</b> (και συγγενικές: <i>πρῶτος, ὕστατος, ἥμισυς, ἐναντίος</i>) ανήκουν στις ειδικές, αλλά αξίζουν χωριστή μεταχείριση γιατί η αλλαγή θέσης τους παράγει <b>τοπική/μεριστική σημασία</b> — δηλώνουν ένα <i>μέρος</i> του ουσιαστικού (την άκρη, το μέσο, το έσχατο σημείο του).</p><p>Σε <b>κατηγορηματική θέση</b> (άναρθρες) σημαίνουν «το άκρο/μέσο/έσχατο μέρος του Χ» — λειτουργούν δηλαδή σαν μεριστικός προσδιορισμός: αναφέρονται όχι σε όλο το αντικείμενο αλλά σε ένα τμήμα του. Σε <b>επιθετική θέση</b> (έναρθρες) έχουν την κανονική επιθετική σημασία «ακραίος / μεσαίος / τελευταίος».</p><ul><li><b>ἄκρος</b>: κατηγ. <i>ἄκρον τό ὄρος / τό ὄρος ἄκρον</i> = «η κορυφή του βουνού» (το άκρο μέρος)· επιθ. <i>τό ἄκρον ὄρος</i> = «το ψηλό/ακρότατο βουνό».</li><li><b>μέσος</b>: κατηγ. <i>μέση ἡ ἀγορά / ἡ ἀγορά μέση</i> = «το μέσο/κέντρο της αγοράς»· επιθ. <i>ἡ μέση ἀγορά</i> = «η μεσαία αγορά».</li><li><b>ἔσχατος</b>: κατηγ. <i>ἐσχάτη ἡ νῆσος</i> = «το έσχατο/άκρο σημείο του νησιού»· επιθ. <i>ἡ ἐσχάτη νῆσος</i> = «το τελευταίο/απώτατο νησί».</li></ul><p>Η σημασία αυτή της κατηγορηματικής θέσης ισοδυναμεί με γενική διαιρετική: <i>ἄκρον τό ὄρος</i> ≈ <i>τό ἄκρον τοῦ ὄρους</i> (Smyth §1172) = «το ανώτατο σημείο του βουνού». Συχνά λοιπόν το ουσιαστικοποιημένο ουδέτερο (<i>τό ἄκρον, τό μέσον, τό ἔσχατον</i>) + γενική προτιμάται ως ισοδύναμη διατύπωση.</p>","table":{"title":"ἄκρος / μέσος / ἔσχατος: θέση και σημασία","cols":["Λέξη","Κατηγορηματική θέση","Επιθετική θέση"],"rows":[["ἄκρος","ἄκρον τό ὄρος = η κορυφή του βουνού","τό ἄκρον ὄρος = το ψηλό/ακρότατο βουνό"],["μέσος","μέση ἡ ἀγορά = το κέντρο της αγοράς","ἡ μέση ἀγορά = η μεσαία αγορά"],["ἔσχατος","ἐσχάτη ἡ νῆσος = το άκρο σημείο του νησιού","ἡ ἐσχάτη νῆσος = το απώτατο/τελευταίο νησί"],["πρῶτος","πρῶτος ὁ δάκτυλος = η άκρη του δαχτύλου","ὁ πρῶτος δάκτυλος = το πρώτο δάχτυλο"]]},"examples":[{"gr":"Ἐπί ἄκρῳ τῷ ὄρει ἐστρατοπεδεύσαντο.","an":"<i>ἄκρῳ</i> σε κατηγορηματική θέση = «στρατοπέδευσαν στην κορυφή (στο ψηλότερο σημείο) του βουνού». Μεριστική σημασία: όχι σε όλο το βουνό, αλλά στην άκρη του. Ισοδύναμο: <i>ἐπ' ἄκρου τοῦ ὄρους</i>."},{"gr":"Ἐν μέσῃ τῇ ἀγορᾷ ἔστησαν.","an":"<i>μέσῃ</i> (κατηγορηματική θέση) = «στάθηκαν στο κέντρο/στο μέσο της αγοράς». Πρβλ. <i>ἐν τῇ μέσῃ ἀγορᾷ</i> = στη μεσαία αγορά (αν υπήρχαν πολλές)."},{"gr":"Ἔσχατοι οἱ Πέρσαι ἐτάχθησαν.","an":"<i>ἔσχατοι</i> (κατηγορηματική θέση) = «οι Πέρσες τάχθηκαν στο έσχατο/τελευταίο σημείο (στην ουρά της παράταξης)»."},{"gr":"Περί ἄκραις ταῖς χερσί χειρῖδας ἔχουσιν.","an":"Ξεν. Κύρ. Παιδ. 8.8.17 — <i>ἄκραις</i> σε κατηγορηματική θέση: «γύρω από τα άκρα των χεριών (τις άκρες των χεριών) έχουν χειρόκτια». Μεριστική σημασία: το άκρο μέρος του χεριού, όχι όλο το χέρι."},{"gr":"Διά μέσου τοῦ παραδείσου ῥεῖ ὁ Μαίανδρος ποταμός.","an":"Ξεν. Ἀνάβ. 1.2.7 — <i>μέσου</i> (εδώ ουσιαστικοποιημένο, διά μέσου = ισοδύναμο της κατηγορ. <i>μέση</i>): «(ο ποταμός Μαίανδρος) ρέει μέσα από το μέσο/κέντρο του πάρκου». Δηλώνει το ενδιάμεσο μέρος του χώρου."}],"note":"Κανόνας-κλειδί: για τα ἄκρος/μέσος/ἔσχατος, η κατηγορηματική θέση δίνει ΤΟΠΙΚΗ/ΜΕΡΙΣΤΙΚΗ σημασία («το άκρο μέρος του...»), ενώ η επιθετική δίνει ΠΟΙΟΤΙΚΗ («ο ακραίος/μεσαίος/τελευταίος...»). Μην το συγχέετε με τη χρονική σημασία απομονωμένων λέξεων."},{"h":"Διάκριση κατηγορηματικού προσδιορισμού από κατηγορούμενο","body":"<p>Η συχνότερη και δυσκολότερη σύγχυση των μαθητών: κατηγορηματικός προσδιορισμός <i>ή</i> κατηγορούμενο; Και τα δύο εκφέρονται με άναρθρο επίθετο/μετοχή που συμφωνεί με όνομα, και τα δύο δηλώνουν ιδιότητα. Η διάκριση όμως είναι σαφής και στηρίζεται σε <b>δύο κριτήρια</b>.</p><h3>Κριτήριο 1 — το ρήμα</h3><p>Το <b>κατηγορούμενο απαιτεί συνδετικό (ή δοκούν/κλητικό) ρήμα</b> — εἰμί, γίγνομαι, καθίσταμαι, φαίνομαι, δοκῶ, ὀνομάζομαι, αἱροῦμαι, νομίζομαι κ.λπ. Αποτελεί <i>αναγκαίο συμπλήρωμα</i> του ρήματος: χωρίς αυτό η πρόταση είναι ελλιπής. Ο κατηγορηματικός προσδιορισμός <b>δεν χρειάζεται συνδετικό ρήμα</b>· προσαρτάται απευθείας σε ένα όνομα και η πρόταση στέκει χωρίς αυτόν.</p><ul><li><i>Ἡ πόλις ἐστίν ἐρήμη.</i> → <b>κατηγορούμενο</b> (υπάρχει το <i>ἐστίν</i>· το <i>ἐρήμη</i> είναι το αναγκαίο συμπλήρωμα).</li><li><i>Κατέλαβον τήν πόλιν ἐρήμην.</i> → <b>κατηγορηματικός προσδιορισμός</b> (το ρήμα <i>κατέλαβον</i> δεν είναι συνδετικό· το <i>ἐρήμην</i> προσδιορίζει το αντικείμενο <i>τήν πόλιν</i>).</li></ul><h3>Κριτήριο 2 — το άρθρο του ονόματος</h3><p>Ο κατηγορηματικός προσδιορισμός συνοδεύει συνήθως <b>έναρθρο</b> όνομα (<i>τήν πόλιν</i> ἐρήμην). Το κατηγορούμενο αναφέρεται στο υποκείμενο/αντικείμενο που μπορεί να είναι έναρθρο ή άναρθρο, αλλά το ίδιο το κατηγορούμενο είναι πάντα άναρθρο και συνδέεται μέσω ρήματος.</p><h3>Το ενδιάμεσο: επιρρηματικό / προληπτικό κατηγορούμενο</h3><p>Υπάρχει και η περίπτωση του <b>κατηγορουμένου του αντικειμένου</b> (μετά από ρήματα όπως ποιῶ, καθίστημι, νομίζω, ἡγοῦμαι, αἱροῦμαι): <i>τήν πόλιν ἐποίησαν ἐρήμην</i> = κατηγορούμενο του αντικειμένου (το ρήμα είναι μεταβατικό-«γίνομαι»-τύπου, και χωρίς το <i>ἐρήμην</i> η σημασία ατελής). Διαφέρει από το <i>κατέλαβον τήν πόλιν ἐρήμην</i> (κατηγορηματικός), όπου το <i>ἐρήμην</i> δεν είναι αναγκαίο συμπλήρωμα του ρήματος.</p>","table":{"title":"Κατηγορηματικός προσδιορισμός vs Κατηγορούμενο","cols":["Κριτήριο","Κατηγορηματικός προσδ.","Κατηγορούμενο"],"rows":[["Συνδετικό ρήμα","ΟΧΙ απαραίτητο","ΝΑΙ απαραίτητο (εἰμί, γίγνομαι...)"],["Σχέση με όνομα","προσαρτάται απευθείας στο όνομα","συνδέεται με υποκ./αντικ. μέσω ρήματος"],["Αναγκαιότητα","προαιρετικός (η πρόταση στέκει)","αναγκαίο συμπλήρωμα του ρήματος"],["Σημασία","παροδική ιδιότητα της στιγμής","αποδίδει/βεβαιώνει ιδιότητα μέσω ρήματος"],["Παράδειγμα","κατέλαβον τήν πόλιν ἐρήμην","ἡ πόλις ἦν ἐρήμη"]]},"examples":[{"gr":"Ξενοφῶν ἔλαβε τόν ποταμόν μέγαν.","an":"<i>μέγαν</i> = κατηγορηματικός προσδ. (το <i>ἔλαβε/βρήκε</i> δεν είναι συνδετικό): «βρήκε τον ποταμό μεγάλο (φουσκωμένο εκείνη τη στιγμή)»."},{"gr":"Ὁ ποταμός ἐγένετο μέγας.","an":"<i>μέγας</i> = κατηγορούμενο (υπάρχει το συνδετικό <i>ἐγένετο</i>): «ο ποταμός έγινε μεγάλος». Αναγκαίο συμπλήρωμα του ρήματος."},{"gr":"Οἱ Ἀθηναῖοι Περικλέα στρατηγόν εἵλοντο.","an":"<i>στρατηγόν</i> = κατηγορούμενο του αντικειμένου (<i>εἵλοντο</i> = εξέλεξαν): «εξέλεξαν τον Περικλή στρατηγό». Όχι κατηγορηματικός προσδ., γιατί το ρήμα απαιτεί το συμπλήρωμα."},{"gr":"Ἀλέξανδρος προὐχώρει συντεταγμένῳ τῷ στρατῷ.","an":"<i>συντεταγμένῳ</i> (μετοχή σε κατηγορηματική θέση, πριν το έναρθρο ουσ.) = κατηγορηματικός προσδ. στο <i>τῷ στρατῷ</i>: «ο Αλέξανδρος προχωρούσε με τον στρατό συντεταγμένο». Το ρήμα <i>προὐχώρει</i> δεν είναι συνδετικό· δηλώνει την παροδική κατάσταση του στρατού (= «συντεταγμένῳ ὄντι»)."},{"gr":"Λευκίππην εἶδε δεδεμένην.","an":"(τύπου μυθιστορ.) — <i>δεδεμένην</i> = κατηγορηματικός προσδ. (μετοχή) στο αντικ. <i>Λευκίππην</i>· το <i>εἶδε</i> δεν είναι συνδετικό: «είδε τη Λευκίππη δεμένη (εκείνη τη στιγμή)». Πρβλ. αν είχαμε <i>ἐδέδετο</i> ή <i>ἦν δεδεμένη</i> → κατηγορούμενο."}],"note":"Συνοπτικός έλεγχος: «Υπάρχει συνδετικό/δοκούν ρήμα που να απαιτεί το επίθετο;» — ΝΑΙ → κατηγορούμενο. ΟΧΙ, το επίθετο κρέμεται απευθείας από έναρθρο όνομα και δηλώνει στιγμιαία κατάσταση → κατηγορηματικός προσδιορισμός."},{"h":"Συνολική διάκριση των τριών ειδών & μέθοδος αναγνώρισης","body":"<p>Για να κλείσει το θέμα, συνοψίζουμε τη <b>διάκριση επιθετικού – κατηγορηματικού – κατηγορουμένου</b> και δίνουμε μια πρακτική μέθοδο αναγνώρισης σε τρία βήματα.</p><h3>Συνοπτική αντιπαραβολή</h3><ul><li><b>Επιθετικός προσδιορισμός:</b> έναρθρος / σε επιθετική θέση· δηλώνει <i>μόνιμη</i> ιδιότητα· δεν θέλει ρήμα. <i>ὁ ἀγαθός ἀνήρ</i>.</li><li><b>Κατηγορηματικός προσδιορισμός:</b> άναρθρος / σε κατηγορηματική θέση δίπλα σε <i>έναρθρο</i> όνομα· δηλώνει <i>παροδική</i> ιδιότητα· δεν θέλει συνδετικό ρήμα. <i>ἀγαθός ὁ ἀνήρ / ὁ ἀνήρ ἀγαθός</i> (μέσα σε πρόταση με άλλο ρήμα).</li><li><b>Κατηγορούμενο:</b> άναρθρο επίθετο που συνδέεται με όνομα <i>μέσω συνδετικού/δοκούντος ρήματος</i>· αναγκαίο συμπλήρωμα. <i>ὁ ἀνήρ ἐστιν ἀγαθός</i>.</li></ul><h3>Μέθοδος αναγνώρισης σε 3 βήματα</h3><ol><li><b>Βρες το ρήμα.</b> Είναι συνδετικό/δοκούν (εἰμί, γίγνομαι, φαίνομαι, καθίσταμαι, δοκῶ, νομίζομαι, αἱροῦμαι...) και το επίθετο το συμπληρώνει; → <b>Κατηγορούμενο</b>. Αν όχι, προχώρα.</li><li><b>Κοίτα το άρθρο.</b> Το επίθετο είναι έναρθρο ή μέσα στο σύμπλεγμα άρθρου–ουσιαστικού; → <b>Επιθετικός</b>. Αν είναι άναρθρο και έξω από το σύμπλεγμα, δίπλα σε έναρθρο όνομα → προχώρα.</li><li><b>Έλεγξε τη σημασία.</b> Δηλώνει παροδική ιδιότητα και δέχεται νοητό «ὤν/οὖσα/ὄν (=όντας)»; → <b>Κατηγορηματικός προσδιορισμός</b>.</li></ol><p>Συμπληρωματικά: για τις ειδικές λέξεις (<i>πᾶς, ὅλος, μόνος, αὐτός, ἄκρος, μέσος, ἔσχατος, ἕκαστος</i>) η αναγνώριση γίνεται αυτόματα από τη θέση: άναρθρες έξω από το σύμπλεγμα = κατηγορηματικός (με τη μετατόπιση σημασίας που είδαμε)· έναρθρες μέσα στο σύμπλεγμα = επιθετικός.</p>","examples":[{"gr":"Πᾶσαν τήν ἡμέραν οἱ στρατιῶται ἐβάδιζον.","an":"Βήμα 1: <i>ἐβάδιζον</i> όχι συνδετικό. Βήμα 2: <i>πᾶσαν</i> άναρθρο, πριν το άρθρο, δίπλα σε έναρθρο <i>τήν ἡμέραν</i>. Βήμα 3: δηλώνει έκταση/ποσότητα → <b>κατηγορηματικός προσδιορισμός</b>: «όλη/ολόκληρη την ημέρα βάδιζαν»."},{"gr":"Ὁ στρατηγός σοφός ἐφαίνετο.","an":"Βήμα 1: <i>ἐφαίνετο</i> = δοκούν ρήμα, απαιτεί το <i>σοφός</i> → <b>κατηγορούμενο</b>: «ο στρατηγός φαινόταν σοφός». (Όχι κατηγορηματικός, μολονότι η θέση μοιάζει.)"},{"gr":"Ὁ σοφός στρατηγός ἐνίκησεν.","an":"Βήμα 1: <i>ἐνίκησεν</i> όχι συνδετικό. Βήμα 2: <i>ὁ σοφός στρατηγός</i> = επιθετική θέση → <b>επιθετικός προσδιορισμός</b>: «ο σοφός στρατηγός νίκησε» (μόνιμη ιδιότητα)."},{"gr":"Τόν ποταμόν διέβησαν ἄκρον.","an":"<i>ἄκρον</i> άναρθρο, εκτός συμπλέγματος, δίπλα σε έναρθρο <i>τόν ποταμόν</i>, ρήμα μη συνδετικό → <b>κατηγορηματικός (μεριστικός)</b>: «διέβησαν το άκρο/ρηχό μέρος του ποταμού»."},{"gr":"Ἀθάνατον τήν περί αὑτῶν μνήμην καταλείψουσιν.","an":"Ἰσοκρ. 9.3 — Βήμα 1: <i>καταλείψουσιν</i> όχι συνδετικό. Βήμα 2: <i>ἀθάνατον</i> άναρθρο, πριν το έναρθρο <i>τήν μνήμην</i>. Βήμα 3: παροδική/προκύπτουσα ιδιότητα → <b>κατηγορηματικός προσδιορισμός</b>: «θα αφήσουν τη μνήμη τους αθάνατη»."},{"gr":"Τήν κεφαλήν ψιλήν ἔχων προσήλαυνεν.","an":"Πρβλ. Ξεν. Ἀνάβ. 1.8.6 — Βήμα 1: <i>ἔχων/προσήλαυνεν</i> μη συνδετικά. Βήμα 2: <i>ψιλήν</i> άναρθρο, μετά το έναρθρο <i>τήν κεφαλήν</i>. Βήμα 3: στιγμιαία κατάσταση → <b>κατηγορηματικός προσδιορισμός</b>: «έχοντας γυμνό το κεφάλι, προέλαυνε»."}],"note":"Χρυσός κανόνας μνήμης: ΡΗΜΑ συνδετικό → κατηγορούμενο· ΑΡΘΡΟ μέσα στο σύμπλεγμα → επιθετικός· ΑΡΘΡΟ έξω + παροδική ιδιότητα + «(όντας)» → κατηγορηματικός. Τα τρία κριτήρια (ρήμα–θέση–σημασία) εφαρμόζονται πάντα με αυτή τη σειρά."}]);
  T("syn-parathesi-epexigisi", [{"h":"Τι είναι οι ομοιόπτωτοι προσδιορισμοί — η θέση παράθεσης & επεξήγησης","body":"<p>Στη σύνταξη της αρχαίας ελληνικής, κάθε <b>ουσιαστικό</b> (ή ουσιαστικοποιημένη λέξη) μπορεί να συνοδεύεται από <b>προσδιορισμούς</b>, δηλαδή λέξεις που το χαρακτηρίζουν, το περιορίζουν ή το διασαφηνίζουν. Οι ονοματικοί προσδιορισμοί χωρίζονται σε δύο μεγάλες ομάδες ανάλογα με την πτώση τους:</p><ul><li><b>Ομοιόπτωτοι</b>: βρίσκονται στην <i>ίδια πτώση</i> με τη λέξη που προσδιορίζουν (το προσδιοριζόμενο). Σε αυτούς ανήκουν ο <b>επιθετικός προσδιορισμός</b>, ο <b>κατηγορηματικός προσδιορισμός</b>, η <b>παράθεση</b> και η <b>επεξήγηση</b>.</li><li><b>Ετερόπτωτοι</b>: βρίσκονται σε <i>διαφορετική πτώση</i> (γενική, δοτική ή αιτιατική) από το προσδιοριζόμενο.</li></ul><p>Η <b>παράθεση</b> και η <b>επεξήγηση</b> είναι οι δύο ομοιόπτωτοι προσδιορισμοί που εκφέρονται με <b>ουσιαστικό</b> (όχι με επίθετο, όπως ο επιθετικός). Πρόκειται δηλαδή για ένα ουσιαστικό που τοποθετείται δίπλα σε άλλο ουσιαστικό, στην <i>ίδια πτώση, στο ίδιο γένος και (συνήθως) στον ίδιο αριθμό</i>, ώστε τα δύο να αναφέρονται στο <b>ίδιο πρόσωπο ή πράγμα</b> (συναναφορά / ταυτοπροσωπία).</p><p>Η θεμελιώδης ιδέα είναι η <b>ισοδυναμία αναφοράς</b>: όταν λέμε <i>«ὁ Σωκράτης, ὁ φιλόσοφος»</i>, και οι δύο λέξεις δηλώνουν το ίδιο πρόσωπο. Δεν προσθέτουμε ένα ποιοτικό γνώρισμα (όπως θα έκανε ένα επίθετο: <i>ὁ σοφός Σωκράτης</i>), αλλά <b>ταυτίζουμε</b> τη μία λέξη με την άλλη. Αυτό ακριβώς το ξεχωρίζει από τον επιθετικό προσδιορισμό: ο επιθετικός <i>χαρακτηρίζει</i> (ποιόν;), ενώ η παράθεση/επεξήγηση <i>ταυτίζει</i> (ποιος ακριβώς;).</p><p>Η μόνη διαφορά μεταξύ παράθεσης και επεξήγησης βρίσκεται στη <b>σχέση εύρους εννοιών</b> ανάμεσα στις δύο λέξεις — δηλαδή στο ποια λέξη είναι γενικότερη και ποια ειδικότερη. Αυτό το κριτήριο αναπτύσσεται στις επόμενες ενότητες.</p>","examples":[{"gr":"Ὁ Σωκράτης, ὁ φιλόσοφος, ἐδίδασκεν.","an":"Ὁ Σωκράτης = υποκείμενο· ὁ φιλόσοφος = ομοιόπτωτος προσδιορισμός (ονομαστική, αρσενικό, ενικός — όπως το Σωκράτης). Και οι δύο λέξεις αναφέρονται στο ίδιο πρόσωπο."},{"gr":"Εἶδον τόν Σωκράτη, τόν φιλόσοφον.","an":"Παρατήρησε ότι ο προσδιορισμός ακολουθεί την πτώση του προσδιοριζομένου: αιτιατική τόν Σωκράτη → αιτιατική τόν φιλόσοφον. Γι' αυτό λέγεται «ομοιόπτωτος»."},{"gr":"Κόλακι, δεινῷ θηρίῳ καί βλάβῃ μεγάλῃ.","an":"Πλάτ. Φαῖδρος 240b — δεινῷ θηρίῳ καί βλάβῃ μεγάλῃ = ομοιόπτωτος προσδιορισμός (παράθεση) στο κόλακι: όλα σε δοτική, όπως το προσδιοριζόμενο. Δείχνει την ομοιοπτωσία και στη δοτική."},{"gr":"Ἀθηναῖος ὤν, πόλεως τῆς μεγίστης.","an":"Πλάτ. Ἀπολ. 29d — εδώ φαίνεται η αρχή της συμφωνίας πτώσης· το προσδιοριστικό σύνολο ακολουθεί τη λέξη που προσδιορίζει. Παράδειγμα ομοιόπτωτης (και ετερόπτωτης) δομής σε κλασικό κείμενο."}],"table":{"title":"Οι τέσσερις ομοιόπτωτοι προσδιορισμοί","cols":["Προσδιορισμός","Εκφέρεται με","Λειτουργία","Παράδειγμα"],"rows":[["Επιθετικός","Επίθετο / μετοχή / αριθμητικό","Δηλώνει μόνιμη ιδιότητα — απαντά στο «ποιος;»","ὁ <b>σοφός</b> ἀνήρ"],["Κατηγορηματικός","Επίθετο (άναρθρο) δίπλα σε έναρθρο όνομα","Δηλώνει παροδική κατάσταση","ἀκούω τόν θόρυβον <b>πολύν</b>"],["Παράθεση","Ουσιαστικό","Παραθέτει γνωστό, γενικότερο γνώρισμα","ὁ Σωκράτης, ὁ <b>φιλόσοφος</b>"],["Επεξήγηση","Ουσιαστικό","Διασαφηνίζει γενική/αόριστη λέξη (ειδικότερο)","ὁ φιλόσοφος, ὁ <b>Σωκράτης</b>"]]},"note":"Προσοχή στη διάκριση από τον επιθετικό: αν ο προσδιορισμός είναι ΕΠΙΘΕΤΟ → επιθετικός ή κατηγορηματικός. Αν είναι ΟΥΣΙΑΣΤΙΚΟ που ταυτίζεται στην αναφορά με το προσδιοριζόμενο → παράθεση ή επεξήγηση."},{"h":"Η Παράθεση: ορισμός, λειτουργία, ανάλυση","body":"<p><b>Παράθεση</b> ονομάζεται το ουσιαστικό (ή ισοδύναμη λέξη) που τοποθετείται («παρατίθεται») δίπλα σε ένα άλλο ουσιαστικό, στην ίδια πτώση, για να του <b>αποδώσει μια γνωστή, βέβαιη ιδιότητα ή ένα ξεχωριστό γνώρισμα</b>. Το καθοριστικό είναι ότι η παράθεση εκφράζει έννοια <b>γενικότερη (ευρύτερη)</b> από το προσδιοριζόμενο όνομα.</p><p>Με άλλα λόγια, το προσδιοριζόμενο είναι μια <b>μερική / ειδική</b> έννοια (π.χ. ένα συγκεκριμένο πρόσωπο, ο Σωκράτης), και η παράθεση το εντάσσει σε μια <b>γενικότερη κατηγορία ή τάξη</b> (π.χ. στους φιλοσόφους, στους Αθηναίους, στους βασιλείς). Η παράθεση λειτουργεί σαν να λέει: <i>«αυτός, ο οποίος ανήκει στην ευρύτερη ομάδα Χ»</i>.</p><h3>Πώς αναλύεται η παράθεση</h3><p>Η παράθεση <b>αναλύεται σε δευτερεύουσα αναφορική πρόταση</b> (με το «ο οποίος / που είναι»). Αυτό είναι το ασφαλέστερο αποδεικτικό τεστ:</p><ul><li><i>Σόλων, ὁ Ἀθηναῖος</i> → «ο Σόλων, <b>ο οποίος ήταν</b> Αθηναίος».</li><li><i>Ἀλέξανδρος, ὁ βασιλεύς</i> → «ο Αλέξανδρος, <b>που ήταν</b> βασιλιάς».</li></ul><h3>Λέξεις που λειτουργούν ως παράθεση</h3><p>Ως παράθεση μπορεί να λειτουργεί όχι μόνο απλό ουσιαστικό, αλλά και: <b>αντωνυμία</b> (προσωπική ή δεικτική), ουσιαστικοποιημένο <b>επίθετο/μετοχή</b>, και ολόκληρη <b>περιγραφική φράση</b> (π.χ. <i>πόλιν Ἑλληνίδα ἐπί θαλάττῃ</i>).</p>","examples":[{"gr":"Ὁ Σωκράτης, ὁ γλύπτης, καθεύδει.","an":"ὁ γλύπτης = παράθεση στο ὁ Σωκράτης. Η ιδιότητα «γλύπτης» είναι γενικότερη (πολλοί είναι γλύπτες) από το συγκεκριμένο πρόσωπο «Σωκράτης». Ανάλυση: «ο Σωκράτης, ο οποίος είναι γλύπτης»."},{"gr":"Ἀλέξανδρος, ὁ βασιλεύς, ἐπολιόρκει τήν Τῦρον, τήν πόλιν.","an":"Δύο παραθέσεις: ὁ βασιλεύς (γενικότερο του Ἀλέξανδρος) και τήν πόλιν (γενικότερο του Τῦρον, αφού πολλές είναι πόλεις). Πρόσεξε την ταύτιση πτώσης: ονομ.+ονομ., αιτ.+αιτ."},{"gr":"Σόλων, ὁ Ἀθηναῖος, ἐνομοθέτησεν.","an":"ὁ Ἀθηναῖος = παράθεση. Ο «Αθηναίος» είναι γενική έννοια (όλοι οι πολίτες των Αθηνών), ο «Σόλων» ειδική. Ανάλυση: «ο Σόλων, ο οποίος ήταν Αθηναίος»."},{"gr":"Ἀφικνοῦνται εἰς Κερασοῦντα, πόλιν Ἑλληνίδα ἐπί θαλάττῃ.","an":"Ξεν. Ἀνάβ. 5.3.2 — πόλιν Ἑλληνίδα ἐπί θαλάττῃ = εκτεταμένη (περιγραφική) παράθεση στο Κερασοῦντα: μια ολόκληρη φράση που εντάσσει το ειδικό όνομα «Κερασοῦς» στη γενική κατηγορία «ελληνική παραθαλάσσια πόλη»."},{"gr":"Ταλθύβιος ἥκω, Δαναϊδῶν ὑπηρέτης.","an":"Εὐρ. Ἑκάβη 503 — ὑπηρέτης = παράθεση στο εννοούμενο «ἐγώ» (το α' πρόσωπο του ἥκω): «εγώ, ο Ταλθύβιος, ήρθα, ο υπηρέτης των Δαναϊδῶν». Η παράθεση συμφωνεί με το πρόσωπο που εμπεριέχεται στο ρήμα."},{"gr":"Ἐγώ, Θεμιστοκλῆς, ἥκω παρά σέ.","an":"Θουκ. 1.137 (τύπου) — Θεμιστοκλῆς = παράθεση σε ονομαστική στο α' πρόσωπο που εμπεριέχεται στο ρήμα ἥκω. Η παράθεση εντάσσει το «εγώ» στο συγκεκριμένο, γνωστό όνομα."}],"note":"Ένδειξη παράθεσης: η προσδιοριστική λέξη ονομάζει μια ΤΑΞΗ ή ΚΑΤΗΓΟΡΙΑ (φιλόσοφος, βασιλεύς, πόλις, ποταμός, νῆσος, Ἀθηναῖος) στην οποία ανήκει το ειδικό προσδιοριζόμενο (κύριο όνομα). Συχνά: ΚΥΡΙΟ ΟΝΟΜΑ + κοινό ουσιαστικό-κατηγορία = παράθεση."},{"h":"Η Επεξήγηση: ορισμός, λειτουργία, το τεστ «δηλαδή»","body":"<p><b>Επεξήγηση</b> ονομάζεται το ουσιαστικό (ή ισοδύναμη λέξη) που τοποθετείται δίπλα σε άλλο ουσιαστικό, στην ίδια πτώση, για να <b>διασαφηνίσει, να εξειδικεύσει και να κάνει συγκεκριμένη</b> τη γενική, αόριστη ή ασαφή σημασία του. Εδώ η σχέση είναι <b>αντίστροφη</b> από την παράθεση: η επεξήγηση εκφράζει έννοια <b>ειδικότερη (στενότερη)</b> από το προσδιοριζόμενο όνομα.</p><p>Δηλαδή το προσδιοριζόμενο είναι <b>γενικό/αόριστο</b> (π.χ. «ο φιλόσοφος», «ο ναύαρχος», «αυτό», «τοῦτο»), και η επεξήγηση το <b>καθορίζει</b> δίνοντας το συγκεκριμένο πρόσωπο ή πράγμα (π.χ. «ο Σωκράτης», «ο Λύσανδρος»). Πρόκειται για κίνηση <i>από το γενικό προς το ειδικό</i>.</p><h3>Το αποφασιστικό τεστ: «δηλαδή»</h3><p>Το πιο πρακτικό και αλάνθαστο κριτήριο: η επεξήγηση <b>μεταφράζεται/συμπληρώνεται με τη λέξη «δηλαδή»</b> πριν από αυτήν. Αν μπορεί να μπει το «δηλαδή», πρόκειται για επεξήγηση· αν όχι (αλλά ταιριάζει το «ο οποίος είναι»), πρόκειται για παράθεση.</p><ul><li><i>Ὁ ναύαρχος, ὁ Λύσανδρος</i> → «ο ναύαρχος, <b>δηλαδή</b> ο Λύσανδρος». ✓ Επεξήγηση.</li><li><i>Ὁ Σωκράτης, ὁ φιλόσοφος</i> → «ο Σωκράτης, <b>ο οποίος είναι</b> φιλόσοφος» (όχι «δηλαδή»). ✓ Παράθεση.</li></ul><p>Η επεξήγηση είναι ιδιαίτερα συχνή όταν το προσδιοριζόμενο είναι <b>δεικτική ή αόριστη αντωνυμία</b> ουδετέρου (τοῦτο, ἐκεῖνο, ἕν), η οποία είναι εξ ορισμού «κενή» σημασιολογικά και ζητάει εξειδίκευση.</p>","examples":[{"gr":"Ὁ γλύπτης, ὁ Σωκράτης, καθεύδει.","an":"Αντιστροφή του προηγούμενου παραδείγματος. Τώρα προσδιοριζόμενο είναι το γενικό «ὁ γλύπτης» και επεξήγηση το ειδικό «ὁ Σωκράτης». Τεστ: «ο γλύπτης, δηλαδή ο Σωκράτης». ✓"},{"gr":"Ὁ ναύαρχος, ὁ Λύσανδρος, ἐνίκησεν.","an":"ὁ Λύσανδρος = επεξήγηση. Το «ναύαρχος» είναι γενικός τίτλος, το «Λύσανδρος» το συγκεκριμένο πρόσωπο. «ο ναύαρχος, δηλαδή ο Λύσανδρος»."},{"gr":"Περικλῆς ἐγένετο μαθητής τούτου, Ἀναξαγόρου.","an":"τούτου = γενική δεικτικής αντωνυμίας (αόριστη), Ἀναξαγόρου = επεξήγηση στην ίδια πτώση (γενική). «μαθητής αυτού, δηλαδή του Αναξαγόρα». Κλασικό μοτίβο: δεικτική αντωνυμία + ονοματική επεξήγηση."},{"gr":"Ὁ βασιλεύς, ὁ Ἀλέξανδρος, ἐπολιόρκει τήν πόλιν, τήν Τῦρον.","an":"Δύο επεξηγήσεις: ὁ Ἀλέξανδρος εξειδικεύει το γενικό «βασιλεύς», τήν Τῦρον εξειδικεύει το γενικό «πόλιν». «τον βασιλιά, δηλαδή τον Αλέξανδρο… την πόλη, δηλαδή την Τύρο»."},{"gr":"Δύο γάρ, ὦ ἄνδρες, ἐστόν, ἡ μέν εἰς μακάρων νήσους, ἡ δ' εἰς τάρταρον.","an":"Πλάτ. Γοργ. 524a (τύπου, για τίς ὁδούς) — ἡ μέν… ἡ δέ = επεξηγηματικός/επιμεριστικός προσδιορισμός που εξειδικεύει την αόριστη ποσοτική έννοια «δύο»: «δύο, δηλαδή η μία… η άλλη…»."},{"gr":"Ἕν τοῦτο μόνον αἰτοῦμαι, τήν εἰρήνην.","an":"τήν εἰρήνην = επεξήγηση στο αόριστο/δεικτικό «ἕν τοῦτο». «ένα τούτο μόνο ζητώ, δηλαδή την ειρήνη.» Τυπική επεξήγηση ύστερα από κενή σημασιολογικά δεικτική/αριθμητική λέξη."}],"note":"Μνημονικός κανόνας: ΕΠΕΞήγηση → ΕΠΕΞεργάζεται/εΞΕιδικεύει· δέχεται το «ΔΗΛΑΔΗ». ΠΑΡΑθεση → ΠΑΡΑθέτει γενική ιδιότητα· αναλύεται σε «Ο ΟΠΟΙΟΣ ΕΙΝΑΙ»."},{"h":"Το κρίνσιμο κριτήριο: γενικότερο ↔ ειδικότερο (πώς ξεχωρίζω τις δύο)","body":"<p>Η ίδια ακριβώς δομή —δύο ομοιόπτωτα ουσιαστικά δίπλα-δίπλα— μπορεί να είναι <b>παράθεση ή επεξήγηση ανάλογα με το ΠΟΙΟ ΕΙΝΑΙ ΤΟ ΠΡΟΣΔΙΟΡΙΖΟΜΕΝΟ</b>. Δεν αποφασίζει η σειρά αυτή καθεαυτή, αλλά η σχέση εύρους εννοιών ανάμεσα στο προσδιοριζόμενο (κύρια λέξη) και στον προσδιορισμό. Συγκρίνουμε πάντοτε <b>τον προσδιορισμό με το προσδιοριζόμενο</b>:</p><ul><li>Αν ο <b>προσδιορισμός είναι ΓΕΝΙΚΟΤΕΡΟΣ</b> από το προσδιοριζόμενο → <b>ΠΑΡΑΘΕΣΗ</b>. (Το ειδικό εντάσσεται σε ευρύτερη τάξη.)</li><li>Αν ο <b>προσδιορισμός είναι ΕΙΔΙΚΟΤΕΡΟΣ</b> από το προσδιοριζόμενο → <b>ΕΠΕΞΗΓΗΣΗ</b>. (Το γενικό/αόριστο εξειδικεύεται.)</li></ul><h3>Τρία εργαλεία ελέγχου που πρέπει να συμφωνούν</h3><ol><li><b>Τεστ ευρύτητας</b>: ποιο όνομα δηλώνει «τους πολλούς» (γενικό) και ποιο «τον έναν/συγκεκριμένο» (ειδικό); Ο προσδιορισμός που είναι ο «ένας» → επεξήγηση· ο προσδιορισμός που είναι «οι πολλοί» → παράθεση.</li><li><b>Τεστ «ο οποίος είναι»</b>: αν η ανάλυση σε αναφορική πρόταση βγάζει νόημα → παράθεση.</li><li><b>Τεστ «δηλαδή»</b>: αν χωράει το «δηλαδή» → επεξήγηση.</li></ol><p>Σχεδόν πάντοτε, όταν δίπλα-δίπλα βρίσκονται ένα <b>κύριο όνομα</b> (Σωκράτης, Λύσανδρος, Τῦρος) και ένα <b>κοινό ουσιαστικό-κατηγορία</b> (φιλόσοφος, ναύαρχος, πόλις): το κύριο όνομα είναι το ειδικό και το κοινό ουσιαστικό το γενικό. Άρα: <i>κύριο όνομα ως προσδιοριζόμενο + κοινό ουσιαστικό ως προσδιορισμός = παράθεση</i>· <i>κοινό ουσιαστικό ως προσδιοριζόμενο + κύριο όνομα ως προσδιορισμός = επεξήγηση</i>.</p>","examples":[{"gr":"Ὁ Σωκράτης (ειδικό), ὁ φιλόσοφος (γενικό).","an":"Προσδιορισμός φιλόσοφος = γενικότερος → ΠΑΡΑΘΕΣΗ. «ο Σωκράτης, ο οποίος είναι φιλόσοφος.»"},{"gr":"Ὁ φιλόσοφος (γενικό), ὁ Σωκράτης (ειδικό).","an":"Προσδιορισμός Σωκράτης = ειδικότερος → ΕΠΕΞΗΓΗΣΗ. «ο φιλόσοφος, δηλαδή ο Σωκράτης.»"},{"gr":"Τοῦτο (γενικό/αόριστο), ἡ ἐλευθερία (ειδικό), ἀγαθόν ἐστιν.","an":"Δεικτική αντωνυμία τοῦτο = κενή/γενική· ἡ ἐλευθερία την εξειδικεύει → ΕΠΕΞΗΓΗΣΗ. «αυτό, δηλαδή η ελευθερία.» (Πολύ συνηθισμένο σχήμα: αντωνυμία + επεξήγηση.)"},{"gr":"Κῦρος, ὁ τῶν Περσῶν βασιλεύς, ἤθροιζε στράτευμα.","an":"ὁ τῶν Περσῶν βασιλεύς = ΠΑΡΑΘΕΣΗ (γενικότερη έννοια: ένας από τους βασιλείς) στο ειδικό κύριο όνομα Κῦρος. Τεστ «ο οποίος είναι»: «ο Κύρος, ο οποίος ήταν βασιλιάς των Περσών.»"},{"gr":"Ὁ ποταμός, ὁ Εὐφράτης, βαθύς ἐστιν.","an":"Προσδιοριζόμενο = γενικό «ὁ ποταμός», προσδιορισμός = ειδικό κύριο όνομα «ὁ Εὐφράτης» → ΕΠΕΞΗΓΗΣΗ. «ο ποταμός, δηλαδή ο Ευφράτης.»"}],"table":{"title":"Παράθεση vs Επεξήγηση — συγκριτικός πίνακας","cols":["Στοιχείο","Παράθεση","Επεξήγηση"],"rows":[["Έννοια προσδιορισμού","Γενικότερη (ευρύτερη)","Ειδικότερη (στενότερη)"],["Έννοια προσδιοριζομένου","Ειδική / μερική","Γενική / αόριστη"],["Κίνηση σημασίας","Ειδικό → εντάσσεται σε γενικό","Γενικό → εξειδικεύεται"],["Τεστ ανάλυσης","«ο οποίος είναι…»","«δηλαδή…»"],["Τυπική μορφή","Κύριο όνομα + κοινό ουσιαστικό","Κοινό ουσιαστικό / αντωνυμία + κύριο όνομα"],["Παράδειγμα","Σωκράτης, ὁ φιλόσοφος","ὁ φιλόσοφος, Σωκράτης"]]},"note":"ΠΑΓΙΔΑ: Μην κρίνεις μηχανικά από τη σειρά. Κρίνε από το ΕΥΡΟΣ ΤΗΣ ΕΝΝΟΙΑΣ. Στην πράξη η σειρά συνήθως συμβαδίζει με το εύρος, αλλά το αποφασιστικό είναι ποια λέξη είναι το προσδιοριζόμενο και ποια εκφράζει γενικότερη/ειδικότερη έννοια."},{"h":"Ειδικές κατηγορίες παράθεσης & επεξήγησης (προχωρημένη ύλη)","body":"<p>Πέρα από την απλή μορφή, η αρχαία ελληνική (και η γραμματική του Smyth/της Πύλης) διακρίνει ορισμένες ιδιαίτερες κατηγορίες, χρήσιμες για ασκήσεις ανώτερου επιπέδου.</p><h3>Α. Προεξαγγελτική παράθεση</h3><p>Πρόκειται για ουσιαστικό (συνήθως ουδέτερο επίθετο ως ουσιαστικό: <i>τό μέγιστον, τό δεινότατον, τό θαυμαστόν, τό κεφάλαιον</i>) που τοποθετείται στην <b>αρχή</b> και <b>προαναγγέλλει/χαρακτηρίζει ολόκληρη την πρόταση</b> που ακολουθεί. Αναφέρεται όχι σε μία λέξη αλλά σε όλο το νόημα.</p><h3>Β. Επιμεριστική παράθεση</h3><p>Όταν μια γενική/συλλογική έννοια (π.χ. «οι στρατιώτες») <b>διαιρείται σε επιμέρους ομάδες</b> με τα <i>ὁ μέν … ὁ δέ</i>, <i>οἱ μέν … οἱ δέ</i>. Κάθε σκέλος είναι παράθεση που επιμερίζει το σύνολο.</p><h3>Γ. Γενική παραθετική (αὑτῶν)</h3><p>Η γενική της αντωνυμίας <i>αὑτῶν / ἑαυτῶν</i> δίπλα σε κτητική αντωνυμία ή για έμφαση: <i>τά σφέτερα αὐτῶν</i> = «τα δικά τους (πράγματα)».</p><h3>Δ. Επεξήγηση με απαρέμφατο ή πρόταση</h3><p>Όταν το προσδιοριζόμενο είναι <b>ουδέτερη δεικτική αντωνυμία</b> ή ουδέτερο όνομα/επίρρημα (τοῦτο, ἐκεῖνο, ὧδε, οὕτω), η επεξήγηση μπορεί να μην είναι ουσιαστικό αλλά:</p><ul><li><b>Απαρέμφατο</b> (έναρθρο ή τελικό): <i>ἐπί τό κρίνειν</i> επεξηγεί το <i>ἐπί τούτῳ</i>.</li><li><b>Ειδική / πλάγια πρόταση</b> (με ὅτι, ὡς): <i>τοῦτο… ὅτι…</i> «αυτό, δηλαδή ότι…».</li></ul><p>Αυτές οι περιπτώσεις δείχνουν ότι η σχέση παράθεσης/επεξήγησης δεν περιορίζεται σε δύο ουσιαστικά, αλλά είναι μια <b>γενική σχέση συναναφοράς/διασάφησης</b> που μπορεί να συνδέει και προτάσεις.</p>","examples":[{"gr":"Τό δέ μέγιστον, οὐδείς ἀντεῖπεν.","an":"τό μέγιστον = προεξαγγελτική παράθεση: δεν προσδιορίζει μία λέξη, αλλά προαναγγέλλει όλο το «οὐδείς ἀντεῖπεν». Απόδοση: «και το σπουδαιότερο: κανείς δεν αντιμίλησε.»"},{"gr":"Οἱ στρατιῶται, οἱ μέν ἐμάχοντο, οἱ δέ ἔφευγον.","an":"οἱ μέν … οἱ δέ = επιμεριστική παράθεση στο συλλογικό «οἱ στρατιῶται». Επιμερίζει το σύνολο σε δύο ομάδες."},{"gr":"Ἐβουλεύοντο περί τῶν σφετέρων αὐτῶν.","an":"αὐτῶν = γενική παραθετική, ενισχύει την κτητική σφετέρων: «για τα δικά τους (συμφέροντα)»."},{"gr":"Τοῦτο σκόπει, ὅτι οὐ ῥᾴδιόν ἐστιν.","an":"ὅτι οὐ ῥᾴδιόν ἐστιν = επεξηγηματική (ειδική) πρόταση που επεξηγεί το ουδέτερο τοῦτο. «αυτό σκέψου, δηλαδή ότι δεν είναι εύκολο.»"},{"gr":"Οὗτοι μέν, ὦ Κλέαρχε, ἄλλος ἄλλα λέγει.","an":"Ξεν. Ἀνάβ. 2.1.15 — ἄλλος ἄλλα = επιμεριστική (διανεμητική) παράθεση στο συλλογικό «οὗτοι»: «αυτοί, ο καθένας λέει κι άλλα.» Κλασικό σχῆμα καθ' ὅλον καί μέρος."},{"gr":"Τό δέ δεινότατον πάντων, εἰς τοῦτο προήχθημεν.","an":"τό δεινότατον πάντων = προεξαγγελτική παράθεση που χαρακτηρίζει εκ των προτέρων ολόκληρη την επόμενη φράση. «και το πιο φοβερό απ' όλα: φτάσαμε ως εκεί.»"}],"note":"Στις προχωρημένες περιπτώσεις, αν δεις ουδέτερη δεικτική αντωνυμία (τοῦτο, ἐκεῖνο, ταῦτα) ή τα επιρρήματα ὧδε/οὕτω και έπειτα απαρέμφατο ή ότι-/ως-πρόταση → πιθανότατα επεξήγηση με «δηλαδή»."},{"h":"Στίξη, σειρά λέξεων & συχνά λάθη","body":"<p>Η <b>στίξη</b> είναι το ορατό σημάδι της παράθεσης και της επεξήγησης. Επειδή πρόκειται για χαλαρά προσαρτημένο (μη περιοριστικό) προσδιορισμό, χωρίζεται <b>πάντοτε με κόμμα(τα)</b> από το προσδιοριζόμενο:</p><ul><li><b>Ένα κόμμα</b> πριν, αν ο προσδιορισμός βρίσκεται στο τέλος: <i>ἐνίκησεν ὁ ναύαρχος, ὁ Λύσανδρος.</i></li><li><b>Δύο κόμματα</b> (εγκλεισμός), αν παρεμβάλλεται μέσα στην πρόταση: <i>ὁ Σωκράτης, ὁ φιλόσοφος, ἐδίδασκεν.</i></li><li>Στη νέα ελληνική απόδοση η επεξήγηση μπορεί να εισάγεται και με <b>άνω και κάτω τελεία ( : )</b> ή με <b>παύλα ( — )</b>, ιδίως όταν είναι εκτεταμένη: «ζητούσε ένα πράγμα: την ελευθερία».</li></ul><h3>Γιατί η στίξη έχει σημασία</h3><p>Το κόμμα δείχνει ότι ο προσδιορισμός <b>δεν είναι περιοριστικός</b> (όπως ο επιθετικός), αλλά <b>επεξηγηματικός/παραθετικός</b> — απλώς ταυτίζει ή διασαφηνίζει, χωρίς να αλλάζει την έκταση της αναφοράς. Η απουσία κόμματος συχνά υποδηλώνει επιθετικό προσδιορισμό ή κατηγορούμενο, οπότε η ανάλυση αλλάζει.</p><h3>Συχνά λάθη & τρόποι αποφυγής</h3><ul><li><b>Σύγχυση με κατηγορούμενο</b>: στο <i>ὁ Σωκράτης ἐστί φιλόσοφος</i> το «φιλόσοφος» είναι <b>κατηγορούμενο</b> (μέσω του ρ. εἰμί, χωρίς άρθρο, χωρίς κόμμα), όχι παράθεση. Παράθεση = δίπλα στο όνομα, με κόμμα, χωρίς συνδετικό ρήμα.</li><li><b>Σύγχυση με επιθετικό</b>: αν ο προσδιορισμός είναι επίθετο και ενσωματώνεται χωρίς κόμμα (ὁ σοφός ἀνήρ) → επιθετικός, όχι παράθεση.</li><li><b>Λανθασμένη κρίση από τη σειρά</b>: όπως τονίστηκε, κρίνε από το εύρος της έννοιας, όχι μόνο από το ποιο όνομα προηγείται.</li><li><b>Παράλειψη ελέγχου ομοιοπτωσίας</b>: επιβεβαίωσε ότι προσδιορισμός και προσδιοριζόμενο είναι στην ίδια πτώση — αν είναι σε διαφορετική πτώση, πρόκειται για ετερόπτωτο προσδιορισμό, όχι παράθεση/επεξήγηση.</li></ul>","examples":[{"gr":"Ὦ Σώκρατες, ὦ φίλε, ἄκουσον.","an":"ὦ φίλε = παράθεση σε κλητική (ομοιοπτωσία και στην κλητική!). Χωρίζεται με κόμμα. Δείχνει ότι η ομοιόπτωση ισχύει σε ΟΛΕΣ τις πτώσεις."},{"gr":"Ὁ Σωκράτης ἐστί φιλόσοφος.","an":"ΟΧΙ παράθεση. Εδώ «φιλόσοφος» = κατηγορούμενο μέσω του ἐστί (άναρθρο, χωρίς κόμμα). Σύγκρινε με την παράθεση: «ὁ Σωκράτης, ὁ φιλόσοφος, …»."},{"gr":"Ἕν μόνον ἐπόθει, τήν νίκην.","an":"τήν νίκην = επεξήγηση στο αόριστο ἕν (ένα μόνο πράγμα). Ένα κόμμα, γιατί ο προσδιορισμός είναι στο τέλος. Τεστ: «ένα μόνο, δηλαδή τη νίκη.»"},{"gr":"Τόν ἐμόν, τοῦ ταλαιπώρου, βίον.","an":"Ἀριστοφ. Πλοῦτος 33 (τύπου) — τοῦ ταλαιπώρου = παράθεση/επεξήγηση σε γενική, ομοιόπτωτη με την κτητική ἐμόν: «τη ζωή τη δική μου, του ταλαίπωρου.» Χωρίζεται με κόμματα (εγκλεισμός)."},{"gr":"Ἀκούω τόν θόρυβον πολύν.","an":"ΟΧΙ παράθεση. πολύν = κατηγορηματικός προσδιορισμός (άναρθρο επίθετο δίπλα σε έναρθρο όνομα, χωρίς κόμμα): «ακούω τον θόρυβο πολύ / να είναι πολύς.» Αντίθεση προς την παράθεση που είναι ουσιαστικό με κόμμα."}],"note":"Χρυσός κανόνας ανάλυσης: (1) Είναι ουσιαστικό; (2) Ίδια πτώση με το προσδιοριζόμενο; (3) Χωρίζεται με κόμμα και αναφέρεται στο ίδιο πρόσωπο/πράγμα; → τότε παράθεση ή επεξήγηση. Διάλεξε με τα τεστ «ο οποίος είναι» (παράθεση) / «δηλαδή» (επεξήγηση)."}]);
  T("syn-eteroptwtoi-genikis", [{"h":"Τι είναι οι ετερόπτωτοι προσδιορισμοί — και η θέση της γενικής","body":"<p>Στο αρχαιοελληνικό συντακτικό κάθε ουσιαστικό (ή λέξη που έχει θέση ουσιαστικού) μπορεί να συνοδεύεται από <b>προσδιορισμούς</b>, δηλαδή λέξεις που το ορίζουν στενότερα, το χαρακτηρίζουν ή το συμπληρώνουν. Οι <b>ονοματικοί</b> προσδιορισμοί (ουσιαστικά, επίθετα, αντωνυμίες, μετοχές, αριθμητικά) χωρίζονται σε δύο μεγάλες κατηγορίες ανάλογα με την πτώση τους σε σχέση με τον προσδιοριζόμενο όρο.</p><p><b>Ομοιόπτωτοι</b> ονομάζονται οι προσδιορισμοί που βρίσκονται στην <i>ίδια πτώση</i> με τη λέξη που προσδιορίζουν (παράθεση, επεξήγηση, επιθετικός/κατηγορηματικός προσδιορισμός). <b>Ετερόπτωτοι</b> ονομάζονται οι ονοματικοί προσδιορισμοί που βρίσκονται σε <i>διαφορετική (πλάγια) πτώση</i> από τη λέξη που προσδιορίζουν. Επειδή σε αρχαία πλάγιες πτώσεις είναι η γενική, η δοτική και η αιτιατική, οι ετερόπτωτοι προσδιορισμοί εκφέρονται σε <b>γενική, δοτική ή αιτιατική</b>.</p><p>Από τις τρεις, η <b>γενική</b> είναι ασυγκρίτως η πιο πλούσια και πολυλειτουργική: αυτό οφείλεται στο ότι η αρχαία ελληνική γενική έχει συγχωνεύσει δύο παλαιότερες ινδοευρωπαϊκές πτώσεις — τη <i>γνήσια γενική</i> (που δηλώνει σχέση, προέλευση, μέρος-όλο) και την <i>αφαιρετική</i> (που δηλώνει χωρισμό, αφετηρία, σύγκριση). Έτσι η γενική ως ετερόπτωτος προσδιορισμός εκφράζει ένα ευρύτατο φάσμα σχέσεων ανάμεσα σε δύο ονόματα.</p><p><b>Βασική μέθοδος αναγνώρισης:</b> εντοπίζω το ουσιαστικό-πυρήνα, βρίσκω τη γενική που το συνοδεύει, ελέγχω αν βρίσκεται σε <i>διαφορετική</i> πτώση (αν είναι ίδια πτώση, π.χ. «ὁ ποταμός ὁ Νεῖλος», είναι ομοιόπτωτος, όχι ετερόπτωτος) και τέλος καθορίζω <i>ποια σημασιολογική σχέση</i> εκφράζει, ώστε να κατατάξω το είδος της γενικής.</p>","examples":[{"gr":"ἡ τῶν Ἀθηναίων πόλις","an":"η πόλη των Αθηναίων — «τῶν Ἀθηναίων»: γενική (πλάγια πτώση) προσδιορίζει το «πόλις» (ονομαστική) → ετερόπτωτος προσδιορισμός, γενική κτητική."},{"gr":"ὁ ποταμός ὁ Νεῖλος","an":"ο ποταμός ο Νείλος — εδώ «Νεῖλος» είναι στην ίδια πτώση (ονομαστική) με το «ποταμός» → ομοιόπτωτος (παράθεση), ΟΧΙ ετερόπτωτος. Αντιπαράδειγμα προς αποφυγή σύγχυσης."},{"gr":"διδάσκαλος τῶν παίδων","an":"δάσκαλος των παιδιών — «τῶν παίδων» γενική προσδιορίζει το «διδάσκαλος» → ετερόπτωτος, γενική αντικειμενική (διδάσκει τα παιδιά)."},{"gr":"ἡ τῆς ψυχῆς ἀρετή","an":"η αρετή της ψυχής — «τῆς ψυχῆς»: γενική σε διαφορετική (πλάγια) πτώση από τον πυρήνα «ἀρετή» → ετερόπτωτος προσδιορισμός (κτητική/αναφοράς). Πβ. Πλάτ. Πολιτεία."},{"gr":"αἱ τῶν πολεμίων νῆες","an":"τα πλοία των εχθρών — «τῶν πολεμίων»: ετερόπτωτος προσδιορισμός σε γενική (κτητική) που προσδιορίζει το «νῆες» (τύπου Θουκυδίδη)."}],"table":{"title":"Συνοπτικός χάρτης της γενικής ως ετερόπτωτου προσδιορισμού","cols":["Είδος γενικής","Τι δηλώνει","Παράδειγμα"],"rows":[["Κτητική / συγγένειας / καταγωγής","κτήτορα, γονέα, καταγωγή","ἡ οἰκία τοῦ πατρός"],["Δημιουργού","τον δημιουργό έργου","τά τοῦ Φειδίου ἔργα"],["Διαιρετική (του όλου)","το όλον, του οποίου μέρος είναι ο πυρήνας","οἱ ἄριστοι τῶν πολιτῶν"],["Ύλης","το υλικό κατασκευής","κρηπίς λίθων"],["Περιεχομένου","το περιεχόμενο","κρήνη ὕδατος"],["Ιδιότητας","ηλικία, μέγεθος, διάσταση, διάρκεια","ὁδός πέντε ἡμερῶν"],["Αξίας / τιμήματος","υλική ή ηθική αξία","χωρίον δέκα μνῶν"],["Αιτίας","την αιτία (συχνά δικανική/ψυχικά πάθη)","γραφή κλοπῆς"],["Υποκειμενική","το υποκείμενο της ρηματικής έννοιας","ὁ φόβος τῶν πολεμίων (οι εχθροί φοβούνται)"],["Αντικειμενική","το αντικείμενο της ρηματικής έννοιας","ὁ φόβος τῶν πολεμίων (φοβούμαστε τους εχθρούς)"],["Συγκριτική","τον β΄ όρο σύγκρισης / χωρισμό","κρείττων χρημάτων"]]},"note":"Προσοχή στη διάκριση ομοιόπτωτου / ετερόπτωτου: κριτήριο είναι η ΠΤΩΣΗ, όχι η θέση. «ὁ ἀδελφός ὁ ἐμός» (ομοιόπτωτος, ίδια πτώση) ≠ «ὁ ἀδελφός ἐμοῦ/μου» (ετερόπτωτος, γενική κτητική)."},{"h":"Γενική κτητική, συγγένειας και καταγωγής — και η γενική του δημιουργού","body":"<p>Η <b>γενική κτητική</b> είναι η πιο συνηθισμένη χρήση: δηλώνει τον <b>κτήτορα</b>, αυτόν δηλαδή στον οποίον ανήκει ή στον οποίον αναφέρεται το προσδιοριζόμενο όνομα. Η σχέση μεταφράζεται κατά κανόνα με τη νεοελληνική γενική («του/της…») ή με την κτητική αντωνυμία («μου, σου, μας…»). Όταν ο κτήτορας είναι προσωπική αντωνυμία, χρησιμοποιείται η <i>γενική των προσωπικών αντωνυμιών</i> (μου, σου, ἡμῶν, ὑμῶν).</p><h3>Συγγένειας και καταγωγής</h3><p>Στενή υποκατηγορία της κτητικής είναι η γενική που δηλώνει <b>συγγενική σχέση</b> ή <b>καταγωγή</b>. Πολύ χαρακτηριστικά εμφανίζεται στα ελληνικά πατρωνύμια, όπου η λέξη «υἱός / παῖς / θυγάτηρ» συχνά παραλείπεται και εννοείται: <i>Θουκυδίδης ὁ Ὀλόρου</i> = ο Θουκυδίδης, ο γιος του Ολόρου.</p><h3>Σύνταξη με επίθετα</h3><p>Κτητική γενική (σχέσης) δέχονται και ορισμένα επίθετα που σημαίνουν <b>οικειότητα, κοινότητα, φιλία ή έχθρα</b>: <i>οἰκεῖος, συγγενής, κοινός, ἴδιος, φίλος, ἐχθρός, πολέμιος, ἱερός</i> κ.ά. (π.χ. <i>ἱερός τοῦ Ἀπόλλωνος</i> = αφιερωμένος στον Απόλλωνα).</p><h3>Γενική του δημιουργού</h3><p>Συγγενική προς την κτητική είναι η <b>γενική του δημιουργού (ή του ποιητικού αιτίου)</b>: δηλώνει το πρόσωπο που <i>δημιούργησε</i> ένα έργο τέχνης, λόγου ή πράξης. Εκφέρεται με γενική προσώπου που συνοδεύει όνομα έργου. Πολλοί συντακτικοί τη θεωρούν ειδικότερη περίπτωση της κτητικής, άλλοι την εντάσσουν στην υποκειμενική (αφού ο δημιουργός είναι το «υποκείμενο» της δημιουργίας)· στο σχολικό συντακτικό αναγνωρίζεται ως ξεχωριστό είδος.</p>","examples":[{"gr":"ἡ οἰκία τοῦ Σωκράτους","an":"το σπίτι του Σωκράτη — «τοῦ Σωκράτους»: γενική κτητική στο «οἰκία» (δηλώνει τον ιδιοκτήτη)."},{"gr":"ἡ πόλις ἡμῶν","an":"η πόλη μας — «ἡμῶν»: γενική προσωπικής αντωνυμίας, κτητική στο «πόλις»."},{"gr":"Περικλῆς ὁ Ξανθίππου","an":"ο Περικλής, ο γιος του Ξανθίππου — «τοῦ Ξανθίππου»: γενική καταγωγής/συγγένειας· εννοείται το «υἱός»."},{"gr":"τά τοῦ Φειδίου ἔργα","an":"τα έργα του Φειδία — «τοῦ Φειδίου»: γενική του δημιουργού (ο Φειδίας τα δημιούργησε)."},{"gr":"αἱ Δημοσθένους δημηγορίαι","an":"οι δημηγορίες του Δημοσθένη — γενική του δημιουργού (ο Δημοσθένης τις συνέθεσε)."},{"gr":"χωρίον τῶν πολεμίων","an":"τόπος των εχθρών (που ανήκει στους εχθρούς) — γενική κτητική."},{"gr":"Θουκυδίδης ὁ Ὀλόρου","an":"Θουκ. — ο Θουκυδίδης, ο γιος του Ολόρου· «τοῦ Ὀλόρου» γενική καταγωγής/συγγένειας (εννοείται «υἱός»), όπως ο ίδιος ο ιστορικός αυτοπροσδιορίζεται."},{"gr":"τά τῶν θεῶν ἱερά","an":"οι ναοί/τα ιερά των θεών — «τῶν θεῶν» γενική κτητική (ανήκουν στους θεούς, αφιερωμένα σ' αυτούς) (τύπου Θουκυδίδη)."}],"note":"Η γενική κτητική μπορεί να μπει και κατηγορηματικά μετά από συνδετικό ρήμα: «τῶν νικώντων τό ἄρχειν ἐστί» = των νικητών είναι το να εξουσιάζουν (= γνώρισμα/ιδιότητα/καθήκον των νικητών). Αυτή λέγεται γενική κτητική κατηγορηματική και δηλώνει σε ποιον ανήκει ή ταιριάζει κάτι."},{"h":"Γενική διαιρετική (του όλου)","body":"<p>Η <b>γενική διαιρετική</b> ή <b>γενική του διαιρεμένου όλου</b> δηλώνει το <b>σύνολο (το όλον)</b>, από το οποίο ο προσδιοριζόμενος όρος αποτελεί ένα <b>μέρος</b>. Με άλλα λόγια, ο πυρήνας είναι το μέρος και η γενική είναι το όλον μέσα στο οποίο αυτό εντάσσεται. Μεταφράζεται με «από τους/τις/τα…» ή με απλή γενική του όλου.</p><h3>Πότε εμφανίζεται</h3><p>Η διαιρετική γενική συνοδεύει κατεξοχήν:</p><ul><li><b>Αριθμητικά και ποσοτικές λέξεις:</b> <i>εἷς, δύο, πολλοί, ὀλίγοι, ἕκαστος, οὐδείς, μυρίοι</i> (π.χ. <i>εἷς τῶν στρατηγῶν</i>).</li><li><b>Αόριστες και ερωτηματικές αντωνυμίες:</b> <i>τις, τινές, ἕκαστος, τίς; ποῖος;</i> (π.χ. <i>τινές τῶν πολιτῶν</i>).</li><li><b>Επίθετα υπερθετικού βαθμού:</b> <i>ἄριστος, κάλλιστος, μέγιστος</i> (π.χ. <i>ὁ ἄριστος τῶν Ἑλλήνων</i> = ο καλύτερος από τους Έλληνες).</li><li><b>Επιρρήματα τόπου ή ποσού:</b> <i>πανταχοῦ τῆς γῆς, εἰς τοῦτο ἀνοίας</i> (= σε τέτοιο σημείο ανοησίας).</li><li><b>Άρθρο/ουδέτερο που δηλώνει μέρος:</b> <i>τό ἥμισυ τοῦ στρατοῦ, τό πλεῖστον τῆς ἡμέρας</i>.</li></ul><h3>Ιδιαίτερες περιπτώσεις</h3><p>Η διαιρετική γενική εμφανίζεται και ως <b>γενική του χώρου/τόπου του όλου</b>: <i>τῆς Ἰταλίας</i> = σε ένα μέρος της Ιταλίας. Επίσης η <i>γενική του χρόνου μέσα στον οποίο</i> γίνεται κάτι έχει διαιρετική προέλευση (νύχτα = ένα μέρος του εικοσιτετραώρου), γι' αυτό πολλά συντακτικά τη συνδέουν με τη διαιρετική.</p>","examples":[{"gr":"οἱ πρεσβύτατοι τῶν στρατηγῶν","an":"οι γεροντότεροι από τους στρατηγούς — «τῶν στρατηγῶν»: γενική διαιρετική (το όλον), στο «οἱ πρεσβύτατοι» (το μέρος)."},{"gr":"εἷς τῶν ἑπτά σοφῶν","an":"ένας από τους επτά σοφούς — αριθμητικό «εἷς» + γενική διαιρετική."},{"gr":"τινές τῶν ῥητόρων","an":"κάποιοι από τους ρήτορες — αόριστη αντωνυμία + γενική διαιρετική."},{"gr":"τό ἥμισυ τοῦ στρατεύματος","an":"το μισό του στρατεύματος — ουδέτερο που δηλώνει μέρος + γενική διαιρετική."},{"gr":"εἰς τοῦτο θράσους ἀφίκετο","an":"έφτασε σε τέτοιο σημείο θράσους — «θράσους»: διαιρετική γενική σε δεικτική φράση ποσού/βαθμού."},{"gr":"οὐδείς ἀνθρώπων","an":"κανείς από τους ανθρώπους — «ἀνθρώπων»: γενική διαιρετική στο «οὐδείς»."},{"gr":"πολλοί τῶν στρατιωτῶν","an":"πολλοί από τους στρατιώτες — «τῶν στρατιωτῶν» γενική διαιρετική στο ποσοτικό «πολλοί» (τύπου Ξενοφώντος, Ἀνάβ.)."},{"gr":"ὁ σοφώτατος τῶν Ἑλλήνων","an":"ο σοφότατος από τους Έλληνες — «τῶν Ἑλλήνων» γενική διαιρετική στο υπερθετικό «σοφώτατος» (το όλον μέσα στο οποίο ξεχωρίζει ο πυρήνας)."}],"note":"Διάκριση από την κτητική: στη διαιρετική το όλον ΠΕΡΙΕΧΕΙ τον πυρήνα ως μέλος του («ένας από…»), ενώ στην κτητική το ένα ΑΝΗΚΕΙ στο άλλο ως ιδιοκτησία. Τεστ: αν χωράει το «από τους/τις/τα», είναι διαιρετική."},{"h":"Γενική της ύλης, του περιεχομένου και της ιδιότητας","body":"<p>Τρία στενά συνδεδεμένα είδη δηλώνουν <i>από τι, τι περιέχει ή τι χαρακτηριστικό έχει</i> ο πυρήνας.</p><h3>Γενική της ύλης</h3><p>Δηλώνει το <b>υλικό</b> από το οποίο είναι κατασκευασμένο ή αποτελείται το προσδιοριζόμενο όνομα. Μεταφράζεται «από / κατασκευασμένος από». Συχνά εναλλάσσεται με επίθετο ύλης (<i>χρυσοῦς, ἀργυροῦς, λίθινος</i>).</p><h3>Γενική του περιεχομένου</h3><p>Δηλώνει <b>τι περιέχει</b> ένα δοχείο, χώρος ή σύνολο. Ο πυρήνας είναι λέξη χωρητικότητας ή συνάθροισης (<i>κρήνη, ἀγέλη, σωρός, ὄχλος, ταμιεῖον</i>) και η γενική το περιεχόμενό της. Διαφέρει από την ύλη: το νερό της «κρήνης ὕδατος» δεν είναι το υλικό της κρήνης αλλά αυτό που περιέχει.</p><h3>Γενική της ιδιότητας</h3><p>Δηλώνει ένα <b>γνώρισμα</b> του πυρήνα: <b>ηλικία, μέγεθος, διάσταση, διάρκεια, βάρος, αριθμό</b>. Εκφέρεται με γενική που περιέχει συνήθως αριθμητικό ή ποσοτικό προσδιορισμό (<i>ὁδός πέντε ἡμερῶν, τεῖχος εἴκοσι ποδῶν</i>). Η νεοελληνική αποδίδει «μήκους/ύψους/ηλικίας…» ή με αριθμό + ουσιαστικό.</p><p>Στην ιδιότητα εντάσσονται ως ειδικότερες περιπτώσεις: η <i>γενική της ηλικίας</i> (<i>παῖς ἑπτά ἐτῶν</i>), η <i>γενική του μέτρου / της διάστασης</i> (<i>τεῖχος πλέθρου τό ὕψος</i>), η <i>γενική του βάρους</i> και η <i>γενική του χρονικού ή τοπικού διαστήματος / αποστάσεως</i> (<i>ἀπεῖχε σταδίων ἑπτά</i> = απείχε επτά στάδια).</p>","examples":[{"gr":"κρηπίς λίθων","an":"κρηπίδα από πέτρες — «λίθων»: γενική της ύλης (το υλικό της κρηπίδας)."},{"gr":"στέφανος χρυσοῦ","an":"στεφάνι από χρυσό — «χρυσοῦ»: γενική της ύλης· πβ. το ισοδύναμο επίθετο «στέφανος χρυσοῦς»."},{"gr":"κρήνη ὕδατος","an":"πηγή νερού — «ὕδατος»: γενική του περιεχομένου (τι περιέχει η πηγή)."},{"gr":"ἀγέλη βοῶν","an":"αγέλη βοδιών — «βοῶν»: γενική του περιεχομένου (από τι αποτελείται η αγέλη)."},{"gr":"ὁδός πέντε ἡμερῶν","an":"δρόμος πέντε ημερών — «πέντε ἡμερῶν»: γενική της ιδιότητας (δηλώνει τη διάρκεια/μέγεθος της διαδρομής)."},{"gr":"παῖς ἑπτά ἐτῶν","an":"παιδί επτά ετών — «ἑπτά ἐτῶν»: γενική της ιδιότητας (ηλικία)."},{"gr":"τεῖχος ὀκτώ σταδίων","an":"τείχος οκτώ σταδίων — «ὀκτώ σταδίων»: γενική της ιδιότητας (μέγεθος/έκταση)."},{"gr":"τάφρος ὀργυιῶν πέντε τό εὖρος","an":"τύπου Ξεν. Ἀνάβ. 1.7.14 — τάφρος πέντε οργιών στο πλάτος· «ὀργυιῶν πέντε» γενική της ιδιότητας (διάσταση/μέγεθος)."},{"gr":"ποτήριον ἀργύρου","an":"κύπελλο από ασήμι — «ἀργύρου» γενική της ύλης (πβ. το ισοδύναμο «ποτήριον ἀργυροῦν»)."}],"note":"Παγίδα: «κρήνη ὕδατος» = περιεχομένου (νερό μέσα στην πηγή), όχι ύλης· «ἀσπίς χαλκοῦ» = ύλης (η ασπίδα είναι ΦΤΙΑΓΜΕΝΗ από χαλκό). Κριτήριο: αν ο πυρήνας είναι δοχείο/σύνολο → περιεχομένου· αν δηλώνεται το συστατικό υλικό → ύλης."},{"h":"Γενική της αξίας (τιμήματος) και της αιτίας","body":"<h3>Γενική της αξίας ή του τιμήματος</h3><p>Δηλώνει την <b>αξία</b> — υλική (χρηματική) ή ηθική — του προσδιοριζομένου ή το <b>τίμημα</b> μιας συναλλαγής. Εκφέρεται με γενική που περιέχει συνήθως όνομα νομισματικής μονάδας ή ποσού (<i>μνᾶ, τάλαντον, δραχμή</i>). Μεταφράζεται «αξίας…» ή «αντί…».</p><p>Με την αξία συντάσσονται και επίθετα όπως <i>ἄξιος, ἀνάξιος, ἀντάξιος, τίμιος, ἄτιμος, ὤνιος</i> (π.χ. <i>ἄξιος τιμῆς</i> = άξιος τιμής), καθώς και ρήματα αξίας/αγοραπωλησίας (<i>ἀξιῶ, τιμῶμαι, ὠνοῦμαι, πωλῶ, πρίαμαι</i>), που όμως ανήκουν στη ρηματική σύνταξη.</p><h3>Γενική της αιτίας</h3><p>Δηλώνει την <b>αιτία</b> ή το <b>έγκλημα/κατηγορία</b> για το οποίο γίνεται κάτι. Εμφανίζεται κατεξοχήν:</p><ul><li>Με <b>ουσιαστικά και επίθετα δικανικής σημασίας:</b> <i>γραφή, δίκη, αἴτιος, ἀναίτιος, ἔνοχος, ὑπεύθυνος, ὑπόδικος</i> (π.χ. <i>γραφή κλοπῆς</i> = κατηγορία για κλοπή, <i>αἴτιος θανάτου</i>).</li><li>Με <b>ουσιαστικά που δηλώνουν ψυχικά πάθη / συναισθήματα:</b> <i>φόβος, λύπη, χαρά, ζῆλος, ἔρως, οἶκτος</i> (π.χ. <i>λύπη τῶν παρόντων κακῶν</i> = λύπη για τα παρόντα δεινά).</li></ul><p>Με τη γενική αιτίας συντάσσονται και ρήματα δικανικά (<i>γράφομαι, διώκω, φεύγω, κρίνω, ἁλίσκομαι, αἰτιῶμαι</i>) και ρήματα/επιφωνήματα ψυχικού πάθους (<i>θαυμάζω, ζηλῶ, οἰκτίρω, εὐδαιμονίζω, φεῦ τῶν κακῶν</i>) — στο πεδίο της ρηματικής σύνταξης.</p>","examples":[{"gr":"χωρίον δέκα μνῶν","an":"κτήμα αξίας δέκα μνών — «δέκα μνῶν»: γενική της αξίας."},{"gr":"οἶκος ὀκτώ ταλάντων","an":"σπίτι αξίας οκτώ ταλάντων — «ὀκτώ ταλάντων»: γενική της αξίας/τιμήματος."},{"gr":"ἄξιος πολλῶν ἐπαίνων","an":"άξιος πολλών επαίνων — «πολλῶν ἐπαίνων»: γενική (ηθικής) αξίας στο επίθετο «ἄξιος»."},{"gr":"γραφή κλοπῆς","an":"κατηγορία (γραπτή μήνυση) για κλοπή — «κλοπῆς»: γενική της αιτίας (το έγκλημα)."},{"gr":"αἴτιος τῆς συμφορᾶς","an":"υπαίτιος της συμφοράς — «τῆς συμφορᾶς»: γενική της αιτίας στο «αἴτιος»."},{"gr":"ὁ τῶν παρόντων κακῶν φόβος","an":"ο φόβος για τα παρόντα δεινά — «τῶν παρόντων κακῶν»: γενική της αιτίας (το συναίσθημα φόβος οφείλεται στα δεινά)."},{"gr":"δίκη φόνου","an":"δίκη για φόνο — «φόνου» γενική της αιτίας (το έγκλημα για το οποίο διεξάγεται η δίκη)· δικανικός όρος συχνός σε Λυσία/Δημοσθένη."},{"gr":"ἄξιος θανάτου","an":"άξιος θανάτου (που του αξίζει θάνατος) — «θανάτου» γενική της αξίας στο επίθετο «ἄξιος» (τύπου Πλάτ. Ἀπολ.)."}],"note":"Η ίδια φράση «ὁ φόβος τῶν πολεμίων» μπορεί να είναι γενική αιτίας (ο φόβος ΛΟΓΩ των εχθρών) μόνο αν τα συμφραζόμενα δηλώνουν αιτία· πιο συχνά αναλύεται ως υποκειμενική/αντικειμενική. Πάντα κρίνε από το νόημα."},{"h":"Γενική υποκειμενική και αντικειμενική — η κρισιμότερη διάκριση","body":"<p>Όταν ο πυρήνας είναι <b>ρηματικό ουσιαστικό</b> (παράγωγο ρήματος, π.χ. <i>φόβος ← φοβοῦμαι, νίκη ← νικῶ, ἀγάπη ← ἀγαπῶ, ἔρως ← ἐρῶ</i>) ή επίθετο ρηματικής σημασίας, η γενική που το συνοδεύει δηλώνει είτε <b>ποιος ενεργεί</b> (υποκειμενική) είτε <b>σε ποιον/τι κατευθύνεται η ενέργεια</b> (αντικειμενική). Είναι η πιο εξεταζόμενη και η πιο επικίνδυνη διάκριση, γιατί η ΙΔΙΑ μορφή μπορεί να ερμηνευθεί και με τους δύο τρόπους.</p><h3>Γενική υποκειμενική</h3><p>Η γενική αντιστοιχεί στο <b>υποκείμενο</b> της ρηματικής έννοιας: μετατρέπω το ουσιαστικό σε ρήμα και η γενική γίνεται υποκείμενο. <i>ἡ νίκη τῶν Ἀθηναίων</i> → «οἱ Ἀθηναῖοι νικῶσιν» (οι Αθηναίοι νικούν). Η γενική «κάνει» την ενέργεια.</p><h3>Γενική αντικειμενική</h3><p>Η γενική αντιστοιχεί στο <b>αντικείμενο</b> της ρηματικής έννοιας: <i>ὁ φόβος τῶν πολεμίων</i> → «φοβούμεθα τούς πολεμίους» (φοβόμαστε τους εχθρούς). Η γενική «δέχεται» την ενέργεια.</p><h3>ΤΟ ΤΕΣΤ (μετατροπή σε ρήμα)</h3><p>Μετατρέπω τον πυρήνα στο αντίστοιχο ρήμα και ρωτώ:</p><ul><li>Αν η γενική απαντά στο «<b>ποιος;</b>» (υποκείμενο) → <b>υποκειμενική</b>.</li><li>Αν η γενική απαντά στο «<b>ποιον / τι;</b>» (αντικείμενο) → <b>αντικειμενική</b>.</li></ul><p>Παράδειγμα της αμφισημίας: <i>ὁ φόβος τῶν πολεμίων</i> = (α) <b>υποκ.</b> «οι εχθροί φοβούνται» ή (β) <b>αντικ.</b> «(εμείς) φοβόμαστε τους εχθρούς». Μόνο τα συμφραζόμενα αποφασίζουν. Όταν συνυπάρχουν και τα δύο, το υποκείμενο μπαίνει συχνά εμπρόθετα: <i>ὁ τῶν Περσῶν εἰς τούς Ἕλληνας φόβος</i> = ο φόβος των Περσών προς τους Έλληνες (Πέρσες = υποκ., Έλληνες = αντικ.).</p><h3>Επίθετα που παίρνουν αντικειμενική γενική</h3><p>Πολλά επίθετα ρηματικής σημασίας συντάσσονται με αντικειμενική γενική, κατά σημασιολογικές ομάδες (βλ. πίνακα).</p>","examples":[{"gr":"ἡ νίκη τῶν Ἑλλήνων","an":"η νίκη των Ελλήνων — «τῶν Ἑλλήνων»: γενική υποκειμενική (οι Έλληνες νικούν)."},{"gr":"ἡ τῆς πόλεως ἅλωσις","an":"η άλωση της πόλης — «τῆς πόλεως»: υποκειμενική αν «η πόλη αλώθηκε» (πάσχει)· εδώ ρηματικό ουσιαστικό παθητικής σημασίας → η πόλη είναι το πάσχον υποκείμενο."},{"gr":"διδάσκαλος τῶν παίδων","an":"δάσκαλος των παιδιών — «τῶν παίδων»: αντικειμενική (διδάσκει τα παιδιά → «ποιους;»)."},{"gr":"ὁ τῶν Ἀθηναίων φόβος","an":"αμφίσημο: (α) υποκ. «οι Αθηναίοι φοβούνται», (β) αντικ. «(κάποιοι) φοβούνται τους Αθηναίους» — η σημασία κρίνεται από τα συμφραζόμενα."},{"gr":"ἡ τῆς πατρίδος ἀγάπη","an":"η αγάπη για την πατρίδα — «τῆς πατρίδος»: αντικειμενική (αγαπούμε την πατρίδα)."},{"gr":"ἔμπειρος πολέμου","an":"έμπειρος στον πόλεμο — «πολέμου»: αντικειμενική γενική στο επίθετο εμπειρίας «ἔμπειρος»."},{"gr":"ἔμπειρος τῆς χώρας τῆς Παφλαγόνων","an":"Ξεν. Ἀνάβ. 5.6.6 — γνώστης της χώρας των Παφλαγόνων· «τῆς χώρας» αντικειμενική γενική στο «ἔμπειρος» (απαντά στο «έμπειρος τίνος;»)."},{"gr":"ἡ τῶν νόμων φυλακή","an":"η τήρηση/φύλαξη των νόμων — «τῶν νόμων» αντικειμενική γενική στο ρηματικό ουσιαστικό «φυλακή» (φυλάσσει τους νόμους → «τι;»)."}],"table":{"title":"Επίθετα που συντάσσονται με αντικειμενική γενική (κατά σημασία)","cols":["Σημασιολογική ομάδα","Επίθετα","Παράδειγμα"],"rows":[["Μνήμη / λήθη","μνήμων, ἀμνήμων, ἐπιλήσμων","μνήμων τῶν εὐεργετῶν"],["Επιμέλεια / αμέλεια","ἐπιμελής, ἀμελής, ὀλίγωρος","ἐπιμελής τῶν κοινῶν"],["Κυριότητα / εξουσία","κύριος, ἐγκρατής, ἀκρατής","ἐγκρατής ἑαυτοῦ"],["Εμπειρία / γνώση","ἔμπειρος, ἄπειρος, ἐπιστήμων, ἀνεπιστήμων","ἔμπειρος πολέμου"],["Συμμετοχή / πληρότητα","μέτοχος, κοινωνός, μεστός, πλήρης","ψυχή ἐλπίδος μεστή"],["Χωρισμός / στέρηση","ἐλεύθερος, ἔρημος, κενός, γυμνός, ὀρφανός, ἄμοιρος","ὀρφανός πατρός"],["Επιθυμία","ἐπιθυμητικός, ἐραστής","ἐραστής τιμῆς"]]},"note":"Κλασική παγίδα: «ἡ τοῦ πατρός ἀγάπη». Υποκειμενική = «ο πατέρας αγαπά» (η αγάπη που τρέφει ο πατέρας)· αντικειμενική = «(κάποιος) αγαπά τον πατέρα» (η αγάπη προς τον πατέρα). ΠΑΝΤΑ κάνε το τεστ «ποιος;» / «ποιον;» και κρίνε από τα συμφραζόμενα."},{"h":"Γενική συγκριτική (ο δεύτερος όρος σύγκρισης)","body":"<p>Η <b>γενική συγκριτική</b> κατάγεται από την παλαιά αφαιρετική πτώση και δηλώνει τον <b>δεύτερο όρο μιας σύγκρισης</b> — αυτό δηλαδή με το οποίο συγκρίνεται ο πυρήνας. Αντιστοιχεί στο νεοελληνικό «από / παρά». Εμφανίζεται ως ετερόπτωτος προσδιορισμός κυρίως σε <b>επίθετα και επιρρήματα συγκριτικού βαθμού ή συγκριτικής σημασίας</b>.</p><h3>Με ποιες λέξεις συντάσσεται</h3><ul><li><b>Επίθετα/επιρρήματα συγκριτικού βαθμού:</b> <i>μείζων, ἐλάττων, κρείττων, βελτίων, σοφώτερος, μᾶλλον</i> (π.χ. <i>σοφώτερος τῶν ἄλλων</i>). Είναι ισοδύναμη με το «ἤ + ομοιόπτωτο» (<i>σοφώτερος ἤ οἱ ἄλλοι</i>).</li><li><b>Επίθετα συγκριτικής σημασίας</b> (χωρίς συγκριτική κατάληξη): <i>διπλάσιος, πολλαπλάσιος, πρότερος, ὕστερος, περιττός, ἐναντίος, διάφορος, ἄλλος, ἀλλότριος</i> (π.χ. <i>διπλάσιος τοῦ ἑτέρου</i>, <i>ἐπιστήμη ἐπιστήμης διάφορος</i>).</li><li><b>Υπερθετικά</b> όταν δεν δηλώνουν μέρος του όλου αλλά υπεροχή έναντι όλων (συχνά όμως εδώ η γενική είναι διαιρετική — βλ. σημείωση).</li></ul><h3>Σύνδεση με χωρισμό / στέρηση</h3><p>Η ίδια αφαιρετική γενική στηρίζει και τα επίθετα που δηλώνουν <b>χωρισμό, στέρηση, απόσταση, διαφορά</b> (<i>ἐλεύθερος, ἔρημος, κενός, καθαρός, γυμνός, ξένος</i>) — γι' αυτό συγγενεύουν εννοιολογικά συγκριτική και στέρηση: <i>ἐλεύθερος φόβου</i> = ελεύθερος από φόβο.</p>","examples":[{"gr":"κρείττων χρημάτων","an":"ανώτερος από τα χρήματα (αδιάφθορος) — «χρημάτων»: γενική συγκριτική στο συγκριτικό «κρείττων»."},{"gr":"σοφώτερος τῶν ἄλλων","an":"σοφότερος από τους άλλους — «τῶν ἄλλων»: γενική συγκριτική (= ἤ οἱ ἄλλοι)."},{"gr":"μείζων τοῦ ἀδελφοῦ","an":"μεγαλύτερος από τον αδελφό — «τοῦ ἀδελφοῦ»: γενική συγκριτική."},{"gr":"διπλάσιος τῆς πρόσθεν δυνάμεως","an":"διπλάσιος από την προηγούμενη δύναμη — «τῆς πρόσθεν δυνάμεως»: γενική συγκριτική σε επίθετο συγκριτικής σημασίας."},{"gr":"ἐπιστήμη ἐπιστήμης διάφορος","an":"μια επιστήμη διαφορετική από άλλη επιστήμη — «ἐπιστήμης»: γενική συγκριτική (διαφοράς) στο «διάφορος»."},{"gr":"ἐλεύθερος πάσης αἰσχύνης","an":"ελεύθερος από κάθε ντροπή — «πάσης αἰσχύνης»: αφαιρετικής προέλευσης γενική χωρισμού/στέρησης."},{"gr":"τό ὅλον μεῖζον τοῦ μέρους","an":"το όλον είναι μεγαλύτερο από το μέρος — «τοῦ μέρους» γενική συγκριτική στο συγκριτικό «μεῖζον» (= ἤ τό μέρος)· κλασικός φιλοσοφικός τύπος."},{"gr":"οὐδέν κρεῖττον τῆς ἀληθείας","an":"τίποτε ανώτερο από την αλήθεια — «τῆς ἀληθείας» γενική συγκριτική στο «κρεῖττον» (τύπου Πλάτωνος)."}],"note":"Με υπερθετικό + γενική, πρόσεξε: «ὁ ἄριστος τῶν Ἑλλήνων» = ο καλύτερος ΑΝΑΜΕΣΑ στους Έλληνες (γενική ΔΙΑΙΡΕΤΙΚΗ, ο πυρήνας ανήκει στο όλον), ΟΧΙ συγκριτική. Η συγκριτική γενική θέλει σύγκριση με κάτι ΕΞΩ από το σύνολο."},{"h":"Γενική του χρόνου και του τόπου ως προσδιορισμός","body":"<p>Δύο ακόμη είδη γενικής λειτουργούν ως ετερόπτωτοι προσδιορισμοί ονομάτων (και όχι μόνο ως επιρρηματικοί προσδιορισμοί ρημάτων), δηλώνοντας χρονική ή τοπική σχέση.</p><h3>Γενική του χρόνου</h3><p>Ως προσδιορισμός ονόματος, η γενική του χρόνου δηλώνει το <b>χρονικό πλαίσιο / διάστημα μέσα στο οποίο</b> ανήκει ή τοποθετείται ο πυρήνας (<i>τά τῆς νυκτός ἔργα</i> = τα νυχτερινά έργα). Η προέλευσή της είναι διαιρετική: η νύχτα είναι ένα μέρος του εικοσιτετραώρου, μέσα στο οποίο γίνεται η πράξη. Ως επιρρηματικός προσδιορισμός σε ρήμα, η ίδια γενική δηλώνει τον χρόνο μέσα στον οποίο: <i>νυκτός</i> = κατά τη διάρκεια της νύχτας, <i>χειμῶνος</i> = τον χειμώνα.</p><h3>Γενική του τόπου</h3><p>Δηλώνει τον <b>τόπο / χώρο μέσα στον οποίο ή μέρος του οποίου</b> βρίσκεται ή συμβαίνει κάτι (<i>πεδίου</i> = σε ανοιχτό πεδίο, <i>τῆς ὁδοῦ</i> = πάνω στον δρόμο). Και αυτή είναι διαιρετικής προέλευσης (ένα μέρος της έκτασης) και απαντά συχνά με γεωγραφικά/τοπικά ονόματα ή με επιρρήματα τόπου + γενική (<i>πανταχοῦ τῆς γῆς</i> = παντού στη γη, <i>οὐδαμοῦ γῆς</i> = πουθενά στον κόσμο).</p><p>Επειδή χρόνος και τόπος συνδέονται συχνά πιο φυσικά με ρήμα παρά με όνομα, στα σχολικά συντακτικά εμφανίζονται και ως <i>επιρρηματικές</i> χρήσεις της γενικής· ως ετερόπτωτοι ονοματικοί προσδιορισμοί καταγράφονται όταν προσδιορίζουν σαφώς ουσιαστικό.</p>","examples":[{"gr":"τά τῆς νυκτός ἔργα","an":"τα νυχτερινά έργα — «τῆς νυκτός»: γενική του χρόνου (διαιρετικής προέλευσης) που προσδιορίζει το «ἔργα»."},{"gr":"αἱ τοῦ θέρους ἡμέραι","an":"οι μέρες του καλοκαιριού — «τοῦ θέρους»: γενική του χρόνου στο «ἡμέραι»."},{"gr":"ἡ τῆς ὁδοῦ τραχύτης","an":"η τραχύτητα του δρόμου — «τῆς ὁδοῦ»: γενική του τόπου/αναφοράς στον τόπο."},{"gr":"πανταχοῦ τῆς γῆς","an":"παντού στη γη — «τῆς γῆς»: γενική του τόπου (διαιρετική) μετά από επίρρημα τόπου."},{"gr":"νυκτός πορεία","an":"νυχτερινή πορεία — «νυκτός»: γενική του χρόνου που χαρακτηρίζει την πορεία."},{"gr":"οὐδαμοῦ γῆς","an":"πουθενά στον κόσμο — «γῆς» γενική του τόπου (διαιρετική) μετά από επίρρημα τόπου (τύπου Πλάτωνος)."},{"gr":"τά τοῦ χειμῶνος ἔργα","an":"τα έργα/εργασίες του χειμώνα — «τοῦ χειμῶνος» γενική του χρόνου που προσδιορίζει το «ἔργα» (διαιρετικής προέλευσης)."}],"note":"Όταν η γενική χρόνου/τόπου εξαρτάται από ΡΗΜΑ (νυκτός ἀφίκετο = έφτασε νύχτα), είναι επιρρηματικός προσδιορισμός, όχι ετερόπτωτος ονοματικός. Ετερόπτωτος είναι μόνο όταν προσδιορίζει ΟΝΟΜΑ."},{"h":"Μεθοδολογία αναγνώρισης, σύνοψη ειδών και συχνές παγίδες","body":"<p>Για να αναγνωρίσεις σωστά μια γενική ως ετερόπτωτο προσδιορισμό, ακολούθησε σταθερά τα εξής βήματα:</p><ol><li><b>Βρες τον πυρήνα.</b> Ποιο όνομα προσδιορίζει η γενική;</li><li><b>Έλεγξε την πτώση.</b> Διαφορετική πτώση από τον πυρήνα → ετερόπτωτος. Ίδια πτώση → ομοιόπτωτος (σταμάτα εδώ).</li><li><b>Ρώτησε «τι σχέση δηλώνει».</b> Κτήση; Μέρος-όλο; Υλικό; Ιδιότητα; Αιτία; Αξία; Σύγκριση;</li><li><b>Αν ο πυρήνας είναι ρηματικό όνομα,</b> κάνε το τεστ υποκειμενικής/αντικειμενικής: μετάτρεψέ τον σε ρήμα και ρώτησε «ποιος;» (υποκ.) ή «ποιον/τι;» (αντικ.).</li><li><b>Επιβεβαίωσε με μετάφραση</b> που να αναδεικνύει τη σχέση (π.χ. «αξίας…», «από τους…», «για…»).</li></ol><h3>Διαφορά ετερόπτωτου από εμπρόθετο / επιρρηματικό</h3><p>Ο ετερόπτωτος προσδιορισμός είναι <i>ονοματικός</i> και εξαρτάται από <b>όνομα</b>. Αν η γενική εξαρτάται από <b>ρήμα</b> (γενική αντικείμενο, ή επιρρηματική γενική χρόνου/τόπου/αιτίας σε ρήμα), δεν είναι ετερόπτωτος ονοματικός προσδιορισμός. Αν εισάγεται με πρόθεση (<i>ἐκ τῆς πόλεως</i>), είναι εμπρόθετος, όχι ετερόπτωτος.</p><h3>Οι τρεις «δίδυμες» παγίδες</h3><ul><li><b>Διαιρετική vs κτητική:</b> «ένας από…» (διαιρετική) ≠ «που ανήκει σε…» (κτητική).</li><li><b>Διαιρετική vs συγκριτική</b> με υπερθετικό: «μέσα στο σύνολο» (διαιρετική) ≠ «έναντι άλλου, εκτός συνόλου» (συγκριτική).</li><li><b>Υποκειμενική vs αντικειμενική:</b> πάντα το τεστ «ποιος;» / «ποιον;».</li></ul><p>Με την παραπάνω μεθοδολογία και τον πίνακα-σύνοψη, ο μαθητής μπορεί να αναγνωρίσει και να δικαιολογήσει κάθε γενική-ετερόπτωτο προσδιορισμό που θα συναντήσει σε αρχαιοελληνικό κείμενο.</p>","examples":[{"gr":"οἱ ἄριστοι τῶν πολιτῶν / κρείττων τῶν πολιτῶν","an":"το πρώτο «τῶν πολιτῶν» = διαιρετική (οι καλύτεροι ΜΕΣΑ στους πολίτες)· το δεύτερο = συγκριτική (ανώτερος ΑΠΟ τους πολίτες). Ίδια μορφή, διαφορετική λειτουργία λόγω της σημασίας του πυρήνα."},{"gr":"ἡ τοῦ πατρός οἰκία / ἡ τοῦ πατρός ἀγάπη","an":"το πρώτο = κτητική (το σπίτι ανήκει στον πατέρα)· το δεύτερο = υποκ./αντικ. ανάλογα με τα συμφραζόμενα (ο πατέρας αγαπά / αγαπούμε τον πατέρα)."},{"gr":"ἐκ τῆς πόλεως ἐξῆλθεν","an":"«ἐκ τῆς πόλεως»: ΕΜΠΡΟΘΕΤΟΣ προσδιορισμός σε ρήμα — ΟΧΙ ετερόπτωτος ονοματικός. Αντιπαράδειγμα ορίου."},{"gr":"εἷς τῶν στρατηγῶν / σοφώτερος τῶν στρατηγῶν","an":"το πρώτο «τῶν στρατηγῶν» = διαιρετική (ένας ΑΠΟ τους στρατηγούς, μέλος του συνόλου)· το δεύτερο = συγκριτική (σοφότερος ΑΠΟ τους στρατηγούς, εκτός συνόλου). Κριτήριο η σημασία του πυρήνα (αριθμητικό vs συγκριτικό)."},{"gr":"ἀκούω τῶν μαρτύρων","an":"ακούω τους μάρτυρες — «τῶν μαρτύρων» γενική ΑΝΤΙΚΕΙΜΕΝΟ στο ρήμα «ἀκούω», ΟΧΙ ετερόπτωτος ονοματικός προσδιορισμός. Αντιπαράδειγμα ορίου (γενική εξαρτώμενη από ρήμα)."}],"table":{"title":"Τελικός πίνακας-σύνοψη: όλα τα είδη γενικής ως ετερόπτωτου προσδιορισμού","cols":["Είδος","Κριτήριο / τεστ","Μετάφραση-κλειδί","Παράδειγμα"],"rows":[["Κτητική","ανήκει σε / γνώρισμα ποιου","του / μου","ἡ οἰκία τοῦ πατρός"],["Συγγένειας-καταγωγής","γονέας / προέλευση","γιος/κόρη του","Περικλῆς ὁ Ξανθίππου"],["Δημιουργού","ποιος το δημιούργησε","έργο του","τά τοῦ Φειδίου ἔργα"],["Διαιρετική","ένας/μέρος από","από τους/τις","εἷς τῶν στρατηγῶν"],["Ύλης","από τι υλικό","από","στέφανος χρυσοῦ"],["Περιεχομένου","τι περιέχει","με / από","κρήνη ὕδατος"],["Ιδιότητας","ηλικία/μέγεθος/διάρκεια","ηλικίας/μήκους…","παῖς ἑπτά ἐτῶν"],["Αξίας","πόσο αξίζει","αξίας / αντί","χωρίον δέκα μνῶν"],["Αιτίας","γιατί / για ποιο έγκλημα","για","γραφή κλοπῆς"],["Υποκειμενική","τεστ «ποιος;»","–","ἡ νίκη τῶν Ἑλλήνων"],["Αντικειμενική","τεστ «ποιον/τι;»","προς / για","διδάσκαλος τῶν παίδων"],["Συγκριτική","β΄ όρος σύγκρισης (εκτός συνόλου)","από / παρά","σοφώτερος τῶν ἄλλων"],["Χρόνου","μέσα σε ποιο χρ. διάστημα","της / τον","τά τῆς νυκτός ἔργα"],["Τόπου","σε ποιο μέρος / χώρο","στο","πανταχοῦ τῆς γῆς"]]},"note":"Χρυσός κανόνας: η μορφή της γενικής ΔΕΝ προδίδει το είδος — ίδια μορφή υπηρετεί πολλές λειτουργίες. Το είδος καθορίζεται πάντα από (α) τη σημασία του πυρήνα και (β) τα συμφραζόμενα. Πρώτα νόημα, μετά ταμπέλα."}]);
  T("syn-eteroptwtoi-dot-ait", [{"h":"Τι είναι οι ετερόπτωτοι προσδιορισμοί — η θέση δοτικής & αιτιατικής","body":"<p>Στα Αρχαία Ελληνικά κάθε ονοματικός όρος (ουσιαστικό, επίθετο, αντωνυμία) μπορεί να δέχεται <b>προσδιορισμούς</b>, δηλαδή λέξεις που τον συνοδεύουν και τον φωτίζουν, καθορίζοντας ή συμπληρώνοντας τη σημασία του. Οι ονοματικοί προσδιορισμοί χωρίζονται σε δύο μεγάλες κατηγορίες ανάλογα με την πτώση τους σε σχέση με τον προσδιοριζόμενο όρο:</p><ul><li><b>Ομοιόπτωτοι</b>: βρίσκονται στην ίδια πτώση (και συνήθως στο ίδιο γένος και αριθμό) με τη λέξη που προσδιορίζουν — π.χ. ο επιθετικός προσδιορισμός, ο κατηγορηματικός, η παράθεση, η επεξήγηση.</li><li><b>Ετερόπτωτοι</b>: βρίσκονται σε <i>διαφορετική</i> (ἑτέρα) πτώση από τη λέξη που προσδιορίζουν. Δηλώνουν μια <b>σχέση</b> ανάμεσα στον προσδιορισμό και στον προσδιοριζόμενο όρο.</li></ul><p>Ως ετερόπτωτοι ονοματικοί προσδιορισμοί λειτουργούν αποκλειστικά οι <b>πλάγιες πτώσεις</b>: η <b>γενική</b>, η <b>δοτική</b> και η <b>αιτιατική</b> (ποτέ η ονομαστική και η κλητική, που είναι «πτώσεις του προσφωνείν»). Η παρούσα θεωρία εστιάζει στους ετερόπτωτους προσδιορισμούς σε <b>δοτική</b> και σε <b>αιτιατική</b>.</p><h3>Πώς αναγνωρίζουμε έναν ετερόπτωτο προσδιορισμό</h3><p>Πρέπει να συντρέχουν δύο προϋποθέσεις: (α) η λέξη να εξαρτάται από έναν <i>όνομα</i> (ουσιαστικό, επίθετο ή αντωνυμία) — όχι από ρήμα· αν εξαρτάται από ρήμα, τότε είναι <b>αντικείμενο</b> ή επιρρηματικός προσδιορισμός, όχι ετερόπτωτος ονοματικός προσδιορισμός. (β) η πτώση της να διαφέρει από εκείνη του προσδιοριζομένου.</p><p>Η <b>δοτική</b> ως ετερόπτωτος προσδιορισμός εμφανίζεται κυρίως δίπλα σε <b>επίθετα</b> (δοτική αντικειμενική, δοτική της αναφοράς) και σε ορισμένα <b>ουσιαστικά</b> (δοτική χαριστική/αντιχαριστική, δοτική κτητική). Η <b>αιτιατική</b> ως ετερόπτωτος προσδιορισμός εμφανίζεται σχεδόν αποκλειστικά δίπλα σε <b>επίθετα</b> (και μετοχές) ως <b>αιτιατική της αναφοράς</b>.</p>","examples":[{"gr":"Ἦσαν γάρ τοῖς Ἀθηναίοις οἱ ἱππεῖς ὠφέλιμοι.","an":"Γιατί οι ιππείς ήταν χρήσιμοι στους Αθηναίους. — Το «τοῖς Ἀθηναίοις» (δοτική) προσδιορίζει το επίθετο «ὠφέλιμοι» (ονομαστική): ετερόπτωτος προσδιορισμός, δοτική αντικειμενική."},{"gr":"Τυφλός τά ὦτα τόν τε νοῦν τά τ' ὄμματ' εἶ.","an":"Είσαι τυφλός στα αυτιά, στο νου και στα μάτια. — Οι αιτιατικές «τά ὦτα, τόν νοῦν, τά ὄμματα» προσδιορίζουν το επίθετο «τυφλός»: ετερόπτωτος προσδιορισμός, αιτιατική της αναφοράς."},{"gr":"Ὄνομα δέ τῷ ὄρει ἦν Θήχης.","an":"Ξεν. Ἀνάβ. 4.7.21 — Το όρος είχε όνομα Θήχης. «τῷ ὄρει»: δοτ. κτητική με εἰμί, ετερόπτωτος προσδιορισμός· υποκείμενο «ὄνομα»."},{"gr":"Διαφέρει γυνή ἀνδρός τήν φύσιν.","an":"Πλάτ. Πολιτ. 453b — Η γυναίκα διαφέρει από τον άνδρα ως προς τη φύση. «τήν φύσιν» (αιτιατική): αιτιατική της αναφοράς, ετερόπτωτος προσδιορισμός."}],"table":{"title":"Οι ετερόπτωτοι προσδιορισμοί σε δοτική και αιτιατική — επισκόπηση","cols":["Πτώση","Είδος","Εξαρτάται από","Δηλώνει"],"rows":[["Δοτική","Αντικειμενική","επίθετα (& ομόρριζα ονόματα ρημάτων με δοτ. αντικ.)","το πρόσωπο/πράγμα προς το οποίο στρέφεται η σχέση"],["Δοτική","Της αναφοράς","επίθετα (ικανότητας, κατάστασης κ.λπ.)","ως προς τι ισχύει η ιδιότητα"],["Δοτική","Χαριστική/Αντιχαριστική","ουσιαστικά (& ρήματα)","υπέρ ή σε βάρος ποιου"],["Δοτική","Κτητική","ουσιαστικά (με εἰμί/γίγνομαι/ὑπάρχω)","τον κάτοχο/κτήτορα"],["Αιτιατική","Της αναφοράς","επίθετα, μετοχές (& σπάν. ρήματα)","ως προς τι / κατά τι"]]},"note":"Κλειδί διάκρισης: αν ο όρος εξαρτάται από ΟΝΟΜΑ (επίθετο/ουσιαστικό/αντωνυμία) → ετερόπτωτος ονοματικός προσδιορισμός· αν εξαρτάται από ΡΗΜΑ → αντικείμενο ή επιρρηματικός προσδιορισμός."},{"h":"Δοτική αντικειμενική (δίπλα σε επίθετα)","body":"<p>Η <b>δοτική αντικειμενική</b> είναι ετερόπτωτος προσδιορισμός που δηλώνει το <b>αντικείμενο</b> (το πρόσωπο ή το πράγμα) προς το οποίο στρέφεται ή κατευθύνεται η έννοια της προσδιοριζομένης λέξης. Ονομάζεται «αντικειμενική» γιατί λειτουργεί σαν αντικείμενο της έννοιας που κρύβεται μέσα στο επίθετο: το «<i>ὠφέλιμος τοῖς Ἀθηναίοις</i>» ισοδυναμεί νοηματικά με «<i>ὠφελεῖ τούς Ἀθηναίους</i>».</p><p>Η δοτική αντικειμενική εξαρτάται κατά κανόνα από <b>επίθετα</b> (και τα αντίστοιχα επιρρήματα ή ομόρριζα ουσιαστικά) που σημαίνουν μια σχέση, η οποία απαιτεί δεύτερο όρο. Επειδή τα επίθετα αυτά είναι πάρα πολλά, η σχολική παράδοση τα κατατάσσει σε ομάδες κατά σημασιολογικά πεδία (βλ. πίνακα). Στη νεοελληνική η σχέση αυτή αποδίδεται με εμπρόθετο ή με γενική (π.χ. «χρήσιμος <i>στους / για τους</i> Αθηναίους», «εχθρός <i>της</i> ελευθερίας»).</p><h3>Κριτήριο αναγνώρισης</h3><p>Ρωτάμε «σε ποιον / προς ποιον / για ποιον / με ποιον;» ισχύει η ιδιότητα του επιθέτου. Αν η δοτική απαντά σε αυτή την ερώτηση και είναι αναγκαία για να ολοκληρωθεί η σημασία του επιθέτου, πρόκειται για δοτική αντικειμενική.</p>","examples":[{"gr":"Βασιλεύς γάρ καί τύραννος ἅπας ἐχθρός ἐλευθερίᾳ.","an":"Γιατί κάθε βασιλιάς και τύραννος είναι εχθρός της ελευθερίας. — «ἐλευθερίᾳ»: δοτ. αντικειμενική στο επίθετο «ἐχθρός» (φιλία/έχθρα)."},{"gr":"Οἱ ὅμοιοι τοῖς ὁμοίοις εὖνοί εἰσι.","an":"Οι όμοιοι είναι ευνοϊκά διακείμενοι προς τους όμοιους. — «τοῖς ὁμοίοις»: δοτ. αντικειμενική στο «εὖνοι»."},{"gr":"Ὁ πατήρ ὁ ἡμέτερος φίλος ἦν Μενεκλεῖ.","an":"Ο πατέρας μας ήταν φίλος του Μενεκλή. — «Μενεκλεῖ»: δοτ. αντικειμενική στο «φίλος»."},{"gr":"Πρῶτον τόν στρατηγόν δεῖ εὐπειθέστατον εἶναι τοῖς νόμοις.","an":"Πρώτα-πρώτα ο στρατηγός πρέπει να είναι πάρα πολύ πειθαρχικός στους νόμους. — «τοῖς νόμοις»: δοτ. αντικειμενική στο «εὐπειθέστατον» (υποταγή)."},{"gr":"Ἐγώ, ὦ ἄνδρες Ἕλληνες, γείτων οἰκῶ τῇ Ἑλλάδι.","an":"Εγώ, άνδρες Έλληνες, κατοικώ γείτονας στην Ελλάδα. — «τῇ Ἑλλάδι»: δοτ. αντικειμενική στο «γείτων» (γειτνίαση)."},{"gr":"Ἡ τύχη οὐκ ἔστι σύμμαχος τοῖς μή δρῶσι.","an":"Η τύχη δεν είναι σύμμαχος εκείνων που δεν ενεργούν. — «τοῖς μή δρῶσι»: δοτ. αντικειμενική στο σύνθετο με σύν- «σύμμαχος»."},{"gr":"Σοί οὐδείς ἴσος ἐστίν.","an":"Κανείς δεν είναι ίσος με σένα. — «Σοί»: δοτ. αντικειμενική στο «ἴσος» (ισότητα)."},{"gr":"Μέθη φύλαξιν ἀπρεπέστατον.","an":"Η μέθη είναι κάτι εντελώς ακατάλληλο για τους φύλακες. — «φύλαξιν»: δοτ. αντικειμενική στο «ἀπρεπέστατον» (το αρμόζον/ταιριαστό)."},{"gr":"Πολέμιος δέ ἦν αὐτῷ καί ὁ ἀδελφός.","an":"(τύπου Ξεν. Ἀνάβ.) — Εχθρικός του ήταν και ο αδελφός. «αὐτῷ»: δοτ. αντικειμενική στο «πολέμιος» (φιλία/έχθρα)."},{"gr":"Ἀνδρί δικαίῳ πᾶσα γῆ φίλη.","an":"Στον δίκαιο άνδρα κάθε τόπος είναι φιλικός. — «ἀνδρί δικαίῳ»: δοτ. αντικειμενική στο επίθετο «φίλη»."},{"gr":"Φίλος ἦν τῷ τε Κύρῳ καί τοῖς ἄλλοις στρατιώταις.","an":"(τύπου Ξεν. Ἀνάβ.) — Ήταν φίλος και του Κύρου και των άλλων στρατιωτών. «τῷ Κύρῳ, τοῖς στρατιώταις»: δοτ. αντικειμενική στο «φίλος»."},{"gr":"Ταῦτα ὠφέλιμα τῇ πόλει ἐστίν.","an":"Αυτά είναι ωφέλιμα για την πόλη. — «τῇ πόλει»: δοτ. αντικειμενική στο «ὠφέλιμα» (ωφέλεια/βλάβη)."}],"table":{"title":"Σημασιολογικές ομάδες επιθέτων που συντάσσονται με δοτική αντικειμενική","cols":["Σημασία","Χαρακτηριστικά επίθετα"],"rows":[["Ωφέλεια / βλάβη","ὠφέλιμος, χρήσιμος, βλαβερός, ἐπιζήμιος, λυσιτελής, σύμφορος, ἀσύμφορος"],["Φιλία / έχθρα","φίλος, εὐμενής, εὔνους, ἐπιτήδειος, προσφιλής — δυσμενής, ἐχθρός, πολέμιος"],["Ευπείθεια / υποταγή","εὐπειθής, πιστός, ὑπήκοος — ἀπειθής, ἄπιστος"],["Ακολουθία / διαδοχή","ἀκόλουθος, ἑπόμενος, διάδοχος"],["Προσέγγιση / μείξη","γείτων, ὅμορος, πλησίος, ὅμαιμος — ἄμικτος"],["Ομοιότητα / ταυτότητα","ὁ αὐτός, ὅμοιος, παραπλήσιος, προσεμφερής — ἀνόμοιος, διάφορος"],["Ισότητα / συμφωνία","ἴσος, ἰσόπαλος, ἰσόρροπος, σύμφωνος — ἄνισος, ἀσύμφωνος"],["Καταλληλότητα («αρμόζει»)","ἁρμόδιος, πρόσφορος, πρεπώδης — ἀνάρμοστος, ἀπρεπής, ἀνεπιτήδειος"],["Σύνθετα με ἐν- / σύν-","ἔμφυτος, ἐντριβής — σύμφυτος, σύμμαχος, σύμφωνος, συγγενής"]]},"note":"Προσοχή: η ίδια δοτική, όταν εξαρτάται από ομόρριζο ΟΥΣΙΑΣΤΙΚΟ ρήματος που συντάσσεται με δοτική (π.χ. «ἡ τοῖς πολεμίοις ἐπίθεσις» από το ἐπιτίθεμαι + δοτ.), παραμένει δοτική αντικειμενική — ετερόπτωτος προσδιορισμός του ουσιαστικού."},{"h":"Δοτική της αναφοράς (δίπλα σε επίθετα)","body":"<p>Η <b>δοτική της αναφοράς</b> είναι ετερόπτωτος προσδιορισμός που προσδιορίζει κυρίως <b>επίθετα</b> και δηλώνει το <b>σημείο, την πλευρά ή το πεδίο</b> ως προς το οποίο ισχύει η ιδιότητα που εκφράζει το επίθετο. Απαντά στην ερώτηση «<i>ως προς τι; κατά τι; σε ποιο σημείο;</i>».</p><p>Ενώ η δοτική αντικειμενική δηλώνει <i>προς ποιον</i> στρέφεται η σχέση, η δοτική της αναφοράς <b>περιορίζει</b> το εύρος εφαρμογής του επιθέτου σε μια συγκεκριμένη όψη: λ.χ. «<i>ἀσθενής τῷ σώματι</i>» σημαίνει ότι κάποιος είναι αδύναμος <i>όχι γενικά</i>, αλλά <i>ως προς το σώμα</i> — μπορεί να είναι ισχυρός κατά την ψυχή. Στη νεοελληνική αποδίδεται με «ως προς…», «στο…», «κατά…».</p><p>Τα επίθετα που συντάσσονται με δοτική της αναφοράς δηλώνουν συχνά <b>ικανότητα, δύναμη/αδυναμία, καταλληλότητα, ποσότητα ή ψυχική/σωματική κατάσταση</b>: <i>ἀσθενής, δυνατός, ἰσχυρός, ἱκανός, δεινός, καλός, αἰσχρός, τραχύς, φοβερός, ταχύς, εὐπροσήγορος</i>.</p><h3>Διάκριση από τη δοτική αντικειμενική</h3><p>Δοκιμή: μετατρέπουμε νοηματικά το επίθετο σε ρήμα. Αν προκύπτει αντικείμενο («ὠφέλιμος τοῖς Ἀθηναίοις» → «ὠφελεῖ τούς Ἀθηναίους») → <b>αντικειμενική</b>. Αν δεν προκύπτει αντικείμενο αλλά απλώς περιορισμός («ἀσθενής τῷ σώματι» → αδύναμος <i>ως προς</i> το σώμα, όχι «αδυνατίζει το σώμα») → <b>της αναφοράς</b>.</p>","examples":[{"gr":"Ἀσθενής τῷ σώματι.","an":"Αδύναμος ως προς το σώμα. — «τῷ σώματι»: δοτ. της αναφοράς στο «ἀσθενής»."},{"gr":"Ταχύς τοῖς ποσί.","an":"Γρήγορος ως προς τα πόδια. — «τοῖς ποσί»: δοτ. της αναφοράς στο «ταχύς»."},{"gr":"Εὐπροσήγορος τῷ λόγῳ.","an":"Προσηνής (καταδεκτικός) ως προς τον λόγο/την ομιλία. — «τῷ λόγῳ»: δοτ. της αναφοράς στο «εὐπροσήγορος»."},{"gr":"Δεινός λέγειν καί ἰσχυρός τῇ γνώμῃ.","an":"Ικανός στο να μιλά και ισχυρός ως προς την κρίση. — «τῇ γνώμῃ»: δοτ. της αναφοράς στο «ἰσχυρός»."},{"gr":"Ἀνήρ ἡλικίᾳ ἔτι νέος.","an":"Άνδρας ακόμη νέος ως προς την ηλικία. — «ἡλικίᾳ»: δοτ. της αναφοράς στο «νέος»."},{"gr":"Πόλις μεγάλη καί εὐδαίμων τῷ πλήθει τῶν οἰκητόρων.","an":"(τύπου Θουκ.) — Πόλη μεγάλη και ευτυχισμένη ως προς το πλήθος των κατοίκων. «τῷ πλήθει»: δοτ. της αναφοράς."},{"gr":"Διαφέροντες τῇ ἀρετῇ.","an":"Άνθρωποι που υπερέχουν ως προς την αρετή. — «τῇ ἀρετῇ»: δοτ. της αναφοράς στη μετοχή/επίθετο «διαφέροντες»."}],"table":{"title":"Δοτική αντικειμενική vs δοτική της αναφοράς","cols":["Κριτήριο","Δοτική αντικειμενική","Δοτική της αναφοράς"],"rows":[["Ερώτηση","σε ποιον; προς ποιον;","ως προς τι; κατά τι;"],["Σχέση","το επίθετο «κατευθύνεται» στη δοτική","το επίθετο «περιορίζεται» στη δοτική"],["Μετατροπή σε ρήμα","δίνει αντικείμενο (ὠφελεῖ τινα)","δεν δίνει αντικείμενο"],["Νεοελληνικά","σε / για / με","ως προς / στο / κατά"],["Τυπικά επίθετα","φίλος, ἐχθρός, ὠφέλιμος, ἴσος","ἀσθενής, ἰσχυρός, ταχύς, ἱκανός"]]},"note":"Πολλά επίθετα (π.χ. δεινός, ἱκανός, δυνατός) μπορούν να δεχτούν ΚΑΙ δοτική της αναφοράς ΚΑΙ αιτιατική της αναφοράς με ισοδύναμο νόημα (ταχύς τοῖς ποσί = ταχύς τούς πόδας). Η επιλογή πτώσης είναι θέμα ύφους/συγγραφέα."},{"h":"Δοτική χαριστική & αντιχαριστική (δίπλα σε ουσιαστικά)","body":"<p>Η <b>δοτική χαριστική</b> δηλώνει το πρόσωπο <b>προς όφελος</b> του οποίου ισχύει ή γίνεται κάτι· η <b>δοτική αντιχαριστική</b> (ή δοτική της βλάβης) δηλώνει το πρόσωπο <b>σε βάρος</b> του οποίου. Ανήκουν στην ευρύτερη οικογένεια της <b>δοτικής προσωπικής</b>. Όταν η δοτική αυτή προσδιορίζει <b>ουσιαστικό</b> (και όχι ρήμα), λειτουργεί ως <b>ετερόπτωτος ονοματικός προσδιορισμός</b>.</p><p>Στη νεοελληνική αποδίδεται με «για / προς όφελος / χάριν» (χαριστική) και «σε βάρος / εις βάρος / εναντίον» (αντιχαριστική). Συχνά συνοδεύεται από προσωπικές αντωνυμίες (μοι, σοι, ἡμῖν, αὐτῷ) και απαντά κατεξοχήν με ρήματα ή ονόματα ωφέλειας/βλάβης.</p><h3>Προσοχή στην εξάρτηση</h3><p>Η ίδια δοτική, αν εξαρτάται από <b>ρήμα</b>, είναι επιρρηματική δοτική προσωπική (χαριστική/αντιχαριστική) — όχι ετερόπτωτος προσδιορισμός. Ως ετερόπτωτος προσδιορισμός χαρακτηρίζεται μόνο όταν συμπληρώνει <i>όνομα</i>.</p>","examples":[{"gr":"Ἄλλο δέ στράτευμα αὐτῷ συνελέγετο ἐν Χερρονήσῳ.","an":"Άλλο στράτευμα συγκεντρωνόταν γι' αυτόν στη Χερσόνησο. — «αὐτῷ»: δοτ. χαριστική (όφελος)."},{"gr":"Πᾶς ἀνήρ αὑτῷ πονεῖ.","an":"Κάθε άνθρωπος μοχθεί για τον εαυτό του. — «αὑτῷ»: δοτ. χαριστική."},{"gr":"Οἱ σύμμαχοι τοῖς Ἀθηναίοις τόν φόρον ἔφερον.","an":"Οι σύμμαχοι έφερναν τον φόρο προς όφελος των Αθηναίων / για τους Αθηναίους. — «τοῖς Ἀθηναίοις»: δοτ. χαριστική."},{"gr":"Οὗτος ὁ νόμος τοῖς ἀδικοῦσι χαλεπός.","an":"Αυτός ο νόμος είναι σκληρός σε βάρος των αδίκων. — «τοῖς ἀδικοῦσι»: δοτ. αντιχαριστική (της βλάβης)."},{"gr":"Πᾶς ἀνήρ, κἄν δοῦλος ᾖ τις, ἥδεται τό φῶς ὁρῶν.","an":"(τύπου τραγ.) — Κάθε άνθρωπος χαίρεται βλέποντας το φως. Σε ονοματική εκδοχή «ἡ τοῖς πολίταις σωτηρία» (η σωτηρία προς όφελος των πολιτών) η δοτ. είναι χαριστική στο όνομα «σωτηρία»."},{"gr":"Ἡ τῇ πόλει βοήθεια.","an":"Η βοήθεια προς όφελος της πόλης. — «τῇ πόλει»: δοτ. χαριστική, ετερόπτωτος προσδιορισμός στο ουσιαστικό «βοήθεια»."},{"gr":"Ἐπιβουλή τοῖς πολεμίοις.","an":"Επιβουλή σε βάρος των εχθρών. — «τοῖς πολεμίοις»: δοτ. αντιχαριστική, ετερόπτωτος προσδιορισμός στο ουσιαστικό «ἐπιβουλή»."}],"note":"Η διάκριση χαριστική/αντιχαριστική κρίνεται από το νόημα: όφελος → χαριστική, ζημία/βλάβη → αντιχαριστική. Και οι δύο είναι μορφές της δοτικής προσωπικής."},{"h":"Δοτική κτητική (δίπλα σε ουσιαστικά, με εἰμί / γίγνομαι / ὑπάρχω)","body":"<p>Η <b>δοτική κτητική</b> δηλώνει τον <b>κάτοχο/κτήτορα</b> και απαντά κατεξοχήν με τα ρήματα ύπαρξης <i>εἰμί, γίγνομαι, ὑπάρχω</i>. Στη σύνταξη αυτή, το <b>υποκείμενο</b> του ρήματος είναι το <i>κτήμα</i> (αυτό που κατέχεται), ενώ ο <b>κτήτορας</b> τίθεται σε <b>δοτική</b>. Έτσι το «<i>ἔστι μοι βιβλίον</i>» = «έχω ένα βιβλίο» (κατά λέξη: «υπάρχει σε μένα βιβλίο»).</p><p>Όταν η δοτική κτητική συνδέεται στενά με ένα <b>ουσιαστικό</b> και δηλώνει τον κάτοχό του, λειτουργεί ως <b>ετερόπτωτος ονοματικός προσδιορισμός</b> αυτού του ουσιαστικού. Στη νεοελληνική αποδίδεται με ρήμα «έχω» ή με κτητική γενική/αντωνυμία.</p><h3>Διαφορά από τη γενική κτητική</h3><p>Η <b>γενική</b> κτητική προσδιορίζει απευθείας το ουσιαστικό μέσα στην ίδια φράση («τό βιβλίον <i>τοῦ μαθητοῦ</i>»). Η <b>δοτική</b> κτητική απαιτεί ρήμα ύπαρξης και τοποθετεί τον κάτοχο σε δοτική («τῷ μαθητῇ ἐστι βιβλίον»). Η δοτική κτητική <i>τονίζει την κατοχή</i> ως γεγονός· η γενική απλώς προσδιορίζει.</p>","examples":[{"gr":"Ἔστι μοι χρήματα πολλά.","an":"Έχω πολλά χρήματα (κατά λέξη: υπάρχουν σε μένα πολλά χρήματα). — «μοι»: δοτ. κτητική· υποκείμενο «χρήματα»."},{"gr":"Ἡμῖν δέ ξύμμαχοι ἀγαθοί (εἰσιν).","an":"Εμείς όμως έχουμε καλούς συμμάχους. — «ἡμῖν»: δοτ. κτητική· υποκείμενο «ξύμμαχοι»."},{"gr":"Ὑπάρχει γάρ νῦν ἡμῖν οὐδέν τῶν ἐπιτηδείων.","an":"Γιατί τώρα δεν έχουμε καθόλου εφόδια. — «ἡμῖν»: δοτ. κτητική με ὑπάρχω."},{"gr":"Τῷ ἀνδρί ὄνομα ἦν Κῦρος.","an":"Ο άνδρας είχε το όνομα Κύρος / το όνομα του άνδρα ήταν Κύρος. — «τῷ ἀνδρί»: δοτ. κτητική· υποκείμενο «ὄνομα»."},{"gr":"Ὄνομα δέ τῷ ὄρει ἦν Θήχης.","an":"Ξεν. Ἀνάβ. 4.7.21 — Το όρος είχε όνομα Θήχης. «τῷ ὄρει»: δοτ. κτητική με εἰμί· υποκείμενο «ὄνομα»."},{"gr":"Παῖδες δέ μοι οὔπω εἰσίν.","an":"Παιδιά δεν έχω ακόμη (κατά λέξη: δεν υπάρχουν ακόμη σε μένα παιδιά). — «μοι»: δοτ. κτητική· υποκείμενο «παῖδες»."},{"gr":"Ἦν δέ τῷ Κύρῳ στρατιά πολλή.","an":"(τύπου Ξεν. Ἀνάβ.) — Ο Κύρος είχε πολλή στρατιά. «τῷ Κύρῳ»: δοτ. κτητική· υποκείμενο «στρατιά»."}],"table":{"title":"Δοτική κτητική vs γενική κτητική","cols":["Κριτήριο","Δοτική κτητική","Γενική κτητική"],"rows":[["Ρήμα","απαιτεί εἰμί / γίγνομαι / ὑπάρχω","δεν απαιτεί ρήμα ύπαρξης"],["Υποκείμενο","το κτήμα (στην ονομαστική)","–"],["Θέση κατόχου","δοτική","γενική"],["Έμφαση","τονίζει την ίδια την κατοχή","απλός προσδιορισμός κτήσης"],["Παράδειγμα","ἔστι μοι βιβλίον","τό βιβλίον τοῦ μαθητοῦ"]]},"note":"Συχνή «παγίδα»: με ρήμα ύπαρξη η δοτική του προσώπου είναι σχεδόν πάντοτε κτητική (όχι αντικειμενική). Αν λείπει το ρήμα ύπαρξης και η δοτική απλώς ωφελείται/βλάπτεται → χαριστική/αντιχαριστική, όχι κτητική."},{"h":"Αιτιατική της αναφοράς (δίπλα σε επίθετα & μετοχές)","body":"<p>Η <b>αιτιατική της αναφοράς</b> είναι ο κατεξοχήν ετερόπτωτος προσδιορισμός σε αιτιατική. Δηλώνει —όπως και η δοτική της αναφοράς— το <b>σημείο ή την πλευρά ως προς την οποία</b> ισχύει μια ιδιότητα ή μια ενέργεια. Προσδιορίζει κυρίως <b>επίθετα</b> (και μετοχές, σπανιότερα και ρήματα) και απαντά στην ερώτηση «<i>ως προς τι; κατά τι;</i>». Στη νεοελληνική αποδίδεται με «ως προς…», «στο…», «κατά…».</p><p>Η σύνταξη αυτή κληρονομεί την παλιά «αιτιατική του καθ' ὅ» (accusative of respect). Είναι ιδιαίτερα συχνή με:</p><ul><li><b>μέρη του σώματος</b> και ψυχικές/πνευματικές ιδιότητες: <i>τυφλός τά ὄμματα, ἀλγῶν τόν πόδα, φιλότιμος τήν γνώμην</i>·</li><li><b>καταγωγή/γένος</b>: <i>Ἕλλην τό γένος, Θηβαῖος τό γένος</i>·</li><li><b>διαστάσεις/μέγεθος/ποσότητα</b>: <i>τό μῆκος, τό εὖρος, τό ὕψος, τό βάθος, τό μέγεθος, τό πλῆθος, τόν ἀριθμόν</i>.</li></ul><h3>Σχέση με τη δοτική της αναφοράς</h3><p>Οι δύο πτώσεις είναι σε μεγάλο βαθμό εναλλάξιμες. Πολλά επίθετα δέχονται και τις δύο: «<i>ταχύς τοῖς ποσί</i>» (δοτ.) = «<i>ταχύς τούς πόδας</i>» (αιτ.). Η αιτιατική της αναφοράς είναι όμως η <b>μόνη επιλογή</b> στις τυποποιημένες εκφράσεις διαστάσεων («<i>τό εὖρος / τό ὕψος / τό μῆκος</i>»).</p>","examples":[{"gr":"Τυφλός τά τ' ὦτα τόν τε νοῦν τά τ' ὄμματ' εἶ.","an":"Είσαι τυφλός στα αυτιά, στο νου και στα μάτια. — «τά ὦτα, τόν νοῦν, τά ὄμματα»: αιτ. της αναφοράς στο «τυφλός»."},{"gr":"Ἕλληνες τό γένος.","an":"Έλληνες ως προς την καταγωγή. — «τό γένος»: αιτ. της αναφοράς."},{"gr":"Φιλοτιμότατος (ἦν) τήν γνώμην.","an":"Ήταν εξαιρετικά φιλόδοξος ως προς τη διάθεση/τη σκέψη. — «τήν γνώμην»: αιτ. της αναφοράς."},{"gr":"Διαφέρει γυνή ἀνδρός τήν φύσιν.","an":"Πλάτ. Πολιτ. 453b — Η γυναίκα διαφέρει από τον άνδρα ως προς τη φύση. «τήν φύσιν»: αιτ. της αναφοράς (εδώ με ρήμα)."},{"gr":"Πύργος ᾠκοδόμητο, σταδίου καί τό μῆκος καί τό εὖρος.","an":"Είχε χτιστεί πύργος, ενός σταδίου και ως προς το μήκος και ως προς το πλάτος. — «τό μῆκος, τό εὖρος»: αιτ. της αναφοράς (διαστάσεις)."},{"gr":"Τεῖχος πλίνθινον ᾠκοδόμητο, τό μέν εὖρος πεντήκοντα ποδῶν, τό δέ ὕψος ἑκατόν.","an":"Είχε χτιστεί πλίνθινο τείχος, με πλάτος πενήντα πόδια και ύψος εκατό. — «τό εὖρος, τό ὕψος»: αιτ. της αναφοράς."},{"gr":"Ἀλγῶ τήν κεφαλήν.","an":"Πονώ ως προς το κεφάλι / πονάει το κεφάλι μου. — «τήν κεφαλήν»: αιτ. της αναφοράς (μέλος σώματος)."},{"gr":"Διά μέσου δέ τῆς πόλεως ῥεῖ ποταμός Κύδνος ὄνομα, εὖρος δύο πλέθρων.","an":"Ξεν. Ἀνάβ. 1.2.23 — Μέσα από την πόλη κυλά ποταμός με το όνομα Κύδνος, πλάτους δύο πλέθρων. «εὖρος»: αιτ. της αναφοράς (διάσταση)· «ὄνομα» επίσης αιτ. αναφοράς."},{"gr":"Λυδός ἦν τό γένος.","an":"(τύπου Ξεν.) — Ήταν Λυδός ως προς την καταγωγή. «τό γένος»: αιτ. της αναφοράς."},{"gr":"Κάμνω τούς πόδας.","an":"Είμαι κουρασμένος ως προς τα πόδια / πονούν τα πόδια μου. — «τούς πόδας»: αιτ. της αναφοράς (μέλη σώματος)."}],"table":{"title":"Τυπικές περιπτώσεις αιτιατικής της αναφοράς","cols":["Πεδίο","Παραδείγματα φράσεων"],"rows":[["Μέλη σώματος / ψυχικές-πνευματικές ιδιότητες","τυφλός τά ὄμματα· ἀσθενής τό σῶμα· φιλότιμος τήν γνώμην· ἀλγῶν τόν πόδα"],["Καταγωγή / γένος","Ἕλλην τό γένος· Θηβαῖος τό γένος· Λυδός τό γένος"],["Διαστάσεις / μέγεθος / ποσότητα","τό μῆκος, τό εὖρος, τό ὕψος, τό βάθος, τό μέγεθος, τό πλῆθος, τόν ἀριθμόν"]]},"note":"Παγίδα διάκρισης: η αιτιατική της αναφοράς ΔΕΝ είναι αντικείμενο. Με ρήματα όπως «ἀλγῶ τήν κεφαλήν», η αιτιατική δηλώνει ΩΣ ΠΡΟΣ ΤΙ, όχι ΤΙ· γι' αυτό δεν μετατρέπεται σε υποκείμενο παθητικής σύνταξης (δεν λέμε «ἡ κεφαλή ἀλγεῖται»)."},{"h":"Σύνοψη, μεθοδολογία αναγνώρισης & συχνές παγίδες","body":"<p>Για να χαρακτηρίσουμε σωστά μια δοτική ή αιτιατική ως ετερόπτωτο προσδιορισμό, ακολουθούμε σταθερή πορεία:</p><h3>Βήματα ανάλυσης</h3><ol><li><b>Βρίσκουμε τη λέξη εξάρτησης.</b> Αν είναι ΟΝΟΜΑ (επίθετο/ουσιαστικό/αντωνυμία/μετοχή) → υποψήφιος ετερόπτωτος προσδιορισμός. Αν είναι ΡΗΜΑ → αντικείμενο ή επιρρηματικός προσδιορισμός (όχι ετερόπτωτος).</li><li><b>Ελέγχουμε την πτώση:</b> πρέπει να διαφέρει από του προσδιοριζομένου.</li><li><b>Θέτουμε την κατάλληλη ερώτηση:</b> «σε ποιον;» (αντικειμενική) — «ως προς τι;» (αναφοράς) — «για/σε βάρος ποιου;» (χαριστική/αντιχαριστική) — «ποιος κατέχει;» με εἰμί/γίγνομαι/ὑπάρχω (κτητική).</li></ol><h3>Δοκιμές διάκρισης</h3><ul><li><b>Δοτ. αντικειμενική ↔ δοτ. αναφοράς:</b> μετατροπή επιθέτου σε ρήμα· αν προκύπτει αντικείμενο → αντικειμενική, αλλιώς → αναφοράς.</li><li><b>Δοτ. αναφοράς ↔ αιτ. αναφοράς:</b> νοηματικά ταυτόσημες· συχνά εναλλάξιμες. Στις διαστάσεις (τό εὖρος κ.λπ.) μόνο αιτιατική.</li><li><b>Δοτ. κτητική ↔ δοτ. χαριστική:</b> με ρήμα ύπαρξης και υποκείμενο το κτήμα → κτητική· χωρίς, με νόημα οφέλους/βλάβης → χαριστική/αντιχαριστική.</li></ul><p>Με τον τρόπο αυτό αξιοποιείται πλήρως το τρίπτυχο <b>εξάρτηση – πτώση – ερώτηση</b>, που είναι το ασφαλέστερο κριτήριο για κάθε ετερόπτωτο προσδιορισμό.</p>","examples":[{"gr":"Ὠφέλιμος τῇ πόλει ἀνήρ.","an":"Άνδρας χρήσιμος για την πόλη. — εξάρτηση: επίθετο «ὠφέλιμος»· ερώτηση «σε ποιον;» → δοτ. αντικειμενική."},{"gr":"Ἀσθενής τῷ σώματι, ἰσχυρός τήν ψυχήν.","an":"Αδύναμος ως προς το σώμα, ισχυρός ως προς την ψυχή. — «τῷ σώματι»: δοτ. αναφοράς· «τήν ψυχήν»: αιτ. αναφοράς (παράλληλη χρήση)."},{"gr":"Ἔστι τῷ βασιλεῖ θησαυρός μέγας.","an":"Ο βασιλιάς έχει μεγάλο θησαυρό. — ρήμα ύπαρξης + υποκείμενο «θησαυρός» → «τῷ βασιλεῖ» δοτ. κτητική."},{"gr":"Πολέμιος μέν τοῖς Ἀθηναίοις, Λακεδαιμόνιος δέ τό γένος.","an":"Εχθρικός προς τους Αθηναίους, αλλά Λακεδαιμόνιος ως προς την καταγωγή. — «τοῖς Ἀθηναίοις»: δοτ. αντικειμενική (σε ποιον;)· «τό γένος»: αιτ. αναφοράς (ως προς τι;)· δύο διαφορετικά είδη ετερόπτωτου στην ίδια φράση."},{"gr":"Ἡ τοῖς συμμάχοις βοήθεια ὠφέλιμος ἦν τῇ πόλει.","an":"Η βοήθεια προς όφελος των συμμάχων ήταν χρήσιμη για την πόλη. — «τοῖς συμμάχοις»: δοτ. χαριστική στο όνομα «βοήθεια»· «τῇ πόλει»: δοτ. αντικειμενική στο επίθετο «ὠφέλιμος»."}],"table":{"title":"Ταχεία διαγνωστική πυξίδα","cols":["Ερώτηση που απαντά","Εξάρτηση","Χαρακτηρισμός"],"rows":[["σε ποιον; προς ποιον;","επίθετο/όνομα","δοτική αντικειμενική"],["ως προς τι; (δοτ.)","επίθετο","δοτική της αναφοράς"],["ως προς τι; (αιτ.)","επίθετο/μετοχή","αιτιατική της αναφοράς"],["για / σε βάρος ποιου;","όνομα (ή ρήμα)","δοτική χαριστική / αντιχαριστική"],["ποιος κατέχει; (+εἰμί)","όνομα","δοτική κτητική"]]},"note":"Γενικός κανόνας μνήμης: ΡΗΜΑ → αντικείμενο/επιρρηματικός· ΟΝΟΜΑ → ετερόπτωτος ονοματικός προσδιορισμός. Πάντα ελέγχουμε πρώτα από τι εξαρτάται η πλάγια πτώση."}]);
  T("syn-deuter-basika", [{"h":"Πρόταση, περίοδος, ημιπερίοδος: το πλαίσιο","body":"<p>Πριν μιλήσουμε για δευτερεύουσες προτάσεις και σύνδεση, πρέπει να ορίσουμε τις βασικές μονάδες του λόγου.</p><h3>Τι είναι πρόταση</h3><p><b>Πρόταση</b> είναι ο ελάχιστος γλωσσικός σχηματισμός που εκφράζει ένα ολοκληρωμένο νόημα και έχει (φανερό ή εννοούμενο) <b>ρήμα</b>. Κάθε ρήμα ορίζει μία πρόταση: όσα ρήματα, τόσες προτάσεις.</p><h3>Κύρια (ανεξάρτητη) και δευτερεύουσα (εξαρτημένη)</h3><ul><li><b>Κύρια ή ανεξάρτητη πρόταση</b> είναι εκείνη που στέκεται μόνη της στον λόγο, χωρίς να χρειάζεται άλλη για να σταθεί νοηματικά. Φέρει αυτοτελές νόημα.</li><li><b>Δευτερεύουσα ή εξαρτημένη ή υποτεταγμένη πρόταση</b> είναι εκείνη που <i>δεν στέκεται μόνη της</i> στον λόγο, αλλά εξαρτάται από μια κύρια (ή από άλλη δευτερεύουσα) της οποίας το νόημα συμπληρώνει. Εισάγεται πάντοτε με <b>υποτακτικό σύνδεσμο</b> ή με <b>αναφορική / ερωτηματική αντωνυμία ή επίρρημα</b>.</li></ul><h3>Περίοδος και ημιπερίοδος</h3><p><b>Περίοδος</b> ονομάζεται ένα σύνολο προτάσεων (κυρίων και δευτερευουσών) που εκφράζει ένα πλήρες, ολοκληρωμένο νόημα και κλείνει με τελεία. <b>Ημιπερίοδος</b> είναι το τμήμα της περιόδου που κλείνει με άνω τελεία. Μέσα στην περίοδο οι προτάσεις συνδέονται μεταξύ τους με τους τρόπους που θα δούμε (παράταξη, υπόταξη, ασύνδετο).</p><h3>Δύο διαστάσεις κάθε δευτερεύουσας</h3><p>Για να αναλύσουμε σωστά μια δευτερεύουσα, ελέγχουμε πάντα δύο πράγματα: (α) την <b>εισαγωγή</b> της (με ποια λέξη μπαίνει) και (β) την <b>εκφορά</b> της (σε ποια έγκλιση/χρόνο εκφέρεται). Αυτά τα δύο, μαζί με τον <b>συντακτικό ρόλο</b>, αποτελούν την πλήρη ταυτότητά της.</p>","examples":[{"gr":"Λέγει ὅτι ταῦτα ἀληθῆ ἐστιν.","an":"Λέει ότι αυτά είναι αληθινά. — «Λέγει»: κύρια πρόταση. «ὅτι ... ἐστιν»: δευτερεύουσα ειδική, αντικείμενο του «λέγει»· δεν στέκεται μόνη της."},{"gr":"Ἐπεί ἐτελεύτησεν ὁ Κῦρος, οἱ στρατιῶται ἠθύμησαν.","an":"Όταν πέθανε ο Κύρος, οι στρατιώτες αποθαρρύνθηκαν. — «ἐπεί ... Κῦρος»: δευτερεύουσα χρονική (προτάσσεται)· «οἱ στρατιῶται ἠθύμησαν»: κύρια."},{"gr":"Οὗτος μέν πλούσιός ἐστιν, ἐκεῖνος δέ πένης.","an":"Αυτός είναι πλούσιος, εκείνος όμως φτωχός. — Δύο κύριες προτάσεις, αντιθετικά συνδεδεμένες (μέν ... δέ)."},{"gr":"Ὅ τι ὑμεῖς πεπόνθατε, οὐκ οἶδα.","an":"Πλάτ. Ἀπολ. 17a — Πώς εσείς έχετε επηρεαστεί, δεν το ξέρω. «οὐκ οἶδα»: κύρια· «ὅ τι ... πεπόνθατε»: δευτερεύουσα (πλάγια ερωτηματική), αντικείμενο· δείχνει ότι μία περίοδος δομείται από κύρια + εξαρτημένη."},{"gr":"Εἴπερ γε Δαρείου ἐστί παῖς, οὐκ ἀμαχεί ταῦτα ἐγώ λήψομαι.","an":"Ξεν. Ἀνάβ. 1.7.9 — Αν πράγματι είναι γιος του Δαρείου, δεν θα τα πάρω αυτά αμαχητί. Δύο ρήματα → δύο προτάσεις: υποθετική («εἴπερ ... ἐστί») + κύρια-απόδοση."}],"note":"Προσοχή: «όσα ρήματα, τόσες προτάσεις» — αλλά ένα συνημμένο/ μετοχή ΔΕΝ αποτελεί χωριστή πρόταση· αντιστοιχεί σε δευτερεύουσα μόνο όταν αναλυθεί. Επίσης το ρήμα μιας πρότασης μπορεί να εννοείται (π.χ. ελλειπτικές προτάσεις)."},{"h":"Η μεγάλη διαίρεση: ονοματικές και επιρρηματικές","body":"<p>Οι δευτερεύουσες προτάσεις διακρίνονται, ανάλογα με τη <b>θέση/λειτουργία</b> που έχουν μέσα στην περίοδο (δηλαδή ανάλογα με το <i>τι μέρος του λόγου ισοδυναμούν</i>), σε δύο μεγάλες κατηγορίες:</p><h3>Α. Ονοματικές προτάσεις</h3><p>Ισοδυναμούν με <b>όνομα (ουσιαστικό)</b> και επομένως πιάνουν στην περίοδο τη θέση που θα έπιανε ένα ουσιαστικό. Λειτουργούν ως: <b>υποκείμενο</b>, <b>αντικείμενο</b>, <b>κατηγορούμενο</b> ή <b>επεξήγηση</b>. Σε αυτές ανήκουν οι <b>ειδικές</b>, οι <b>ενδοιαστικές</b>, οι <b>πλάγιες ερωτηματικές</b> και οι <b>(ονοματικές) αναφορικές</b>.</p><h3>Β. Επιρρηματικές προτάσεις</h3><p>Ισοδυναμούν με <b>επίρρημα / επιρρηματικό προσδιορισμό</b> και δηλώνουν μια επιρρηματική σχέση (χρόνο, αιτία, σκοπό, αποτέλεσμα, υπόθεση, εναντίωση). Λειτουργούν ως <b>επιρρηματικοί προσδιορισμοί</b> του ρήματος της κύριας. Σε αυτές ανήκουν οι <b>χρονικές, αιτιολογικές, τελικές, αποτελεσματικές (συμπερασματικές), υποθετικές, εναντιωματικές/παραχωρητικές</b> και οι <b>(επιρρηματικές) αναφορικές</b>.</p><h3>Γενικός κανόνας άρνησης</h3><p>Ένα πρώτο, χρήσιμο διαγνωστικό: οι περισσότερες <b>ονοματικές</b> και οι αναφορικές προσδιοριστικές παίρνουν άρνηση <b>οὐ</b> (κρίσης), ενώ οι <b>επιρρηματικές</b> (τελικές, ενδοιαστικές, υποθετικές, εναντιωματικές, χρονικές προσδοκίας) παίρνουν άρνηση <b>μή</b> (επιθυμίας/υπόθεσης). Υπάρχουν εξαιρέσεις (βλ. κάθε είδος ξεχωριστά).</p>","table":{"title":"Συνοπτική ταξινόμηση των δευτερευουσών προτάσεων","cols":["Κατηγορία","Είδος","Λειτουργία","Τυπική άρνηση"],"rows":[["Ονοματικές","Ειδικές","υποκ./αντικ./επεξήγηση","οὐ"],["Ονοματικές","Ενδοιαστικές","υποκ./αντικ./επεξήγηση","—"],["Ονοματικές","Πλάγιες ερωτηματικές","υποκ./αντικ./επεξήγηση","οὐ / μή"],["Ονοματικές/Επιρρ.","Αναφορικές","ποικίλη (ονοματική ή επιρρηματική)","οὐ ή μή"],["Επιρρηματικές","Χρονικές","επιρρ. προσδ. χρόνου","οὐ / μή"],["Επιρρηματικές","Αιτιολογικές","επιρρ. προσδ. αιτίας","οὐ / μή"],["Επιρρηματικές","Τελικές","επιρρ. προσδ. σκοπού","μή"],["Επιρρηματικές","Αποτελεσματικές","επιρρ. προσδ. αποτελέσματος","οὐ / μή"],["Επιρρηματικές","Υποθετικές","επιρρ. προσδ. υπόθεσης (όρος)","μή"],["Επιρρηματικές","Εναντιωματικές/Παραχωρητικές","επιρρ. προσδ. εναντίωσης","μή"]]},"note":"Η ίδια λέξη εισαγωγής μπορεί να εισάγει διαφορετικά είδη (π.χ. ὡς = ειδικός, αιτιολογικός, τελικός, χρονικός, αποτελεσματικός σύνδεσμος)· πάντα κρίνουμε από το νόημα και την εκφορά, όχι μόνο από τη λέξη."},{"h":"Ονοματικές Ι: Ειδικές και Ενδοιαστικές","body":"<h3>1. Ειδικές προτάσεις</h3><p>Οι <b>ειδικές</b> δηλώνουν μια κρίση και ισοδυναμούν με ειδικό απαρέμφατο· εκφράζουν το αντικείμενο ρημάτων λεκτικών, γνωστικών, δεικτικών, αισθήσεως (λέγω, φημί, ἀγγέλλω, οἶδα, γιγνώσκω, δηλῶ, ἀκούω, ὁρῶ κ.λπ.).</p><ul><li><b>Εισαγωγή:</b> με τους ειδικούς συνδέσμους <b>ὅτι</b> (αντικειμενική κρίση) και <b>ὡς</b> (υποκειμενική κρίση, με χροιά αβεβαιότητας ή σκοπιάς του υποκειμένου).</li><li><b>Εκφορά:</b> με <b>οριστική</b> (πραγματικό), με <b>δυνητική οριστική / δυνητική ευκτική</b> (δυνατό/πιθανό), με <b>ευκτική του πλαγίου λόγου</b> όταν εξαρτώνται από ιστορικό χρόνο.</li><li><b>Λειτουργία:</b> αντικείμενο, υποκείμενο (σε απρόσωπα: δῆλόν ἐστιν ὅτι...), επεξήγηση. <b>Άρνηση:</b> οὐ.</li></ul><h3>2. Ενδοιαστικές προτάσεις</h3><p>Οι <b>ενδοιαστικές</b> (ή διστακτικές) δηλώνουν <b>φόβο, ανησυχία, δισταγμό</b>. Εξαρτώνται από ρήματα και εκφράσεις που σημαίνουν φόβο ή προσοχή: φοβοῦμαι, δέδοικα, δέος ἐστί, κίνδυνός ἐστι, ὁρῶ (=προσέχω), φυλάττομαι, εὐλαβοῦμαι.</p><ul><li><b>Εισαγωγή:</b> με το <b>μή</b> (φόβος μήπως <i>γίνει</i> κάτι ανεπιθύμητο) και <b>μή οὐ</b> (φόβος μήπως <i>δεν</i> γίνει κάτι επιθυμητό).</li><li><b>Εκφορά:</b> με <b>υποτακτική</b> (όταν ο φόβος αφορά κάτι προσδοκώμενο) και με <b>ευκτική του πλαγίου λόγου</b> (μετά από ιστορικό χρόνο). Σπανιότερα με <b>οριστική</b>, όταν ο φόβος αφορά κάτι ήδη συντελεσμένο ή πραγματικό.</li><li><b>Λειτουργία:</b> αντικείμενο, υποκείμενο (σε απρόσωπη έκφραση φόβου), επεξήγηση.</li></ul>","examples":[{"gr":"Οὗτοι ἔλεγον ὅτι Κῦρος τέθνηκεν.","an":"Αυτοί έλεγαν ότι ο Κύρος έχει πεθάνει. — Ειδική με «ὅτι» + παρακείμενο οριστικής (αντικειμενική κρίση)· αντικείμενο του «ἔλεγον»."},{"gr":"Ἔλεγον ὡς οὐ καλῶς πράττοιεν.","an":"Έλεγαν ότι (τάχα) δεν ενεργούσαν σωστά. — Ειδική με «ὡς» (υποκειμενική χροιά) + ευκτική πλαγίου λόγου, λόγω εξάρτησης από ιστορικό χρόνο («ἔλεγον»)."},{"gr":"Φοβοῦμαι μή οὐ δυνηθῶ.","an":"Φοβάμαι μήπως δεν μπορέσω. — Ενδοιαστική με «μή οὐ» (φόβος μήπως ΔΕΝ γίνει το επιθυμητό) + υποτακτική· αντικείμενο του «φοβοῦμαι»."},{"gr":"Ἐφοβήθησαν μή καί ἐπί σφᾶς ὁ στρατός χωρήσῃ.","an":"Φοβήθηκαν μήπως ο στρατός προχωρήσει και εναντίον τους. — Ενδοιαστική με «μή» + υποτακτική αορίστου (προσδοκώμενο ανεπιθύμητο)."},{"gr":"Ἔδεισα μή τι πάθοιτε.","an":"Ξεν. (πβ. Smyth §2225) — Φοβήθηκα μήπως πάθετε κάτι. Ενδοιαστική με «μή» + ευκτική πλαγίου λόγου, μετά από ιστορικό χρόνο («ἔδεισα»)."},{"gr":"Δῆλον ἦν ὅτι ἐγγύς που βασιλεύς ἦν.","an":"(τύπου Ξεν. Ἀνάβ.) — Ήταν φανερό ότι ο βασιλιάς ήταν κάπου κοντά. Ειδική με «ὅτι» + οριστική, ως υποκείμενο του απρόσωπου «δῆλον ἦν»."}],"note":"Παγίδα: το «μή» στις ενδοιαστικές ΔΕΝ είναι άρνηση αλλά σύνδεσμος εισαγωγής· γι' αυτό το «μή οὐ» μεταφράζεται «μήπως δεν». Επίσης η ευκτική του πλαγίου λόγου είναι προαιρετική: μετά από ιστορικό χρόνο μπορεί να διατηρηθεί η υποτακτική για ζωντάνια (παράσταση)."},{"h":"Ονοματικές ΙΙ: Πλάγιες ερωτηματικές","body":"<p>Οι <b>πλάγιες ερωτηματικές</b> είναι ερωτήσεις που δεν διατυπώνονται ευθέως αλλά εξαρτώνται από ρήμα. Εκφράζουν απορία, ερώτηση, άγνοια, έρευνα, φροντίδα: ἐρωτῶ, πυνθάνομαι, σκοπῶ, οἶδα, ἀγνοῶ, θαυμάζω, βουλεύομαι, ἐνθυμοῦμαι, λέγω (= καθορίζω).</p><h3>Ολικής vs μερικής αγνοίας</h3><ul><li><b>Ολικής αγνοίας</b> (η απορία αφορά ολόκληρη την πρόταση — απάντηση «ναι/όχι»): εισάγονται με <b>εἰ</b> (= αν, μήπως), και στη διμελή μορφή με <b>εἰ ... ἤ / πότερον (πότερα) ... ἤ</b> (= αν ... ή).</li><li><b>Μερικής αγνοίας</b> (η απορία αφορά ένα μέρος): εισάγονται με <b>ερωτηματικές αντωνυμίες/επιρρήματα</b> (τίς, πόσος, ποῖος, πῶς, ποῦ, πότε, πόθεν) ή με τις αντίστοιχες <b>αναφορικές-ερωτηματικές</b> (ὅστις, ὁπόσος, ὁποῖος, ὅπως, ὅπου, ὁπότε, ὁπόθεν).</li></ul><h3>Εκφορά</h3><p>Με κάθε έγκλιση που θα είχε και η αντίστοιχη ευθεία ερώτηση: <b>οριστική</b> (ερώτηση κρίσης για πραγματικό), <b>απορηματική υποτακτική</b> (ερώτηση επιθυμίας, «τι να κάνω;»), <b>δυνητική οριστική/ευκτική</b>, και <b>ευκτική του πλαγίου λόγου</b> μετά από ιστορικό χρόνο.</p><p><b>Λειτουργία:</b> αντικείμενο, υποκείμενο, επεξήγηση. <b>Άρνηση:</b> οὐ (σε ερωτήσεις κρίσης), μή (σε ερωτήσεις επιθυμίας/βουλήσεως).</p>","examples":[{"gr":"Ἐρήσομαι ὅστις ἐστίν ὁ διδάσκαλος.","an":"Θα ρωτήσω ποιος είναι ο δάσκαλος. — Πλάγια ερωτηματική μερικής αγνοίας (αναφορ. αντων. «ὅστις») + οριστική· αντικείμενο του «ἐρήσομαι»."},{"gr":"Ἠρώτων αὐτόν εἰ ἀναπλεύσειεν.","an":"Τον ρωτούσαν αν είχε αποπλεύσει. — Πλάγια ολικής αγνοίας με «εἰ» + ευκτική πλαγίου λόγου (εξάρτηση από ιστορικό «ἠρώτων»)."},{"gr":"Οὐκ οἶδα πότερον πορεύωμαι ἤ μένω.","an":"Δεν ξέρω αν να προχωρήσω ή να μείνω. — Διμελής πλάγια ολικής αγνοίας («πότερον ... ἤ») + απορηματική υποτακτική (ερώτηση επιθυμίας)."},{"gr":"Σκόπει ὅπως μή αἰσχρῶς ἀπολῇ.","an":"Πρόσεχε πώς να μη χαθείς άδοξα. — (Σύνορο με βουλητική:) πλάγια ερωτηματική / βουλητική μερικής αγνοίας με «ὅπως» + υποτακτική, άρνηση «μή»."},{"gr":"Ὅ τι ὑμεῖς πεπόνθατε, οὐκ οἶδα.","an":"Πλάτ. Ἀπολ. 17a — Πώς εσείς έχετε επηρεαστεί, δεν το ξέρω. Πλάγια ερωτηματική μερικής αγνοίας («ὅ τι») + οριστική παρακειμένου· αντικείμενο του «οἶδα»."},{"gr":"Ἐβουλεύοντο εἰ τόν στρατόν διαβιβάσειαν.","an":"(τύπου Ξεν.) — Σκέφτονταν αν να περάσουν απέναντι τον στρατό. Πλάγια ολικής αγνοίας με «εἰ» + ευκτική πλαγίου λόγου (εξάρτηση από ιστορικό «ἐβουλεύοντο»)."}],"note":"Διάκριση από ειδικές: αν μπορεί να μπει «αν/ποιος/πώς/πού» → πλάγια ερωτηματική· αν μπορεί να μπει μόνο «ότι» → ειδική. Το «εἰ» των πλάγιων ερωτηματικών (= αν, μήπως) δεν συγχέεται με το υποθετικό «εἰ» (= εάν)."},{"h":"Αναφορικές προτάσεις: ονοματικές και επιρρηματικές","body":"<p>Οι <b>αναφορικές</b> εισάγονται με <b>αναφορικές αντωνυμίες</b> (ὅς, ἥ, ὅ· ὅστις· ὅσος· οἷος· ὁπόσος· ὁποῖος) ή <b>αναφορικά επιρρήματα</b> (οὗ, ὅπου, ὅθεν, ὅποι, ὡς, ὥσπερ, ὅσον, ᾗ) και «αναφέρονται» σε όρο της προηγούμενης πρότασης (τον <b>όρο αναφοράς</b>). Είναι το πιο πολυλειτουργικό είδος και δεν ανήκει σε μία μόνο κατηγορία.</p><h3>Α. Ονοματικές αναφορικές</h3><p>Ισοδυναμούν με όνομα και λειτουργούν ως υποκείμενο, αντικείμενο, κατηγορούμενο, επεξήγηση ή ως <b>προσδιορισμός</b> (αναφορικές προσδιοριστικές, όταν υπάρχει όρος αναφοράς που προσδιορίζουν). Εκφορά: οριστική (πραγματικό), δυνητική έγκλιση, υποτακτική/ευκτική με αοριστολογική χροιά.</p><h3>Β. Επιρρηματικές αναφορικές</h3><p>Πέρα από τον αναφορικό χαρακτήρα τους, λανθάνει μέσα τους μια <b>επιρρηματική σχέση</b> (αιτία, σκοπός, αποτέλεσμα, υπόθεση, εναντίωση), που φαίνεται από το νόημα και κυρίως από την <b>εκφορά</b>:</p><ul><li><b>Αναφορικο-αιτιολογικές</b> (= επειδή): οριστική.</li><li><b>Αναφορικο-τελικές</b> (= για να): <b>οριστική μέλλοντα</b>.</li><li><b>Αναφορικο-αποτελεσματικές/συμπερασματικές</b> (= ώστε): οριστική, συχνά μετά από «οὕτως, τοιοῦτος, τοσοῦτος».</li><li><b>Αναφορικο-υποθετικές</b> (= εάν): δηλώνουν όρο/προϋπόθεση, με εκφορά υποθετικού λόγου (ὅστις + υποτακτική + ἄν, ή ευκτική κ.λπ.).</li></ul><p>Συχνά συνοδεύονται από φαινόμενα όπως η <b>έλξη του αναφορικού</b> (το αναφορικό παίρνει την πτώση του όρου αναφοράς) και η <b>έλξη/ενσωμάτωση του όρου αναφοράς</b>.</p>","examples":[{"gr":"Ὅστις ἑαυτόν φιλεῖ, μετ' ἐμοῦ μαχέσθω.","an":"Όποιος αγαπά τον εαυτό του, ας πολεμήσει μαζί μου. — Ονοματική αναφορική (αοριστολογική) ως υποκείμενο· εκφορά οριστική με γενική/αόριστη σημασία."},{"gr":"Θαυμαστόν ποιεῖς, ὅς ἡμῖν οὐδέν δίδως.","an":"Κάνεις κάτι παράξενο, αφού/που δεν μας δίνεις τίποτα. — Αναφορικο-αιτιολογική (= ἐπειδή) + οριστική· δικαιολογεί το «θαυμαστόν»."},{"gr":"Δώσω ὑμῖν ἡγεμόνα, ὅς ὑμᾶς ἄξει.","an":"Θα σας δώσω οδηγό, ο οποίος θα σας οδηγήσει (= για να σας οδηγήσει). — Αναφορικο-τελική + οριστική μέλλοντα."},{"gr":"Τίς οὕτως εὐήθης ἐστίν ὑμῶν ὅστις ἀγνοεῖ τόν ἐκεῖθεν πόλεμον δεῦρο ἥξοντα;","an":"Ποιος από σας είναι τόσο αφελής ώστε να αγνοεί ότι ο πόλεμος από εκεί θα έρθει εδώ; — Αναφορικο-αποτελεσματική (μετά από «οὕτως»)."},{"gr":"Ὅστις ζῆν ἐπιθυμεῖ, πειράσθω νικᾶν.","an":"Ξεν. (Κύρ. Παιδ., πβ. αναφορικο-υποθετικές) — Όποιος επιθυμεί να ζει, ας προσπαθεί να νικά. Αναφορικο-υποθετική (= ἐάν τις) με αοριστολογική σημασία· ισοδυναμεί με όρο/προϋπόθεση."},{"gr":"Τούτους ἄρχοντας ἐποίει ἧς κατεστρέφετο χώρας.","an":"Ξεν. Ἀνάβ. 1.9.14 — Αυτούς τους έκανε άρχοντες της χώρας που υπέτασσε. Αναφορική προσδιοριστική με έλξη του αναφορικού («ἧς» αντί «ἥν», στην πτώση του όρου αναφοράς «χώρας»)."}],"note":"Παγίδα: η αναφορική προσδιοριστική (στενά συνδεδεμένη με τον όρο αναφοράς, χωρίς κόμμα) δεν χωρίζεται με κόμμα και «ταυτίζει»· η προσθετική/παρενθετική (με κόμμα) απλώς προσθέτει πληροφορία. Η σωστή στίξη αλλάζει το νόημα."},{"h":"Επιρρηματικές Ι: Χρονικές και Αιτιολογικές","body":"<h3>1. Χρονικές προτάσεις</h3><p>Δηλώνουν τον χρόνο στον οποίο γίνεται η πράξη της κύριας. Ως προς τη χρονική σχέση δηλώνουν το <b>σύγχρονο</b>, το <b>προτερόχρονο</b> ή το <b>υστερόχρονο</b>.</p><ul><li><b>Εισαγωγή:</b> ὅτε, ὁπότε, ὡς, ἡνίκα (= όταν, σύγχρονο)· ἐπεί, ἐπειδή, ὡς (= αφού, προτερόχρονο)· πρίν (= πριν, υστερόχρονο)· ἕως, ἔστε, μέχρι, ἄχρι (= ώσπου, όσο)· ἐξ οὗ, ἀφ' οὗ (= από τότε που).</li><li><b>Εκφορά:</b> <b>οριστική</b> (πραγματικός/καθορισμένος χρόνος)· <b>υποτακτική + ἄν</b> (→ ὅταν, ἐπειδάν, ἐπάν, πρίν ἄν, ἕως ἄν: αόριστη επανάληψη στο παρόν-μέλλον ή προσδοκία)· <b>ευκτική</b> (επανάληψη στο παρελθόν, ή ευκτική πλαγίου λόγου).</li><li><b>Άρνηση:</b> οὐ (συνήθως)· μή στις υποθετικού χαρακτήρα.</li></ul><h3>2. Αιτιολογικές προτάσεις</h3><p>Δηλώνουν την αιτία ή το αίτιο της κύριας· λειτουργούν ως επιρρηματικός προσδιορισμός της αιτίας.</p><ul><li><b>Εισαγωγή:</b> ὅτι, διότι (αντικειμενική αιτία)· ὡς (υποκειμενική αιτία, η αιτία ως γνώμη κάποιου)· ἐπεί, ἐπειδή (= αφού, επειδή)· σπανιότερα εἰ (μετά από ρήματα ψυχικού πάθους: «που/επειδή»).</li><li><b>Εκφορά:</b> <b>οριστική</b> (πραγματική αιτία)· <b>δυνητική οριστική/ευκτική</b> (πιθανή/δυνατή αιτία)· <b>ευκτική του πλαγίου λόγου</b> (υποκειμενική αιτία ή εξάρτηση από ιστορικό χρόνο).</li></ul>","examples":[{"gr":"Ὅτε ἡ ναυμαχία ἐγένετο, ἔτυχεν ἐν Ἀβύδῳ ὤν.","an":"Όταν έγινε η ναυμαχία, έτυχε να είναι στην Άβυδο. — Χρονική με «ὅτε» + οριστική (καθορισμένος χρόνος, σύγχρονο)."},{"gr":"Ἐπειδάν πάντα ἀκούσητε, κρίνατε.","an":"Αφού τα ακούσετε όλα, κρίνετε. — Χρονικοϋποθετική με «ἐπειδάν» (ἐπεί+ἄν) + υποτακτική (προσδοκία/αόριστη επανάληψη)."},{"gr":"Οὐ πρότερον ἐπαύσαντο πρίν τήν πόλιν εἷλον.","an":"Δεν σταμάτησαν προτού καταλάβουν την πόλη. — Χρονική με «πρίν» + οριστική (υστερόχρονο, μετά από αρνητική κύρια)."},{"gr":"Ξενοφῶντα ᾐτιῶντο ὅτι ἐδίωκεν ἀπό τῆς φάλαγγος.","an":"Κατηγορούσαν τον Ξενοφώντα επειδή απομάκρυνε (τους στρατιώτες) από τη φάλαγγα. — Αιτιολογική με «ὅτι» + οριστική (αντικειμενική αιτία)."},{"gr":"Ἐπεί δέ ἡμέρα ἐγένετο, συνῆλθον οἱ στρατηγοί.","an":"Ξεν. Ἀνάβ. 3.3.1 (τύπου) — Όταν/αφού ξημέρωσε, συγκεντρώθηκαν οι στρατηγοί. Χρονική με «ἐπεί» + οριστική (προτερόχρονο, καθορισμένος χρόνος)."},{"gr":"Ἀπώλλυντο, ὅτι οὐδαμόθεν ἐπιτήδεια εἶχον.","an":"(τύπου Ξεν.) — Καταστρέφονταν, επειδή δεν είχαν από πουθενά εφόδια. Αιτιολογική με «ὅτι» + οριστική (πραγματική, αντικειμενική αιτία)."}],"note":"Το «πρίν»: όταν η κύρια είναι καταφατική, το «πρίν» (= πριν) παίρνει ΑΠΑΡΕΜΦΑΤΟ (δεν είναι πρόταση)· όταν η κύρια είναι αρνητική, το «πρίν» (= προτού/ώσπου) εκφέρεται με έγκλιση και αποτελεί χρονική πρόταση. Το «ὡς» και «ἐπεί» είναι πολυσήμαντα: κρίνε από το νόημα αν είναι χρονικά ή αιτιολογικά."},{"h":"Επιρρηματικές ΙΙ: Τελικές, Αποτελεσματικές, Εναντιωματικές/Παραχωρητικές","body":"<h3>1. Τελικές προτάσεις</h3><p>Δηλώνουν τον <b>σκοπό</b> για τον οποίο γίνεται η πράξη της κύριας.</p><ul><li><b>Εισαγωγή:</b> ἵνα, ὅπως, ὡς (= για να). Άρνηση: <b>μή</b> (ή ἵνα μή, ὅπως μή = για να μη).</li><li><b>Εκφορά:</b> κατά κανόνα <b>υποτακτική</b> (σκοπός προσδοκώμενος, μετά από αρκτικό χρόνο)· <b>ευκτική του πλαγίου λόγου</b> μετά από ιστορικό χρόνο· σπάνια οριστική ιστορικού χρόνου (απραγματοποίητος σκοπός).</li></ul><h3>2. Αποτελεσματικές (συμπερασματικές) προτάσεις</h3><p>Δηλώνουν το <b>αποτέλεσμα</b> της πράξης της κύριας. Συχνά προαναγγέλλονται από δεικτικά: οὕτως, τοσοῦτος, τοιοῦτος, εἰς τοῦτο.</p><ul><li><b>Εισαγωγή:</b> <b>ὥστε</b> (και <b>ὡς</b>). Άρνηση: οὐ (πραγματικό αποτέλεσμα) / μή (επιδιωκόμενο, με απαρέμφατο).</li><li><b>Εκφορά:</b> <b>οριστική</b> (πραγματικό αποτέλεσμα, με έμφαση στην πραγματικότητά του) ή <b>απαρέμφατο</b> (αποτέλεσμα ως φυσική/δυνατή/επιδιωκόμενη συνέπεια — το λεγόμενο «ὥστε + απαρέμφατο»).</li></ul><h3>3. Εναντιωματικές και Παραχωρητικές</h3><p>Δηλώνουν <b>εναντίωση</b> προς το περιεχόμενο της κύριας (παραχώρηση). Διακρίνονται:</p><ul><li><b>Εναντιωματικές</b> (η εναντίωση αφορά κάτι <i>πραγματικό</i>): εἰ καί, ἐάν καί, καίτοι (= αν και, μολονότι).</li><li><b>Παραχωρητικές</b> (η εναντίωση αφορά κάτι <i>υποθετικό/μη πραγματικό</i>): καί εἰ, κἄν (καί ἐάν), οὐδ' εἰ, μηδ' ἐάν (= και αν ακόμη, ακόμη κι αν).</li></ul><p>Εκφορά: όπως των υποθετικών (οριστική / υποτακτική + ἄν / ευκτική). Άρνηση: μή.</p>","examples":[{"gr":"Κύνας τρέφομεν, ἵνα φυλάττωσι τάς οἰκίας.","an":"Τρέφουμε σκύλους, για να φυλάνε τα σπίτια. — Τελική με «ἵνα» + υποτακτική (σκοπός, μετά από αρκτικό χρόνο)."},{"gr":"Παρεσκευάζοντο ὅπως τά τείχη φυλάττοιεν.","an":"Ετοιμάζονταν για να φυλάνε τα τείχη. — Τελική με «ὅπως» + ευκτική πλαγίου λόγου (εξάρτηση από ιστορικό «παρεσκευάζοντο»)."},{"gr":"Οὕτω διάκειμαι, ὥστε οὐδέ δεῖπνον ἔχω.","an":"Βρίσκομαι σε τέτοια κατάσταση, ώστε δεν έχω ούτε φαγητό. — Αποτελεσματική με «ὥστε» + οριστική (πραγματικό αποτέλεσμα· προαναγγελία «οὕτω»)."},{"gr":"Εἰ καί χρήματα εὐποροῦμεν, οὐκ εὐτυχοῦμεν.","an":"Αν και έχουμε άφθονα χρήματα, δεν είμαστε ευτυχισμένοι. — Εναντιωματική με «εἰ καί» (πραγματική εναντίωση)."},{"gr":"Καί εἰ θαλάττης εἴργοιντο, δύναιντ' ἄν καλῶς διαζῆν.","an":"Ακόμη κι αν αποκλείονταν από τη θάλασσα, θα μπορούσαν να ζουν καλά. — Παραχωρητική με «καί εἰ» + ευκτική (υποθετική εναντίωση)."},{"gr":"Ὡς δ' ἄν μάθῃς ὅτι οὐδ' ἄν ὑμεῖς δικαίως οὔτε βασιλεῖ οὔτ' ἐμοί ἀπιστοίητε, ἀντάκουσον.","an":"Ξεν. Ἀνάβ. 2.5.16 — Για να μάθεις όμως ότι ούτε εσείς δίκαια θα δυσπιστούσατε ούτε στον βασιλιά ούτε σ' εμένα, άκουσε με τη σειρά σου. Τελική με «ὡς» (+ ἄν) + υποτακτική (σκοπός)."},{"gr":"Ὅπως μή ποιήσετε ὅ πολλάκις ὑμᾶς ἔβλαψε.","an":"Δημ. 4.20 — Προσέξτε να μην κάνετε αυτό που πολλές φορές σας έβλαψε. Τελική/βουλητική με «ὅπως μή» + οριστική μέλλοντα· άρνηση «μή»."}],"note":"Διάκριση τελικής/αποτελεσματικής: «ὥστε» = αποτέλεσμα, «ἵνα/ὅπως/ὡς» = σκοπός. «ὥστε + οριστική» τονίζει πραγματικό αποτέλεσμα· «ὥστε + απαρέμφατο» δηλώνει δυνατό/επιδιωκόμενο ή φυσικό επακόλουθο και είναι συντακτικά απαρεμφατική σύνταξη, όχι πρόταση με έγκλιση."},{"h":"Επιρρηματικές ΙΙΙ: Υποθετικές προτάσεις και οι υποθετικοί λόγοι","body":"<p>Η <b>υποθετική πρόταση</b> (ή <b>υπόθεση</b>) μαζί με την κύρια από την οποία εξαρτάται (την <b>απόδοση</b>) σχηματίζουν τον <b>υποθετικό λόγο</b>. Είναι το πιο τυποποιημένο κεφάλαιο: το είδος καθορίζεται από τον <b>συνδυασμό</b> εισαγωγής+εκφοράς της υπόθεσης με την εκφορά της απόδοσης.</p><ul><li><b>Εισαγωγή:</b> με <b>εἰ</b> (+ οριστική/ευκτική) ή με <b>ἐάν, ἄν, ἤν</b> (= εἰ+ἄν, + υποτακτική). Άρνηση της υπόθεσης: <b>μή</b>.</li></ul><h3>Τα έξι είδη του υποθετικού λόγου</h3><p>Διακρίνουμε: (1) το <b>πραγματικό</b>, (2) το <b>αντίθετο του πραγματικού</b> (μη πραγματικό), (3) την <b>προσδοκία/προσδοκώμενο</b>, (4) την <b>αόριστη επανάληψη στο παρόν-μέλλον</b>, (5) την <b>απλή σκέψη του λέγοντος</b>, (6) την <b>αόριστη επανάληψη στο παρελθόν</b>.</p>","table":{"title":"Οι έξι (6) υποθετικοί λόγοι: υπόθεση και απόδοση","cols":["Είδος","Υπόθεση (εἰ/ἐάν + ...)","Απόδοση","Σημασία"],"rows":[["1. Πραγματικό","εἰ + οριστική (κάθε χρόνου)","κάθε έγκλιση","Υπόθεση που θεωρείται πραγματική/απλώς διατυπώνεται"],["2. Αντίθετο του πραγματικού","εἰ + οριστική ιστορικού χρόνου","δυνητική οριστική (ιστ. χρόνος + ἄν)","Υπόθεση αντίθετη προς την πραγματικότητα"],["3. Προσδοκώμενο","ἐάν + υποτακτική","οριστική μέλλοντα (ή ισοδύναμο)","Κάτι που αναμένεται/προσδοκάται στο μέλλον"],["4. Αόριστη επανάληψη (παρόν-μέλλον)","ἐάν + υποτακτική","οριστική ενεστώτα (ή γνωμικός αόρ.)","Κάτι που επαναλαμβάνεται/ισχύει γενικά τώρα"],["5. Απλή σκέψη του λέγοντος","εἰ + ευκτική","δυνητική ευκτική (ευκτική + ἄν)","Υπόθεση ως απλή σκέψη/ενδεχόμενο"],["6. Αόριστη επανάληψη (παρελθόν)","εἰ + ευκτική","οριστική ιστορικού χρόνου","Κάτι που επαναλαμβανόταν στο παρελθόν"]]},"examples":[{"gr":"Εἰ θεοί εἰσιν, καί βωμοί εἰσιν.","an":"Αν υπάρχουν θεοί, υπάρχουν και βωμοί. — Υποθ. λόγος του πραγματικού (εἰ + οριστική / οριστική)."},{"gr":"Εἰ ταῦτα ἐποίησας, ἥμαρτες ἄν.","an":"Αν είχες κάνει αυτά, θα είχες σφάλει. — Αντίθετο του πραγματικού (εἰ + αόρ. οριστ. / δυνητική οριστ. με ἄν)."},{"gr":"Ἐάν ταῦτα ποιήσῃς, εὐτυχήσεις.","an":"Αν κάνεις αυτά, θα ευτυχήσεις. — Προσδοκώμενο (ἐάν + υποτακτική / μέλλοντας)."},{"gr":"Εἴ τις φιλοπονοίη, εὐτυχοίη ἄν.","an":"Αν κανείς ήταν εργατικός, θα ευτυχούσε. — Απλή σκέψη του λέγοντος (εἰ + ευκτική / δυνητική ευκτική)."},{"gr":"Εἴπερ γε Δαρείου ἐστί παῖς, οὐκ ἀμαχεί ταῦτα ἐγώ λήψομαι.","an":"Ξεν. Ἀνάβ. 1.7.9 — Αν πράγματι είναι γιος του Δαρείου, δεν θα τα πάρω αυτά αμαχητί. Υποθ. λόγος του πραγματικού (εἰ + οριστική «ἐστί» / οριστική μέλλοντα «λήψομαι»)."},{"gr":"Ἤν ἐγγύς ἔλθῃ θάνατος, οὐδείς βούλεται θνῄσκειν.","an":"(τύπου Εὐρ./παροιμ.) — Αν πλησιάσει ο θάνατος, κανείς δεν θέλει να πεθάνει. Αόριστη επανάληψη στο παρόν-μέλλον (ἤν=ἐάν + υποτακτική / οριστική ενεστώτα)."}],"note":"Συχνή παγίδα: η εκφορά της απόδοσης (κύριας) είναι αυτή που τελικά καθορίζει το είδος, μαζί με την υπόθεση. Όταν η υπόθεση είναι «λανθάνουσα» (κρυμμένη σε μετοχή, εμπρόθετο, αναφορική κ.λπ.), αναλύουμε σε εἰ/ἐάν + κατάλληλη έγκλιση. Το «ἄν» της απόδοσης (δυνητικό) δεν συγχέεται με το «ἄν» της υπόθεσης (= εἰ+ἄν στην υποτακτική)."},{"h":"Σύνδεση προτάσεων: παράταξη, υπόταξη, ασύνδετο","body":"<p>Μέσα στην περίοδο οι προτάσεις συνδέονται μεταξύ τους με τρεις τρόπους.</p><h3>1. Ασύνδετο σχήμα</h3><p>Οι προτάσεις τοποθετούνται η μία δίπλα στην άλλη <b>χωρίς συνδετική λέξη</b> (απλή παράθεση με κόμμα). Δίνει ζωντάνια, ταχύτητα, ένταση (ασύνδετο σχήμα ως υφολογικό μέσο). Σχήμα: πρόταση , πρόταση , πρόταση.</p><h3>2. Παρατακτική σύνδεση (παράταξη)</h3><p>Συνδέονται με <b>παρατακτικούς συνδέσμους</b> προτάσεις <b>όμοιες μεταξύ τους ως προς τη βαθμίδα</b>: κύρια με κύρια, ή δευτερεύουσα με δευτερεύουσα του ίδιου είδους. Η παράταξη δεν δημιουργεί εξάρτηση· απλώς αντιπαραθέτει ισοδύναμες προτάσεις. Είδη παρατακτικών συνδέσμων:</p><ul><li><b>Συμπλεκτικοί</b> (προσθέτουν): καί, τε, οὐδέ, μηδέ, οὔτε...οὔτε, μήτε...μήτε.</li><li><b>Αντιθετικοί / εναντιωματικοί</b> (αντιπαραθέτουν): ἀλλά, δέ, μέν...δέ, ὅμως, μέντοι, καίτοι, ἀτάρ.</li><li><b>Διαζευκτικοί</b> (χωρίζουν / προσφέρουν εκλογή): ἤ, ἤτοι, ἤ...ἤ, εἴτε...εἴτε.</li><li><b>Αιτιολογικοί</b> (εξηγούν): γάρ (και ὡς, ἐπεί στην αρχή περιόδου).</li><li><b>Συμπερασματικοί</b> (συνάγουν συμπέρασμα): ἄρα, οὖν, δή, γοῦν, τοίνυν, οὔκουν, οὐκοῦν, τοιγάρτοι, τοιγαροῦν, ὥστε (στην αρχή περιόδου).</li></ul><h3>3. Υποτακτική σύνδεση (υπόταξη)</h3><p>Μια <b>δευτερεύουσα</b> πρόταση συνδέεται-υποτάσσεται σε μια κύρια (ή σε άλλη δευτερεύουσα), εισαγόμενη με <b>υποτακτικό σύνδεσμο</b> ή αναφορική/ερωτηματική λέξη. Σχήμα: κύρια + υποτακτικός σύνδεσμος + δευτερεύουσα. Είδη υποτακτικών συνδέσμων (κατά το είδος που εισάγουν): <b>ειδικοί</b> (ὅτι, ὡς)· <b>ενδοιαστικοί/διστακτικοί</b> (μή, μή οὐ)· <b>χρονικοί</b> (ὅτε, ἐπεί, πρίν, ἕως...)· <b>αιτιολογικοί</b> (ὅτι, διότι, ἐπεί...)· <b>τελικοί</b> (ἵνα, ὅπως, ὡς)· <b>αποτελεσματικοί/συμπερασματικοί</b> (ὥστε, ὡς)· <b>υποθετικοί</b> (εἰ, ἐάν)· <b>εναντιωματικοί/παραχωρητικοί</b> (εἰ καί, καί εἰ...).</p>","table":{"title":"Παρατακτικοί σύνδεσμοι κατά κατηγορία","cols":["Κατηγορία","Λειτουργία","Κύριοι σύνδεσμοι"],"rows":[["Συμπλεκτικοί","πρόσθεση","καί, τε, οὐδέ, μηδέ, οὔτε...οὔτε, μήτε...μήτε"],["Αντιθετικοί","αντίθεση","ἀλλά, δέ, μέν...δέ, ὅμως, μέντοι, ἀτάρ"],["Διαζευκτικοί","διάζευξη/εκλογή","ἤ, ἤτοι, ἤ...ἤ, εἴτε...εἴτε"],["Αιτιολογικοί","αιτιολόγηση","γάρ"],["Συμπερασματικοί","συμπέρασμα","ἄρα, οὖν, δή, τοίνυν, γοῦν, οὐκοῦν, ὥστε"]]},"examples":[{"gr":"Συμβαλόντες τάς ἀσπίδας ἐωθοῦντο, ἐμάχοντο, ἀπέκτεινον, ἀπέθνῃσκον.","an":"Συγκρούοντας τις ασπίδες έσπρωχναν, μάχονταν, σκότωναν, σκοτώνονταν. — Ασύνδετο σχήμα τεσσάρων κυρίων προτάσεων (ζωντάνια, ένταση μάχης)."},{"gr":"Ἐν Ἀθήναις διδάσκουσι καί νουθετοῦσι τούς παῖδας.","an":"Στην Αθήνα διδάσκουν και νουθετούν τα παιδιά. — Παρατακτική συμπλεκτική σύνδεση δύο κυρίων με «καί»."},{"gr":"Οὗτος μέν δίκαιός ἐστιν, ἐκεῖνος δέ ἄδικος.","an":"Αυτός είναι δίκαιος, εκείνος όμως άδικος. — Παρατακτική αντιθετική σύνδεση με «μέν ... δέ»."},{"gr":"Πάντες ἄρα οἱ ἄνθρωποι θνητοί εἰσιν.","an":"Άρα όλοι οι άνθρωποι είναι θνητοί. — Παρατακτική συμπερασματική σύνδεση με «ἄρα» (συμπέρασμα από τα προηγούμενα)."},{"gr":"Πολλά ἐπιτηδεύουσιν ἐν τῷ βίῳ, ἵνα πορίζωνται τά ἀναγκαῖα.","an":"Επιδίδονται σε πολλά στη ζωή, για να εξασφαλίζουν τα αναγκαία. — Υποτακτική σύνδεση: κύρια + τελική δευτερεύουσα («ἵνα» + υποτακτική)."},{"gr":"Οἱ μέν αὐτῶν ἐτόξευον, οἱ δέ ἐσφενδόνων, οἱ δέ λίθους ἔρριπτον.","an":"(τύπου Ξεν. Ἀνάβ.) — Άλλοι από αυτούς τόξευαν, άλλοι σφεντόνιζαν, άλλοι έριχναν πέτρες. Παρατακτική σύνδεση τριών κυρίων με μεριστικό «οἱ μέν ... οἱ δέ ... οἱ δέ»."}],"note":"Προσοχή: παρατάσσονται ΜΟΝΟ όμοιες βαθμίδες (κύρια+κύρια, δευτ.+δευτ. ίδιου είδους). Ορισμένοι σύνδεσμοι είναι «εγκλιτικοί/μετά-θετικοί» και ΔΕΝ μπαίνουν πρώτοι στην πρόταση: γάρ, δέ, οὖν, μέν, τε, τοίνυν — τοποθετούνται δεύτεροι. Το «καί», «ὡς», «ἐπεί», «ὥστε» είναι πολυλειτουργικά (παρατακτικά ή υποτακτικά κατά περίπτωση)."}]);
  T("syn-eidikes", [{"h":"Τι είναι οι ειδικές προτάσεις — ορισμός και φύση","body":"<p>Οι <b>ειδικές προτάσεις</b> είναι <b>δευτερεύουσες ονοματικές</b> προτάσεις. Ονομάζονται «ειδικές» επειδή χρησιμεύουν για να <b>ειδικεύσουν</b>, δηλαδή να συγκεκριμενοποιήσουν, το γενικό και αόριστο νόημα ενός ρήματος (κυρίως λεκτικού, γνωστικού, αισθητικού ή δοξαστικού) ή μιας δεικτικής αντωνυμίας της κύριας πρότασης.</p><p>Π.χ. το ρήμα <i>λέγω</i> από μόνο του είναι αόριστο: <i>λέγω</i> — τι λέω; Η ειδική πρόταση δίνει το <b>περιεχόμενο</b> της λεκτικής ή νοητικής ενέργειας: <i>λέγω <b>ὅτι ὁ Κῦρος τέθνηκεν</b></i>. Έτσι η ειδική πρόταση λειτουργεί όπως ένα ουσιαστικό-αντικείμενο ή υποκείμενο· γι’ αυτό κατατάσσεται στις <b>ονοματικές</b> δευτερεύουσες (μαζί με τις πλάγιες ερωτηματικές και τις βουλητικές/ενδοιαστικές).</p><p>Στον <b>πλάγιο λόγο</b> η ειδική πρόταση είναι το βασικό μέσο για να μεταφερθεί μια <b>κρίση</b> (κατάφαση ή απόφαση) που στον ευθύ λόγο ήταν αυτοτελής κύρια πρόταση κρίσεως. Δηλαδή: ευθύς λόγος <i>«Ὁ Κῦρος τέθνηκεν»</i> &rarr; πλάγιος λόγος <i>λέγουσιν <b>ὅτι ὁ Κῦρος τέθνηκεν</b></i>. Αυτό εξηγεί και τη στενή σχέση της με τον <b>ειδικό απαρέμφατο</b> (<i>λέγουσι τόν Κῦρον τεθνηκέναι</i>), που είναι ισοδύναμος τρόπος μεταφοράς κρίσεως.</p><p><b>Άρνηση:</b> Επειδή εκφράζουν πραγματική κρίση/γεγονός, οι ειδικές προτάσεις δέχονται την άρνηση <b>οὐ (οὐκ, οὐχ)</b>, ποτέ <i>μή</i> — και αυτό είναι ένα από τα ασφαλέστερα κριτήρια αναγνώρισής τους.</p>","examples":[{"gr":"Οὗτοι ἔλεγον ὅτι Κῦρος τέθνηκεν.","an":"Αυτοί έλεγαν ότι ο Κύρος έχει πεθάνει. — Κύρια: «Οὗτοι ἔλεγον». Ειδική: «ὅτι Κῦρος τέθνηκεν», αντικείμενο στο λεκτικό «ἔλεγον», εισάγεται με «ὅτι», εκφέρεται με οριστική παρακειμένου (πραγματικό γεγονός)."},{"gr":"Δείξωμεν τοῖς βαρβάροις ὅτι δυνάμεθα τούς ἐχθρούς τιμωρεῖσθαι.","an":"Ας αποδείξουμε στους βαρβάρους ότι μπορούμε να τιμωρούμε τους εχθρούς. — Ειδική «ὅτι δυνάμεθα...» ως αντικείμενο στο δεικτικό «δείξωμεν»· «ὅτι» γιατί η κρίση παρουσιάζεται ως αντικειμενική/βέβαιη."},{"gr":"Οἱ δέ εἶπον ὅτι ἱκανοί ἐσμεν.","an":"Ξεν. Ἀνάβ. 5.4.10 — «αυτοί είπαν ότι είμαστε ικανοί». Λεκτικό «εἶπον» &rarr; ειδική-αντικείμενο «ὅτι ἱκανοί ἐσμεν» με οριστική ενεστώτα· διατήρηση του προσώπου του ευθέος λόγου."},{"gr":"Ἀπεκρίνατο ὅτι οὔ.","an":"Ξεν. Ἀνάβ. 1.6.7 — «αποκρίθηκε πως όχι». Σύντομη ειδική-αντικείμενο μετά το λεκτικό «ἀπεκρίνατο»· άρνηση «οὔ» (ποτέ μή), δείγμα του κριτηρίου της άρνησης."},{"gr":"Φησίν ὅτι οὐδέν ἠδίκηκεν.","an":"«Λέει ότι σε τίποτε δεν έχει αδικήσει». — Λεκτικό «φησίν» &rarr; ειδική-αντικείμενο με οριστική παρακειμένου· άρνηση «οὐδέν» (= οὐ), όχι μή (τύπου Λυσίου)."}],"note":"Προσοχή στον όρο: «ειδική» πρόταση ≠ «ειδικό» απαρέμφατο μόνο ονοματικά — και τα δύο μεταφέρουν κρίση στον πλάγιο λόγο, αλλά η ειδική είναι ολόκληρη πρόταση με ρήμα σε προσωπική έγκλιση, ενώ το ειδικό απαρέμφατο έχει απαρέμφατο. Η σύγχυση είναι συχνή λάθος-παγίδα στις εξετάσεις."},{"h":"Εισαγωγή: οι σύνδεσμοι ὅτι και ὡς","body":"<p>Οι ειδικές προτάσεις εισάγονται με τους δύο <b>ειδικούς συνδέσμους</b>:</p><ul><li><b>ὅτι</b> — όταν ο ομιλητής παρουσιάζει το περιεχόμενο της πρότασης ως <b>αντικειμενικό, βέβαιο, πραγματικό</b>. Είναι ο πιο συνηθισμένος και ο πιο «ουδέτερος» σύνδεσμος.</li><li><b>ὡς</b> — όταν ο ομιλητής παρουσιάζει το περιεχόμενο ως <b>υποκειμενικό</b>, ως προσωπική γνώμη ή ισχυρισμό άλλου, συχνά με χροιά <b>αμφιβολίας, επιφύλαξης ή ψεύδους</b> («τάχα, δήθεν»). Είναι το ισοδύναμο ενός εισαγωγικού «πως / ότι δήθεν».</li></ul><p>Αυτή η διάκριση αντανακλά την <b>υποκειμενική στάση</b> του ομιλητή απέναντι στην κρίση που μεταφέρει, όχι αντικειμενικό κανόνα της γλώσσας· γι’ αυτό συχνά και το <i>ὅτι</i> και το <i>ὡς</i> μεταφράζονται απλώς «ότι».</p><p>Σε ορισμένα κείμενα συναντάται και ο σύνδεσμος <b>ὅπως</b> με ειδική σημασία (σπανιότερα), ενώ ο <b>διπλός σύνδεσμος ὡς … ὅτι</b> ή το <i>ὡς</i> με υπερθετικό δεν αφορά εδώ. Η σχολική παράδοση εστιάζει σταθερά στο δίπολο <b>ὅτι / ὡς</b>.</p><p>Το <i>ὅτι</i> μπορεί επίσης να λειτουργεί ως <b>ὅτι recitativum</b> (αναφορικό-εισαγωγικό ευθέος λόγου), εισάγοντας αυτούσια τα λόγια κάποιου· τότε δεν είναι κανονική ειδική πρόταση πλαγίου λόγου αλλά εισαγωγή κατά λέξη παράθεσης (π.χ. <i>εἶπεν ὅτι· «οὐκ ἄν ἔλθοιμι»</i>).</p>","examples":[{"gr":"Πυνθάνομαι ὡς χρήματα εἴληφεν Αἰσχίνης.","an":"Πληροφορούμαι ότι (τάχα) έχει πάρει χρήματα ο Αισχίνης. — Το «ὡς» δηλώνει ότι ο ομιλητής δεν εγγυάται την αλήθεια της είδησης· αποδίδει την πληροφορία ως φήμη/ισχυρισμό."},{"gr":"Λέγει ὅτι Περδίκκας πρῶτος ἐνέβαλεν ἐς τήν τῶν Θηβαίων.","an":"Λέει ότι ο Περδίκκας πρώτος εισέβαλε στη χώρα των Θηβαίων. — Το «ὅτι» παρουσιάζει το γεγονός ως αντικειμενικό· εκφορά με οριστική αορίστου."},{"gr":"Ἔλεγον ὡς οὐ δεῖ αὐτούς ἐκπλεῖν.","an":"«Έλεγαν πως (τάχα) δεν πρέπει αυτοί να αποπλεύσουν». — Το «ὡς» χρωματίζει την κρίση ως ισχυρισμό άλλων, με επιφύλαξη ως προς το κύρος της· άρνηση «οὐ» (ειδική, όχι τελική) (τύπου Θουκυδίδου)."},{"gr":"Οἶδα ὅτι ὑμεῖς ἐμοί οὐ πείθεσθε.","an":"«Γνωρίζω ότι εσείς δεν με ακούτε». — Γνωστικό «οἶδα» &rarr; ειδική με «ὅτι» (αντικειμενική, βέβαιη κρίση)· οριστική ενεστώτα, άρνηση «οὐ»."}],"table":{"title":"Οι εισαγωγικοί σύνδεσμοι των ειδικών προτάσεων","cols":["Σύνδεσμος","Στάση ομιλητή","Χροιά","Μετάφραση"],"rows":[["ὅτι","αντικειμενική","βέβαιο, πραγματικό γεγονός","ότι, πως"],["ὡς","υποκειμενική","γνώμη / αμφιβολία / δήθεν","ότι (τάχα, δήθεν)"]]},"note":"Παγίδα: το «ὡς» είναι πολυσήμαντο — εισάγει επίσης αιτιολογικές, τελικές, χρονικές, αναφορικές, συμπερασματικές και απλές αναφορικές προτάσεις, καθώς και λειτουργεί ως πρόθεση/επίρρημα. Μόνο όταν εξαρτάται από λεκτικό/γνωστικό/αισθητικό ρήμα και μεταφέρει κρίση είναι ειδικός σύνδεσμος."},{"h":"Ρήματα εξάρτησης: από τι κρέμονται οι ειδικές προτάσεις","body":"<p>Η ειδική πρόταση δεν στέκεται μόνη· εξαρτάται πάντοτε από ένα <b>ρηματικό τύπο εξάρτησης</b> που σημαίνει <i>λέω, γνωρίζω, αντιλαμβάνομαι, νομίζω, δείχνω</i>. Τα ρήματα αυτά είναι τα ίδια που συντάσσονται και με ειδικό απαρέμφατο ή με κατηγορηματική μετοχή. Διακρίνονται σε κατηγορίες:</p><h3>1. Λεκτικά (verba dicendi)</h3><p><i>λέγω, φημί, εἶπον, ἀγγέλλω / ἀπαγγέλλω / ἀναγγέλλω, ἀποκρίνομαι, διδάσκω, δηλῶ, μαρτυρῶ, κηρύττω, βοῶ, διηγοῦμαι</i> και απρόσωπα <i>λέγεται, ἀγγέλλεται, δῆλόν ἐστι</i>.</p><h3>2. Γνωστικά / διανοητικά (verba sentiendi-mentis)</h3><p><i>γιγνώσκω, οἶδα, ἐπίσταμαι, μανθάνω, πυνθάνομαι, ἐνθυμοῦμαι, μέμνημαι / ἀναμιμνῄσκομαι, ἐννοῶ, λογίζομαι, ἀγνοῶ</i> (με άρνηση).</p><h3>3. Αισθητικά (verba sentiendi)</h3><p><i>αἰσθάνομαι, ὁρῶ, ἀκούω</i> και απρόσωπα <i>σαφές ἐστι, φανερόν ἐστι</i>.</p><h3>4. Δοξαστικά (verba putandi)</h3><p><i>νομίζω, οἴομαι (οἶμαι), ὑπολαμβάνω, ἡγοῦμαι, ἐλπίζω, πιστεύω, δοκῶ</i>.</p><h3>5. Δεικτικά (verba demonstrandi)</h3><p><i>δείκνυμι, ἀποδείκνυμι, ἐπιδείκνυμι, σημαίνω</i>.</p><p>Όταν το ρήμα εξάρτησης είναι <b>απρόσωπο</b> (<i>δῆλόν ἐστι, φανερόν ἐστι, λέγεται, ἀγγέλλεται</i>), η ειδική πρόταση δεν είναι αντικείμενο αλλά <b>υποκείμενο</b> (βλ. επόμενη ενότητα).</p>","examples":[{"gr":"Σχεδόν ἐγίγνωσκον ὅτι εἴη που πλησίον τό στράτευμα τῶν πολεμίων.","an":"Σχεδόν αντιλαμβάνονταν ότι κάπου κοντά ήταν το στράτευμα των εχθρών. — Γνωστικό ρήμα «ἐγίγνωσκον» (ιστορικός χρόνος) &rarr; ειδική με ευκτική του πλαγίου λόγου «εἴη»."},{"gr":"Οἶμαι γάρ ὅτι πάντες ἄνθρωποι περί τόν τόπον τοῦτον εἰώθασι διατρίβειν.","an":"Νομίζω, βέβαια, ότι όλοι οι άνθρωποι συνηθίζουν να διατρίβουν σ’ αυτόν τον τόπο. — Δοξαστικό «οἶμαι» &rarr; ειδική-αντικείμενο με οριστική παρακειμένου «εἰώθασι»."},{"gr":"Καί τοῦτο μέν οὐκ ἀγνοῶ, ὅτι οὐδέν μοι ἀρκέσει ὅδε ὁ βωμός.","an":"Και τούτο δεν το αγνοώ, ότι δηλαδή τίποτε δεν θα μου είναι αρκετός αυτός ο βωμός. — Γνωστικό «ἀγνοῶ»· η ειδική επεξηγεί τη δεικτική αντωνυμία «τοῦτο»."},{"gr":"Ἤκουσεν ὅτι Τισσαφέρνης σύν Κύρῳ ἀναβαίνοι.","an":"«Άκουσε ότι ο Τισσαφέρνης ανέβαινε μαζί με τον Κύρο». — Αισθητικό «ἤκουσεν» (αντίληψη με τη διάνοια, όχι άμεση αίσθηση) &rarr; ειδική-αντικείμενο· μετά ιστορικό χρόνο ευκτική πλαγίου λόγου «ἀναβαίνοι» (τύπου Ξεν. Ἀνάβ. 1)."},{"gr":"Δηλώσω ὑμῖν ὅτι καί ὁ πατήρ αὐτοῦ ταὐτά ἔπραττεν.","an":"«Θα σας δείξω ότι και ο πατέρας του τα ίδια έπραττε». — Λεκτικό/δεικτικό «δηλώσω» &rarr; ειδική-αντικείμενο με οριστική παρατατικού (πραγματικό παρελθόν)."}],"table":{"title":"Κατηγορίες ρημάτων εξάρτησης των ειδικών προτάσεων","cols":["Κατηγορία","Σημασία","Χαρακτηριστικά ρήματα"],"rows":[["Λεκτικά","λέω, ανακοινώνω","λέγω, φημί, ἀγγέλλω, ἀποκρίνομαι, διδάσκω, δηλῶ, μαρτυρῶ, κηρύττω"],["Γνωστικά / διανοητικά","γνωρίζω, θυμάμαι, μαθαίνω","γιγνώσκω, οἶδα, ἐπίσταμαι, μανθάνω, πυνθάνομαι, μέμνημαι, ἐνθυμοῦμαι, ἀγνοῶ"],["Αισθητικά","αντιλαμβάνομαι","αἰσθάνομαι, ὁρῶ, ἀκούω, σαφές/φανερόν ἐστι"],["Δοξαστικά","νομίζω, ελπίζω","νομίζω, οἴομαι, ὑπολαμβάνω, ἡγοῦμαι, ἐλπίζω, πιστεύω"],["Δεικτικά","δείχνω, αποδεικνύω","δείκνυμι, ἀποδείκνυμι, ἐπιδείκνυμι, σημαίνω"]]},"note":"Τα ίδια ρήματα συντάσσονται εναλλακτικά με ειδικό απαρέμφατο ή κατηγορηματική μετοχή. Η επιλογή ειδικής πρότασης (έναντι απαρεμφάτου) είναι συχνά υφολογική· τα αισθητικά (ὁρῶ, ἀκούω, αἰσθάνομαι) προτιμούν κατηγορηματική μετοχή, αλλά δέχονται και ειδική όταν δηλώνεται αντίληψη με τη διάνοια (όχι άμεση αίσθηση)."},{"h":"Εκφορά και εγκλίσεις","body":"<p>Επειδή η ειδική πρόταση μεταφέρει μια <b>κρίση</b> (όπως οι κύριες προτάσεις κρίσεως), εκφέρεται με εγκλίσεις που δηλώνουν το πραγματικό ή το δυνατό. Οι εγκλίσεις αυτές είναι τέσσερις:</p><h3>1. Οριστική</h3><p>Δηλώνει κάτι <b>πραγματικό</b> ή κάτι που ο ομιλητής θεωρεί βέβαιο. Είναι η συνηθέστερη εκφορά. Μπορεί να βρίσκεται σε οποιονδήποτε χρόνο, ανάλογα με τη χρονική σχέση προς το ρήμα εξάρτησης.</p><h3>2. Δυνητική οριστική (οριστική + ἄν)</h3><p>Δηλώνει το <b>μη πραγματικό</b> — κάτι που θα μπορούσε να συμβεί στο παρελθόν αλλά δεν συνέβη (απραγματοποίητο, αντίθετο προς την πραγματικότητα).</p><h3>3. Δυνητική ευκτική (ευκτική + ἄν)</h3><p>Δηλώνει το <b>δυνατό-πιθανό</b> στο παρόν ή στο μέλλον, υπό προϋποθέσεις.</p><h3>4. Ευκτική του πλαγίου λόγου</h3><p>Εμφανίζεται όταν το ρήμα εξάρτησης είναι σε <b>ιστορικό χρόνο</b> (παρατατικό, αόριστο, υπερσυντέλικο). Τότε η οριστική του ευθέος λόγου μπορεί προαιρετικά να τραπεί σε ευκτική του πλαγίου λόγου, που υποδηλώνει ότι η κρίση ανήκει στο πρόσωπο του παρελθόντος (όχι στον ομιλητή) — έχει χροιά <b>υποκειμενική / αβέβαιη</b>.</p><p><b>Σημαντικό:</b> η ευκτική του πλαγίου λόγου είναι <b>προαιρετική</b>· ο συγγραφέας μπορεί να κρατήσει την οριστική ακόμη και μετά από ιστορικό χρόνο, για ζωντάνια και έμφαση στην αντικειμενική αλήθεια του γεγονότος (<i>ἔλεγον ὅτι ... ἐστιν</i> δίπλα στο <i>ἔλεγον ὅτι ... εἴη</i>).</p>","examples":[{"gr":"Δῆλον ἦν ὅτι ῥᾳδίως ἄν ἐδύναντο τούς πολεμίους νικᾶν.","an":"Ήταν φανερό ότι εύκολα θα μπορούσαν να νικούν τους εχθρούς (αλλά δεν το έκαναν). — Δυνητική οριστική «ἄν ἐδύναντο»: μη πραγματικό του παρελθόντος."},{"gr":"Οἶδα ὅτι πάντες ἄν ὁμολογήσαιτε.","an":"Γνωρίζω ότι όλοι θα συμφωνούσατε. — Δυνητική ευκτική «ἄν ὁμολογήσαιτε»: δυνατό-πιθανό στο παρόν/μέλλον."},{"gr":"Ἔλεγον ὅτι βασιλεύς σφίσι φίλος ἔσοιτο.","an":"Έλεγαν ότι ο βασιλιάς θα ήταν φίλος τους. — Ρήμα εξάρτησης σε ιστορικό χρόνο «ἔλεγον» &rarr; ευκτική του πλαγίου λόγου «ἔσοιτο» (μέλλοντα). Ο ευθύς λόγος ήταν: «βασιλεύς ἡμῖν φίλος ἔσται»."},{"gr":"Δῆλόν ἐστιν ὅτι οὐκ ἄν προὔλεγεν, εἰ μή ἐπίστευεν ἀληθεύσειν.","an":"Είναι φανερό ότι δεν θα προέλεγε, αν δεν πίστευε ότι θα έλεγε αλήθεια. — Δυνητική οριστική «ἄν προὔλεγεν» μέσα στην ειδική· η άρνηση είναι «οὐκ»."},{"gr":"Πρῶτον μέν αὐτό ὑμῖν τοῦτο γενέσθω τεκμήριον, ὅτι κατεγνώκει ἄν αὐτοῦ ὁ Λυσιθείδης.","an":"Λυσίας (τύπου) — «πρώτα ας γίνει σ’ εσάς τεκμήριο αυτό, ότι θα τον είχε καταδικάσει ο Λυσιθείδης». Επεξηγηματική ειδική στο «τοῦτο» με δυνητική οριστική «κατεγνώκει ἄν» (μη πραγματικό του παρελθόντος)."},{"gr":"Σχεδόν ἐγίγνωσκον ὅτι εἴη που πλησίον τό στράτευμα.","an":"«Σχεδόν αντιλαμβάνονταν ότι κάπου κοντά ήταν το στράτευμα». — Ιστορικός χρόνος «ἐγίγνωσκον» &rarr; ευκτική πλαγίου λόγου «εἴη» (χωρίς ἄν: όχι δυνητική)."}],"table":{"title":"Εκφορά ειδικών προτάσεων ανά έγκλιση","cols":["Έγκλιση","Σημασία","Προϋπόθεση"],"rows":[["Οριστική","πραγματικό / βέβαιο","κάθε χρόνος εξάρτησης"],["Δυνητική οριστική (+ ἄν)","μη πραγματικό του παρελθόντος","απραγματοποίητη υπόθεση"],["Δυνητική ευκτική (+ ἄν)","δυνατό-πιθανό παρόντος/μέλλοντος","υπό προϋποθέσεις"],["Ευκτική πλαγίου λόγου","υποκειμενική / αβέβαιη κρίση","μετά από ιστορικό χρόνο (προαιρετική)"]]},"note":"Η ευκτική του πλαγίου λόγου ΔΕΝ παίρνει «ἄν»· αν δεις «ευκτική + ἄν» πρόκειται για δυνητική ευκτική, όχι ευκτική πλαγίου λόγου. Επίσης: μετά από ιστορικό χρόνο η διατήρηση της οριστικής (αντί ευκτικής) είναι απολύτως ορθή και πολύ συχνή στον Θουκυδίδη/Ξενοφώντα."},{"h":"Συντακτικός ρόλος μέσα στην περίοδο","body":"<p>Ως ονοματική πρόταση, η ειδική επέχει θέση ονόματος και μπορεί να λειτουργεί με τρεις βασικούς τρόπους:</p><h3>α) Αντικείμενο</h3><p>Όταν εξαρτάται από <b>προσωπικό</b> μεταβατικό ρήμα λεκτικό, γνωστικό, αισθητικό, δοξαστικό ή δεικτικό. Είναι ο πιο συνηθισμένος ρόλος. Ισοδυναμεί με το αντικείμενο που θα έδινε ένα ειδικό απαρέμφατο.</p><h3>β) Υποκείμενο</h3><p>Όταν εξαρτάται από <b>απρόσωπο</b> ρήμα ή απρόσωπη έκφραση (<i>δῆλόν ἐστι, φανερόν ἐστι, σαφές ἐστι, λέγεται, ἀγγέλλεται, ὡμολόγηται</i>). Η ειδική πρόταση είναι τότε το λογικό υποκείμενο της απρόσωπης έκφρασης.</p><h3>γ) Επεξήγηση</h3><p>Όταν στην κύρια πρόταση υπάρχει μια <b>δεικτική αντωνυμία ουδετέρου γένους</b> (<i>τοῦτο, ταῦτα, ἐκεῖνο, τόδε</i>) ή ένα γενικό-αόριστο ουσιαστικό, και η ειδική πρόταση αναλύει-επεξηγεί το περιεχόμενό της. Η δεικτική αντωνυμία είναι ο κανονικός όρος (αντικείμενο/υποκείμενο) και η ειδική απλώς τον διασαφηνίζει.</p><p>Σπανιότερα η ειδική μπορεί να λειτουργήσει και ως <b>παράθεση</b> ή να αντιστοιχεί σε άλλον ονοματικό όρο, αλλά τα τρία παραπάνω είναι τα κανονικά της σχολικού συντακτικού.</p>","examples":[{"gr":"Οὐ γάρ ἠγγέλθη αὐτοῖς ὅτι τεθνηκότες εἶεν.","an":"Διότι δεν τους είχε αναγγελθεί ότι είχαν σκοτωθεί. — Απρόσωπο «ἠγγέλθη» &rarr; η ειδική «ὅτι τεθνηκότες εἶεν» είναι ΥΠΟΚΕΙΜΕΝΟ· εκφορά με ευκτική πλαγίου λόγου (περιφραστική) μετά ιστορικό χρόνο."},{"gr":"Δῆλόν ἐστιν ὅτι μᾶλλον ἡσθήσεσθε τοῖς παρακαλοῦσιν ὑμᾶς ἐπί τόν πόλεμον.","an":"Είναι φανερό ότι θα ευχαριστηθείτε περισσότερο με αυτούς που σας προτρέπουν στον πόλεμο. — Απρόσωπη έκφραση «δῆλόν ἐστιν»· η ειδική = ΥΠΟΚΕΙΜΕΝΟ."},{"gr":"Ταῦτα λέγω, ὡς τό παράπαν οὐ νομίζεις θεούς.","an":"Αυτά λέω, ότι δηλαδή καθόλου δεν πιστεύεις σε θεούς. — Δεικτική αντωνυμία «ταῦτα» = αντικείμενο του «λέγω»· η ειδική «ὡς ... οὐ νομίζεις» την ΕΠΕΞΗΓΕΙ."},{"gr":"Οὗτοι ἔλεγον ὅτι Κῦρος τέθνηκεν.","an":"Αυτοί έλεγαν ότι ο Κύρος είχε πεθάνει. — Προσωπικό λεκτικό «ἔλεγον» &rarr; η ειδική = ΑΝΤΙΚΕΙΜΕΝΟ."},{"gr":"Λέγεται ὅτι Κῦρος ἐνταῦθα κατέλυσεν.","an":"«Λέγεται ότι ο Κύρος εδώ κατέλυσε». — Απρόσωπο παθητικό «λέγεται» &rarr; η ειδική «ὅτι ... κατέλυσεν» είναι ΥΠΟΚΕΙΜΕΝΟ· οριστική αορίστου (τύπου Ξεν.)."},{"gr":"Φανερόν γάρ ἐστιν ὅτι οὐκ ἄν προεῖλεν Φίλιππος τόν πόλεμον.","an":"«Διότι είναι φανερό ότι ο Φίλιππος δεν θα προτιμούσε τον πόλεμο». — Απρόσωπη έκφραση «φανερόν ἐστιν» &rarr; ειδική-ΥΠΟΚΕΙΜΕΝΟ με δυνητική οριστική «ἄν προεῖλεν» (τύπου Δημοσθένους)."}],"note":"Κανόνας-κλειδί: προσωπικό ρήμα εξάρτησης &rarr; η ειδική είναι ΑΝΤΙΚΕΙΜΕΝΟ· απρόσωπο ρήμα/έκφραση &rarr; η ειδική είναι ΥΠΟΚΕΙΜΕΝΟ· προηγείται δεικτική αντωνυμία ουδετέρου &rarr; η ειδική είναι ΕΠΕΞΗΓΗΣΗ. Αυτή η τριχοτόμηση ζητείται σχεδόν πάντα στην ανάλυση."},{"h":"Διάκριση ειδικών από αιτιολογικές (και άλλες με ὅτι/ὡς)","body":"<p>Το μεγαλύτερο πρόβλημα αναγνώρισης προκύπτει επειδή <b>οι ίδιοι σύνδεσμοι ὅτι και ὡς</b> εισάγουν και <b>ειδικές</b> και <b>αιτιολογικές</b> προτάσεις. Η διάκριση γίνεται με βάση τέσσερα κριτήρια:</p><h3>1. Είδος ρήματος εξάρτησης</h3><ul><li><b>Ειδική:</b> εξαρτάται από <b>λεκτικό, γνωστικό, αισθητικό, δοξαστικό, δεικτικό</b> ρήμα (λέω/γνωρίζω/νομίζω/δείχνω). Δίνει το <i>περιεχόμενο</i> αυτού που λέγεται ή νοείται.</li><li><b>Αιτιολογική:</b> εξαρτάται από ρήμα ή έκφραση που δηλώνει <b>ψυχικό πάθος ή αξιολογική κρίση</b> (<i>χαίρω, λυποῦμαι, ἄχθομαι, ἀγανακτῶ, θαυμάζω, αἰσχύνομαι</i>) ή από οποιαδήποτε πρόταση της οποίας δηλώνει την <b>αιτία</b>. Απαντά στην ερώτηση «γιατί;».</li></ul><h3>2. Συντακτικός ρόλος</h3><ul><li><b>Ειδική:</b> ονοματική — λειτουργεί ως <b>αντικείμενο / υποκείμενο / επεξήγηση</b> (αναγκαίο συμπλήρωμα του ρήματος).</li><li><b>Αιτιολογική:</b> επιρρηματική — λειτουργεί ως <b>επιρρηματικός προσδιορισμός της αιτίας</b> (δεν συμπληρώνει το νόημα του ρήματος, το αιτιολογεί).</li></ul><h3>3. Δοκιμή αντικατάστασης</h3><p>Η <b>ειδική</b> μπορεί να αντικατασταθεί με <b>ειδικό απαρέμφατο</b> (<i>λέγει ὅτι ἦλθεν &rarr; λέγει ἐλθεῖν/ἐληλυθέναι</i>) ή να αναλυθεί ως «το γεγονός ότι...». Η <b>αιτιολογική</b> αντιστοιχεί σε εμπρόθετο της αιτίας (<i>διά τό + απαρέμφατο</i>) ή σε αιτιολογική μετοχή και μεταφράζεται «επειδή, διότι».</p><h3>4. Νόημα-μετάφραση</h3><p><b>Ειδική:</b> «ότι / πως» (δηλώνει <i>τι</i>). <b>Αιτιολογική:</b> «επειδή / διότι / γιατί» (δηλώνει <i>γιατί</i>).</p>","examples":[{"gr":"Λέγει ὅτι ὁ Σωκράτης ἀδικεῖ.","an":"ΕΙΔΙΚΗ. Ρήμα λεκτικό «λέγει»· η πρόταση δίνει το ΠΕΡΙΕΧΟΜΕΝΟ· είναι αντικείμενο· μεταφράζεται «ότι»· αντικαθίσταται με απαρέμφατο: «λέγει τόν Σωκράτη ἀδικεῖν»."},{"gr":"Χαίρω ὅτι ὁ Σωκράτης ἦλθεν.","an":"ΑΙΤΙΟΛΟΓΙΚΗ. Ρήμα ψυχικού πάθους «χαίρω»· η πρόταση δίνει την ΑΙΤΙΑ της χαράς· είναι επιρρηματικός προσδιορισμός· μεταφράζεται «επειδή / που»· αναλύεται «διά τό τόν Σωκράτη ἐλθεῖν»."},{"gr":"Θαυμάζω ὡς ταῦτα ἐποίησεν.","an":"ΑΙΤΙΟΛΟΓΙΚΗ. «θαυμάζω» (αξιολογική/συναισθηματική κρίση) &rarr; αιτία του θαυμασμού· «επειδή / που έκανε αυτά». Αν όμως ήταν «αἰσθάνομαι ὡς ταῦτα ἐποίησεν» = ΕΙΔΙΚΗ («αντιλαμβάνομαι ότι...»)."},{"gr":"Ἀγανακτῶ ὅτι οὕτω ταπεινῶς διεκείμεθα.","an":"ΑΙΤΙΟΛΟΓΙΚΗ. Ρήμα ψυχικού πάθους «ἀγανακτῶ» &rarr; η πρόταση δίνει την ΑΙΤΙΑ της αγανάκτησης· «επειδή / που βρισκόμασταν σε τόσο ταπεινή κατάσταση» (τύπου Δημοσθένους)."},{"gr":"Πυνθάνομαι ὅτι οἱ πολέμιοι προσελαύνουσιν.","an":"ΕΙΔΙΚΗ. Γνωστικό «πυνθάνομαι» &rarr; η πρόταση δίνει το ΠΕΡΙΕΧΟΜΕΝΟ της πληροφορίας (αντικείμενο)· «ότι»· αντικαθίσταται με απαρέμφατο «προσελαύνειν». Αντίθεση προς τα ρήματα ψυχικού πάθους."}],"table":{"title":"Ειδικές vs Αιτιολογικές προτάσεις","cols":["Κριτήριο","Ειδική","Αιτιολογική"],"rows":[["Ρήμα εξάρτησης","λεκτικό, γνωστικό, αισθητικό, δοξαστικό, δεικτικό","ψυχικού πάθους / αξιολόγησης (χαίρω, λυποῦμαι, θαυμάζω) — ή δηλώνει αιτία","ψυχικού πάθους"],["Είδος πρότασης","ονοματική","επιρρηματική"],["Συντακτικός ρόλος","αντικείμενο / υποκείμενο / επεξήγηση","επιρρηματικός προσδ. αιτίας"],["Μετάφραση","ότι, πως (τι;)","επειδή, διότι, που (γιατί;)"],["Ισοδυναμία","ειδικό απαρέμφατο","διά τό + απαρέμφατο / αιτιολ. μετοχή"]]},"note":"Με ρήματα ψυχικού πάθους (χαίρω, ἄχθομαι, αἰσχύνομαι) το «ὅτι/ὡς» κανονικά εισάγει ΑΙΤΙΟΛΟΓΙΚΗ. Δεύτερη παγίδα: το «ὡς» εισάγει επίσης τελικές (σκοπός, με ευκτική/υποτακτική, άρνηση μή), συμπερασματικές (ὥστε/ὡς), χρονικές, αναφορικές και απλές παραβολικές — πάντα ελέγχουμε ΡΗΜΑ ΕΞΑΡΤΗΣΗΣ + ΑΡΝΗΣΗ (ειδική = οὐ· τελική/βουλητική = μή) πριν αποφανθούμε."}]);
  T("syn-endoiastikes", [{"h":"Ορισμός και φύση των ενδοιαστικών προτάσεων","body":"<p><b>Ενδοιαστικές</b> (από το <i>ενδοιάζω</i> = διστάζω, αμφιβάλλω, ανησυχώ· ο <i>ενδοιασμός</i> είναι ο δισταγμός και η αγωνία της ψυχής) ονομάζονται οι <b>δευτερεύουσες ονοματικές προτάσεις</b> που δηλώνουν <b>φόβο, ανησυχία ή ενδοιασμό</b> μήπως συμβεί κάτι κακό (ανεπιθύμητο) ή μήπως δεν πραγματοποιηθεί κάτι καλό (επιθυμητό).</p><p>Είναι <b>ονοματικές</b>, δηλαδή ισοδυναμούν με όνομα (ουσιαστικό) και λειτουργούν μέσα στην πρόταση όπως ένα ουσιαστικό: ως <b>αντικείμενο</b> ή ως <b>υποκείμενο</b>. Δεν είναι επιρρηματικές και γι' αυτό <b>δεν φανερώνουν σκοπό</b> — αυτό είναι το βασικό σημείο που τις διακρίνει από τις τελικές προτάσεις, με τις οποίες μοιάζουν εξωτερικά (και οι δύο εισάγονται με <i>μή</i>).</p><p>Η ψυχολογική τους αφετηρία είναι ο φόβος: το υποκείμενο φοβάται για ένα ενδεχόμενο γεγονός. Επειδή το περιεχόμενό τους αναφέρεται σε κάτι <b>ενδεχόμενο, πιθανό ή προσδοκώμενο</b> (όχι σε βεβαιωμένο γεγονός), η φυσική τους έγκλιση είναι η <b>υποτακτική</b>. Γεννιούνται ιστορικά από δύο ανεξάρτητες προτάσεις: μια κύρια με ρήμα φόβου (<i>φοβοῦμαι</i>) και μια αρχικά ανεξάρτητη ευχετική/αποτρεπτική (<i>μή τοῦτο γένηται</i> = «μακάρι να μη γίνει αυτό»), που σταδιακά εξαρτήθηκε και έγινε δευτερεύουσα.</p><p><b>Άρνηση:</b> Μέσα στην ενδοιαστική πρόταση η άρνηση είναι <b>οὐ</b> (όχι <i>μή</i>), διότι το <i>μή</i> έχει ήδη χρησιμοποιηθεί ως εισαγωγικός σύνδεσμος. Έτσι προκύπτει ο διπλός τύπος <i>μή οὐ</i>.</p>","examples":[{"gr":"Φοβοῦμαι μή νοσήσῃ ὁ φίλος.","an":"Φοβάμαι μήπως αρρωστήσει ο φίλος (μου). — Φόβος για κάτι ανεπιθύμητο· ονοματική πρόταση, αντικείμενο του «φοβοῦμαι»."},{"gr":"Φοβοῦμαι μή οὐ νοσήσῃ ὁ φίλος ... (πβ.) μή οὐ σωθῇ.","an":"Φοβάμαι μήπως δεν σωθεί (ο φίλος). — Φόβος για κάτι επιθυμητό που ίσως δεν γίνει· εδώ το «οὐ» είναι η άρνηση μέσα στην πρόταση."},{"gr":"Φοβούμεθα μή ἀμφοτέρων ἅμα ἡμαρτήκαμεν.","an":"Θουκ. 3.53.3 — «Φοβόμαστε μήπως έχουμε αποτύχει και στα δύο ταυτόχρονα.» Ονοματική, αντικείμενο του «φοβούμεθα»· εδώ φόβος για κάτι ήδη συντελεσμένο (οριστική παρακειμένου)."},{"gr":"Δεδιώς μή λαβών με δίκην ἐπιθῇ.","an":"Ξεν. Ἀνάβ. 1.3.10 — «επειδή φοβόταν μήπως με συλλάβει και μου επιβάλει τιμωρία.» Ενδοιαστική, αντικείμενο της μετοχής «δεδιώς» (= φοβούμενος)· εκφορά με υποτακτική (ἐπιθῇ)."}]},{"h":"Εισαγωγή: μή, μή οὐ (και ὅπως μή) — η σημασία τους","body":"<p>Οι ενδοιαστικές προτάσεις εισάγονται με τους <b>ενδοιαστικούς συνδέσμους</b> <b>μή</b> και <b>μή οὐ</b>:</p><h3>1) μή (= μήπως / να)</h3><p>Όταν ο φόβος αφορά κάτι <b>ανεπιθύμητο, κακό</b>, που το υποκείμενο <b>δεν θέλει</b> να συμβεί αλλά φοβάται ότι θα συμβεί. Στη νέα ελληνική αποδίδεται με <b>«μήπως»</b> ή με <b>«να»</b>: <i>φοβοῦμαι μή ἔλθῃ</i> = «φοβάμαι μήπως / να έρθει».</p><h3>2) μή οὐ (= μήπως δεν / να μη)</h3><p>Όταν ο φόβος αφορά κάτι <b>επιθυμητό, καλό</b>, που το υποκείμενο <b>θέλει</b> να συμβεί αλλά φοβάται ότι <b>δεν θα συμβεί</b>. Αποδίδεται με <b>«μήπως δεν»</b> ή <b>«να μη»</b>: <i>φοβοῦμαι μή οὐκ ἔλθῃ</i> = «φοβάμαι μήπως δεν / να μην έρθει».</p><p>Στο <i>μή οὐ</i>, το <b>μή</b> είναι ο εισαγωγικός σύνδεσμος και το <b>οὐ</b> είναι η <b>άρνηση</b> του ρήματος της πρότασης. Πρόκειται δηλαδή για άρνηση μέσα στην πρόταση, όχι για διπλό σύνδεσμο.</p><h3>3) ὅπως μή (σπανιότερο)</h3><p>Σπανιότερα η ενδοιαστική εισάγεται με <b>ὅπως μή</b> αντί του απλού <i>μή</i> (κυρίως μετά από ρήματα προσοχής / φροντίδας, π.χ. <i>ὅρα, σκόπει, φύλαττε</i>), με την ίδια σημασία («μήπως»). Δεν πρέπει να συγχέεται με την τελική <i>ὅπως / ὅπως μή</i>.</p><p><b>Μνημονικός κανόνας σημασίας:</b> <i>μή</i> = «μήπως (γίνει το κακό)»· <i>μή οὐ</i> = «μήπως δεν (γίνει το καλό)».</p>","examples":[{"gr":"Δέδοικα μή ἐπιλαθώμεθα τῆς οἴκαδε ὁδοῦ. (πβ. Ξεν.)","an":"Φοβάμαι μήπως ξεχάσουμε τον δρόμο για την πατρίδα. — μή: φόβος για ανεπιθύμητο."},{"gr":"Δέδοικα μή οὐκ ἔχοιμεν τά ἐπιτήδεια.","an":"Φοβάμαι μήπως δεν έχουμε τα αναγκαία (εφόδια). — μή οὐ: φόβος μήπως δεν γίνει το επιθυμητό· εκφορά με ευκτική του πλαγίου λόγου."},{"gr":"Φοβούμεθα μή ἀμφοτέρων ἡμαρτήκαμεν.","an":"Φοβόμαστε μήπως έχουμε αποτύχει και στα δύο. — Φόβος για πραγματικό/συντελεσμένο γεγονός· εκφορά με οριστική παρακειμένου."},{"gr":"Ὅρα μή σαυτόν ψεύσῃς.","an":"Πρόσεχε μήπως ξεγελάσεις τον εαυτό σου. — Εισαγωγή πρακτικά με ρήμα προσοχής· πβ. εισαγωγή «ὅπως μή»."},{"gr":"Δέδοικα μή οὐκ ἔχω ἱκανούς οἷς δῶ.","an":"Ξεν. Ἀνάβ. 1.7.7 — «Φοβάμαι μήπως δεν έχω αρκετούς ανθρώπους στους οποίους να (τα) δώσω.» Καθαρό παράδειγμα «μή οὐ»: φόβος μήπως ΔΕΝ υπάρχει κάτι επιθυμητό· το «οὐ» αρνείται το ρήμα της πρότασης."},{"gr":"Δέδιμεν μή οὐ βέβαιοι ἦτε.","an":"Θουκ. 3.57 — «Φοβόμαστε μήπως δεν είστε σταθεροί (αξιόπιστοι).» Πάλι «μή οὐ» = «μήπως δεν»· φόβος ότι δεν θα πραγματοποιηθεί το επιθυμητό."}],"note":"Προσοχή: το «μή» των ενδοιαστικών δεν είναι αρνητικό μόριο αλλά εισαγωγικός σύνδεσμος. Γι' αυτό, όταν χρειάζεται άρνηση μέσα στην πρόταση, εμφανίζεται το «οὐ» (μή οὐ), όχι δεύτερο «μή»."},{"h":"Τα ρήματα και οι εκφράσεις φόβου (η εξάρτηση)","body":"<p>Οι ενδοιαστικές εξαρτώνται πάντοτε από λέξεις (ρήματα, απρόσωπες εκφράσεις, ουσιαστικά) που δηλώνουν <b>φόβο, ανησυχία, προσοχή ή υποψία</b>. Η γνώση αυτού του καταλόγου είναι το «κλειδί» για να αναγνωρίσεις ότι μια πρόταση με <i>μή</i> είναι ενδοιαστική και όχι τελική.</p><h3>Α. Ρήματα φόβου / ανησυχίας</h3><ul><li><b>φοβοῦμαι</b> (φοβάμαι)</li><li><b>δέδοικα / δέδια</b> (φοβάμαι — παρακείμενος με σημασία ενεστώτα)</li><li><b>ὀκνῶ</b> (διστάζω)</li><li><b>ταρβῶ, ὀρρωδῶ, τρέμω</b> (τρέμω από φόβο)</li><li><b>ἀθυμῶ</b> (αποθαρρύνομαι)</li><li><b>αἰσχύνομαι</b> (ντρέπομαι), <b>διστάζω</b></li></ul><h3>Β. Ρήματα προσοχής / φροντίδας</h3><ul><li><b>ὁρῶ, σκοπῶ, σκοποῦμαι</b> (προσέχω, εξετάζω)</li><li><b>προσέχω, φροντίζω, ἐπιμελοῦμαι</b></li><li><b>εὐλαβοῦμαι, φυλάττομαι</b> (προφυλάσσομαι)</li></ul><h3>Γ. Ρήματα υποψίας</h3><ul><li><b>ὑποπτεύω, ὑποπτεύομαι</b> (υποπτεύομαι)</li><li><b>ἀπιστῶ</b> (δυσπιστώ)</li></ul><h3>Δ. Απρόσωπες εκφράσεις φόβου</h3><ul><li><b>δέος ἐστί</b> (υπάρχει φόβος), <b>φόβος ἐστί</b></li><li><b>κίνδυνός ἐστι</b> (υπάρχει κίνδυνος)</li><li><b>δεινόν ἐστι</b> (είναι φοβερό), <b>φοβερόν ἐστι</b></li><li><b>ὑποψία ἐστί, προσδοκία ἐστί</b></li></ul><p>Από τα <b>προσωπικά</b> ρήματα η ενδοιαστική είναι <b>αντικείμενο</b>· από τις <b>απρόσωπες</b> εκφράσεις και τα ουσιαστικά (<i>δέος, φόβος, κίνδυνος</i>) είναι <b>υποκείμενο</b> ή <b>επεξήγηση</b>.</p>","table":{"title":"Κατηγορίες λέξεων που εισάγουν ενδοιαστικές","cols":["Κατηγορία","Χαρακτηριστικές λέξεις","Σημασία","Ρόλος ενδοιαστικής"],"rows":[["Φόβος","φοβοῦμαι, δέδοικα/δέδια, ὀκνῶ, ταρβῶ, ὀρρωδῶ, ἀθυμῶ","φοβάμαι, διστάζω","αντικείμενο"],["Προσοχή / φροντίδα","ὁρῶ, σκοπῶ, προσέχω, φροντίζω, εὐλαβοῦμαι, φυλάττομαι","προσέχω μήπως","αντικείμενο"],["Υποψία","ὑποπτεύω, ἀπιστῶ","υποπτεύομαι","αντικείμενο"],["Απρόσωπες εκφράσεις","δέος/φόβος/κίνδυνος/δεινόν ἐστι","υπάρχει φόβος/κίνδυνος","υποκείμενο / επεξήγηση"]]},"examples":[{"gr":"Δέδοικα μή νικῶσιν οἱ πολέμιοι.","an":"Φοβάμαι μήπως νικούν οι εχθροί. — Εξάρτηση από «δέδοικα» (ρήμα φόβου), αντικείμενο."},{"gr":"Κίνδυνός ἐστι μή μεταβάλωνται καί γένωνται μετά τῶν πολεμίων.","an":"Υπάρχει κίνδυνος μήπως αλλάξουν στάση και πάνε με το μέρος των εχθρών. — Εξάρτηση από απρόσωπη έκφραση «κίνδυνός ἐστι», υποκείμενο."},{"gr":"Ὅρα μή πολλῶν ἑκάστῳ ἡμῶν χειρῶν δεήσει. (πβ. Ξεν.)","an":"Πρόσεχε μήπως χρειαστούν για τον καθένα μας πολλά χέρια. — Εξάρτηση από ρήμα προσοχής «ὅρα», αντικείμενο."},{"gr":"Ἐφοβοῦντο μή τι πάθῃ.","an":"Ξεν. (πβ. Smyth 2225) — «Φοβούνταν μήπως πάθει αυτή κάτι κακό.» Εξάρτηση από ρήμα φόβου «ἐφοβοῦντο»· εδώ διατήρηση υποτακτικής (πάθῃ) και μετά από ιστορικό χρόνο = ζωντανή παράσταση του φόβου."},{"gr":"Δέδοικα μή τούς καθεστῶτας νόμους ἄριστον ᾖ σῴζοντα τόν βίον τελεῖν.","an":"Σοφ. Ἀντ. 1113-1114 — «Φοβάμαι μήπως είναι το άριστο (το πιο σωστό) να τελειώσει κανείς τη ζωή του τηρώντας τους καθιερωμένους νόμους.» Εξάρτηση από «δέδοικα»· αντικείμενο· εκφορά με υποτακτική του ρ. εἰμί (ᾖ)."}]},{"h":"Εκφορά: υποτακτική, ευκτική του πλαγίου λόγου, οριστική, δυνητική","body":"<p>Η εκφορά (έγκλιση) της ενδοιαστικής εξαρτάται από τον χρόνο του ρήματος εξάρτησης και από τη φύση του φόβου (προσδοκώμενος ή πραγματικός).</p><h3>1) Υποτακτική — η κανονική, κύρια εκφορά</h3><p>Δηλώνει <b>φόβο προσδοκώμενο</b> (κάτι που ενδέχεται να γίνει). Χρησιμοποιείται κατά κανόνα όταν το ρήμα εξάρτησης είναι <b>αρκτικού χρόνου</b> (ενεστώτας, μέλλοντας, παρακείμενος, εντελλόμενος μέλλ.). Η υποτακτική είναι η «φυσική» έγκλιση των ενδοιαστικών, γιατί εκφράζει το ενδεχόμενο.</p><h3>2) Ευκτική του πλαγίου λόγου</h3><p>Όταν το ρήμα εξάρτησης είναι <b>ιστορικού (παρελθοντικού) χρόνου</b> (αόριστος, παρατατικός, υπερσυντέλικος). Η ευκτική του πλαγίου λόγου παρουσιάζει τον φόβο ως <b>υποκειμενικό, αβέβαιο, ως διανόημα του παρελθόντος</b>. Είναι <b>προαιρετική</b>: ο συγγραφέας μπορεί να διατηρήσει και την υποτακτική ακόμη και μετά από ιστορικό χρόνο, για να παραστήσει τον φόβο πιο ζωντανό και άμεσο (όπως τον ένιωσε εκείνη τη στιγμή το υποκείμενο).</p><h3>3) Οριστική (σπάνια)</h3><p>Δηλώνει φόβο για κάτι <b>πραγματικό / βέβαιο</b> — όχι απλώς ενδεχόμενο. Συνήθως με οριστική παρακειμένου ή αορίστου (φόβος ότι κάτι ήδη έγινε) ή μέλλοντα (βέβαιη πρόβλεψη): <i>φοβοῦμαι μή ἡμάρτηκα</i> = «φοβάμαι ότι (πράγματι) έσφαλα».</p><h3>4) Δυνητική ευκτική / δυνητική οριστική (σπάνια)</h3><p>Όταν το περιεχόμενο της ενδοιαστικής είναι δυνατό υπό όρους· διατηρείται το δυνητικό <i>ἄν</i>.</p>","table":{"title":"Εκφορά της ενδοιαστικής ανάλογα με τον χρόνο εξάρτησης","cols":["Χρόνος ρήματος εξάρτησης","Κανονική εκφορά","Σημασία φόβου"],"rows":[["Αρκτικός (ενεστ., μέλλ., παρακ.)","Υποτακτική","προσδοκώμενος, ενδεχόμενος"],["Ιστορικός (αόρ., παρατ., υπερσ.)","Ευκτική πλαγίου λόγου (ή και υποτακτική)","υποκειμενικός / ή ζωντανός"],["Οποιοσδήποτε","Οριστική (σπάνια)","πραγματικός, βέβαιος"],["Οποιοσδήποτε","Δυνητική ευκτική/οριστική (σπάνια)","δυνατός υπό όρους"]]},"examples":[{"gr":"Οἱ τύραννοι φοβοῦνται μή αἱ πόλεις ἐλεύθεραι γένωνται.","an":"Οι τύραννοι φοβούνται μήπως οι πόλεις γίνουν ελεύθερες. — Αρκτικός χρόνος (φοβοῦνται) + υποτακτική (γένωνται): φόβος προσδοκώμενος."},{"gr":"Ἔδεισαν οἱ Ἕλληνες μή προσάγοιεν πρός τό κέρας οἱ πολέμιοι. (πβ. Ξεν. Ἀνάβ.)","an":"Φοβήθηκαν οι Έλληνες μήπως οδηγήσουν οι εχθροί (τις δυνάμεις τους) προς το κέρας. — Ιστορικός χρόνος (ἔδεισαν) + ευκτική πλαγίου λόγου (προσάγοιεν)."},{"gr":"Ἐφοβήθησαν μή καί ἐπί σφᾶς ὁ στρατός χωρήσῃ.","an":"Φοβήθηκαν μήπως ο στρατός προχωρήσει και εναντίον τους. — Ιστορικός χρόνος + διατήρηση υποτακτικής (χωρήσῃ): ο φόβος αποδίδεται ζωντανά."},{"gr":"Φοβούμεθα μή ἀμφοτέρων ἡμαρτήκαμεν.","an":"Φοβόμαστε μήπως αποτύχαμε και στα δύο. — Οριστική παρακειμένου (ἡμαρτήκαμεν): φόβος για κάτι πραγματικό/συντελεσμένο."},{"gr":"Ἔδεισαν οἱ Ἕλληνες μή προσάγοιεν ... καί αὐτούς κατακόψειαν.","an":"Ξεν. (πβ. Smyth 2225) — «Φοβήθηκαν οι Έλληνες μήπως πλησιάσουν (οι εχθροί) και τους κατακόψουν.» Ιστορικός χρόνος (ἔδεισαν) + δύο ευκτικές του πλαγίου λόγου (προσάγοιεν, κατακόψειαν)."},{"gr":"Δεδιότες μή ἀποθάνοιεν.","an":"(τύπου Ξεν.) — «επειδή φοβούνταν μήπως πεθάνουν.» Εξάρτηση από μετοχή ιστορικού πλαισίου· εκφορά με ευκτική του πλαγίου λόγου (ἀποθάνοιεν): ο φόβος ως αβέβαιο διανόημα του παρελθόντος."}],"note":"Η ευκτική του πλαγίου λόγου είναι πάντοτε προαιρετική στις ενδοιαστικές: η διατήρηση της υποτακτικής και μετά από ιστορικό χρόνο είναι συνηθέστατη στον Θουκυδίδη και τον Ξενοφώντα και δηλώνει «ζωντανότερη» παράσταση του φόβου."},{"h":"Συντακτικός ρόλος μέσα στην περίοδο","body":"<p>Επειδή είναι <b>ονοματικές</b>, οι ενδοιαστικές αναλαμβάνουν θέσεις που κανονικά κατέχει ένα ουσιαστικό:</p><h3>α) Αντικείμενο</h3><p>Όταν εξαρτώνται από <b>προσωπικό μεταβατικό ρήμα φόβου / προσοχής / υποψίας</b> (<i>φοβοῦμαι, δέδοικα, ὁρῶ, ὑποπτεύω</i>). Είναι η συχνότερη χρήση.</p><h3>β) Υποκείμενο</h3><p>Όταν εξαρτώνται από <b>απρόσωπη έκφραση φόβου</b> (<i>δέος ἐστί, κίνδυνός ἐστι, δεινόν ἐστι, φόβος ἐστί</i>). Η ενδοιαστική είναι το υποκείμενο της απρόσωπης έκφρασης (απαντά στο «τι;»).</p><h3>γ) Επεξήγηση</h3><p>Όταν αναλύει / επεξηγεί μια προηγούμενη <b>δεικτική αντωνυμία</b> (<i>τοῦτο</i>) ή ένα αφηρημένο <b>ουσιαστικό φόβου</b> (<i>φόβος, δέος, κίνδυνος, ὑποψία</i>): «αυτόν τον φόβο: μήπως...».</p><h3>δ) (Φαινομενικά) ανεξάρτητες — αποτρεπτικές</h3><p>Όταν η ενδοιαστική φαίνεται μόνη της σε αρχή περιόδου· τότε εννοείται ρήμα προσοχής (<i>ὅρα, σκόπει, ὁρᾶτε, σκοπεῖτε</i>) και η πρόταση έχει σημασία προτροπής/αποτροπής: <i>μή ἀγροικότερον ᾖ τό ἀληθές εἰπεῖν</i> = «(πρόσεξε) μήπως είναι αγροίκο να πει κανείς την αλήθεια».</p>","examples":[{"gr":"Φοβοῦνται μή οἱ Βοιωτοί δῃώσωσι τήν Ἀττικήν.","an":"Φοβούνται μήπως οι Βοιωτοί λεηλατήσουν την Αττική. — Αντικείμενο του «φοβοῦνται»."},{"gr":"Δέος ἐγένετο μή ξύν ὅπλοις ἔλθωσιν. (πβ. Θουκ.)","an":"Δημιουργήθηκε φόβος μήπως έρθουν με όπλα. — Υποκείμενο της απρόσωπης έκφρασης «δέος ἐγένετο»."},{"gr":"Ἐφοβήθη τοῦτο, μή οὐκ ἔλθοι ἡ βοήθεια.","an":"Φοβήθηκε αυτό: μήπως δεν έρθει η βοήθεια. — Επεξήγηση στη δεικτική αντωνυμία «τοῦτο»· εκφορά με ευκτική πλαγ. λόγου (μή οὐ = μήπως δεν)."},{"gr":"Ὅρα οὖν μή τῶν ἀδυνάτων ᾖ τό ... (πβ. Πλάτ.)","an":"Πρόσεξε λοιπόν μήπως είναι αδύνατο το... — Αντικείμενο ρήματος προσοχής· δείχνει και τη μετάβαση προς αποτρεπτική χρήση."},{"gr":"Ὅρα, ὦ μακάριε, μή περί τοῖς φιλτάτοις κυβεύῃς τε καί κινδυνεύῃς.","an":"Πλάτ. Πρωτ. 314a — «Πρόσεξε, καλότυχε, μήπως διακινδυνεύεις παίζοντας ζάρια με τα πιο πολύτιμά σου.» Αντικείμενο ρήματος προσοχής «ὅρα»· χαρακτηριστική αποτρεπτική χρήση."},{"gr":"Ὅρα μή σκήψεις ποιῇ.","an":"(τύπου Πλάτ.) — «Πρόσεξε μήπως προβάλλεις προφάσεις.» (Φαινομενικά) ανεξάρτητη ενδοιαστική με σημασία αποτροπής· εννοείται/υπάρχει ρήμα προσοχής «ὅρα»."}],"note":"Όταν την ενδοιαστική την προαναγγέλλει το «τοῦτο» ή ουσιαστικό όπως «φόβος / κίνδυνος», είναι ΕΠΕΞΗΓΗΣΗ — όχι αντικείμενο/υποκείμενο. Πρώτα εντόπισε τον όρο που επεξηγείται."},{"h":"Διάκριση ενδοιαστικών από τελικές (και από πλάγιες ερωτήσεις)","body":"<p>Το δυσκολότερο σημείο: και οι <b>ενδοιαστικές</b> και οι <b>τελικές</b> προτάσεις μπορούν να εισάγονται με <b>μή</b> (πβ. τελικό <i>ἵνα μή, ὅπως μή, ὡς μή</i> και ενδοιαστικό <i>μή</i>). Η διάκριση γίνεται με τρία κριτήρια:</p><h3>1) Σημασία / είδος πρότασης</h3><ul><li><b>Ενδοιαστική = ονοματική</b>: δηλώνει <b>φόβο/ανησυχία</b>· ισοδυναμεί με ουσιαστικό· είναι αντικείμενο ή υποκείμενο. Απόδοση: <b>«μήπως»</b>.</li><li><b>Τελική = επιρρηματική</b>: δηλώνει <b>σκοπό</b>· ισοδυναμεί με επίρρημα· είναι επιρρηματικός προσδιορισμός του σκοπού. Απόδοση: <b>«για να (μην)»</b>.</li></ul><h3>2) Ρήμα εξάρτησης</h3><ul><li>Η ενδοιαστική εξαρτάται από <b>ρήμα/έκφραση φόβου</b> (<i>φοβοῦμαι, δέδοικα, κίνδυνός ἐστι</i>).</li><li>Η τελική εξαρτάται από ρήμα <b>σκόπιμης ενέργειας</b> (κίνησης, δράσης: <i>ἔρχομαι, πράττω, λέγω</i>).</li></ul><h3>3) Η άρνηση</h3><ul><li>Στην <b>ενδοιαστική</b> η άρνηση είναι <b>οὐ</b> → <i>μή οὐ</i>.</li><li>Στην <b>τελική</b> η άρνηση είναι <b>μή</b> → <i>ἵνα μή, ὅπως μή</i> (ποτέ *ἵνα οὐ).</li></ul><p>Πρακτικός κανόνας: αν μπορείς να αποδώσεις με <b>«μήπως»</b> και υπάρχει ρήμα φόβου, είναι <b>ενδοιαστική</b>· αν αποδίδεται με <b>«για να»</b> και δηλώνει σκοπό, είναι <b>τελική</b>.</p><h3>Και από τις πλάγιες ερωτήσεις</h3><p>Τα ρήματα φόβου/προσοχής (π.χ. <i>ὁρῶ, σκοπῶ</i>) μπορούν να συντάσσονται και με <b>πλάγια ερωτηματική</b> πρόταση (<i>εἰ, μή = αν / μήπως</i>). Διάκριση: η πλάγια ερώτηση προϋποθέτει <b>απορία/άγνοια</b> («αναρωτιέμαι αν...»), ενώ η ενδοιαστική δηλώνει <b>φόβο</b> («φοβάμαι μήπως...»). Επίσης τα ρήματα φόβου εναλλακτικά συντάσσονται με <b>τελικό απαρέμφατο</b> (<i>φοβοῦμαι ποιεῖν</i> = διστάζω να κάνω), που δηλώνει φόβο μπροστά σε μελλοντική <b>δική μου</b> ενέργεια.</p>","table":{"title":"Ενδοιαστική vs Τελική (με μή)","cols":["Κριτήριο","Ενδοιαστική","Τελική"],"rows":[["Είδος","Ονοματική","Επιρρηματική"],["Δηλώνει","Φόβο / ανησυχία","Σκοπό"],["Ρήμα εξάρτησης","Φόβου/προσοχής/υποψίας","Σκόπιμης ενέργειας"],["Συντακτ. ρόλος","Αντικείμενο / υποκείμενο","Επιρρ. προσδ. σκοπού"],["Εισαγωγή","μή, μή οὐ (σπάν. ὅπως μή)","ἵνα, ὡς, ὅπως, μή / + μή για άρνηση"],["Άρνηση μέσα","οὐ (→ μή οὐ)","μή (→ ἵνα μή)"],["Απόδοση","μήπως / να","για να (μην)"]]},"examples":[{"gr":"Φοβοῦμαι μή τοῦτο γένηται. (ενδοιαστική)","an":"Φοβάμαι μήπως γίνει αυτό. — Φόβος· αντικείμενο· εξάρτηση από «φοβοῦμαι»."},{"gr":"Φεύγω μή τοῦτο γένηται. (τελική)","an":"Φεύγω για να μη γίνει αυτό. — Σκοπός· επιρρηματικός προσδιορισμός· εξάρτηση από ρήμα ενέργειας «φεύγω»."},{"gr":"Δέδοικα μή οὐ δυνηθῶ δηλῶσαι. (ενδοιαστική)","an":"Φοβάμαι μήπως δεν μπορέσω να (το) εξηγήσω. — Άρνηση «οὐ» μέσα στην πρόταση: σίγουρα ενδοιαστική, όχι τελική."},{"gr":"Πράττω πάντα ὅπως μή ἁμάρτω. (τελική)","an":"Κάνω τα πάντα για να μη σφάλω. — Άρνηση «μή» (όχι «οὐ»): τελική του σκοπού."},{"gr":"Δέδοικα μή οὐκ ἔχω ἱκανούς οἷς δῶ. (ενδοιαστική)","an":"Ξεν. Ἀνάβ. 1.7.7 — «Φοβάμαι μήπως δεν έχω αρκετούς στους οποίους να (τα) δώσω.» Η ακολουθία «μή οὐ» αποκλείει την τελική ερμηνεία: είναι ενδοιαστική (ρήμα φόβου «δέδοικα»)."},{"gr":"Ἀπῆλθον ἵνα μή ληφθεῖεν. (τελική)","an":"«Έφυγαν για να μη συλληφθούν.» — Εξάρτηση από ρήμα ενέργειας/κίνησης (ἀπῆλθον), άρνηση «μή» (ἵνα μή), δήλωση σκοπού: τελική, όχι ενδοιαστική."}],"note":"Σήμα-κλειδί: η ακολουθία «μή οὐ» ΔΕΝ μπορεί ποτέ να είναι τελική (η τελική παίρνει άρνηση μή, όχι οὐ). Άρα «μή οὐ» = σχεδόν βέβαια ενδοιαστική. Αντίστροφα, «ἵνα μή / ὡς μή / ὅπως μή» χωρίς ρήμα φόβου = τελική."}]);
  T("syn-plagies-erotimatikes", [{"h":"Τι είναι οι πλάγιες ερωτηματικές προτάσεις","body":"<p>Οι <b>πλάγιες ερωτηματικές προτάσεις</b> είναι <b>δευτερεύουσες ονοματικές προτάσεις</b> που περιέχουν μια ερώτηση, η οποία όμως δεν διατυπώνεται <i>ευθέως</i> (σε ευθύ λόγο), αλλά <i>πλαγίως</i> (σε πλάγιο λόγο), δηλαδή εξαρτημένη από ένα ρήμα της προηγούμενης πρότασης. Με άλλα λόγια, η ίδια ερώτηση που στον ευθύ λόγο θα ήταν κύρια πρόταση, μεταφέρεται μέσα σε άλλη πρόταση ως εξαρτημένη.</p><p>Σύγκρινε:</p><ul><li><i>Ευθεία ερώτηση</i> (κύρια): «<b>Τίς</b> ἐστιν ὁ διδάσκαλος;» (Ποιος είναι ο δάσκαλος;)</li><li><i>Πλάγια ερώτηση</i> (δευτερεύουσα): «Ἐρωτῶ <b>τίς ἐστιν ὁ διδάσκαλος</b>.» (Ρωτώ ποιος είναι ο δάσκαλος.)</li></ul><p>Στο δεύτερο παράδειγμα η ερώτηση «τίς ἐστιν ὁ διδάσκαλος» δεν στέκεται μόνη της· είναι το <b>αντικείμενο</b> του ρήματος «ἐρωτῶ». Γι' αυτό λέγεται <i>ονοματική</i> πρόταση: ισοδυναμεί με όνομα (ουσιαστικό) και αναλαμβάνει στην πρόταση εξάρτησης έναν ονοματικό συντακτικό ρόλο (αντικείμενο, υποκείμενο, επεξήγηση).</p><h3>Βασικά τυπικά γνωρίσματα</h3><ul><li><b>Δεν φέρουν ερωτηματικό</b> (;) στο τέλος, αφού δεν είναι αυτοτελείς ερωτήσεις.</li><li><b>Εξαρτώνται πάντα από ρήμα</b> (ή ονοματική έκφραση) που σημαίνει ερώτηση, γνώση, σκέψη, αμφιβολία, απόπειρα, φροντίδα, δήλωση κ.λπ.</li><li>Η <b>άρνησή</b> τους είναι <b>οὐ</b> όταν περιέχουν κρίση/γνώμη και <b>μή</b> όταν περιέχουν επιθυμία/απορία για ενέργεια.</li></ul><p>Προσοχή στη διάκριση: η πλάγια ερωτηματική <b>περιέχει αληθινή ερώτηση/απορία</b> που ζητεί απάντηση. Δεν πρέπει να συγχέεται με τις απλές <i>αναφορικές</i> προτάσεις, που δηλώνουν γνωστό περιεχόμενο. Το κρίσιμο κριτήριο είναι το <b>νόημα του ρήματος εξάρτησης</b>: αν αυτό σημαίνει «ρωτώ / απορώ / δεν ξέρω / εξετάζω», η πρόταση είναι πλάγια ερωτηματική.</p>","examples":[{"gr":"Ἐρήσομαι ὅστις ἐστίν ὁ διδάσκαλος.","an":"Θα ρωτήσω ποιος είναι ο δάσκαλος. — Η πρόταση «ὅστις ἐστίν ὁ διδάσκαλος» είναι πλάγια ερωτηματική, αντικείμενο στο ρήμα ερωτήσεως «ἐρήσομαι»."},{"gr":"Σκέψασθε πῶς ἐπί τῶν προγόνων ταῦτα εἶχεν.","an":"Σκεφτείτε πώς ήταν αυτά στην εποχή των προγόνων. — Εισάγεται με το ερωτηματικό επίρρημα «πῶς», εξαρτάται από ρήμα σκέψεως «σκέψασθε»."},{"gr":"Τοῦτο σκεψώμεθα, εἰ ἀληθῆ λέγεις.","an":"Ας εξετάσουμε αυτό, αν λες την αλήθεια. — Η πλάγια ερωτηματική «εἰ ἀληθῆ λέγεις» είναι επεξήγηση στη δεικτική αντωνυμία «τοῦτο»."},{"gr":"Ἠρώτων αὐτούς τίνες εἶεν.","an":"Ξεν. Ἀνάβ. 4.5.10 — Τους ρωτούσαν ποιοι ήταν. Πλάγια ερωτηματική (μερικής αγνοίας) αντικείμενο στο «ἠρώτων»· ευκτική πλαγίου «εἶεν» μετά ιστορικό χρόνο."},{"gr":"Ἐρωτῶντες εἰ λῃσταί εἰσιν.","an":"Θουκ. 1.5 — Ρωτώντας αν είναι ληστές. Πλάγια ερωτηματική ολικής αγνοίας με «εἰ», αντικείμενο στο ρήμα ερωτήσεως."},{"gr":"Οὐδείς ᾔδει ὅποι στρατεύουσιν.","an":"Θουκ. 5.54 — Κανείς δεν ήξερε προς τα πού εκστρατεύουν. Μερικής αγνοίας («ὅποι»), αντικείμενο στο γνωστικό «ᾔδει»."}],"note":"Τυπική παγίδα: μη μπερδεύεις την εισαγωγική λέξη με το είδος της πρότασης. Το «εἰ» εισάγει και υποθετικές («εἰ = αν, σε περίπτωση που») αλλά και πλάγιες ερωτηματικές («εἰ = αν, κατά πόσον»). Το ξεκαθαρίζει το ρήμα εξάρτησης: ύστερα από «ἀπορῶ, ἐρωτῶ, σκοπῶ, ἄδηλόν ἐστι» έχουμε πλάγια ερωτηματική, όχι υποθετική."},{"h":"Είδη κατά το περιεχόμενο: ολικής και μερικής αγνοίας","body":"<p>Ανάλογα με το <b>τι ακριβώς αγνοεί</b> αυτός που ρωτά (και άρα τι είδους απάντηση περιμένει), οι πλάγιες ερωτηματικές διακρίνονται σε δύο μεγάλες κατηγορίες.</p><h3>1. Προτάσεις ολικής αγνοίας (κλειστές)</h3><p>Η άγνοια αφορά <b>ολόκληρο</b> το περιεχόμενο της πρότασης· γι' αυτό η αναμενόμενη απάντηση είναι <b>ναι ή όχι</b>. Διακρίνονται περαιτέρω σε:</p><ul><li><b>Μονομερείς (μονομελείς)</b>: παρουσιάζουν <i>ένα</i> ενδεχόμενο, στο οποίο απαντούμε ναι/όχι. Εισάγονται κυρίως με τον σύνδεσμο <b>εἰ</b> (= αν, κατά πόσον· σπανιότερα ἐάν, ἄν, ἤν).</li><li><b>Διμερείς (διμελείς)</b>: παρουσιάζουν <i>δύο</i> (ή περισσότερα) αντιτιθέμενα ενδεχόμενα, ανάμεσα στα οποία ζητείται επιλογή. Εισάγονται με τα ζεύγη <b>πότερον…ἤ, πότερα…ἤ, εἰ…ἤ, εἴτε…εἴτε</b>.</li></ul><h3>2. Προτάσεις μερικής αγνοίας (ανοικτές)</h3><p>Η άγνοια αφορά <b>ένα μόνο μέρος / όρο</b> του περιεχομένου (το ποιος, το πού, το πότε, το πόσο, το πώς κ.λπ.)· η απάντηση δεν είναι ναι/όχι αλλά μια <b>συγκεκριμένη πληροφορία</b>. Εισάγονται με ερωτηματικές ή αναφορικές αντωνυμίες και επιρρήματα.</p>","table":{"title":"Συνοπτική κατάταξη των πλάγιων ερωτηματικών","cols":["Είδος","Τι αγνοούμε","Αναμενόμενη απάντηση","Εισαγωγή"],"rows":[["Ολικής αγνοίας — μονομερής","Όλο το περιεχόμενο (ένα ενδεχόμενο)","Ναι / Όχι","εἰ (ἐάν, ἄν, ἤν)"],["Ολικής αγνοίας — διμερής","Όλο το περιεχόμενο (δύο ενδεχόμενα)","Επιλογή ανάμεσα στα δύο","πότερον…ἤ, εἰ…ἤ, εἴτε…εἴτε"],["Μερικής αγνοίας","Ένα μέρος/όρο του περιεχομένου","Συγκεκριμένη πληροφορία","ερωτ./αναφ. αντωνυμίες & επιρρήματα"]]},"examples":[{"gr":"Ἠρώτων αὐτόν εἰ ἀναπλεύσειεν ἔχων ἀργύριον.","an":"Τον ρωτούσαν αν είχε ταξιδέψει προς τα πάνω έχοντας χρήματα. — Ολικής αγνοίας, μονομερής (εἰ + ευκτική πλαγίου). Απάντηση: ναι ή όχι."},{"gr":"Ἐβουλεύοντο εἴτε κατακαύσωσιν αὐτούς εἴτε τι ἄλλο χρήσωνται.","an":"Σκέφτονταν είτε να τους κάψουν είτε να τους μεταχειριστούν με κάποιον άλλον τρόπο. — Ολικής αγνοίας, διμερής (εἴτε…εἴτε + απορηματική υποτακτική)."},{"gr":"Εἰπέ μοι πότερον ἡ γῆ πλατεῖά ἐστιν ἤ στρογγύλη.","an":"Πες μου αν η γη είναι επίπεδη ή στρογγυλή. — Ολικής αγνοίας, διμερής (πότερον…ἤ)."},{"gr":"Ἀγνοῶ ὅπου ἐσμέν.","an":"Δεν ξέρω πού βρισκόμαστε. — Μερικής αγνοίας· η άγνοια αφορά μόνο τον τόπο (ὅπου)."},{"gr":"Ἀπορῶ τί πρῶτον εἴπω.","an":"Βρίσκομαι σε αμηχανία τι να πω πρώτα. — Μερικής αγνοίας (τί) με απορηματική υποτακτική."},{"gr":"Ἠρώτων ὅ τι ἐστί τό πρᾶγμα.","an":"Ξεν. Ἀνάβ. 5.7.23 — Ρωτούσαν ποιο είναι το ζήτημα. Μερικής αγνοίας με αναφορικό «ὅ τι»· αγνοείται μόνο η ταυτότητα του πράγματος."},{"gr":"Διηρώτα πότερον βούλοιτο μένειν ἤ ἀπιέναι.","an":"Ξεν. Κύρ. Παιδ. 1.3.15 — Ρωτούσε επίμονα αν ήθελε να μείνει ή να φύγει. Ολικής αγνοίας, διμερής (πότερον … ἤ) με ευκτική πλαγίου."}],"note":"Ο όρος «αγνοία» δεν σημαίνει αμάθεια αλλά «έλλειψη συγκεκριμένης πληροφορίας». «Ολική» = αγνοούμε αν ισχύει το όλον· «μερική» = ξέρουμε ότι κάτι ισχύει, αγνοούμε μόνο μια λεπτομέρειά του."},{"h":"Η εισαγωγή των πλάγιων ερωτηματικών","body":"<p>Ο τρόπος εισαγωγής εξαρτάται απευθείας από το είδος (ολικής ή μερικής αγνοίας).</p><h3>Α. Ολικής αγνοίας — μονομερείς</h3><p>Εισάγονται με τον σύνδεσμο <b>εἰ</b> (= αν, κατά πόσον). Σπανιότερα απαντούν τα <b>ἐάν, ἄν, ἤν</b>.</p><h3>Β. Ολικής αγνοίας — διμερείς (διπλές ερωτήσεις)</h3><p>Παρουσιάζουν δύο σκέλη και εισάγονται με αντιστοιχίες:</p><ul><li><b>πότερον (πότερα) … ἤ</b> → «αν … ή»</li><li><b>εἰ … ἤ</b> → «αν … ή»</li><li><b>εἴτε … εἴτε</b> → «είτε … είτε»</li></ul><p>Το πρώτο σκέλος δίνει το ένα ενδεχόμενο, το «ἤ / εἴτε» εισάγει το αντιτιθέμενο.</p><h3>Γ. Μερικής αγνοίας</h3><p>Εισάγονται με <b>ερωτηματικές</b> ή με <b>αναφορικές</b> αντωνυμίες και επιρρήματα. Χαρακτηριστικό της ελληνικής είναι ότι μετά από ρήμα εξάρτησης μπορεί να χρησιμοποιηθεί <i>είτε</i> η καθαρά ερωτηματική λέξη (τίς, ποῦ) <i>είτε</i> η αντίστοιχη αναφορική/αναφορικού-αόριστη (ὅστις, ὅπου), συχνά με προτίμηση στους τύπους σε <b>ὁπο-</b> (ὅστις, ὁπόσος, ὅπου, ὁπότε…).</p>","table":{"title":"Εισαγωγικές λέξεις μερικής αγνοίας (ερωτηματικές ↔ αναφορικές)","cols":["Σημασία","Ερωτηματική","Αναφορική / αναφ.-αόριστη"],"rows":[["ποιος","τίς","ὅς, ὅστις"],["ποιος από τους δύο","πότερος","ὁπότερος"],["πόσος","πόσος","ὅσος, ὁπόσος"],["τι λογής","ποῖος","οἷος, ὁποῖος"],["πόσο μεγάλος","πηλίκος","ἡλίκος, ὁπηλίκος"],["από ποιον τόπο/γένος","ποδαπός","ὁποδαπός"],["πού (στάση)","ποῦ","οὗ, ὅπου, ἔνθα"],["πού (κίνηση προς)","ποῖ","οἷ, ὅποι"],["από πού","πόθεν","ὅθεν, ὁπόθεν"],["από ποιον δρόμο","πῇ","ᾗ, ὅπῃ"],["πώς","πῶς","ὡς, ὅπως"],["πότε","πότε","ὅτε, ὁπότε, ἡνίκα, ὁπηνίκα"],["πόσες φορές","ποσάκις","ὁποσάκις"]]},"examples":[{"gr":"Ἀπορεῖς εἰ διδακτόν ἐστιν ἡ ἀρετή.","an":"Απορείς αν η αρετή είναι διδακτή. — Ολικής αγνοίας μονομερής με «εἰ»."},{"gr":"Σκόπει ἐάν καί σοί ἀρέσῃ.","an":"Εξέτασε αν αρέσει και σ' εσένα. — Σπάνια εισαγωγή μονομερούς με «ἐάν»."},{"gr":"Σκοπῶμεν εἰ ἡμῖν πρέπει ἤ σοί.","an":"Ας εξετάσουμε αν ταιριάζει σ' εμάς ή σ' εσένα. — Διμερής με «εἰ … ἤ»."},{"gr":"Κρίνετε πότερον ἡ ἀρετή μᾶλλον ἤ ἡ φυγή σῴζει τάς ψυχάς.","an":"Κρίνετε αν μάλλον η αρετή ή η φυγή σώζει τις ψυχές. — Διμερής με «πότερον … ἤ»."},{"gr":"Μή γνώτω ἡ ἀριστερά σου τί ποιεῖ ἡ δεξιά σου.","an":"Ας μη μάθει το αριστερό σου χέρι τι κάνει το δεξί. — Μερικής αγνοίας με ερωτηματική αντωνυμία «τί»."},{"gr":"Ἡρώτα εἰ εἴη ἄλλη ὁδός.","an":"Ρωτούσε αν υπήρχε άλλος δρόμος. — Μονομερής με «εἰ» + ευκτική πλαγίου («εἴη»)."},{"gr":"Ἤρετο αὐτόν εἰ βληθείη.","an":"Ξεν. Κύρ. Παιδ. 8.3.30 — Τον ρώτησε αν είχε χτυπηθεί. Μονομερής ολικής αγνοίας με «εἰ» + ευκτική πλαγίου («βληθείη») μετά ιστορικό χρόνο."},{"gr":"Ἤρετο αὐτόν πόσον χρυσίον ἔχοι.","an":"(τύπου) — Τον ρώτησε πόσο χρυσάφι έχει. Μερικής αγνοίας με ερωτηματικό «πόσον» + ευκτική πλαγίου («ἔχοι»)."}],"note":"Παγίδα ορθογραφίας-σημασίας: στις διπλές ερωτήσεις το «ἤ» είναι διαζευκτικό («ή»), όχι το αναφορικό «ᾗ». Επίσης το «πότερον … ἤ» δεν μεταφράζεται «πότερα … ή» αλλά απλώς «αν … ή»· το «πότερον» εδώ έχει χάσει τη μεταφραστική του αυτοτέλεια και λειτουργεί ως απλό εισαγωγικό μόριο."},{"h":"Η εκφορά (εγκλίσεις) των πλάγιων ερωτηματικών","body":"<p>Επειδή η πλάγια ερωτηματική προέρχεται από μια ευθεία ερώτηση, <b>διατηρεί κατ' αρχήν την έγκλιση της αντίστοιχης ευθείας ερώτησης</b>. Έτσι εκφέρεται με τις εγκλίσεις τόσο των προτάσεων κρίσεως όσο και των προτάσεων επιθυμίας. Συγκεκριμένα:</p><h3>1. Οριστική — το πραγματικό</h3><p>Όταν η ερώτηση αφορά κάτι πραγματικό/αντικειμενικό.</p><h3>2. Δυνητική οριστική — το δυνατό/μη πραγματικό στο παρελθόν</h3><p>Οριστική ιστορικού χρόνου + <b>ἄν</b>· δηλώνει κάτι που θα μπορούσε να συμβεί ή το αντίθετο του πραγματικού.</p><h3>3. Δυνητική ευκτική — το δυνατό στο παρόν/μέλλον</h3><p>Ευκτική + <b>ἄν</b>· δηλώνει το ενδεχόμενο.</p><h3>4. Απορηματική (διστακτική) υποτακτική — η απορία για ενέργεια</h3><p>Υποτακτική (συνήθως α' προσώπου) σε ερωτήσεις του τύπου «τι να κάνω;», όταν εκφράζεται αμηχανία για κάτι που πρέπει/πρόκειται να γίνει. Είναι η πλάγια μορφή της <i>απορηματικής/διστακτικής υποτακτικής</i> του ευθέος λόγου.</p><h3>5. Ευκτική του πλαγίου λόγου — η εξάρτηση από ιστορικό χρόνο</h3><p>Αυτή είναι η πιο χαρακτηριστική εκφορά. Όταν το ρήμα εξάρτησης βρίσκεται σε <b>ιστορικό χρόνο</b> (παρατατικό, αόριστο, υπερσυντέλικο), η οριστική ή η απορηματική υποτακτική του ευθέος λόγου μπορεί να μετατραπεί σε <b>ευκτική του πλαγίου λόγου</b>. Δηλώνει ότι το περιεχόμενο παρουσιάζεται ως <i>υποκειμενική γνώμη / αναφορά</i> κάποιου, όχι ως αντικειμενική βεβαιότητα του συγγραφέα. Η χρήση της είναι <b>προαιρετική</b>: ο συγγραφέας μπορεί να κρατήσει την οριστική για ζωντάνια/παραστατικότητα.</p>","table":{"title":"Από τον ευθύ στον πλάγιο: μετατροπή έγκλισης μετά από ιστορικό χρόνο","cols":["Ευθεία ερώτηση","Έγκλιση","Πλάγια (μετά ιστορικό χρόνο)","Έγκλιση"],"rows":[["Τίς ἐστιν;","οριστική","ἠρώτα τίς εἴη","ευκτική πλαγίου"],["Τί πάθω;","απορηματική υποτ.","ἠπόρει τί πάθοι","ευκτική πλαγίου"],["Τί παραγγέλλει;","οριστική","ἤρετο εἰ τί παραγγέλλοι","ευκτική πλαγίου"]]},"examples":[{"gr":"Σκεψόμεθα εἰ ἀληθῆ λέγεις.","an":"Θα εξετάσουμε αν λες την αλήθεια. — Οριστική (λέγεις): το πραγματικό. Εξάρτηση από αρκτικό χρόνο, δεν μετατρέπεται."},{"gr":"Ἐβουλεύοντο εἴτε κατακαύσωσιν αὐτούς εἴτε τι ἄλλο χρήσωνται.","an":"Σκέφτονταν είτε να τους κάψουν είτε να τους μεταχειριστούν αλλιώς. — Απορηματική υποτακτική (κατακαύσωσιν, χρήσωνται): απορία για ενέργεια."},{"gr":"Ἤρετο εἰ τί παραγγέλλοι.","an":"Ρώτησε αν παράγγελνε κάτι. — Ευκτική του πλαγίου λόγου (παραγγέλλοι), γιατί εξαρτάται από τον ιστορικό χρόνο «ἤρετο»· στον ευθύ θα ήταν οριστική «παραγγέλλει;»."},{"gr":"Ἄδηλον ἦν εἴτε κρατήσαιεν εἴτε κρατηθεῖεν.","an":"Ήταν άδηλο αν θα νικούσαν ή αν θα νικιόνταν. — Διμερής· ευκτική πλαγίου (κρατήσαιεν, κρατηθεῖεν) μετά τον ιστορικό «ἦν»."},{"gr":"Ἐπυνθάνετο ὅπως ἄν κάλλιον πορευθείη.","an":"Ζητούσε να μάθει πώς θα μπορούσε να ταξιδέψει καλύτερα. — Δυνητική ευκτική (ἄν … πορευθείη): το δυνατό."},{"gr":"Ἀπορῶν ποῖ τράποιτο, ἀναβαίνει ἐπί λόφον τινά.","an":"Ξεν. Κύρ. Παιδ. 3.1.4 (τύπου) — Μη ξέροντας προς τα πού να στραφεί, ανεβαίνει σε κάποιον λόφο. Απορηματική υποτακτική του ευθέος («ποῖ τράπωμαι;») μετατραπείσα σε ευκτική πλαγίου («τράποιτο»)."},{"gr":"Ἠρώτα αὐτόν τίς εἴη.","an":"(τύπου Ξεν.) — Τον ρωτούσε ποιος ήταν. Ευκτική πλαγίου («εἴη») μετά τον ιστορικό «ἠρώτα»· στον ευθύ «τίς εἶ;» (οριστική)."}],"note":"Κρίσιμη παγίδα: η ευκτική του πλαγίου λόγου εμφανίζεται ΜΟΝΟ ύστερα από ιστορικό χρόνο εξάρτησης και είναι ΠΡΟΑΙΡΕΤΙΚΗ. Αν δεις ευκτική χωρίς «ἄν» σε πλάγια ερωτηματική με ρήμα σε αόριστο/παρατατικό, είναι σχεδόν βέβαια ευκτική πλαγίου — όχι δυνητική (η δυνητική θέλει «ἄν») ούτε ευχετική."},{"h":"Ο συντακτικός ρόλος και τα ρήματα εξάρτησης","body":"<p>Ως <b>ονοματική</b> πρόταση, η πλάγια ερωτηματική παίρνει τη θέση ενός ονόματος μέσα στην πρόταση εξάρτησης. Έχει τρεις βασικούς συντακτικούς ρόλους.</p><h3>1. Αντικείμενο</h3><p>Ο πιο συνηθισμένος ρόλος: αντικείμενο σε <b>μεταβατικό ρήμα</b> που σημαίνει ερώτηση, γνώση/άγνοια, σκέψη, απόπειρα, φροντίδα, δήλωση. Πρόκειται για τα λεγόμενα <i>ρήματα εξάρτησης</i> των πλάγιων ερωτηματικών:</p><ul><li><b>Ερωτηματικά / πληροφορίας</b>: ἐρωτῶ, ἐρωτάω, πυνθάνομαι, ἐρευνῶ.</li><li><b>Απορίας / θαυμασμού</b>: ἀπορῶ, θαυμάζω.</li><li><b>Γνωστικά</b>: οἶδα, γιγνώσκω, ὁρῶ, αἰσθάνομαι, ἀγνοῶ, μανθάνω.</li><li><b>Απόπειρας / φροντίδας</b>: πειρῶμαι, παρασκευάζομαι, φροντίζω, ἐπιμελοῦμαι, φυλάττομαι, πράττω.</li><li><b>Σκέψης / εξέτασης / βούλευσης</b>: σκοπῶ, σκοποῦμαι, ἐξετάζω, βουλεύομαι, λογίζομαι.</li><li><b>Δήλωσης / παρουσίασης</b>: δείκνυμι, δηλῶ, λέγω, φράζω, ἀποκρίνομαι, διδάσκω.</li></ul><h3>2. Υποκείμενο</h3><p>Όταν εξαρτάται από <b>απρόσωπο ρήμα ή απρόσωπη έκφραση</b>: ἄδηλόν ἐστι, ἀφανές ἐστι, ἄπορόν ἐστι, φανερόν ἐστι, δῆλόν ἐστι, θαυμαστόν ἐστι, λέγεται, δέδεικται.</p><h3>3. Επεξήγηση</h3><p>Όταν επεξηγεί προηγούμενη <b>δεικτική αντωνυμία ουδετέρου γένους</b> (τοῦτο, ἐκεῖνο, τάδε) ή κάποιο αφηρημένο ουσιαστικό (ἀπορία, σκέψις, παρασκευή).</p>","examples":[{"gr":"Αὐτός τε θηρᾷ καί τῶν ἄλλων ἐπιμελεῖται ὅπως ἄν θηρῶσιν.","an":"Και ο ίδιος κυνηγά και φροντίζει για το πώς να κυνηγούν οι άλλοι. — Η πλάγια ερωτηματική είναι αντικείμενο (ως προς το περιεχόμενο φροντίδας) στο «ἐπιμελεῖται»."},{"gr":"Ἄδηλον ἦν εἰ ἀδίκως ἐτετιμώρηντο.","an":"Ήταν άδηλο αν είχαν τιμωρηθεί άδικα. — Η πρόταση «εἰ … ἐτετιμώρηντο» είναι υποκείμενο στην απρόσωπη έκφραση «ἄδηλον ἦν»."},{"gr":"Ἐλέγετο καί ᾧ τρόπῳ ἡ ναυμαχία ἐγένετο.","an":"Λεγόταν και με ποιον τρόπο έγινε η ναυμαχία. — Υποκείμενο στο παθητικό-απρόσωπο «ἐλέγετο»."},{"gr":"Τοῦτο σκεψώμεθα, εἰ ἀληθῆ λέγεις.","an":"Αυτό ας εξετάσουμε, αν λες την αλήθεια. — Επεξήγηση στη δεικτική αντωνυμία «τοῦτο»."},{"gr":"Σκόπει πότερος ἡμῶν ἀποκρινεῖται.","an":"Σκέψου ποιος από τους δυο μας θα απαντήσει. — Αντικείμενο στο ρήμα σκέψεως «σκόπει»."},{"gr":"Οἶσθ' εἰ ζῶν κυρεῖ;","an":"Σοφ. Φιλ. 444 — Ξέρεις αν τυχαίνει να ζει; Η πλάγια ερωτηματική «εἰ ζῶν κυρεῖ» είναι αντικείμενο στο γνωστικό «οἶσθα»."},{"gr":"Δῆλον ἦν ὅτῳ τρόπῳ ἔδει πορεύεσθαι.","an":"(τύπου) — Ήταν φανερό με ποιον τρόπο έπρεπε να πορευτούν. Η πλάγια ερωτηματική είναι υποκείμενο στην απρόσωπη έκφραση «δῆλον ἦν»."}],"note":"Διάκριση από τις ειδικές προτάσεις: τα ρήματα «λέγω, δείκνυμι, δηλῶ» μπορούν να εισάγουν ΚΑΙ ειδική («ὅτι/ὡς») ΚΑΙ πλάγια ερωτηματική. Αν ακολουθεί ερωτηματική/αναφορική λέξη ή «εἰ» με νόημα απορίας, είναι πλάγια ερωτηματική· αν ακολουθεί «ὅτι/ὡς» με νόημα βεβαίωσης, είναι ειδική."},{"h":"Μεθοδολογία αναγνώρισης, μετατροπές και συγκριτικός πίνακας","body":"<p>Για να αναγνωρίσεις και να αναλύσεις με ασφάλεια μια πλάγια ερωτηματική, ακολούθησε σταθερά βήματα.</p><h3>Βήματα αναγνώρισης</h3><ol><li><b>Βρες το ρήμα εξάρτησης.</b> Σημαίνει ερώτηση, γνώση, σκέψη, απορία, φροντίδα, δήλωση; Αν ναι, υποψιάσου πλάγια ερωτηματική.</li><li><b>Εντόπισε την εισαγωγική λέξη.</b> εἰ / πότερον…ἤ / εἴτε…εἴτε → ολικής αγνοίας. Ερωτηματική ή αναφορική αντωνυμία/επίρρημα → μερικής αγνοίας.</li><li><b>Δες την έγκλιση εκφοράς</b> και χαρακτήρισέ την (οριστική / δυνητική / απορηματική υποτ. / ευκτική πλαγίου).</li><li><b>Όρισε τον συντακτικό ρόλο</b> (αντικείμενο / υποκείμενο / επεξήγηση) με βάση το ρήμα εξάρτησης.</li></ol><h3>Μετατροπή ευθέος ↔ πλάγιου λόγου</h3><p>Κατά τη μετατροπή μιας ευθείας ερώτησης σε πλάγια:</p><ul><li>Φεύγει το ερωτηματικό (;) και προστίθεται το ρήμα εξάρτησης.</li><li>Οι ευθείες ερωτηματικές αντωνυμίες/επιρρήματα συχνά αντικαθίστανται από τις αναφορικές (τίς → ὅστις, ποῦ → ὅπου).</li><li>Στην ολική ερώτηση χωρίς ερωτηματική λέξη προστίθεται το «εἰ».</li><li>Αν το ρήμα εξάρτησης είναι ιστορικού χρόνου, η οριστική/απορηματική υποτακτική μπορεί να γίνει ευκτική πλαγίου.</li><li>Αλλάζουν ανάλογα πρόσωπα, χρόνοι δεικτικών και επιρρημάτων (ἐγώ→ἐκεῖνος, νῦν→τότε κ.λπ.).</li></ul><p>Παράδειγμα πλήρους μετατροπής: «Τί ποιεῖς;» → (ιστορικός χρόνος) «Ἤρετό με τί ποιοίην.» (Με ρώτησε τι έκανα.)</p>","table":{"title":"Πλάγιες ερωτηματικές vs άλλες ονοματικές προτάσεις","cols":["Γνώρισμα","Πλάγιες ερωτηματικές","Ειδικές","Ενδοιαστικές"],"rows":[["Νόημα","ερώτηση / απορία","βεβαίωση γεγονότος","φόβος / ανησυχία"],["Ρήμα εξάρτησης","ἐρωτῶ, ἀπορῶ, οἶδα, σκοπῶ","λέγω, νομίζω, ἀκούω","φοβοῦμαι, κίνδυνός ἐστι"],["Εισαγωγή","εἰ, πότερον…ἤ, ερωτ./αναφ. λέξεις","ὅτι, ὡς","μή, μή οὐ"],["Άρνηση","οὐ (κρίση) / μή (επιθυμία)","οὐ","—"],["Εκφορά","όλες (+ ευκτ. πλαγίου, απορημ. υποτ.)","οριστική, δυνητικές, ευκτ. πλαγίου","υποτακτική, ευκτ. πλαγίου"],["Ρόλος","αντικ./υποκ./επεξήγηση","αντικ./υποκ./επεξήγηση","αντικ./υποκ./επεξήγηση"]]},"examples":[{"gr":"Ἤρετό με τί ποιοίην.","an":"Με ρώτησε τι έκανα. — Μετατροπή του ευθέος «Τί ποιεῖς;» σε πλάγιο μετά ιστορικό χρόνο: τίς→διατηρείται το «τί», οριστική «ποιεῖς»→ευκτική πλαγίου «ποιοίην», αλλαγή προσώπου."},{"gr":"Οὐκ οἶδα εἰ ἀληθῆ λέγεις ἤ ψεύδῃ.","an":"Δεν ξέρω αν λες την αλήθεια ή ψέματα. — Διμερής (εἰ…ἤ), αντικείμενο στο γνωστικό «οἶδα», οριστική εκφορά (πραγματικό), άρνηση «οὐκ» γιατί περιέχει κρίση."},{"gr":"Σκεπτέον εἰ συμφέρει ἤ μή.","an":"Πρέπει να εξεταστεί αν συμφέρει ή όχι. — Υποκείμενο στο ρηματικό επίθετο/απρόσωπο «σκεπτέον»· διμερής με «ἤ μή»."},{"gr":"Ἐθαύμαζον ἐπί πόσον ἡ θάλασσα διήκοι.","an":"(τύπου Ξεν.) — Απορούσαν ως πού εκτεινόταν η θάλασσα. Μερικής αγνοίας με «ἐπί πόσον», αντικείμενο στο ρήμα θαυμασμού· ευκτική πλαγίου («διήκοι»)."},{"gr":"Εἴτε ὠφελίαν εἴτε βλάβην παρέχει, σκεπτέον.","an":"Πλάτ. Φαῖδρ. 237d (τύπου) — Πρέπει να εξεταστεί αν παρέχει ωφέλεια ή βλάβη. Διμερής με «εἴτε … εἴτε», υποκείμενο στο «σκεπτέον»."}],"note":"Συνηθέστερα λάθη μαθητών: (1) να χαρακτηρίζουν «υποθετική» κάθε πρόταση με «εἰ» — έλεγξε πάντα το ρήμα εξάρτησης· (2) να ξεχνούν τον διττό ρόλο της άρνησης (οὐ/μή)· (3) να συγχέουν την ευκτική του πλαγίου (χωρίς ἄν, μετά ιστορικό χρόνο) με τη δυνητική ευκτική (πάντα με ἄν)."}]);
  T("syn-anaforikes", [{"h":"Τι είναι οι αναφορικές προτάσεις — ορισμός, λειτουργία, στίξη","body":"<p><b>Αναφορικές</b> ονομάζονται οι δευτερεύουσες προτάσεις που <b>αναφέρονται σε έναν όρο</b> μιας άλλης (συνήθως της κύριας) πρότασης ή σε ολόκληρο το νόημά της, και τον προσδιορίζουν, τον εξειδικεύουν ή τον συμπληρώνουν. Ο όρος στον οποίο αναφέρονται λέγεται <b>όρος αναφοράς</b> ή <b>προηγούμενο</b> (Lat. <i>antecedent</i>), επειδή κανονικά προηγείται της αναφορικής πρότασης.</p><p>Εισάγονται πάντοτε με μια <b>αναφορική λέξη</b>: είτε με <b>αναφορική αντωνυμία</b> (ὅς, ἥ, ὅ· ὅστις· οἷος· ὅσος· ἡλίκος· ὅσπερ κ.λπ.) είτε με <b>αναφορικό επίρρημα</b> (οὗ, ὅπου, ἔνθα· οἷ, ὅποι· ὅθεν, ὁπόθεν· ᾗ, ὅπῃ· ὡς, ὥσπερ, ὅπως· ὅτε, ὁπότε, ἡνίκα). Η αναφορική λέξη επιτελεί διπλό έργο: αφενός <b>συνδέει</b> τη δευτερεύουσα με την προσδιοριζόμενη λέξη, αφετέρου <b>έχει δική της συντακτική θέση</b> μέσα στην αναφορική πρόταση (υποκείμενο, αντικείμενο, προσδιορισμός κ.λπ.).</p><h3>Δύο μεγάλες κατηγορίες</h3><p>Με βάση το είδος της εισαγωγικής λέξης και τη λειτουργία τους, οι αναφορικές διακρίνονται σε:</p><ul><li><b>Αναφορικές ονοματικές</b>: εισάγονται με αναφορική <i>αντωνυμία</i> και ισοδυναμούν με όνομα (ουσιαστικό ή επίθετο)· λειτουργούν δηλαδή ως υποκείμενο, αντικείμενο, κατηγορούμενο, παράθεση, επεξήγηση, επιθετικός ή ετερόπτωτος προσδιορισμός.</li><li><b>Αναφορικές επιρρηματικές</b>: εισάγονται με αναφορικό <i>επίρρημα</i> και ισοδυναμούν με επίρρημα τόπου, χρόνου, τρόπου ή ποσού.</li></ul><p>Ξεχωριστή, ιδιαίτερα σημαντική ομάδα αποτελούν οι <b>αναφορικές με επιρρηματική σημασία</b> (αναφορικοϋποθετικές, τελικές, αποτελεσματικές, αιτιολογικές, παραχωρητικές, παραβολικές): εισάγονται μεν με αναφορική λέξη, αλλά εκφράζουν επιρρηματική σχέση προς την κύρια.</p><h3>Στίξη — προσδιοριστικές vs. προσθετικές</h3><p>Ανάλογα με το αν είναι απαραίτητες για το νόημα διακρίνονται σε:</p><ul><li><b>Προσδιοριστικές / αναγκαίες</b> (περιοριστικές): εξειδικεύουν τον όρο αναφοράς και είναι αναπόσπαστες· <i>δεν</i> χωρίζονται με κόμμα. Π.χ. «<i>οἱ ἄνθρωποι</i> <b>οἵ ἀδικοῦσι</b> κολάζονται».</li><li><b>Προσθετικές / παραθετικές</b> (μη περιοριστικές): δίνουν μια πρόσθετη, μη απαραίτητη πληροφορία και χωρίζονται με κόμμα. Π.χ. «Σωκράτης, <b>ὅς σοφώτατος ἦν</b>, κατεδικάσθη».</li></ul>","examples":[{"gr":"Οὐ καλά ἦν ἅ ἔπραξα.","an":"Δεν ήταν καλά αυτά που έπραξα. — Η αναφορική «ἅ ἔπραξα» (ονοματική) λειτουργεί ως <b>υποκείμενο</b> του «ἦν»· το «ἅ» είναι αντικείμενο του «ἔπραξα» μέσα στη δευτερεύουσα."},{"gr":"Ἔστιν δίκης ὀφθαλμός ὅς τά πάνθ᾽ ὁρᾷ.","an":"Υπάρχει οφθαλμός της δίκης, ο οποίος τα πάντα βλέπει. — Προσδιοριστική αναφορική στον όρο «ὀφθαλμός»· το «ὅς» είναι υποκείμενο του «ὁρᾷ»."},{"gr":"Ἅ μή οἶδα, οὐδέ οἴομαι εἰδέναι.","an":"Όσα δεν ξέρω, ούτε νομίζω ότι τα ξέρω (πρβλ. Πλάτ. Ἀπολ. 21d). — Ονοματική αναφορική ως αντικείμενο· άρνηση «μή» γιατί έχει αόριστη/υποθετική χροιά."},{"gr":"Ἅ μή προσήκει μήτ᾽ ἄκουε μήθ᾽ ὅρα.","an":"Όσα δεν ταιριάζει, ούτε να ακούς ούτε να βλέπεις. — Ελεύθερη ονοματική αναφορική ως αντικείμενο των «ἄκουε / ὅρα»· γενικευτική χροιά με άρνηση «μή»."},{"gr":"Ξενοφῶν, ὅς καί στρατηγός ᾑρέθη, Ἀθηναῖος ἦν.","an":"Ο Ξενοφών, ο οποίος και εκλέχθηκε στρατηγός, ήταν Αθηναίος. — <b>Προσθετική (παραθετική)</b> αναφορική, χωρισμένη με κόμμα· «ὅς» υποκείμενο του «ᾑρέθη»."}]},{"h":"Οι εισαγωγικές λέξεις: αναφορικές αντωνυμίες και επιρρήματα","body":"<p>Η σωστή αναγνώριση μιας αναφορικής πρότασης ξεκινά από την εισαγωγική της λέξη. Διακρίνουμε δύο ομάδες.</p><h3>1. Αναφορικές αντωνυμίες (→ ονοματικές αναφορικές)</h3><ul><li><b>ὅς, ἥ, ὅ</b> = ο οποίος / αυτός που (η κύρια, η πιο συνηθισμένη)</li><li><b>ὅσπερ, ἥπερ, ὅπερ</b> = ο οποίος ακριβώς (εμφατική)</li><li><b>ὅστις, ἥτις, ὅ τι</b> = όποιος, καθένας που (αόριστη/γενικευτική)</li><li><b>ὅσος, -η, -ον</b> = όσος (ποσό)· <b>οἷος, -α, -ον</b> = οποίου είδους / τέτοιος που (ποιόν)</li><li><b>ἡλίκος, ὁπηλίκος</b> = όσο μεγάλος (μέγεθος/ηλικία)· <b>ὁποῖος, ὁπότερος, ὁποδαπός</b> (έμμεσα/αόριστα)</li></ul><h3>2. Αναφορικά επιρρήματα (→ επιρρηματικές αναφορικές)</h3><p>Δηλώνουν τόπο, χρόνο, τρόπο ή ποσό και ισοδυναμούν με επίρρημα:</p><ul><li><b>Τόπου — στάση:</b> οὗ, ὅπου, ἔνθα, ἵνα (= όπου)</li><li><b>Τόπου — κίνηση προς:</b> οἷ, ὅποι (= όπου, προς τα όπου)</li><li><b>Τόπου — κίνηση από:</b> ὅθεν, ὁπόθεν, ἔνθεν (= από όπου)</li><li><b>Τρόπου:</b> ᾗ, ὅπῃ, ὡς, ὥσπερ, ὅπως (= όπως, με τον τρόπο που)</li><li><b>Χρόνου:</b> ὅτε, ὁπότε, ἡνίκα, ἐπεί (αναφορικοχρονικά)</li><li><b>Ποσού:</b> ὅσον, ὅσῳ (= όσο)</li></ul><p><b>Χρήσιμη παγίδα:</b> Πολλές από αυτές τις λέξεις (ὡς, ὅπως, ὅτε, ὅσον, ᾗ) εισάγουν και άλλα είδη δευτερευουσών (ειδικές, τελικές, χρονικές, παραβολικές). Η αναγνώριση γίνεται από το νόημα και τη σύνταξη, όχι μόνο από τη λέξη.</p>","table":{"title":"Αναφορικές λέξεις και η αντιστοιχία τους","cols":["Είδος","Εισαγωγικές λέξεις","Σημασία / Λειτουργία","Είδος αναφορικής"],"rows":[["Αντωνυμία προσώπου/πράγματος","ὅς, ἥ, ὅ · ὅσπερ","ο οποίος (ακριβώς)","ονοματική"],["Αόριστη/γενικευτική","ὅστις, ἥτις, ὅ τι","όποιος, καθένας που","ονοματική (συχνά υποθ. χροιά)"],["Ποσού","ὅσος · ὅσον, ὅσῳ","όσος / όσο","ονοματική / επιρρηματική ποσού"],["Ποιού","οἷος · ἡλίκος","τέτοιος που / όσο μεγάλος","ονοματική"],["Επίρρημα τόπου (στάση)","οὗ, ὅπου, ἔνθα","όπου","επιρρηματική τόπου"],["Επίρρημα τόπου (κίνηση)","οἷ, ὅποι · ὅθεν, ὁπόθεν","προς όπου / από όπου","επιρρηματική τόπου"],["Επίρρημα τρόπου","ᾗ, ὅπῃ, ὡς, ὥσπερ","όπως, με τον τρόπο που","επιρρηματική τρόπου / παραβολική"],["Επίρρημα χρόνου","ὅτε, ὁπότε, ἡνίκα","τότε που, όταν","αναφορικοχρονική"]]},"examples":[{"gr":"Ἔνθα ἦσαν οἱ πολέμιοι, ἐκεῖ ἐστρατοπεδεύσαντο.","an":"Όπου ήταν οι εχθροί, εκεί στρατοπέδευσαν. — «ἔνθα ... πολέμιοι»: επιρρηματική αναφορική τόπου (στάση), ισοδύναμη με επίρρημα τόπου· προεξαγγέλλεται από το δεικτικό «ἐκεῖ»."},{"gr":"Λέγε ὅπως γιγνώσκεις.","an":"Μίλα όπως κρίνεις σωστό. — «ὅπως γιγνώσκεις»: επιρρηματική αναφορική τρόπου."},{"gr":"Τοιοῦτός ἐστιν οἷον πάντες ἴσμεν.","an":"Είναι τέτοιος όπως όλοι γνωρίζουμε. — Η αντωνυμία «οἷον» (ποιού) σε συσχετισμό με το δεικτικό «τοιοῦτος»."},{"gr":"Ἐπορεύοντο ὅθεν ἦλθον.","an":"Προχωρούσαν από εκεί από όπου είχαν έρθει. — Επιρρηματική αναφορική τόπου (κίνηση από)· το «ὅθεν» ισοδυναμεί με επίρρημα τόπου-αφετηρίας."},{"gr":"Ὅσῳ μᾶλλον πιστεύεις, τοσούτῳ μᾶλλον σφαλήσῃ.","an":"Όσο περισσότερο εμπιστεύεσαι, τόσο περισσότερο θα σφάλεις. — Επιρρηματική αναφορική ποσού «ὅσῳ ... τοσούτῳ» (συσχετισμός ποσού)."}]},{"h":"Αναφορικές ονοματικές: συντακτικοί ρόλοι","body":"<p>Οι <b>ονοματικές</b> αναφορικές ισοδυναμούν με όνομα και μπορούν να καταλάβουν κάθε θέση που παίρνει ένα ουσιαστικό ή επίθετο. Όταν λείπει ο όρος αναφοράς (είναι σιωπηρός ή ενσωματωμένος), μιλούμε για <b>ελεύθερες / αυτοτελείς</b> αναφορικές (π.χ. «ὅς λέγει» = «αυτός που λέγει»). Όταν υπάρχει εκπεφρασμένος όρος αναφοράς, μιλούμε για <b>προσδιοριστικές</b>.</p><h3>Οι κυριότερες συντακτικές θέσεις</h3><ul><li><b>Υποκείμενο</b> ρήματος: «<i>ὅς ταῦτα ποιεῖ</i> ἁμαρτάνει» (αυτός που τα κάνει σφάλλει).</li><li><b>Αντικείμενο</b>: «θαυμάζω <i>ἅ λέγεις</i>» (θαυμάζω όσα λες).</li><li><b>Κατηγορούμενο</b>: «οὗτός ἐστιν <i>ὅν ἐζήτεις</i>» (αυτός είναι εκείνος που ζητούσες).</li><li><b>Παράθεση / Επεξήγηση</b>: σε ονόματα προσώπων ή πραγμάτων.</li><li><b>Επιθετικός προσδιορισμός</b> (η συνηθέστερη χρήση): προσδιορίζει ουσιαστικό, όπως ένα επίθετο.</li><li><b>Ετερόπτωτος προσδιορισμός</b> (γενική / δοτική): π.χ. αντικειμενική γενική.</li></ul><p>Η <b>πτώση της αναφορικής αντωνυμίας</b> καθορίζεται κατά κανόνα από τη <i>συντακτική της θέση μέσα στην αναφορική πρόταση</i>, ενώ το <b>γένος και ο αριθμός</b> της ακολουθούν τον όρο αναφοράς (συμφωνία). Π.χ. στο «τούς ἄνδρας <b>οὕς</b> εἶδον», το «οὕς» είναι αρσενικό πληθυντικό (από τον όρο «ἄνδρας») αλλά αιτιατική (γιατί είναι αντικείμενο του «εἶδον»).</p>","examples":[{"gr":"Οὗτός ἐστιν ὅν πάλαι ζητοῦμεν.","an":"Αυτός είναι εκείνος που από καιρό ζητούμε. — Ονοματική αναφορική ως <b>κατηγορούμενο</b> στο «οὗτος»· το «ὅν» αιτιατική (αντικείμενο του «ζητοῦμεν»)."},{"gr":"Ξενοφῶν, ὅς καί συνέγραψε τήν Ἀνάβασιν, Ἀθηναῖος ἦν.","an":"Ο Ξενοφών, ο οποίος και έγραψε την Ανάβαση, ήταν Αθηναίος. — Προσθετική (παραθετική) αναφορική, χωρισμένη με κόμμα· «ὅς» υποκείμενο του «συνέγραψε»."},{"gr":"Μέμνησο ὧν ὑπέσχου.","an":"Να θυμάσαι όσα υποσχέθηκες. — Ελεύθερη ονοματική αναφορική ως αντικείμενο· εδώ υπάρχει και έλξη (βλ. παρακάτω): «ὧν» αντί «ἅ»."},{"gr":"Ὅς μέν γάρ οἴεται ἱκανῶς ἔχειν, οὐδέν ζητεῖ.","an":"Όποιος νομίζει ότι είναι αρκετός, τίποτε δεν αναζητεί. — Ελεύθερη ονοματική αναφορική ως <b>υποκείμενο</b> του «ζητεῖ»· το «ὅς» υποκείμενο του «οἴεται»."},{"gr":"Λέγω ἅ φρονῶ.","an":"Λέγω όσα σκέφτομαι. — Ελεύθερη ονοματική αναφορική ως <b>αντικείμενο</b> του «λέγω»· το «ἅ» αντικείμενο του «φρονῶ»."}],"note":"Παγίδα συμφωνίας: γένος + αριθμός από τον όρο αναφοράς· πτώση από τη θέση μέσα στην αναφορική. Εξαίρεση σε αυτό αποτελεί η έλξη του αναφορικού (βλ. ενότητα 6)."},{"h":"Αναφορικές με επιρρηματική σημασία (Ι): αναφορικοϋποθετικές","body":"<p>Πρόκειται για αναφορικές που, ενώ εισάγονται με αναφορική λέξη, <b>ισοδυναμούν με υποθετική πρόταση</b> (πρόταση εἰ-). Δηλώνουν δηλαδή την προϋπόθεση/υπόθεση από την οποία εξαρτάται η κύρια. Είναι από τα συχνότερα φαινόμενα της αττικής σύνταξης.</p><h3>Πώς αναγνωρίζονται</h3><ul><li>Εισάγονται κυρίως με τις <b>αόριστες/γενικευτικές</b> αναφορικές: <b>ὅστις, ὅς (αόρ.), ὅσος, οἷος</b> και τα επιρρήματα <b>ὅπου, ὅπως, ὅταν</b> κ.λπ.</li><li>Έχουν <b>γενικό / αόριστο</b> νόημα (= «όποιος / όσοι κι αν»).</li><li>Συχνή <b>άρνηση μή</b> (όχι οὐ) — ισχυρή ένδειξη υποθετικής χροιάς.</li><li>Η <b>έγκλιση</b> και ο <b>χρόνος</b> αντιστοιχούν στους τύπους των υποθετικών λόγων.</li></ul><h3>Αναλύονται σε υποθετικό λόγο</h3><p>Η αναφορικοϋποθετική + η κύρια σχηματίζουν έναν πλήρη <b>υποθετικό λόγο</b>· η αναφορική ισοδυναμεί με την υπόθεση και η κύρια με την απόδοση. Αναγνωρίζονται και τα έξι είδη:</p><ul><li><b>Πραγματικό:</b> οριστική (εἰ + οριστ. → οριστ.)</li><li><b>Αντίθετο του πραγματικού:</b> οριστ. ιστορικού χρόνου + ἄν στην απόδοση</li><li><b>Προσδοκώμενο:</b> ἐάν/ὅταν + υποτακτική → οριστ. μέλλοντα (στην αναφ. η αντωνυμία παίρνει <b>ἄν</b>: ὅς ἄν, ὅστις ἄν + υποτ.)</li><li><b>Αόριστη επανάληψη στο παρόν/μέλλον:</b> ὅς/ὅστις ἄν + υποτακτική → οριστ. ενεστ.</li><li><b>Αόριστη επανάληψη στο παρελθόν:</b> ὅς/ὅστις + ευκτική επαναληπτική → οριστ. παρατατικού</li><li><b>Απλή σκέψη:</b> ευκτική + δυνητική ευκτική (ἄν) στην απόδοση</li></ul>","examples":[{"gr":"Ὅστις ἄν ταῦτα ποιῇ, κολασθήσεται.","an":"Όποιος τα κάνει αυτά, θα τιμωρηθεί. — Αναφορικοϋποθετική του <b>προσδοκώμενου</b>: «ὅστις ἄν ... ποιῇ» (= ἐάν τις ταῦτα ποιῇ) + απόδοση οριστ. μέλλοντα."},{"gr":"Ἅ μή ἐπιστάμεθα, οὐκ ἄν ἐπιχειροῖμεν πράττειν.","an":"Όσα δεν ξέρουμε, δεν θα επιχειρούσαμε να τα πράξουμε. — Αναφορικοϋποθετική της <b>απλής σκέψης</b>· υπόθεση «ἅ μή ἐπιστάμεθα» (άρνηση μή!), απόδοση δυνητική ευκτική «οὐκ ἄν ἐπιχειροῖμεν»."},{"gr":"Ὅς μή ἐπίσταται, σιγάτω.","an":"Όποιος δεν ξέρει, ας σωπαίνει. — Γενικευτική αναφορικοϋποθετική (= ἐάν τις μή ἐπίσταται)· η άρνηση «μή» προδίδει την υποθετική σημασία."},{"gr":"Ὅ ἄν τις σπείρῃ, τοῦτο καί θερίσει.","an":"Ό,τι σπείρει κανείς, αυτό και θα θερίσει. — Αναφορικοϋποθετική <b>αόριστης επανάληψης / προσδοκωμένου</b>: «ὅ ἄν τις σπείρῃ» (= ἐάν τι σπείρῃ) + απόδοση οριστ. μέλλοντα «θερίσει»."},{"gr":"Ὅστις τοῖς νόμοις μή πείθοιτο, οὐκ ἄν εὐδαιμονοίη.","an":"Όποιος δεν θα υπάκουε στους νόμους, δεν θα ευτυχούσε. — Αναφορικοϋποθετική της <b>απλής σκέψης</b>· ευκτική «πείθοιτο» (άρνηση μή) στην υπόθεση, δυνητική ευκτική «οὐκ ἄν εὐδαιμονοίη» στην απόδοση."}],"note":"Κανόνας-κλειδί: αν η αναφορική γενικεύει ή έχει άρνηση «μή» και αναλύεται σε «εἰ/ἐάν + ...», είναι αναφορικοϋποθετική. Το «ἄν» (ὅς ἄν, ὅστις ἄν, ὅταν) με υποτακτική είναι αλάνθαστο σημάδι."},{"h":"Αναφορικές με επιρρηματική σημασία (ΙΙ): τελικές, αποτελεσματικές, αιτιολογικές, παραχωρητικές, παραβολικές","body":"<p>Πέρα από τις υποθετικές, η αναφορική πρόταση μπορεί να αποκτά και άλλες επιρρηματικές αποχρώσεις, που φαίνονται από το νόημα, την έγκλιση και τα συμφραζόμενα.</p><h3>α) Αναφορικές τελικές (σκοπού)</h3><p>Εισάγονται με <b>ὅς, ὅστις</b> και εκφέρονται κατά κανόνα με <b>οριστική μέλλοντα</b> (σπανιότερα ευκτική στο πλάγιο λόγο). Δηλώνουν σκοπό· ισοδυναμούν με τελική πρόταση (ἵνα/ὅπως). Συχνά μετά από ρήματα αποστολής/εκλογής (πέμπω, αἱροῦμαι, πορίζομαι).</p><h3>β) Αναφορικές αποτελεσματικές (συμπερασματικές)</h3><p>Εισάγονται με <b>ὅς, ὅστις, οἷος, ὅσος</b> και προϋποθέτουν συνήθως στην κύρια μια <b>δεικτική / ποσοτική λέξη</b> (οὕτως, τοιοῦτος, τοσοῦτος, τηλικοῦτος). Δηλώνουν αποτέλεσμα· εκφέρονται με <b>οριστική</b> (πραγματικό αποτέλεσμα) ή δυνητικές εγκλίσεις. Ισοδυναμούν με συμπερασματική (ὥστε).</p><h3>γ) Αναφορικές αιτιολογικές</h3><p>Εισάγονται με <b>ὅς, ὅστις, ὅσος, οἷος</b> και δηλώνουν την <b>αιτία</b> του περιεχομένου της κύριας· ισοδυναμούν με αιτιολογική (ὅτι, ἐπεί). Έγκλιση οριστική (ή δυνητική). Συχνά μετά από ρήματα/εκφράσεις ψυχικού πάθους (θαυμάζω, μακαρίζω, οἰκτίρω).</p><h3>δ) Αναφορικές παραχωρητικές / εναντιωματικές</h3><p>Σπανιότερες· δηλώνουν εναντίωση/παραχώρηση (= «αν και»). Εισάγονται με <b>ὅς, ὅστις</b> και αναγνωρίζονται από το νόημα.</p><h3>ε) Αναφορικές παραβολικές (συγκριτικές)</h3><p>Δηλώνουν <b>σύγκριση / παρομοίωση</b> ως προς το ποσό, το ποιόν ή τον τρόπο. Εισάγονται με <b>ὡς, ὥσπερ, ὅπως, ὅσος, οἷος, ὅσῳ ... τοσούτῳ</b> κ.λπ., σε συσχετισμό με δεικτικό (οὕτως, τοσοῦτος, τοιοῦτος). Εκφέρονται με <b>οριστική</b> (πραγματική σύγκριση) ή δυνητικές εγκλίσεις (υποτιθέμενη). Δες την ξεχωριστή κατηγορία των παραβολικών στο οικείο κεφάλαιο.</p>","table":{"title":"Αναφορικές με επιρρηματική σημασία — σύνοψη","cols":["Είδος","Εισαγωγή","Έγκλιση / Εκφορά","Ισοδυναμεί με","Δείκτης αναγνώρισης"],"rows":[["Υποθετικές","ὅς (αόρ.), ὅστις, ὅσος, οἷος","εγκλίσεις υποθετικών λόγων","εἰ / ἐάν","γενίκευση, άρνηση μή, ἄν+υποτ."],["Τελικές","ὅς, ὅστις","οριστ. μέλλοντα (ή ευκτ. πλαγ.)","ἵνα / ὅπως","ρήμα αποστολής/εκλογής, σκοπός"],["Αποτελεσματικές","ὅς, ὅστις, οἷος, ὅσος","οριστική / δυνητικές","ὥστε","δεικτικό οὕτως/τοιοῦτος/τοσοῦτος"],["Αιτιολογικές","ὅς, ὅστις, ὅσος, οἷος","οριστική / δυνητική","ὅτι / ἐπεί","ρήμα ψυχικού πάθους, αιτία"],["Παραχωρητικές","ὅς, ὅστις","οριστ. / δυνητικές","εἰ καί / καίπερ","εναντίωση στο νόημα"],["Παραβολικές","ὡς, ὥσπερ, οἷος, ὅσος, ὅσῳ","οριστική / δυνητικές","όπως / σαν","συσχετισμός με δεικτικό"]]},"examples":[{"gr":"Πρέσβεις εἵλοντο, οἵτινες ταῦτα ἀπαγγελοῦσιν.","an":"Εξέλεξαν πρέσβεις, για να αναγγείλουν αυτά. — Αναφορική <b>τελική</b>: «οἵτινες ... ἀπαγγελοῦσιν» οριστ. μέλλοντα μετά από ρήμα εκλογής· = ἵνα ἀπαγγέλλωσιν."},{"gr":"Τίς οὕτως ἐστί μαινόμενος, ὅστις οὐ βούλεται σοί φίλος εἶναι;","an":"Ποιος είναι τόσο τρελός, ώστε να μη θέλει να είναι φίλος σου; (τύπου αποτελεσματικής) — Αναφορική <b>αποτελεσματική</b>: το «οὕτως» στην κύρια προεξαγγέλλει· «ὅστις οὐ βούλεται» = ὥστε μή βούλεσθαι."},{"gr":"Τήν μητέρα ἐμακάριζον, οἵων τέκνων ἔτυχεν.","an":"Μακάριζαν τη μητέρα, γιατί απέκτησε τέτοια παιδιά. — Αναφορική <b>αιτιολογική</b> μετά από ρήμα ψυχικού πάθους· «οἵων τέκνων ἔτυχεν» = ὅτι τοιούτων τέκνων ἔτυχεν."},{"gr":"Ἐμέ ἠγάπα, ὥσπερ καί ὑμεῖς τούς ὑμετέρους παῖδας ἀγαπᾶτε.","an":"Με αγαπούσε, όπως κι εσείς αγαπάτε τα δικά σας παιδιά. — Αναφορική <b>παραβολική</b> τρόπου· πραγματική σύγκριση με οριστική."},{"gr":"Ἔπεμψεν ἀγγέλους, οἵ ἐροῦσι τῷ βασιλεῖ τά γεγενημένα.","an":"Έστειλε αγγελιοφόρους, οι οποίοι θα πουν στον βασιλιά τα γεγονότα. — Αναφορική <b>τελική</b>: «οἵ ἐροῦσι» οριστ. μέλλοντα μετά από ρήμα αποστολής· = ἵνα εἴπωσιν."},{"gr":"Θαυμάζω τόν ἄνδρα, ὅς τοσαῦτα τετόλμηκεν.","an":"Θαυμάζω τον άνδρα, που τόσα έχει τολμήσει. — Αναφορική <b>αιτιολογική</b> μετά από ρήμα ψυχικού πάθους («θαυμάζω»)· = ὅτι τοσαῦτα τετόλμηκεν."}],"note":"Μην μπερδεύεις: το «ὥστε» εισάγει συμπερασματική, αλλά μια αναφορική γίνεται αποτελεσματική μόνο όταν στηρίζεται σε δεικτικό (οὕτως/τοιοῦτος/τοσοῦτος) της κύριας. Η αιτιολογική αναφορική σχεδόν πάντα συνοδεύει ρήμα συγκίνησης/αξιολόγησης."},{"h":"Η έλξη του αναφορικού (attractio relativi)","body":"<p>Με τον όρο <b>έλξη του αναφορικού</b> εννοούμε το φαινόμενο κατά το οποίο η αναφορική αντωνυμία <b>δεν μπαίνει στην πτώση που της ανήκει</b> κατά τη συντακτική της θέση μέσα στην αναφορική πρόταση, αλλά <b>«έλκεται» (παρασύρεται) στην πτώση του όρου αναφοράς</b>. Είναι γνήσιο, πολύ συχνό αττικό φαινόμενο και θεωρείται δείγμα καλλιεπούς λόγου.</p><h3>Οι προϋποθέσεις (πότε γίνεται)</h3><p>Για να συμβεί κανονική (ευθεία) έλξη πρέπει να συντρέχουν <b>όλες</b> οι παρακάτω συνθήκες:</p><ul><li>Η αναφορική αντωνυμία βρίσκεται κανονικά σε <b>αιτιατική</b> (ως αντικείμενο του ρήματος της αναφορικής)· σπανιότερα σε ονομαστική.</li><li>Ο όρος αναφοράς βρίσκεται σε <b>γενική ή δοτική</b>.</li><li>Ο όρος αναφοράς είναι κατά κανόνα <b>ουσιαστικό με άρθρο ή αντωνυμία</b> και προηγείται.</li></ul><p><b>Αποτέλεσμα:</b> η αιτιατική του αναφορικού μετατρέπεται στη γενική ή δοτική του όρου αναφοράς.</p><h3>Σχηματικά</h3><p><i>Χωρίς έλξη:</i> «ἄξιος τῆς τιμῆς <b>ἥν</b> ἔχει» (ἥν = αιτιατική, αντικείμενο του ἔχει).<br><i>Με έλξη:</i> «ἄξιος τῆς τιμῆς <b>ἧς</b> ἔχει» (ἧς = γενική, παρασυρμένη από το «τῆς τιμῆς»).</p><h3>Συχνότερες περιπτώσεις στα κείμενα</h3><p>Πάρα πολύ συνηθισμένη με ρήματα μνήμης, αντίληψης, στέρησης, μετοχής (μέμνημαι, ἀκούω, ἀποστεροῦμαι, μετέχω) και γενικά όπου ο όρος αναφοράς είναι γενική ή δοτική.</p><h3>Πότε ΔΕΝ γίνεται έλξη</h3><ul><li>Όταν θα προέκυπτε ασάφεια ή σύγχυση γένους/αριθμού.</li><li>Όταν το αναφορικό είναι <b>ὅστις</b> (η έλξη προτιμά το ὅς).</li><li>Όταν η αναφορική είναι παραθετική (προσθετική) ή έχει έμφαση στη δική της σύνταξη.</li><li>Όταν ο όρος αναφοράς είναι σε αιτιατική (τότε δεν συντρέχει η προϋπόθεση).</li></ul>","examples":[{"gr":"Ἐμέμνητο τῶν συμφορῶν ὧν ἔπαθεν.","an":"Θυμόταν τις συμφορές που έπαθε. — Κανονικά: «τῶν συμφορῶν <b>ἅς</b> ἔπαθεν» (ἅς = αιτ., αντικ. του ἔπαθεν). Με έλξη: «<b>ὧν</b>» (γενική), παρασυρμένη από το «τῶν συμφορῶν»."},{"gr":"Ἀπεστερήθην ὧν ὁ πατήρ μοι κατέλιπεν χρημάτων.","an":"Στερήθηκα τα χρήματα που μου άφησε ο πατέρας. — Κανονικά «τά χρήματα <b>ἅ</b> κατέλιπεν»· εδώ το αναφορικό έλκεται σε γενική «ὧν» από το «χρημάτων» (γενική στέρησης)."},{"gr":"Ἐπορεύετο σύν ᾗ εἶχε δυνάμει.","an":"Προχωρούσε με τη δύναμη που είχε. — Κανονικά «σύν τῇ δυνάμει <b>ἥν</b> εἶχε» (ἥν = αιτ.)· με έλξη «<b>ᾗ</b>» (δοτική), παρασυρμένη από το «δυνάμει»."},{"gr":"Ἤκουσα τῶν λόγων ὧν εἶπες.","an":"Άκουσα τα λόγια που είπες. — Κανονικά «τούς λόγους <b>οὕς</b> εἶπες»· με έλξη «τῶν λόγων <b>ὧν</b>» (γενική και από το ρήμα ἀκούω + γεν. και από έλξη)."},{"gr":"Ὁ ἐμός πάππος κάλλιστος ἦν Μήδων ὅσων ἑώρακα.","an":"Ο παππούς μου ήταν ο ωραιότερος από όσους Μήδους έχω δει (πρβλ. Ξεν., Κύρου Παιδεία 1.3.2). — Κανονικά «Μήδων <b>ὅσους</b> ἑώρακα» (ὅσους = αιτ.)· με έλξη «<b>ὅσων</b>» (γενική) από το «Μήδων»."},{"gr":"Ἄξιοί εἰσι τῆς ἐλευθερίας ἧς κέκτηνται.","an":"Είναι άξιοι της ελευθερίας που κατέχουν. — Κανονικά «τῆς ἐλευθερίας <b>ἥν</b> κέκτηνται» (ἥν = αιτ., αντικ.)· με έλξη «<b>ἧς</b>» (γενική) από το «τῆς ἐλευθερίας»."}],"note":"Κλασική παγίδα: στο «ὧν ἔπαθεν» το «ὧν» μοιάζει γενική αντικείμενο, αλλά συντακτικά είναι αιτιατική-αντικείμενο που έλκεται. Στην ΑΝΑΛΥΣΗ πρέπει να αποκαθιστούμε την κανονική πτώση: ὧν → ἅς."},{"h":"Η αντίστροφη έλξη (ανθέλξη) και σύνοψη της εκφοράς","body":"<h3>Αντίστροφη έλξη (ανθέλξη)</h3><p>Στην <b>αντίστροφη έλξη</b> συμβαίνει το αντίθετο της κανονικής: εδώ <b>ο όρος αναφοράς</b> είναι εκείνος που <b>έλκεται και προσαρμόζεται στην πτώση της αναφορικής αντωνυμίας</b> (αντί η αντωνυμία να ακολουθεί τον όρο). Συχνά ο όρος αναφοράς <b>μετατίθεται</b> και τοποθετείται <i>μέσα</i> στην αναφορική πρόταση ή αμέσως μετά την αντωνυμία.</p><p>Προϋπόθεση: η αναφορική αντωνυμία έχει τη δική της (συνήθως αιτιατική) σύνταξη, και ο όρος αναφοράς —που κανονικά θα ήταν σε άλλη πτώση— παρασύρεται στην πτώση της.</p><p><i>Κανονικά:</i> «μεγάλη ἦν <b>ἡ κώμη</b> εἰς <b>ἥν</b> ἀφίκοντο» (ἡ κώμη = ονομαστική, υποκ.· ἥν = αιτ. με την «εἰς»).<br><i>Με ανθέλξη:</i> «μεγάλη ἦν, εἰς <b>ἥν</b> ἀφίκοντο <b>κώμην</b>» — το «κώμην» έλκεται σε αιτιατική (από το «ἥν») και μπαίνει μέσα στην αναφορική.</p><h3>Σύνοψη εκφοράς (έγκλιση) των αναφορικών</h3><p>Οι αναφορικές εκφέρονται με όλες τις εγκλίσεις, ανάλογα με τη σημασία:</p><ul><li><b>Προτάσεις κρίσης</b> (πραγματικό· άρνηση <b>οὐ</b>): <i>οριστική</i> (το πραγματικό), <i>δυνητική οριστική</i> (το δυνατό/μη πραγματικό στο παρελθόν), <i>δυνητική ευκτική</i> (το δυνατό στο παρόν/μέλλον).</li><li><b>Προτάσεις επιθυμίας/προσδοκίας</b> (άρνηση <b>μή</b>): <i>υποτακτική</i> (ὅς ἄν / ὅστις ἄν — προσδοκώμενο, αόριστη επανάληψη), <i>ευχετική ευκτική</i>, <i>ευκτική του πλαγίου λόγου</i> (σε εξάρτηση από ιστορικό χρόνο), <i>ευκτική επαναληπτική</i> (αόριστη επανάληψη στο παρελθόν).</li></ul><p>Η επιλογή της έγκλισης δεν είναι αυθαίρετη: συμβαδίζει με το αν η αναφορική είναι απλώς προσδιοριστική (συνήθως οριστική) ή με επιρρηματική/υποθετική χροιά (τότε ακολουθεί τους κανόνες των αντίστοιχων επιρρηματικών προτάσεων).</p>","table":{"title":"Εκφορά αναφορικών ανά σημασία","cols":["Σημασία","Άρνηση","Εγκλίσεις","Παράδειγμα τύπου"],"rows":[["Πραγματικό / απλή διασάφηση","οὐ","οριστική","ὅς ταῦτα ἔπραξεν"],["Δυνατό (παρόν/μέλλον)","οὐ","δυνητική ευκτική (ἄν)","ὅς ταῦτα πράξειεν ἄν"],["Δυνατό/μη πραγματικό (παρελθόν)","οὐ","δυνητική οριστική (ἄν)","ὅς ταῦτα ἔπραξεν ἄν"],["Προσδοκώμενο / αόρ. επανάληψη (παρόν-μέλλ.)","μή","ὅς ἄν / ὅστις ἄν + υποτακτική","ὅς ἄν ταῦτα πράττῃ"],["Αόριστη επανάληψη (παρελθόν)","μή","ευκτική επαναληπτική","ὅς ταῦτα πράττοι"],["Πλάγιος λόγος (εξάρτ. ιστ. χρόνου)","—","ευκτική πλαγίου λόγου","ἔλεγεν ἅ ἀκούσειε"]]},"examples":[{"gr":"Μεγάλη τε ἦν, εἰς ἥν ἀφίκοντο κώμην.","an":"Ήταν μεγάλο, το χωριό στο οποίο έφτασαν. — <b>Αντίστροφη έλξη</b>: ο όρος αναφοράς «κώμην» έλκεται σε αιτιατική από το «ἥν» (αντί ονομαστική «ἡ κώμη») και τίθεται μέσα στην αναφορική."},{"gr":"Ἐλαφηβολίας ἄγουσιν, ἅς θυσίας θύουσιν.","an":"Τελούν τα Ελαφηβόλια, τις θυσίες που προσφέρουν. — Ανθέλξη: το «θυσίας» έλκεται σε αιτιατική από το «ἅς»."},{"gr":"Λύσανδρος ἔλεγεν οὐκ εἶναι κύριος ὧν ἐρωτῷτο ὑπό τοῦ Θηραμένους.","an":"Ο Λύσανδρος έλεγε ότι δεν είναι αρμόδιος για όσα ρωτιόταν από τον Θηραμένη. — Ευθεία έλξη («ὧν» αντί «ἅ») μαζί με ευκτική του πλαγίου λόγου «ἐρωτῷτο» (εξάρτηση από ιστορικό χρόνο)."},{"gr":"Ἔλεγον ὅτι Λακεδαιμόνιοι ὧν δέονται πάντων πεπραγότες εἶεν.","an":"Έλεγαν ότι οι Λακεδαιμόνιοι είχαν επιτύχει όλα όσα ήθελαν. — <b>Αντίστροφη έλξη</b>: το «πάντων» (κανονικά «πάντα», αιτ. αντικ.) έλκεται σε γενική από το «ὧν»· συνάμα ευκτική πλαγίου λόγου «εἶεν»."},{"gr":"Ἀκούσας ἅ ἀκούσειεν ἐθαύμασεν.","an":"Όταν άκουσε όσα είχε ακούσει, θαύμασε. — Αναφορική με <b>ευκτική του πλαγίου λόγου</b> «ἀκούσειεν» σε εξάρτηση από ιστορικό χρόνο· εκφορά πλαγίου λόγου."}],"note":"Διάκριση: στην ΕΥΘΕΙΑ έλξη αλλάζει πτώση το ΑΝΑΦΟΡΙΚΟ (παρασύρεται από τον όρο). Στην ΑΝΤΙΣΤΡΟΦΗ έλξη αλλάζει πτώση ο ΟΡΟΣ ΑΝΑΦΟΡΑΣ (παρασύρεται από το αναφορικό) και συχνά μετακινείται μέσα στην πρόταση."}]);
  T("syn-aitiologikes", [{"h":"Ορισμός, φύση και συντακτικός ρόλος","body":"<p>Οι <b>αιτιολογικές προτάσεις</b> είναι <b>δευτερεύουσες επιρρηματικές προτάσεις</b> που δηλώνουν την <b>αιτία</b>, δηλαδή τον λόγο για τον οποίο συμβαίνει το περιεχόμενο μιας άλλης πρότασης (συνήθως της κύριας). Φανερώνουν <i>γιατί</i> γίνεται κάτι, αποτελώντας τη γλωσσική έκφραση της σχέσης <b>αιτίου</b> και <b>αιτιατού (αποτελέσματος)</b>: η αιτιολογική πρόταση περιέχει το αίτιο, η εξαρτώσα πρόταση το αποτέλεσμα.</p><p>Στον λόγο η αιτιολογική πρόταση είναι ισοδύναμη με τους <b>επιρρηματικούς προσδιορισμούς της αιτίας</b> που εκφέρονται με άλλους τρόπους: με <b>εμπρόθετο</b> (διά τοῦτο, ἕνεκα, ἐκ, ἀπό + γενική), με <b>αιτιολογική μετοχή</b> (π.χ. <i>ἅτε / οἷα / ὡς + μετοχή</i>), με <b>δοτική της αιτίας</b> ή με <b>γενική της αιτίας</b>. Έτσι η περίοδος «<i>ἐχάρη διά τήν νίκην</i>» μετασχηματίζεται σε «<i>ἐχάρη ὅτι ἐνίκησεν</i>».</p><h3>Συντακτική θέση της αιτιολογικής πρότασης</h3><p>Ανάλογα με το ρήμα ή την έκφραση από την οποία εξαρτάται, η αιτιολογική πρόταση λειτουργεί ως:</p><ul><li><b>Επιρρηματικός προσδιορισμός της αιτίας</b> στο ρήμα της προσδιοριζόμενης πρότασης (η συνηθέστερη και βασική χρήση). Π.χ. <i>χαίρω ὅτι ἥκεις</i>.</li><li><b>Επεξήγηση</b> σε προηγηθέντα εμπρόθετο ή επιρρηματικό προσδιορισμό της αιτίας (π.χ. σε <i>διά τοῦτο</i>, <i>διά ταῦτα</i>). Η αιτιολογική αναπτύσσει τι ακριβώς είναι αυτό το «τοῦτο».</li><li><b>Υποκείμενο</b> σε απρόσωπα ρήματα και απρόσωπες εκφράσεις που σημαίνουν ψυχικό πάθος ή αξιολόγηση (π.χ. <i>δεινόν ἐστι, θαυμαστόν ἐστι, αἰσχρόν ἐστι</i>) — κυρίως όταν η αιτιολογική εισάγεται με το <i>εἰ</i>.</li></ul><p>Η αιτιολογική πρόταση δηλώνει σχεδόν πάντοτε αιτία· σπανιότερα μπορεί να εκφράζει και <b>αφορμή</b>. Συχνά εξαρτάται από ρήματα και εκφράσεις <b>ψυχικού πάθους</b> (χαίρω, ἥδομαι, λυποῦμαι, ἀγανακτῶ, θαυμάζω, αἰσχύνομαι), από ρήματα <b>αξιολόγησης ή ψόγου/επαίνου</b> (αἰτιῶμαι, μέμφομαι, ἐπαινῶ) και από εκφράσεις χάρης (χάριν ἔχω, χάριν οἶδα).</p>","examples":[{"gr":"Χαίρω ὅτι εὐδοκιμεῖς.","an":"Κύρια: <i>χαίρω</i>. Αιτιολογική: <i>ὅτι εὐδοκιμεῖς</i>, ως επιρρηματικός προσδιορισμός της αιτίας στο <i>χαίρω</i> (ρήμα ψυχικού πάθους). Μτφρ.: «Χαίρομαι που / επειδή ευδοκιμείς.»"},{"gr":"Διά τοῦτο ὑμᾶς συνεκάλεσα, ὅτι κίνδυνος ἐγγύς ἐστιν.","an":"Η αιτιολογική <i>ὅτι κίνδυνος ἐγγύς ἐστιν</i> λειτουργεί ως <b>επεξήγηση</b> στον εμπρόθετο της αιτίας <i>διά τοῦτο</i> της κύριας. Μτφρ.: «Γι' αυτόν τον λόγο σας συγκάλεσα, επειδή ο κίνδυνος είναι κοντά.»"},{"gr":"Δεινόν ἐστιν εἰ τοῖς πολεμίοις ἐπιτρέψομεν.","an":"Απρόσωπη έκφραση <i>δεινόν ἐστιν</i>· η αιτιολογική-υποθετική <i>εἰ ... ἐπιτρέψομεν</i> λειτουργεί ως <b>υποκείμενο</b> της απρόσωπης έκφρασης. Μτφρ.: «Είναι φοβερό (το γεγονός) ότι / αν θα το επιτρέψουμε αυτό στους εχθρούς.»"},{"gr":"Χάριν ἔχω σοι ὅτι με ἔσωσας.","an":"Από την έκφραση χάρης <i>χάριν ἔχω</i> εξαρτάται η αιτιολογική <i>ὅτι με ἔσωσας</i> (επιρρ. προσδ. αιτίας, οριστική). Μτφρ.: «Σου χρωστώ ευγνωμοσύνη, επειδή με έσωσες.»"},{"gr":"Σωκράτης ἥδετο ὅτι τήν τέχνην ἐπιδεικνύοι ὁ νεανίσκος.","an":"Από ρήμα ψυχικού πάθους (<i>ἥδετο</i>) εξαρτάται η αιτιολογική <i>ὅτι ... ἐπιδεικνύοι</i>· ευκτική του πλαγίου λόγου μετά από ιστορικό χρόνο (τύπου Ξεν.). Μτφρ.: «Ο Σωκράτης ευχαριστιόταν, επειδή ο νεαρός επιδείκνυε την τέχνη του.»"}]},{"h":"Εισαγωγή: οι αιτιολογικοί σύνδεσμοι","body":"<p>Οι αιτιολογικές προτάσεις εισάγονται με τους εξής συνδέσμους, που όλοι αποδίδονται στη νέα ελληνική με «<i>επειδή, διότι, γιατί, που</i>»:</p><ul><li><b>ὅτι</b> — ο κατεξοχήν αιτιολογικός σύνδεσμος· δηλώνει <b>αντικειμενική / πραγματική</b> αιτιολογία (αιτία που ο ομιλητής παρουσιάζει ως πραγματικό γεγονός).</li><li><b>διότι</b> — ισοδύναμο του <i>ὅτι</i>, εμφατικότερο· επίσης αντικειμενική αιτιολογία.</li><li><b>ἐπεί</b> και <b>ἐπειδή</b> — αρχικά χρονικοί σύνδεσμοι· πολύ συχνά αιτιολογικοί («αφού, μια και, επειδή»). Συνήθως εισάγουν την αιτιολογική πρόταση <b>πριν</b> από την κύρια (προτασσόμενη αιτία).</li><li><b>ὡς</b> — δηλώνει <b>υποκειμενική</b> αιτιολογία· παρουσιάζει την αιτία ως <i>γνώμη / ισχυρισμό</i> του υποκειμένου (όχι του ομιλητή).</li><li><b>εἰ</b> — εισάγει <b>υποθετική (πιθανή / ενδεχόμενη)</b> αιτιολογία, κυρίως ύστερα από ρήματα και εκφράσεις ψυχικού πάθους (θαυμάζω, ἀγανακτῶ, αἰσχύνομαι, δεινόν ἐστι κ.λπ.). Αποδίδεται με «που / επειδή / αφού», όχι με «αν» (αν και διατηρεί υποθετική απόχρωση).</li></ul><p>Σπανιότερα, αιτιολογική χροιά μπορούν να προσλάβουν και οι χρονικοί σύνδεσμοι <b>ὅτε, ὁπότε</b> (= «αφού, τη στιγμή που → επειδή»), όταν τα συμφραζόμενα φωτίζουν αιτιολογική σχέση. Ενίοτε αιτιολογική σημασία έχει και το <b>ὅπου</b> (= «αφού, εφόσον»).</p><h3>Η σημασία της επιλογής του συνδέσμου</h3><p>Η επιλογή του συνδέσμου δεν είναι ουδέτερη: αποκαλύπτει τη <b>στάση του ομιλητή απέναντι στην αιτία</b>. Το <i>ὅτι/διότι</i> «υπογράφει» την αιτία ο ίδιος ο ομιλητής ως αληθινή· το <i>ὡς</i> την αποδίδει στο υποκείμενο, αποστασιοποιούμενος· το <i>εἰ</i> την παρουσιάζει ως ενδεχόμενο που προκαλεί συγκίνηση ή αντίδραση.</p>","table":{"title":"Σύνδεσμοι εισαγωγής και είδος αιτιολογίας","cols":["Σύνδεσμος","Σημασία","Είδος αιτιολογίας","Νεοελληνική απόδοση"],"rows":[["ὅτι","ο κύριος αιτιολογικός","αντικειμενική / πραγματική","επειδή, διότι, που"],["διότι","εμφατικό ισοδύναμο του ὅτι","αντικειμενική / πραγματική","διότι, επειδή"],["ἐπεί / ἐπειδή","χρονικοαιτιολογικοί","πραγματική (συχνά προτασσόμενη)","αφού, μια και, επειδή"],["ὡς","κατά τη γνώμη του υποκειμένου","υποκειμενική","επειδή τάχα, με τη σκέψη ότι"],["εἰ","ύστερα από ρ. ψυχικού πάθους","υποθετική / ενδεχόμενη","που, επειδή, αν"],["ὅτε / ὁπότε","χρονικοί με αιτιολογική χροιά","πραγματική (σπάνια)","αφού, μια και"]]},"examples":[{"gr":"Ξενοφῶντα ᾐτιῶντο ὅτι ἐδίωκεν.","an":"Από το ρήμα ψόγου <i>ᾐτιῶντο</i> εξαρτάται η αιτιολογική <i>ὅτι ἐδίωκεν</i> (αντικειμενική αιτιολογία, οριστική). Μτφρ.: «Κατηγορούσαν τον Ξενοφώντα, επειδή (τους) καταδίωκε.»"},{"gr":"Ἐπεί νύξ ἐγένετο, ἀνεχώρησαν.","an":"Εδώ το <i>ἐπεί</i> είναι <b>χρονικό</b> (= όταν / αφού έγινε νύχτα). Πρόκειται για χρονική, όχι αιτιολογική πρόταση — βλ. τη διάκριση παρακάτω. Μτφρ.: «Όταν έπεσε η νύχτα, αποχώρησαν.»"},{"gr":"Ἐπεί ταῦτα οὕτως ἔχει, πορευτέον ἐστίν.","an":"Εδώ το <i>ἐπεί</i> είναι <b>αιτιολογικό</b> (= αφού / επειδή έτσι έχουν τα πράγματα). Δηλώνει τον λόγο, όχι τον χρόνο. Μτφρ.: «Αφού έτσι έχουν τα πράγματα, πρέπει να βαδίσουμε.»"},{"gr":"Τούς Ἀθηναίους ἐμέμφοντο ὡς οὐ βοηθοῖεν.","an":"Από το <i>ἐμέμφοντο</i> εξαρτάται η αιτιολογική με <i>ὡς</i> + <b>ευκτική του πλαγίου λόγου</b> (<i>βοηθοῖεν</i>): υποκειμενική αιτιολογία — η αιτία αποδίδεται στη γνώμη όσων μέμφονται. Μτφρ.: «Κατηγορούσαν τους Αθηναίους, επειδή τάχα δεν βοηθούσαν.»"},{"gr":"Ἐπεί δέ ὑμεῖς οὐ βούλεσθε συμπορεύεσθαι, ἀνάγκη δή μοι ... τῇ Κύρου φιλίᾳ χρῆσθαι.","an":"Ξεν. Ἀνάβ. 1.3.5 — προτασσόμενη <b>αιτιολογική</b> με <i>ἐπεί</i> + οριστική (<i>βούλεσθε</i>)· δίνει τον λόγο για το συμπέρασμα της κύριας. Μτφρ.: «Επειδή εσείς δεν θέλετε να συνεχίσετε την πορεία, είμαι αναγκασμένος να διατηρήσω τη φιλία του Κύρου.»"},{"gr":"Ἐτύγχανε γάρ ἐφ' ἁμάξης πορευόμενος, διότι ἐτέτρωτο.","an":"Ξεν. Ἀνάβ. 2.4.14 — αιτιολογική με <i>διότι</i> + οριστική (<i>ἐτέτρωτο</i>, υπερσ.): εμφατική, αντικειμενική αιτία (αναφέρεται στον Ἀριαῖο). Μτφρ.: «Έτυχε να πορεύεται πάνω σε άμαξα, διότι (= επειδή) είχε τραυματιστεί.»"}]},{"h":"Είδη αιτιολογίας: πραγματική — υποκειμενική — υποθετική","body":"<p>Ανάλογα με το <b>ποιος εγγυάται</b> την αιτία και <b>πόσο βέβαιη</b> είναι, διακρίνουμε τρία είδη αιτιολογίας. Η διάκριση φαίνεται τόσο από τον σύνδεσμο όσο και από την έγκλιση εκφοράς.</p><h3>1. Αντικειμενική / πραγματική αιτιολογία</h3><p>Ο <b>ομιλητής</b> παρουσιάζει την αιτία ως <b>πραγματικό, αντικειμενικά αποδεκτό γεγονός</b>, για το οποίο αναλαμβάνει ο ίδιος την ευθύνη. Εισάγεται με <b>ὅτι, διότι</b> (και με <i>ἐπεί, ἐπειδή</i>) και εκφέρεται κανονικά με <b>οριστική</b>. Είναι το συνηθέστερο είδος.</p><h3>2. Υποκειμενική αιτιολογία</h3><p>Η αιτία δεν παρουσιάζεται από τον ομιλητή ως αντικειμενική αλήθεια, αλλά αποδίδεται στην <b>υποκειμενική γνώμη / σκέψη / ισχυρισμό του υποκειμένου</b> της εξαρτώσας πρότασης ή τρίτου προσώπου. Ο ομιλητής μένει ουδέτερος ή και επιφυλακτικός. Εισάγεται κατεξοχήν με <b>ὡς</b> (νεοελλ. «με τη σκέψη ότι, επειδή τάχα»). Εκφέρεται με <b>οριστική</b> ή πολύ συχνά, ύστερα από ιστορικό χρόνο, με <b>ευκτική του πλαγίου λόγου</b>, που τονίζει ακριβώς ότι η αιτία ανήκει στη σκέψη άλλου, όχι στον ομιλητή.</p><h3>3. Υποθετική αιτιολογία</h3><p>Η αιτία παρουσιάζεται ως <b>ενδεχόμενη / πιθανή / υποτιθέμενη</b>, ως ένα γεγονός που, αν ισχύει, προκαλεί κάποιο ψυχικό πάθος ή αξιολογική αντίδραση. Εισάγεται με <b>εἰ</b> και απαντά κανονικά <b>ύστερα από ρήματα ή εκφράσεις ψυχικού πάθους</b>: <i>θαυμάζω, ἀγανακτῶ, αἰσχύνομαι, αἰσχρόν ἐστι, δεινόν ἐστι, θαυμαστόν ἐστι, αἰσχύνη ἐστί</i>. Διατηρεί τυπικά τη μορφή υποθετικής πρότασης (εἰ + οριστική, σπανιότερα ευκτική), αλλά νοηματικά είναι αιτιολογική και αποδίδεται με «που / επειδή».</p>","table":{"title":"Τα τρία είδη αιτιολογίας συγκριτικά","cols":["Είδος","Σύνδεσμος","Ποιος εγγυάται την αιτία","Τυπική έγκλιση"],"rows":[["Αντικειμενική / πραγματική","ὅτι, διότι, ἐπεί, ἐπειδή","ο ίδιος ο ομιλητής (πραγματικό γεγονός)","οριστική"],["Υποκειμενική","ὡς","το υποκείμενο / τρίτος (γνώμη, ισχυρισμός)","οριστική ή ευκτική πλαγίου λόγου"],["Υποθετική","εἰ","παρουσιάζεται ως ενδεχόμενο","εἰ + οριστική (σπάν. ευκτική)"]]},"examples":[{"gr":"Ἄνδρες, μή θαυμάζετε ὅτι πολλάκις ὑμᾶς συγκαλῶ.","an":"<b>Αντικειμενική αιτιολογία</b>: <i>ὅτι ... συγκαλῶ</i> με οριστική· ο ομιλητής δίνει ως πραγματική αιτία ότι τους συγκαλεί συχνά. Μτφρ.: «Άνδρες, μην απορείτε που σας συγκαλώ συχνά.»"},{"gr":"Οὐκ ἐβούλοντο ἀπιέναι, ὡς αὐτοί μέν ἦσαν ἀήττητοι.","an":"<b>Υποκειμενική αιτιολογία</b> με <i>ὡς</i>: η αιτία (ότι θεωρούσαν εαυτούς αήττητους) ανήκει στη σκέψη των ίδιων, όχι του αφηγητή. Μτφρ.: «Δεν ήθελαν να αποχωρήσουν, με τη σκέψη ότι αυτοί ήταν αήττητοι.»"},{"gr":"Θαυμάζω δ' ἔγωγε εἰ μηδείς ὑμῶν ἐνθυμεῖται.","an":"<b>Υποθετική αιτιολογία</b> από ρήμα ψυχικού πάθους (<i>θαυμάζω</i>) με <i>εἰ</i> + οριστική. Μτφρ.: «Απορώ που (= επειδή) κανείς σας δεν το σκέφτεται.»"},{"gr":"Αἰσχρόν ἐστιν εἰ μή τοῖς φίλοις βοηθήσομεν.","an":"<b>Υποθετική αιτιολογία</b>-υποκείμενο στην απρόσωπη έκφραση <i>αἰσχρόν ἐστιν</i>. Μτφρ.: «Είναι ντροπή που / αν δεν θα βοηθήσουμε τους φίλους.»"},{"gr":"Θαυμάζω δ' ἔγωγε εἰ μηδείς ὑμῶν μήτ' ἐνθυμεῖται μήτ' ὀργίζεται.","an":"Ρητορικός τύπος (πρβλ. Δημοσθ.) — <b>υποθετική αιτιολογία</b> με <i>εἰ</i> + οριστική ύστερα από <i>θαυμάζω</i>· άρνηση <i>μή</i> κατά τη φύση του <i>εἰ</i>. Μτφρ.: «Απορώ που κανείς σας ούτε το σκέφτεται ούτε αγανακτεί.»"},{"gr":"Ἠγανάκτουν ὡς δεινά πεπονθότες εἶεν.","an":"<b>Υποκειμενική αιτιολογία</b> με <i>ὡς</i> + ευκτική πλαγίου λόγου (περιφρ. <i>πεπονθότες εἶεν</i>): η αιτία αποδίδεται στη γνώμη των αγανακτούντων. Μτφρ.: «Αγανακτούσαν, με τη σκέψη ότι είχαν πάθει φοβερά πράγματα.»"}]},{"h":"Εκφορά (έγκλιση) και χρόνος","body":"<p>Η έγκλιση εκφοράς δηλώνει τον τρόπο με τον οποίο ο ομιλητής αντιλαμβάνεται την αιτία (πραγματική, δυνατή, μη πραγματική, αποδιδόμενη σε άλλον). Οι αιτιολογικές προτάσεις εκφέρονται με:</p><ul><li><b>Οριστική</b> — όταν η αιτία είναι <b>πραγματική</b> και αντικειμενικά αποδεκτή. Είναι η κανονική, συνηθέστερη εκφορά. Π.χ. <i>χαίρω ὅτι ἥκεις</i>.</li><li><b>Δυνητική οριστική</b> (οριστική ιστορικού χρόνου + <i>ἄν</i>) — όταν η αιτία παρουσιάζεται ως <b>δυνατή στο παρελθόν</b> ή ως <b>μη πραγματική / αντίθετη προς την πραγματικότητα</b>. Π.χ. <i>ἀγανακτῶ ὅτι οὐκ ἄν ἐποίησας τοῦτο</i>.</li><li><b>Δυνητική ευκτική</b> (ευκτική + <i>ἄν</i>) — όταν η αιτία είναι <b>δυνατή / πιθανή στο παρόν ή στο μέλλον</b> (κάτι που θα μπορούσε να ισχύει).</li><li><b>Ευκτική του πλαγίου λόγου</b> — όταν το ρήμα εξάρτησης βρίσκεται σε <b>ιστορικό χρόνο</b> και η αιτία ανάγεται στο παρελθόν ή αποδίδεται στη σκέψη άλλου προσώπου (υποκειμενική αιτιολογία, κυρίως με <i>ὡς</i>). Δηλώνει ότι ο ομιλητής δεν εγγυάται την αλήθεια της αιτίας. Π.χ. <i>ᾐτιῶντο αὐτόν ὅτι προδοίη τήν πόλιν</i>.</li></ul><h3>Πώς συνδέεται ο χρόνος εξάρτησης με την έγκλιση</h3><p>Όταν το ρήμα της εξαρτώσας πρότασης είναι <b>αρκτικού χρόνου</b> (ενεστώτας, μέλλοντας, παρακείμενος), η αιτιολογική κρατά την αρχική της έγκλιση (οριστική / δυνητική). Όταν είναι <b>ιστορικού χρόνου</b> (παρατατικός, αόριστος, υπερσυντέλικος), τότε η οριστική μπορεί να μετατραπεί σε <b>ευκτική του πλαγίου λόγου</b>, ιδίως όταν η αιτία είναι υποκειμενική — δηλώνεται έτσι η αποστασιοποίηση του ομιλητή.</p>","note":"Προσοχή: η ευκτική του πλαγίου λόγου στην αιτιολογική πρόταση ΔΕΝ είναι υποχρεωτική μετά από ιστορικό χρόνο. Όταν ο ομιλητής θέλει να παραστήσει την αιτία ως αδιαμφισβήτητα πραγματική (αντικειμενική), διατηρεί την οριστική ακόμη και μετά από ιστορικό χρόνο. Έτσι η εναλλαγή οριστικής / ευκτικής πλαγίου λόγου είναι ακριβώς το εργαλείο διάκρισης αντικειμενικής από υποκειμενική αιτιολογία.","examples":[{"gr":"Χαίρω ὅτι ἀφίκου σῶος.","an":"Οριστική (<i>ἀφίκου</i>, αόρ.) → <b>πραγματική</b> αιτία. Μτφρ.: «Χαίρομαι που έφτασες σώος.»"},{"gr":"Ἠγανάκτουν ὅτι οὐκ ἄν ἐδυνήθησαν ἀμύνασθαι.","an":"<b>Δυνητική οριστική</b> (<i>οὐκ ἄν ἐδυνήθησαν</i>) → αιτία μη πραγματική / δυνατή στο παρελθόν. Μτφρ.: «Αγανακτούσαν, επειδή δεν θα μπορούσαν να αμυνθούν.»"},{"gr":"Μακάριος εἶ ὅτι οὐκ ἄν φοβοῖο τόν θάνατον.","an":"<b>Δυνητική ευκτική</b> (<i>οὐκ ἄν φοβοῖο</i>) → αιτία δυνατή στο παρόν/μέλλον. Μτφρ.: «Είσαι ευτυχισμένος, γιατί δεν θα φοβόσουν τον θάνατο.»"},{"gr":"Σωκράτην ᾐτιῶντο ὅτι τούς νέους διαφθείροι.","an":"Ρήμα εξάρτησης ιστορικού χρόνου (<i>ᾐτιῶντο</i>) → <b>ευκτική του πλαγίου λόγου</b> (<i>διαφθείροι</i>): η αιτία αποδίδεται στη γνώμη των κατηγόρων, ο αφηγητής δεν την εγγυάται. Μτφρ.: «Κατηγορούσαν τον Σωκράτη, επειδή (τάχα) διέφθειρε τους νέους.»"},{"gr":"Οἱ Ἕλληνες ἐφοβοῦντο τόν Κῦρον, ὅτι ἤγαγεν αὐτούς ἐπί βασιλέα.","an":"Ρήμα ψυχικού πάθους ιστορικού χρόνου (<i>ἐφοβοῦντο</i>) με αιτιολογική σε <b>οριστική</b> (<i>ἤγαγεν</i>): ο αφηγητής εγγυάται την αιτία ως πραγματική (τύπου Ξεν. Ἀνάβ.). Μτφρ.: «Οι Έλληνες φοβούνταν τον Κύρο, επειδή τους οδήγησε εναντίον του βασιλιά.»"},{"gr":"Ἐπῄνεσαν τόν Κλέαρχον ὅτι μόνος ἐφρόντιζε τῶν στρατιωτῶν.","an":"Ρήμα επαίνου (<i>ἐπῄνεσαν</i>) με αιτιολογική σε <b>οριστική</b> (<i>ἐφρόντιζε</i>): αντικειμενική, πραγματική αιτία διατηρημένη μετά από ιστορικό χρόνο. Μτφρ.: «Επαίνεσαν τον Κλέαρχο, επειδή μόνος αυτός φρόντιζε τους στρατιώτες.»"}]},{"h":"Άρνηση και θέση στον λόγο","body":"<p><b>Άρνηση.</b> Οι αιτιολογικές προτάσεις, ως προτάσεις κρίσης που αναφέρονται σε πραγματικό ή θεωρούμενο ως πραγματικό γεγονός, παίρνουν την άρνηση <b>οὐ (οὐκ, οὐχ)</b>. Π.χ. <i>ἀγανακτῶ ὅτι οὐκ ἦλθες</i> = «αγανακτώ που δεν ήρθες».</p><p><b>Εξαίρεση — το αιτιολογικό «εἰ».</b> Όταν η αιτιολογική εισάγεται με <b>εἰ</b> (υποθετική αιτιολογία), η άρνηση είναι κανονικά <b>μή</b>, σύμφωνα με τη φύση των υποθετικών προτάσεων: <i>θαυμάζω εἰ μή τις ὑμῶν ἀγανακτεῖ</i>. Σε ορισμένες όμως περιπτώσεις, όταν τονίζεται έντονα ο πραγματικός χαρακτήρας της αιτίας, μπορεί να εμφανιστεί και το <i>οὐ</i> μέσα στην <i>εἰ</i>-πρόταση. Αυτή η εναλλαγή <i>μή / οὐ</i> είναι ένα ακόμη σημάδι ότι η <i>εἰ</i>-αιτιολογική στέκεται μεταξύ υπόθεσης και αιτίας.</p><h3>Θέση στον λόγο και στίξη</h3><p>Η αιτιολογική πρόταση μπορεί να βρίσκεται:</p><ul><li><b>Μετά</b> την κύρια (η συνηθέστερη θέση), όταν η αιτία προστίθεται ως εξήγηση: <i>χαίρω, ὅτι ἥκεις</i>.</li><li><b>Πριν</b> από την κύρια, ιδίως με <b>ἐπεί / ἐπειδή</b>, όταν η αιτία τίθεται ως δεδομένη βάση του συλλογισμού: <i>ἐπεί ταῦτα οὕτως ἔχει, ...</i>.</li></ul><p>Από την κύρια χωρίζεται κανονικά με κόμμα. Όταν είναι επεξηγηματική σε <i>διά τοῦτο</i>, το κόμμα κάνει σαφή τη σχέση επεξήγησης.</p><h3>Συνοπτικά οι μέθοδοι έκφρασης της αιτίας</h3><p>Η αιτιολογική πρόταση είναι μόνο ένας από τους τρόπους. Ισοδύναμα: <b>αιτιολογική μετοχή</b> (<i>ἅτε / οἷα + μετοχή</i> = αντικειμενική αιτία· <i>ὡς + μετοχή</i> = υποκειμενική), <b>εμπρόθετοι</b> (<i>διά + αιτ., ἕνεκα + γεν., ἐκ / ἀπό + γεν.</i>), <b>δοτική</b> και <b>γενική της αιτίας</b>. Η ικανότητα μετασχηματισμού από τον έναν τρόπο στον άλλον είναι βασική συντακτική δεξιότητα.</p>","examples":[{"gr":"Ἀγανακτῶ ὅτι οὐκ ἐβοήθησάς μοι.","an":"Άρνηση <b>οὐκ</b> (αντικειμενική αιτιολογία με ὅτι). Μτφρ.: «Αγανακτώ που δεν με βοήθησες.»"},{"gr":"Θαυμάζω εἰ μή τις ὑμῶν ἀγανακτεῖ.","an":"Υποθετική αιτιολογία με <i>εἰ</i> → άρνηση <b>μή</b>. Μτφρ.: «Απορώ που κανείς σας δεν αγανακτεί.»"},{"gr":"Ἅτε παῖς ὤν, ἥδετο τῷ δώρῳ.","an":"Ισοδύναμη έκφραση: <b>αιτιολογική μετοχή</b> με <i>ἅτε</i> (αντικειμενική αιτία) αντί αιτιολογικής πρότασης (= <i>ὅτι παῖς ἦν</i>). Μτφρ.: «Επειδή ήταν παιδί, χαιρόταν με το δώρο.»"},{"gr":"Λυποῦμαι ὅτι οὐχ οἷός τ' εἰμί σε ὠφελῆσαι.","an":"Από ρήμα ψυχικού πάθους (<i>λυποῦμαι</i>) αιτιολογική με <i>ὅτι</i>· άρνηση <b>οὐχ</b> (πραγματικό γεγονός). Μτφρ.: «Λυπάμαι που δεν είμαι σε θέση να σε ωφελήσω.»"},{"gr":"Ἐπεί δέ οὐκ ἔπειθεν, ἀπῆλθεν.","an":"<b>Προτασσόμενη</b> αιτιολογική με <i>ἐπεί</i> (πριν από την κύρια), άρνηση <b>οὐκ</b>· η αιτία τίθεται ως δεδομένη βάση. Μτφρ.: «Επειδή δεν τους έπειθε, έφυγε.»"},{"gr":"Ὡς προδιδούς τήν πόλιν, ἀπεκτάνθη.","an":"Ισοδύναμη έκφραση: <b>αιτιολογική μετοχή</b> με <i>ὡς</i> (υποκειμενική αιτία = κατά την κρίση άλλων) αντί αιτιολογικής πρότασης (= <i>ὡς προεδίδου</i>). Μτφρ.: «Επειδή τάχα πρόδιδε την πόλη, θανατώθηκε.»"}]},{"h":"Διακρίσεις-παγίδες: ὅτι ειδικό/αιτιολογικό και ἐπεί χρονικό/αιτιολογικό","body":"<p>Δύο διακρίσεις είναι κρίσιμες και ζητούνται συστηματικά στις εξετάσεις, γιατί ο ίδιος σύνδεσμος εισάγει διαφορετικά είδη προτάσεων.</p><h3>Α. ὅτι ειδικό ή αιτιολογικό;</h3><p>Το <i>ὅτι</i> μπορεί να εισάγει είτε <b>ειδική</b> είτε <b>αιτιολογική</b> πρόταση. Κριτήρια διάκρισης:</p><ul><li><b>Ειδική</b> πρόταση: λειτουργεί ως <b>αντικείμενο</b> (σπανιότερα υποκείμενο ή επεξήγηση) και εξαρτάται από ρήματα <b>λεκτικά, γνωστικά, αισθητικά, δεικτικά</b> (<i>λέγω, φημί, οἶδα, γιγνώσκω, ἀκούω, ὁρῶ, δηλῶ, ἀγγέλλω</i>). Απαντά στο «<i>τι;</i>» (τι λέει, τι ξέρει). Αποδίδεται με «<i>ότι, πως</i>».</li><li><b>Αιτιολογική</b> πρόταση: λειτουργεί ως <b>επιρρηματικός προσδιορισμός της αιτίας</b> και εξαρτάται κυρίως από ρήματα <b>ψυχικού πάθους, ψόγου/επαίνου, αξιολόγησης</b> (<i>χαίρω, λυποῦμαι, θαυμάζω, αἰτιῶμαι, μέμφομαι</i>). Απαντά στο «<i>γιατί;</i>». Αποδίδεται με «<i>επειδή, διότι, που</i>».</li></ul><p>Πρακτικός κανόνας: αν η πρόταση δηλώνει <b>το περιεχόμενο</b> του λέγειν/νοεῖν → ειδική· αν δηλώνει <b>τον λόγο</b> του ψυχικού πάθους ή της κρίσης → αιτιολογική.</p><h3>Β. ἐπεί / ἐπειδή χρονικό ή αιτιολογικό;</h3><p>Τα <i>ἐπεί, ἐπειδή</i> είναι εκ καταγωγής χρονικά, αλλά πολύ συχνά αιτιολογικά. Κριτήρια:</p><ul><li><b>Χρονικό</b> <i>ἐπεί</i>: δηλώνει <b>χρονική σχέση</b> (πότε;). Μπορεί να αντικατασταθεί με «<i>όταν, αφού</i>» (χρονικά) και συχνά συνοδεύεται από χρονικά επιρρήματα (<i>τότε, ἤδη, εὐθύς</i>). Π.χ. <i>ἐπεί ἐτελεύτησε Δαρεῖος, ...</i> = «όταν πέθανε ο Δαρείος».</li><li><b>Αιτιολογικό</b> <i>ἐπεί</i>: δηλώνει <b>τον λόγο</b> (γιατί;). Αντικαθίσταται με «<i>επειδή, αφού, μια και</i>» (αιτιολογικά) και ισοδυναμεί με <i>ἐπειδή / διότι</i>. Π.χ. <i>ἐπεί οὐκ ἤθελον πείθεσθαι, ἐκόλασεν αὐτούς</i> = «επειδή δεν ήθελαν να υπακούσουν».</li></ul><p>Πρακτικός κανόνας: δοκίμασε να αντικαταστήσεις το <i>ἐπεί</i> με «<b>όταν</b>» και με «<b>επειδή</b>». Αν στέκει μόνο το «όταν» → χρονικό· αν δίνει νόημα το «επειδή» (απαντά στο «γιατί έγινε το κύριο;») → αιτιολογικό. Σε αμφίσημες περιπτώσεις τα συμφραζόμενα και η λογική σχέση αιτίου-αποτελέσματος κρίνουν.</p>","table":{"title":"Κριτήρια διάκρισης","cols":["Σύνδεσμος","Είδος","Εξάρτηση / κριτήριο","Συντακτικός ρόλος"],"rows":[["ὅτι","Ειδική","λεκτικά, γνωστικά, αισθητικά ρ. (λέγω, οἶδα, ὁρῶ)· «τι;»","αντικείμενο (ή υποκ./επεξ.)"],["ὅτι","Αιτιολογική","ρ. ψυχ. πάθους / ψόγου (χαίρω, θαυμάζω, αἰτιῶμαι)· «γιατί;»","επιρρ. προσδ. αιτίας"],["ἐπεί / ἐπειδή","Χρονική","δηλώνει χρόνο· = «όταν, αφού»· «πότε;»","επιρρ. προσδ. χρόνου"],["ἐπεί / ἐπειδή","Αιτιολογική","δηλώνει αιτία· = «επειδή»· «γιατί;»","επιρρ. προσδ. αιτίας"]]},"note":"Τραπ: το ίδιο ισχύει και για το «ὡς», που μπορεί να είναι ειδικός, αιτιολογικός, τελικός, συμπερασματικός, χρονικός ή παραβολικός σύνδεσμος — η διάκριση γίνεται πάντοτε από το ρήμα εξάρτησης και το νόημα. Επίσης το αιτιολογικό «εἰ» δεν πρέπει να συγχέεται με το υποθετικό «εἰ» γνήσιας υπόθεσης: στην αιτιολογία το γεγονός θεωρείται υπαρκτό (γι' αυτό μεταφράζεται «που/επειδή»), ενώ στην υπόθεση μένει στο επίπεδο της προϋπόθεσης.","examples":[{"gr":"Λέγει ὅτι οἱ πολέμιοι προσέρχονται.","an":"<b>Ειδική</b> (αντικείμενο του <i>λέγει</i>, λεκτικό ρήμα· «τι λέει;»). Μτφρ.: «Λέει ότι οι εχθροί πλησιάζουν.»"},{"gr":"Χαίρω ὅτι οἱ πολέμιοι ἀπεχώρησαν.","an":"<b>Αιτιολογική</b> (επιρρ. προσδ. αιτίας στο <i>χαίρω</i>, ρ. ψυχ. πάθους· «γιατί χαίρεσαι;»). Μτφρ.: «Χαίρομαι που αποχώρησαν οι εχθροί.»"},{"gr":"Ἐπεί ἀφίκοντο εἰς τό στρατόπεδον, ἐδείπνουν.","an":"<b>Χρονικό ἐπεί</b> (= όταν / αφού έφτασαν· «πότε;»). Μτφρ.: «Όταν έφτασαν στο στρατόπεδο, δειπνούσαν.»"},{"gr":"Ἐπεί οὐκ ἐπείθοντο, ἐπολιόρκει τήν πόλιν.","an":"<b>Αιτιολογικό ἐπεί</b> (= επειδή δεν υπάκουαν· «γιατί πολιορκούσε;»). Μτφρ.: «Επειδή δεν υπάκουαν, πολιορκούσε την πόλη.»"},{"gr":"Οἶδα ὅτι πάντες ἄνθρωποι θνητοί εἰσιν.","an":"<b>Ειδική</b> (αντικείμενο του γνωστικού <i>οἶδα</i>· «τι ξέρω;»). Διακρίνεται από την αιτιολογική επειδή δηλώνει περιεχόμενο γνώσης, όχι λόγο. Μτφρ.: «Ξέρω ότι όλοι οι άνθρωποι είναι θνητοί.»"},{"gr":"Θαυμάζω ὅτι τοῦτο ἐποίησας.","an":"<b>Αιτιολογική</b> (επιρρ. προσδ. αιτίας στο ρ. ψυχ. πάθους <i>θαυμάζω</i>· «γιατί απορείς;»). Πρβλ. το ειδικό <i>θαυμάζω ὅτι ...</i> δεν στέκει — εδώ απαντά στο «γιατί». Μτφρ.: «Απορώ που το έκανες αυτό.»"}]}]);
  T("syn-telikes", [{"h":"Ορισμός και ταυτότητα των τελικών προτάσεων","body":"<p><b>Τελικές</b> ονομάζονται οι δευτερεύουσες (εξαρτημένες) επιρρηματικές προτάσεις που δηλώνουν τον <b>σκοπό</b>, την επιδίωξη ή τον τελικό στόχο για τον οποίο γίνεται η ενέργεια του ρήματος της προσδιοριζόμενης (συνήθως κύριας) πρότασης. Η ονομασία προέρχεται από τη λέξη <i>τέλος</i>, που στην αρχαία ελληνική σημαίνει «σκοπός, στόχος, επιδίωξη». Απαντούν, δηλαδή, στο ερώτημα <i>«για ποιον σκοπό;»</i> ή <i>«με ποιον στόχο;»</i>.</p><p>Επειδή φανερώνουν σκοπό, οι τελικές προτάσεις δηλώνουν πάντοτε κάτι <b>μελλοντικό</b> και <b>προσδοκώμενο</b> σε σχέση με την ενέργεια από την οποία εξαρτώνται· ο σκοπός είναι λογικά μεταγενέστερος της πράξης που αποβλέπει σ' αυτόν. Γι' αυτό και η κύρια έγκλισή τους είναι η <b>υποτακτική</b>, η έγκλιση του προσδοκώμενου και του βουλητικού.</p><p>Ως προς τη <b>συντακτική τους λειτουργία</b>, οι τελικές προτάσεις λειτουργούν στο σύνολό τους ως <b>επιρρηματικός προσδιορισμός του σκοπού</b> στο ρήμα της προσδιοριζόμενης πρότασης. Είναι, επομένως, επιρρηματικές προτάσεις και ισοδυναμούν με εμπρόθετο προσδιορισμό σκοπού (π.χ. <i>ἐπί θήραν</i>) ή με τελική μετοχή (μετοχή μέλλοντα).</p><p><b>Άρνηση:</b> Επειδή εκφράζουν επιδίωξη/βούληση, οι τελικές προτάσεις παίρνουν την άρνηση <b>μή</b> (όχι <i>οὐ</i>). Έτσι σχηματίζονται οι αρνητικές τελικές με <i>ἵνα μή, ὅπως μή, ὡς μή</i> ή απλώς με τον αρνητικό τελικό σύνδεσμο που ισοδυναμεί με «για να μη».</p>","examples":[{"gr":"Κύνας τρέφομεν, ἵνα φυλάττωσι τάς οἰκίας.","an":"«Τρέφουμε σκυλιά, για να φυλάγουν τα σπίτια.» Η τελική <i>ἵνα φυλάττωσι...</i> δηλώνει τον σκοπό του <i>τρέφομεν</i> (= για ποιον σκοπό τρέφουμε; για να φυλάγουν). Εισάγεται με <i>ἵνα</i> και εκφέρεται με υποτακτική (<i>φυλάττωσι</i>), γιατί το ρήμα εξάρτησης είναι αρκτικού χρόνου (ενεστώτας)."},{"gr":"Μή μέλλωμεν, ἵνα μή ὁ καιρός παρέλθῃ.","an":"«Ας μην καθυστερούμε, για να μη χαθεί η κατάλληλη ευκαιρία.» Αρνητική τελική με <i>ἵνα μή</i>· η άρνηση είναι <b>μή</b>, όπως ταιριάζει στον βουλητικό/προσδοκώμενο χαρακτήρα του σκοπού. Εκφορά με υποτακτική αορίστου (<i>παρέλθῃ</i>)."},{"gr":"Ἅ Ἀβροκόμας κατέκαυσεν, ἵνα μή Κῦρος διαβῇ.","an":"Ξεν. Ἀνάβ. 1.4.18 — «(πλοῖα) τα οποία ο Αβροκόμας έκαψε, για να μη διαβεί ο Κύρος (τον ποταμό).» Αρνητική τελική <i>ἵνα μή ... διαβῇ</i> με άρνηση <b>μή</b> και υποτακτική αορίστου· δηλώνει τον σκοπό για τον οποίο έκαψε τα πλοία (επιρρηματικός προσδ. σκοπού)."},{"gr":"Λαβών ὑμᾶς ἐπορευόμην, ἵνα ὠφελοίην αὐτόν.","an":"Ξεν. Ἀνάβ. 1.3.4 — «Παίρνοντας εσάς πορευόμουν, για να τον βοηθήσω.» Η τελική δηλώνει τον σκοπό της πορείας (επιρρηματικός προσδ. σκοπού)· εξάρτηση από ιστορικό χρόνο (<i>ἐπορευόμην</i>) → ευκτική του πλαγίου (<i>ὠφελοίην</i>). Καθαρό παράδειγμα σκοπού προσδοκώμενου στο παρελθόν."}]},{"h":"Εισαγωγή: οι τελικοί σύνδεσμοι","body":"<p>Οι τελικές προτάσεις εισάγονται με τους <b>τελικούς συνδέσμους</b>:</p><ul><li><b>ἵνα</b> (= για να) — ο πιο συνηθισμένος και «ουδέτερος» τελικός σύνδεσμος της αττικής πεζογραφίας.</li><li><b>ὅπως</b> (= για να, όπως, ώστε) — επίσης πολύ συχνός· αρχικά είχε τροπική χροιά («με ποιον τρόπο»), γι' αυτό προτιμάται κυρίως ύστερα από ρήματα που σημαίνουν <i>προσπαθώ, φροντίζω, επιδιώκω</i>.</li><li><b>ὡς</b> (= για να) — συχνότερος στον Ξενοφώντα, στους τραγικούς και στον Όμηρο· σπανιότερος στους πεζογράφους της κλασικής αττικής (Θουκυδίδης, Πλάτων, ρήτορες).</li><li><b>ὄφρα</b> (= για να) — επικός/ποιητικός τελικός σύνδεσμος (Όμηρος), δεν απαντά στην αττική πεζογραφία.</li></ul><p>Όταν η τελική είναι αρνητική, στους παραπάνω συνδέσμους προστίθεται η άρνηση <b>μή</b>: <i>ἵνα μή, ὅπως μή, ὡς μή, ὄφρα μή</i> (= για να μη). Σε ορισμένες περιπτώσεις το αρνητικό <i>μή</i> μπορεί να εισάγει τελική πρόταση και μόνο του (σκέτο <i>μή</i> = «μήπως / για να μη»), ιδίως μετά από ρήματα φόβου ή πρόνοιας, όπου όμως πρέπει να γίνεται διάκριση από τις ενδοιαστικές προτάσεις.</p><p><b>Προσοχή στην πολυσημία:</b> οι ίδιοι σύνδεσμοι (<i>ὅπως, ὡς</i>) εισάγουν και άλλα είδη προτάσεων (πλάγιες ερωτηματικές, ειδικές, αναφορικές, αποτελεσματικές). Η σωστή αναγνώριση γίνεται από το <b>νόημα</b> (δήλωση σκοπού), από την <b>έγκλιση</b> (υποτακτική / ευκτική του πλαγίου) και από την <b>άρνηση μή</b>.</p>","examples":[{"gr":"Παιδεύουσι τούς παῖδας, ὅπως ἀγαθοί γένωνται.","an":"«Εκπαιδεύουν τα παιδιά, για να γίνουν ενάρετα.» Εισαγωγή με <i>ὅπως</i> (τελικός), εκφορά με υποτακτική αορίστου (<i>γένωνται</i>) μετά από αρκτικό χρόνο εξάρτησης (<i>παιδεύουσι</i>). Σκοπός προσδοκώμενος."},{"gr":"Φεύγωμεν, ὡς σωθῶμεν.","an":"«Ας φύγουμε, για να σωθούμε.» Εισαγωγή με τον τελικό σύνδεσμο <i>ὡς</i>· υποτακτική αορίστου <i>σωθῶμεν</i>. Το <i>ὡς</i> ως τελικός είναι συχνό στον Ξενοφώντα."},{"gr":"βῆ δ' ἰέναι, ὄφρα ... (Ὅμηρος, τύπος)","an":"«Ξεκίνησε να πηγαίνει, για να ...» Επικό παράδειγμα με τον ομηρικό τελικό σύνδεσμο <i>ὄφρα</i>, ο οποίος ανήκει στην ποιητική γλώσσα και όχι στην αττική πεζογραφία."},{"gr":"Ἐπιμέλεται ὅπως οἱ νεώτεροι ὡς βέλτιστοι ἔσονται.","an":"Τύπου Πλάτ. Ἀπολ. 24d (<i>περί πολλοῦ ποιεῖται ὅπως ... ἔσονται</i>) — «Φροντίζει ώστε οι νεότεροι να γίνουν όσο το δυνατόν καλύτεροι.» Μετά από ρήμα φροντίδας/επιμέλειας το <i>ὅπως</i> εισάγει τελική (συχνά με μέλλοντα οριστικής, χαρακτηριστική κατασκευή των ρημάτων <i>ἐπιμελοῦμαι, φροντίζω, σκοπῶ</i>)."},{"gr":"Ὡς δ' ἄν μάθῃς, ἀντάκουσον.","an":"Ξεν. (τύπου Κύρ. Παιδ.) — «Και για να μάθεις, άκουσε με τη σειρά σου.» Τελική με τον σύνδεσμο <i>ὡς</i> (εδώ <i>ὡς ἄν</i> + υποτακτική <i>μάθῃς</i>)· δείχνει τη συχνή χρήση του <i>ὡς</i> ως τελικού στον Ξενοφώντα."}],"table":{"title":"Τελικοί σύνδεσμοι: χρήση και ύφος","cols":["Σύνδεσμος","Σημασία","Άρνηση","Ύφος / Συχνότητα"],"rows":[["ἵνα","για να","ἵνα μή","Ο πιο κοινός στην αττική πεζογραφία"],["ὅπως","για να","ὅπως μή","Συχνός· συχνά μετά από ρήματα προσπάθειας/φροντίδας"],["ὡς","για να","ὡς μή","Κυρίως Ξενοφών, τραγικοί, Όμηρος· σπάνιος στους Αττικούς πεζογράφους"],["ὄφρα","για να","ὄφρα μή","Επικός/ποιητικός (Όμηρος)· όχι στην αττική πεζογραφία"]]},"note":"Παγίδα: τα ὅπως και ὡς δεν είναι πάντοτε τελικά. Π.χ. στο «οὐκ οἶδα ὅπως τοῦτο ἐγένετο» το ὅπως εισάγει πλάγια ερωτηματική (= με ποιον τρόπο), ενώ στο «λέγει ὡς ἀληθῆ ἐστι» το ὡς εισάγει ειδική. Κριτήριο: η τελική δηλώνει ΣΚΟΠΟ και έχει άρνηση μή."},{"h":"Εκφορά Α: Υποτακτική και ευκτική του πλαγίου λόγου","body":"<p>Η εκφορά (έγκλιση) της τελικής πρότασης εξαρτάται καθοριστικά από τον <b>χρόνο του ρήματος εξάρτησης</b> (αρκτικός ή ιστορικός). Οι δύο βασικοί, κανονικοί τρόποι εκφοράς είναι:</p><h3>1. Υποτακτική</h3><p>Η τελική εκφέρεται με <b>υποτακτική</b> όταν δηλώνει σκοπό <b>προσδοκώμενο με βεβαιότητα / προσδοκία</b>. Αυτό συμβαίνει κανονικά όταν το ρήμα της πρότασης από την οποία εξαρτάται η τελική βρίσκεται σε <b>αρκτικό χρόνο</b> (ενεστώτας, μέλλοντας, παρακείμενος, καθώς και προστακτική, υποτακτική, ευχετική ευκτική, δηλαδή χρόνοι/εγκλίσεις «του παρόντος-μέλλοντος»). Χρησιμοποιείται κανονικά υποτακτική ενεστώτα (για διαρκή σκοπό) ή αορίστου (για στιγμιαίο/συνοπτικό σκοπό).</p><h3>2. Ευκτική του πλαγίου λόγου</h3><p>Η τελική εκφέρεται με <b>ευκτική του πλαγίου λόγου</b> (ευκτική κάθε χρόνου), <b>αντί</b> της υποτακτικής, όταν το ρήμα από το οποίο εξαρτάται η τελική βρίσκεται σε <b>ιστορικό χρόνο</b> (παρατατικό, αόριστο, υπερσυντέλικο, καθώς και ιστορικό-διηγηματικό ενεστώτα). Πρόκειται για ίσχυση της ακολουθίας των χρόνων (<i>consecutio temporum</i>): ο ομιλητής, καθώς αναφέρεται στο παρελθόν, μεταθέτει την προσδοκώμενη ενέργεια στην ευκτική.</p><p><b>Σημαντική παρατήρηση:</b> Ακόμη και μετά από ιστορικό χρόνο, η αττική συχνά διατηρεί την <b>υποτακτική</b> αντί της ευκτικής του πλαγίου, για να παραστήσει τον σκοπό πιο ζωηρά και «μπροστά στα μάτια» του αναγνώστη (η λεγόμενη <i>vivid / graphic</i> εκφορά). Έτσι η υποτακτική μετά από ιστορικό χρόνο δεν είναι λάθος· είναι υφολογική επιλογή ζωντάνιας.</p>","examples":[{"gr":"Ἐσθίομεν, ἵνα ζῶμεν.","an":"«Τρώμε, για να ζούμε.» Εξάρτηση από αρκτικό χρόνο (ενεστώτας <i>ἐσθίομεν</i>) → εκφορά με <b>υποτακτική</b> ενεστώτα (<i>ζῶμεν</i>, διαρκής σκοπός)."},{"gr":"Ἦλθον, ἵνα ἴδοιμι τήν πόλιν.","an":"«Ήρθα, για να δω την πόλη.» Εξάρτηση από ιστορικό χρόνο (αόριστος <i>ἦλθον</i>) → εκφορά με <b>ευκτική του πλαγίου λόγου</b> (<i>ἴδοιμι</i>, ευκτική αορίστου). Δηλώνει σκοπό προσδοκώμενο στο παρελθόν."},{"gr":"Ἀφικόμεθα εἰς Πέρσας, ἵνα τόν βασιλέα ἴδοιμεν.","an":"«Φτάσαμε στους Πέρσες, για να δούμε τον βασιλιά.» Ιστορικός χρόνος εξάρτησης (<i>ἀφικόμεθα</i>) → ευκτική πλαγίου <i>ἴδοιμεν</i>. Κανονική εφαρμογή της ακολουθίας των χρόνων."},{"gr":"Συνήγαγε στρατιάν, ἵνα κατάσχῃ τήν ἀρχήν.","an":"«Συγκέντρωσε στρατό, για να κρατήσει την εξουσία.» Παρότι η εξάρτηση είναι ιστορικός χρόνος (<i>συνήγαγε</i>, αόριστος), διατηρείται <b>υποτακτική</b> (<i>κατάσχῃ</i>) για ζωηρότερη/παραστατική απόδοση του σκοπού — επιτρεπτή και συνηθισμένη στην αττική."},{"gr":"Λαβών ὑμᾶς ἐπορευόμην, ἵνα ὠφελοίην αὐτόν ἀνθ' ὧν εὖ ἔπαθον ὑπ' ἐκείνου.","an":"Ξεν. Ἀνάβ. 1.3.4 — «Παίρνοντας εσάς πορευόμουν, για να τον βοηθήσω σε αντάλλαγμα για τις ευεργεσίες που δέχτηκα απ' αυτόν.» Ιστορικός χρόνος εξάρτησης (παρατ. <i>ἐπορευόμην</i>) → <b>ευκτική του πλαγίου</b> (<i>ὠφελοίην</i>). Ο Ξενοφών προτιμά την ευκτική στις τελικές μετά από ιστορικό χρόνο."}],"table":{"title":"Επιλογή έγκλισης ανάλογα με τον χρόνο εξάρτησης","cols":["Χρόνος ρήματος εξάρτησης","Κανονική εκφορά τελικής","Σημασία","Επιτρεπτή εναλλακτική"],"rows":[["Αρκτικός (ενεστ., μέλλ., παρακ., προστ., υποτ.)","Υποτακτική","Σκοπός προσδοκώμενος","—"],["Ιστορικός (παρατ., αόρ., υπερσ., ιστ. ενεστ.)","Ευκτική του πλαγίου λόγου","Σκοπός προσδοκώμενος στο παρελθόν","Υποτακτική (ζωηρή/παραστατική εκφορά)"]]},"note":"Η ευκτική στην τελική πρόταση είναι ΠΑΝΤΑ ευκτική του πλαγίου λόγου (όχι ευχετική, όχι δυνητική) και προϋποθέτει ιστορικό χρόνο εξάρτησης. Αν δείτε ευκτική σε τελική χωρίς ιστορικό χρόνο στην εξάρτηση, επανελέγξτε τον χαρακτηρισμό της πρότασης."},{"h":"Εκφορά Β: Δυνητική υποτακτική, δυνητική ευκτική και η οριστική ιστορικού χρόνου (ανεκπλήρωτος σκοπός)","body":"<p>Πέρα από τους δύο κανονικούς τρόπους εκφοράς, η τελική πρόταση παρουσιάζει και ορισμένες ειδικότερες, σημαντικές εκφορές:</p><h3>1. Υποτακτική + ἄν (δυνητική υποτακτική)</h3><p>Όταν στην τελική προστίθεται το <b>ἄν</b> (το λεγόμενο <i>αοριστολογικό ἄν</i>, συχνά συγχωνευμένο σε <i>ὡς ἄν, ὅπως ἄν</i>), ο σκοπός παριστάνεται ως <b>ενδεχόμενος / υπό προϋπόθεση</b>, δηλαδή «για να, ενδεχομένως / εφόσον προκύψει η ευκαιρία». Το <i>ἄν</i> εμφανίζεται κυρίως με τους συνδέσμους <i>ὡς</i> και <i>ὅπως</i> (σπανιότερα με <i>ἵνα</i>) και προσδίδει χροιά υποθετική/δυνητική στον σκοπό.</p><h3>2. Ευκτική + ἄν (δυνητική ευκτική)</h3><p>Σπανιότερα η τελική μπορεί να εκφερθεί με <b>δυνητική ευκτική</b> (ευκτική + <i>ἄν</i>), όταν ο σκοπός παρουσιάζεται ως δυνατός υπό όρους στο παρελθόν ή ως ευγενικά/υποθετικά διατυπωμένη δυνατότητα.</p><h3>3. Οριστική ιστορικού χρόνου — ο ανεκπλήρωτος (μη πραγματοποιήσιμος) σκοπός</h3><p>Η σημαντικότερη ειδική εκφορά: όταν ο σκοπός είναι <b>ανεκπλήρωτος, μη πραγματοποιήσιμος</b> — επειδή η ενέργεια από την οποία θα εξαρτιόταν δεν έγινε ή δεν μπορεί πια να γίνει — η τελική εκφέρεται με <b>οριστική ιστορικού χρόνου</b> (παρατατικού ή αορίστου). Αυτό συμβαίνει χαρακτηριστικά όταν στην κύρια πρόταση υπάρχει <b>μη πραγματικό / αντίθετο του πραγματικού</b> (δυνητική οριστική ή ευχή ανεκπλήρωτη). Η οριστική ιστορικού χρόνου στην τελική αντιστοιχεί στο νεοελληνικό «για να ... (αλλά αυτό δεν έγινε)».</p>","examples":[{"gr":"Σπεύδωμεν, ὡς ἄν φθάσωμεν τούς πολεμίους.","an":"«Ας βιαστούμε, για να προλάβουμε ενδεχομένως τους εχθρούς.» Δυνητική υποτακτική (<i>ὡς ἄν ... φθάσωμεν</i>)· το <i>ἄν</i> δίνει στον σκοπό χροιά ενδεχομένου/υπό προϋπόθεση."},{"gr":"Εἴθε σε εἶχον σύμβουλον, ἵνα μοι συνεβούλευες.","an":"«Μακάρι να σε είχα σύμβουλο, για να με συμβούλευες.» Στην κύρια υπάρχει ανεκπλήρωτη ευχή· γι' αυτό η τελική εκφέρεται με <b>οριστική ιστορικού χρόνου</b> (παρατατικός <i>συνεβούλευες</i>) και δηλώνει <b>ανεκπλήρωτο/μη πραγματοποιήσιμο σκοπό</b> (= αλλά δεν σε έχω, άρα δεν με συμβουλεύεις)."},{"gr":"Τί μ' οὐ λαβών ἔκτεινας εὐθύς, ὡς ἔδειξα μήποτε... ;","an":"Τύπος σοφόκλειας έκφρασης: η τελική με <b>οριστική ιστορικού χρόνου</b> (<i>ἔδειξα</i>) μετά από μη-πραγματικό περιεχόμενο της κύριας δηλώνει σκοπό που ΔΕΝ μπόρεσε να πραγματοποιηθεί, επειδή η προϋπόθεσή του δεν συνέβη."},{"gr":"Ἐχρῆν αὐτούς ἐλθεῖν, ἵνα ταῦτα εἶδον.","an":"«Έπρεπε να είχαν έρθει, ώστε να τα έβλεπαν αυτά (αλλά δεν ήρθαν, άρα δεν τα είδαν).» Στην κύρια υπάρχει μη-πραγματικό (<i>ἐχρῆν</i> + απαρέμφατο, δηλωτικό του αντιθέτου προς το πραγματικό)· γι' αυτό η τελική εκφέρεται με <b>οριστική ιστορικού χρόνου</b> (αόρ. <i>εἶδον</i>) και δηλώνει ανεκπλήρωτο σκοπό."}],"note":"Κανόνας-κλειδί: ΟΡΙΣΤΙΚΗ ιστορικού χρόνου σε τελική = ανεκπλήρωτος σκοπός, και προϋποθέτει σχεδόν πάντα μη-πραγματικό περιεχόμενο (δυνητική οριστική ή ανεκπλήρωτη ευχή) στην προσδιοριζόμενη πρόταση. Είναι το αντίστοιχο του «θα ... για να ... (αλλά τίποτε από τα δύο δεν έγινε)»."},{"h":"Διάκριση τελικών από τις αποτελεσματικές (συμπερασματικές) προτάσεις","body":"<p>Η συχνότερη παγίδα είναι η σύγχυση των <b>τελικών</b> με τις <b>αποτελεσματικές (συμπερασματικές)</b> προτάσεις, καθώς και τα δύο είδη μεταφράζονται στα νέα ελληνικά με «ώστε / για να» και εκφράζουν μια σχέση κύριας–δευτερεύουσας που αφορά «αποτέλεσμα» ή «σκοπό».</p><h3>Η ουσιαστική διαφορά</h3><p>Η τελική δηλώνει <b>σκοπό/πρόθεση</b>: κάτι που <i>επιδιώκεται</i> και είναι μελλοντικό, προσδοκώμενο, ΟΧΙ κατ' ανάγκην πραγματικό. Η αποτελεσματική δηλώνει <b>αποτέλεσμα/συμπέρασμα</b>: κάτι που <i>προκύπτει</i> πραγματικά (ή ως φυσική, λογική συνέπεια) από την ενέργεια της κύριας.</p><h3>Κριτήρια διάκρισης</h3><ul><li><b>Εισαγωγή:</b> Τελικές → <i>ἵνα, ὅπως, ὡς</i> (και <i>ὄφρα</i>). Αποτελεσματικές → <b>ὥστε</b> (σπανιότερα <i>ὡς</i>).</li><li><b>Άρνηση:</b> Τελικές → <b>μή</b> πάντοτε. Αποτελεσματικές → <b>οὐ</b> όταν εκφέρονται με οριστική (πραγματικό αποτέλεσμα)· <b>μή</b> μόνο όταν εκφέρονται με απαρέμφατο (ενδεχόμενο/φυσικό αποτέλεσμα).</li><li><b>Εκφορά:</b> Τελικές → υποτακτική / ευκτική πλαγίου (+ οριστική ιστ. χρόνου για ανεκπλήρωτο σκοπό). Αποτελεσματικές → <b>ὥστε + οριστική</b> (πραγματικό αποτέλεσμα) ή <b>ὥστε + απαρέμφατο</b> (ενδεχόμενο/επακόλουθο φυσικό αποτέλεσμα).</li><li><b>Νόημα/μετάφραση:</b> Τελική = «για να» (πρόθεση). Αποτελεσματική = «ώστε, με αποτέλεσμα να» (συνέπεια). Δοκιμή: αν αντικαθίσταται από «με σκοπό να», είναι τελική· αν από «με αποτέλεσμα να», είναι αποτελεσματική.</li><li><b>Δείκτες στην κύρια:</b> Η αποτελεσματική συχνά προαναγγέλλεται από δεικτικές λέξεις στην κύρια: <i>οὕτως, τοσοῦτος, τοιοῦτος, τηλικοῦτος</i> («τόσο πολύ ... ώστε»). Η τελική δεν συνοδεύεται από τέτοιους δείκτες ποσού/ποιού.</li></ul>","examples":[{"gr":"Ἦλθεν, ἵνα ἴδῃ τόν φίλον. (τελική)","an":"«Ήρθε, για να δει τον φίλο.» Σκοπός/πρόθεση· εισαγωγή <i>ἵνα</i>, υποτακτική, άρνηση θα ήταν <i>μή</i>. ΔΕΝ δηλώνεται ότι όντως τον είδε — μόνο ο σκοπός."},{"gr":"Οὕτως ἀνδρείως ἐμάχετο, ὥστε πάντες ἐθαύμαζον. (αποτελεσματική, πραγματικό αποτέλεσμα)","an":"«Πολεμούσε τόσο γενναία, ώστε όλοι τον θαύμαζαν.» Εισαγωγή <i>ὥστε</i>, εκφορά με <b>οριστική</b> (<i>ἐθαύμαζον</i>) → πραγματικό αποτέλεσμα. Άρνηση θα ήταν <i>οὐ</i>. Δείκτης <i>οὕτως</i> στην κύρια."},{"gr":"Τοσαύτη ἦν ἡ βοή, ὥστε μή ἀκούειν ἀλλήλων. (αποτελεσματική, ενδεχόμενο αποτέλεσμα)","an":"«Τόση ήταν η βοή, ώστε να μην ακούει ο ένας τον άλλον.» Εισαγωγή <i>ὥστε</i>, εκφορά με <b>απαρέμφατο</b> (<i>ἀκούειν</i>) → φυσικό/επακόλουθο αποτέλεσμα· άρνηση <b>μή</b>. Δείκτης <i>τοσαύτη</i>."},{"gr":"Φρούριον ἐτείχισαν, ἵνα μή οἱ πολέμιοι εἰσβάλωσιν. (τελική)","an":"«Έχτισαν φρούριο, για να μην εισβάλουν οι εχθροί.» Σκοπός με <i>ἵνα μή</i> + υποτακτική. Σύγκρινε με υποθετικό αποτελεσματικό «ὥστε μή εἰσβάλλειν» που θα δήλωνε συνέπεια, όχι πρόθεση."},{"gr":"Ὁ ποταμός τοσοῦτος ἦν, ὥστε οἱ στρατιῶται οὐ διέβησαν. (αποτελεσματική)","an":"«Ο ποταμός ήταν τόσο μεγάλος, ώστε οι στρατιώτες δεν τον διάβηκαν.» Δείκτης <i>τοσοῦτος</i> στην κύρια· εισαγωγή <i>ὥστε</i>· οριστική <i>διέβησαν</i> με άρνηση <b>οὐ</b> → πραγματικό αποτέλεσμα. Αντιπαραβολή με τελική: εδώ δεν υπάρχει πρόθεση, αλλά πραγματική συνέπεια."}],"table":{"title":"Τελικές vs Αποτελεσματικές — συγκριτικός πίνακας","cols":["Στοιχείο","Τελικές","Αποτελεσματικές (συμπερασματικές)"],"rows":[["Δηλώνουν","Σκοπό / πρόθεση","Αποτέλεσμα / συμπέρασμα"],["Εισαγωγή","ἵνα, ὅπως, ὡς (ὄφρα)","ὥστε (σπάν. ὡς)"],["Εκφορά","Υποτακτική, ευκτική πλαγίου, οριστ. ιστ. χρόνου","ὥστε + οριστική (πραγματικό) / ὥστε + απαρέμφατο (ενδεχόμενο)"],["Άρνηση","μή (πάντα)","οὐ (με οριστική) / μή (με απαρέμφατο)"],["Δείκτες στην κύρια","—","οὕτως, τοσοῦτος, τοιοῦτος, τηλικοῦτος"],["Μετάφραση-δοκιμή","«με σκοπό να»","«με αποτέλεσμα να»"]]},"note":"Συχνότερο λάθος: να χαρακτηριστεί τελική μια πρόταση «να ...» που είναι στην πραγματικότητα αντικείμενο ρήματος (π.χ. ἐκέλευσεν αὐτούς ἀπελθεῖν / εἶπε να φύγουν) ή βουλητική. Δοκιμή: αν το «να» αντικαθίσταται ομαλά με «για να» (σκοπός), είναι τελική· αν συμπληρώνει το νόημα του ρήματος (τι διέταξε; τι θέλει;), είναι βουλητική/αντικείμενο."},{"h":"Θέση, ισοδυναμίες, σύμπτυξη και πρακτική μεθοδολογία αναγνώρισης","body":"<h3>Θέση μέσα στην περίοδο</h3><p>Η τελική πρόταση τοποθετείται κανονικά <b>μετά</b> την προσδιοριζόμενη πρόταση (την κύρια ή τη δευτερεύουσα στην οποία δηλώνει σκοπό), αφού ο σκοπός είναι λογικά μεταγενέστερος της πράξης. Μπορεί όμως, για λόγους έμφασης, να προτάσσεται.</p><h3>Ισοδύναμες εκφράσεις σκοπού</h3><p>Ο σκοπός στην αρχαία ελληνική δεν εκφράζεται μόνο με τελική πρόταση. Ισοδύναμοι τρόποι είναι:</p><ul><li><b>Τελική μετοχή</b> (μετοχή μέλλοντα, συχνά με <i>ὡς</i>): <i>ἦλθεν λυσόμενος τήν θυγατέρα</i> = ἦλθεν, ἵνα λύσηται τήν θυγατέρα.</li><li><b>Εμπρόθετος προσδιορισμός σκοπού</b>: <i>ἐπί θήραν</i> = «για κυνήγι», <i>ἐπί / πρός + αιτιατική</i>.</li><li><b>Τελικό απαρέμφατο</b> (μετά από ρήματα κίνησης, εκλογής, δόσης): <i>ἔδωκεν αὐτῷ χρήματα ἀναλῶσαι</i> = «για να τα ξοδέψει».</li><li><b>Αναφορική τελική πρόταση</b> με ευκτική/μέλλοντα οριστικής: <i>πέμπει ἀγγέλους, οἵτινες ταῦτα ἐροῦσιν</i> = «για να πουν αυτά».</li><li><b>Γενική του σκοπού/απωτέρου σκοπού</b> με άρθρο + απαρέμφατο: <i>τοῦ μή διαφεύγειν</i>.</li></ul><p>Αντίστροφα, μια τελική πρόταση μπορεί να <b>συμπτυχθεί</b> σε τελική μετοχή (μέλλοντα), όταν το υποκείμενο της τελικής ταυτίζεται με όρο της κύριας.</p><h3>Πρακτική μεθοδολογία αναγνώρισης (βήμα-βήμα)</h3><ol><li>Εντόπισε τον εισαγωγικό σύνδεσμο: <i>ἵνα / ὅπως / ὡς / ὄφρα</i>.</li><li>Έλεγξε αν δηλώνεται <b>σκοπός</b> (απάντησε «για ποιον σκοπό;»). Αν ναι → πιθανή τελική.</li><li>Δες την <b>έγκλιση</b>: υποτακτική ή ευκτική του πλαγίου (ή οριστ. ιστ. χρόνου για ανεκπλήρωτο σκοπό) → επιβεβαίωση τελικής.</li><li>Δες την <b>άρνηση</b>: <i>μή</i> → συνηγορεί υπέρ τελικής (αν <i>οὐ</i> με οριστική + <i>ὥστε</i> → αποτελεσματική).</li><li>Έλεγξε τον <b>χρόνο εξάρτησης</b> για να αιτιολογήσεις την έγκλιση (αρκτικός → υποτακτική· ιστορικός → ευκτική πλαγίου ή κατ' εξαίρεση υποτακτική).</li><li>Απόδωσε τη <b>συντακτική λειτουργία</b>: επιρρηματικός προσδιορισμός του σκοπού στο ρήμα της προσδιοριζόμενης πρότασης.</li></ol>","examples":[{"gr":"Πέμπει ἄγγελον, ἵνα ἀπαγγείλῃ τά γεγενημένα.","an":"«Στέλνει αγγελιοφόρο, για να αναγγείλει τα γεγονότα.» Πλήρης ανάλυση: εισαγωγή <i>ἵνα</i> (τελ.)· σκοπός· υποτακτική αορίστου <i>ἀπαγγείλῃ</i> (αρκτικός χρόνος εξάρτησης <i>πέμπει</i>)· άρνηση θα ήταν <i>μή</i>· λειτουργία: επιρρηματικός προσδ. σκοπού στο <i>πέμπει</i>."},{"gr":"Πέμπει ἄγγελον ἀπαγγελοῦντα τά γεγενημένα.","an":"Η ίδια ιδέα συμπτυγμένη σε <b>τελική μετοχή μέλλοντα</b> (<i>ἀπαγγελοῦντα</i>) — ισοδύναμη της τελικής πρότασης· δείχνει την εναλλαξιμότητα τελικής πρότασης και τελικής μετοχής."},{"gr":"Παρεσκευάζοντο, ὅπως / ὡς εὖ ἀγωνιοῖντο.","an":"«Προετοιμάζονταν, για να αγωνιστούν καλά.» Ιστορικός χρόνος εξάρτησης (<i>παρεσκευάζοντο</i>, παρατατικός) → ευκτική του πλαγίου λόγου (<i>ἀγωνιοῖντο</i>). Δείχνει την κανονική μετάβαση σε ευκτική μετά από ιστορικό χρόνο."},{"gr":"Συνέπεμπε δέ αὐτῷ καί τῆς ἑαυτοῦ δυνάμεως, ὅπως ... (τύπου Ξεν.)","an":"«Έστελνε μαζί του και μέρος της δικής του δύναμης, για να ...» Τελική με <i>ὅπως</i> εξαρτημένη από ιστορικό χρόνο· δείχνει τη χρήση του <i>ὅπως</i> ως τελικού στην αφηγηματική πεζογραφία. Λειτουργία: επιρρηματικός προσδ. σκοπού."}],"note":"Σύνοψη-μνημονικό: ΣΚΟΠΟΣ + (ἵνα/ὅπως/ὡς) + υποτακτική ή ευκτική πλαγίου + άρνηση ΜΗ = τελική. Αν δεις ὥστε ή άρνηση οὐ ή δείκτη οὕτως/τοσοῦτος, σκέψου αποτελεσματική. Αν το «να» συμπληρώνει ρήμα βούλησης/εντολής, σκέψου βουλητική/αντικείμενο, όχι τελική."}]);
  T("syn-apotelesmatikes", [{"h":"Ορισμός, ονομασία και συντακτικός ρόλος","body":"<p><b>Αποτελεσματικές</b> ή <b>συμπερασματικές</b> (λατ. consecutivae) ονομάζονται οι δευτερεύουσες επιρρηματικές προτάσεις που δηλώνουν το <b>αποτέλεσμα</b> ή το <b>συμπέρασμα</b> που προκύπτει από την ενέργεια ή την κατάσταση που εκφράζει το ρήμα της προσδιοριζόμενης (συνήθως κύριας) πρότασης.</p><p>Η διπλή ονομασία αντανακλά δύο όψεις του ίδιου φαινομένου: όταν τονίζεται η <i>πραγματική, φυσική απόρροια</i> μιας ενέργειας μιλάμε για <b>αποτέλεσμα</b> (\"τόσο πολύ έτρεξε, ώστε κουράστηκε\")· όταν τονίζεται το <i>λογικό πόρισμα</i> που εξάγει ο ομιλητής μιλάμε για <b>συμπέρασμα</b> (\"είσαι τόσο αναίσθητος, ώστε δεν μπορείς να σκεφτείς\"). Στη σχολική πράξη οι δύο όροι είναι ταυτόσημοι.</p><h3>Συντακτικός ρόλος</h3><p>Ως επιρρηματικές προτάσεις λειτουργούν κατά κανόνα ως <b>επιρρηματικός προσδιορισμός του αποτελέσματος</b> στο ρήμα της κύριας. Ειδικότερα μπορεί να είναι:</p><ul><li><b>Επιρρηματικός προσδιορισμός του αποτελέσματος</b> (η συνηθέστερη περίπτωση, με <i>ὥστε / ὡς</i>).</li><li><b>Επιρρηματικός προσδιορισμός του όρου / της προϋπόθεσης / της συμφωνίας</b> (με τις εκφράσεις <i>ἐφ' ᾧ, ἐφ' ᾧτε</i>: \"με τον όρο να...\").</li><li><b>Επεξήγηση</b> σε προηγούμενη δεικτική λέξη ή εμπρόθετο προσδιορισμό (π.χ. σε <i>ἐπί τούτῳ ... ἐφ' ᾧτε</i>).</li></ul><p>Όταν στην κύρια προηγείται δεικτική (συσχετιστική) λέξη — <i>οὕτω(ς), τοσοῦτος, τοιοῦτος, τηλικοῦτος</i> κ.ά. — η αποτελεσματική πρόταση εξειδικεύει το περιεχόμενο αυτής της δεικτικής λέξης και είναι στενά συνδεδεμένη μαζί της.</p>","examples":[{"gr":"Οὕτω σκαιός εἶ καί ἀναίσθητος, Αἰσχίνη, ὥστ' οὐ δύνασαι λογίσασθαι.","an":"Είσαι τόσο αδέξιος και αναίσθητος, Αισχίνη, ώστε δεν μπορείς να σκεφτείς. — Κύρια: <i>οὕτω σκαιός εἶ καί ἀναίσθητος</i> (με δεικτικό <i>οὕτω</i>)· δευτερεύουσα αποτελεσματική: <i>ὥστ' οὐ δύνασαι λογίσασθαι</i>, επιρρηματικός προσδιορισμός του αποτελέσματος που εξειδικεύει το <i>οὕτω</i>. Εκφορά με οριστική (<i>δύνασαι</i>) = πραγματικό αποτέλεσμα· άρνηση <i>οὐ</i>. (Δημ., Περί στεφ. 120)"},{"gr":"Νῦν οὕτω διάκειμαι ὑφ' ὑμῶν, ὡς οὐδέ δεῖπνον ἔχω ἐν τῇ ἐμαυτοῦ χώρᾳ.","an":"Τώρα έχω καταντήσει από εσάς σε τέτοια κατάσταση, ώστε ούτε φαγητό δεν έχω στην ίδια μου τη χώρα. — Αποτελεσματική με <i>ὡς</i> + οριστική (<i>ἔχω</i>): πραγματικό αποτέλεσμα. Δεικτικό στην κύρια: <i>οὕτω</i>. (Ξεν. Ἑλλ. 4.1.33)"},{"gr":"Ὥστε βασιλεύς τήν μέν πρός ἑαυτόν ἐπιβουλήν οὐκ ᾐσθάνετο.","an":"Ξεν. Ἀνάβ. 1.1.8 — «ώστε ο βασιλιάς δεν αντιλαμβανόταν τη συνωμοσία εναντίον του». Αποτελεσματική σε αρχή περιόδου, λειτουργεί ως επιρρ. προσδ. του αποτελέσματος· εκφορά με οριστική (<i>ᾐσθάνετο</i>), άρνηση <b>οὐκ</b> = πραγματικό αποτέλεσμα."},{"gr":"Τοιοῦτος ἦν ἐν τοῖς κινδύνοις, ὥστε πάντες αὐτόν ἐθαύμαζον.","an":"Ήταν τέτοιος στους κινδύνους, ώστε όλοι τον θαύμαζαν. — Δεικτικό ποιότητας <i>τοιοῦτος</i> στην κύρια· η αποτελεσματική (<i>ὥστε ... ἐθαύμαζον</i>, οριστική) εξειδικεύει τη δεικτική λέξη ως επιρρ. προσδ. του αποτελέσματος. (τύπου Ξενοφῶντος)"}],"note":"Προσοχή στη διάκριση όρων: όλες οι αποτελεσματικές είναι «επιρρηματικές», αλλά ΟΧΙ «τελικές». Η σύγχυση αποτελέσματος / σκοπού είναι το συχνότερο λάθος και αναλύεται διεξοδικά στο τελευταίο κεφάλαιο."},{"h":"Εισαγωγή: ὥστε, ὡς και οι εκφράσεις ἐφ' ᾧ / ἐφ' ᾧτε","body":"<p>Οι αποτελεσματικές προτάσεις εισάγονται με τους <b>συμπερασματικούς (αποτελεσματικούς) συνδέσμους</b>:</p><ul><li><b>ὥστε</b> — ο κύριος και συντριπτικά συχνότερος σύνδεσμος· συντάσσεται είτε με <b>έγκλιση</b> (οριστική, δυνητική οριστική/ευκτική, ευκτική του πλαγίου λόγου) είτε με <b>απαρέμφατο</b>.</li><li><b>ὡς</b> — σπανιότερο, ισοδύναμο του <i>ὥστε</i>· απαντά κυρίως με οριστική, αλλά και με απαρέμφατο.</li></ul><h3>Οι εκφράσεις του όρου / της προϋπόθεσης</h3><p>Ξεχωριστή κατηγορία αποτελεσματικών (δηλωτικών <b>όρου, προϋπόθεσης ή συμφωνίας</b>) εισάγεται με τις παγιωμένες εκφράσεις:</p><ul><li><b>ἐφ' ᾧ</b> και <b>ἐφ' ᾧτε</b> (= «με τον όρο να, υπό την προϋπόθεση ότι, με τη συμφωνία να»).</li></ul><p>Αυτές εκφέρονται κανονικά με <b>απαρέμφατο</b> ή με <b>οριστική μέλλοντα</b>. Δηλώνουν ένα αποτέλεσμα που τίθεται ως όρος συμφωνίας ανάμεσα σε δύο μέρη — γι' αυτό προτιμώνται μετά από ρήματα όπως <i>συγχωρῶ, σπένδομαι, ὁμολογῶ, ἀφίημι</i> (\"συμφωνώ / κάνω συνθήκη με τον όρο να...\").</p><h3>Δεικτικές (συσχετιστικές) λέξεις στην κύρια</h3><p>Πολύ συχνά η κύρια πρόταση «προαναγγέλλει» την αποτελεσματική με μια δεικτική λέξη που εκφράζει ποσό, ποιότητα ή μέγεθος. Η συσχέτιση δεικτικού + <i>ὥστε</i> είναι το χαρακτηριστικότερο σχήμα του φαινομένου (βλ. χωριστό κεφάλαιο).</p>","examples":[{"gr":"Συνεχώρησαν αὐτοῖς ... τήν εἰρήνην, ἐφ' ᾧτε ἔχειν τήν ἑαυτῶν ἑκάστους.","an":"Συμφώνησαν μαζί τους ... την ειρήνη, με τον όρο να κρατά ο καθένας τα δικά του. — Αποτελεσματική του όρου / της συμφωνίας με <i>ἐφ' ᾧτε</i> + απαρέμφατο (<i>ἔχειν</i>). Δεν δηλώνει αποτέλεσμα που συνέβη, αλλά τη συμφωνημένη προϋπόθεση."},{"gr":"Ἐπί τούτοις ... ἐφ' ᾧτε πλείονα κτήσονται.","an":"Με αυτούς τους όρους ... με την προϋπόθεση ότι θα αποκτήσουν περισσότερα. — Παράδειγμα εκφοράς της έκφρασης όρου με <b>οριστική μέλλοντα</b> (<i>κτήσονται</i>), που είναι η δεύτερη κανονική εκφορά των <i>ἐφ' ᾧ / ἐφ' ᾧτε</i>."},{"gr":"Ἀφίεμέν σε, ἐπί τούτῳ μέντοι, ἐφ' ᾧτε μηκέτι φιλοσοφεῖν.","an":"Σε αφήνουμε ελεύθερο, αλλά με αυτόν τον όρο, να μη φιλοσοφείς πια. — (Πλάτ. Ἀπολ. 29c) <i>ἐφ' ᾧτε</i> + απαρέμφατο· άρνηση <b>μή</b> (<i>μηκέτι</i>) όπως ταιριάζει στο απαρέμφατο. Επεξήγηση στο εμπρόθετο <i>ἐπί τούτῳ</i>."},{"gr":"Ξυνέβησαν ... παραδοῦναι σφᾶς αὐτούς, ὥστε βουλεῦσαι ὅ τι ἄν ἐκείνοις δοκῇ.","an":"Συμφώνησαν ... να παραδοθούν, με τον όρο εκείνοι να αποφασίσουν ό,τι τους φανεί. — (τύπου Θουκυδίδου) Εδώ το ίδιο το <i>ὥστε</i> + απαρέμφατο (<i>βουλεῦσαι</i>) έχει σημασία όρου / συμφωνίας, ισοδύναμη με τα <i>ἐφ' ᾧ / ἐφ' ᾧτε</i>."},{"gr":"Ἔχω τριήρεις, ὥστε ἑλεῖν τό ἐκείνων πλοῖον.","an":"Ξεν. Ἀνάβ. 1.4.8 — «έχω τριήρεις, ώστε να πιάσω το πλοίο τους». <i>ὥστε</i> + απαρέμφατο (<i>ἑλεῖν</i>): φυσικό / ενδεχόμενο αποτέλεσμα, ικανότητα-δυνατότητα· δείχνει την κανονική εναλλακτική εκφορά του ὥστε με απαρέμφατο."}],"table":{"title":"Εισαγωγικά στοιχεία των αποτελεσματικών προτάσεων","cols":["Εισαγωγικό","Σημασία","Κανονική εκφορά","Κατηγορία αποτελέσματος"],"rows":[["ὥστε","ώστε, με αποτέλεσμα να","οριστική / δυνητική / ευκτική πλαγίου λόγου ή απαρέμφατο","πραγματικό ή ενδεχόμενο / φυσικό"],["ὡς","ώστε (σπανιότερο)","κυρίως οριστική, σπάνια απαρέμφατο","κυρίως πραγματικό"],["ἐφ' ᾧ","με τον όρο να, υπό την προϋπόθεση ότι","απαρέμφατο ή οριστική μέλλοντα","όρος / προϋπόθεση / συμφωνία"],["ἐφ' ᾧτε","με τον όρο να, με τη συμφωνία να","απαρέμφατο ή οριστική μέλλοντα","όρος / προϋπόθεση / συμφωνία"]]},"note":"Το ίδιο το ὥστε, όταν δεν εισάγει δευτερεύουσα αλλά στέκεται στην αρχή περιόδου με σημασία «επομένως, λοιπόν, γι' αυτό», είναι ΣΥΜΠΕΡΑΣΜΑΤΙΚΟΣ ΣΥΝΔΕΣΜΟΣ ΚΥΡΙΑΣ πρότασης — όχι εισαγωγικό δευτερεύουσας. Π.χ. «ὥστε οὐκ ἄν δικαίως ... » στην αρχή φράσης = «Επομένως δεν θα ... δίκαια»."},{"h":"Εκφορά Α: ὥστε + οριστική (πραγματικό αποτέλεσμα)","body":"<p>Όταν το αποτέλεσμα παρουσιάζεται ως <b>πραγματικό γεγονός που όντως συνέβη</b>, η αποτελεσματική εκφέρεται με <b>οριστική</b>. Αυτή είναι η εκφορά του <b>πραγματικού (αντικειμενικού) αποτελέσματος</b>: ο ομιλητής βεβαιώνει ότι το αποτέλεσμα πραγματοποιήθηκε.</p><p>Όπως διδάσκει η σχολική γραμματική και επιβεβαιώνει ο Smyth (§2274 κ.ε.), η οριστική «τονίζει την πραγματική επέλευση» του αποτελέσματος. Συντακτικά, η πρόταση είναι εδώ <b>ανεξάρτητη ως προς την έγκλισή της</b> από την κύρια — σχηματίζει μια κανονική κρίση.</p><h3>Παραλλαγές της έγκλισης (όλες με κύριο σύνδεσμο ὥστε/ὡς)</h3><ul><li><b>Οριστική (απλή)</b>: πραγματικό αποτέλεσμα που συνέβη.</li><li><b>Δυνητική οριστική</b> (<i>ὥστε ... ἄν</i> + παρελθ. χρόνος οριστικής): αποτέλεσμα δυνατό στο παρελθόν αλλά <i>μη πραγματικό</i> / υποθετικό.</li><li><b>Δυνητική ευκτική</b> (<i>ὥστε ... ἄν</i> + ευκτική): αποτέλεσμα πιθανό / ενδεχόμενο υπό προϋποθέσεις στο παρόν-μέλλον.</li><li><b>Ευκτική του πλαγίου λόγου</b>: όταν η αποτελεσματική εξαρτάται από ρήμα ιστορικού χρόνου και το αποτέλεσμα τίθεται «πλαγίως».</li></ul><h3>Άρνηση</h3><p>Με όλες τις εγκλίσεις (οριστική, δυνητική, ευκτική) η άρνηση είναι <b>οὐ</b>, όπως αρμόζει σε πρόταση κρίσης.</p>","examples":[{"gr":"Νῦν οὕτω διάκειμαι ὑφ' ὑμῶν, ὡς οὐδέ δεῖπνον ἔχω ἐν τῇ ἐμαυτοῦ χώρᾳ.","an":"Τώρα έχω από εσάς καταντήσει έτσι, ώστε ούτε δείπνο δεν έχω στη χώρα μου. — ΟΡΙΣΤΙΚΗ (<i>ἔχω</i>): πραγματικό αποτέλεσμα. Άρνηση <b>οὐ(δέ)</b>. (Ξεν. Ἑλλ. 4.1.33)"},{"gr":"Πάντες πολεμικά ὅπλα κατεσκεύαζον, ὥστε τήν πόλιν ὄντως ἄν ἡγήσω πολέμου ἐργαστήριον εἶναι.","an":"Όλοι κατασκεύαζαν πολεμικά όπλα, ώστε θα νόμιζες πραγματικά ότι η πόλη ήταν εργαστήριο πολέμου. — ΔΥΝΗΤΙΚΗ ΟΡΙΣΤΙΚΗ (<i>ἄν ἡγήσω</i>): αποτέλεσμα δυνατό αλλά υποθετικό/μη πραγματικό· (Ξεν. Ἀγησ. 1.26)."},{"gr":"Πλοῖα δ' ὑμῖν πάρεστιν, ὥστε ἐξαίφνης ἄν ἐπιπέσοιτε.","an":"Έχετε διαθέσιμα πλοία, ώστε θα μπορούσατε να επιτεθείτε ξαφνικά. — ΔΥΝΗΤΙΚΗ ΕΥΚΤΙΚΗ (<i>ἄν ἐπιπέσοιτε</i>): ενδεχόμενο αποτέλεσμα υπό προϋποθέσεις· (Ξεν. Ἀνάβ. 5.7.7)."},{"gr":"Οἱ νεκροί ὑπό τῷ τείχει ἔκειντο, ὥστε οὐ ῥάδιον εἴη ἀνελέσθαι.","an":"Οι νεκροί κείτονταν κάτω από το τείχος, ώστε δεν ήταν εύκολο να τους περισυλλέξουν. — ΕΥΚΤΙΚΗ ΤΟΥ ΠΛΑΓΙΟΥ ΛΟΓΟΥ (<i>εἴη</i>) μετά από ιστορικό χρόνο (<i>ἔκειντο</i>)· άρνηση <b>οὐ</b>. (τύπου Θουκυδίδου)"},{"gr":"Ὥστε οἱ μέν ἐγγύτατα τῶν πολεμίων καί ἔφυγον ἐκ τῶν σκηνωμάτων.","an":"Ξεν. Ἀνάβ. 2.2.17 — «ώστε όσοι ήταν πλησιέστερα στους εχθρούς μάλιστα και τράπηκαν σε φυγή από τις σκηνές τους». ΟΡΙΣΤΙΚΗ αορίστου (<i>ἔφυγον</i>): πραγματικό αποτέλεσμα που όντως συνέβη, σε αρχή περιόδου."},{"gr":"Ὥστε μηδέν δι' ἄλλο με ἡγεῖσθε ταύτην ποιεῖσθαι τήν ἀπολογίαν.","an":"Λυσ. 16.8 — «ώστε να μη νομίζετε ότι για κανέναν άλλο λόγο κάνω αυτή την απολογία». Παράδειγμα όπου το <i>ὥστε</i> εισάγει κύρια (προστακτική <i>ἡγεῖσθε</i>) με συμπερασματική σημασία· χρήσιμη αντιδιαστολή προς τη δευτερεύουσα αποτελεσματική."}],"note":"Η οριστική ΔΕΝ είναι υποχρεωτική όποτε το αποτέλεσμα όντως συνέβη: ο συγγραφέας μπορεί να επιλέξει απαρέμφατο για να μην τονίσει την πραγματοποίηση (Smyth §2258). Έτσι το απαρέμφατο μπορεί κατά περιεχόμενο να δηλώνει γεγονός, χωρίς όμως να το βεβαιώνει· η οριστική το βεβαιώνει ρητά."},{"h":"Εκφορά Β: ὥστε + απαρέμφατο (ενδεχόμενο / φυσικό αποτέλεσμα)","body":"<p>Όταν το αποτέλεσμα παρουσιάζεται όχι ως βεβαιωμένο γεγονός αλλά ως <b>ενδεχόμενο, φυσική / αναμενόμενη απόρροια, τάση, ικανότητα ή δυνατότητα</b> της ενέργειας του ρήματος, η αποτελεσματική εκφέρεται με (τελικό) <b>απαρέμφατο</b>. Αυτή είναι η εκφορά του <b>φυσικού / ενδεχόμενου αποτελέσματος</b>.</p><p>Κατά τον Smyth (§2250 κ.ε.), το απαρέμφατο δηλώνει αποτέλεσμα «που μπορεί να επέλθει ως συνέπεια πρόθεσης, τάσης, ικανότητας ή εν γένει της φύσης ενός πράγματος ή μιας ενέργειας», χωρίς να τονίζεται η πραγματική επέλευσή του. Το απαρέμφατο προτιμάται ιδίως:</p><ul><li>όταν υπάρχει στην κύρια δεικτικό ποσού/ποιότητας (<i>τοσοῦτος, τοιοῦτος, οὕτω</i>) που δηλώνει βαθμό/τάση·</li><li>μετά από <b>άρνηση ή υπόθεση</b> στην κύρια (ο σύνδεσμος <i>ὥστε</i> τότε σχεδόν πάντα παίρνει απαρέμφατο)·</li><li>όταν το αποτέλεσμα είναι αναμενόμενο, δυνατό ή απλώς λογικά συναγόμενο.</li></ul><h3>Τρεις σημασιολογικές αποχρώσεις του ὥστε + απαρέμφατο</h3><p>Η σχολική παράδοση διακρίνει τρεις χρήσεις:</p><ol><li><b>Ενδεχόμενο / δυνατό αποτέλεσμα</b> (το συνηθέστερο): «κατάφεραν ώστε να...».</li><li><b>Επιδιωκόμενο αποτέλεσμα ≈ σκοπός</b>: εδώ το <i>ὥστε</i> + απαρέμφατο πλησιάζει τις τελικές προτάσεις («ώστε / για να ακούν»).</li><li><b>Όρος / προϋπόθεση / συμφωνία</b>: συνώνυμο των <i>ἐφ' ᾧ / ἐφ' ᾧτε</i> («με τον όρο να...»).</li></ol><h3>Άρνηση</h3><p>Με το απαρέμφατο η άρνηση είναι <b>μή</b>. Μάλιστα, όταν η ίδια η αποτελεσματική περιέχει ή υπονοεί άρνηση, το απαρέμφατο είναι η προτιμώμενη εκφορά.</p>","examples":[{"gr":"Ξενοφῶν καί Χειρίσοφος διεπράξαντο, ὥστε λαβεῖν τούς νεκρούς.","an":"Ο Ξενοφών και ο Χειρίσοφος κατάφεραν να παραλάβουν τους νεκρούς. — ΑΠΑΡΕΜΦΑΤΟ (<i>λαβεῖν</i>): ενδεχόμενο/επιτευχθέν αποτέλεσμα ύστερα από <i>διεπράξαντο</i> (\"κατόρθωσαν ώστε\"). (τύπου Ξενοφῶντος)"},{"gr":"Κραυγήν πολλήν ἐποίουν καλοῦντες ἀλλήλους, ὥστε καί τούς πολεμίους ἀκούειν.","an":"Έκαναν μεγάλη κραυγή καλώντας ο ένας τον άλλον, ώστε να ακούν και οι εχθροί. — ΑΠΑΡΕΜΦΑΤΟ (<i>ἀκούειν</i>) με χροιά ΣΚΟΠΟΥ (επιδιωκόμενο αποτέλεσμα): εδώ το <i>ὥστε</i> πλησιάζει τελική πρόταση. (Ξεν. Ἀνάβ. 2.2.17)"},{"gr":"Τίς οὕτω μαίνεται, ὥστε μή βούλεσθαί σοι φίλος εἶναι;","an":"Ποιος είναι τόσο τρελός, ώστε να μη θέλει να είναι φίλος σου; — Δεικτικό <i>οὕτω</i> + <i>ὥστε</i> + απαρέμφατο (<i>βούλεσθαι</i>)· άρνηση <b>μή</b>, που επιβεβαιώνει την εκφορά με απαρέμφατο. (τύπου Ξενοφῶντος)"},{"gr":"Οὐδείς οὕτως ἀνόητός ἐστιν, ὥστε πόλεμον πρό εἰρήνης αἱρεῖσθαι.","an":"Κανείς δεν είναι τόσο ανόητος, ώστε να προτιμά τον πόλεμο από την ειρήνη. — Άρνηση στην κύρια (<i>οὐδείς</i>) + δεικτικό <i>οὕτως</i> ⇒ ΑΠΑΡΕΜΦΑΤΟ (<i>αἱρεῖσθαι</i>): τυπική περίπτωση όπου το ὥστε παίρνει απαρέμφατο. (τύπου Ἡροδότου)"},{"gr":"Πάντας οὕτω διατιθείς, ὥστε αὐτῷ εἶναι φίλους.","an":"Ξεν. Ἀνάβ. 1.1.5 — «μεταχειριζόμενος όλους έτσι, ώστε να του είναι φίλοι». Δεικτικό <i>οὕτω</i> + <i>ὥστε</i> + ΑΠΑΡΕΜΦΑΤΟ (<i>εἶναι</i>): φυσικό αποτέλεσμα της μεταχείρισης."}],"table":{"title":"Πραγματικό (οριστική) vs ενδεχόμενο/φυσικό (απαρέμφατο) αποτέλεσμα","cols":["Κριτήριο","ὥστε + ΟΡΙΣΤΙΚΗ","ὥστε + ΑΠΑΡΕΜΦΑΤΟ"],"rows":[["Σημασία","Πραγματικό αποτέλεσμα — όντως συνέβη","Ενδεχόμενο / φυσικό / αναμενόμενο — τάση, ικανότητα, δυνατότητα"],["Έμφαση","Στην πραγματική επέλευση (βεβαίωση)","Στη φύση-τάση της ενέργειας (όχι ρητή βεβαίωση)"],["Άρνηση","οὐ","μή"],["Σχέση με κύρια","Σχετικά ανεξάρτητη κρίση","Στενά εξαρτημένη· συχνά μετά δεικτικό, άρνηση ή υπόθεση"],["Συχνές αφορμές","Διαπιστωμένο γεγονός","Δεικτικό βαθμού (τοσοῦτος/οὕτω), άρνηση/υπόθεση στην κύρια, σκοπός, όρος"]]},"note":"ΠΑΓΙΔΑ ΑΡΝΗΣΗΣ: η άρνηση είναι αλάνθαστος δείκτης εκφοράς. Βλέπεις «ὥστε ... οὐ» ⇒ οριστική/έγκλιση ⇒ πραγματικό αποτέλεσμα. Βλέπεις «ὥστε ... μή» ⇒ απαρέμφατο ⇒ ενδεχόμενο/φυσικό αποτέλεσμα. Δεν ισχύει το αντίστροφο αυτόματα, αλλά η αντιστοιχία οὐ↔οριστική / μή↔απαρέμφατο είναι ο ασφαλέστερος κανόνας."},{"h":"Η συσχέτιση δεικτικού + ὥστε (τοσοῦτος ... ὥστε)","body":"<p>Πολύ συχνά η κύρια πρόταση περιέχει μια <b>δεικτική (συσχετιστική) λέξη</b> που προαναγγέλλει την αποτελεσματική και δηλώνει τον <b>βαθμό, το ποσό, το μέγεθος ή την ποιότητα</b> της ενέργειας από την οποία απορρέει το αποτέλεσμα. Η αποτελεσματική τότε <b>εξειδικεύει</b> αυτή τη δεικτική λέξη.</p><h3>Οι κύριες συσχετίσεις</h3><ul><li><b>οὕτω(ς) ... ὥστε</b> = «τόσο / έτσι ... ώστε» (τρόπος / βαθμός).</li><li><b>τοσοῦτος ... ὥστε</b> = «τόσο μεγάλος / τόσος ... ώστε» (ποσό / μέγεθος).</li><li><b>τοιοῦτος ... ὥστε</b> = «τέτοιος ... ώστε» (ποιότητα).</li><li><b>τηλικοῦτος ... ὥστε</b> = «τόσο μεγάλος (σε ηλικία ή μέγεθος) ... ώστε».</li><li>Επίσης επιρρήματα/εκφράσεις ποσού: <i>εἰς τοσοῦτο(ν), εἰς τοῦτο, μέχρι τούτου ... ὥστε</i>.</li></ul><p>Η παρουσία τέτοιου δεικτικού είναι το <b>ασφαλέστερο μορφολογικό «καμπανάκι»</b> ότι ακολουθεί αποτελεσματική πρόταση. Όταν υπάρχει δεικτικό βαθμού, η εκφορά κλίνει συχνά προς το <b>απαρέμφατο</b> (φυσικό αποτέλεσμα), αλλά απαντά και η οριστική όταν τονίζεται η πραγματική επέλευση.</p><h3>Θέση και στίξη</h3><p>Το δεικτικό βρίσκεται στην κύρια, ο σύνδεσμος <i>ὥστε</i> στην αρχή της δευτερεύουσας· πριν το <i>ὥστε</i> μπαίνει συνήθως κόμμα. Η συσχέτιση μπορεί να επεκταθεί και σε <b>πλάγιες ερωτήσεις/προτάσεις</b> με δεικτικά (<i>τοσοῦτον ... ὅσον</i>), αλλά τότε δεν πρόκειται πια για αποτελεσματική.</p>","examples":[{"gr":"Εἰς τοσοῦτον ὕβρεως ἦλθον, ὥστε ἔπεισαν ὑμᾶς ἐλάσαι ἐκ τῆς πόλεως.","an":"Έφτασαν σε τέτοιο σημείο αλαζονείας, ώστε σας έπεισαν να (τον) διώξετε από την πόλη. — Δεικτικό ποσού <i>εἰς τοσοῦτον</i> + <i>ὥστε</i> + ΟΡΙΣΤΙΚΗ (<i>ἔπεισαν</i>): πραγματικό αποτέλεσμα παρά την παρουσία δεικτικού. (τύπου ρητόρων)"},{"gr":"Τοσαύτη φιλοτιμία ἐνῆν αὐτοῖς, ὥστε ... προθύμως κινδυνεύειν.","an":"Τόση φιλοδοξία υπήρχε μέσα τους, ώστε να αψηφούν πρόθυμα τον κίνδυνο. — <i>τοσαύτη (τοσοῦτος) ... ὥστε</i> + ΑΠΑΡΕΜΦΑΤΟ (<i>κινδυνεύειν</i>): φυσικό αποτέλεσμα της φιλοτιμίας. (τύπου Ἀττικῆς πεζογραφίας)"},{"gr":"Τοιοῦτός ἐστιν, ὥστε πάντας αὐτόν θαυμάζειν.","an":"Είναι τέτοιος, ώστε όλοι να τον θαυμάζουν. — <i>τοιοῦτος ... ὥστε</i> (ποιότητα) + ΑΠΑΡΕΜΦΑΤΟ (<i>θαυμάζειν</i>)."},{"gr":"Οὕτω σκαιός εἶ καί ἀναίσθητος, ὥστ' οὐ δύνασαι λογίσασθαι.","an":"Είσαι τόσο αδέξιος και αναίσθητος, ώστε δεν μπορείς να σκεφτείς. — <i>οὕτω ... ὥστε</i> + ΟΡΙΣΤΙΚΗ (<i>δύνασαι</i>), άρνηση <b>οὐ</b>: πραγματικό αποτέλεσμα. (Δημ., Περί στεφ. 120)"},{"gr":"Ἐπί τοσοῦτον δέ ἀφίκετο, ὥστε τύραννος γενέσθαι.","an":"Έφτασε σε τέτοιο σημείο, ώστε να γίνει τύραννος. — <i>ἐπί τοσοῦτον ... ὥστε</i> (όριο/βαθμός) + ΑΠΑΡΕΜΦΑΤΟ (<i>γενέσθαι</i>): φυσικό/ενδεχόμενο αποτέλεσμα. (τύπου ρητόρων)"},{"gr":"Τηλικοῦτος ἦν τό μέγεθος, ὥστε πάντας ἐκπλήττειν.","an":"Ήταν τόσο μεγάλος σε μέγεθος, ώστε να τους καταπλήσσει όλους. — Δεικτικό μεγέθους <i>τηλικοῦτος</i> + <i>ὥστε</i> + ΑΠΑΡΕΜΦΑΤΟ (<i>ἐκπλήττειν</i>): φυσικό αποτέλεσμα. (τύπου Ἀττικῆς πεζογραφίας)"}],"table":{"title":"Συσχετιστικά (δεικτικά) στην κύρια και η σημασία τους","cols":["Δεικτικό στην κύρια","Δηλώνει","Απόδοση","Τυπικό σχήμα"],"rows":[["οὕτω(ς)","τρόπο / βαθμό","τόσο, έτσι","οὕτω ... ὥστε"],["τοσοῦτος, -αύτη, -οῦτο","ποσό / μέγεθος","τόσος","τοσοῦτος ... ὥστε"],["τοιοῦτος, -αύτη, -οῦτο","ποιότητα","τέτοιος","τοιοῦτος ... ὥστε"],["τηλικοῦτος","ηλικία / μέγεθος","τόσο μεγάλος","τηλικοῦτος ... ὥστε"],["εἰς τοσοῦτο(ν), εἰς τοῦτο, μέχρι τούτου","όριο / βαθμό","σε τέτοιο σημείο","εἰς τοσοῦτον ... ὥστε"]]},"note":"Μην μπερδεύεις το αποτελεσματικό σχήμα «τοσοῦτος ... ὥστε» με το συγκριτικό-αναλογικό «τοσοῦτος ... ὅσος / ὅσῳ ... τοσούτῳ» (= «όσο ... τόσο»). Το δεύτερο εισάγει αναφορική/παραβολική πρόταση, ΟΧΙ αποτελεσματική."},{"h":"Διάκριση αποτελεσματικών από τελικές (και από αιτιολογικές)","body":"<p>Η μεγαλύτερη δυσκολία είναι η διάκριση <b>αποτελέσματος</b> από <b>σκοπό</b>, επειδή το <i>ὥστε</i> + απαρέμφατο μπορεί να εκφράσει «επιδιωκόμενο αποτέλεσμα» που εννοιολογικά πλησιάζει τις τελικές προτάσεις.</p><h3>Βασική εννοιολογική διαφορά</h3><ul><li><b>Τελικές</b> (<i>ἵνα, ὅπως, ὡς</i>): δηλώνουν τον <b>σκοπό</b> — αυτό που <i>επιδιώκει</i> το υποκείμενο, ανεξάρτητα από το αν θα επιτευχθεί. Είναι στραμμένες στο <b>μέλλον / στην πρόθεση</b>.</li><li><b>Αποτελεσματικές</b> (<i>ὥστε, ὡς</i>): δηλώνουν το <b>αποτέλεσμα</b> — αυτό που <i>προκύπτει</i> από την ενέργεια, είτε ως πραγματικό γεγονός είτε ως φυσική απόρροια.</li></ul><h3>Μορφολογικά κριτήρια (αλάνθαστα)</h3><ol><li><b>Σύνδεσμος</b>: <i>ἵνα / ὅπως</i> ⇒ ποτέ αποτελεσματική. <i>ὥστε</i> ⇒ ποτέ τελική. (Μόνο το <i>ὡς</i> είναι κοινό και στις δύο, οπότε εκεί κρίνει το νόημα.)</li><li><b>Δεικτικό βαθμού</b> (<i>οὕτω, τοσοῦτος, τοιοῦτος</i>) στην κύρια ⇒ σχεδόν βέβαιη αποτελεσματική.</li><li><b>Έγκλιση εκφοράς</b>: οι τελικές εκφέρονται με <b>υποτακτική</b> (μετά αρκτικό χρόνο) ή <b>ευκτική του πλαγίου λόγου</b> (μετά ιστορικό)· οι αποτελεσματικές με <b>οριστική / απαρέμφατο</b> (και δυνητικές εγκλίσεις). Η οριστική ή το απαρέμφατο αποκλείουν τελική.</li><li><b>Άρνηση</b>: τελικές ⇒ <b>μή</b>· αποτελεσματικές ⇒ <b>οὐ</b> (με έγκλιση) ή <b>μή</b> (με απαρέμφατο). Άρα «<i>ὥστε ... οὐ</i>» αποκλείει τελική.</li></ol><h3>Όταν το νόημα παραμένει διφορούμενο</h3><p>Σε <i>ὥστε</i> + απαρέμφατο μετά από ρήμα προσπάθειας (<i>πράττω, παρασκευάζομαι, ποιῶ</i>) η απόχρωση είναι «επιδιωκόμενο αποτέλεσμα» — κρατάμε τον χαρακτηρισμό <b>αποτελεσματική</b> (λόγω του <i>ὥστε</i>), σημειώνοντας τη χροιά σκοπού.</p><h3>Διάκριση και από τις αιτιολογικές</h3><p>Η αποτελεσματική δίνει τη <b>συνέπεια</b>, η αιτιολογική (<i>ὅτι, διότι, ἐπεί, ὡς</i>) δίνει την <b>αιτία</b>. Σχέση αντίστροφη: στο «έβρεξε, ώστε πλημμύρισε» η βροχή είναι αιτία και η πλημμύρα αποτέλεσμα (αποτελεσματική)· στο «πλημμύρισε, επειδή έβρεξε» η βροχή τίθεται ως αιτία (αιτιολογική).</p>","examples":[{"gr":"ΤΕΛΙΚΗ: Ἐλάμβανε μισθόν, ἵνα μή ἐνδεής εἴη.","an":"Έπαιρνε μισθό, για να μην είναι σε ένδεια. — Σύνδεσμος <i>ἵνα</i>, ευκτική πλαγίου λόγου (<i>εἴη</i>) μετά ιστορικό χρόνο, άρνηση <b>μή</b> = ΣΚΟΠΟΣ (τελική)."},{"gr":"ΑΠΟΤΕΛΕΣΜΑΤΙΚΗ: Τοσοῦτον μισθόν ἐλάμβανεν, ὥστε οὐκ ἐνδεής ἦν.","an":"Έπαιρνε τόσο μισθό, ώστε δεν ήταν σε ένδεια. — Δεικτικό <i>τοσοῦτον</i> + <i>ὥστε</i> + οριστική (<i>ἦν</i>), άρνηση <b>οὐκ</b> = ΑΠΟΤΕΛΕΣΜΑ (πραγματικό)."},{"gr":"ΟΡΙΑΚΗ (χροιά σκοπού): Κραυγήν πολλήν ἐποίουν καλοῦντες ἀλλήλους, ὥστε καί τούς πολεμίους ἀκούειν.","an":"Έκαναν μεγάλη κραυγή καλώντας ο ένας τον άλλον, ώστε να ακούν και οι εχθροί. — <i>ὥστε</i> + απαρέμφατο: ΑΠΟΤΕΛΕΣΜΑΤΙΚΗ με χροιά σκοπού (επιδιωκόμενο αποτέλεσμα). Αν ο συγγραφέας έγραφε <i>ἵνα ... ἀκούωσι</i>, θα ήταν καθαρά τελική. (Ξεν. Ἀνάβ. 2.2.17)"},{"gr":"ΤΕΛΙΚΗ: Ταῦτα δ' ἐποίει, ὅπως οἱ στρατιῶται μή ἀθυμοῖεν.","an":"Αυτά τα έκανε, για να μην αποθαρρύνονται οι στρατιώτες. — Σύνδεσμος <i>ὅπως</i> + ευκτική πλαγίου λόγου (<i>ἀθυμοῖεν</i>) μετά ιστορικό χρόνο· άρνηση <b>μή</b> = ΣΚΟΠΟΣ. Αντιπαράθεση προς το <i>ὥστε</i> + οριστική της προηγούμενης. (τύπου Ξενοφῶντος)"}],"table":{"title":"Συγκριτικός πίνακας: Τελικές vs Αποτελεσματικές","cols":["Κριτήριο","ΤΕΛΙΚΕΣ (σκοπός)","ΑΠΟΤΕΛΕΣΜΑΤΙΚΕΣ (αποτέλεσμα)"],"rows":[["Εισαγωγή","ἵνα, ὅπως, ὡς","ὥστε, ὡς (+ ἐφ' ᾧ / ἐφ' ᾧτε)"],["Σημασία","επιδίωξη / πρόθεση (μέλλον)","συνέπεια / πόρισμα (πραγματικό ή φυσικό)"],["Εκφορά","υποτακτική· ευκτική πλαγίου λόγου","οριστική / δυνητικές / ευκτ. πλαγ. / απαρέμφατο"],["Άρνηση","πάντοτε μή","οὐ (έγκλιση) ή μή (απαρέμφατο)"],["Δεικτικό βαθμού στην κύρια","όχι","συχνά (οὕτω, τοσοῦτος, τοιοῦτος)"],["Λειτουργία","επιρρ. προσδ. του σκοπού","επιρρ. προσδ. του αποτελέσματος / όρου"]]},"note":"Μνημονικός κανόνας: «ἵνα/ὅπως = σκοπός, ὥστε = αποτέλεσμα· υποτακτική = σκοπός, οριστική/απαρέμφατο = αποτέλεσμα». Μοναδική γκρίζα ζώνη το κοινό <i>ὡς</i> και το <i>ὥστε</i> + απαρέμφατο με χροιά σκοπού — εκεί αποφασίζει το νόημα, αλλά ο χαρακτηρισμός ακολουθεί τον σύνδεσμο."}]);
  T("syn-ypothetikes", [{"h":"Τι είναι ο υποθετικός λόγος — υπόθεση και απόδοση","body":"<p><b>Υποθετικός λόγος</b> ονομάζεται το λογικό σύνολο που αποτελείται από δύο προτάσεις οι οποίες συνδέονται μεταξύ τους με σχέση <b>αιτίου και αιτιατού</b> (προϋπόθεσης και συμπεράσματος). Δεν πρόκειται απλώς για μια δευτερεύουσα πρόταση, αλλά για ένα <i>ζεύγος</i> προτάσεων που το ένα μέλος εξαρτά τη λογική του ισχύ από το άλλο.</p><h3>Τα δύο μέλη</h3><ul><li><b>Υπόθεση</b> (ή <i>ηγούμενον</i>): η δευτερεύουσα <b>υποθετική πρόταση</b>, που εισάγεται με τους υποθετικούς συνδέσμους <b>εἰ</b> ή <b>ἐάν / ἄν / ἤν</b> και διατυπώνει την προϋπόθεση/τον όρο.</li><li><b>Απόδοση</b> (ή <i>επόμενον / συμπέρασμα</i>): η <b>κύρια πρόταση</b>, που διατυπώνει το συμπέρασμα, δηλαδή ό,τι ισχύει ή θα ίσχυε αν αληθεύει η υπόθεση.</li></ul><p>Η σχέση τους είναι: «<i>αν ισχύει το Α (υπόθεση), τότε ισχύει το Β (απόδοση)</i>». Το νόημα ολόκληρου του υποθετικού λόγου το καθορίζει <b>όχι μόνο η υπόθεση αλλά ο συνδυασμός υπόθεσης + απόδοσης</b>: γι' αυτό, για να χαρακτηρίσουμε το είδος, εξετάζουμε <b>πάντοτε και τα δύο μέλη μαζί</b> (την έγκλιση και τον χρόνο της υπόθεσης ΚΑΙ της απόδοσης).</p><h3>Μεθοδολογία αναγνώρισης</h3><p>Για να βρούμε το είδος ενός υποθετικού λόγου ακολουθούμε τρία βήματα:</p><ol><li>Εντοπίζουμε την <b>υπόθεση</b> (τη δευτερεύουσα με εἰ/ἐάν) και την <b>απόδοση</b> (την κύρια).</li><li>Σημειώνουμε την <b>έγκλιση και τον χρόνο</b> καθενός μέλους.</li><li>Αντιστοιχίζουμε τον συνδυασμό στο σχήμα ενός από τα <b>έξι είδη</b>.</li></ol><p>Καθοριστικός δείκτης είναι ο <b>σύνδεσμος εισαγωγής</b>: το <b>εἰ</b> συντάσσεται με <i>οριστική</i> ή <i>ευκτική</i> (είδη 1, 2, 5, 6), ενώ το <b>ἐάν/ἄν/ἤν</b> (= εἰ + ἄν) συντάσσεται <i>αποκλειστικά με υποτακτική</i> (είδη 3, 4).</p>","examples":[{"gr":"Εἰ θεοί τι δρῶσιν αἰσχρόν, οὐκ εἰσίν θεοί.","an":"Αν οι θεοί κάνουν κάτι αισχρό, δεν είναι θεοί. — Υπόθεση: «εἰ … δρῶσιν» (εδώ οριστική/υποτακτική κατά τις εκδόσεις)· απόδοση: «οὐκ εἰσίν θεοί». Φαίνεται καθαρά η λογική σχέση όρου–συμπεράσματος."},{"gr":"Εἰ βούλει, μένε.","an":"Αν θέλεις, μείνε. — Υπόθεση «εἰ βούλει» (εἰ + οριστική ενεστώτα), απόδοση «μένε» (προστακτική). Παράδειγμα 1ου είδους με απόδοση σε προστακτική."},{"gr":"Εἰ ἡσυχίαν Φίλιππος ἄγει, οὐκέτι δεῖ λέγειν.","an":"Δημ. Περί τῶν ἐν Χερρονήσῳ 8.5 — «Αν ο Φίλιππος μένει ήσυχος, δεν χρειάζεται πια να μιλάμε». Υπόθεση «εἰ … ἄγει» (εἰ + οριστ. ενεστ.), απόδοση «οὐκέτι δεῖ λέγειν»: καθαρά διακριτά τα δύο μέλη του λόγου."},{"gr":"Εἰ μή πατήρ ἦσθα, εἶπον ἄν σε οὐκ εὖ φρονεῖν.","an":"Σοφ. Ἀντιγόνη 755 — «Αν δεν ήσουν πατέρας, θα έλεγα πως δεν σκέφτεσαι σωστά». Υπόθεση «εἰ μή … ἦσθα» (εἰ + παρατατικός), απόδοση «εἶπον ἄν» (δυνητική οριστική): ζεύγος υπόθεσης–απόδοσης με αντίθετη-του-πραγματικού σχέση."}],"note":"Άρνηση: στην υπόθεση χρησιμοποιείται κατά κανόνα το «μή» (εἰ μή, ἐάν μή = «εκτός αν»)· στην απόδοση η άρνηση ακολουθεί την έγκλισή της (συνήθως «οὐ» στην οριστική, «μή» στην προστακτική/βουλητική)."},{"h":"Οι σύνδεσμοι, το ἄν και οι αρνήσεις","body":"<p>Πριν περάσουμε στα έξι είδη, χρειάζεται να ξεκαθαρίσουμε τα <b>τυπικά εργαλεία</b> του υποθετικού λόγου, γιατί από αυτά εξαρτάται η σωστή αναγνώριση.</p><h3>Οι υποθετικοί σύνδεσμοι</h3><ul><li><b>εἰ</b>: ο βασικός υποθετικός σύνδεσμος· συντάσσεται με <b>οριστική</b> (είδη 1, 2) και με <b>ευκτική</b> (είδη 5, 6).</li><li><b>ἐάν, ἄν, ἤν</b>: προκύπτουν από τη συγχώνευση <b>εἰ + ἄν</b> και συντάσσονται <b>μόνο με υποτακτική</b> (είδη 3, 4). Προσοχή να μη συγχέεται αυτό το <i>υποθετικό</i> ἄν με το δυνητικό ἄν της απόδοσης.</li></ul><h3>Το ἄν — δύο διαφορετικά «ἄν»</h3><p>Στον υποθετικό λόγο συναντούμε το μόριο <b>ἄν</b> με δύο εντελώς διαφορετικούς ρόλους:</p><ul><li><b>Υποθετικό/αοριστολογικό ἄν</b>: ενσωματωμένο στον σύνδεσμο (ἐάν, ἄν, ἤν) μαζί με υποτακτική, στην <i>υπόθεση</i>.</li><li><b>Δυνητικό ἄν</b>: συνοδεύει την έγκλιση της <i>απόδοσης</i> για να σχηματίσει <b>δυνητική οριστική</b> (2ο είδος) ή <b>δυνητική ευκτική</b> (5ο είδος).</li></ul><h3>Πότε παραλείπεται το δυνητικό ἄν της απόδοσης</h3><p>Στο 2ο είδος (αντίθετο του πραγματικού), η δυνητική απόδοση κανονικά έχει ἄν. Όμως το <b>ἄν παραλείπεται</b> όταν η απόδοση εκφέρεται με:</p><ul><li>παρατατικό <b>απρόσωπων ρημάτων ή εκφράσεων</b> δυνατότητας/αναγκαιότητας/καθήκοντος: <b>ἔδει, ἐχρῆν/χρῆν, ἐξῆν, προσῆκε, εἰκός ἦν, καλόν ἦν, δίκαιον ἦν</b> κ.τ.ό.·</li><li><b>ρηματικό επίθετο σε –τέος + ἦν</b> (π.χ. ποιητέον ἦν).</li></ul><p>Σε αυτές τις περιπτώσεις η <i>ίδια η σημασία</i> του ρήματος (= «έπρεπε / μπορούσε / ταίριαζε, αλλά δεν έγινε») φέρει το αντίθετο-του-πραγματικού νόημα, οπότε το ἄν περιττεύει.</p>","examples":[{"gr":"Εἰ ἐπεπόνθεσαν τοῦτο, ἔδει αὐτούς ὀργίζεσθαι.","an":"Αν είχαν πάθει αυτό, θα έπρεπε να οργίζονται. — Αντίθετο του πραγματικού· η απόδοση «ἔδει … ὀργίζεσθαι» (παρατατικός απρόσωπου + απαρέμφατο) είναι δυνητική στη σημασία της χωρίς δυνητικό ἄν."},{"gr":"Ἐάν ζητῇς καλῶς, εὑρήσεις.","an":"Αν ψάξεις σωστά, θα βρεις. — Το «ἐάν» (= εἰ + ἄν) + υποτακτική «ζητῇς» δείχνει υποθετικό ἄν στην υπόθεση· η απόδοση «εὑρήσεις» (οριστ. μέλλοντα) δεν παίρνει δυνητικό ἄν."},{"gr":"Εἰ ἐβουλόμην χρήματα λαμβάνειν, ἐξῆν ἄν μοι πλουτεῖν.","an":"(τύπου Λυσιανικού) — «Αν ήθελα να παίρνω χρήματα, θα μου ήταν δυνατόν να πλουτώ». Με «ἐξῆν» (παρατατικός απρόσωπου) το ἄν μπορεί και να παραλειφθεί· εδώ διατηρείται για έμφαση. Δείχνει το αντίθετο-του-πραγματικού νόημα του απρόσωπου παρατατικού."},{"gr":"Εἰ μή πατήρ ἦσθα, εἶπον ἄν σε οὐκ εὖ φρονεῖν.","an":"Σοφ. Ἀντιγόνη 755 — Η απόδοση «εἶπον ἄν» έχει το <b>δυνητικό ἄν</b> (οριστ. ιστ. χρόνου + ἄν), αντιπαρατιθέμενο προς το υποθετικό ἄν του ἐάν: τυπικό δείγμα δυνητικής οριστικής στην απόδοση."}],"table":{"title":"Σύνδεσμοι, εγκλίσεις και αρνήσεις","cols":["Σύνδεσμος","Έγκλιση υπόθεσης","Είδη όπου εμφανίζεται","Άρνηση υπόθεσης"],"rows":[["εἰ","οριστική","1ο (πραγματικό), 2ο (αντίθετο)","μή"],["εἰ","ευκτική","5ο (απλή σκέψη), 6ο (επανάληψη παρελθόν)","μή"],["ἐάν / ἄν / ἤν","υποτακτική","3ο (προσδοκώμενο), 4ο (επανάληψη παρόν-μέλλον)","μή (ἐάν μή)"]]},"note":"Το «εἰ μή» σημαίνει «εκτός αν / παρά μόνο αν»· το «εἰ δέ μή» μετά από καταφατική πρόταση σημαίνει «ειδάλλως, διαφορετικά»."},{"h":"1ο είδος — Το πραγματικό","body":"<p>Το <b>πραγματικό</b> (ή <i>της πραγματικότητας</i>) παρουσιάζει την υπόθεση ως κάτι που ο ομιλητής θεωρεί <b>πραγματικό, αληθινό ή τουλάχιστον δεδομένο</b>, χωρίς να τοποθετείται για το αν τελικά συμβαίνει· απλώς δηλώνει: «αν ισχύει το Α — και θεωρώ ότι ισχύει — τότε ισχύει το Β». Είναι το πιο «ουδέτερο» και πιο συχνό είδος.</p><h3>Σχήμα</h3><ul><li><b>Υπόθεση</b>: <b>εἰ + οριστική</b> οποιουδήποτε χρόνου.</li><li><b>Απόδοση</b>: <b>οποιαδήποτε έγκλιση</b> (οριστική, προστακτική, δυνητική, ευχετική κ.λπ.), ανάλογα με το τι θέλει να δηλώσει ο ομιλητής.</li></ul><p>Καθοριστικό γνώρισμα είναι ότι η υπόθεση έχει <b>εἰ + οριστική</b> (όχι ευκτική, όχι υποτακτική). Αναφορά μπορεί να γίνεται σε παρόν, παρελθόν ή μέλλον — αυτό που μετράει είναι ότι ο όρος προβάλλεται ως <i>πραγματικός</i>.</p><p>Άρνηση υπόθεσης: <b>μή</b>· άρνηση απόδοσης: συνήθως <b>οὐ</b>.</p>","examples":[{"gr":"Εἰ εἰσί βωμοί, εἰσί καί θεοί.","an":"Αν υπάρχουν βωμοί, υπάρχουν και θεοί. — Υπόθεση «εἰ εἰσί» (εἰ + οριστ. ενεστ.), απόδοση «εἰσί καί θεοί» (οριστ. ενεστ.). Κλασικό πραγματικό: ο ομιλητής θεωρεί την ύπαρξη βωμών δεδομένη."},{"gr":"Εἰ ταῦτα λέγεις, ἁμαρτάνεις.","an":"Αν λες αυτά, σφάλλεις. — εἰ + οριστική ενεστώτα στην υπόθεση, οριστική ενεστώτα στην απόδοση· δηλώνει πραγματική, παρούσα κατάσταση."},{"gr":"Εἰ τοῦτο ἐποίησεν, ἥμαρτεν.","an":"Αν έκανε αυτό, έσφαλε. — Αναφορά στο παρελθόν: εἰ + οριστ. αορίστου / απόδοση οριστ. αορίστου. Παραμένει 1ο είδος, γιατί το κρίσιμο είναι το «εἰ + οριστική», όχι ο χρόνος."},{"gr":"Εἰ θεός ἐστιν ὁ νοῦς, εὖ ἄν ἔχοι.","an":"Αν ο νους είναι θεός, καλώς θα είχε. — Υπόθεση πραγματικού (εἰ + οριστ.) με απόδοση σε δυνητική ευκτική· δείχνει ότι η απόδοση μπορεί να έχει «οποιαδήποτε έγκλιση»."},{"gr":"Εἰ ἡσυχίαν Φίλιππος ἄγει, οὐκέτι δεῖ λέγειν.","an":"Δημ. Περί τῶν ἐν Χερρονήσῳ 8.5 — «Αν ο Φίλιππος μένει ήσυχος, δεν χρειάζεται πια να μιλάμε». εἰ + οριστ. ενεστ. «ἄγει» / οριστ. ενεστ. «δεῖ»: ο όρος προβάλλεται ως πραγματικός, παρόν."},{"gr":"Εἰ μέν εἰσιν ἀγαθοί, δικαίως ἄν τιμῷντο.","an":"(τύπου Ἰσοκρατικού) — «Αν είναι αγαθοί, δίκαια θα τιμώνταν». εἰ + οριστ. ενεστ. στην υπόθεση (πραγματικό), δυνητική ευκτική στην απόδοση: ξανά απόδοση «οποιασδήποτε έγκλισης» σε 1ο είδος."}],"note":"Μην μπερδεύετε το «εἰ + οριστική μέλλοντα» (που εκφράζει ισχυρό όρο/απειλή, π.χ. «εἰ μή παύσῃ, μετανοήσεις») με το προσδοκώμενο: εκεί η υπόθεση έχει οριστική, όχι υποτακτική, άρα παραμένει 1ο είδος."},{"h":"2ο είδος — Το αντίθετο του πραγματικού (μη πραγματικό)","body":"<p>Το <b>αντίθετο του πραγματικού</b> (ή <i>μη πραγματικό / της μη πραγματικότητας</i>) δηλώνει υπόθεση που <b>είναι αντίθετη προς την πραγματικότητα</b>: ο ομιλητής γνωρίζει ότι ο όρος <i>δεν</i> ισχύει (ή δεν ίσχυσε), και γι' αυτό ούτε το συμπέρασμα ισχύει. Είναι ο τύπος «αν ίσχυε το Α — που όμως δεν ισχύει — θα ίσχυε το Β».</p><h3>Σχήμα</h3><ul><li><b>Υπόθεση</b>: <b>εἰ + οριστική ιστορικού χρόνου</b> (παρατατικός, αόριστος, σπανιότερα υπερσυντέλικος).</li><li><b>Απόδοση</b>: <b>δυνητική οριστική</b> (= οριστική ιστορικού χρόνου + <b>ἄν</b>)· εναλλακτικά παρατατικός απρόσωπου ρήματος (ἔδει, ἐχρῆν, ἐξῆν…) + απαρέμφατο <i>χωρίς ἄν</i>.</li></ul><p>Διάκριση παρόντος/παρελθόντος μέσω χρόνου: <b>παρατατικός</b> και στα δύο μέλη ⇒ αντίθετο στο <i>παρόν</i>· <b>αόριστος</b> ⇒ αντίθετο στο <i>παρελθόν</i>.</p><p>Άρνηση υπόθεσης: <b>μή</b>· άρνηση απόδοσης: <b>οὐ</b>.</p>","examples":[{"gr":"Οὗτοι, εἰ ἦσαν ἄνδρες ἀγαθοί, οὐκ ἄν ποτε ταῦτα ἔπασχον.","an":"Αυτοί, αν ήταν γενναίοι, δεν θα πάθαιναν ποτέ αυτά. — Υπόθεση «εἰ ἦσαν» (εἰ + παρατατικός), απόδοση «οὐκ ἄν … ἔπασχον» (δυνητική οριστική παρατατικού). Αντίθετο στο παρόν: στην πραγματικότητα δεν είναι γενναίοι, γι' αυτό και τα παθαίνουν."},{"gr":"Εἰ μή ἐγώ ἐκέλευον, οὐκ ἄν ἐποίει Ἀγασίας.","an":"Αν δεν διέταζα εγώ, δεν θα το έκανε ο Αγασίας. — Στην πραγματικότητα διέταξα· άρα το έκανε. Παρατατικός + δυνητική οριστική παρατατικού = αντίθετο στο παρόν/διαρκές."},{"gr":"Εἰ ταῦτα ἐποίησας, ἥμαρτες ἄν.","an":"Αν είχες κάνει αυτά, θα είχες σφάλει. — εἰ + αόριστος / δυνητική οριστική αορίστου = αντίθετο στο παρελθόν (στην πραγματικότητα δεν τα έκανες)."},{"gr":"Εἰ ἐβούλετο δίκαιος εἶναι, ἐξῆν αὐτῷ τά δίκαια πράττειν.","an":"Αν ήθελε να είναι δίκαιος, του ήταν δυνατόν να πράττει τα δίκαια. — Απόδοση με παρατατικό απρόσωπου «ἐξῆν» + απαρέμφατο, χωρίς δυνητικό ἄν· εξακολουθεί να είναι 2ο είδος."},{"gr":"Εἰ μή πατήρ ἦσθα, εἶπον ἄν σε οὐκ εὖ φρονεῖν.","an":"Σοφ. Ἀντιγόνη 755 — «Αν δεν ήσουν πατέρας, θα έλεγα πως δεν σκέφτεσαι σωστά». εἰ + παρατατικός «ἦσθα» / δυνητική οριστική «εἶπον ἄν»: αντίθετο στο παρόν (στην πραγματικότητα είναι πατέρας)."},{"gr":"Οὐκ ἄν ἐπεχείρησα πράττειν ταῦτα, εἰ μή ἠναγκάσθην.","an":"(τύπου Δημοσθενικού) — «Δεν θα είχα επιχειρήσει να τα κάνω αυτά, αν δεν είχα αναγκαστεί». εἰ + αόριστος «ἠναγκάσθην» / δυνητική οριστική αορίστου «οὐκ ἄν ἐπεχείρησα»: αντίθετο στο παρελθόν."}],"note":"Ο παρακείμενος συγκαταλέγεται μόνο εν μέρει στους ιστορικούς χρόνους· γι' αυτό σπάνια εμφανίζεται στην υπόθεση του 2ου είδους. Οι κατεξοχήν ιστορικοί χρόνοι είναι παρατατικός, αόριστος, υπερσυντέλικος."},{"h":"3ο είδος — Το προσδοκώμενο","body":"<p>Το <b>προσδοκώμενο</b> (ή <i>της προσδοκίας / της αναμονής</i>) παρουσιάζει την υπόθεση ως κάτι που <b>αναμένεται να συμβεί στο μέλλον</b> με βεβαιότητα ή ισχυρή πιθανότητα. Η σκέψη είναι: «αν συμβεί το Α (και το περιμένω), τότε θα συμβεί το Β». Είναι ο τύπος των προβλέψεων, των υποσχέσεων, των απειλών και των όρων που τίθενται για το μέλλον.</p><h3>Σχήμα</h3><ul><li><b>Υπόθεση</b>: <b>ἐάν / ἄν / ἤν + υποτακτική</b> (ενεστώτα ή αορίστου).</li><li><b>Απόδοση</b>: <b>οριστική μέλλοντα</b> ή άλλη ισοδύναμη έκφραση μέλλοντος / μελλοντικής βούλησης (π.χ. προστακτική, μέλλοντας περιφραστικός, δυνητική με μελλοντική σημασία).</li></ul><p>Χαρακτηριστικός δείκτης: η <b>υποτακτική στην υπόθεση</b> (που προδίδει το ενσωματωμένο ἄν) σε συνδυασμό με τη <b>μελλοντική απόδοση</b>.</p><p>Άρνηση υπόθεσης: <b>μή</b> (ἐάν μή)· άρνηση απόδοσης: <b>οὐ</b>.</p>","examples":[{"gr":"Ἐάν θεός ἐθέλῃ, ἥξω παρά σέ αὔριον.","an":"Αν θέλει ο θεός, θα έρθω σ' εσένα αύριο. — Υπόθεση «ἐάν ἐθέλῃ» (ἐάν + υποτακτ. ενεστ.), απόδοση «ἥξω» (οριστ. μέλλοντα). Τυπικό προσδοκώμενο με αναφορά στο μέλλον. (Πρβλ. Πλάτ.: ἥξω παρά σέ αὔριον, ἐάν θεός ἐθέλῃ.)"},{"gr":"Ἐάν ζητῇς καλῶς, εὑρήσεις.","an":"Αν ψάξεις σωστά, θα βρεις. — ἐάν + υποτακτική / οριστική μέλλοντα: προσδοκώμενο αποτέλεσμα μιας μελλοντικής ενέργειας."},{"gr":"Ἤν δ' ἐγγύς ἔλθῃ τοῦ τέλους, οὐδείς φοβήσεται.","an":"Κι αν πλησιάσει στο τέλος, κανείς δεν θα φοβηθεί. — «ἤν» (= ἐάν) + υποτακτ. αορίστου / οριστ. μέλλοντα. Δείχνει ότι ἤν και ἄν είναι ισοδύναμα του ἐάν."},{"gr":"Ἄν μή καθέξῃς γλῶσσαν, ἔσται σοι κακά.","an":"Αν δεν συγκρατήσεις τη γλώσσα σου, θα έχεις συμφορές. — Αρνητική υπόθεση «ἄν μή … καθέξῃς» + μελλοντική απόδοση: προσδοκώμενο με χροιά απειλής/προειδοποίησης."},{"gr":"Ἐάν τις ταῦτα παραβαίνῃ, ζημίᾳ κολασθήσεται.","an":"(τύπου Λυσιανικού) — «Αν κάποιος παραβεί αυτά, θα τιμωρηθεί». ἐάν + υποτακτ. ενεστ. «παραβαίνῃ» / οριστ. μέλλοντα «κολασθήσεται»: προσδοκώμενος όρος που τίθεται για το μέλλον (νομικού τύπου διατύπωση)."},{"gr":"Ἐάν με ἀδικῇς, ἀμυνοῦμαι.","an":"(τύπου Δημοσθενικού) — «Αν με αδικήσεις, θα αμυνθώ». ἐάν + υποτακτ. «ἀδικῇς» / οριστ. μέλλοντα «ἀμυνοῦμαι»: τυπικό προσδοκώμενο με χροιά απειλής."}],"note":"Η διαφορά 3ου από 4ο είδος δεν βρίσκεται στην υπόθεση (και τα δύο: ἐάν + υποτακτική) αλλά στην ΑΠΟΔΟΣΗ: μέλλοντας ⇒ 3ο (προσδοκώμενο, εφάπαξ μελλοντικό γεγονός)· ενεστώτας/γνωμικός αόριστος ⇒ 4ο (αόριστη επανάληψη)."},{"h":"4ο είδος — Αόριστη επανάληψη στο παρόν και μέλλον","body":"<p>Η <b>αόριστη επανάληψη στο παρόν–μέλλον</b> δηλώνει μια υπόθεση που <b>επαναλαμβάνεται αόριστα</b> (κάθε φορά, οσάκις) στο παρόν ή/και το μέλλον, με ένα συμπέρασμα που ισχύει <b>ως γενικός κανόνας</b>. Η σκέψη είναι: «κάθε φορά / όποτε συμβαίνει το Α, (συνήθως / κατά κανόνα) συμβαίνει και το Β». Είναι ο τύπος των γνωμικών, των φυσικών νόμων και των γενικών αληθειών.</p><h3>Σχήμα</h3><ul><li><b>Υπόθεση</b>: <b>ἐάν / ἄν / ἤν + υποτακτική</b> (ίδια με το προσδοκώμενο).</li><li><b>Απόδοση</b>: <b>οριστική ενεστώτα</b> (γενική/διαρκής αλήθεια) ή <b>γνωμικός αόριστος</b> (αόριστος με σημασία γενικής αλήθειας).</li></ul><p>Το διακριτικό γνώρισμα είναι η <b>ενεστωτική/γνωμική απόδοση</b>, που μετατρέπει το «θα» του μέλλοντα σε «κατά κανόνα / συνήθως».</p><p>Άρνηση υπόθεσης: <b>μή</b>· άρνηση απόδοσης: <b>οὐ</b>.</p>","examples":[{"gr":"Ἐάν τις τόν ἥλιον ἀναιδῶς ἐγχειρῇ θεάσασθαι, τήν ὄψιν ἀφαιρεῖται.","an":"Αν (κάθε φορά που) κάποιος επιχειρεί αναιδώς να ατενίσει τον ήλιο, χάνει την όρασή του. — ἐάν + υποτακτ. / οριστ. ενεστ.: γενικός κανόνας που ισχύει πάντοτε."},{"gr":"Ἤν ἐγγύς ἔλθῃ θάνατος, οὐδείς βούλεται θνῄσκειν.","an":"Όποτε πλησιάζει ο θάνατος, κανείς δεν θέλει να πεθάνει. — Υποτακτική στην υπόθεση + οριστ. ενεστ. στην απόδοση: διαχρονική, επαναλαμβανόμενη αλήθεια."},{"gr":"Ἤν δέ τις τούτων τι παραβαίνῃ, ζημίαν αὐτοῖς ἐπέθεσαν.","an":"Κι αν κάποιος παραβεί κάτι απ' αυτά, του επιβάλλουν ποινή. — ἤν + υποτακτ. / γνωμικός αόριστος «ἐπέθεσαν» (= κατά κανόνα επιβάλλουν): επανάληψη με γνωμικό αόριστο."},{"gr":"Ὅταν σπεύδῃ τις αὐτός, χὠ θεός συνάπτεται.","an":"Όταν κάποιος σπεύδει ο ίδιος, και ο θεός βοηθάει. — Χρονικοϋποθετική (ὅταν + υποτακτ.) με ενεστωτική απόδοση· λειτουργεί ως αόριστη επανάληψη στο παρόν (γνωμικό)."},{"gr":"Ἐάν τις ἀδικῇ, δίκην δίδωσιν.","an":"(τύπου γνωμικού) — «Αν κάποιος αδικεί, τιμωρείται». ἐάν + υποτακτ. «ἀδικῇ» / οριστ. ενεστ. «δίδωσιν»: γενικός κανόνας με χροιά νόμου (επανάληψη παρόν–μέλλον)."},{"gr":"Ἐάν τις πολλά ἔχῃ χρήματα, πολλούς ἔχει φίλους.","an":"(τύπου γνωμικού) — «Αν κάποιος έχει πολλά χρήματα, έχει πολλούς φίλους». ἐάν + υποτακτ. / οριστ. ενεστ.: διαχρονική, επαναλαμβανόμενη παρατήρηση."}],"note":"Όταν η απόδοση είναι ΕΝΕΣΤΩΤΑΣ ⇒ 4ο είδος· όταν είναι ΜΕΛΛΟΝΤΑΣ ⇒ 3ο είδος. Ίδια υπόθεση, διαφορετική απόδοση, διαφορετικό είδος — γι' αυτό εξετάζουμε πάντα και τα δύο μέλη."},{"h":"5ο είδος — Η απλή σκέψη του λέγοντος","body":"<p>Η <b>απλή σκέψη (του λέγοντος)</b> παρουσιάζει την υπόθεση ως μια <b>απλή, υποκειμενική σκέψη ή ενδεχόμενο</b>, χωρίς ο ομιλητής να παίρνει θέση για το αν ισχύει στην πραγματικότητα. Είναι ο πιο «θεωρητικός», απαλός υποθετικός λόγος: «ας υποθέσουμε / αν τυχόν ίσχυε το Α, τότε (ενδεχομένως) θα ίσχυε το Β». Διαφέρει από το αντίθετο του πραγματικού, γιατί <i>δεν</i> προϋποθέτει ότι ο όρος είναι ψευδής — απλώς τον φέρνει ως σκέψη.</p><h3>Σχήμα</h3><ul><li><b>Υπόθεση</b>: <b>εἰ + ευκτική</b> (ενεστώτα ή αορίστου).</li><li><b>Απόδοση</b>: <b>δυνητική ευκτική</b> (ευκτική + <b>ἄν</b>)· εναλλακτικά οριστική αρκτικού χρόνου ή άλλη έκφραση δυνατότητας.</li></ul><p>Χαρακτηριστικός δείκτης: η <b>ευκτική στην υπόθεση</b> μαζί με <b>δυνητική ευκτική στην απόδοση</b> — το λεγόμενο «ζεύγος ευκτικών».</p><p>Άρνηση υπόθεσης: <b>μή</b>· άρνηση απόδοσης: <b>οὐ</b>.</p>","examples":[{"gr":"Εἰ οἱ πολῖται ὁμονοοῖεν, εὐδαίμων ἄν γίγνοιτο ἡ πόλις.","an":"Αν οι πολίτες ομονοούσαν, ευτυχισμένη θα γινόταν η πόλη. — Υπόθεση «εἰ ὁμονοοῖεν» (εἰ + ευκτ.), απόδοση «ἄν γίγνοιτο» (δυνητ. ευκτ.). Απλή σκέψη: το ενδεχόμενο τίθεται θεωρητικά."},{"gr":"Εἴ τις αὐτούς ξυνελών φαίη πεφυκέναι ἐπί τό ἄρχειν, ὀρθῶς ἄν εἴποι.","an":"Αν κάποιος συνοψίζοντας έλεγε ότι είναι από τη φύση τους φτιαγμένοι για να εξουσιάζουν, σωστά θα μιλούσε. — εἰ + ευκτ. «φαίη» / δυνητ. ευκτ. «ἄν εἴποι»: κλασικό 5ο είδος."},{"gr":"Εἰ μή καθαροί εἴημεν, οὐκ ἄν δύναιντο οἱ θεοί ἡμᾶς δέχεσθαι.","an":"Αν δεν ήμασταν καθαροί, δεν θα μπορούσαν οι θεοί να μας δεχτούν. — Αρνητική υπόθεση «εἰ μή … εἴημεν» (ευκτ.) + δυνητική ευκτική: απλή σκέψη με άρνηση."},{"gr":"Ὀκνοίην ἄν εἰς τά πλοῖα ἐμβαίνειν ἅ ἡμῖν δοίη.","an":"Ξεν. Ἀνάβ. (τύπου 1.3) — «Θα δίσταζα να επιβιβαστώ στα πλοία που τυχόν θα μας έδινε». Δυνητική ευκτική «ὀκνοίην ἄν» με ευκτική «δοίη» (ευκτική του πλαγίου/υποθετική): καθαρό «ζεύγος ευκτικών», απλή σκέψη."},{"gr":"Εἴ τις ἔροιτό με τί ἐστι δικαιοσύνη, οὐκ ἄν ῥᾳδίως ἀποκριναίμην.","an":"(τύπου Πλατωνικού) — «Αν κάποιος με ρωτούσε τι είναι η δικαιοσύνη, δεν θα απαντούσα εύκολα». εἰ + ευκτ. αορίστου «ἔροιτο» / δυνητ. ευκτ. «ἄν ἀποκριναίμην»: θεωρητικό ενδεχόμενο που προβάλλεται ως σκέψη."}],"note":"Λεπτή αλλά κρίσιμη διαφορά 5ου από 2ου: το 5ο έχει εἰ + ΕΥΚΤΙΚΗ (υπόθεση ως ουδέτερη σκέψη)· το 2ο έχει εἰ + ΟΡΙΣΤΙΚΗ ιστορικού χρόνου (υπόθεση γνωστά ψευδής). Επομένως η έγκλιση της υπόθεσης τα ξεχωρίζει."},{"h":"6ο είδος — Αόριστη επανάληψη στο παρελθόν","body":"<p>Η <b>αόριστη επανάληψη στο παρελθόν</b> δηλώνει υπόθεση που <b>επαναλαμβανόταν αόριστα στο παρελθόν</b> (κάθε φορά που…, οσάκις…), με συμπέρασμα που επίσης ίσχυε επαναλαμβανόμενα. Είναι το παρελθοντικό αντίστοιχο του 4ου είδους: «κάθε φορά που συνέβαινε το Α, (συνήθως) συνέβαινε και το Β».</p><h3>Σχήμα</h3><ul><li><b>Υπόθεση</b>: <b>εἰ + ευκτική</b> (η λεγόμενη <i>επαναληπτική ευκτική</i>).</li><li><b>Απόδοση</b>: <b>οριστική ιστορικού χρόνου</b> (κατεξοχήν παρατατικός, που δηλώνει τη διάρκεια/επανάληψη· ενίοτε γνωμικός/επαναληπτικός αόριστος).</li></ul><p>Η διαφορά από το 5ο είδος (που έχει επίσης εἰ + ευκτική στην υπόθεση) βρίσκεται στην <b>απόδοση</b>: εδώ <i>οριστική ιστορικού χρόνου</i> (πραγματικό, επαναλαμβανόμενο παρελθόν), ενώ στο 5ο <i>δυνητική ευκτική</i> (θεωρητικό ενδεχόμενο).</p><p>Άρνηση υπόθεσης: <b>μή</b>· άρνηση απόδοσης: <b>οὐ</b>.</p>","examples":[{"gr":"Εἴ τινα τῶν ἐχθρῶν λάβοιεν, ἀπέκτεινον.","an":"Κάθε φορά που έπιαναν κάποιον από τους εχθρούς, τον σκότωναν. — Υπόθεση «εἴ … λάβοιεν» (εἰ + επαναληπτ. ευκτ.), απόδοση «ἀπέκτεινον» (παρατατικός). Τυπική επανάληψη στο παρελθόν."},{"gr":"Εἰ δέ τις αὐτῷ δοκοίη βλακεύειν, ἔπαιεν ἄν.","an":"Κι αν του φαινόταν κάποιος ότι τεμπελιάζει, τον χτυπούσε. — εἰ + ευκτ. «δοκοίη» / απόδοση οριστ. ιστ. χρόνου «ἔπαιεν» (ενίοτε με δυνητικό ἄν επαναληπτικής σημασίας): επανάληψη στο παρελθόν."},{"gr":"Ὁπότε προσβλέψειέ τινας τῶν ἐν ταῖς τάξεσι, τοτέ μέν εἶπεν ἄν…","an":"Όποτε έριχνε το βλέμμα του σε κάποιους από τις τάξεις, άλλοτε έλεγε… — Χρονικοϋποθετική (ὁπότε + ευκτ.) με παρελθοντική επαναλαμβανόμενη απόδοση: ισοδυναμεί με 6ο είδος."},{"gr":"Εἴ πού τι ὁρῴη βρωτόν, διεδίδου.","an":"Ξεν. Ἀνάβ. 4.5.8 — «Όποτε έβλεπε κάπου κάτι φαγώσιμο, το μοίραζε» (ο Ξενοφῶν στους στρατιῶτες που ταλαιπωρούνταν από την πείνα). εἰ + επαναληπτ. ευκτ. «ὁρῴη» / παρατατικός «διεδίδου»: πρότυπο παράδειγμα 6ου είδους από αττικό πεζό."},{"gr":"Εἴ τις αὐτῷ δοκοίη τῶν πρός τοῦτο τεταγμένων βλακεύειν, ἐκόλαζεν.","an":"(τύπου Ξενοφώντειου) — «Αν του φαινόταν κάποιος από τους ταγμένους γι' αυτό ότι αμελεί, τον τιμωρούσε». εἰ + ευκτ. «δοκοίη» / παρατατικός «ἐκόλαζεν»: αόριστη επανάληψη συνήθειας στο παρελθόν."}],"table":{"title":"Συγκριτικός πίνακας: τα δύο «επαναλαμβανόμενα» και η σχέση με την ευκτική","cols":["Είδος","Υπόθεση","Απόδοση","Χρονική αναφορά"],"rows":[["4ο (επανάληψη παρόν-μέλλον)","ἐάν + υποτακτική","οριστ. ενεστώτα / γνωμικός αόριστος","παρόν–μέλλον"],["6ο (επανάληψη παρελθόν)","εἰ + ευκτική","οριστ. ιστορικού χρόνου (παρατατικός)","παρελθόν"],["5ο (απλή σκέψη)","εἰ + ευκτική","δυνητική ευκτική","θεωρητικό ενδεχόμενο"]]},"note":"Προσοχή: 5ο και 6ο μοιράζονται την υπόθεση (εἰ + ευκτική)· τα ξεχωρίζει αποκλειστικά η απόδοση (δυνητική ευκτική ⇒ 5ο, οριστική ιστορικού χρόνου ⇒ 6ο)."},{"h":"Συγκεντρωτικός πίνακας των έξι ειδών","body":"<p>Ο παρακάτω πίνακας συνοψίζει <b>και τα έξι είδη</b> με το πλήρες σχήμα τους. Είναι το βασικό εργαλείο αναγνώρισης: αφού εντοπίσουμε έγκλιση/χρόνο υπόθεσης και απόδοσης, βρίσκουμε τη γραμμή που ταιριάζει.</p><h3>Πρακτικοί κανόνες-κλειδιά</h3><ul><li><b>εἰ + οριστική</b> ⇒ 1ο (αρκτικός χρ. ή όποιος χρόνος) ή 2ο (ιστορικός χρ. + δυνητική απόδοση).</li><li><b>ἐάν/ἄν/ἤν + υποτακτική</b> ⇒ 3ο (απόδ. μέλλοντας) ή 4ο (απόδ. ενεστώτας/γνωμικός).</li><li><b>εἰ + ευκτική</b> ⇒ 5ο (απόδ. δυνητική ευκτική) ή 6ο (απόδ. οριστ. ιστορικού χρόνου).</li></ul><p>Δηλαδή: η <b>έγκλιση της υπόθεσης</b> περιορίζει σε δύο πιθανά είδη, και η <b>απόδοση</b> κρίνει οριστικά ανάμεσά τους.</p>","table":{"title":"Τα 6 είδη υποθετικών λόγων — πλήρες σχήμα","cols":["Είδος","Σημασία","Υπόθεση (έγκλιση/χρόνος)","Απόδοση (έγκλιση/χρόνος)","Παράδειγμα"],"rows":[["1ο","Πραγματικό","εἰ + οριστική (κάθε χρόνου)","οποιαδήποτε έγκλιση","Εἰ εἰσί βωμοί, εἰσί καί θεοί"],["2ο","Αντίθετο του πραγματικού","εἰ + οριστική ιστ. χρόνου","δυνητική οριστική (+ἄν) / ἔδει κ.λπ. + απαρ.","Εἰ ἦσαν ἀγαθοί, οὐκ ἄν ἔπασχον"],["3ο","Προσδοκώμενο","ἐάν/ἄν/ἤν + υποτακτική","οριστική μέλλοντα","Ἐάν ζητῇς, εὑρήσεις"],["4ο","Αόριστη επανάληψη παρόν–μέλλον","ἐάν/ἄν/ἤν + υποτακτική","οριστική ενεστώτα / γνωμικός αόριστος","Ἐάν τις ἐγχειρῇ…, ἀφαιρεῖται"],["5ο","Απλή σκέψη του λέγοντος","εἰ + ευκτική","δυνητική ευκτική (+ἄν)","Εἰ ὁμονοοῖεν, εὐδαίμων ἄν γίγνοιτο"],["6ο","Αόριστη επανάληψη παρελθόν","εἰ + ευκτική (επαναληπτική)","οριστική ιστορικού χρόνου","Εἴ τινα λάβοιεν, ἀπέκτεινον"]]},"note":"Μνημονικό: η ΟΡΙΣΤΙΚΗ στην υπόθεση δίνει 1ο/2ο, η ΥΠΟΤΑΚΤΙΚΗ δίνει 3ο/4ο, η ΕΥΚΤΙΚΗ δίνει 5ο/6ο. Μέσα σε κάθε ζεύγος, η απόδοση κάνει την τελική διάκριση."},{"h":"Εξαρτημένοι (πλάγιοι) υποθετικοί λόγοι","body":"<p>Όταν ένας υποθετικός λόγος μεταφέρεται σε <b>πλάγιο λόγο</b> (δηλαδή εξαρτάται από ρήμα λεκτικό, γνωστικό, δοξαστικό κ.λπ.), μετασχηματίζονται και τα δύο μέλη του. Μιλάμε τότε για <b>εξαρτημένο</b> ή <b>πλάγιο υποθετικό λόγο</b>.</p><h3>Πώς μετασχηματίζεται η ΑΠΟΔΟΣΗ</h3><p>Η απόδοση (κύρια πρόταση στον ευθύ λόγο) γίνεται, ανάλογα με το ρήμα εξάρτησης, ένα από τα μέσα του πλαγίου λόγου:</p><ul><li><b>ειδικό απαρέμφατο</b> (μετά από λεκτικά/δοξαστικά: φημί, νομίζω, οἴομαι…),</li><li><b>κατηγορηματική μετοχή</b> (μετά από οἶδα, ὁρῶ, ἀκούω, αἰσθάνομαι… σε αιτιατική),</li><li><b>ειδική πρόταση</b> (μετά από λέγω ὅτι/ὡς, δηλῶ ὅτι…).</li></ul><h3>Πώς μετασχηματίζεται η ΥΠΟΘΕΣΗ</h3><p>Η υπόθεση μπορεί:</p><ul><li>να <b>διατηρήσει τη μορφή της</b> (ιδίως μετά από αρκτικό χρόνο εξάρτησης), ή</li><li>μετά από <b>ιστορικό χρόνο εξάρτησης</b>, να τραπεί σε <b>εἰ + ευκτική του πλαγίου λόγου</b> (η υποτακτική του προσδοκώμενου/επανάληψης γίνεται ευκτική πλαγίου λόγου, και χάνεται το ἄν του ἐάν → ξαναγίνεται εἰ).</li></ul><p>Π.χ. ευθύς: <b>ἐάν ἔλθῃ</b> ⇒ μετά από ιστορικό χρόνο: <b>εἰ ἔλθοι</b> (ευκτική πλαγίου λόγου).</p>","examples":[{"gr":"Ευθύς: «Ἐάν ζητῇς, εὑρήσεις». → Πλάγιος: Εἶπεν ὅτι, εἰ ζητοίη, εὑρήσοι.","an":"Ευθύς: «Αν ψάχνεις, θα βρεις». → Πλάγιος (μετά από ιστορικό «εἶπεν»): Είπε ότι, αν έψαχνε, θα έβρισκε. — Η υπόθεση «ἐάν ζητῇς» (υποτακτ.) έγινε «εἰ ζητοίη» (ευκτ. πλαγ. λόγου)· η απόδοση «εὑρήσεις» έγινε «εὑρήσοι» (ευκτ. μέλλ. πλαγ. λόγου) μέσα σε ειδική πρόταση."},{"gr":"Εἰς ὑμᾶς εἰσελθών ἐλπίζω τῶν δικαίων τεύξεσθαι.","an":"Παρουσιαζόμενος μπροστά σας, ελπίζω να βρω το δίκιο μου. — Η μετοχική υπόθεση «εἰσελθών» = «ἐάν εἰσέλθω» (3ο είδος, προσδοκώμενο)· η απόδοση εκφέρεται με απαρέμφατο πλαγίου λόγου «τεύξεσθαι» (= θα τύχω), επειδή εξαρτάται από το «ἐλπίζω»."},{"gr":"Ενομιζε, εἰ ταῦτα πράξειεν, εὐδαίμων ἄν γενέσθαι.","an":"Νόμιζε ότι, αν έκανε αυτά, θα γινόταν ευτυχισμένος. — Υπόθεση 5ου είδους (εἰ + ευκτ. πλαγ. λόγου «πράξειεν») με απόδοση σε δυνητικό απαρέμφατο «ἄν γενέσθαι»: δείχνει διατήρηση του δυνητικού ἄν στο απαρέμφατο της απόδοσης."},{"gr":"Ἔλεγον ὅτι, εἰ μή βοηθήσειαν, ἁλώσοιτο ἡ πόλις.","an":"(τύπου Θουκυδίδειου) — «Έλεγαν ότι, αν δεν βοηθούσαν, θα έπεφτε η πόλη». Μετά από ιστορικό «ἔλεγον», η υπόθεση τράπηκε σε «εἰ + ευκτ. πλαγ. λόγου» («βοηθήσειαν»), η απόδοση σε ευκτ. μέλλ. πλαγ. λόγου «ἁλώσοιτο» σε ειδική πρόταση."}],"note":"Κανόνας μετατροπής εγκλίσεων στον πλάγιο μετά από ιστορικό χρόνο: οριστική → ίδια οριστική ή ευκτική πλαγ. λόγου· υποτακτική (ἐάν +) → ευκτική πλαγ. λόγου (εἰ +)· η δυνητική οριστική/ευκτική διατηρεί το ἄν της όταν γίνεται απαρέμφατο/μετοχή."},{"h":"Λανθάνοντες υποθετικοί λόγοι — η κρυμμένη υπόθεση","body":"<p>Συχνά η υπόθεση δεν εκφέρεται με ρητή υποθετική πρόταση (εἰ/ἐάν…) αλλά <b>«λανθάνει» (κρύβεται)</b> μέσα σε άλλη συντακτική δομή. Τότε έχουμε <b>λανθάνοντα υποθετικό λόγο</b>. Η κρυμμένη υπόθεση μπορεί να εντοπιστεί και να <b>αναλυθεί</b> σε πλήρη υποθετική πρόταση, αρκεί να βρούμε το είδος από την έγκλιση/χρόνο της <b>απόδοσης</b> (της κύριας).</p><h3>Πού κρύβεται η υπόθεση</h3><ul><li><b>Υποθετική μετοχή</b> (με άρνηση μή): το πιο συχνό· π.χ. «οἱ ἀδικοῦντες» = «εἰ/ἐάν τινες ἀδικῶσι».</li><li><b>Αναφορική υποθετική πρόταση</b> (αναφορική χωρίς ορισμένο προσδιοριζόμενο): «ὅς ἄν … » = «ἐάν τις …».</li><li><b>Χρονικοϋποθετική πρόταση</b> (ὅταν, ὁπόταν, ἐπάν, ἐπειδάν, ὁσάκις…): δηλώνει αόριστο χρόνο, άρα και όρο.</li><li><b>Εναντιωματική πρόταση/μετοχή</b> (εἰ καί, ἐάν καί, κἄν, οὐδ' εἰ…): «έστω κι αν / αν και».</li><li><b>Εμπρόθετος προσδιορισμός</b> (ἄνευ, μετά, ἐκ, ἀπό + γενική): «ἄνευ τούτων» = «εἰ μή ταῦτα εἴη/εἶχον».</li><li><b>Επίρρημα</b> (ἄλλως, οὕτως, ἀμαχεί, δικαίως, ἐκείνως, ταύτῃ): «ἄλλως» = «εἰ ἄλλως ἔχοι/πράξοι».</li></ul><h3>Πώς αναλύεται</h3><p>(1) Εντοπίζω πού κρύβεται η υπόθεση. (2) Βρίσκω το είδος από την <b>έγκλιση/χρόνο της απόδοσης</b> (δυνητική οριστική ⇒ 2ο, μέλλοντας ⇒ 3ο, ενεστώτας ⇒ 4ο, δυνητική ευκτική ⇒ 5ο, οριστ. ιστ. χρόνου ⇒ 6ο). (3) Ξαναγράφω σε πλήρη «εἰ/ἐάν + έγκλιση … απόδοση».</p>","examples":[{"gr":"Οὐκ ἄν ἦλθον δεῦρο, ὑμῶν μή κελευσάντων. → Εἰ μή ὑμεῖς ἐκελεύσατε, οὐκ ἄν ἦλθον δεῦρο.","an":"Δεν θα είχαν έρθει εδώ, αν δεν είχατε διατάξει εσείς. — Η υποθετική μετοχή «μή κελευσάντων» κρύβει την υπόθεση. Απόδοση «οὐκ ἄν ἦλθον» = δυνητική οριστική ⇒ 2ο είδος (αντίθετο του πραγματικού)."},{"gr":"Τῷ ἀνδρί ὅν ἄν ἕλησθε πείσομαι. → Τῷ ἀνδρί, ἐάν τινα ἕλησθε, πείσομαι.","an":"Θα υπακούσω στον άντρα, όποιον κι αν διαλέξετε. — Αναφορική υποθετική «ὅν ἄν ἕλησθε» (αναφορ. + ἄν + υποτακτ.). Απόδοση «πείσομαι» = μέλλοντας ⇒ 3ο είδος (προσδοκώμενο)."},{"gr":"Οἱ κολακεύοντες πιστευθέντες τούς πιστεύσαντας ἀδικοῦσιν. → Ἐάν οἱ κολακεύοντες πιστευθῶσι, τούς πιστεύσαντας ἀδικοῦσιν.","an":"Οι κόλακες, όταν τους εμπιστεύονται, αδικούν εκείνους που τους εμπιστεύτηκαν. — Υποθετική μετοχή «πιστευθέντες». Απόδοση «ἀδικοῦσιν» = οριστ. ενεστ. ⇒ 4ο είδος (αόριστη επανάληψη)."},{"gr":"Ἄνευ γάρ ἀρχόντων οὐδέν ἄν οὔτε καλόν οὔτε ἀγαθόν γένοιτο. → Εἰ μή εἶεν ἄρχοντες, οὐδέν ἄν γένοιτο.","an":"Χωρίς άρχοντες, τίποτε καλό ή αγαθό δεν θα μπορούσε να γίνει. — Εμπρόθετος «ἄνευ ἀρχόντων» κρύβει την υπόθεση. Απόδοση «ἄν γένοιτο» = δυνητική ευκτική ⇒ 5ο είδος (απλή σκέψη)."},{"gr":"Ὁποσάκις ἔλθοιεν, εὐμενῶς αὐτούς προσεδέχετο. → Εἰ ἔλθοιεν, εὐμενῶς αὐτούς προσεδέχετο.","an":"Όσες φορές έρχονταν, τους δεχόταν φιλικά. — Χρονικοϋποθετική «ὁποσάκις ἔλθοιεν» (ευκτ.). Απόδοση «προσεδέχετο» = οριστ. παρατατικού ⇒ 6ο είδος (επανάληψη στο παρελθόν)."},{"gr":"Οἱ ταῦτα ποιοῦντες δικαίως ἄν ἐπαινοῖντο. → Εἴ τινες ταῦτα ποιοῖεν, δικαίως ἄν ἐπαινοῖντο.","an":"(τύπου Ἰσοκρατικού) — «Όσοι κάνουν αυτά, δίκαια θα επαινούνταν». Επιθετική/υποθετική μετοχή «οἱ ποιοῦντες» κρύβει τον όρο. Απόδοση «ἄν ἐπαινοῖντο» = δυνητική ευκτική ⇒ 5ο είδος."}],"table":{"title":"Πού κρύβεται η υπόθεση — οδηγός αναγνώρισης","cols":["Φορέας κρυμμένης υπόθεσης","Δείκτης","Ανάλυση σε"],"rows":[["Υποθετική μετοχή","μετοχή + άρνηση μή","εἰ/ἐάν + ανάλογη έγκλιση"],["Αναφορική υποθετική πρόταση","ὅς/ὅστις (αόριστη) + έγκλιση","εἰ/ἐάν τις + έγκλιση"],["Χρονικοϋποθετική πρόταση","ὅταν, ὁπόταν, ἐπειδάν, ὁσάκις","ἐάν/εἰ + έγκλιση"],["Εναντιωματική","εἰ καί, ἐάν καί, κἄν, οὐδ' εἰ","«έστω κι αν» (υποθετικό-εναντιωματικό)"],["Εμπρόθετος προσδιορισμός","ἄνευ, μετά, ἐκ, ἀπό + γενική","εἰ (μή) + έγκλιση"],["Επίρρημα","ἄλλως, οὕτως, ἀμαχεί, δικαίως","εἰ + έγκλιση"]]},"note":"Το ΕΙΔΟΣ του λανθάνοντος υποθετικού λόγου το κρίνει ΠΑΝΤΑ η έγκλιση/χρόνος της ΑΠΟΔΟΣΗΣ (κύριας), όχι ο φορέας της κρυμμένης υπόθεσης. Η άρνηση «μή» στη μετοχή/αναφορική είναι το πιο αξιόπιστο σημάδι ότι κρύβεται όρος."},{"h":"Ελλειπτικοί και σύνθετοι υποθετικοί λόγοι","body":"<p>Δύο ακόμη ειδικές μορφές που συναντούμε συχνά στα κείμενα:</p><h3>Ελλειπτικοί υποθετικοί λόγοι</h3><p>Είναι οι υποθετικοί λόγοι στους οποίους <b>λείπει (παραλείπεται) ένα μέλος ή τμήμα μέλους</b>, που εύκολα εννοείται από τα συμφραζόμενα. Διακρίνονται:</p><ul><li><b>Έλλειψη ρήματος στην υπόθεση</b>: παγιωμένες εκφράσεις όπως <b>εἰ δέ μή</b> (= ειδάλλως), <b>εἰ μή</b> (= εκτός αν), <b>εἴ τι ἄλλο</b>, <b>ὥσπερ ἄν εἰ</b> (= σαν να), <b>εἴπερ τις (καί ἄλλος)</b>.</li><li><b>Έλλειψη ολόκληρης της απόδοσης</b>: π.χ. σε εκφράσεις απειλής ή σιωπηρού συμπεράσματος («εἰ μή παύσῃ —» με την απόδοση να υπονοείται).</li><li><b>Έλλειψη ολόκληρης της υπόθεσης</b>: όταν ο όρος υπονοείται από τα συμφραζόμενα και μένει μόνο η δυνητική απόδοση.</li></ul><h3>Σύνθετοι υποθετικοί λόγοι</h3><p>Όταν ένας υποθετικός λόγος αποτελείται από <b>περισσότερες από μία υποθέσεις ή/και αποδόσεις</b>:</p><ul><li><b>Πολλές υποθέσεις – μία απόδοση</b> (συνδεδεμένες με καί, ἤ, οὔτε…οὔτε).</li><li><b>Μία υπόθεση – πολλές αποδόσεις</b>.</li><li><b>Πολλές υποθέσεις – πολλές αποδόσεις</b>.</li></ul><p>Σε σύνθετο υποθετικό λόγο χαρακτηρίζουμε <b>κάθε ζεύγος υπόθεσης–απόδοσης χωριστά</b>, καθώς μπορεί να ανήκουν σε διαφορετικά είδη.</p>","examples":[{"gr":"Πειθώμεθα πάντες· εἰ δέ μή, ἀπολούμεθα.","an":"Ας υπακούσουμε όλοι· ειδάλλως, θα χαθούμε. — Ελλειπτικός: «εἰ δέ μή» = «αν όμως δεν (υπακούσουμε)», με παραλειπόμενο το ρήμα της υπόθεσης που εννοείται από την προηγούμενη πρόταση. Η πλήρης απόδοση είναι 3ο είδος (μέλλοντας)."},{"gr":"Φιλόσοφος εἶ, εἴπερ τις καί ἄλλος.","an":"Είσαι φιλόσοφος, αν υπάρχει και κανείς άλλος (= όσο κανείς άλλος). — Ελλειπτικός με παγιωμένη φράση «εἴπερ τις καί ἄλλος», όπου εννοείται «εἴπερ τις καί ἄλλος ἐστί φιλόσοφος»."},{"gr":"Εἰ μέν βούλεσθε εἰρήνην, εὖ ποιήσετε· εἰ δέ πόλεμον, σφαλήσεσθε.","an":"Αν θέλετε ειρήνη, θα πράξετε καλά· αν όμως πόλεμο, θα αποτύχετε. — Σύνθετος: δύο υποθέσεις («εἰ βούλεσθε εἰρήνην» / «εἰ δέ πόλεμον» με παράλειψη του «βούλεσθε») με δύο αποδόσεις, και τα δύο ζεύγη 1ου/3ου είδους (εἰ + οριστ. / μέλλοντας)."},{"gr":"Ἐάν μέν τις σωφρονῇ, εὐδαιμονεῖ· ἐάν δέ ὑβρίζῃ, κολάζεται.","an":"(τύπου γνωμικού) — «Αν κάποιος σωφρονεί, ευτυχεί· αν όμως αλαζονεύεται, τιμωρείται». Σύνθετος υποθετικός με δύο αντιθετικά ζεύγη υπόθεσης–απόδοσης (ἐάν + υποτακτ. / οριστ. ενεστ.), και τα δύο 4ου είδους· χαρακτηρίζονται χωριστά."}],"note":"Στο «ὥσπερ ἄν εἰ» (= ὡσανεί, σαν να) έχουμε ελλειπτική παρομοιωτική-υποθετική έκφραση: το δυνητικό ἄν ανήκει σε εννοούμενη απόδοση. Συχνά μεταφράζεται απλώς «σαν να»."}]);
  T("syn-xronikes", [{"h":"Τι είναι οι χρονικές προτάσεις — ορισμός και θέση στο σύστημα","body":"<p>Οι <b>χρονικές προτάσεις</b> είναι <b>δευτερεύουσες (εξαρτημένες) επιρρηματικές προτάσεις</b>. Ανήκουν, δηλαδή, στην ίδια μεγάλη οικογένεια με τις αιτιολογικές, τις τελικές, τις αποτελεσματικές, τις υποθετικές, τις εναντιωματικές/παραχωρητικές και τις αναφορικές: όλες προσδιορίζουν το ρήμα μιας άλλης πρότασης (της κύριας ή μιας προϊσταμένης) λειτουργώντας ως επιρρηματικά της.</p><p>Ειδικότερα, η χρονική πρόταση <b>δηλώνει τον χρόνο μέσα στον οποίο γίνεται ή σε σχέση με τον οποίο τοποθετείται η πράξη της προσδιοριζόμενης πρότασης</b>. Ισοδυναμεί συντακτικά με έναν <i>επιρρηματικό προσδιορισμό του χρόνου</i>· γι' αυτό και μπορεί κανείς, πρόχειρα, να την αντικαταστήσει με χρονικό επίρρημα ή εμπρόθετο: <i>ἐπεί ἐνίκησαν</i> ≈ <i>μετά τήν νίκην</i>.</p><h3>Πώς αναγνωρίζεται</h3><p>Η αναγνώριση μιας χρονικής πρότασης απαιτεί τρία βήματα, τα οποία θα μας απασχολήσουν σε όλη τη θεωρία:</p><ul><li><b>Εισαγωγή:</b> με ποιον χρονικό σύνδεσμο ή χρονικό επιρρηματικό εισάγεται.</li><li><b>Χρονική σχέση:</b> αν δηλώνει <i>σύγχρονο</i>, <i>προτερόχρονο</i> ή <i>υστερόχρονο</i> σε σχέση με την πράξη της κύριας.</li><li><b>Εκφορά:</b> με ποια έγκλιση (οριστική, υποτακτική + ἄν, ευκτική) εκφέρεται, και τι σημαίνει αυτή η έγκλιση (πραγματικό, προσδοκώμενο, αόριστη επανάληψη, πλάγιος λόγος).</li></ul><p><b>Συντακτικός ρόλος:</b> ολόκληρη η χρονική πρόταση λειτουργεί ως <b>επιρρηματικός προσδιορισμός του χρόνου</b> στο ρήμα της προσδιοριζόμενης πρότασης. Προσοχή: δεν εισάγει πλάγια ερώτηση και δεν είναι ονοματική — δεν λειτουργεί ποτέ ως υποκείμενο/αντικείμενο.</p>","examples":[{"gr":"Ἐπεί ἐτελεύτησε Δαρεῖος, κατέστη βασιλεύς Ἀρταξέρξης.","an":"Κύρια: «κατέστη βασιλεύς Ἀρταξέρξης». Δευτ. χρονική: «Ἐπεί ἐτελεύτησε Δαρεῖος», εισαγ. με χρον. ἐπεί, εκφορά με οριστική (πραγματικό), δηλώνει το <b>προτερόχρονο</b> (ο θάνατος προηγείται της ενθρόνισης). Λειτουργεί ως επιρρηματικός προσδιορισμός του χρόνου στο «κατέστη»."},{"gr":"Ὅτε ταῦτα ἤκουσαν οἱ στρατιῶται, ἐθορύβησαν.","an":"Χρονική «Ὅτε ταῦτα ἤκουσαν», εισαγ. με ὅτε, οριστική αορίστου, προτερόχρονο/σύγχρονο σε σχέση με το «ἐθορύβησαν»· ισοδυναμεί με «μετά τό ἀκοῦσαι ταῦτα»."},{"gr":"Ἐπεί ἐτελεύτησε Δαρεῖος, Τισσαφέρνης διαβάλλει τόν Κῦρον.","an":"Ξεν. Ἀνάβ. 1.1.3 — χρονική «Ἐπεί ἐτελεύτησε Δαρεῖος» (ἐπεί + οριστ. αορίστου), <b>προτερόχρονο</b>· επιρρ. προσδ. χρόνου στο «διαβάλλει». Δείχνει την τυπική θέση της χρονικής πριν την κύρια."},{"gr":"Ἐπειδή Κῦρος ἐκάλει, λαβών ὑμᾶς ἐπορευόμην.","an":"Ξεν. Ἀνάβ. 1.3.4 — χρονική «Ἐπειδή Κῦρος ἐκάλει» (ἐπειδή + οριστ. παρατατικού), δηλώνει χρόνο της πράξης· λειτουργεί ως επιρρ. προσδ. χρόνου στο «ἐπορευόμην», όχι ως ονοματική."}],"note":"Μη συγχέεις τη χρονική με την αναφορική-χρονική (π.χ. «τότε ὅτε…») ούτε με τη χρονική χρήση μετοχής. Η μετοχή («ταῦτα ἀκούσαντες») αποδίδει την ίδια χρονική σχέση χωρίς σύνδεσμο και ρήμα οριστικής — είναι ισοδύναμη έκφραση, όχι χρονική πρόταση."},{"h":"Εισαγωγή: οι χρονικοί σύνδεσμοι και τα χρονικά επιρρηματικά","body":"<p>Οι χρονικές προτάσεις εισάγονται με μεγάλη ποικιλία <b>χρονικών συνδέσμων</b> και <b>χρονικών επιρρηματικών εκφράσεων</b>. Είναι χρήσιμο να τους ομαδοποιήσουμε κατά τη χρονική σημασία τους, γιατί η σημασία του συνδέσμου προδικάζει συχνά και τη χρονική σχέση που δηλώνει η πρόταση.</p><h3>α) Σύνδεσμοι του «όταν / τη στιγμή που» (κυρίως σύγχρονο)</h3><ul><li><b>ὅτε, ὁπότε</b> = όταν, τότε που</li><li><b>ἡνίκα, ὁπηνίκα</b> = τη στιγμή ακριβώς που, μόλις</li><li><b>ὡς</b> = όταν, μόλις, αφού (πολυσήμαντος — και αιτιολογικός/παραβολικός/τελικός αλλού)</li><li><b>ἄμα</b> (συνήθως με μετοχή: ἄμα + μετοχή) = συγχρόνως που</li></ul><h3>β) Σύνδεσμοι του «αφού / αφότου» (κυρίως προτερόχρονο)</h3><ul><li><b>ἐπεί, ἐπειδή</b> = αφού, αφότου (χρον.) — αλλά και «επειδή» (αιτιολ.)· βλ. ξεχωριστή ενότητα.</li><li><b>ἐξ οὗ, ἀφ' οὗ, ἀφ' ὅτου</b> = από τότε που, αφότου</li></ul><h3>γ) Σύνδεσμοι του «έως ότου / μέχρι» (κυρίως υστερόχρονο — όριο)</h3><ul><li><b>ἕως, ἔστε</b> = ωσότου, όσο, μέχρι που</li><li><b>μέχρι, ἄχρι</b> (και <b>μέχρι οὗ, ἄχρι οὗ</b>) = μέχρι να, ωσότου</li><li><b>πρίν</b> = προτού, πριν (ιδιάζουσα σύνταξη — δική του ενότητα)</li></ul><h3>δ) Σύνδεσμοι με προσδοκία/επανάληψη (κράση με ἄν)</h3><p>Όταν ο σύνδεσμος συγχωνευθεί με το αοριστολογικό <b>ἄν</b>, προκύπτουν τύποι που <b>πάντοτε</b> εκφέρονται με υποτακτική: <b>ὅταν</b> (ὅτε+ἄν), <b>ὁπόταν</b> (ὁπότε+ἄν), <b>ἐπάν / ἐπήν</b> (ἐπεί+ἄν), <b>ἐπειδάν</b> (ἐπειδή+ἄν). Η ίδια η μορφή τους σου λέει ότι ακολουθεί υποτακτική.</p>","table":{"title":"Χρονικοί σύνδεσμοι κατά σημασία","cols":["Σύνδεσμος","Σημασία","Κύρια χρον. σχέση","Τύπος + ἄν"],"rows":[["ὅτε / ὁπότε","όταν, τότε που","σύγχρονο","ὅταν / ὁπόταν"],["ἡνίκα / ὁπηνίκα","τη στιγμή που, μόλις","σύγχρονο","ἡνίκ' ἄν"],["ὡς","όταν, μόλις, αφού","σύγχρ./προτερ.","ὡς ἄν"],["ἐπεί / ἐπειδή","αφού, αφότου","προτερόχρονο","ἐπάν(ἐπήν) / ἐπειδάν"],["ἐξ οὗ / ἀφ' οὗ","από τότε που","προτερόχρονο","—"],["ἕως / ἔστε","ωσότου, όσο","σύγχρ./υστερ.","ἕως ἄν / ἔστ' ἄν"],["μέχρι / ἄχρι (οὗ)","μέχρι, ωσότου","υστερόχρονο","μέχρι(ς) ἄν"],["πρίν","προτού, πριν","υστερ. (+ απαρ.) / προτερ. (+ έγκλ.)","πρίν ἄν"]]},"examples":[{"gr":"Ἐπειδάν διαπράξωμαι ἅ δέομαι, ἥξω.","an":"Εισαγ. με ἐπειδάν (= ἐπειδή + ἄν), άρα υποχρεωτικά υποτακτική «διαπράξωμαι». Δηλώνει <b>προσδοκώμενο</b> στο μέλλον· χρον. σχέση προτερόχρονο. Πβ. «μόλις διεκπεραιώσω…»."},{"gr":"Ἡνίκα ἦν δείλη, ἐφαίνοντο οἱ πολέμιοι.","an":"Εισαγ. ἡνίκα, οριστική παρατατικού (πραγματικό), <b>σύγχρονο</b>: «τη στιγμή που / όταν ήταν αργά το απόγευμα»."},{"gr":"Ἐξ οὗ Ἕλληνές εἰσιν, οὐ πώποτε τοιαῦτα ἐγένετο.","an":"Εισαγ. με ἐξ οὗ (= αφότου, από τότε που), αναφορικο-χρονικός δείκτης, οριστική· δηλώνει <b>αφετηρία στον χρόνο</b> (προτερόχρονο-διάρκεια). Πβ. «ἀφ' οὗ»."},{"gr":"Ὁπόταν τις μέλλῃ καλῶς ἄρχειν, δεῖ αὐτόν πρῶτον ἄρχεσθαι.","an":"Εισαγ. με ὁπόταν (= ὁπότε + ἄν), άρα υποτακτική «μέλλῃ»· η ίδια η μορφή του συνδέσμου επιβάλλει την υποτακτική. <b>Αόριστη επανάληψη</b> (γνωμικό): «κάθε φορά που…»."}],"note":"Πολλοί σύνδεσμοι είναι πολυλειτουργικοί: ὡς = χρονικός / αιτιολογικός / τελικός / παραβολικός / ειδικός / συμπερασματικός· ἕως / μέχρι / ἄχρι λειτουργούν και ως προθέσεις (+ γενική). Η αναγνώριση γίνεται πάντα από τα συμφραζόμενα, όχι μηχανικά."},{"h":"Οι τρεις χρονικές σχέσεις: σύγχρονο, προτερόχρονο, υστερόχρονο","body":"<p>Η ουσία της χρονικής πρότασης είναι η <b>χρονική σχέση</b> ανάμεσα στην πράξη της και στην πράξη της προσδιοριζόμενης (κύριας) πρότασης. Υπάρχουν τρεις δυνατότητες:</p><h3>1. Σύγχρονο (ταυτόχρονο)</h3><p>Οι δύο πράξεις γίνονται <b>συγχρόνως</b>. Διακρίνουμε:</p><ul><li><b>Σύγχρονο παράλληλης/συνεχούς διάρκειας</b> («όσο, ενόσω»): και οι δύο πράξεις εκτείνονται στον ίδιο χρόνο. Εισάγεται κυρίως με <b>ἕως, ἔστε, ὅσον χρόνον, ἐν ᾧ</b> και εκφέρεται συνήθως με <b>παρατατικό/ενεστώτα</b>.</li><li><b>Σύγχρονο στιγμιαίο / σημείου</b> («μόλις, τη στιγμή που»): η μία πράξη συμπίπτει με μια στιγμή της άλλης. Εισάγεται με <b>ὅτε, ὁπότε, ἡνίκα, ὡς</b>.</li></ul><h3>2. Προτερόχρονο</h3><p>Η πράξη της χρονικής πρότασης <b>προηγείται</b> εκείνης της κύριας («αφού, αφότου»). Φυσικοί φορείς της είναι το <b>ἐπεί, ἐπειδή, ὡς, ἀφ' οὗ, ἐξ οὗ</b>. Συχνά η χρονική εκφέρεται με <b>αόριστο</b> (στιγμιαία προγενέστερη πράξη) ή με παρακείμενο/υπερσυντέλικο.</p><h3>3. Υστερόχρονο</h3><p>Η πράξη της χρονικής πρότασης <b>έπεται</b> εκείνης της κύριας («προτού, ωσότου, μέχρι να»). Είναι η σχέση που δηλώνεται με <b>πρίν</b> (όταν συντάσσεται με απαρέμφατο) και με τα όρια <b>ἕως, ἔστε, μέχρι, ἄχρι</b> («ωσότου να γίνει κάτι»). Επειδή η δευτερεύουσα πράξη ανήκει στο μέλλον σε σχέση με την κύρια, έχει συχνά χροιά <b>προσδοκίας/σκοπού</b>.</p><p>Πρακτικός κανόνας: <i>η χρονική σχέση κρίνεται από τη σημασία του συνδέσμου και από τον χρόνο/έγκλιση του ρήματος μαζί</i> — όχι από έναν μόνο παράγοντα.</p>","table":{"title":"Σύνοψη των τριών σχέσεων","cols":["Σχέση","Σημασία","Τυπικοί σύνδεσμοι","Τυπική εκφορά"],"rows":[["Σύγχρονο διάρκειας","όσο, ενόσω","ἕως, ἔστε, ἐν ᾧ, ὅσον χρόνον","παρατατικός / ενεστώτας"],["Σύγχρονο στιγμής","όταν, μόλις","ὅτε, ὁπότε, ἡνίκα, ὡς","οριστική (αορ./παρατ.), υποτ.+ἄν"],["Προτερόχρονο","αφού, αφότου","ἐπεί, ἐπειδή, ὡς, ἀφ' οὗ","οριστική αορ./παρακ., υποτ.+ἄν"],["Υστερόχρονο","προτού, ωσότου","πρίν, ἕως, μέχρι, ἄχρι, ἔστε","απαρέμφατο (πρίν) / υποτ.+ἄν"]]},"examples":[{"gr":"Ἕως ἐστέ ἐν ἀσφαλεῖ, βουλεύεσθε.","an":"<b>Σύγχρονο διάρκειας</b>: «όσο βρίσκεστε σε ασφάλεια». Εισαγ. ἕως, οριστ. ενεστώτα — παράλληλη διάρκεια με το «βουλεύεσθε»."},{"gr":"Ὡς εἶδον τούς πολεμίους, ἔφυγον.","an":"<b>Προτερόχρονο/στιγμιαίο σύγχρονο</b>: «μόλις είδαν». Εισαγ. ὡς, οριστ. αορίστου· η όραση προηγείται ελάχιστα της φυγής."},{"gr":"Περιμένετε, ἔστ' ἄν ἔλθω.","an":"<b>Υστερόχρονο</b>: «ωσότου έρθω». Εισαγ. ἔστε + ἄν, υποτακτική — όριο/προσδοκία στο μέλλον."},{"gr":"Ἐν ᾧ ταῦτα ἐβουλεύοντο, ἧκον οἱ ἄγγελοι.","an":"<b>Σύγχρονο διάρκειας</b>: αναφορικο-χρον. «ἐν ᾧ (χρόνῳ)» + παρατατικός «ἐβουλεύοντο» = «ενόσω σχεδίαζαν αυτά»· η κύρια στιγμιαία πράξη («ἧκον») τοποθετείται μέσα στη διάρκεια."},{"gr":"Ἐπεί ἀφίκοντο εἰς τόν ποταμόν, ἐστρατοπεδεύσαντο.","an":"<b>Προτερόχρονο</b> (τύπου Ξεν. Ἀνάβ.): ἐπεί + οριστ. αορίστου «ἀφίκοντο»· η άφιξη προηγείται της στρατοπέδευσης — η συνηθέστερη αφηγηματική χρήση."}]},{"h":"Εκφορά (I): οριστική και υποτακτική + αοριστολογικό ἄν","body":"<p>Η <b>έγκλιση</b> (εκφορά) της χρονικής πρότασης δεν είναι διακοσμητική: δηλώνει τον <i>τρόπο με τον οποίο παρουσιάζεται η πράξη</i> — πραγματική, προσδοκώμενη, αόριστα επαναλαμβανόμενη ή μεταφερόμενη σε πλάγιο λόγο. Παράλληλη είναι εδώ η σύνταξη με τις υποθετικές προτάσεις.</p><h3>1. Οριστική — το πραγματικό</h3><p>Η <b>οριστική</b> (κάθε χρόνου) δηλώνει ότι η πράξη της χρονικής θεωρείται <b>πραγματικό γεγονός</b>. Είναι η πιο συνηθισμένη εκφορά για το παρελθόν: <i>ἐπεί + οριστική αορίστου</i> = «αφού πραγματικά έγινε». Εδώ ανήκει και η οριστική ιστορικού χρόνου που δηλώνει <b>μη πραγματικό (αντίθετο του πραγματικού)</b>, σπανιότερα, σε αναλογία προς τις υποθετικές.</p><h3>2. Υποτακτική + ἄν (αοριστολογικό) — το προσδοκώμενο και η αόριστη επανάληψη</h3><p>Όταν η πράξη ανήκει στο <b>μέλλον</b> ή είναι <b>αόριστα/συχνά επαναλαμβανόμενη στο παρόν</b>, η χρονική εκφέρεται με <b>υποτακτική συνοδευόμενη υποχρεωτικά από το αοριστολογικό ἄν</b>. Το ἄν δεν στέκει χωριστά: συγχωνεύεται με τον σύνδεσμο και δίνει τους τύπους:</p><ul><li><b>ὅταν</b> = ὅτε + ἄν, <b>ὁπόταν</b> = ὁπότε + ἄν</li><li><b>ἐπάν / ἐπήν</b> = ἐπεί + ἄν, <b>ἐπειδάν</b> = ἐπειδή + ἄν</li><li><b>ἕως ἄν, ἔστ' ἄν, μέχρι(ς) ἄν, πρίν ἄν</b> (όπου το ἄν μένει χωριστό)</li></ul><p>Δύο αξίες της υποτακτικής + ἄν:</p><ul><li><b>Προσδοκώμενο (μελλοντική αναφορά):</b> «όταν/μόλις/ωσότου γίνει» κάτι αναμενόμενο. Κύρια συνήθως σε μέλλοντα ή προστακτική.</li><li><b>Αόριστη επανάληψη στο παρόν/μέλλον:</b> «κάθε φορά που». Κύρια σε ενεστώτα γνωμικό.</li></ul>","table":{"title":"Οριστική vs υποτακτική+ἄν","cols":["Εκφορά","Σημασία","Αναφορά χρόνου","Παράδειγμα-τύπος"],"rows":[["Οριστική","πραγματικό γεγονός","συνήθως παρελθόν/παρόν","ἐπεί ἦλθεν"],["Οριστ. ιστ. χρόνου","μη πραγματικό (σπάνια)","παρελθόν","—"],["Υποτ. + ἄν","προσδοκώμενο","μέλλον","ὅταν ἔλθῃ"],["Υποτ. + ἄν","αόριστη επανάληψη","παρόν/μέλλον (γνωμικό)","ὅταν τις ἀδικῇ"]]},"examples":[{"gr":"Ἐπεί ἀφίκετο, ἔπεμψε τούς ἀγγέλους.","an":"Οριστική αορίστου «ἀφίκετο» = <b>πραγματικό</b> γεγονός του παρελθόντος· προτερόχρονο."},{"gr":"Ὅταν ταῦτα ἀκούσῃς, θαυμάσεις.","an":"ὅταν (ὅτε+ἄν) + υποτακτική «ἀκούσῃς» = <b>προσδοκώμενο</b> στο μέλλον· κύρια σε μέλλοντα «θαυμάσεις»."},{"gr":"Ὅταν τις ἀδικῇ, κολάζεται.","an":"ὅταν + υποτ. «ἀδικῇ», κύρια ενεστώτα γνωμικός «κολάζεται» = <b>αόριστη επανάληψη</b>: «κάθε φορά που αδικεί κανείς, τιμωρείται»."},{"gr":"Ἐπειδάν δέ διαπράξωμαι ἅ δέομαι, ἥξω.","an":"τύπου Ξεν. Ἀνάβ. — ἐπειδάν (ἐπειδή+ἄν) + υποτακτική «διαπράξωμαι», κύρια σε μέλλοντα «ἥξω» = <b>προσδοκώμενο</b>· η μορφή ἐπειδάν επιβάλλει την υποτακτική."},{"gr":"Ὅταν σπεύδῃ τις αὐτός, χὠ θεός συνάπτεται.","an":"Αἰσχ. Πέρσ. 742 (παροιμιώδες) — ὅταν + υποτ. «σπεύδῃ», κύρια ενεστώτα γνωμικός «συνάπτεται» = <b>αόριστη επανάληψη / γνωμική αλήθεια</b>: «όταν σπεύδει κανείς ο ίδιος, συμπράττει και ο θεός»."}],"note":"Ταράζει τους μαθητές το ότι το ἄν εδώ είναι <b>αοριστολογικό</b> (της χρονικής/υποθετικής), όχι δυνητικό. Γι' αυτό δεν δηλώνει «δυνατότητα» αλλά αοριστία/προσδοκία· και γι' αυτό συγχωνεύεται στον τύπο ὅταν, ἐπειδάν κ.λπ."},{"h":"Εκφορά (II): η ευκτική — επανάληψη στο παρελθόν και πλάγιος λόγος","body":"<p>Η <b>ευκτική</b> στις χρονικές προτάσεις εμφανίζεται σε δύο κύριες περιπτώσεις, και είναι σημαντικό να τις διακρίνει κανείς, γιατί αλλάζει η ερμηνεία.</p><h3>1. Ευκτική της αόριστης επανάληψης στο παρελθόν (ευκτ. επαναληπτική)</h3><p>Αντιστοιχεί στην υποτακτική+ἄν, αλλά μεταφερμένη στο <b>παρελθόν</b>. Δηλώνει πράξη που <b>επαναλαμβανόταν αόριστα</b> κάθε φορά που συνέβαινε η συνθήκη. Η κύρια εκφέρεται τότε με <b>οριστική παρατατικού</b> (κατ' επανάληψη ενέργεια του παρελθόντος). <b>Δεν παίρνει ἄν.</b></p><p>Σχήμα: <i>ὁπότε / ἐπεί + ευκτική … + κύρια με παρατατικό</i> = «κάθε φορά που … , (συνήθως) …».</p><h3>2. Ευκτική του πλαγίου λόγου</h3><p>Όταν η χρονική πρόταση βρίσκεται μέσα σε <b>πλάγιο λόγο</b> (εξαρτάται από ρήμα λεκτικό/γνωστικό/αισθήσεως) και το ρήμα εξάρτησης είναι <b>ιστορικού χρόνου</b>, η οριστική ή η υποτακτική+ἄν της ευθείας μπορεί να τραπεί σε <b>ευκτική του πλαγίου λόγου</b> (χωρίς ἄν). Αποδίδει την πράξη όπως την παρουσιάζει το υποκείμενο, όχι ως αντικειμενικό γεγονός.</p><h3>3. Ευκτική από έλξη</h3><p>Σπανιότερα η ευκτική οφείλεται σε <b>έλξη</b>: όταν προηγείται άλλη ευκτική (π.χ. δυνητική ή ευχετική) στην προϊσταμένη πρόταση, μπορεί να την «έλξει» και η χρονική.</p><p><b>Σύνοψη της λογικής εκφοράς:</b> οριστική → πραγματικό· υποτ.+ἄν → προσδοκώμενο ή επανάληψη στο παρόν/μέλλον· ευκτική (χωρίς ἄν) → επανάληψη στο παρελθόν ή πλάγιος λόγος μετά από ιστορικό χρόνο.</p>","table":{"title":"Επανάληψη: παρόν/μέλλον vs παρελθόν","cols":["Χρονική βαθμίδα","Έγκλιση χρονικής","ἄν;","Έγκλιση κύριας"],"rows":[["Παρόν/μέλλον (αόρ. επανάληψη)","υποτακτική","ναι (ὅταν…)","ενεστώτας γνωμικός"],["Παρελθόν (αόρ. επανάληψη)","ευκτική","όχι","παρατατικός"],["Πλάγιος λόγος μετά ιστ. χρόνο","ευκτική (πλαγ. λόγου)","όχι","ιστ. χρόνος εξάρτησης"]]},"examples":[{"gr":"Ὁπότε προσβλέψειέ τινα τῶν ἐν ταῖς τάξεσι, εἶπεν ἄν· «Ὦ ἄνδρες…».","an":"ὁπότε + <b>ευκτική</b> «προσβλέψειε» = <b>αόριστη επανάληψη στο παρελθόν</b>: «κάθε φορά που έριχνε το βλέμμα του σε κάποιον…». (Το ἄν στην κύρια «εἶπεν ἄν» είναι δυνητικό-επαναληπτικό, της κύριας — όχι της χρονικής.)"},{"gr":"Ἐπεί δείπνον γένοιτο, ἀπῄεσαν.","an":"ἐπεί + ευκτική «γένοιτο», κύρια παρατατικού «ἀπῄεσαν» = «κάθε φορά που τελείωνε το δείπνο, αποχωρούσαν» — <b>επανάληψη στο παρελθόν</b>."},{"gr":"Ἔλεγεν ὅτι ἀπέλθοι, ἐπεί τά χρήματα λάβοι.","an":"Μέσα σε πλάγιο λόγο μετά ιστ. χρόνο «ἔλεγεν»: η χρονική «ἐπεί … λάβοι» εκφέρεται με <b>ευκτική του πλαγίου λόγου</b> (αντί υποτ.+ἄν / οριστ. της ευθείας)."},{"gr":"Ὁπότε σπείσαιντο, ἀναπαύοιντο ἄν ὀλίγον χρόνον.","an":"τύπου Ξενοφῶντος — ὁπότε + <b>ευκτική</b> «σπείσαιντο», κύρια με δυνητική-επαναληπτική «ἀναπαύοιντο ἄν» = «κάθε φορά που έκαναν σπονδές/ανακωχή, ξεκουράζονταν για λίγο» — <b>αόριστη επανάληψη στο παρελθόν</b>."}],"note":"Ποτέ μην μπερδεύεις την ευκτική επανάληψης (στη χρονική, χωρίς ἄν) με τη δυνητική ευκτική (στην κύρια, με ἄν). Στο πρώτο παράδειγμα, το «ἄν» ανήκει στο «εἶπεν», όχι στο «προσβλέψειε»."},{"h":"Ο σύνδεσμος πρίν: απαρέμφατο vs έγκλιση — ο μεγάλος κανόνας","body":"<p>Ο <b>πρίν</b> («προτού, πριν») έχει ξεχωριστή, διπλή σύνταξη που εξετάζεται πάντοτε στις εξετάσεις. Ο κανόνας στηρίζεται στο <b>αν η προσδιοριζόμενη (κύρια) πρόταση είναι καταφατική ή αρνητική</b>.</p><h3>1. Κύρια καταφατική → πρίν + ΑΠΑΡΕΜΦΑΤΟ</h3><p>Όταν η κύρια είναι <b>καταφατική</b>, ο πρίν συντάσσεται με <b>(τελικό) απαρέμφατο</b> και η χρονική δηλώνει το <b>υστερόχρονο</b> («προτού να…»). Είναι η συνηθέστερη περίπτωση. Το απαρέμφατο έχει υποκείμενο σε <b>αιτιατική</b> (ετεροπροσωπία) ή ταυτοπροσωπία.</p><p><i>Σχήμα:</i> [καταφατική κύρια] + <b>πρίν + απαρέμφατο</b>. Π.χ. «ἀπῆλθον πρίν τόν στρατηγόν ἀφικέσθαι» = «έφυγαν προτού φτάσει ο στρατηγός».</p><h3>2. Κύρια αρνητική → πρίν + ΕΓΚΛΙΣΗ (οριστική / υποτακτική+ἄν / ευκτική)</h3><p>Όταν η κύρια είναι <b>αρνητική</b> (ή έχει αρνητική/απαγορευτική σημασία: μή, οὐ, ἐρώτηση που περιμένει αρνητική απάντηση), ο πρίν συντάσσεται με <b>έγκλιση όπως κάθε άλλη χρονική</b> και δηλώνει συνήθως το <b>προτερόχρονο/σύγχρονο</b> («πριν / ωσότου»). Συγκεκριμένα:</p><ul><li><b>Οριστική</b> (ιστ. χρόνου): πραγματικό γεγονός του παρελθόντος.</li><li><b>Υποτακτική + ἄν</b> (πρίν ἄν): προσδοκώμενο/αόριστη επανάληψη στο μέλλον — κύρια σε μέλλον/προστακτική (π.χ. «μή ἀπέλθητε, πρίν ἄν ἀκούσητε»).</li><li><b>Ευκτική</b>: επανάληψη στο παρελθόν ή πλάγιος λόγος.</li></ul><p>Η λογική: όταν η κύρια αρνείται κάτι, το «πριν» σημαίνει «ωσότου / μέχρις ότου» και χρειάζεται ολοκληρωμένη πρόταση με έγκλιση.</p>","table":{"title":"Σύνταξη του πρίν","cols":["Μορφή κύριας","Σύνταξη πρίν","Χρον. σχέση","Μετάφραση"],"rows":[["Καταφατική","πρίν + απαρέμφατο","υστερόχρονο","προτού να…"],["Αρνητική","πρίν + οριστική (ιστ. χρ.)","προτερόχρονο","πριν / ωσότου (πραγμ.)"],["Αρνητική (μέλλον)","πρίν ἄν + υποτακτική","προτερόχρ./προσδοκ.","ωσότου / προτού να…"],["Αρνητική (παρελθ./πλάγ.)","πρίν + ευκτική","επανάληψη/πλάγ.λόγ.","ωσότου / προτού"]]},"examples":[{"gr":"Οἱ Ἀθηναῖοι ἀπῆλθον πρίν τούς πολεμίους ἐπιθέσθαι.","an":"Κύρια <b>καταφατική</b> «ἀπῆλθον» → πρίν + <b>απαρέμφατο</b> «ἐπιθέσθαι» (υποκ. «τούς πολεμίους» σε αιτιατική, ετεροπροσωπία). Δηλώνει <b>υστερόχρονο</b>: «έφυγαν προτού επιτεθούν οι εχθροί»."},{"gr":"Μή ἀπέλθητε, πρίν ἄν ἀκούσητε.","an":"Κύρια <b>αρνητική/απαγορευτική</b> «μή ἀπέλθητε» → πρίν ἄν + <b>υποτακτική</b> «ἀκούσητε». <b>Προσδοκώμενο</b>: «μη φύγετε, προτού (ωσότου) ακούσετε»."},{"gr":"Οὐ πρότερον ἐπαύσαντο πρίν τήν πόλιν εἷλον.","an":"Κύρια <b>αρνητική</b> «οὐ … ἐπαύσαντο» → πρίν + <b>οριστική αορίστου</b> «εἷλον» (πραγματικό παρελθόν): «δεν σταμάτησαν, προτού κυριεύσουν την πόλη»."},{"gr":"Οὔτε Κύρῳ ἰέναι ἤθελε, πρίν ἡ γυνή αὐτόν ἔπεισε καί πίστεις ἔλαβε.","an":"Ξεν. Ἀνάβ. 1.2.26 — κύρια <b>αρνητική</b> «οὔτε … ἰέναι ἤθελε» → πρίν + <b>οριστική αορίστου</b> «ἔπεισε … ἔλαβε»: «ούτε ήθελε να πάει στον Κύρο, ωσότου τον έπεισε η γυναίκα του και έλαβε εγγυήσεις» — πραγματικό παρελθόν."},{"gr":"Καί οὐ πρόσθεν ἐπαύσαντο πρίν τήν πόλιν ἐς στάσιν κατέστησαν.","an":"τύπου Θουκυδίδου — κύρια <b>αρνητική</b> με «πρόσθεν» («οὐ πρόσθεν ἐπαύσαντο») → πρίν + <b>οριστική</b>· το «πρόσθεν» είναι το προειδοποιητικό σήμα της σύνταξης με έγκλιση: «δεν σταμάτησαν προτού οδηγήσουν την πόλη σε εμφύλιο»."}],"note":"Δύο παγίδες: (α) Συχνά στην αρνητική κύρια υπάρχει το <b>πρότερον / πρόσθεν</b> («οὐ πρότερον… πρίν…») — χρήσιμο σήμα αναγνώρισης. (β) Μην κρίνεις από το αν υπάρχει «οὐ» επιφανειακά μόνο· μέτρα τη συνολική (αρνητική/απαγορευτική/ρητορικά αρνητική) σημασία της κύριας."},{"h":"Διάκριση ἐπεί/ἐπειδή χρονικού από αιτιολογικό — και άλλες παγίδες","body":"<p>Το συχνότερο λάθος στις χρονικές είναι η σύγχυση του <b>ἐπεί / ἐπειδή</b>: οι ίδιοι σύνδεσμοι λειτουργούν και ως <b>χρονικοί</b> («αφού, αφότου») και ως <b>αιτιολογικοί</b> («επειδή, διότι»). Η αναγνώριση γίνεται με τα παρακάτω κριτήρια.</p><h3>Κριτήρια διάκρισης</h3><ul><li><b>Δοκιμή αντικατάστασης:</b> Αν αντικαθίσταται φυσικά με «αφού / αφότου / όταν» → <b>χρονικός</b>. Αν με «επειδή / διότι / γιατί» → <b>αιτιολογικός</b>.</li><li><b>Χρονική αλληλουχία γεγονότων:</b> Αν η πρόταση τοποθετεί απλώς το γεγονός στον χρόνο (ένα συμβάν προηγείται άλλου) → χρονικός. Αν εξηγεί <i>γιατί</i> γίνεται η πράξη της κύριας → αιτιολογικός.</li><li><b>Σχέση αιτίου-αιτιατού:</b> Αν υπάρχει λογική «αιτία → αποτέλεσμα» → αιτιολογικός.</li><li><b>Συμφραζόμενα/συνεκφορά:</b> Δείκτες όπως «τότε, μετά ταῦτα, εὐθύς» ευνοούν χρονική ανάγνωση· δείκτες όπως «διά τοῦτο, οὕτω» ευνοούν αιτιολογική.</li></ul><p>Συχνά η σημασία είναι <b>αμφίσημη</b> και χωρούν και οι δύο αναγνώσεις (χρονικο-αιτιολογικό ἐπεί)· τότε επιλέγουμε με βάση το νόημα του κειμένου, αλλά δηλώνουμε και τη δυνατότητα.</p><h3>Άλλες κλασικές παγίδες</h3><ul><li><b>ὡς πολυλειτουργικό:</b> πέρα από χρονικό, είναι αιτιολογικό, τελικό, παραβολικό, ειδικό, συμπερασματικό, αναφορικό. Κρίνε πάντα από έγκλιση + νόημα.</li><li><b>ἕως / μέχρι / ἄχρι ως προθέσεις:</b> με γενική («μέχρι τῆς νυκτός») είναι εμπρόθετος προσδιορισμός, όχι σύνδεσμος που εισάγει πρόταση.</li><li><b>Αναφορικο-χρονικές:</b> «ἐν ᾧ (χρόνῳ)», «ἀφ' οὗ», «ἐξ οὗ», «μέχρι οὗ» — προέρχονται από αναφορική αντωνυμία αλλά λειτουργούν ως χρονικοί δείκτες.</li><li><b>Χρονική μετοχή:</b> ισοδυναμεί νοηματικά με χρονική πρόταση (ταῦτα ἀκούσας = ἐπεί ταῦτα ἤκουσε), αλλά συντακτικά είναι επιρρηματική μετοχή, όχι πρόταση.</li></ul>","table":{"title":"ἐπεί/ἐπειδή: χρονικό ή αιτιολογικό;","cols":["Κριτήριο","Χρονικό","Αιτιολογικό"],"rows":[["Αντικατάσταση","αφού / αφότου / όταν","επειδή / διότι / γιατί"],["Νόημα","τοποθέτηση στον χρόνο","εξήγηση της αιτίας"],["Σχέση με κύρια","χρονική ακολουθία","αίτιο → αποτέλεσμα"],["Δείκτες context","τότε, εὐθύς, μετά ταῦτα","διά τοῦτο, οὕτως"]]},"examples":[{"gr":"Ἐπεί ἐτελεύτησεν ὁ πατήρ, παρέλαβε τήν ἀρχήν.","an":"<b>Χρονικό</b> ἐπεί: «αφού πέθανε ο πατέρας» — απλή χρονική ακολουθία (θάνατος → ανάληψη)· αντικαθίσταται με «αφότου»."},{"gr":"Ἐπεί οὖν οὐκ ἔπειθον, ἐπορευόμην.","an":"<b>Αιτιολογικό-χρονικό</b>: «επειδή/αφού λοιπόν δεν τους έπειθα, προχωρούσα». Με «οὖν» και νόημα αιτίας κλίνει προς αιτιολογικό· αποδεκτή και χρονική ανάγνωση."},{"gr":"Ἐπειδή ταχέως ἥκεις, χάριν σοι οἶδα.","an":"<b>Αιτιολογικό</b>: «επειδή ήρθες γρήγορα, σου χρωστώ ευγνωμοσύνη» — η πρόταση εξηγεί την αιτία της ευγνωμοσύνης (αντικατάσταση με «διότι»)."},{"gr":"Ἐπειδή Κῦρος ἐκάλει, λαβών ὑμᾶς ἐπορευόμην.","an":"Ξεν. Ἀνάβ. 1.3.4 — εδώ ο Κλέαρχος αφηγείται χρονική ακολουθία· πρωτεύει η <b>χρονική</b> ανάγνωση («όταν / αφού με καλούσε ο Κύρος»), αν και υπολανθάνει και αιτιολογική απόχρωση. Καλό δείγμα αμφισημίας ἐπειδή."},{"gr":"Ἐπεί δέ ταῦτα ἐγένετο, οἱ μέν ἄλλοι ἀπῆλθον.","an":"<b>Χρονικό</b> ἐπεί (τύπου ιστορικού): «αφού έγιναν αυτά» — η μετάβαση «μετά ταῦτα» και η αμιγής χρονική ακολουθία αποκλείουν την αιτιολογική ανάγνωση."}],"note":"Πρακτικός χρυσός κανόνας: αν μπορείς να βάλεις «αφού» ΚΑΙ να κρατήσεις το νόημα μιας απλής χρονικής σειράς, είναι χρονικό· αν χρειάζεσαι «επειδή/γιατί» για να βγει το νόημα, είναι αιτιολογικό. Σε αμφισημία, κατέγραψε και τις δύο δυνατότητες."}]);
  T("syn-enantiomatikes", [{"h":"Τι είναι και ποια θέση έχουν στον λόγο","body":"<p>Οι <b>εναντιωματικές</b> και οι <b>παραχωρητικές</b> προτάσεις είναι δύο συγγενικά είδη <b>δευτερευουσών επιρρηματικών προτάσεων</b>. Και οι δύο εκφράζουν μια <b>εναντίωση</b> (αντίθεση, αντίσταση) προς το περιεχόμενο της κύριας πρότασης: δηλώνουν δηλαδή κάτι που θα περίμενε κανείς να <i>εμποδίσει</i> την πραγματοποίηση όσων λέει η κύρια πρόταση, και όμως η κύρια πρόταση ισχύει παρ' όλα αυτά. Γι' αυτό και αποτελούν τη φυσική «αντίστροφη» των <b>αιτιολογικών</b> προτάσεων: η αιτιολογική δίνει τον λόγο που εξηγεί την κύρια, ενώ η εναντιωματική/παραχωρητική δίνει έναν λόγο που θα ανέμενε κανείς να την <i>ανατρέψει</i>, αλλά τελικά αποτυγχάνει.</p><p>Στην περίοδο λειτουργούν ως <b>επιρρηματικός προσδιορισμός της εναντίωσης / παραχώρησης</b> στο ρήμα της κύριας πρότασης. Από άποψη περιεχομένου είναι <b>προτάσεις κρίσεως</b> (εκφράζουν μια κρίση, μια διαπίστωση), όχι επιθυμίας.</p><h3>Η βασική διάκριση των δύο ειδών</h3><p>Η διαφορά τους είναι λεπτή αλλά ουσιώδης και κρίνεται από <b>τη φύση της αντίθεσης</b> που διατυπώνεται:</p><ul><li><b>Εναντιωματική</b>: η εναντίωση αφορά κάτι <b>πραγματικό</b> ή που το θεωρούμε πραγματικό. Έχει χαρακτήρα κοντινό στις <i>αιτιολογικές-υποθετικές</i>, αλλά με αντιθετικό περιεχόμενο. Μεταφράζεται «<i>αν και, μολονότι, παρόλο που</i>». Π.χ. «αν και πράγματι έχουμε χρήματα...».</li><li><b>Παραχωρητική</b>: η εναντίωση αφορά κάτι <b>υποθετικό</b> – μια υπόθεση που τη <i>δεχόμαστε, την παραχωρούμε</i> για χάρη της συζήτησης, ακόμη κι αν είναι αμφίβολη, απίθανη ή και αδύνατη. Μεταφράζεται «<i>και αν, και αν ακόμη, ακόμη κι αν, έστω κι αν</i>». Π.χ. «και αν ακόμη μας νικήσουν...».</li></ul><p>Μνημονικά: <b>Εναντιωματική = «αν και» (γεγονός)</b>· <b>Παραχωρητική = «και αν» (υπόθεση)</b>. Η σειρά των λέξεων «αν–και» δίνει το κλειδί.</p>","examples":[{"gr":"Εἰ καί χρήματα εὐποροῦμεν, οὐκ εὐτυχοῦμεν.","an":"Αν και (πράγματι) διαθέτουμε άφθονα χρήματα, δεν είμαστε ευτυχισμένοι. — Εναντιωματική (το «έχουμε χρήματα» είναι γεγονός)· εισαγωγή με εἰ καί, εκφορά με οριστική, λειτουργία: επιρρηματικός προσδιορισμός της εναντίωσης στο «οὐκ εὐτυχοῦμεν»."},{"gr":"Καί ἐάν οἱ πολέμιοι τό ναυτικόν ἡμῶν νικήσωσι, κρατήσομεν αὐτῶν.","an":"Και αν ακόμη οι εχθροί νικήσουν το ναυτικό μας, θα τους νικήσουμε. — Παραχωρητική (απλή υπόθεση που την παραχωρούμε)· εισαγωγή με καί ἐάν, εκφορά με υποτακτική, προσδιορισμός παραχώρησης στο «κρατήσομεν»."},{"gr":"Εἰ καί τυραννεῖς, ἐξισωτέον τό γοῦν ἴσ' ἀντιλέξαι.","an":"Σοφ. Οἰδ. Τύρ. 408 — «αν και είσαι βασιλιάς (κυβερνάς ως τύραννος)»· εναντιωματική με εἰ καί + οριστική, που δηλώνει αναγνωρισμένο γεγονός (η εξουσία του Οιδίποδα είναι πραγματική)."},{"gr":"Καί εἰ σύν τεθρίπποις βούλοιντο ἀπιέναι, πολλούς ἄν ἡγεμόνας δοῖεν.","an":"Ξεν. Ἀνάβ. 3.2.24 (τύπου) — «και αν ακόμη ήθελαν να φύγουν με τέθριππα άρματα»· παραχωρητική με καί εἰ + ευκτική, ακραία υπόθεση που παραχωρείται."}]},{"h":"Εναντιωματικές: εισαγωγή, εκφορά, σημασία","body":"<p>Οι <b>εναντιωματικές</b> δηλώνουν εναντίωση προς κάτι που <b>θεωρείται πραγματικό</b>. Παρουσιάζουν δηλαδή ένα γεγονός ως ισχύον και αμέσως σημειώνουν ότι, παρά το γεγονός αυτό, ισχύει και η κύρια πρόταση. Είναι κατά βάθος <b>πραγματικές υποθετικές με αντιθετικό χρωματισμό</b>· γι' αυτό η εκφορά τους ακολουθεί τους κανόνες των αντίστοιχων υποθετικών συνδέσμων.</p><h3>Εισαγωγή (εναντιωματικοί σύνδεσμοι)</h3><p>Εισάγονται με τους εναντιωματικούς συνδέσμους που σχηματίζονται με <b>υποθετικό σύνδεσμο + καί</b>, όπου το <b>καί</b> τίθεται <i>μετά</i> τον υποθετικό σύνδεσμο:</p><ul><li><b>εἰ καί</b> (= αν και) — με οριστική ή ευκτική.</li><li><b>ἐάν καί, ἄν καί, ἤν καί</b> (= αν και) — με υποτακτική.</li></ul><p>Στο σχολικό συντακτικό αναγνωρίζονται επίσης ως ισοδύναμα της εναντιωματικής σημασίας (κυρίως στις μετοχές και στον σύνδεσμο που τις αναλύει) τα <b>καίτοι</b> (= και βέβαια, και όμως· συνήθως με μετοχή ή με κύρια πρόταση) και <b>καίπερ</b> (= αν και, μολονότι· πάντοτε με εναντιωματική μετοχή). Η εναντιωματική μετοχή αναλύεται κανονικά σε πρόταση με <b>εἰ καί + οριστική</b> στον ίδιο χρόνο.</p><h3>Εκφορά</h3><p>Η εκφορά ταυτίζεται με εκείνη των <b>υποθετικών</b>, γιατί ο σκελετός είναι υποθετικός:</p><ul><li>με <b>οριστική</b> ή <b>ευκτική</b>, όταν εισάγονται με <b>εἰ καί</b> (η οριστική για το πραγματικό· η ευκτική σε πλάγιο λόγο ή σε αόριστη επανάληψη στο παρελθόν).</li><li>με <b>υποτακτική</b>, όταν εισάγονται με <b>ἐάν καί, ἄν καί, ἤν καί</b>.</li></ul><h3>Άρνηση</h3><p>Η άρνηση είναι <b>μή</b> (όπως σε όλες τις υποθετικού τύπου προτάσεις): π.χ. <i>εἰ καί μή βούλεται</i> (αν και δεν θέλει).</p>","examples":[{"gr":"Εἰ καί μή βλέπεις, φρονεῖς δ' ὅμως.","an":"(τύπου) Αν και δεν βλέπεις, ωστόσο σκέφτεσαι (καταλαβαίνεις). — εἰ καί + οριστική, άρνηση μή· στην κύρια το ὅμως («ωστόσο») τονίζει την αντίθεση."},{"gr":"Ὁ μέντοι Ἀγησίλαος, καίπερ ὁρῶν ἐκείνους, οὐκ ἐδίωκεν.","an":"Ο Αγησίλαος όμως, αν και τους έβλεπε, δεν τους καταδίωκε. — Εναντιωματική μετοχή με καίπερ· αναλύεται: «εἰ καί ἑώρα ἐκείνους». Φανερώνει εναντίωση προς πραγματικό γεγονός."},{"gr":"Σωκράτης, καίτοι χρηστότατος ὤν, ὅμως φάρμακον ἔπιεν.","an":"Ο Σωκράτης, αν και ήταν εξαιρετικά ενάρετος, ωστόσο ήπιε το δηλητήριο. — εναντιωματική μετοχή (χρηστότατος ὤν) με καίτοι/ὅμως· ανάλυση: «εἰ καί χρηστότατος ἦν»."},{"gr":"Ἐάν καί πολλά πάθωμεν, οὐκ ἐνδώσομεν.","an":"Αν και (όσα κι αν) πάθουμε πολλά, δεν θα υποχωρήσουμε. — ἐάν καί + υποτακτική (πάθωμεν), άρνηση στην κύρια οὐ· εναντιωματική σημασίας προσέγγισης («μολονότι ενδέχεται να πάθουμε»)."},{"gr":"Πόλιν μέν, εἰ καί μή βλέπεις, φρονεῖς δ' ὅμως οἵᾳ νόσῳ σύνεστιν.","an":"Σοφ. Οἰδ. Τύρ. 302 — «αν και δεν βλέπεις, ωστόσο νιώθεις με τι αρρώστια ζει η πόλη»· εναντιωματική με εἰ καί + οριστική, άρνηση μή, αντίθεση που εξαίρει το ὅμως της κύριας. Η πηγή του αρχικού παραδείγματος."},{"gr":"Εἰ καί τῳ σμικρότερον δοκεῖ εἶναι, ὅμως σκεπτέον.","an":"Πλάτ. Λάχ. 182c (τύπου) — «αν και σε κάποιον φαίνεται κάπως μικρότερης σημασίας»· εναντιωματική με εἰ καί + οριστική, που παραδέχεται ένα πραγματικό δεδομένο χωρίς να το θεωρεί εμπόδιο."}],"table":{"title":"Εναντιωματικές: σύνδεσμος → εκφορά","cols":["Σύνδεσμος","Σημασία","Εκφορά (έγκλιση)"],"rows":[["εἰ καί","αν και, μολονότι","οριστική (πραγματικό) / ευκτική (πλάγιος λόγος, επανάληψη)"],["ἐάν καί / ἄν καί / ἤν καί","αν και","υποτακτική"],["καίτοι","και όμως, και βέβαια","με κύρια πρόταση ή με μετοχή"],["καίπερ (+ μετοχή)","αν και, μολονότι","εναντιωματική μετοχή → εἰ καί + οριστική"]]},"note":"Προσοχή στη θέση του «καί»: στις εναντιωματικές το καί ακολουθεί τον υποθετικό σύνδεσμο (εἰ + καί). Αυτό το «καί» τονίζει ολόκληρη την πρόταση («αν πράγματι, μολονότι»). Η αλλαγή σειράς (καί + εἰ) αλλάζει το είδος σε παραχωρητική."},{"h":"Παραχωρητικές: εισαγωγή, εκφορά, σημασία","body":"<p>Οι <b>παραχωρητικές</b> δηλώνουν εναντίωση προς κάτι <b>υποθετικό</b> – προς μια υπόθεση που ο ομιλητής <b>παραχωρεί</b>, την αποδέχεται προσωρινά «για χάρη της συζήτησης», ακόμη κι αν τη θεωρεί αβέβαιη, απίθανη, ακραία ή και αδύνατη. Το νόημα είναι: «<i>έστω και αν συμβεί / έστω και αν ίσχυε αυτό το ακραίο, και πάλι ισχύει η κύρια</i>». Είναι επομένως <b>υποθετικές με ενισχυμένη, ακραία υπόθεση</b>.</p><h3>Εισαγωγή (παραχωρητικοί σύνδεσμοι)</h3><p>Εισάγονται με <b>καί + υποθετικό σύνδεσμο</b> (το καί <i>προηγείται</i>), και διακρίνονται ανάλογα με το αν η κύρια είναι καταφατική ή αρνητική:</p><ul><li>Όταν η κύρια είναι <b>καταφατική</b>: <b>καί εἰ, κεἰ, καί ἐάν, καί ἄν, κἄν, καί ἤν</b> (= και αν, και αν ακόμη, έστω κι αν).</li><li>Όταν η κύρια είναι <b>αρνητική</b>: <b>οὐδ' εἰ, μηδ' εἰ, οὐδ' ἐάν, μηδ' ἐάν, οὐδ' ἄν, μηδ' ἄν, οὐδ' ἤν, μηδ' ἤν</b> (= ούτε αν, ούτε αν ακόμη, και αν δεν...). Το οὐδ'/μηδ' = «και ... δεν / ούτε αν».</li></ul><h3>Εκφορά</h3><p>Όπως και στις εναντιωματικές, ακολουθεί τους υποθετικούς κανόνες:</p><ul><li>με <b>οριστική</b> ή <b>ευκτική</b>, όταν εισάγονται με τα <b>καί εἰ, κεἰ, οὐδ' εἰ, μηδ' εἰ</b>.</li><li>με <b>υποτακτική</b>, όταν εισάγονται με τα <b>καί ἐάν, καί ἄν, κἄν, καί ἤν, οὐδ' ἐάν, μηδ' ἐάν, οὐδ' ἄν, μηδ' ἄν, οὐδ' ἤν</b>.</li></ul><h3>Άρνηση</h3><p>Η άρνηση της ίδιας της παραχωρητικής πρότασης είναι <b>μή</b>. Σημείωση: τα οὐδ'/μηδ' στην <i>αρχή</i> του συνδέσμου δεν αρνούνται την παραχωρητική, αλλά συνδέουν αρνητικά με την αρνητική κύρια («ούτε καν αν»).</p>","examples":[{"gr":"Καί εἰ μή βούλει, ἀνάγκη σοι πείθεσθαι.","an":"Και αν ακόμη δεν θέλεις, είσαι αναγκασμένος να υπακούς. — καί εἰ + οριστική, άρνηση της παραχωρητικής μή· καταφατική κύρια, οπότε σύνδεσμος του καταφατικού τύπου (καί εἰ)."},{"gr":"Κἄν μή θέλωσιν, οἱ θεοί τό δίκαιον τελοῦσιν.","an":"Και αν ακόμη δεν θέλουν, οι θεοί φέρνουν σε πέρας το δίκαιο. — κἄν (= καί ἐάν) + υποτακτική (θέλωσιν)· ακραία υπόθεση που παραχωρείται."},{"gr":"Οὐκ ἄν δυναίμην, οὐδ' εἰ πάνυ βουλοίμην, τοῦτο πρᾶξαι.","an":"Δεν θα μπορούσα, ούτε αν ακόμη το ήθελα πάρα πολύ, να το κάνω αυτό. — Αρνητική κύρια (οὐκ ἄν δυναίμην) → παραχωρητική του αρνητικού τύπου οὐδ' εἰ + ευκτική (βουλοίμην)."},{"gr":"Καί ἐάν πάντες ἀπολίπωσιν, ἐγώ μενῶ.","an":"Και αν ακόμη όλοι εγκαταλείψουν, εγώ θα μείνω. — καί ἐάν + υποτακτική· καταφατική κύρια· έντονη εναντίωση σε ακραία υπόθεση («έστω κι αν φύγουν όλοι»)."},{"gr":"Οὐδ' εἰ πάντες ἔλθοιεν Πέρσαι, πλήθει γε οὐχ ὑπερβαλοίμεθ' ἄν τούς πολεμίους.","an":"Ξεν. Κύρ. 2.1.8 — «ούτε αν ακόμη έρθουν όλοι οι Πέρσες, δεν θα τους ξεπερνούσαμε σε πλήθος»· παραχωρητική αρνητικού τύπου με οὐδ' εἰ + ευκτική, λόγω αρνητικής κύριας (οὐχ ὑπερβαλοίμεθ' ἄν)."},{"gr":"Καί μοι μή θορυβήσητε, μηδέ ἄν δόξω τι ὑμῖν μέγα λέγειν.","an":"Πλάτ. Ἀπολ. 20e — «και μη θορυβήσετε, ούτε αν ακόμη σας φανεί ότι μιλώ κάπως μεγάλα»· παραχωρητική με μηδέ ἄν + υποτακτική· το μηδέ (όχι οὐδέ) επειδή η κύρια είναι απαγορευτική με άρνηση μή (μή θορυβήσητε)."}],"table":{"title":"Παραχωρητικοί σύνδεσμοι ανά τύπο κύριας","cols":["Κύρια πρόταση","Σύνδεσμοι","Εκφορά"],"rows":[["Καταφατική (με εἰ)","καί εἰ, κεἰ, καί ἤν*","οριστική / ευκτική"],["Καταφατική (με ἐάν)","καί ἐάν, καί ἄν, κἄν, καί ἤν","υποτακτική"],["Αρνητική (με εἰ)","οὐδ' εἰ, μηδ' εἰ","οριστική / ευκτική"],["Αρνητική (με ἐάν)","οὐδ' ἐάν, μηδ' ἐάν, οὐδ' ἄν, μηδ' ἄν, οὐδ' ἤν","υποτακτική"]]},"note":"Το «μηδ' εἰ» χρησιμοποιείται όταν η κύρια είναι προτρεπτική/απαγορευτική ή έχει άρνηση μή (π.χ. προστακτική), ενώ το «οὐδ' εἰ» όταν η κύρια έχει άρνηση οὐ (απλή κρίση). Αυτή η εναλλαγή οὐ/μή αντανακλά την άρνηση της ίδιας της κύριας πρότασης."},{"h":"Εναντιωματική ή παραχωρητική; Η μέθοδος της διάκρισης","body":"<p>Η σύγχυση των δύο ειδών είναι το πιο συχνό λάθος. Η ασφαλής διάκριση γίνεται με <b>τρία διαδοχικά κριτήρια</b>:</p><h3>1. Κριτήριο της σειράς «καί»</h3><p>Κοίτα <b>πού βρίσκεται το καί</b> ως προς τον υποθετικό σύνδεσμο:</p><ul><li><b>εἰ + καί</b> / <b>ἐάν + καί</b> (το καί <i>έπεται</i>) → <b>εναντιωματική</b> («αν και»).</li><li><b>καί + εἰ</b> / <b>καί + ἐάν</b> (το καί <i>προηγείται</i>, ή κράση: κεἰ, κἄν) → <b>παραχωρητική</b> («και αν ακόμη»).</li></ul><h3>2. Κριτήριο πραγματικότητας</h3><p>Ρώτησε: το περιεχόμενο της δευτερεύουσας είναι <b>γεγονός / θεωρείται πραγματικό</b> ή είναι μια <b>καθαρή υπόθεση που παραχωρώ</b>;</p><ul><li>Πραγματικό → <b>εναντιωματική</b>. (Ξέρω ότι έχει χρήματα· «αν και έχει χρήματα».)</li><li>Υπόθεση/ακραίο/αμφίβολο → <b>παραχωρητική</b>. (Δεν ξέρω αν θα μας νικήσουν· «και αν ακόμη μας νικήσουν».)</li></ul><h3>3. Κριτήριο μετάφρασης</h3><p>Δοκίμασε τη μετάφραση:</p><ul><li>Ταιριάζει «<b>αν και, μολονότι, παρόλο που</b>» → εναντιωματική.</li><li>Ταιριάζει «<b>και αν (ακόμη), έστω κι αν, ακόμη κι αν</b>» → παραχωρητική.</li></ul><p>Σε επίπεδο νοήματος και οι δύο ισοδυναμούν λογικά με τη σχέση «παρ' όλα αυτά». Η κύρια πρόταση συχνά συνοδεύεται από τα <b>ὅμως, ἀλλ' ὅμως, δέ</b> («ωστόσο, κι όμως»), που είναι σαφής ένδειξη εναντιωματικής/παραχωρητικής περιόδου.</p>","examples":[{"gr":"Εἰ καί νέος ἐστίν, σώφρων ἐστί.","an":"Αν και είναι νέος, είναι συνετός. — Το «είναι νέος» είναι γεγονός → εναντιωματική (εἰ καί)."},{"gr":"Καί εἰ νέος ἦν, σώφρων ἄν ἦν.","an":"Και αν ακόμη ήταν νέος, θα ήταν συνετός. — Υπόθεση που παραχωρείται («ας υποθέσουμε ότι ήταν νέος») → παραχωρητική (καί εἰ)."},{"gr":"Ὅμως δ', καίπερ τοιούτων ὄντων, οὐκ ἀπέστημεν.","an":"Κι όμως, αν και τα πράγματα ήταν τέτοια, δεν αποστατήσαμε. — Το ὅμως στην κύρια + καίπερ + μετοχή = τυπική εναντιωματική δομή."},{"gr":"Συμβουλεύω σοι, καίπερ νεώτερος ὤν.","an":"Ξεν. Κύρ. 4.5.32 — «σε συμβουλεύω, αν και είμαι νεότερος»· εναντιωματική μετοχή με καίπερ (το «νεότερος» = πραγματικό), αντιπαραβολή στο νόημα «αν και» — άρα όχι παραχωρητική."},{"gr":"Καί εἰ μηδέν αὐτῷ τούτων ὑπῆρχεν, ῥᾴδιον γνῶναι τόν ἀληθῆ λέγοντα.","an":"Δημ. (τύπου) — «και αν ακόμη δεν υπήρχε σ' αυτόν τίποτε από αυτά»· παραχωρητική με καί εἰ + οριστική· υπόθεση εξ ορισμού μη ισχύουσα που μόνο παραχωρείται — εδώ ταιριάζει μόνο το «και αν ακόμη», όχι το «αν και»."}],"note":"Παγίδα: το «εἰ καί» και το «καί εἰ» δεν είναι πάντα τυπογραφικά ξεχωριστά σε όλα τα κείμενα, και ορισμένοι συγγραφείς τα χρησιμοποιούν χαλαρά. Όταν η σειρά είναι αμφίβολη, αποφασίζει το κριτήριο πραγματικότητας (2) και η σημασία του ὅμως· αν το περιεχόμενο είναι αναμφισβήτητα πραγματικό, πρόκειται για εναντιωματική, ανεξάρτητα από επιφανειακές ομοιότητες."},{"h":"Η μετοχή ως ισοδύναμο: εναντιωματική / παραχωρητική μετοχή","body":"<p>Η εναντίωση δεν εκφράζεται μόνο με δευτερεύουσα πρόταση αλλά και με <b>επιρρηματική μετοχή</b>. Στο σχολικό συντακτικό η μετοχή αυτή ονομάζεται <b>εναντιωματική</b> (όταν δηλώνει εναντίωση σε πραγματικό) ή, σπανιότερα, <b>παραχωρητική</b> (σε υποθετικό), και είναι κρίσιμη για τις ασκήσεις «ανάλυσης μετοχής σε πρόταση».</p><h3>Αναγνώριση</h3><p>Η εναντιωματική μετοχή συνοδεύεται πολύ συχνά από τα μόρια:</p><ul><li><b>καίπερ</b> (= αν και, μολονότι) — το πιο χαρακτηριστικό· σχεδόν αποκλειστικά εναντιωματικό.</li><li><b>καί, καίτοι</b> (= και όμως) πριν από τη μετοχή.</li><li><b>καί ταῦτα</b> (= και μάλιστα, και αυτό ενώ).</li><li>Στην κύρια συχνά υπάρχει το <b>ὅμως</b> (= ωστόσο), που «απαντά» στη μετοχή.</li></ul><h3>Ανάλυση σε πρόταση</h3><p>Η εναντιωματική μετοχή <b>αναλύεται σε εναντιωματική πρόταση με εἰ καί + οριστική</b>, στον ίδιο χρόνο με τη μετοχή (ή με ἐάν καί + υποτακτική, ανάλογα με το ρήμα εξάρτησης):</p><ul><li>μετοχή ενεστώτα → εἰ καί + οριστική ενεστώτα/παρατατικού.</li><li>μετοχή αορίστου → εἰ καί + οριστική αορίστου.</li><li>μετοχή με υποθετική/μελλοντική αναφορά → ἐάν καί + υποτακτική.</li></ul><p>Η μετοχή, ως επιρρηματική, λειτουργεί κι αυτή ως <b>επιρρηματικός προσδιορισμός της εναντίωσης</b> στο ρήμα της πρότασής της.</p>","examples":[{"gr":"Καίπερ ἰσχυρός ὤν, ἡττήθη.","an":"Αν και ήταν δυνατός, νικήθηκε. — Εναντιωματική μετοχή με καίπερ. Ανάλυση: «εἰ καί ἰσχυρός ἦν, ἡττήθη» (εἰ καί + οριστική παρατατικού, ίδιος χρόνος με τη μετοχή ενεστώτα)."},{"gr":"Ὁρῶν ταῦτα ὅμως ἐσιώπα.","an":"Αν και τα έβλεπε αυτά, ωστόσο σιωπούσε. — Εναντιωματική μετοχή (ὁρῶν) που αναγνωρίζεται από το ὅμως της κύριας. Ανάλυση: «εἰ καί ἑώρα ταῦτα, ὅμως ἐσιώπα»."},{"gr":"Καί πολλά παθών οὐκ ἀπέκαμεν.","an":"Αν και έπαθε πολλά, δεν κουράστηκε. — Εναντιωματική μετοχή αορίστου (παθών) με προτακτικό καί. Ανάλυση: «εἰ καί πολλά ἔπαθεν, οὐκ ἀπέκαμεν»."},{"gr":"Δίκαιος ἄν ὤν, οὐκ ἄν ἀδικοίη.","an":"Και αν ακόμη ήταν δίκαιος, δεν θα αδικούσε (υποθετικό περιεχόμενο). — Παραχωρητική μετοχή· αναλύεται σε «καί εἰ δίκαιος ἦν / εἴη». Το δυνητικό ἄν δηλώνει την υποθετική, παραχωρητική φύση."},{"gr":"Ἀποπλεῖ οἴκαδε καίπερ μέσου χειμῶνος ὄντος.","an":"Ξεν. Ἀγησ. 2.31 — «πλέει πίσω στην πατρίδα, αν και ήταν καταμεσής του χειμώνα»· εναντιωματική (γενική απόλυτη) μετοχή με καίπερ. Ανάλυση: «εἰ καί μέσος χειμών ἦν»."},{"gr":"Καί τοῦ Κλέωνος καίπερ μανιώδης οὖσα ἡ ὑπόσχεσις ἀπέβη.","an":"Θουκ. 4.39 — «και η υπόσχεση του Κλέωνα, αν και ήταν παράλογη, εκπληρώθηκε»· εναντιωματική μετοχή με καίπερ (μανιώδης οὖσα). Ανάλυση: «εἰ καί μανιώδης ἦν»."}],"table":{"title":"Ανάλυση εναντιωματικής/παραχωρητικής μετοχής","cols":["Μετοχή (χρόνος/μόριο)","Είδος","Ανάλυση σε πρόταση"],"rows":[["καίπερ + μτχ. ενεστώτα","εναντιωματική","εἰ καί + οριστική ενεστώτα/παρατατικού"],["καίπερ/καί + μτχ. αορίστου","εναντιωματική","εἰ καί + οριστική αορίστου"],["μτχ. + ὅμως στην κύρια","εναντιωματική","εἰ καί + οριστική (ίδιος χρόνος)"],["δυνητική μτχ. (μτχ. + ἄν)","παραχωρητική","καί εἰ + οριστική/ευκτική"]]},"note":"Διάκριση από την υποθετική μετοχή: και οι δύο σχετίζονται με υπόθεση, αλλά η υποθετική απλώς θέτει όρο («αν...»), ενώ η παραχωρητική θέτει όρο εναντιωματικό («και αν ακόμη..., παρ' όλα αυτά»). Το κλειδί είναι το ὅμως ή η αντίθεση νοήματος στην κύρια."},{"h":"Σύνοψη, συντακτική λειτουργία και συγκριτικός πίνακας","body":"<p>Συγκεντρωτικά, για τη γρήγορη αναγνώριση και τον πλήρη συντακτικό χαρακτηρισμό της περιόδου:</p><h3>Πλήρης χαρακτηρισμός (τι γράφουμε στην ανάλυση)</h3><p>Για κάθε τέτοια πρόταση αναφέρουμε διαδοχικά: <b>(α)</b> ότι είναι <i>δευτερεύουσα επιρρηματική εναντιωματική / παραχωρητική</i>· <b>(β)</b> τον <i>εισαγωγικό σύνδεσμο</i> (εἰ καί / ἐάν καί / καί εἰ / κἄν / οὐδ' εἰ κ.ο.κ.)· <b>(γ)</b> την <i>εκφορά</i> (οριστική / ευκτική / υποτακτική) με την αιτιολόγησή της· <b>(δ)</b> ότι εκφράζει <i>κρίση</i>· <b>(ε)</b> τη <i>συντακτική θέση</i>: επιρρηματικός προσδιορισμός της εναντίωσης / παραχώρησης στο ρήμα της κύριας.</p><h3>Κοινά γνωρίσματα και των δύο ειδών</h3><ul><li>Είναι <b>επιρρηματικές προτάσεις κρίσεως</b>.</li><li>Έχουν <b>υποθετικό σκελετό</b> (γι' αυτό η εκφορά ακολουθεί τους υποθετικούς κανόνες: εἰ → οριστική/ευκτική, ἐάν → υποτακτική).</li><li>Άρνηση <b>μή</b> (στην ίδια την πρόταση).</li><li>Λογικά ισοδυναμούν με «παρ' όλα αυτά»· η κύρια συχνά φέρει <b>ὅμως / ἀλλ' ὅμως / δέ</b>.</li><li>Συνδέονται με την <b>εναντιωματική/παραχωρητική μετοχή</b> (καίπερ, καίτοι, καί + μτχ.) ως ισοδύναμα.</li></ul><p>Η μόνη πραγματική διαφορά είναι <b>πραγματικό (εναντιωματική) vs υποθετικό-παραχωρούμενο (παραχωρητική)</b>, που αποτυπώνεται και στη σειρά «εἰ καί» έναντι «καί εἰ».</p>","examples":[{"gr":"Εἰ καί ὀλίγοι ἐσμέν, ὅμως μαχούμεθα.","an":"Αν και είμαστε λίγοι, ωστόσο θα πολεμήσουμε. — Εναντιωματική (εἰ καί + οριστική, πραγματικό «είμαστε λίγοι»)· το ὅμως στην κύρια. Θέση: επιρρ. προσδ. εναντίωσης στο «μαχούμεθα»."},{"gr":"Κἄν ἀποθάνω, ἡ ἀλήθεια μενεῖ.","an":"Και αν ακόμη πεθάνω, η αλήθεια θα μείνει. — Παραχωρητική (κἄν = καί ἐάν + υποτακτική ἀποθάνω)· ακραία υπόθεση που παραχωρείται· θέση: επιρρ. προσδ. παραχώρησης στο «μενεῖ»."},{"gr":"Οὐκ ἄν παυσαίμην, οὐδ' εἰ πολλάκις με κωλύοιτε.","an":"Δεν θα σταματούσα, ούτε αν ακόμη πολλές φορές με εμποδίζατε. — Παραχωρητική αρνητικού τύπου (οὐδ' εἰ + ευκτική, λόγω αρνητικής κύριας οὐκ ἄν)."},{"gr":"Καί ἐάν μή ἡμεῖς παρακελευώμεθα, ἱκανῶς ἐπιμελήσεται.","an":"Πλάτ. Μενέξ. 248d — «και αν ακόμη εμείς δεν προτρέπουμε, [η πόλη] θα φροντίσει αρκετά»· παραχωρητική με καί ἐάν + υποτακτική, καταφατική κύρια. Θέση: επιρρ. προσδ. παραχώρησης στο «ἐπιμελήσεται»."},{"gr":"Γελᾷ δ' ὁ μωρός, κἄν τι μή γέλοιον ᾖ.","an":"Μένανδρος, Γνῶμαι Μονόστιχοι 108 — «γελάει ο ανόητος, και αν ακόμη δεν υπάρχει κάτι αστείο»· παραχωρητική με κἄν (= καί ἐάν) + υποτακτική (ᾖ), άρνηση μή της παραχωρητικής."}],"table":{"title":"Συγκριτικός πίνακας: Εναντιωματικές vs Παραχωρητικές","cols":["Χαρακτηριστικό","Εναντιωματικές","Παραχωρητικές"],"rows":[["Φύση εναντίωσης","πραγματικό / θεωρούμενο πραγματικό","υποθετικό / παραχωρούμενο (ακραίο, αμφίβολο)"],["Σύνδεσμοι","εἰ καί, ἐάν καί, ἄν καί, ἤν καί (+ καίτοι, καίπερ)","καί εἰ, κεἰ, κἄν, καί ἐάν / οὐδ' εἰ, μηδ' εἰ, οὐδ' ἐάν, μηδ' ἄν"],["Θέση του «καί»","μετά τον υποθ. σύνδεσμο (εἰ + καί)","πριν τον υποθ. σύνδεσμο (καί + εἰ)"],["Μετάφραση","αν και, μολονότι, παρόλο που","και αν (ακόμη), έστω κι αν, ακόμη κι αν"],["Εκφορά","εἰ → οριστ./ευκτ.· ἐάν → υποτακτ.","εἰ → οριστ./ευκτ.· ἐάν → υποτακτ."],["Άρνηση","μή","μή (οὐδ'/μηδ' = σύνδεση με αρνητική κύρια)"],["Είδος περιεχομένου","κρίσεως","κρίσεως"],["Συντακτική θέση","επιρρ. προσδ. εναντίωσης","επιρρ. προσδ. παραχώρησης"]]},"note":"Τελική μνημονική: «αν–και» (εἰ καί) = ΓΕΓΟΝΟΣ → εναντιωματική· «και–αν» (καί εἰ) = ΥΠΟΘΕΣΗ → παραχωρητική. Και στις δύο, αν δεις στην κύρια το ὅμως, έχεις βρει σχεδόν σίγουρα εναντιωματική/παραχωρητική περίοδο."}]);
  T("syn-aprosopi", [{"h":"Τι είναι η απρόσωπη σύνταξη — ο ορισμός και η λογική της","body":"<p><b>Απρόσωπη σύνταξη</b> ονομάζουμε τη σύνταξη στην οποία το ρήμα της πρότασης βρίσκεται μόνο στο <b>γ΄ ενικό πρόσωπο</b> και <i>δεν έχει ως υποκείμενο ένα συγκεκριμένο πρόσωπο ή πράγμα</i> (δηλ. ένα όνομα ή αντωνυμία σε ονομαστική). Το ρήμα δηλώνει κάτι γενικό, αόριστο ή αναγκαστικό, και το υποκείμενό του είναι μια ολόκληρη έννοια — ένα <b>απαρέμφατο</b> ή μια <b>δευτερεύουσα ονοματική πρόταση</b>.</p><p>Δύο είναι τα δομικά στοιχεία κάθε απρόσωπης σύνταξης:</p><ul><li><b>Το απρόσωπο ρήμα ή η απρόσωπη έκφραση</b> (το «κατηγόρημα»): π.χ. <i>δεῖ, χρή, ἔξεστι, δοκεῖ, συμβαίνει, ἀναγκαῖόν ἐστι, καλόν ἐστι</i> κ.λπ.</li><li><b>Το υποκείμενό του</b>, που ΔΕΝ είναι ποτέ ονομαστική προσώπου/πράγματος, αλλά <b>απαρέμφατο</b> ή <b>δευτερεύουσα πρόταση</b> (ειδική, ενδοιαστική, πλάγια ερωτηματική).</li></ul><p><b>Πρακτικός κανόνας αναγνώρισης:</b> ρωτάμε «ποιος;» ή «τι;» στο ρήμα και απαντάμε με ολόκληρη πράξη/γεγονός, όχι με ουσιαστικό. Στο <i>δεῖ μάχεσθαι</i> δεν ρωτάμε «ποιος δεῖ;» (δεν υπάρχει «αυτός που πρέπει»), αλλά «τι είναι αναγκαίο;» → «<i>το να πολεμάμε</i>» (= <i>μάχεσθαι</i>). Άρα υποκείμενο του <i>δεῖ</i> είναι το απαρέμφατο <i>μάχεσθαι</i>.</p><p>Αντιδιαστολή με την <b>προσωπική σύνταξη</b>: εκεί το ρήμα έχει για υποκείμενο όνομα/αντωνυμία σε ονομαστική και κλίνεται σε όλα τα πρόσωπα (<i>ἐγώ γράφω, σύ γράφεις...</i>). Το ίδιο ρήμα μπορεί να είναι άλλοτε προσωπικό και άλλοτε απρόσωπο, ανάλογα με το αν έχει ή όχι ονομαστική υποκείμενο.</p>","examples":[{"gr":"Δεῖ τούς πολίτας τοῖς νόμοις πείθεσθαι.","an":"Πρέπει οι πολίτες να υπακούουν στους νόμους. — Ρήμα απρόσωπο: <b>δεῖ</b> (γ΄ ενικό). Υποκείμενό του το απαρέμφατο <b>πείθεσθαι</b> («το να υπακούουν»). Υποκείμενο του απαρεμφάτου: <b>τούς πολίτας</b> (αιτιατική). Δεν υπάρχει καμία ονομαστική προσώπου."},{"gr":"Συμβαίνει πολλάκις τούς ἀδίκους εὐτυχεῖν.","an":"Συμβαίνει πολλές φορές οι άδικοι να ευτυχούν. — <b>Συμβαίνει</b>: απρόσωπο ρήμα. Υποκείμενο: το απαρέμφατο <b>εὐτυχεῖν</b>. Υποκείμενο του απαρεμφάτου: <b>τούς ἀδίκους</b> (αιτ.)."},{"gr":"Ἀγγέλλεται ὅτι οἱ πολέμιοι προσέρχονται.","an":"Αναγγέλλεται ότι οι εχθροί πλησιάζουν. — Εδώ το υποκείμενο του απρόσωπου <b>ἀγγέλλεται</b> δεν είναι απαρέμφατο αλλά ολόκληρη η ειδική πρόταση <b>ὅτι οἱ πολέμιοι προσέρχονται</b>."},{"gr":"Ὕει. / Νίφει. / Ἀστράπτει.","an":"Βρέχει. / Χιονίζει. / Αστράφτει. — Τα ρήματα φυσικών φαινομένων είναι γνήσια απρόσωπα· δεν εννοείται κανένα πρόσωπο ως υποκείμενο (αρχικά εννοούνταν ο Ζευς / ο θεός)."},{"gr":"Γράμματα μαθεῖν δεῖ.","an":"Smyth §1984 — Είναι ανάγκη να μάθει κανείς γράμματα. — <b>δεῖ</b> απρόσωπο· υποκείμενό του το απαρέμφατο <b>μαθεῖν</b> («το να μάθει»), με αντικείμενο <b>γράμματα</b>. Δεν υπάρχει ονομαστική υποκείμενο."},{"gr":"Τί χρή ποιεῖν;","an":"Smyth §1984 — Τι πρέπει να κάνει κανείς; — <b>χρή</b> απρόσωπο· υποκείμενό του το απαρέμφατο <b>ποιεῖν</b>, με αντικείμενο την ερωτηματική αντωνυμία <b>τί</b>. Η ερώτηση δεν αφορά «ποιον», αλλά «τι (πράξη)»."}],"note":"Θεμελιώδης αρχή: στην απρόσωπη σύνταξη το υποκείμενο του ρήματος είναι ΠΑΝΤΑ απαρέμφατο ή δευτερεύουσα πρόταση — ποτέ ονομαστική προσώπου ή πράγματος. Όποτε δείτε ονομαστική να κάνει το ρήμα, η σύνταξη είναι προσωπική."},{"h":"Πλήρης κατάλογος απρόσωπων ρημάτων","body":"<p>Τα απρόσωπα ρήματα διακρίνονται σε δύο μεγάλες ομάδες:</p><h3>Α. Ρήματα μόνο απρόσωπα (αποκλειστικώς τριτοπρόσωπα)</h3><p>Δεν απαντούν παρά μόνο στο γ΄ ενικό· δεν υπάρχει προσωπική τους χρήση:</p><ul><li><b>δεῖ</b> = πρέπει, είναι ανάγκη (συντάσσεται και με γενική: <i>δεῖ μοί τινος</i> = μου χρειάζεται κάτι)</li><li><b>χρή</b> = πρέπει, είναι αναγκαίο (απαρχαϊσμένο· παρατατικός <i>ἐχρῆν / χρῆν</i>)</li><li><b>μέλει</b> (μοί τινος) = με νοιάζει, φροντίζω για κάτι</li><li><b>μεταμέλει</b> (μοί τινος) = μετανοώ για κάτι</li><li><b>προσήκει</b> = αρμόζει, ταιριάζει, ανήκει (καθήκον)</li><li><b>μέτεστί</b> (μοί τινος) = μου ανήκει μερίδιο, μετέχω σε κάτι</li><li><b>μέλλει</b> = πρόκειται, είναι πιθανό</li></ul><h3>Β. Ρήματα που είναι κατά βάση προσωπικά, αλλά χρησιμοποιούνται και απροσώπως</h3><p>Όταν πάρουν για υποκείμενο απαρέμφατο ή πρόταση, λειτουργούν απρόσωπα:</p><ul><li><b>ἔξεστι, πάρεστι, ἔνεστι, ἐγχωρεῖ, ἐνδέχεται</b> = είναι δυνατό, επιτρέπεται</li><li><b>δοκεῖ</b> (μοι) = μου φαίνεται καλό, αποφασίζω / νομίζω</li><li><b>φαίνεται</b> = φαίνεται (ότι/πως)</li><li><b>συμβαίνει, τυγχάνει, συμπίπτει</b> = τυχαίνει, συμβαίνει</li><li><b>πρέπει, προσήκει, ἁρμόζει</b> = ταιριάζει, αρμόζει</li><li><b>συμφέρει, λυσιτελεῖ, ἀρκεῖ</b> = συμφέρει, ωφελεί, αρκεί</li><li><b>λέγεται, ἀγγέλλεται, ὁμολογεῖται, νομίζεται, πιστεύεται</b> = (παθητικά) λέγεται, αναγγέλλεται, ομολογείται κ.λπ.</li><li><b>ἔστι</b> (= είναι δυνατό, υπάρχει η δυνατότητα, με απαρέμφατο)</li></ul><p><b>Σημείωση για το νόημα:</b> πολλά απρόσωπα ρήματα συνοδεύονται από <b>γενική</b> ή <b>δοτική</b> που συμπληρώνουν το νόημά τους (<i>μέλει μοι τῆς πατρίδος</i>, <i>δεῖ μοι χρημάτων</i>). Αυτά τα ρήματα του «ενδιαφέροντος / μετοχής / ανάγκης» (<i>μέλει, μεταμέλει, μέτεστι, δεῖ</i>) έχουν χαρακτηριστική σύνταξη με δοτική προσώπου + γενική πράγματος.</p>","examples":[{"gr":"Ἔξεστι τοῖς πολίταις ἐλευθέρως ζῆν.","an":"Είναι δυνατό / επιτρέπεται στους πολίτες να ζουν ελεύθερα. — <b>ἔξεστι</b>: απρόσωπο. Υποκείμενο: <b>ζῆν</b>. Δοτική προσωπική: <b>τοῖς πολίταις</b> (= το λογικό υποκείμενο)."},{"gr":"Μέλει μοι τῆς τῶν φίλων σωτηρίας.","an":"Με νοιάζει / φροντίζω για τη σωτηρία των φίλων. — <b>μέλει</b>: μόνο απρόσωπο. Δοτική προσώπου: <b>μοι</b>· γενική πράγματος (αντικείμενο): <b>τῆς σωτηρίας</b>. (Εδώ το νόημα ολοκληρώνεται με τη γενική, χωρίς απαρέμφατο.)"},{"gr":"Δεῖ μοι χρημάτων.","an":"Μου χρειάζονται χρήματα. — Ιδιόρρυθμη σύνταξη του <b>δεῖ</b>: δοτική προσώπου (<b>μοι</b>) + γενική του πράγματος που χρειάζεται (<b>χρημάτων</b>)."},{"gr":"Μεταμέλει μοι τῶν εἰρημένων.","an":"Μετανοώ για όσα ειπώθηκαν. — <b>μεταμέλει</b>: μόνο απρόσωπο· δοτ. προσώπου <b>μοι</b> + γεν. <b>τῶν εἰρημένων</b>."},{"gr":"Οὐ χρή με ἐνθένδε ἀπελθεῖν πρίν ἄν δῶ δίκην.","an":"(τύπου Ξεν.) Δεν πρέπει εγώ να φύγω από εδώ προτού τιμωρηθώ. — <b>χρή</b> με αιτιατική προσώπου (<b>με</b>) = υποκείμενο του απαρεμφάτου <b>ἀπελθεῖν</b>, που είναι το υποκείμενο του χρή."},{"gr":"Δοκεῖ μοι ἀπιέναι.","an":"Μου φαίνεται καλό να αποχωρήσω / αποφασίζω να φύγω. — <b>δοκεῖ</b> εδώ απρόσωπο (όχι «φαίνεται»): υποκείμενό του το απαρέμφατο <b>ἀπιέναι</b>, με δοτική προσωπική <b>μοι</b>. Πρβλ. προσωπικό «οὗτος δοκεῖ σοφός εἶναι»."}],"table":{"title":"Συνοπτικός πίνακας απρόσωπων ρημάτων","cols":["Ρήμα","Σημασία","Κατηγορία / Σύνταξη"],"rows":[["δεῖ","πρέπει, είναι ανάγκη","μόνο απρόσωπο· + απαρέμφ., συχνά αιτ. προσώπου, ή δοτ.+γεν."],["χρή","πρέπει, είναι αναγκαίο","μόνο απρόσωπο· + απαρέμφ. + αιτιατική προσώπου"],["μέλει (μοι)","με νοιάζει","μόνο απρόσωπο· δοτ. προσώπου + γενική"],["μεταμέλει (μοι)","μετανοώ","μόνο απρόσωπο· δοτ. προσώπου + γενική"],["προσήκει","αρμόζει, είναι καθήκον","+ απαρέμφ. + δοτική προσωπική"],["ἔξεστι / πάρεστι / ἔνεστι","είναι δυνατό, επιτρέπεται","+ απαρέμφ. + δοτική προσωπική"],["δοκεῖ (μοι)","μου φαίνεται καλό, αποφασίζω","+ απαρέμφ. + δοτική προσωπική"],["συμβαίνει / τυγχάνει","συμβαίνει, τυχαίνει","+ απαρέμφ. ή ειδική πρόταση"],["συμφέρει / λυσιτελεῖ / ἀρκεῖ","συμφέρει, ωφελεί, αρκεί","+ απαρέμφ. + δοτική προσωπική"],["μέλλει","πρόκειται, είναι πιθανό","μόνο απρόσωπο· + απαρέμφ."],["λέγεται / ἀγγέλλεται / ὁμολογεῖται","λέγεται, αναγγέλλεται","παθητικά απρόσωπα· + ειδικό απαρέμφ. ή ειδική πρόταση"]]},"note":"Προσοχή στη διττή φύση: ρήματα όπως δοκεῖ, φαίνεται, συμφέρει, ἔξεστι είναι απρόσωπα ΜΟΝΟ όταν υποκείμενό τους είναι απαρέμφατο/πρόταση. Με ονομαστική υποκείμενο γίνονται προσωπικά (π.χ. «οὗτος δοκεῖ σοφός εἶναι» = αυτός φαίνεται σοφός — προσωπικό)."},{"h":"Απρόσωπες εκφράσεις (περιφράσεις)","body":"<p>Εκτός από τα απρόσωπα ρήματα, η αρχαία ελληνική σχηματίζει πλήθος <b>απρόσωπων εκφράσεων</b> (περιφραστικών απρόσωπων), που λειτουργούν συντακτικά ακριβώς όπως τα απρόσωπα ρήματα: παίρνουν υποκείμενο απαρέμφατο ή πρόταση και (συχνά) δοτική προσωπική. Σχηματίζονται με τρεις τρόπους:</p><h3>Α. ἐστί + ουδέτερο επιθέτου ή αφηρημένο ουσιαστικό</h3><p>Αυτή είναι η πιο πλούσια κατηγορία. Το <i>ἐστί</i> πολλές φορές παραλείπεται:</p><ul><li><b>ἀναγκαῖόν ἐστι, δέον ἐστί, χρεών ἐστι</b> = είναι ανάγκη, πρέπει</li><li><b>δυνατόν / οἷόν τέ ἐστι</b> = είναι δυνατό</li><li><b>καλόν / ἀγαθόν / αἰσχρόν ἐστι</b> = είναι καλό / ωραίο / αισχρό</li><li><b>δίκαιον / ὅσιον / θεμιτόν ἐστι</b> = είναι δίκαιο / όσιο / θεμιτό</li><li><b>ῥᾴδιον / χαλεπόν ἐστι</b> = είναι εύκολο / δύσκολο</li><li><b>εἰκός ἐστι</b> = είναι φυσικό / λογικό</li><li><b>δῆλον / φανερόν / ἄδηλόν ἐστι</b> = είναι φανερό / άδηλο</li><li><b>ἀνάγκη (ἐστί), ὥρα (ἐστί), καιρός (ἐστί), θέμις (ἐστί)</b> = είναι ανάγκη / ώρα / ευκαιρία / θεμιτό (ουσιαστικά ως κατηγορούμενα)</li></ul><h3>Β. ἔχει + τροπικό επίρρημα</h3><p>Το <i>ἔχει</i> + επίρρημα ισοδυναμεί με «είναι»:</p><ul><li><b>καλῶς / εὖ ἔχει</b> = είναι καλό, καλώς έχει</li><li><b>κακῶς / δεινῶς ἔχει</b> = είναι κακό, βρίσκεται σε άσχημη κατάσταση</li><li><b>ῥᾳδίως / χαλεπῶς ἔχει</b> = είναι εύκολο / δύσκολο</li><li><b>οὕτως ἔχει</b> = έτσι είναι</li></ul><h3>Γ. γ΄ ενικό ρηματικού επιθέτου σε -τέον</h3><p>Το <b>ρηματικό επίθετο σε -τέον</b> (ουδέτερο) + <i>ἐστί</i> εκφράζει αναγκαιότητα, ισοδύναμα με «πρέπει να...»:</p><ul><li><b>πρακτέον (ἐστί)</b> = πρέπει να πράξει κανείς</li><li><b>ἰτέον (ἐστί)</b> = πρέπει να πάει κανείς</li><li><b>πειστέον (ἐστί)</b> = πρέπει να υπακούσει κανείς</li></ul><p>Το ποιητικό αίτιο εδώ μπαίνει σε <b>δοτική (προσωπική του ποιητικού αιτίου)</b>: <i>ἡμῖν πρακτέον ἐστί</i> = εμείς πρέπει να πράξουμε.</p>","examples":[{"gr":"Ἀναγκαῖόν ἐστι τοῖς στρατιώταις μάχεσθαι.","an":"Είναι ανάγκη οι στρατιώτες να πολεμήσουν. — Απρόσωπη έκφραση <b>ἀναγκαῖόν ἐστι</b>. Υποκείμενο: <b>μάχεσθαι</b>. Δοτ. προσωπική: <b>τοῖς στρατιώταις</b>. Το <i>ἀναγκαῖον</i> είναι κατηγορούμενο στο απαρέμφατο-υποκείμενο."},{"gr":"Καλόν ἐστι τήν ἀλήθειαν λέγειν.","an":"Είναι καλό να λέει κανείς την αλήθεια. — <b>καλόν ἐστι</b>: απρόσωπη έκφραση. Υποκείμενο: <b>λέγειν</b>· αντικείμενο του απαρεμφάτου: <b>τήν ἀλήθειαν</b>."},{"gr":"Δῆλόν ἐστιν ὅτι οὐκ οἶδεν.","an":"Είναι φανερό ότι δεν γνωρίζει. — <b>δῆλόν ἐστι</b>: ΔΕΝ παίρνει απαρέμφατο, αλλά ειδική πρόταση (<b>ὅτι οὐκ οἶδεν</b>) ως υποκείμενο. Το ίδιο και τα φανερόν/ἄδηλόν ἐστι."},{"gr":"Ἡμῖν πειστέον ἐστί τοῖς ἄρχουσιν.","an":"Εμείς πρέπει να υπακούμε στους άρχοντες. — Ρηματικό επίθετο σε -τέον (<b>πειστέον</b>) + ἐστί = αναγκαιότητα. Δοτική του ποιητικού αιτίου: <b>ἡμῖν</b>· αντικείμενο: <b>τοῖς ἄρχουσιν</b>."},{"gr":"Καλῶς ἔχει παύσασθαι τοῦ πολέμου.","an":"Είναι καλό να σταματήσουμε τον πόλεμο. — Έκφραση <b>καλῶς ἔχει</b> (= είναι καλό). Υποκείμενο: το απαρέμφατο <b>παύσασθαι</b>."},{"gr":"Ἐμοί τοῦτο οὐ ποιητέον.","an":"Ξεν. Ἀνάβ. 1.3.15 — Αυτό δεν πρέπει να το κάνω εγώ. — Ρηματικό επίθετο σε -τέον (<b>ποιητέον</b>, εννοείται ἐστί) = αναγκαιότητα. Δοτική ποιητικού αιτίου: <b>ἐμοί</b>· υποκείμενο/αντικείμενο της πράξης: <b>τοῦτο</b>."},{"gr":"Εἰκός ἐστι τούς ἀγαθούς εὐδαιμονεῖν.","an":"Είναι φυσικό/λογικό οι καλοί να ευτυχούν. — Έκφραση <b>εἰκός ἐστι</b>· υποκείμενο το απαρέμφατο <b>εὐδαιμονεῖν</b>, με υποκείμενο απαρεμφάτου <b>τούς ἀγαθούς</b> (αιτ.)."}],"note":"Στις εκφράσεις με «ἐστί + ουδέτερο», το ουδέτερο επίθετο (καλόν, ἀναγκαῖον...) είναι ΚΑΤΗΓΟΡΟΥΜΕΝΟ· υποκείμενο παραμένει το απαρέμφατο/η πρόταση. Συχνά το ἐστί παραλείπεται και πρέπει να το εννοήσουμε."},{"h":"Το υποκείμενο του απρόσωπου ρήματος","body":"<p>Όπως είδαμε, το υποκείμενο ενός απρόσωπου ρήματος δεν είναι ποτέ όνομα/αντωνυμία σε ονομαστική. Είναι ένα από τα εξής:</p><h3>α) Άναρθρο απαρέμφατο (η πιο συχνή περίπτωση)</h3><p>Το απαρέμφατο, ως «ρηματικό ουσιαστικό», αναλαμβάνει τον ρόλο του υποκειμένου. Αναγνωρίζεται ρωτώντας «τι;» στο ρήμα. Μπορεί να είναι:</p><ul><li><b>Τελικό απαρέμφατο</b> — με τα ρήματα του πρέπειν/δύνασθαι/συμφέρειν (δεῖ, χρή, ἔξεστι, προσήκει, συμφέρει, δοκεῖ-αποφασίζω): δηλώνει επιδιωκόμενη πράξη.</li><li><b>Ειδικό απαρέμφατο</b> — με τα παθητικά λεκτικά/δοξαστικά (λέγεται, νομίζεται, ὁμολογεῖται, δοκεῖ-νομίζω): δηλώνει κρίση/περιεχόμενο.</li></ul><h3>β) Δευτερεύουσα ονοματική πρόταση</h3><p>Όταν το περιεχόμενο είναι σύνθετο, υποκείμενο γίνεται ολόκληρη πρόταση:</p><ul><li><b>Ειδική</b> (ὅτι, ὡς): με τα <i>ἀγγέλλεται, λέγεται, δῆλόν ἐστι, φανερόν ἐστι</i></li><li><b>Πλάγια ερωτηματική</b> (εἰ, ὅστις, πότερον...): με τα <i>ἄδηλόν ἐστι, ἀμφισβητεῖται</i></li><li><b>Ενδοιαστική</b> (μή, μή οὐ): με τα <i>κίνδυνός ἐστι, φόβος ἐστί, δεινόν ἐστι</i></li></ul><h3>γ) «Εσωτερικό» / αφηρημένο υποκείμενο (ιδιόρρυθμα)</h3><p>Σε ορισμένα απρόσωπα το υποκείμενο ενυπάρχει στην ίδια τη σημασία του ρήματος (cognate): <i>ὕει</i> (= ὑετός γίγνεται), <i>πολεμεῖται</i> (= πόλεμος γίγνεται). Δεν αναζητούμε εξωτερικό υποκείμενο.</p>","examples":[{"gr":"Προσήκει τοῖς νέοις τούς πρεσβυτέρους τιμᾶν.","an":"Αρμόζει στους νέους να τιμούν τους μεγαλύτερους. — Υποκείμενο του <b>προσήκει</b>: τελικό απαρέμφατο <b>τιμᾶν</b>. Υποκ. απαρεμφ.: <b>τούς νέους</b> (από τη δοτ. τοῖς νέοις)· αντικείμενο: <b>τούς πρεσβυτέρους</b>."},{"gr":"Λέγεται τόν Κῦρον ἀνδρεῖον εἶναι.","an":"Λέγεται ότι ο Κύρος είναι ανδρείος. — Υποκείμενο του παθητικού <b>λέγεται</b>: ΕΙΔΙΚΟ απαρέμφατο <b>εἶναι</b>. Υποκ. του εἶναι: <b>τόν Κῦρον</b>· κατηγορούμενο: <b>ἀνδρεῖον</b>."},{"gr":"Ἄδηλόν ἐστιν εἰ ἀφίξεται.","an":"Είναι άγνωστο αν θα έρθει. — Υποκείμενο της έκφρασης <b>ἄδηλόν ἐστι</b>: η πλάγια ερωτηματική πρόταση <b>εἰ ἀφίξεται</b>."},{"gr":"Κίνδυνός ἐστι μή ἡ πόλις ἁλῷ.","an":"Υπάρχει κίνδυνος μήπως κυριευθεί η πόλη. — Υποκείμενο της έκφρασης <b>κίνδυνός ἐστι</b>: η ενδοιαστική πρόταση <b>μή ἡ πόλις ἁλῷ</b>."},{"gr":"Δεῖ σ’ ἐλθεῖν.","an":"Smyth — Πρέπει εσύ να πας. — Υποκείμενο του <b>δεῖ</b>: το τελικό απαρέμφατο <b>ἐλθεῖν</b>· υποκείμενο του απαρεμφάτου σε αιτιατική: <b>σε</b>. Τυπικό παράδειγμα «άναρθρο απαρέμφατο ως υποκείμενο»."},{"gr":"Φανερόν ἦν ὅτι ἐγγύς που βασιλεύς ἐστιν.","an":"(τύπου Ξεν.) Ήταν φανερό ότι ο βασιλιάς ήταν κάπου κοντά. — Υποκείμενο της έκφρασης <b>φανερόν ἦν</b>: η ειδική πρόταση <b>ὅτι ... ἐστιν</b> (όχι απαρέμφατο)."}],"note":"Διάκριση κλειδί: δεῖ/χρή/ἔξεστι/προσήκει → τελικό απαρέμφατο. λέγεται/νομίζεται/ὁμολογεῖται → ειδικό απαρέμφατο. δῆλόν/φανερόν/ἄδηλόν ἐστι → δευτερεύουσα πρόταση (όχι απαρέμφατο)."},{"h":"Δοτική προσωπική και αιτιατική προσώπου","body":"<p>Δίπλα στο απρόσωπο ρήμα συχνά υπάρχει ένας όρος που δηλώνει <b>ποιο πρόσωπο αφορά</b> η πράξη — αυτός που πρέπει, μπορεί, του αρμόζει κ.λπ. Αυτός ο όρος είναι το <b>λογικό (νοηματικό) υποκείμενο</b> και ταυτόχρονα το <b>υποκείμενο του απαρεμφάτου</b>. Εμφανίζεται σε δύο πτώσεις:</p><h3>Α. Δοτική προσωπική</h3><p>Είναι η συνηθέστερη. Δηλώνει το πρόσωπο στο οποίο αναφέρεται το απρόσωπο. Τη συναντούμε με τα: <b>ἔξεστι, δοκεῖ, προσήκει, συμφέρει, λυσιτελεῖ, πρέπει, μέλει, μεταμέλει, ἀρκεῖ</b> και τις περισσότερες εκφράσεις (<i>ἀναγκαῖόν ἐστι, καλόν ἐστι...</i>) καθώς και με το ρηματικό επίθετο σε -τέον (δοτ. ποιητικού αιτίου).</p><h3>Β. Αιτιατική προσώπου</h3><p>Τη συναντούμε κατεξοχήν με τα <b>χρή</b> (πάντοτε) και <b>δεῖ</b> (συνήθως), αλλά και γενικά όταν το υποκείμενο του απαρεμφάτου δηλώνεται ρητά. Εδώ το πρόσωπο τίθεται σε αιτιατική ως κανονικό υποκείμενο του απαρεμφάτου.</p><h3>Η σχέση των δύο — μετατροπή</h3><p>Όταν υπάρχει <b>δοτική προσωπική</b>, αυτή λειτουργεί ταυτόχρονα και ως λογικό υποκείμενο του απαρεμφάτου. Στη μετάφραση/ανάλυση συχνά τη μετατρέπουμε νοερά σε <b>αιτιατική</b> (το κανονικό υποκείμενο του απαρεμφάτου): <i>ἐμοί προσήκει λέγειν</i> → υποκείμενο του <i>λέγειν</i> νοείται <i>ἐμέ</i>.</p><p><b>Ετεροπροσωπία:</b> στην απρόσωπη σύνταξη υπάρχει σχεδόν πάντοτε <b>ετεροπροσωπία</b> — δηλ. το υποκείμενο του απρόσωπου ρήματος (το απαρέμφατο) διαφέρει από το υποκείμενο του απαρεμφάτου (το πρόσωπο σε δοτ./αιτ.).</p>","examples":[{"gr":"Ἔδοξέ μοι τήν ἐπιστολήν πέμπειν.","an":"Αποφάσισα (μου φάνηκε καλό) να στείλω την επιστολή. — <b>ἔδοξε</b>: απρόσωπο. Υποκ.: <b>πέμπειν</b>. <b>Δοτική προσωπική</b>: <b>μοι</b> (= το λογικό υποκείμενο· υποκ. του πέμπειν νοείται ἐμέ). Αντικείμενο: <b>τήν ἐπιστολήν</b>."},{"gr":"Χρή τούς ἀγαθούς πολίτας τῇ πατρίδι βοηθεῖν.","an":"Πρέπει οι καλοί πολίτες να βοηθούν την πατρίδα. — <b>χρή</b>: παίρνει πάντοτε ΑΙΤΙΑΤΙΚΗ προσώπου. Υποκ. απαρεμφ. (βοηθεῖν): <b>τούς ἀγαθούς πολίτας</b> (αιτ.). Αντικείμενο: <b>τῇ πατρίδι</b>."},{"gr":"Δεῖ ἡμᾶς ἀνδρείως ἀγωνίζεσθαι.","an":"Πρέπει εμείς να αγωνιζόμαστε γενναία. — <b>δεῖ</b> με ΑΙΤΙΑΤΙΚΗ προσώπου (<b>ἡμᾶς</b>) = υποκ. του απαρεμφάτου <b>ἀγωνίζεσθαι</b>."},{"gr":"Συμφέρει τῇ πόλει τούς νόμους φυλάττεσθαι.","an":"Συμφέρει στην πόλη να τηρούνται οι νόμοι. — <b>συμφέρει</b> + <b>δοτική προσωπική τῇ πόλει</b>· υποκείμενο το απαρέμφατο <b>φυλάττεσθαι</b>· υποκ. του απαρεμφ.: <b>τούς νόμους</b>."},{"gr":"Ἔξεστί σοι μένειν.","an":"(τύπου Ξεν.) Σου επιτρέπεται / μπορείς να μείνεις. — <b>ἔξεστι</b> + <b>δοτική προσωπική σοι</b> (= το λογικό υποκείμενο)· υποκείμενο του ρήματος το απαρέμφατο <b>μένειν</b>."},{"gr":"Προσήκει σοι ταῦτα πράττειν.","an":"(τύπου ρητόρων) Αρμόζει σ’ εσένα να κάνεις αυτά. — <b>προσήκει</b> + <b>δοτική προσωπική σοι</b>· υποκείμενο το απαρέμφατο <b>πράττειν</b>, αντικείμενο <b>ταῦτα</b>· υποκ. απαρεμφάτου νοείται σε (αιτ.) από το σοι."}],"table":{"title":"Δοτική προσωπική ή αιτιατική προσώπου;","cols":["Απρόσωπο","Πτώση προσώπου","Παράδειγμα"],"rows":[["χρή","πάντοτε αιτιατική","χρή σέ μένειν"],["δεῖ","συνήθως αιτιατική (σπάν. δοτ.)","δεῖ σε μένειν / δεῖ σοι"],["ἔξεστι, πάρεστι","δοτική","ἔξεστί σοι μένειν"],["δοκεῖ, προσήκει, πρέπει","δοτική","δοκεῖ μοι, προσήκει σοι"],["συμφέρει, λυσιτελεῖ, ἀρκεῖ","δοτική","συμφέρει ἡμῖν"],["μέλει, μεταμέλει","δοτική (+ γενική πράγμ.)","μέλει μοι τῆς πόλεως"],["ρηματ. επίθ. -τέον","δοτική ποιητικού αιτίου","ἡμῖν πρακτέον"]]},"note":"Η δοτική προσωπική με απρόσωπο ρήμα είναι ταυτόχρονα το λογικό υποκείμενο της πράξης· γι' αυτό στη μετατροπή προς προσωπική σύνταξη γίνεται ονομαστική, ενώ ως υποκείμενο του απαρεμφάτου γίνεται αιτιατική."},{"h":"Μετατροπή προσωπικής ↔ απρόσωπης σύνταξης","body":"<p>Ένα από τα πιο τυπικά ζητούμενα στις ασκήσεις είναι η <b>μετατροπή</b> μιας πρότασης από προσωπική σε απρόσωπη σύνταξη και αντίστροφα. Η διαδικασία είναι μηχανική, αρκεί να κρατάμε σταθερό το νόημα.</p><h3>Α. Από προσωπική → απρόσωπη</h3><ol><li>Παίρνω το ρήμα της προσωπικής και το κάνω <b>απαρέμφατο</b>.</li><li>Το <b>υποκείμενο</b> (ονομαστική) της προσωπικής γίνεται <b>υποκείμενο του απαρεμφάτου σε αιτιατική</b> (ή δοτική προσωπική, ανάλογα με το απρόσωπο).</li><li>Προτάσσω ένα <b>απρόσωπο ρήμα/έκφραση</b> (δεῖ, χρή, προσήκει, ἀναγκαῖόν ἐστι...), ανάλογα με το νόημα.</li><li>Τα υπόλοιπα στοιχεία (αντικείμενα, προσδιορισμοί) μένουν ως έχουν.</li></ol><h3>Β. Από απρόσωπη → προσωπική</h3><ol><li>Το <b>απαρέμφατο</b> (υποκ. του απρόσωπου) γίνεται ρήμα σε προσωπικό τύπο.</li><li>Το <b>υποκείμενο του απαρεμφάτου</b> (αιτ. ή δοτ. προσωπική) γίνεται <b>ονομαστική — υποκείμενο του νέου ρήματος</b>, στο ίδιο πρόσωπο/αριθμό.</li><li>Το απρόσωπο ρήμα είτε <b>καταργείται</b> (αν ήταν απλό «πρέπει») είτε αποδίδεται με τροπικό/επιρρηματικό στοιχείο.</li></ol><h3>Ιδιαίτερη περίπτωση: τα δοξαστικά/λεκτικά (προσωπική παθητική)</h3><p>Με τα <i>λέγεται, νομίζεται, δοκεῖ, ἀγγέλλεται, ὁμολογεῖται</i> η αρχαία προτιμά τη <b>προσωπική παθητική σύνταξη</b>: το υποκείμενο του ειδικού απαρεμφάτου ανεβαίνει σε <b>ονομαστική</b> και γίνεται υποκείμενο του ρήματος, που πλέον συμφωνεί μαζί του. (Smyth: <i>Κῦρος ἠγγέλθη νικῆσαι</i> αντί <i>ἠγγέλθη Κῦρον νικῆσαι</i>.)</p>","examples":[{"gr":"Οἱ δικασταί τηροῦσι τούς νόμους.  →  Δεῖ τούς δικαστάς τηρεῖν τούς νόμους.","an":"Οι δικαστές τηρούν τους νόμους → Πρέπει οι δικαστές να τηρούν τους νόμους. — Προσωπική → απρόσωπη: ρήμα <i>τηροῦσι</i> → απαρέμφ. <b>τηρεῖν</b>· υποκ. <i>οἱ δικασταί</i> (ονομ.) → <b>τούς δικαστάς</b> (αιτ., υποκ. απαρεμφ.)· προτάσσεται το <b>δεῖ</b>."},{"gr":"Ἐμοί προσήκει λέγειν.  →  Ἐγώ προσήκω λέγειν.","an":"Πρέπει εγώ να μιλήσω → (προσωπικά) Εγώ αρμόζει να μιλήσω / Εγώ οφείλω να μιλήσω. — Απρόσωπη → προσωπική: η δοτική προσωπική <b>ἐμοί</b> γίνεται ονομαστική <b>ἐγώ</b> και το ρήμα προσαρμόζεται στο α΄ πρόσωπο."},{"gr":"Λέγεται τόν Σωκράτη σοφόν εἶναι.  →  Ὁ Σωκράτης λέγεται σοφός εἶναι.","an":"Λέγεται ότι ο Σωκράτης είναι σοφός → Ο Σωκράτης λέγεται (πως είναι) σοφός. — Απρόσωπη παθητική → προσωπική παθητική: το υποκ. του ειδικού απαρεμφ. (<b>τόν Σωκράτη</b>, αιτ.) ανεβαίνει σε ονομαστική (<b>ὁ Σωκράτης</b>) και γίνεται υποκείμενο του <b>λέγεται</b>· το κατηγορούμενο επίσης σε ονομαστική (<b>σοφός</b>)."},{"gr":"Νομίζεται τούς θεούς πάντα εἰδέναι.  →  Οἱ θεοί νομίζονται πάντα εἰδέναι.","an":"Νομίζεται ότι οι θεοί τα γνωρίζουν όλα → Οι θεοί νομίζονται ότι τα γνωρίζουν όλα. — Ίδια μετατροπή: αιτιατική (<b>τούς θεούς</b>) → ονομαστική (<b>οἱ θεοί</b>)· το ρήμα γίνεται πληθυντικός <b>νομίζονται</b>."},{"gr":"Κῦρος ἠγγέλθη νικῆσαι.","an":"Smyth §1982 — (προσωπική παθητική, η προτιμώμενη) Αναγγέλθηκε ότι ο Κύρος νίκησε. — Το υποκείμενο του ειδικού απαρεμφάτου ανέβηκε σε ονομαστική (<b>Κῦρος</b>) και έγινε υποκείμενο του <b>ἠγγέλθη</b>· ισοδ. απρόσωπο: «ἠγγέλθη Κῦρον νικῆσαι»."},{"gr":"Οἱ στρατιῶται ἐπαιδεύοντο.  →  Ἔδει τούς στρατιώτας παιδεύεσθαι.","an":"(τύπου ασκήσεως) Οι στρατιώτες εκπαιδεύονταν → Έπρεπε οι στρατιώτες να εκπαιδεύονται. — Προσωπική → απρόσωπη: ρήμα → απαρέμφ. <b>παιδεύεσθαι</b>· ονομαστική <i>οἱ στρατιῶται</i> → αιτιατική <b>τούς στρατιώτας</b> (υποκ. απαρεμφ.)· προτάσσεται το <b>ἔδει</b>."}],"note":"Η προσωπική παθητική σύνταξη (Κῦρος ἠγγέλθη νικῆσαι) είναι η προτιμώμενη στην αττική με λέγεται/νομίζεται/ἀγγέλλεται/δοκεῖ. Η απρόσωπη (ἠγγέλθη Κῦρον νικῆσαι) είναι ισοδύναμη αλλά λιγότερο συνηθισμένη."},{"h":"Απρόσωπη παθητική σύνταξη και μεθοδολογία αναγνώρισης","body":"<h3>Η απρόσωπη παθητική σύνταξη</h3><p>Πολλά παθητικά ρήματα στο γ΄ ενικό λειτουργούν απρόσωπα. Διακρίνονται σε δύο τύπους:</p><ul><li><b>Λεκτικά / δοξαστικά παθητικά</b> (<i>λέγεται, ἀγγέλλεται, ὁμολογεῖται, νομίζεται, πιστεύεται, ὁρᾶται</i>): παίρνουν υποκείμενο <b>ειδικό απαρέμφατο</b> ή <b>ειδική πρόταση</b> (ὅτι/ὡς). Π.χ. <i>ἀγγέλλεται ὅτι...</i> / <i>λέγεται τόν Κῦρον...εἶναι</i>. Συχνά μετατρέπονται σε προσωπική παθητική (βλ. προηγ. ενότητα).</li><li><b>Ιδιόρρυθμα παθητικά απρόσωπα</b> (cognate, χωρίς εξωτερικό υποκείμενο): το νόημα του υποκειμένου ενυπάρχει στο ρήμα. Π.χ. <i>πολεμεῖται</i> (= πόλεμος γίγνεται), <i>παρεσκεύασταί τινι</i> (= παρασκευή γεγένηταί τινι), <i>κεκινδύνευται</i>. Εδώ ΔΕΝ αναζητούμε υποκείμενο εκτός ρήματος· το ποιητικό αίτιο μπαίνει σε δοτική.</li></ul><h3>Μεθοδολογία αναγνώρισης — βήμα προς βήμα</h3><ol><li><b>Βρίσκω το ρήμα</b> και ελέγχω αν είναι στο <b>γ΄ ενικό</b>.</li><li><b>Ψάχνω ονομαστική υποκείμενο.</b> Αν υπάρχει όνομα/αντωνυμία σε ονομαστική που συμφωνεί με το ρήμα → <b>προσωπική</b>. Αν ΔΕΝ υπάρχει → υποψία απρόσωπης.</li><li><b>Ρωτώ «τι;» στο ρήμα.</b> Αν η απάντηση είναι απαρέμφατο ή πρόταση → <b>απρόσωπη σύνταξη</b>· αυτό είναι το υποκείμενο.</li><li><b>Εντοπίζω τη δοτική/αιτιατική προσώπου</b> (= λογικό υποκείμενο = υποκ. του απαρεμφάτου).</li><li><b>Αναλύω το απαρέμφατο</b>: υποκείμενό του, αντικείμενα, προσδιορισμούς.</li></ol><h3>Συχνά λάθη που πρέπει να αποφεύγονται</h3><ul><li>Να θεωρούμε υποκείμενο του απρόσωπου τη δοτική/αιτιατική προσώπου — ΛΑΘΟΣ· υποκείμενο είναι το απαρέμφατο/η πρόταση.</li><li>Να μπερδεύουμε το προσωπικό <i>δοκεῖ/φαίνεται</i> (με ονομαστική: «οὗτος δοκεῖ σοφός εἶναι») με το απρόσωπο («δοκεῖ μοι ἀπιέναι»).</li><li>Να περιμένουμε απαρέμφατο από τα <i>δῆλον/φανερόν/ἄδηλόν ἐστι</i> — αυτά παίρνουν πρόταση.</li></ul>","examples":[{"gr":"Ἠγγέλθη ὅτι ἡττημένοι εἶεν οἱ Λακεδαιμόνιοι.","an":"Αναγγέλθηκε ότι οι Λακεδαιμόνιοι είχαν νικηθεί. — Απρόσωπο παθητικό <b>ἠγγέλθη</b>· υποκείμενό του η ειδική πρόταση <b>ὅτι...εἶεν οἱ Λακεδαιμόνιοι</b>."},{"gr":"Παρεσκεύασται τοῖς πολεμίοις πρός μάχην.","an":"Έχουν κάνει προετοιμασίες οι εχθροί για μάχη (= έχει γίνει προετοιμασία από τους εχθρούς). — Ιδιόρρυθμο παθητικό απρόσωπο <b>παρεσκεύασται</b> (= παρασκευή γεγένηται)· δοτ. ποιητικού αιτίου <b>τοῖς πολεμίοις</b>· δεν υπάρχει εξωτερικό υποκείμενο."},{"gr":"Πολεμεῖται τοῖς Ἀθηναίοις πρός τούς Λακεδαιμονίους.","an":"Γίνεται πόλεμος από τους Αθηναίους εναντίον των Λακεδαιμονίων. — <b>πολεμεῖται</b> = «πόλεμος γίγνεται»· cognate ιδιόρρυθμο απρόσωπο, χωρίς εξωτερικό υποκείμενο· ποιητικό αίτιο σε δοτική <b>τοῖς Ἀθηναίοις</b>."},{"gr":"Ὁμολογεῖται τήν ἀρετήν ἄριστον εἶναι.","an":"Ομολογείται (γίνεται δεκτό) ότι η αρετή είναι το άριστο. — Λεκτικό παθητικό <b>ὁμολογεῖται</b>· υποκ. το ειδικό απαρέμφ. <b>εἶναι</b>· υποκ. του εἶναι σε αιτ. <b>τήν ἀρετήν</b>· κατηγ. <b>ἄριστον</b>. (Μετατρέπεται προσωπικά: <i>ἡ ἀρετή ὁμολογεῖται ἀρίστη εἶναι</i>.)"},{"gr":"Λέγεται Ἀρχέλαον τυραννῆσαι.","an":"(τύπου Πλάτ.) Λέγεται ότι ο Αρχέλαος έγινε τύραννος. — Λεκτικό παθητικό <b>λέγεται</b>· υποκ. το ειδικό απαρέμφ. <b>τυραννῆσαι</b>· υποκ. του απαρεμφ. σε αιτ. <b>Ἀρχέλαον</b>. (Προσωπικά: <i>Ἀρχέλαος λέγεται τυραννῆσαι</i>.)"},{"gr":"Δέδοκται τῇ βουλῇ τόν στρατηγόν αἱρεῖσθαι.","an":"(τύπου ψηφισμάτων) Έχει αποφασιστεί από τη βουλή να εκλεγεί ο στρατηγός. — Απρόσωπο παθητικό <b>δέδοκται</b> (παρακείμ. του δοκεῖ)· δοτ. ποιητ. αιτίου <b>τῇ βουλῇ</b>· υποκείμενο το απαρέμφατο <b>αἱρεῖσθαι</b>· υποκ. απαρεμφ. <b>τόν στρατηγόν</b> (αιτ.)."}],"note":"Χρυσός κανόνας ανάλυσης: «γ΄ ενικό + όχι ονομαστική + απάντηση στο τι; = απαρέμφατο/πρόταση» → απρόσωπη σύνταξη, με υποκείμενο το απαρέμφατο/την πρόταση και λογικό υποκείμενο τη δοτική/αιτιατική προσώπου."}]);
  T("syn-aparemfato-eidi", [{"h":"Τι είναι το απαρέμφατο — ο ρηματικός χαρακτήρας και ο ονοματικός χαρακτήρας","body":"<p>Το <b>απαρέμφατο</b> είναι ονοματικός (άκλιτος) τύπος του ρήματος· η ίδια η ονομασία του («α-παρέμφατο» = αυτό που δεν εμφαίνει, δεν δηλώνει πρόσωπο και αριθμό) φανερώνει τη φύση του. Είναι, με δύο λόγια, ένα <b>αφηρημένο ρηματικό ουσιαστικό ουδετέρου γένους</b>: από τη μια μεριά είναι <i>όνομα</i> (ουσιαστικό), από την άλλη <i>ρήμα</i>.</p><p>Ως <b>ρήμα</b> το απαρέμφατο διατηρεί όλα τα ρηματικά γνωρίσματα εκτός από το πρόσωπο και τον αριθμό:</p><ul><li>έχει <b>φωνή</b> (ενεργητική, μέση, παθητική): <i>λύειν – λύεσθαι</i>·</li><li>έχει <b>χρόνο</b>, που όμως δηλώνει ποιόν ενεργείας και όχι χρονική βαθμίδα (το ενεστωτικό απαρέμφατο = εξακολούθηση/διάρκεια, το αοριστικό = στιγμιαία/συνοπτική πράξη, το παρακειμενικό = συντελεσμένη)·</li><li>έχει <b>υποκείμενο</b> (σε ονομαστική ή σε αιτιατική, βλ. ταυτοπροσωπία/ετεροπροσωπία)·</li><li>συντάσσεται με <b>αντικείμενο</b> και <b>κατηγορούμενο</b>, παίρνει προσδιορισμούς και άρνηση όπως κάθε ρήμα.</li></ul><p>Ως <b>όνομα</b> (ουσιαστικό ουδέτερο) το απαρέμφατο μπορεί να επιτελεί όλες τις συντακτικές θέσεις ενός ουσιαστικού: υποκείμενο, αντικείμενο, κατηγορούμενο, προσδιορισμό, επεξήγηση, ακόμη και όρο εμπρόθετου συνόλου (όταν παίρνει άρθρο).</p><p>Με βάση δύο διαφορετικά κριτήρια το απαρέμφατο διακρίνεται:</p><ul><li><b>ως προς τη μορφή</b>: σε <i>έναρθρο</i> (με άρθρο) και <i>άναρθρο</i> (χωρίς άρθρο)·</li><li><b>ως προς τη σημασία/λειτουργία</b>: σε <i>ειδικό</i> και <i>τελικό</i> (η διάκριση αυτή αφορά το άναρθρο απαρέμφατο που λειτουργεί ως αντικείμενο ή υποκείμενο ρημάτων).</li></ul><p>Οι δύο αυτές διακρίσεις είναι ανεξάρτητες μεταξύ τους και θα μας απασχολήσουν διεξοδικά παρακάτω.</p>","examples":[{"gr":"βούλομαι λέγειν.","an":"Θέλω να μιλήσω. (το <i>λέγειν</i> έχει φωνή και ποιόν ενεργείας — ενεστωτικό = διάρκεια)"},{"gr":"τό ἀδικεῖν αἰσχρόν ἐστιν.","an":"Το να αδικεί κανείς είναι αισχρό. (έναρθρο, ως υποκείμενο — καθαρά ονοματική χρήση)"},{"gr":"νομίζω τούς θεούς πάντα ὁρᾶν.","an":"Νομίζω ότι οι θεοί τα βλέπουν όλα. (το απαρέμφατο <i>ὁρᾶν</i> έχει υποκείμενο σε αιτιατική <i>τούς θεούς</i> και αντικείμενο <i>πάντα</i> — πλήρης ρηματική σύνταξη)"},{"gr":"τό γάρ ἀδικεῖν τοῦ ἀδικεῖσθαι κάκιόν ἐστι.","an":"(τύπου Πλάτ. Γοργ.) Το να αδικεί κανείς είναι χειρότερο από το να αδικείται. (δύο έναρθρα απαρέμφατα ως αφηρημένα ουσιαστικά — φωνή ενεργ./παθ.· γεν. συγκριτική <i>τοῦ ἀδικεῖσθαι</i>)"},{"gr":"χαλεπόν ἐστι τό ἑαυτόν γνῶναι.","an":"(τύπου, πρβλ. «γνῶθι σαυτόν») Δύσκολο είναι το να γνωρίσει κανείς τον εαυτό του. (έναρθρο απαρ. αορ. <i>γνῶναι</i> με αντικ. <i>ἑαυτόν</i> — συνδυασμός ονοματικού και ρηματικού χαρακτήρα)"}],"note":"Προσοχή στην ορολογία: το «ποιόν ενεργείας». Ο χρόνος του απαρεμφάτου ΔΕΝ δηλώνει παρόν/παρελθόν/μέλλον (εκτός από το απαρέμφατο μέλλοντα και το δυνητικό), αλλά τον τρόπο με τον οποίο παρουσιάζεται η πράξη: εξακολουθητικά (ενεστ.), συνοπτικά (αόρ.), συντελεσμένα (παρακ.)."},{"h":"Ειδικό απαρέμφατο — η ισοδυναμία με ειδική πρόταση και τα ρήματα εξάρτησης","body":"<p>Το <b>ειδικό απαρέμφατο</b> είναι άναρθρο απαρέμφατο που ισοδυναμεί με <b>ειδική πρόταση</b>· δηλώνει δηλαδή μια κρίση, μια γνώμη ή μια διαπίστωση που θεωρείται (από τον ομιλητή ή από το υποκείμενο) αληθινή. Στη νεοελληνική μεταφράζεται με <b>ειδική πρόταση που εισάγεται με το «ότι» (ή «πως»)</b>.</p><p>Χαρακτηριστικά γνωρίσματα του ειδικού απαρεμφάτου:</p><ul><li>Μεταφράζεται με <b>«ότι / πως»</b>.</li><li>Παίρνει άρνηση <b>οὐ</b> (όπως και η ειδική πρόταση).</li><li>Εμφανίζεται σε όλους τους χρόνους, και κυρίως σε <b>απαρέμφατο μέλλοντα</b> (το οποίο είναι σχεδόν αποκλειστικό γνώρισμα του ειδικού), καθώς και σε <b>δυνητικό απαρέμφατο</b> (απαρέμφατο + <i>ἄν</i>).</li><li>Συντακτικά λειτουργεί συνήθως ως <b>αντικείμενο</b> (σπανιότερα ως υποκείμενο) του ρήματος εξάρτησης.</li></ul><p>Το ειδικό απαρέμφατο εξαρτάται από ρήματα που δηλώνουν <b>λόγο, γνώμη, σκέψη, αντίληψη ή γνώση</b>. Τα κυριότερα είναι:</p><ul><li><b>Λεκτικά</b> (ρήματα του λέγειν): <i>λέγω, φημί, λέγομαι, ὁμολογῶ, ἀποκρίνομαι, ἀγγέλλω, διδάσκω, ὑπισχνοῦμαι, ὄμνυμι, ἀρνοῦμαι, ἀπαγγέλλω, δηλῶ</i>.</li><li><b>Δοξαστικά / γνωστικά</b> (ρήματα γνώμης και σκέψης): <i>νομίζω, οἴομαι (οἶμαι), ἡγοῦμαι, δοκῶ (= νομίζω), ὑπολαμβάνω, ἐλπίζω, ὑποπτεύω, ὑπονοῶ, κρίνω</i>.</li><li><b>Αισθητικά / γνωστικά</b> (ρήματα αίσθησης και γνώσης, στη σημασία «πληροφορούμαι, μαθαίνω ότι»): <i>γιγνώσκω, πυνθάνομαι (= πληροφορούμαι), ἀκούω (= πληροφορούμαι), αἰσθάνομαι, οἶδα, μανθάνω, μέμνημαι</i>.</li><li><b>Απρόσωπα ρήματα και εκφράσεις</b> ανάλογης σημασίας: <i>λέγεται, ἀγγέλλεται, νομίζεται, δοκεῖ (μοι) = μου φαίνεται, δῆλόν ἐστι, φανερόν ἐστι, ὁμολογεῖταί</i> — εδώ το ειδικό απαρέμφατο είναι <b>υποκείμενο</b>.</li></ul>","examples":[{"gr":"οἱ πρέσβεις ἤγγειλαν βασιλέα οὐ παρέξεσθαι χρήματα.","an":"Οι πρέσβεις ανήγγειλαν ότι ο βασιλιάς δεν θα παρέχει χρήματα. (λεκτικό <i>ἤγγειλαν</i> + ειδικό απαρ. μέλλοντα <i>παρέξεσθαι</i>· άρνηση οὐ· ετεροπροσωπία: υποκ. <i>βασιλέα</i> σε αιτ.)"},{"gr":"νομίζω τήν ἀρετήν κτητήν εἶναι.","an":"Νομίζω ότι η αρετή αποκτάται. (δοξαστικό <i>νομίζω</i> + ειδικό απαρ. <i>εἶναι</i> με κατηγ. <i>κτητήν</i> σε αιτ. — ετεροπροσωπία)"},{"gr":"φησί γράψαι ταῦτα.","an":"Λέει / ισχυρίζεται ότι έγραψε αυτά. (λεκτικό <i>φησί</i> + ειδικό απαρ. αορ. <i>γράψαι</i> — ταυτοπροσωπία: εννοείται υποκ. αὐτός σε ονομ.)"},{"gr":"ἐλπίζω τούς πολεμίους νικήσειν.","an":"Ελπίζω ότι θα νικήσω τους εχθρούς. / Ελπίζω να νικήσω τους εχθρούς. (το <i>ἐλπίζω</i> με απαρ. μέλλοντα = ειδικό· αντικείμενο <i>τούς πολεμίους</i>)"},{"gr":"λέγεται τόν Κῦρον ἀποθανεῖν.","an":"Λέγεται ότι ο Κύρος πέθανε. (απρόσωπο <i>λέγεται</i> + ειδικό απαρ. ως υποκείμενο· υποκ. απαρ. <i>τόν Κῦρον</i> σε αιτ.)"},{"gr":"φησί Κῦρον νικᾶν.","an":"(Smyth, Greek Grammar §2018 — παράδειγμα της σύνταξης) Λέει ότι ο Κύρος νικά. (η κύρια πρόταση «Κῦρος νικᾷ» γίνεται αντικείμενο του <i>φησί</i> ως ειδικό απαρ.· υποκ. <i>Κῦρον</i> αιτ.)"},{"gr":"οὐ νομίζω τούτους εἶναι θεούς.","an":"(τύπου, πρβλ. κατηγορίες περί ασέβειας) Δεν νομίζω ότι αυτοί είναι θεοί. (δοξαστικό <i>νομίζω</i> με προτακτική άρνηση οὐ· ειδικό απαρ. <i>εἶναι</i> — διαγνωστικό η άρνηση οὐ)"},{"gr":"οἶμαι γάρ ἄν οὐκ ἀχαρίστως μοι ἔχειν.","an":"(Ξεν. Ἀνάβ. 2.3.18 — Ξενοφών) Νομίζω ότι δεν θα ήταν αχάριστο για μένα. (δοξαστικό <i>οἶμαι</i> + ειδικό δυνητικό απαρ. <i>ἄν ... ἔχειν</i> — το <i>ἄν</i> + απαρ. δείχνει ειδικό)"}],"table":{"title":"Ρήματα εξάρτησης του ΕΙΔΙΚΟΥ απαρεμφάτου","cols":["Κατηγορία","Σημασία","Χαρακτηριστικά ρήματα"],"rows":[["Λεκτικά","λέγω, διακηρύσσω","λέγω, φημί, ὁμολογῶ, ἀγγέλλω, ἀποκρίνομαι, ὄμνυμι, ὑπισχνοῦμαι, ἀρνοῦμαι"],["Δοξαστικά","νομίζω, σκέπτομαι","νομίζω, οἴομαι, ἡγοῦμαι, δοκῶ (=νομίζω), ἐλπίζω, ὑπολαμβάνω, ὑποπτεύω, κρίνω"],["Αισθητικά–γνωστικά","αντιλαμβάνομαι, μαθαίνω","γιγνώσκω, πυνθάνομαι, ἀκούω, αἰσθάνομαι, οἶδα, μανθάνω, μέμνημαι"],["Απρόσωπα","λέγεται/φαίνεται ότι","λέγεται, ἀγγέλλεται, νομίζεται, δοκεῖ (μοι), δῆλόν/φανερόν ἐστι"]]},"note":"Παγίδα: το ρήμα δοκῶ έχει ΔΥΟ συντάξεις. (α) δοκῶ = «νομίζω» → ειδικό απαρ. (δοκῶ τοῦτο ἀληθές εἶναι). (β) δοκῶ / δοκεῖ μοι = «μου φαίνεται σωστό, αποφασίζω» → τελικό απαρ. Επίσης το ἐλπίζω, ὑπισχνοῦμαι, ὄμνυμι, ἀπειλῶ συντάσσονται κανονικά με απαρ. μέλλοντα (ειδικό), επειδή δηλώνουν προσδοκία/μελλοντική πράξη."},{"h":"Τελικό απαρέμφατο — η ισοδυναμία με βουλητική/τελική πρόταση και τα ρήματα εξάρτησης","body":"<p>Το <b>τελικό απαρέμφατο</b> είναι άναρθρο απαρέμφατο που ισοδυναμεί με <b>βουλητική πρόταση</b> (ή με πρόταση επιθυμίας/σκοπού). Δηλώνει κάτι <i>επιθυμητό, επιδιωκόμενο, ζητούμενο</i> — όχι μια διαπίστωση αλλά μια θέληση, μια προτροπή, έναν σκοπό. Στη νεοελληνική μεταφράζεται με <b>«να»</b>.</p><p>Χαρακτηριστικά γνωρίσματα του τελικού απαρεμφάτου:</p><ul><li>Μεταφράζεται με <b>«να»</b>.</li><li>Παίρνει άρνηση <b>μή</b> (όπως και η βουλητική πρόταση).</li><li>Δεν τίθεται σε χρόνο μέλλοντα (δηλώνει επιθυμία, που είναι στραμμένη στο μέλλον, και άρα χρησιμοποιεί ενεστώτα ή αόριστο = ποιόν ενεργείας, όχι χρονική βαθμίδα).</li><li>Συντακτικά λειτουργεί ως <b>αντικείμενο</b> (στα προσωπικά ρήματα) ή ως <b>υποκείμενο</b> (στα απρόσωπα ρήματα και εκφράσεις).</li></ul><p>Το τελικό απαρέμφατο εξαρτάται από ρήματα που δηλώνουν <b>θέληση, επιθυμία, προτροπή, παρακίνηση, εμπόδιο, δυνατότητα, προσπάθεια</b>. Τα κυριότερα είναι:</p><ul><li><b>Βουλητικά</b> (θέλησης/επιθυμίας): <i>βούλομαι, ἐθέλω (θέλω), ἐπιθυμῶ, εὔχομαι, δέομαι (= παρακαλώ), ὀρέγομαι, ποθῶ</i>.</li><li><b>Κελευστικά / προτρεπτικά</b> (προσταγής, παρακίνησης, συμβουλής): <i>κελεύω, προστάττω, παραινῶ, συμβουλεύω, πείθω, παρακαλῶ, παρακελεύομαι, δέομαι, ἀξιῶ, αἰτῶ, ἱκετεύω, κηρύττω, διδάσκω (= μαθαίνω σε κάποιον)</i>.</li><li><b>Κωλυτικά / απαγορευτικά</b> (εμποδίου): <i>κωλύω, ἀπαγορεύω, εἴργω, ἀπείργω, ἀποτρέπω, παύω, φοβοῦμαι (μή)</i>· σε αυτά συχνά προστίθεται περιττή («παραπληρωματική») άρνηση μή.</li><li><b>Δυνητικά / παρακελευσματικά</b> (δυνατότητας, ικανότητας, καταλληλότητας): <i>δύναμαι, ἔχω (= μπορώ), οἷός τέ εἰμι, ἐπίσταμαι, μέλλω, εἴωθα</i>.</li><li><b>Πειρατικά</b> (προσπάθειας): <i>πειρῶμαι, σπεύδω, σπουδάζω, μηχανῶμαι, παρασκευάζομαι</i>.</li><li><b>Απρόσωπα ρήματα και εκφράσεις</b> που δηλώνουν αναγκαιότητα, καθήκον, δυνατότητα, αρμοδιότητα — εδώ το τελικό απαρ. είναι <b>υποκείμενο</b>: <i>δεῖ, χρή, πρέπει, προσήκει, ἔξεστι, οἷόν τέ ἐστι, ἀνάγκη ἐστί, καιρός ἐστι, ἄξιόν ἐστι, καλῶς ἔχει, δίκαιόν ἐστι</i>.</li></ul>","examples":[{"gr":"βούλομαι ὑμᾶς τήν ἀλήθειαν εἰδέναι.","an":"Θέλω εσείς να μάθετε την αλήθεια. (βουλητικό <i>βούλομαι</i> + τελικό απαρ. <i>εἰδέναι</i>· ετεροπροσωπία: υποκ. <i>ὑμᾶς</i>)"},{"gr":"συμβουλεύω ὑμῖν μή παραδιδόναι τά ὅπλα.","an":"Σας συμβουλεύω να μην παραδώσετε τα όπλα. (κελευστικό <i>συμβουλεύω</i> + τελικό απαρ.· άρνηση μή)"},{"gr":"κελεύει τούς στρατιώτας μάχεσθαι.","an":"Διατάζει τους στρατιώτες να πολεμούν. (κελευστικό <i>κελεύει</i>· αντικ. <i>τούς στρατιώτας</i> = υποκ. απαρεμφάτου)"},{"gr":"δεῖ τούς πολίτας τοῖς νόμοις πείθεσθαι.","an":"Πρέπει οι πολίτες να υπακούουν στους νόμους. (απρόσωπο <i>δεῖ</i> + τελικό απαρ. ως ΥΠΟΚΕΙΜΕΝΟ· υποκ. απαρ. <i>τούς πολίτας</i>)"},{"gr":"ἐκώλυον τούς πολεμίους μή διαβαίνειν τόν ποταμόν.","an":"Εμπόδιζαν τους εχθρούς να περάσουν το ποτάμι. (κωλυτικό <i>ἐκώλυον</i> + παραπληρωματική άρνηση μή)"},{"gr":"πειρῶμαι ὑμᾶς διδάσκειν.","an":"Προσπαθώ να σας διδάξω. (πειρατικό <i>πειρῶμαι</i> + τελικό απαρ.)"},{"gr":"ἐκέλευσεν εἰσελθεῖν τόν Ξενοφῶντα.","an":"(τύπου Ξεν. Ἀνάβ.) Διέταξε να μπει μέσα ο Ξενοφών. (κελευστικό <i>ἐκέλευσεν</i> + τελικό απαρ. αορ.· υποκ. απαρ. <i>τόν Ξενοφῶντα</i> σε αιτ.)"},{"gr":"οἱ στρατιῶται οὐκ ἤθελον ἰέναι.","an":"(τύπου Ξεν. Ἀνάβ. — πρβλ. «οὐκ ἰέναι ἤθελε») Οι στρατιώτες δεν ήθελαν να προχωρήσουν. (βουλητικό <i>ἤθελον</i> + τελικό απαρ. <i>ἰέναι</i>· η άρνηση οὐκ ανήκει στο ρήμα, όχι στο απαρ.)"},{"gr":"ἀνάγκη ἐστί πάντας ἀποθνῄσκειν.","an":"Είναι ανάγκη να πεθαίνουν όλοι. (απρόσωπη έκφραση <i>ἀνάγκη ἐστί</i> + τελικό απαρ. ως υποκείμενο· υποκ. απαρ. <i>πάντας</i> σε αιτ.)"}],"table":{"title":"Ρήματα εξάρτησης του ΤΕΛΙΚΟΥ απαρεμφάτου","cols":["Κατηγορία","Σημασία","Χαρακτηριστικά ρήματα"],"rows":[["Βουλητικά","θέλω, επιθυμώ","βούλομαι, ἐθέλω, ἐπιθυμῶ, εὔχομαι, ποθῶ, ὀρέγομαι"],["Κελευστικά/προτρεπτικά","διατάζω, συμβουλεύω, πείθω","κελεύω, προστάττω, παραινῶ, συμβουλεύω, πείθω, ἀξιῶ, αἰτῶ, δέομαι, ἱκετεύω"],["Κωλυτικά/απαγορευτικά","εμποδίζω, απαγορεύω","κωλύω, ἀπαγορεύω, εἴργω, ἀποτρέπω, παύω"],["Δυνητικά","μπορώ, γνωρίζω","δύναμαι, ἔχω(=μπορώ), οἷός τέ εἰμι, ἐπίσταμαι, μέλλω"],["Πειρατικά","προσπαθώ","πειρῶμαι, σπεύδω, σπουδάζω, μηχανῶμαι, παρασκευάζομαι"],["Απρόσωπα (απαρ.=υποκ.)","πρέπει, είναι ανάγκη","δεῖ, χρή, πρέπει, προσήκει, ἔξεστι, ἀνάγκη/καιρός/ἄξιόν ἐστι"]]},"note":"Κρίσιμη παγίδα — άρνηση: ΕΙΔΙΚΟ → οὐ, ΤΕΛΙΚΟ → μή. Είναι το ασφαλέστερο διαγνωστικό κριτήριο μαζί με τη μετάφραση («ότι» vs «να»). Δεύτερη παγίδα: μερικά ρήματα είναι «διπρόσωπα»: πείθω τινά λέγειν (=κελευστικό, τελικό) αλλά πείθομαι (=δοξαστικό «πιστεύω», ειδικό). Το ίδιο και το φοβοῦμαι: φοβοῦμαι μή ... (να μην) = τελικό/βουλητικό· αλλά «φοβᾶμαι ότι» απαντά κυρίως με πρόταση."},{"h":"Το υποκείμενο του απαρεμφάτου — ταυτοπροσωπία και ετεροπροσωπία","body":"<p>Επειδή το απαρέμφατο διατηρεί ρηματικό χαρακτήρα, έχει <b>δικό του υποκείμενο</b>. Το ποια πτώση παίρνει αυτό το υποκείμενο εξαρτάται από τη σχέση του με το υποκείμενο του ρήματος εξάρτησης. Διακρίνουμε δύο περιπτώσεις:</p><h3>1. Ταυτοπροσωπία</h3><p>Όταν το υποκείμενο του απαρεμφάτου είναι το <b>ίδιο (ταὐτό)</b> πρόσωπο με το υποκείμενο του ρήματος εξάρτησης, έχουμε <b>ταυτοπροσωπία</b>. Τότε το υποκείμενο του απαρεμφάτου:</p><ul><li><b>δεν επαναλαμβάνεται</b> (παραλείπεται ως ευκόλως εννοούμενο)·</li><li>νοείται σε <b>ονομαστική</b> πτώση (όπως το υποκείμενο του ρήματος)·</li><li>τα τυχόν <b>κατηγορούμενα ή επιθετικοί προσδιορισμοί</b> του μπαίνουν επίσης σε <b>ονομαστική</b>.</li></ul><p>π.χ. <i>ὁ στρατηγός νομίζει σοφός εἶναι</i> — εδώ υποκ. του <i>εἶναι</i> εννοείται «αὐτός» (= ο στρατηγός), και το κατηγορούμενο <i>σοφός</i> είναι ονομαστική.</p><h3>2. Ετεροπροσωπία</h3><p>Όταν το υποκείμενο του απαρεμφάτου είναι <b>διαφορετικό (ἕτερο)</b> από το υποκείμενο του ρήματος εξάρτησης, έχουμε <b>ετεροπροσωπία</b>. Τότε το υποκείμενο του απαρεμφάτου:</p><ul><li><b>εκφέρεται κανονικά</b> και μπαίνει σε <b>αιτιατική</b>·</li><li>τα κατηγορούμενα και οι προσδιορισμοί του ακολουθούν, μπαίνοντας κι αυτά σε <b>αιτιατική</b>.</li></ul><p>π.χ. <i>νομίζω τόν στρατηγόν σοφόν εἶναι</i> — υποκ. του <i>εἶναι</i> = <i>τόν στρατηγόν</i> (αιτ.), κατηγ. <i>σοφόν</i> (αιτ.).</p><h3>3. Απρόσωπη σύνταξη</h3><p>Στα <b>απρόσωπα ρήματα και εκφράσεις</b> (δεῖ, χρή, ἔξεστι, δοκεῖ, λέγεται...) το απαρέμφατο είναι <b>υποκείμενο</b> του ρήματος. Το δικό του υποκείμενο μπαίνει σε <b>αιτιατική</b>· αν όμως υπάρχει δοτική προσωπική (δοτική του ενεργούντος προσώπου ή του κρίνοντος), το υποκείμενο του απαρεμφάτου μπορεί κατ' <b>έλξη</b> να τεθεί σε δοτική.</p><p>π.χ. <i>ἔξεστιν ὑμῖν εὐδαίμοσι εἶναι</i> (κατ' έλξη δοτική <i>εὐδαίμοσι</i>) δίπλα στο κανονικό <i>ἔξεστιν ὑμᾶς εὐδαίμονας εἶναι</i>.</p>","examples":[{"gr":"ὁμολογῶ ἀδικεῖν.","an":"Ομολογώ ότι αδικώ. (ΤΑΥΤΟΠΡΟΣΩΠΙΑ — υποκ. απαρ. εννοείται «ἐγώ» σε ονομ.)"},{"gr":"ὁμολογῶ σε δίκαιον εἶναι.","an":"Ομολογώ ότι εσύ είσαι δίκαιος. (ΕΤΕΡΟΠΡΟΣΩΠΙΑ — υποκ. απαρ. <i>σε</i> σε αιτ., κατηγ. <i>δίκαιον</i> σε αιτ.)"},{"gr":"οἱ Ἀθηναῖοι ἔφασαν ἐλεύθεροι εἶναι.","an":"Οι Αθηναίοι έλεγαν ότι είναι ελεύθεροι. (ταυτοπροσωπία — κατηγ. <i>ἐλεύθεροι</i> σε ονομ., σε συμφωνία με το εννοούμενο ονομαστικό υποκείμενο)"},{"gr":"δεῖ τόν στρατιώτην ἀνδρεῖον εἶναι.","an":"Πρέπει ο στρατιώτης να είναι ανδρείος. (απρόσωπο <i>δεῖ</i>· υποκ. απαρ. <i>τόν στρατιώτην</i> σε αιτ., κατηγ. <i>ἀνδρεῖον</i> σε αιτ.)"},{"gr":"ἔξεστι τοῖς πολίταις (κατ' ἔλξιν) ἐλευθέροις εἶναι.","an":"Επιτρέπεται στους πολίτες να είναι ελεύθεροι. (έλξη του υποκ. του απαρ. σε δοτική <i>τοῖς πολίταις</i>, άρα και κατηγ. <i>ἐλευθέροις</i> σε δοτ.)"},{"gr":"νομίζω ταῦτα ἀληθῆ εἶναι.","an":"Νομίζω ότι αυτά είναι αληθινά. (ΕΤΕΡΟΠΡΟΣΩΠΙΑ — υποκ. απαρ. <i>ταῦτα</i> σε αιτ. ουδ., κατηγ. <i>ἀληθῆ</i> σε αιτ.)"},{"gr":"οἴεται σοφός εἶναι.","an":"(τύπου Πλάτ., πρβλ. Ἀπολ.) Νομίζει ότι είναι σοφός. (ΤΑΥΤΟΠΡΟΣΩΠΙΑ — υποκ. απαρ. εννοείται «αὐτός» σε ονομ., κατηγ. <i>σοφός</i> σε ονομ.)"}],"note":"Στην ταυτοπροσωπία ΠΟΤΕ δεν βάζουμε το υποκείμενο του απαρεμφάτου σε αιτιατική: λάθος *νομίζω ἐμαυτόν σοφόν εἶναι* όταν εννοείται απλώς «εγώ». Το κατηγορούμενο μάς προδίδει την πτώση: ονομαστικό κατηγ. = ταυτοπροσωπία, αιτιατικό κατηγ. = ετεροπροσωπία. Στη σύνταξη γράφουμε: «υποκείμενο του απαρεμφάτου, ενν. αὐτός (ονομαστική) λόγω ταυτοπροσωπίας»."},{"h":"Το άναρθρο απαρέμφατο — όλες οι συντακτικές χρήσεις","body":"<p>Το <b>άναρθρο απαρέμφατο</b> (χωρίς άρθρο) επιτελεί πλήθος συντακτικών λειτουργιών. Τις κατατάσσουμε ως εξής:</p><h3>α) Ως υποκείμενο</h3><p>Κυρίως με <b>απρόσωπα ρήματα και απρόσωπες εκφράσεις</b> (δεῖ, χρή, πρέπει, ἔξεστι, δοκεῖ, ἀνάγκη ἐστί, καλόν ἐστι...). Εδώ ανήκει και το ειδικό απαρ. ως υποκ. του λέγεται κ.τ.ό.</p><h3>β) Ως αντικείμενο</h3><p>Με τα προσωπικά μεταβατικά ρήματα εξάρτησης (βουλητικά, κελευστικά, λεκτικά, δοξαστικά κ.λπ.). Εδώ ανήκουν το ειδικό και το τελικό απαρ. ως αντικείμενα.</p><h3>γ) Ως κατηγορούμενο ή κατηγορηματικός προσδιορισμός</h3><p>Συνήθως με το <i>εἰμί</i> ή ρήμα συνδετικό, όταν το υποκείμενο είναι κι αυτό απαρέμφατο ή αφηρημένη έννοια.</p><h3>δ) Ως επεξήγηση</h3><p>Επεξηγεί προηγούμενο όρο (συνήθως δεικτική αντωνυμία τοῦτο, ή ουσιαστικό όπως ὥρα, καιρός).</p><h3>ε) Απαρέμφατο του σκοπού (τελικό-αναφορικό)</h3><p>Μετά από ρήματα <b>κίνησης, εκλογής, δόσης, παράδοσης</b> (δίδωμι, παρέχω, αἱροῦμαι, πέμπω, λαμβάνω, καταλείπω), δηλώνει τον <b>σκοπό</b> για τον οποίο γίνεται κάτι· μεταφράζεται «για να».</p><h3>στ) Απαρέμφατο της αναφοράς</h3><p>Προσδιορίζει κατά τι ισχύει ένα <b>επίθετο</b> (κυρίως θαυμαστός, δεινός, ἱκανός, ἄξιος, χαλεπός, ῥᾴδιος, αἰσχρός, καλός, ἀγαθός) ή ένα ουσιαστικό· είναι το αντίστοιχο της αιτιατικής/δοτικής της αναφοράς, σε μορφή απαρεμφάτου. Μεταφράζεται «ως προς το να, στο να».</p><h3>ζ) Απαρέμφατο του αποτελέσματος (συμπερασματικό)</h3><p>Εισάγεται κυρίως με το <b>ὥστε</b> (σπανιότερα ὡς) και δηλώνει το <b>ενδεχόμενο/δυνατό αποτέλεσμα</b> (σε αντίθεση με το ὥστε + οριστική, που δηλώνει το πραγματικό). Συχνά προηγείται δεικτικό «τόσο» (οὕτω, τοσοῦτος, τηλικοῦτος). Άρνηση μή.</p>","examples":[{"gr":"καλόν ἐστι τό ἀποθνῄσκειν ὑπέρ τῆς πατρίδος.","an":"Είναι ωραίο να πεθαίνει κανείς για την πατρίδα. (άναρθρο/εδώ έναρθρο ως ΥΠΟΚΕΙΜΕΝΟ — το αντίστοιχο άναρθρο: <i>καλόν ἐστιν ἀποθνῄσκειν...</i>)"},{"gr":"ἔδωκεν αὐτοῖς τήν πόλιν φυλάττειν.","an":"Τους έδωσε την πόλη για να τη φυλάγουν. (ΑΠΑΡΕΜΦΑΤΟ ΤΟΥ ΣΚΟΠΟΥ μετά από ρήμα δόσης)"},{"gr":"εἵλοντο αὐτόν στρατηγεῖν.","an":"Τον εξέλεξαν για να είναι στρατηγός / να στρατηγεί. (απαρ. σκοπού μετά από ρήμα εκλογής <i>αἱροῦμαι</i>)"},{"gr":"θαυμαστός τό μέγεθος καί δεινός ἰδεῖν.","an":"Θαυμαστός ως προς το μέγεθος και φοβερός στο να τον βλέπει κανείς (στην όψη). (ΑΠΑΡΕΜΦΑΤΟ ΤΗΣ ΑΝΑΦΟΡΑΣ στο επίθετο <i>δεινός</i>)"},{"gr":"ῥᾴδιον γνῶναι.","an":"Εύκολο να το καταλάβει κανείς / στο να γνωρίσει. (απαρ. αναφοράς στο επίθ. <i>ῥᾴδιον</i>)"},{"gr":"οὕτως ἀνόητος ἦν ὥστε ταῦτα ποιεῖν.","an":"Ήταν τόσο ανόητος ώστε να κάνει αυτά. (ΑΠΑΡΕΜΦΑΤΟ ΤΟΥ ΑΠΟΤΕΛΕΣΜΑΤΟΣ, ὥστε + απαρ.· άρν. μή)"},{"gr":"τοῦτο μόνον αἰσχρόν ἐστι, τό ψεύδεσθαι.","an":"Αυτό μόνο είναι αισχρό, το να λέει κανείς ψέματα. (ΕΠΕΞΗΓΗΣΗ στο <i>τοῦτο</i>)"},{"gr":"ἦλθον μαθεῖν.","an":"(τύπου Ξεν.) Ήρθα για να μάθω. (ΑΠΑΡΕΜΦΑΤΟ ΤΟΥ ΣΚΟΠΟΥ μετά από ρήμα κίνησης <i>ἦλθον</i>· αοριστικό = συνοπτικό ποιόν)"},{"gr":"οὕτω σοφός ἐστιν ὥστε πάντας διδάσκειν δύνασθαι.","an":"(τύπου) Είναι τόσο σοφός ώστε να μπορεί να διδάσκει όλους. (απαρ. αποτελέσματος με ὥστε — δηλώνει ενδεχόμενη/φυσική συνέπεια· προηγείται δεικτικό <i>οὕτω</i>)"},{"gr":"ἄξιός ἐστι θαυμάζεσθαι.","an":"(τύπου) Είναι άξιος να θαυμάζεται. (ΑΠΑΡΕΜΦΑΤΟ ΤΗΣ ΑΝΑΦΟΡΑΣ στο επίθ. <i>ἄξιος</i>· παθητικό απαρ. <i>θαυμάζεσθαι</i>)"}],"note":"Διάκριση ὥστε + απαρ. / ὥστε + οριστική: το απαρέμφατο δηλώνει αποτέλεσμα ΕΝΔΕΧΟΜΕΝΟ, φυσική/λογική συνέπεια, χωρίς να βεβαιώνεται ότι έγινε (άρν. μή)· η οριστική δηλώνει αποτέλεσμα ΠΡΑΓΜΑΤΙΚΟ που όντως συνέβη (άρν. οὐ). π.χ. οὕτω σοφός ἐστιν ὥστε πάντας διδάσκειν (ικανός να...) vs οὕτω σοφός ἐστιν ὥστε πάντας ἐδίδαξεν (και πράγματι τους δίδαξε)."},{"h":"Το έναρθρο απαρέμφατο — το απαρέμφατο ως καθαρό ουσιαστικό","body":"<p>Το <b>έναρθρο απαρέμφατο</b> παίρνει μπροστά του το <b>άρθρο του ουδετέρου γένους</b> και κλίνεται, ως προς το άρθρο, σε όλες τις πτώσεις του ενικού (πλην κλητικής): <i>τό λέγειν, τοῦ λέγειν, τῷ λέγειν, τό λέγειν</i>. Έτσι λειτουργεί όπως ένα <b>πλήρες πτωτικό ουσιαστικό</b> και μπορεί να επιτελεί όλες τις θέσεις που επιτελεί ένα ουσιαστικό σε κάθε πτώση. Διατηρεί ωστόσο τον ρηματικό χαρακτήρα του (έχει υποκείμενο, αντικείμενο, προσδιορισμούς). Η άρνησή του είναι κατά κανόνα <b>μή</b> (γιατί έχει υποθετική/γενική σημασία: «το να μην...»).</p><h3>Κατά πτώση χρήσεις</h3><ul><li><b>Ονομαστική (τό + απαρ.)</b>: ως <b>υποκείμενο</b> ή <b>κατηγορούμενο</b>.</li><li><b>Αιτιατική (τό + απαρ.)</b>: ως <b>αντικείμενο</b> ρήματος, ως <b>αιτιατική της αναφοράς</b>, ή ως όρος εμπρόθετου (π.χ. <i>διά τό..., εἰς τό..., πρός τό..., κατά τό...</i>).</li><li><b>Γενική (τοῦ + απαρ.)</b>: ως κάθε είδους γενική προσδιοριστική — <b>γενική υποκειμενική, αντικειμενική, διαιρετική, της αιτίας, της αξίας, του σκοπού</b>· ως όρος εμπρόθετου (<i>πρό τοῦ..., ἀντί τοῦ..., ἕνεκα τοῦ..., διά τοῦ...</i>)· και ως <b>γενική του σκοπού</b> («για να», ισοδύναμη με τελική πρόταση).</li><li><b>Δοτική (τῷ + απαρ.)</b>: ως <b>δοτική της αιτίας, του τρόπου, του μέσου/οργάνου, της αναφοράς</b>· ως όρος εμπρόθετου (<i>ἐν τῷ..., σύν τῷ...</i> → χρονική/τροπική σημασία).</li></ul><p>Το έναρθρο απαρέμφατο είναι ιδιαίτερα αγαπητό στον φιλοσοφικό και ρητορικό λόγο (Πλάτων, Δημοσθένης, Θουκυδίδης), γιατί επιτρέπει να μετατραπεί ολόκληρη μια πράξη σε αφηρημένη έννοια-ουσιαστικό.</p>","examples":[{"gr":"τό λακωνίζειν ἐστί φιλοσοφεῖν.","an":"Το να μιμείται κανείς τους Λάκωνες είναι το να φιλοσοφεί. (υποκ. <i>τό λακωνίζειν</i> — ονομαστική· κατηγ. <i>φιλοσοφεῖν</i>)"},{"gr":"τοῦ πιεῖν ἐπιθυμία.","an":"Η επιθυμία του να πιει κανείς. (γενική αντικειμενική, <i>τοῦ πιεῖν</i> στο ουσ. <i>ἐπιθυμία</i>)"},{"gr":"διά τό ξένος εἶναι οὐκ ἄν ἠδικήθη.","an":"Λόγω του ότι ήταν ξένος δεν θα αδικούνταν. (εμπρόθετος της αιτίας, <i>διά τό ... εἶναι</i>)"},{"gr":"ἐν τῷ λέγειν.","an":"Κατά τη διάρκεια του να μιλά κανείς / ενώ μιλούσε. (εμπρόθετος χρονικός, <i>ἐν τῷ</i> + απαρ.)"},{"gr":"πρό τοῦ μάχεσθαι.","an":"Πριν από τη μάχη / πριν αρχίσει να πολεμά. (εμπρόθετος χρονικός, <i>πρό τοῦ</i> + απαρ.)"},{"gr":"τοῦ μή διαφεύγειν ἕνεκα.","an":"Με σκοπό να μη διαφύγουν. (γενική του σκοπού με άρνηση μή· συνάπτεται και με <i>ἕνεκα</i>)"},{"gr":"τῷ πονεῖν κρατοῦσι τῶν ἐχθρῶν.","an":"Με το να κοπιάζουν / χάρη στον κόπο τους νικούν τους εχθρούς. (δοτική του μέσου/τρόπου, <i>τῷ πονεῖν</i>)"},{"gr":"τό γνῶναι ἐπιστήμην που λαβεῖν ἐστιν.","an":"(τύπου Πλάτ. Θεαίτ.) Το να γνωρίσει κανείς είναι, κατά κάποιον τρόπο, να αποκτήσει γνώση. (έναρθρο απαρ. <i>τό γνῶναι</i> ως υποκείμενο σε ονομαστική)"},{"gr":"εἰς τό κωλύειν τόν Φίλιππον.","an":"(τύπου Δημ.) Με σκοπό το να εμποδίσει κανείς τον Φίλιππο. (εμπρόθετος του σκοπού <i>εἰς τό</i> + απαρ. με αντικ. <i>τόν Φίλιππον</i>)"}],"table":{"title":"Έναρθρο απαρέμφατο: πτώση → συντακτικός ρόλος","cols":["Πτώση άρθρου","Κύριες λειτουργίες","Παράδειγμα"],"rows":[["τό (ονομ.)","υποκείμενο, κατηγορούμενο","τό ἀδικεῖν αἰσχρόν ἐστιν"],["τό (αιτ.)","αντικείμενο, αιτ. αναφοράς, εμπρόθετος (διά/εἰς/πρός/κατά τό)","διά τό θαρρεῖν"],["τοῦ (γεν.)","γεν. υποκ./αντικ./αιτίας/αξίας/σκοπού, εμπρόθετος (πρό/ἀντί/ἕνεκα τοῦ)","ἐπιθυμία τοῦ μανθάνειν"],["τῷ (δοτ.)","δοτ. αιτίας/τρόπου/μέσου/αναφοράς, εμπρόθετος (ἐν/σύν τῷ)","ἐν τῷ φρονεῖν"]]},"note":"Προσοχή στη διάκριση άρθρου από αναφορική/άλλη χρήση: όταν βλέπεις «τοῦ + απαρέμφατο» χωρίς προηγούμενο όρο που να ζητά γενική, είναι πιθανότατα ΓΕΝΙΚΗ ΤΟΥ ΣΚΟΠΟΥ (= ἵνα/ὅπως + υποτ.), συχνά με άρνηση μή. Η άρνηση του έναρθρου απαρεμφάτου είναι σχεδόν πάντοτε μή, ανεξάρτητα αν προέρχεται από ειδικό ή τελικό περιεχόμενο, γιατί έχει γενικευτική/αφηρημένη σημασία."},{"h":"Το απόλυτο απαρέμφατο και το απαρέμφατο αντί προστακτικής","body":"<p>Σε ορισμένες περιπτώσεις το απαρέμφατο εμφανίζεται <b>χωρίς να εξαρτάται</b> από κανένα ρήμα και χωρίς να επιτελεί κάποια από τις συνηθισμένες ονοματικές θέσεις. Οι κυριότερες τέτοιες χρήσεις είναι:</p><h3>1. Το απόλυτο (παρενθετικό) απαρέμφατο</h3><p>Πρόκειται για <b>στερεότυπες εκφράσεις</b> που μπαίνουν παρενθετικά για να περιορίσουν ή να μετριάσουν τη βεβαιότητα μιας κρίσης· λειτουργούν ως <b>επιρρηματικοί προσδιορισμοί της αναφοράς ή του ποσού</b>. Είναι «απόλυτα» γιατί δεν συνδέονται συντακτικά με τον υπόλοιπο λόγο. Τα πιο συχνά:</p><ul><li><b>ὡς ἔπος εἰπεῖν</b> = για να το πω έτσι, σχεδόν, ούτως ειπείν·</li><li><b>ὡς συνελόντι εἰπεῖν / ὡς ἐν κεφαλαίῳ εἰπεῖν</b> = με λίγα λόγια, συνοπτικά·</li><li><b>ὡς εἰπεῖν / ὡς εἰκάσαι</b> = για να το πω / για να εικάσω·</li><li><b>(ὡς) ἐμοί δοκεῖν</b> = κατά τη γνώμη μου·</li><li><b>ὀλίγου δεῖν / μικροῦ δεῖν</b> = σχεδόν, λίγο έλειψε να·</li><li><b>τό νῦν εἶναι</b> = προς το παρόν· <b>τό ἐπ' ἐμοί εἶναι</b> = όσο εξαρτάται από εμένα· <b>τό κατά τοῦτον εἶναι</b> = όσον αφορά αυτόν·</li><li><b>(ὡς) εἰπεῖν, ὡς ἁπλῶς εἰπεῖν</b> = με απλά λόγια.</li></ul><h3>2. Το απαρέμφατο αντί προστακτικής (προστακτικό απαρέμφατο)</h3><p>Σπανιότερα, σε επίσημο/νομικό ή ποιητικό λόγο, το απαρέμφατο μπαίνει <b>αντί προστακτικής</b> για να εκφράσει εντολή, προσταγή ή ευχή. Έχει υποκείμενο σε <b>ονομαστική</b> (αν είναι β΄ πρόσωπο) ή σε αιτιατική. Άρνηση μή.</p><h3>3. Το απαρέμφατο σε αναφωνήσεις (απαρέμφατο της αναφώνησης)</h3><p>Σε επιφωνηματικές εκφράσεις θαυμασμού, αγανάκτησης ή απορίας, συχνά με το άρθρο: «να σκεφτεί κανείς ότι...!». Υποκείμενο σε αιτιατική.</p>","examples":[{"gr":"ὡς ἔπος εἰπεῖν, πάντες ἀπέθανον.","an":"Για να το πω έτσι (σχεδόν), όλοι σκοτώθηκαν. (απόλυτο απαρ. — επιρρ. προσδ. του ποσού/αναφοράς)"},{"gr":"ὡς συνελόντι εἰπεῖν, οὐδέν ἀγαθόν ἔπραξεν.","an":"Με λίγα λόγια, τίποτε καλό δεν έπραξε. (απόλυτο απαρ.)"},{"gr":"ὀλίγου δεῖν ἀπώλοντο πάντες.","an":"Λίγο έλειψε να χαθούν όλοι / σχεδόν χάθηκαν όλοι. (απόλυτο <i>ὀλίγου δεῖν</i> = σχεδόν)"},{"gr":"ὡς ἐμοί δοκεῖν, ἥμαρτεν.","an":"Κατά τη γνώμη μου, έσφαλε. (απόλυτο απαρ. της αναφοράς)"},{"gr":"θαρρῶν νῦν λέγε.","an":"(παράδειγμα προστακτικής διάθεσης) — πρβλ. προστακτικό απαρ.: <i>τούς δέ νεωτέρους μή ἀμελεῖν</i> = οι νεότεροι ας μην αδιαφορούν."},{"gr":"τό ἐμέ ταῦτα παθεῖν!","an":"Να πάθω εγώ αυτά! (απαρέμφατο αναφώνησης· υποκ. <i>ἐμέ</i> σε αιτ., με άρθρο <i>τό</i>)"},{"gr":"ἀληθές γε ὡς ἔπος εἰπεῖν οὐδέν εἰρήκασιν.","an":"(Πλάτ. Ἀπολ. 17a — Πλάτων) Αληθινό, για να το πω έτσι, τίποτε δεν έχουν πει. (απόλυτο <i>ὡς ἔπος εἰπεῖν</i>, παρενθετικός μετριασμός)"},{"gr":"χαίρειν Κῦρος Κυαξάρῃ.","an":"(τύπου επιστολικού — Ξεν. Κύρ. Παιδ.) Ο Κύρος χαιρετά τον Κυαξάρη. (προστακτικό/επιστολικό απαρ. <i>χαίρειν</i> αντί προστακτικής)"}],"note":"Τα απόλυτα απαρέμφατα στο συντακτικό τα χαρακτηρίζουμε «απόλυτο (παρενθετικό) απαρέμφατο, επιρρηματικός προσδιορισμός της αναφοράς». Δεν τους ψάχνουμε υποκείμενο/εξάρτηση. Μην μπερδεύεις το <i>ὀλίγου δεῖν</i> (στερεότυπο = σχεδόν) με το προσωπικό <i>δεῖ</i> + απαρέμφατο."},{"h":"Σύνοψη — διαγνωστικά κριτήρια, άρνηση και βήματα αναγνώρισης","body":"<p>Συγκεντρώνουμε εδώ τα εργαλεία που χρειάζεται κανείς για να <b>αναγνωρίζει και να χαρακτηρίζει</b> κάθε απαρέμφατο σε ένα κείμενο.</p><h3>Α. Έναρθρο ή άναρθρο;</h3><p>Κοιτάζουμε αν προηγείται <b>άρθρο ουδετέρου</b> (τό, τοῦ, τῷ). Αν ναι → έναρθρο (= ουσιαστικό σε πτώση)· εντοπίζουμε την πτώση και βρίσκουμε τον ονοματικό ρόλο (υποκ./αντικ./γενική προσδ./εμπρόθετος...). Αν όχι → άναρθρο, και προχωρούμε στο Β.</p><h3>Β. Ειδικό ή τελικό; (για το άναρθρο που εξαρτάται από ρήμα)</h3><p>Τρία αλληλοεπιβεβαιούμενα κριτήρια:</p><ul><li><b>Μετάφραση</b>: «ότι/πως» → ειδικό· «να» → τελικό.</li><li><b>Άρνηση</b>: οὐ → ειδικό· μή → τελικό.</li><li><b>Ρήμα εξάρτησης</b>: λεκτικό/δοξαστικό/αισθητικό → ειδικό· βουλητικό/κελευστικό/κωλυτικό/δυνητικό/πειρατικό → τελικό.</li></ul><p>Συμπληρωματικά: το <b>απαρέμφατο μέλλοντα</b> και το <b>δυνητικό απαρέμφατο</b> δείχνουν σχεδόν πάντα <b>ειδικό</b>.</p><h3>Γ. Αν δεν εξαρτάται από προσωπικό ρήμα ως αντικ./υποκ.</h3><p>Ελέγχουμε μήπως είναι: απαρ. του σκοπού (μετά από κίνηση/δόση/εκλογή), της αναφοράς (σε επίθετο), του αποτελέσματος (ὥστε), επεξήγηση, ή απόλυτο/προστακτικό/αναφωνήσεως.</p><h3>Δ. Το υποκείμενο</h3><p>Ταυτοπροσωπία → ονομαστική (εννοούμενο)· ετεροπροσωπία/απρόσωπη σύνταξη → αιτιατική (ή κατ' έλξη δοτική). Το κατηγορούμενο ακολουθεί την πτώση του υποκειμένου.</p><h3>Ε. Η άρνηση — συγκεντρωτικά</h3><ul><li><b>οὐ</b>: ειδικό απαρέμφατο.</li><li><b>μή</b>: τελικό απαρέμφατο, απαρ. αποτελέσματος (ὥστε), απαρ. του σκοπού, έναρθρο απαρέμφατο (γενικευτικό), προστακτικό απαρ., και η <i>παραπληρωματική (περιττή) μή</i> μετά από κωλυτικά/αρνητικά ρήματα.</li></ul>","examples":[{"gr":"ἔφη οὐκ εἰδέναι.","an":"Είπε ότι δεν γνώριζε. (ειδικό: λεκτικό <i>ἔφη</i> + άρνηση οὐ + μετάφραση «ότι»)"},{"gr":"παρήγγειλε μή μάχεσθαι.","an":"Παρήγγειλε να μην πολεμούν. (τελικό: κελευστικό + άρνηση μή + μετάφραση «να»)"},{"gr":"οὐκ ἔχω ὅ τι λέγω → δύναμαι λέγειν.","an":"Μπορώ να μιλήσω. (δυνητικό ρήμα <i>δύναμαι</i> → τελικό απαρ.)"},{"gr":"φασί τόν Σωκράτη σοφώτατον γενέσθαι.","an":"Λένε ότι ο Σωκράτης υπήρξε σοφότατος. (ειδικό· ετεροπροσωπία, υποκ. <i>τόν Σωκράτη</i> αιτ.· κατηγ. <i>σοφώτατον</i> αιτ.)"},{"gr":"ἐκώλυσεν αὐτούς μή ἀδικεῖν.","an":"Τους εμπόδισε να αδικούν. (κωλυτικό + παραπληρωματική μή — δεν αλλάζει τη σημασία)"},{"gr":"νομίζω αὐτόν οὐχ ἥξειν.","an":"(τύπου) Νομίζω ότι αυτός δεν θα έρθει. (ΕΙΔΙΚΟ: δοξαστικό + απαρ. μέλλοντα <i>ἥξειν</i> + άρνηση οὐ — δύο δείκτες του ειδικού)"},{"gr":"ἐπειρῶντο μή ἁλίσκεσθαι.","an":"(τύπου) Προσπαθούσαν να μην πιαστούν. (ΤΕΛΙΚΟ: πειρατικό <i>ἐπειρῶντο</i> + άρνηση μή + μετάφραση «να»)"}],"table":{"title":"Συγκριτικός πίνακας: ΕΙΔΙΚΟ vs ΤΕΛΙΚΟ απαρέμφατο","cols":["Κριτήριο","Ειδικό απαρέμφατο","Τελικό απαρέμφατο"],"rows":[["Ισοδυναμεί με","ειδική πρόταση (κρίση)","βουλητική/τελική πρόταση (επιθυμία)"],["Μετάφραση","ότι / πως","να"],["Άρνηση","οὐ","μή"],["Ρήματα εξάρτησης","λεκτικά, δοξαστικά, αισθητικά-γνωστικά","βουλητικά, κελευστικά, κωλυτικά, δυνητικά, πειρατικά"],["Χρόνος μέλλοντα","ναι (συχνά)","όχι"],["Δυνητικό (+ἄν)","ναι","όχι"],["Συντακτικός ρόλος","αντικείμενο / υποκείμενο","αντικείμενο / υποκείμενο"]]},"note":"Τελική υπενθύμιση των τριών «διπρόσωπων» παγίδων: (1) δοκῶ = νομίζω (ειδικό) vs δοκεῖ μοι = αποφασίζω (τελικό)· (2) πείθω τινά + τελικό (=παρακινώ) vs πείθομαι/πέποιθα + ειδικό (=πιστεύω)· (3) ἀκούω/πυνθάνομαι/μανθάνω = «πληροφορούμαι ότι» (ειδικό) — με αυτή τη γνωστική σημασία, όχι την κυριολεκτική. Σε κάθε αμφιβολία, η ΑΡΝΗΣΗ (οὐ/μή) είναι ο πιο αξιόπιστος μάρτυρας."}]);
  T("syn-tautoprosopia", [{"h":"Τι είναι το απαρέμφατο και γιατί έχει δικό του υποκείμενο","body":"<p>Το <b>απαρέμφατο</b> είναι το <i>άκλιτο ρηματικό ουσιαστικό</i>: από τη μία είναι όνομα (δηλώνει την ενέργεια ή κατάσταση ως αφηρημένη έννοια και μπορεί να λειτουργήσει ως υποκείμενο, αντικείμενο κ.λπ.), από την άλλη είναι ρήμα (έχει χρόνο, φωνή, δέχεται άρνηση και — το κρισιμότερο για τη σύνταξη — <b>έχει το δικό του υποκείμενο, αντικείμενο, κατηγορούμενο και προσδιορισμούς</b>).</p><p>Επειδή λοιπόν το απαρέμφατο διατηρεί τη ρηματική του φύση, κάθε φορά που το συναντούμε οφείλουμε να αναζητούμε <b>ποιος ενεργεί ή βρίσκεται στην κατάσταση που δηλώνει</b>. Αυτό το πρόσωπο ή πράγμα είναι το <b>υποκείμενο του απαρεμφάτου</b>. Από το ποιο είναι αυτό το υποκείμενο και από τη σχέση του με το υποκείμενο του ρήματος εξαρτώνται δύο θεμελιώδη φαινόμενα: η <b>ταυτοπροσωπία</b> και η <b>ετεροπροσωπία</b>.</p><h3>Ο κανόνας-κλειδί</h3><p>Ολόκληρη η θεωρία στηρίζεται σε μία διάκριση:</p><ul><li>Αν το υποκείμενο του απαρεμφάτου <b>ταυτίζεται</b> με το υποκείμενο του ρήματος → <b>ταυτοπροσωπία</b> (υποκείμενο σε <b>ονομαστική</b>, συνήθως παραλειπόμενο).</li><li>Αν το υποκείμενο του απαρεμφάτου είναι <b>διαφορετικό</b> → <b>ετεροπροσωπία</b> (υποκείμενο υποχρεωτικά σε <b>αιτιατική</b>).</li></ul><p>Η αναζήτηση του υποκειμένου γίνεται πάντοτε με την ερώτηση: <i>«ποιος (κάνει την ενέργεια του απαρεμφάτου);»</i>. Έπειτα ελέγχουμε αν η απάντηση συμπίπτει ή όχι με το υποκείμενο του ρήματος.</p>","examples":[{"gr":"Βούλομαι <b>μένειν</b>.","an":"Ρήμα: βούλομαι (υποκ. ἐγώ). Απαρέμφατο: μένειν. Ποιος θα μείνει; — ἐγώ. Άρα υποκ. απαρεμφάτου = υποκ. ρήματος → ταυτοπροσωπία· υποκ. (ἐγώ) σε ονομαστική, εννοούμενο. Μτφρ.: «Θέλω να μείνω»."},{"gr":"Κελεύω <b>σε μένειν</b>.","an":"Ρήμα: κελεύω (υποκ. ἐγώ). Απαρέμφατο: μένειν. Ποιος θα μείνει; — σύ (σε). Διαφορετικό από το ἐγώ → ετεροπροσωπία· υποκ. (σε) σε αιτιατική. Μτφρ.: «Σε προστάζω να μείνεις»."},{"gr":"<b>Ἐβούλετο τώ παῖδε</b> ἀμφοτέρω <b>παρεῖναι</b>.","an":"Ξεν. Ἀνάβ. 1.1.1 — Ρήμα: ἐβούλετο (υποκ. Δαρεῖος). Απαρέμφατο: παρεῖναι. Ποιοι να είναι παρόντες; — τώ παῖδε (δυϊκ. αιτ.), όχι ο Δαρείος → ετεροπροσωπία· υποκ. απαρεμφάτου σε αιτιατική. Μτφρ.: «Ήθελε να είναι παρόντες και οι δύο γιοι (του)»."},{"gr":"Οἶμαι <b>εἰδέναι</b>.","an":"Πλ. (τύπου) — Ρήμα: οἶμαι (υποκ. ἐγώ). Απαρέμφατο: εἰδέναι. Ποιος γνωρίζει; — ἐγώ → ταυτοπροσωπία· υποκ. (ἐγώ) σε ονομαστική, εννοούμενο. Μτφρ.: «Νομίζω ότι γνωρίζω»."}],"note":"Πρώτα βρίσκουμε το ρήμα και το υποκείμενό του, μετά το απαρέμφατο και το δικό του υποκείμενο, και τέλος τα συγκρίνουμε. Η σύγκριση αυτή καθορίζει όλη την πτωτική εικόνα της φράσης."},{"h":"Πώς εντοπίζουμε το υποκείμενο του απαρεμφάτου","body":"<p>Το υποκείμενο του απαρεμφάτου δεν δηλώνεται πάντοτε με ξεχωριστή λέξη· πολλές φορές <b>ταυτίζεται με κάποιον όρο της κύριας πρότασης</b> και απλώς εννοείται. Η πρακτική μέθοδος εντοπισμού του ακολουθεί τη σύνταξη του ρήματος εξάρτησης:</p><h3>1. Από το υποκείμενο του ρήματος (ταυτοπροσωπία)</h3><p>Όταν το ρήμα εξάρτησης δηλώνει ότι <b>ο ίδιος ο δράστης</b> κάνει και την ενέργεια του απαρεμφάτου (π.χ. <i>βούλομαι, ἐλπίζω, φημί, νομίζω, δύναμαι, ἐπιχειρῶ</i>), το υποκείμενο του απαρεμφάτου είναι το ίδιο με το υποκείμενο του ρήματος.</p><h3>2. Από το αντικείμενο του ρήματος (ετεροπροσωπία)</h3><p>Όταν το ρήμα εξάρτησης είναι μεταβατικό και η ενέργεια του απαρεμφάτου αφορά <b>το αντικείμενο</b> (αιτιατική ή δοτική), τότε το αντικείμενο αυτό γίνεται υποκείμενο του απαρεμφάτου. Τυπικά ρήματα: <i>κελεύω, πείθω, ἀναγκάζω, ἐῶ, κωλύω, συμβουλεύω, παραινῶ</i>.</p><h3>3. Από τη δοτική προσωπική ή την αιτιατική στα απρόσωπα</h3><p>Στην απρόσωπη σύνταξη το υποκείμενο του απαρεμφάτου δηλώνεται με <b>δοτική προσωπική</b> (συνήθως με <i>δεῖ, χρή, πρέπει, ἔξεστι</i>) ή με <b>αιτιατική</b> — και τότε εφαρμόζεται κανονικά η ετεροπροσωπία.</p>","examples":[{"gr":"Οἱ στρατιῶται <b>ἤλπιζον</b> σωθήσεσθαι.","an":"Υποκ. ρήματος: οἱ στρατιῶται. Ποιοι θα σωθούν; — οἱ ίδιοι οι στρατιώτες. Ταυτοπροσωπία· υποκ. απαρεμφάτου εννοούμενο σε ονομαστική (αὐτοί / οἱ στρατιῶται). Μτφρ.: «Οι στρατιώτες έλπιζαν ότι θα σωθούν»."},{"gr":"Ὁ Κῦρος <b>ἐκέλευσε τούς στρατιώτας</b> προϊέναι.","an":"Υποκ. ρήματος: ὁ Κῦρος. Αντικείμενο: τούς στρατιώτας (αιτ.). Ποιοι θα προχωρήσουν; — οι στρατιώτες, όχι ο Κύρος. Ετεροπροσωπία· το αντικείμενο τούς στρατιώτας είναι ταυτόχρονα υποκείμενο του απαρεμφάτου σε αιτιατική. Μτφρ.: «Ο Κύρος διέταξε τους στρατιώτες να προχωρήσουν»."},{"gr":"<b>Δεῖ ἡμᾶς</b> πονεῖν.","an":"Απρόσωπο ρήμα: δεῖ. Υποκείμενο του δεῖ είναι το ίδιο το απαρέμφατο πονεῖν· υποκείμενο του πονεῖν: ἡμᾶς (αιτ.). Ετεροπροσωπία. Μτφρ.: «Πρέπει εμείς να κοπιάζουμε»."},{"gr":"Τούς <b>ὁπλίτας</b> αὐτοῦ <b>ἐκέλευσε μεῖναι</b>.","an":"Ξεν. Ἀνάβ. 1.5.13 — Υποκ. ρήματος: αὐτός (Κλέαρχος). Αντικείμενο: τούς ὁπλίτας (αιτ.). Ποιοι θα μείνουν; — οι οπλίτες → ετεροπροσωπία· η αιτιατική τούς ὁπλίτας είναι συγχρόνως αντικείμενο του ἐκέλευσε και υποκείμενο του μεῖναι (αὐτοῦ = επίρρ. «εκεί»). Μτφρ.: «Διέταξε τους οπλίτες να μείνουν εκεί»."},{"gr":"Αἱ ἡδοναί <b>πείθουσι τήν ψυχήν</b> μή <b>σωφρονεῖν</b>.","an":"(τύπου) — Υποκ. ρήματος: αἱ ἡδοναί. Αντικείμενο: τήν ψυχήν (αιτ.). Ποια δεν σωφρονεί; — η ψυχή → ετεροπροσωπία· η αιτιατική τήν ψυχήν είναι αντικείμενο του πείθουσι και υποκείμενο του σωφρονεῖν (άρνηση μή, τελικό απαρ.). Μτφρ.: «Οι ηδονές πείθουν την ψυχή να μη σωφρονεί»."}],"note":"Στο ίδιο ρήμα κελεύω βλέπουμε δύο συμπεριφορές: «κελεύω σε μένειν» (το «σε» είναι αντικείμενο-και-υποκείμενο → ετεροπροσωπία). Δεν είναι το είδος του ρήματος που κρίνει αλλά η ταύτιση ή μη των υποκειμένων."},{"h":"Ταυτοπροσωπία: ονομαστική και παράλειψη του υποκειμένου","body":"<p><b>Ταυτοπροσωπία</b> έχουμε όταν <b>το υποκείμενο του απαρεμφάτου είναι το ίδιο με το υποκείμενο του ρήματος εξάρτησης</b>. Τότε ισχύουν τρεις κανόνες:</p><ul><li><b>Πτώση:</b> το υποκείμενο του απαρεμφάτου βρίσκεται σε <b>ονομαστική</b> (γιατί είναι το ίδιο με το υποκείμενο του ρήματος, που είναι κατ' εξοχήν σε ονομαστική).</li><li><b>Παράλειψη:</b> κανονικά το <b>παραλείπουμε</b>, γιατί εννοείται εύκολα από το υποκείμενο του ρήματος. Δεν το επαναλαμβάνουμε.</li><li><b>Συμφωνία όρων:</b> ό,τι αναφέρεται στο υποκείμενο αυτό (κατηγορούμενο, κατηγορηματικός ή επιθετικός προσδιορισμός, παράθεση) μπαίνει επίσης σε <b>ονομαστική</b>, για να συμφωνεί με το εννοούμενο υποκείμενο.</li></ul><p>Όταν ζητείται να γράψουμε το υποκείμενο, το δηλώνουμε με την κατάλληλη ονομαστική αντωνυμία ή ουσιαστικό (π.χ. <i>αὐτός, οὗτος</i>), αλλά σημειώνουμε ότι κανονικά παραλείπεται.</p><h3>Τυπικά ρήματα ταυτοπροσωπίας</h3><p>Ρήματα που εκφράζουν επιθυμία, ελπίδα, προσπάθεια, δύναμη, γνώμη ή λόγο για τον ίδιο τον δράστη: <i>βούλομαι, ἐθέλω, ἐπιθυμῶ, ἐλπίζω, ὑπισχνοῦμαι, ὑπόσχομαι, φημί, οἴομαι, νομίζω, ἡγοῦμαι, δοκῶ, δύναμαι, ἐπίσταμαι, ἐπιχειρῶ, μέλλω, φοβοῦμαι</i>.</p>","examples":[{"gr":"Σωκράτης <b>βούλεται</b> σοφός εἶναι.","an":"Υποκ. ρήματος: Σωκράτης. Απαρέμφατο: εἶναι· υποκ. του = (Σωκράτης), εννοούμενο σε ονομαστική. Ταυτοπροσωπία. Το κατηγορούμενο σοφός μπαίνει σε ΟΝΟΜΑΣΤΙΚΗ, για να συμφωνήσει με το εννοούμενο υποκείμενο. Μτφρ.: «Ο Σωκράτης θέλει να είναι σοφός»."},{"gr":"Οἱ Ἕλληνες <b>ἔφασαν</b> ἕτοιμοι εἶναι μάχεσθαι.","an":"Υποκ.: οἱ Ἕλληνες. Ειδικό απαρέμφατο εἶναι με ταυτοπροσωπία· κατηγορούμενο ἕτοιμοι σε ΟΝΟΜΑΣΤΙΚΗ (πληθ., για συμφωνία). Το μάχεσθαι εξαρτάται από το ἕτοιμοι. Μτφρ.: «Οι Έλληνες είπαν ότι είναι έτοιμοι να πολεμήσουν»."},{"gr":"Νομίζω <b>ἀδικεῖσθαι</b>.","an":"Υποκ. ρήματος: ἐγώ. Ποιος αδικείται; — ἐγώ. Ταυτοπροσωπία· υποκ. απαρεμφάτου (ἐγώ) σε ονομαστική, εννοούμενο και παραλειπόμενο. Μτφρ.: «Νομίζω ότι αδικούμαι»."},{"gr":"Κῦρος <b>ὡμολόγει</b> ἥκιστα δεινός εἶναι λέγειν.","an":"Υποκ.: Κῦρος. Ειδικό απαρέμφατο εἶναι· ταυτοπροσωπία. Κατηγορούμενο δεινός σε ΟΝΟΜΑΣΤΙΚΗ· δεινός λέγειν = ικανός να μιλά. Μτφρ.: «Ο Κύρος παραδεχόταν ότι είναι ελάχιστα ικανός στον λόγο»."},{"gr":"Πέρσης <b>ἔφη</b> εἶναι.","an":"Ξεν. (τύπου) — Υποκ. ρήματος: αὐτός. Ειδικό απαρ. εἶναι· ταυτοπροσωπία (ποιος είναι Πέρσης; — αυτός). Κατηγορούμενο Πέρσης σε ΟΝΟΜΑΣΤΙΚΗ. Μτφρ.: «Είπε ότι είναι Πέρσης»."},{"gr":"Ἐγώ οὐχ <b>ὁμολογήσω</b> ἄκλητος ἥκειν.","an":"Πλ. Συμπ. 174d (τύπου) — Υποκ. ρήματος: ἐγώ. Ειδικό απαρ. ἥκειν· ταυτοπροσωπία. Κατηγορ. προσδ. ἄκλητος σε ΟΝΟΜΑΣΤΙΚΗ (συμφωνεί με το εννοούμενο ἐγώ). Μτφρ.: «Εγώ δεν θα παραδεχτώ ότι έχω έρθει απρόσκλητος»."}],"table":{"title":"Ταυτοπροσωπία — τι μπαίνει σε ονομαστική","cols":["Όρος του απαρεμφάτου","Πτώση","Παρατήρηση"],"rows":[["Υποκείμενο","Ονομαστική","Κανονικά παραλείπεται (εννοείται)"],["Κατηγορούμενο","Ονομαστική","Συμφωνεί με το εννοούμενο υποκείμενο"],["Κατηγορηματικός προσδ.","Ονομαστική","π.χ. αὐτός, μόνος, πᾶς"],["Επιθετικός προσδ. / παράθεση","Ονομαστική","Ακολουθούν το υποκείμενο"]]},"note":"Το σήμα-κατατεθέν της ταυτοπροσωπίας στις εξετάσεις είναι το ΚΑΤΗΓΟΡΟΥΜΕΝΟ ΣΕ ΟΝΟΜΑΣΤΙΚΗ μετά από απαρέμφατο: αν δεις «βούλεται σοφός εἶναι», η ονομαστική σοφός σού δείχνει αμέσως ότι το υποκείμενο ταυτίζεται με αυτό του ρήματος."},{"h":"Ετεροπροσωπία: αιτιατική του υποκειμένου και των συμφωνούντων όρων","body":"<p><b>Ετεροπροσωπία</b> έχουμε όταν <b>το υποκείμενο του απαρεμφάτου είναι διαφορετικό από το υποκείμενο του ρήματος</b>. Τότε:</p><ul><li><b>Πτώση:</b> το υποκείμενο του απαρεμφάτου τίθεται <b>υποχρεωτικά σε αιτιατική</b>. (Δεν παραλείπεται, εκτός αν εύκολα εννοείται από τα συμφραζόμενα.)</li><li><b>Συμφωνία όρων:</b> κάθε όρος που αναφέρεται σε αυτό το υποκείμενο — <b>κατηγορούμενο, κατηγορηματικός/επιθετικός προσδιορισμός, παράθεση</b> — μπαίνει επίσης σε <b>αιτιατική</b>.</li></ul><p>Το υποκείμενο σε αιτιατική προκύπτει με δύο τρόπους: είτε <b>συμπίπτει με το αντικείμενο</b> του ρήματος εξάρτησης (π.χ. «κελεύω <i>τούς στρατιώτας</i> μάχεσθαι»), είτε είναι <b>νέα, ανεξάρτητη αιτιατική</b> που εισάγεται αποκλειστικά ως υποκείμενο του απαρεμφάτου (π.χ. «νομίζω <i>τούς θεούς</i> ἄριστα εἰδέναι»).</p><h3>Προσοχή στη διπλή λειτουργία</h3><p>Στα ρήματα όπως <i>κελεύω, πείθω, ἀναγκάζω, ἐῶ, κωλύω</i> η αιτιατική είναι ταυτόχρονα <b>αντικείμενο του ρήματος ΚΑΙ υποκείμενο του απαρεμφάτου</b>. Σε ρήματα γνώμης/λόγου (<i>νομίζω, φημί, οἴομαι, ἡγοῦμαι</i>) η αιτιατική είναι <b>μόνο</b> υποκείμενο του απαρεμφάτου (το ίδιο το απαρέμφατο με όλους τους όρους του αποτελεί το αντικείμενο).</p>","examples":[{"gr":"Νομίζω <b>τούς θεούς</b> πάντα <b>εἰδέναι</b>.","an":"Υποκ. ρήματος: ἐγώ. Ποιος γνωρίζει; — οἱ θεοί, όχι ἐγώ. Ετεροπροσωπία· υποκ. απαρεμφάτου: τούς θεούς (ΑΙΤΙΑΤΙΚΗ). Αντικείμενο του νομίζω είναι όλο το ειδικό απαρέμφατο (τούς θεούς πάντα εἰδέναι). Μτφρ.: «Νομίζω ότι οι θεοί τα γνωρίζουν όλα»."},{"gr":"Κῦρος <b>ἐνόμιζε ἑαυτόν</b> ὀλβιώτατον <b>εἶναι</b>.","an":"Υποκ. ρήματος: Κῦρος. Υποκ. απαρεμφάτου: ἑαυτόν (ΑΙΤΙΑΤΙΚΗ — αυτοπαθής, αναφέρεται στο ίδιο πρόσωπο αλλά τυπικά διαφορετικό από το γραμματικό υποκείμενο του ειδικού απαρεμφάτου → ετεροπροσωπία). Κατηγορούμενο ὀλβιώτατον σε ΑΙΤΙΑΤΙΚΗ. Μτφρ.: «Ο Κύρος θεωρούσε τον εαυτό του ευτυχέστατο»."},{"gr":"Μιλτιάδης <b>ἔπεισε τούς Ἀθηναίους</b> στρατεῦσαι.","an":"Υποκ. ρήματος: Μιλτιάδης. Αντικείμενο: τούς Ἀθηναίους (αιτ.). Ποιοι εκστρατεύουν; — οι Αθηναίοι. Ετεροπροσωπία· η αιτιατική τούς Ἀθηναίους είναι ΣΥΓΧΡΟΝΩΣ αντικείμενο του ἔπεισε και υποκείμενο του στρατεῦσαι. Μτφρ.: «Ο Μιλτιάδης έπεισε τους Αθηναίους να εκστρατεύσουν»."},{"gr":"Ἡγοῦμαι <b>τοῦτον</b> εἶναι <b>φίλον</b>.","an":"Υποκ. ρήματος: ἐγώ. Υποκ. απαρεμφάτου: τοῦτον (ΑΙΤΙΑΤΙΚΗ, διαφορετικό από ἐγώ). Κατηγορούμενο φίλον σε ΑΙΤΙΑΤΙΚΗ (συμφωνία με το υποκείμενο σε αιτιατική). Μτφρ.: «Θεωρώ ότι αυτός είναι φίλος»."},{"gr":"<b>Ἡγοῦμαι</b> δέ <b>προστάτου</b> δεῖσθαι <b>τό πλῆθος</b>.","an":"Λυσ. (τύπου, δοξαστικό) — Υποκ. ρήματος: ἐγώ. Υποκ. απαρεμφάτου δεῖσθαι: τό πλῆθος (ΑΙΤ., ουδ., διαφορετικό από ἐγώ) → ετεροπροσωπία. προστάτου = γεν. ως συμπλήρωμα του δεῖσθαι. Μτφρ.: «Θεωρώ ότι το πλήθος χρειάζεται προστάτη»."},{"gr":"Οὐκ <b>οἴομαι Σωκράτη</b> ἀσεβῆ <b>εἶναι</b>.","an":"Πλ. (τύπου, δοξαστικό) — Υποκ. ρήματος: ἐγώ. Υποκ. απαρεμφάτου: Σωκράτη (ΑΙΤ., διαφορετικό από ἐγώ) → ετεροπροσωπία. Κατηγορούμενο ἀσεβῆ σε ΑΙΤΙΑΤΙΚΗ. Μτφρ.: «Δεν νομίζω ότι ο Σωκράτης είναι ασεβής»."}],"table":{"title":"Ετεροπροσωπία — τι μπαίνει σε αιτιατική","cols":["Όρος του απαρεμφάτου","Πτώση","Παρατήρηση"],"rows":[["Υποκείμενο","Αιτιατική","Υποχρεωτικά δηλωμένο (συνήθως)"],["Κατηγορούμενο","Αιτιατική","Συμφωνεί με το υποκ. σε αιτιατική"],["Κατηγορηματικός προσδ.","Αιτιατική","π.χ. αὐτόν, μόνον"],["Επιθετικός προσδ. / παράθεση","Αιτιατική","Ακολουθούν το υποκείμενο"]]},"note":"Διάγνωση με μία ματιά: κατηγορούμενο σε ΑΙΤΙΑΤΙΚΗ μετά από απαρέμφατο (ὀλβιώτατον, φίλον) → ετεροπροσωπία· κατηγορούμενο σε ΟΝΟΜΑΣΤΙΚΗ (σοφός, ἕτοιμος) → ταυτοπροσωπία. Το κατηγορούμενο είναι ο πιο αξιόπιστος δείκτης."},{"h":"Το ειδικό απαρέμφατο και η σχέση του με ταυτο-/ετεροπροσωπία","body":"<p>Το <b>ειδικό απαρέμφατο</b> ισοδυναμεί με <b>ειδική πρόταση</b>, μεταφράζεται με το <i>ότι / πως</i> και δέχεται άρνηση <b>οὐ</b>. Δηλώνει κάτι ως <i>κρίση, γνώμη, είδηση</i> — δηλαδή περιεχόμενο σκέψης ή λόγου. Έχει όλους τους χρόνους (μέλλοντα συμπεριλαμβανομένου) και ο χρόνος του δηλώνει το ποιόν/χρονική βαθμίδα σε σχέση με το ρήμα.</p><h3>Εισαγωγή (από ποια ρήματα εξαρτάται)</h3><ul><li><b>Λεκτικά</b> (= λέω, δηλώνω): <i>λέγω, φημί, ἀποκρίνομαι, ὁμολογῶ, ἀρνοῦμαι, ἀγγέλλω, ὑπισχνοῦμαι, ὄμνυμι, ἰσχυρίζομαι</i>.</li><li><b>Δοξαστικά / γνωστικά</b> (= νομίζω, κρίνω): <i>νομίζω, ἡγοῦμαι, οἴομαι (οἶμαι), δοκῶ, ὑπολαμβάνω, λογίζομαι, κρίνω, εἰκάζω, ἐλπίζω</i>.</li><li><b>Αισθητικά</b> (= αντιλαμβάνομαι): <i>αἰσθάνομαι, πυνθάνομαι, ἀκούω, μανθάνω</i> (όταν σημαίνουν «πληροφορούμαι»).</li><li>Επίσης ως <b>υποκείμενο</b> απρόσωπων εκφράσεων του τύπου <i>λέγεται, δοκεῖ, ἀγγέλλεται</i>.</li></ul><h3>Εκφορά (πτώση υποκειμένου)</h3><p>Το ειδικό απαρέμφατο ακολουθεί κανονικά τη διάκριση ταυτο-/ετεροπροσωπίας: αν το υποκείμενό του ταυτίζεται με του ρήματος → ονομαστική (παράλειψη)· αν διαφέρει → αιτιατική.</p><h3>Ανάλυση σε ειδική πρόταση</h3><p>Το ειδικό απαρέμφατο αναλύεται σε ειδική πρόταση με <b>ότι / ὡς</b>. Στην ανάλυση το υποκείμενο γίνεται <b>ονομαστική</b> (γραμματικό υποκείμενο του νέου ρήματος), όποια κι αν ήταν η αρχική του πτώση.</p>","examples":[{"gr":"Λέγουσιν <b>αὐτόν</b> πλούσιον <b>εἶναι</b>. → Λέγουσιν <b>ὅτι αὐτός ἐστι πλούσιος</b>.","an":"Ειδικό απαρ. εἶναι, ετεροπροσωπία (υποκ. αὐτόν σε αιτ., κατηγ. πλούσιον σε αιτ.). Ανάλυση: το αὐτόν γίνεται αὐτός (ΟΝΟΜΑΣΤΙΚΗ), το πλούσιον → πλούσιος (ονομ.), το εἶναι → ἐστί. Μτφρ.: «Λένε ότι αυτός είναι πλούσιος»."},{"gr":"Οἱ πρέσβεις <b>ἤγγειλαν</b> βασιλέα οὐ παρέξεσθαι ἀργύριον.","an":"Λεκτικό ρήμα ἤγγειλαν· ειδικό απαρ. παρέξεσθαι (μέλλ.)· άρνηση οὐ. Ετεροπροσωπία: υποκ. βασιλέα (αιτ.). Μτφρ.: «Οι πρέσβεις ανήγγειλαν ότι ο βασιλιάς δεν θα παρέχει χρήματα»."},{"gr":"Φησί <b>γράψαι</b> τήν ἐπιστολήν.","an":"Λεκτικό φησί (υποκ. αὐτός). Ειδικό απαρ. γράψαι· ταυτοπροσωπία (ποιος έγραψε; — αυτός). Υποκ. εννοούμενο σε ονομ. Μτφρ.: «Λέει ότι έγραψε την επιστολή»."},{"gr":"<b>Ὁμολογεῖς</b> περί ἐμέ ἄδικος <b>γεγενῆσθαι</b>;","an":"(τύπου) — Λεκτικό ὁμολογεῖς (υποκ. σύ). Ειδικό απαρ. γεγενῆσθαι (παρακ.)· ταυτοπροσωπία. Κατηγορ. προσδ. ἄδικος σε ΟΝΟΜΑΣΤΙΚΗ (συμφωνεί με το εννοούμενο σύ). Μτφρ.: «Παραδέχεσαι ότι έχεις φερθεί άδικα απέναντί μου;»"},{"gr":"<b>Λέγεται</b> Ἀλκιβιάδης σοφός <b>εἶναι</b>.","an":"Τύπου — Απρόσωπη παθητική σύνταξη: λέγεται. Ειδικό απαρ. εἶναι· ως «προσωπική παθητική» το υποκ. Ἀλκιβιάδης σε ΟΝΟΜΑΣΤΙΚΗ (έλξη προς το ρήμα), κατηγ. σοφός ονομ. Μτφρ.: «Λέγεται ότι ο Αλκιβιάδης είναι σοφός»."}],"note":"Κλειδί αναγνώρισης ειδικού απαρεμφάτου: (α) εξαρτάται από λεκτικό/δοξαστικό/αισθητικό ρήμα, (β) μεταφράζεται με «ότι», (γ) δέχεται οὐ και (δ) μπορεί να είναι και σε χρόνο μέλλοντα."},{"h":"Το τελικό απαρέμφατο και η σχέση του με ταυτο-/ετεροπροσωπία","body":"<p>Το <b>τελικό απαρέμφατο</b> ισοδυναμεί με <b>βουλητική πρόταση</b>, μεταφράζεται με το <i>να</i> και δέχεται άρνηση <b>μή</b>. Δηλώνει κάτι ως <i>επιθυμητό, σκοπό, προτροπή ή απαγόρευση</i> — όχι ως πραγματικό γεγονός. Γι' αυτό <b>δεν τίθεται ποτέ σε χρόνο μέλλοντα</b> (η επιθυμία στρέφεται προς το μέλλον· χρησιμοποιεί ενεστώτα/αόριστο/παρακείμενο για το ποιόν ενεργείας).</p><h3>Εισαγωγή (από ποια ρήματα εξαρτάται)</h3><ul><li><b>Βουλητικά</b> (= θέλω, επιθυμώ): <i>βούλομαι, ἐθέλω, ἐπιθυμῶ, ποθῶ, εὔχομαι</i>.</li><li><b>Κελευστικά / προτρεπτικά</b> (= διατάζω, προτρέπω): <i>κελεύω, προστάττω, παραγγέλλω, παραινῶ, συμβουλεύω, πείθω, δέομαι, ἀξιῶ</i>.</li><li><b>Εφετικά / αποπειρατικά</b> (= επιχειρώ, αποφασίζω): <i>ἐπιχειρῶ, πειρῶμαι, μέλλω, διανοοῦμαι, βουλεύομαι, ψηφίζομαι, ἀναγκάζω, ἐῶ</i>.</li><li><b>Κωλυτικά / απαγορευτικά</b> (= εμποδίζω): <i>κωλύω, εἴργω, ἀπαγορεύω, ἀποτρέπω, φοβοῦμαι</i>.</li><li>Επίσης ως <b>υποκείμενο</b> απρόσωπων: <i>δεῖ, χρή, πρέπει, ἔξεστι, δοκεῖ, ἀνάγκη ἐστί</i>.</li></ul><h3>Εκφορά (πτώση υποκειμένου)</h3><p>Όπως και το ειδικό, ακολουθεί ταυτο-/ετεροπροσωπία: ταυτοπροσωπία → ονομαστική (παράλειψη)· ετεροπροσωπία → αιτιατική. Τα κελευστικά/κωλυτικά κατά κανόνα φέρνουν <b>ετεροπροσωπία</b>, γιατί κάποιος διατάζει/εμποδίζει κάποιον <i>άλλον</i>.</p><h3>Ανάλυση σε βουλητική / τελική πρόταση</h3><p>Αναλύεται σε βουλητική πρόταση με <b>να</b> (νέα ελλ.) ή σε αρχαία με <b>ἵνα/ὅπως + υποτακτική</b> όταν δηλώνει σκοπό. Το υποκείμενο στην ανάλυση γίνεται <b>ονομαστική</b>.</p>","examples":[{"gr":"Βούλομαι <b>ἀπελθεῖν</b>.","an":"Βουλητικό βούλομαι· τελικό απαρ. ἀπελθεῖν (να). Ταυτοπροσωπία· υποκ. (ἐγώ) ονομ., εννοούμενο. Ανάλυση: «θέλω να φύγω». Άρνηση θα ήταν μή (βούλομαι μή ἀπελθεῖν)."},{"gr":"Συμβουλεύω <b>ὑμῖν μή παραδιδόναι</b> τά ὅπλα.","an":"Κελευστικό συμβουλεύω· τελικό απαρ. παραδιδόναι· άρνηση μή. Υποκ. απαρεμφάτου: το ὑμῖν προεξαγγέλλει το πρόσωπο, αλλά ως υποκ. του απαρεμφάτου εννοείται ὑμᾶς (αιτ.) → ετεροπροσωπία. Μτφρ.: «Σας συμβουλεύω να μην παραδώσετε τα όπλα»."},{"gr":"Ὁ νόμος <b>κελεύει τούς πολίτας</b> πείθεσθαι.","an":"Κελευστικό κελεύει· υποκ. απαρεμφάτου τούς πολίτας (ΑΙΤ.) = αντικείμενο του κελεύει → ετεροπροσωπία. Μτφρ.: «Ο νόμος προστάζει τους πολίτες να πειθαρχούν»."},{"gr":"Ἐπεχείρησαν <b>τήν πόλιν λαβεῖν</b>.","an":"Αποπειρατικό ἐπεχείρησαν (υποκ. αὐτοί). Τελικό απαρ. λαβεῖν· υποκ. εννοούμενο (αὐτοί) σε ονομ. → ταυτοπροσωπία· τήν πόλιν = αντικείμενο του απαρεμφάτου (όχι υποκείμενο!). Μτφρ.: «Επιχείρησαν να καταλάβουν την πόλη»."},{"gr":"Ἐκέλευσε <b>τούς Ἕλληνας</b> εἰς μάχην <b>τάσσεσθαι</b>.","an":"(τύπου) — Κελευστικό ἐκέλευσε (υποκ. Κῦρος). Τελικό απαρ. τάσσεσθαι· υποκ. τούς Ἕλληνας (ΑΙΤ.) = αντικ. του ἐκέλευσε → ετεροπροσωπία. Μτφρ.: «Διέταξε τους Έλληνες να παραταχθούν για μάχη»."},{"gr":"Ἐπεθύμει <b>τιμᾶσθαι</b>.","an":"Ξεν. (τύπου, βουλητικό) — Ρήμα ἐπεθύμει (υποκ. αὐτός). Τελικό απαρ. τιμᾶσθαι· ταυτοπροσωπία (ποιος να τιμάται; — αυτός), υποκ. ονομ. εννοούμενο. Μτφρ.: «Επιθυμούσε να τιμάται»."}],"note":"Προσοχή στη συχνή παγίδα: σε «ἐπεχείρησαν τήν πόλιν λαβεῖν» η αιτιατική τήν πόλιν είναι ΑΝΤΙΚΕΙΜΕΝΟ του απαρεμφάτου, όχι υποκείμενο — γι' αυτό είναι ταυτοπροσωπία. Πάντα ρωτάμε «ποιος ενεργεί;» (υποκ.) χωριστά από «τι/ποιον;» (αντικείμενο)."},{"h":"Απρόσωπη σύνταξη, δοτική προσωπική και ειδικές περιπτώσεις","body":"<p>Στα <b>απρόσωπα ρήματα και εκφράσεις</b> (<i>δεῖ, χρή, πρέπει, ἔξεστι, δοκεῖ, λέγεται, καιρός ἐστι, ἀνάγκη ἐστί, καλόν ἐστι</i>) το <b>απαρέμφατο είναι το υποκείμενο</b> του απρόσωπου ρήματος. Το πρόσωπο που ενεργεί δηλώνεται με δύο τρόπους:</p><ul><li><b>Δοτική προσωπική:</b> με τα <i>δεῖ, χρή, πρέπει, ἔξεστι, δοκεῖ</i>. Τότε το υποκείμενο του απαρεμφάτου εννοείται σε <b>αιτιατική</b>, αλλά οι όροι που συμφωνούν μαζί του (κατηγορούμενο κ.λπ.) μπαίνουν συχνά στην πτώση της <b>δοτικής</b> με έλξη.</li><li><b>Αιτιατική:</b> καθαρή ετεροπροσωπία (π.χ. «δεῖ ἡμᾶς πονεῖν»).</li></ul><h3>Έλξη του κατηγορουμένου</h3><p>Όταν υπάρχει δοτική προσωπική, το κατηγορούμενο/προσδιορισμός μπορεί να <b>ελκυσθεί στη δοτική</b>: <i>«ἔξεστιν ὑμῖν εὐδαίμοσιν εἶναι»</i> (αντί εὐδαίμονας). Αυτό λέγεται <b>έλξη</b> και είναι σταθερό φαινόμενο της αττικής.</p><h3>Παράλειψη του υποκειμένου στην ετεροπροσωπία</h3><p>Παρότι κανόνας είναι η δήλωση της αιτιατικής, το υποκείμενο μπορεί να <b>παραλειφθεί</b> όταν εννοείται εύκολα από τα συμφραζόμενα ή όταν είναι αόριστο («τινά / ἀνθρώπους»): <i>«χαλεπόν εὖ πράττειν»</i> (= το να ευτυχεί κανείς).</p><h3>Αντικείμενο του απαρεμφάτου ≠ υποκείμενο</h3><p>Σταθερή πηγή λαθών: η αιτιατική δίπλα στο απαρέμφατο μπορεί να είναι <b>αντικείμενο</b>, όχι υποκείμενο. Κρίνουμε πάντα από τη σημασία («ποιος ενεργεί» vs «ποιον/τι αφορά η ενέργεια»).</p>","examples":[{"gr":"<b>Ἔξεστιν ὑμῖν εὐδαίμοσιν</b> εἶναι.","an":"Απρόσωπο ἔξεστι· υποκ. = το απαρ. εἶναι. Δοτική προσωπική: ὑμῖν. Υποκ. του εἶναι εννοείται ὑμᾶς (αιτ.), αλλά το κατηγορούμενο εὐδαίμοσιν ελκύεται στη ΔΟΤΙΚΗ από το ὑμῖν. Μτφρ.: «Μπορείτε να είστε ευτυχισμένοι»."},{"gr":"<b>Δεῖ τόν στρατηγόν</b> νοῦν <b>ἔχειν</b>.","an":"Απρόσωπο δεῖ· υποκ. το απαρ. ἔχειν. Υποκ. του ἔχειν: τόν στρατηγόν (ΑΙΤ.) → ετεροπροσωπία. νοῦν = αντικείμενο του ἔχειν. Μτφρ.: «Πρέπει ο στρατηγός να έχει μυαλό»."},{"gr":"<b>Δοκεῖ μοι</b> ταῦτα <b>ἀληθῆ εἶναι</b>.","an":"Απρόσωπο δοκεῖ· δοτ. προσωπ. μοι· υποκ. το απαρ. εἶναι· υποκ. του εἶναι: ταῦτα (ουδ., ως αιτ./ονομ.), κατηγ. ἀληθῆ. Μτφρ.: «Μου φαίνεται ότι αυτά είναι αληθινά»."},{"gr":"<b>Καλόν ἐστι</b> τούς νέους <b>σωφρονεῖν</b>.","an":"Απρόσωπη έκφραση καλόν ἐστι· υποκ. το απαρ. σωφρονεῖν· υποκ. του σωφρονεῖν: τούς νέους (ΑΙΤ.) → ετεροπροσωπία. Μτφρ.: «Είναι καλό οι νέοι να είναι συνετοί»."},{"gr":"<b>Ἔξεστιν ἡμῖν ἀγαθούς</b> εἶναι.","an":"Smyth §1062 (τύπου) — Απρόσωπο ἔξεστι· δοτ. προσωπ. ἡμῖν· υποκ. το απαρ. εἶναι. Εδώ το κατηγορούμενο ἀγαθούς ΔΕΝ ελκύεται, αλλά μένει σε ΑΙΤΙΑΤΙΚΗ, συμφωνώντας με το εννοούμενο αιτιατικό υποκείμενο (ἡμᾶς). Μτφρ.: «Μπορούμε να είμαστε καλοί». (Πρβλ. την παραλλαγή με έλξη: ἀγαθοῖς εἶναι.)"},{"gr":"Φιλάνθρωπον εἶναι <b>δεῖ</b>.","an":"(τύπου) — Απρόσωπο δεῖ· υποκ. το απαρ. εἶναι. Το υποκείμενο του εἶναι είναι αόριστο (τινά) και παραλείπεται· γι' αυτό το κατηγορούμενο φιλάνθρωπον μένει σε ΑΙΤΙΑΤΙΚΗ. Μτφρ.: «Πρέπει (κανείς) να είναι φιλάνθρωπος»."}],"note":"Με δοτική προσωπική, αν δεις κατηγορούμενο σε δοτική (εὐδαίμοσιν, ἑτοίμοις), πρόκειται για έλξη — το «λογικό» υποκείμενο παραμένει η εννοούμενη αιτιατική. Είναι το μόνο σημείο όπου το κατηγορούμενο δεν δείχνει «καθαρά» ονομαστική ή αιτιατική."},{"h":"Συγκεντρωτικός οδηγός: αναγνώριση, ανάλυση και μεθοδολογία","body":"<p>Συνοψίζουμε όλη τη θεωρία σε μια πρακτική, βήμα-προς-βήμα μέθοδο που μπορεί να εφαρμοστεί σε κάθε άσκηση.</p><h3>Βήματα ανάλυσης ενός απαρεμφάτου</h3><ul><li><b>1.</b> Βρες το <b>ρήμα εξάρτησης</b> και το υποκείμενό του (ή διαπίστωσε ότι είναι απρόσωπο).</li><li><b>2.</b> Χαρακτήρισε το απαρέμφατο: <b>ειδικό</b> (ότι, οὐ, όλοι οι χρόνοι) ή <b>τελικό</b> (να, μή, όχι μέλλοντας).</li><li><b>3.</b> Βρες το <b>υποκείμενο του απαρεμφάτου</b> ρωτώντας «ποιος ενεργεί;».</li><li><b>4.</b> Σύγκρινέ το με το υποκείμενο του ρήματος: ίδιο → <b>ταυτοπροσωπία</b> (ονομ., παράλειψη)· διαφορετικό → <b>ετεροπροσωπία</b> (αιτ.).</li><li><b>5.</b> Έλεγξε τους <b>συμφωνούντες όρους</b> (κατηγορούμενο, προσδιορισμούς): ονομαστική στην ταυτοπροσωπία, αιτιατική στην ετεροπροσωπία (ή δοτική με έλξη).</li><li><b>6.</b> Στην <b>ανάλυση</b>, μετάτρεψε το απαρέμφατο σε πρόταση (ειδική με «ότι» / βουλητική με «να»)· το υποκείμενο γίνεται ΟΝΟΜΑΣΤΙΚΗ και το απαρέμφατο ρήμα.</li></ul><h3>Οι πιο αξιόπιστοι δείκτες</h3><p>Το <b>κατηγορούμενο</b> είναι ο ασφαλέστερος δείκτης: ονομαστική → ταυτοπροσωπία, αιτιατική → ετεροπροσωπία. Δεύτερος δείκτης: η ύπαρξη <b>δηλωμένης αιτιατικής-υποκειμένου</b> δίπλα στο απαρέμφατο (αλλά πρόσεξε μην τη συγχέεις με αντικείμενο).</p>","examples":[{"gr":"Οἱ Ἀθηναῖοι <b>ἐνόμιζον</b> ἑαυτούς ἐλευθέρους <b>εἶναι</b>.","an":"Ρήμα: ἐνόμιζον (δοξαστικό) → ειδικό απαρ. Υποκ. απαρεμφ.: ἑαυτούς (αιτ.) → ετεροπροσωπία· κατηγ. ἐλευθέρους σε ΑΙΤ. Ανάλυση: «ἐνόμιζον ὅτι αὐτοί ἐλεύθεροί εἰσιν». Μτφρ.: «Οι Αθηναίοι νόμιζαν ότι είναι ελεύθεροι»."},{"gr":"Ὑπέσχετο <b>βοηθήσειν</b>.","an":"Ρήμα: ὑπέσχετο (λεκτικό/βουλητικό) → ειδικό απαρ. μέλλ. βοηθήσειν. Ταυτοπροσωπία (ποιος θα βοηθήσει; — αυτός). Υποκ. ονομ. εννοούμενο. Ανάλυση: «ὑπέσχετο ὅτι βοηθήσει». Μτφρ.: «Υποσχέθηκε ότι θα βοηθήσει»."},{"gr":"Ἐκέλευσε <b>τούς ὁπλίτας μένειν</b> ἑτοίμους.","an":"Ρήμα: ἐκέλευσε (κελευστικό) → τελικό απαρ. μένειν (να, μή-άρνηση). Υποκ. τούς ὁπλίτας (αιτ.) = αντικ. ρήματος → ετεροπροσωπία· κατηγ. ἑτοίμους σε ΑΙΤ. Μτφρ.: «Διέταξε τους οπλίτες να μένουν έτοιμοι»."},{"gr":"Φασί <b>τόν Σωκράτη σοφόν</b> γενέσθαι. // Σωκράτης <b>φησί σοφός</b> γενέσθαι.","an":"Αντιπαραβολή. Α: φασί (υποκ. αυτοί) + τόν Σωκράτη/σοφόν σε ΑΙΤ. → ετεροπροσωπία («Λένε ότι ο Σ. έγινε σοφός»). Β: φησί (υποκ. Σωκράτης) + σοφός σε ΟΝΟΜ. → ταυτοπροσωπία («Ο Σ. λέει ότι έγινε σοφός»). Η πτώση του κατηγορουμένου αλλάζει το νόημα."},{"gr":"Λέγουσι <b>Κλέαρχον</b> τραχύν <b>εἶναι</b>. → Λέγουσιν ὅτι <b>Κλέαρχός ἐστι τραχύς</b>.","an":"(τύπου) — Ρήμα λέγουσι (λεκτικό) → ειδικό απαρ. εἶναι. Υποκ. Κλέαρχον (ΑΙΤ.) → ετεροπροσωπία· κατηγ. τραχύν σε ΑΙΤ. Στην ανάλυση: Κλέαρχος (ΟΝΟΜ.), τραχύς (ονομ.), ἐστί. Μτφρ.: «Λένε ότι ο Κλέαρχος είναι τραχύς»."},{"gr":"<b>Ἔδοξεν αὐτοῖς</b> πορεύεσθαι.","an":"Ξεν. Ἀνάβ. (τύπου) — Απρόσωπο ἔδοξεν· υποκ. το απαρ. πορεύεσθαι· δοτ. προσωπ. αὐτοῖς. Υποκ. του πορεύεσθαι εννοείται αὐτούς (αιτ.) → ετεροπροσωπία. Μτφρ.: «Αποφάσισαν να βαδίσουν» (κατά λέξη «τους φάνηκε καλό να πορευτούν»)."}],"table":{"title":"Ταυτοπροσωπία vs Ετεροπροσωπία — συγκεντρωτικός πίνακας","cols":["Κριτήριο","Ταυτοπροσωπία","Ετεροπροσωπία"],"rows":[["Υποκ. απαρεμφάτου","Ίδιο με του ρήματος","Διαφορετικό από του ρήματος"],["Πτώση υποκειμένου","Ονομαστική","Αιτιατική"],["Δήλωση υποκειμένου","Παραλείπεται (εννοείται)","Δηλώνεται (συνήθως)"],["Κατηγορούμενο/προσδ.","Ονομαστική","Αιτιατική (ή δοτική με έλξη)"],["Τυπικά ρήματα","βούλομαι, ἐλπίζω, φημί, νομίζω, δύναμαι","κελεύω, πείθω, ἀναγκάζω, νομίζω+άλλο υποκ."],["Στην απρόσωπη σύνταξη","—","δεῖ/χρή + αιτ. ή δοτ. προσωπική"]]},"note":"Χρυσός κανόνας: «Ίδιος δράστης → ονομαστική και παράλειψη· άλλος δράστης → αιτιατική». Και πάντα: το κατηγορούμενο ακολουθεί την πτώση του υποκειμένου του απαρεμφάτου — αυτή η συμφωνία είναι το αλάθητο διαγνωστικό εργαλείο."}]);
  T("syn-metoxi-eidi", [{"h":"Τι είναι η μετοχή – ρηματικό επίθετο","body":"<p>Η <b>μετοχή</b> (μετά + ἔχω, «αυτό που μετέχει») είναι <b>ρηματικό επίθετο</b>: μετέχει συγχρόνως στις ιδιότητες του <i>ρήματος</i> και του <i>επιθέτου</i>. Γι' αυτό συνδυάζει δύο φύσεις σε μία λέξη.</p><p>Ως <b>ρήμα</b> έχει: <i>χρόνους</i> (ενεστώτα, αόριστο, παρακείμενο, μέλλοντα), <i>φωνές/διαθέσεις</i> (ενεργητική, μέση, παθητική), δικό της <i>υποκείμενο</i>, και παίρνει <i>αντικείμενο, κατηγορούμενο και επιρρηματικούς προσδιορισμούς</i> (π.χ. <i>λαβών τάς ναῦς</i>: η μετοχή έχει αντικείμενο <i>τάς ναῦς</i>).</p><p>Ως <b>επίθετο</b> έχει: <i>τρία γένη</i>, κλίνεται σε όλες τις πτώσεις και τους δύο αριθμούς, και <i>συμφωνεί</i> με το υποκείμενό της σε γένος, αριθμό και πτώση (<i>οἱ λέγοντες</i>, <i>τήν στρατιάν ἀθροίσας</i>).</p><p>Με βάση τον συντακτικό της ρόλο, η μετοχή διακρίνεται σε <b>τρία μεγάλα είδη</b>:</p><ul><li><b>Επιθετική (ή αναφορική)</b> – λειτουργεί σαν επίθετο/ουσιαστικό, προσδιορίζει όνομα.</li><li><b>Κατηγορηματική</b> – εξαρτάται από ορισμένα ρήματα ως κατηγορούμενο/κατηγορηματικός προσδιορισμός.</li><li><b>Επιρρηματική</b> – λειτουργεί σαν επιρρηματικός προσδιορισμός (χρόνος, αιτία, σκοπός, υπόθεση, εναντίωση, τρόπος).</li></ul>","examples":[{"gr":"Οἱ δέ Θηβαῖοι ἔπεμψαν εἰς Ἀθήνας ἄγγελον ἐστεφανωμένον.","an":"Οι Θηβαίοι έστειλαν στην Αθήνα έναν στεφανωμένο αγγελιαφόρο. (Η μετοχή <i>ἐστεφανωμένον</i> – αρσενικό, αιτιατική, ενικός – συμφωνεί με το <i>ἄγγελον</i>: ιδιότητα επιθέτου.)"},{"gr":"Λαβών τάς ναῦς ὁ στρατηγός ἀνεχώρησεν.","an":"Αφού πήρε τα πλοία, ο στρατηγός αποχώρησε. (Η μετοχή <i>λαβών</i> έχει δικό της αντικείμενο <i>τάς ναῦς</i>: ιδιότητα ρήματος.)"},{"gr":"Συλλέξας στράτευμα ἐπολιόρκει Μίλητον.","an":"Ξεν. Ἀνάβ. 1.1.7 (τύπου) — Αφού συγκέντρωσε στρατό, πολιορκούσε τη Μίλητο. (Η μετοχή <i>συλλέξας</i> ως ρήμα έχει αντικείμενο <i>στράτευμα</i>· ως επίθετο συμφωνεί με το εννοούμενο υποκείμενο σε γένος-αριθμό-πτώση.)"},{"gr":"Οἱ λέγοντες οὐκ ἀεί τἀληθῆ λέγουσιν.","an":"Όσοι μιλούν δεν λένε πάντοτε την αλήθεια. (Η έναρθρη <i>οἱ λέγοντες</i> κλίνεται σαν επίθετο και ουσιαστικοποιείται, ενώ κρατά ρηματικό αντικείμενο <i>τἀληθῆ</i>: φανερή η διπλή φύση.)"}],"table":{"title":"Τα τρία είδη της μετοχής με μια ματιά","cols":["Είδος","Λειτουργία","Άρθρο","Αντιστοιχεί σε / μεταφράζεται"],"rows":[["Επιθετική / αναφορική","επίθετο ή ουσιαστικό (προσδιορίζει όνομα)","συνήθως έναρθρη","αναφορική πρόταση: «που / ο οποίος…»"],["Κατηγορηματική","κατηγορούμενο / κατηγορ. προσδιορισμός σε ορισμένα ρήματα","πάντοτε άναρθρη","«ότι/πως…», «να…», «που…»"],["Επιρρηματική","επιρρηματικός προσδιορισμός","πάντοτε άναρθρη","δευτερεύουσα επιρρηματική πρόταση"]]},"note":"Πρώτο διαγνωστικό: αν η μετοχή έχει άρθρο, είναι (σχεδόν πάντα) επιθετική. Αν είναι άναρθρη, διακρίνουμε κατηγορηματική (κρέμεται από συγκεκριμένο ρήμα και είναι αναγκαία) από επιρρηματική (εκφράζει χρονική/αιτιολογική κ.λπ. περίσταση)."},{"h":"Χρόνος και φωνή της μετοχής – οι χρονικές σχέσεις","body":"<p>Ο χρόνος της μετοχής δεν δηλώνει απόλυτο χρόνο, αλλά <b>σχέση</b> με τον χρόνο του ρήματος της πρότασης. Οι τρεις σχέσεις είναι:</p><ul><li><b>Σύγχρονο</b> (η πράξη της μετοχής γίνεται <i>ταυτόχρονα</i> με του ρήματος): δηλώνεται κανονικά με μετοχή <b>ενεστώτα</b>.</li><li><b>Προτερόχρονο</b> (η πράξη της μετοχής <i>προηγείται</i>): δηλώνεται με μετοχή <b>αορίστου</b> ή <b>παρακειμένου</b>.</li><li><b>Υστερόχρονο</b> (η πράξη της μετοχής <i>έπεται</i>· σπάνιο): δηλώνεται με μετοχή <b>μέλλοντα</b> – κυρίως στην τελική μετοχή.</li></ul><p>Ως προς τη <b>φωνή/διάθεση</b>, η μετοχή έχει ενεργητική (<i>λύων, λύσας</i>), μέση (<i>λυόμενος, λυσάμενος</i>) και παθητική (<i>λυόμενος, λυθείς, λελυμένος</i>). Η διάθεση καθορίζει και τη μετάφραση κατά την ανάλυση (ενεργητική/παθητική σύνταξη).</p><p>Η αναγνώριση χρόνου είναι κρίσιμη για την <i>ανάλυση</i>: καθορίζει αν θα βάλουμε «αφού/όταν είχε…» (προτερόχρονο) ή «ενώ/καθώς…» (σύγχρονο).</p>","examples":[{"gr":"Ἐπαιάνιζον ἅμα πλέοντες.","an":"Έψαλλαν τον παιάνα ενώ συγχρόνως έπλεαν. (Μετοχή ενεστώτα <i>πλέοντες</i> → σύγχρονο· το <i>ἅμα</i> τονίζει τη σύγχρονη πράξη.)"},{"gr":"Ἀναχωρησάντων δ' αὐτῶν οἱ Ἀθηναῖοι φυλακάς κατεστήσαντο.","an":"Αφού αυτοί αποχώρησαν, οι Αθηναίοι εγκατέστησαν φρουρές. (Μετοχή αορίστου <i>ἀναχωρησάντων</i> → προτερόχρονο: είχε προηγηθεί.)"},{"gr":"Κλέαρχος διέβη παρά τόν Φαρνάβαζον μισθόν ληψόμενος.","an":"Ο Κλέαρχος πέρασε στον Φαρνάβαζο για να πάρει μισθό. (Μετοχή μέλλοντα <i>ληψόμενος</i> → υστερόχρονο· τελική μετοχή.)"},{"gr":"Ἅμα τῇ ἡμέρᾳ συνελθόντες ἐβουλεύοντο.","an":"Ξεν. Ἀνάβ. 2.1.2 (τύπου) — Μόλις ξημέρωσε, αφού συγκεντρώθηκαν, σκέπτονταν. (Μετοχή αορίστου <i>συνελθόντες</i> → προτερόχρονο ως προς τον παρατατικό <i>ἐβουλεύοντο</i>.)"},{"gr":"Ταῦτα πεπραχότες χάριν ἡμῖν εἴσονται.","an":"Αφού θα έχουν κάνει αυτά, θα μας χρωστούν χάρη. (Μετοχή παρακειμένου <i>πεπραχότες</i> → προτερόχρονο με έμφαση στο αποτέλεσμα, ακόμη και ως προς μέλλοντα ρήμα.)"}],"table":{"title":"Χρόνος μετοχής → χρονική σχέση","cols":["Χρόνος μετοχής","Χρονική σχέση","Ενδεικτική μετάφραση"],"rows":[["Ενεστώτας","Σύγχρονο","«ενώ / καθώς / την ώρα που…»"],["Αόριστος","Προτερόχρονο","«αφού / όταν…» (πράξη που προηγήθηκε)"],["Παρακείμενος","Προτερόχρονο (με έμφαση στο αποτέλεσμα)","«αφού είχε…»"],["Μέλλοντας","Υστερόχρονο","«για να… / πρόκειται να…» (κυρ. τελική)"]]},"note":"Προσοχή: ο χρόνος της μετοχής εξετάζεται πάντοτε σε σχέση με το ρήμα της δικής της πρότασης. Μετοχή αορίστου σε πρόταση με ρήμα μέλλοντα δηλώνει και πάλι προτερόχρονο ως προς εκείνον τον μέλλοντα."},{"h":"Α. Επιθετική (αναφορική) μετοχή – η φύση της","body":"<p>Η <b>επιθετική</b> ή <b>αναφορική</b> μετοχή λειτουργεί ακριβώς όπως ένα <i>επίθετο</i> ή ένα <i>ουσιαστικό</i> και αποδίδει στο όνομα ένα <b>μόνιμο, σταθερό γνώρισμα</b>. Είναι κατά κανόνα <b>έναρθρη</b> (συνοδεύεται από άρθρο), γι' αυτό και αναγνωρίζεται εύκολα.</p><p>Ονομάζεται και <b>αναφορική</b> επειδή <b>αναλύεται πάντοτε σε αναφορική πρόταση</b>: <i>ὁ λέγων</i> = <i>ὁ ὅς λέγει</i> («αυτός που λέει»). Το άρθρο της μετοχής γίνεται κατά την ανάλυση <b>αναφορική αντωνυμία</b> (<i>ὅς, ἥ, ὅ</i>), και η μετοχή γίνεται ρήμα στον αντίστοιχο χρόνο/έγκλιση.</p><p>Σπανιότερα η επιθετική μετοχή είναι <b>άναρθρη</b>· τότε λειτουργεί σαν άναρθρο επίθετο/κατηγορηματικός προσδιορισμός και πάλι αναλύεται σε αναφορική (<i>ἄγγελον ἐστεφανωμένον</i> = αγγελιαφόρο που είχε στεφανωθεί).</p><p><b>Άρνηση:</b> παίρνει <b>οὐ</b> όταν δηλώνει πραγματικό γεγονός, και <b>μή</b> όταν έχει υποθετική/γενική σημασία (αναφορικοϋποθετική: <i>ὁ μή δαρείς</i> = «όποιος δεν δαρθεί»).</p>","examples":[{"gr":"Ἀδικοῦσιν οἱ τάς σπονδάς λύοντες.","an":"Αδικούν αυτοί που καταλύουν τις συνθήκες. → Ανάλυση: <i>Ἀδικοῦσιν οἵ τάς σπονδάς λύουσιν.</i> (Το άρθρο <i>οἱ</i> γίνεται αναφορική <i>οἵ</i>, η μετοχή ρήμα <i>λύουσιν</i>.)"},{"gr":"Ὁ μή δαρείς ἄνθρωπος οὐ παιδεύεται.","an":"Ο άνθρωπος που δεν δέρνεται δεν εκπαιδεύεται. (Άρνηση <i>μή</i> → αναφορικοϋποθετική σημασία: «όποιος δεν δαρθεί».)"},{"gr":"Τοῖς νόμοις τοῖς κειμένοις πειθώμεθα.","an":"Ας υπακούμε στους ισχύοντες νόμους. → <i>τοῖς νόμοις οἵ κεῖνται</i> (στους νόμους που ισχύουν). Επιθετικός προσδιορισμός."},{"gr":"Ὁ ποιῶν τι τῶν δικαίων ἐπαινεῖται.","an":"Αυτός που κάνει κάτι δίκαιο επαινείται. → <i>ὅς ποιεῖ τι…</i> (έναρθρη επιθετική, αναλύεται σε αναφορική· κρατά το ρηματικό αντικείμενο <i>τι</i>.)"},{"gr":"Οἱ φεύγοντες ἐκ τῆς μάχης διεσώθησαν.","an":"Όσοι έφευγαν από τη μάχη σώθηκαν. → <i>οἵ ἔφευγον ἐκ τῆς μάχης</i> (έναρθρη μετοχή ενεστώτα → αναφορική με οριστική παρατατικού)."}],"note":"Σταθερό κριτήριο: η έναρθρη μετοχή είναι σχεδόν πάντοτε επιθετική και αναλύεται σε αναφορική πρόταση. Το άρθρο μετατρέπεται σε αναφορική αντωνυμία της ίδιας πτώσης/γένους/αριθμού."},{"h":"Α2. Επιθετική μετοχή – ουσιαστικοποίηση, συντακτικές θέσεις, πλάγιες σημασίες","body":"<p><b>Ουσιαστικοποίηση:</b> όταν παραλείπεται το ουσιαστικό που θα προσδιόριζε η μετοχή, το <i>άρθρο + μετοχή</i> ουσιαστικοποιείται και λειτουργεί ως όνομα: <i>ὁ λέγων</i> (ο ομιλητής), <i>οἱ κρατοῦντες</i> (οι άρχοντες), <i>τό μέλλον</i> (το μέλλον), <i>τό συμφέρον</i> (το συμφέρον), <i>τό δέον</i> (το πρέπον), <i>τά γενόμενα</i> (τα γεγονότα). Η μετοχή στο ουδέτερο δίνει αφηρημένες έννοιες/πράγματα.</p><p><b>Συντακτικές θέσεις της επιθετικής μετοχής</b> (όπως κάθε ονοματικός τύπος):</p><ul><li><b>Υποκείμενο:</b> <i>οἱ φεύγοντες</i> ἐσώθησαν.</li><li><b>Αντικείμενο:</b> τιμῶμεν <i>τούς ἀγαθούς</i>… / <i>τό συμφέρον</i> διώκομεν.</li><li><b>Κατηγορούμενο:</b> οὗτός ἐστιν <i>ὁ ἀδικήσας</i>.</li><li><b>Επιθετικός προσδιορισμός:</b> <i>τοῖς κειμένοις</i> νόμοις.</li><li><b>Κατηγορηματικός προσδιορισμός:</b> Πατηγύας <i>ἐλαύνων</i> προφαίνεται.</li><li><b>Παράθεση / επεξήγηση, ετερόπτωτος ή εμπρόθετος προσδιορισμός, δοτική προσωπική:</b> ἡ τῶν <i>οἰκούντων</i> γνώμη· τοῖς <i>παροῦσι</i>.</li></ul><p><b>Πλάγιες (επιρρηματικές) σημασίες της αναφορικής μετοχής:</b> ακόμη κι έναρθρη, μπορεί να υπονοεί αιτία, σκοπό, υπόθεση ή εναντίωση (αναφορικο-αιτιολογική, -τελική, -υποθετική, -εναντιωματική). Η σημασία προκύπτει από τα συμφραζόμενα.</p>","examples":[{"gr":"Τό μέλλον ἄδηλόν ἐστι πᾶσιν ἀνθρώποις.","an":"Το μέλλον είναι άγνωστο σε όλους τους ανθρώπους. (Ουσιαστικοποιημένη μετοχή <i>τό μέλλον</i> = υποκείμενο.)"},{"gr":"Μακάριός ἐστι πᾶς ὁ μή θνητά φρονῶν.","an":"Ευτυχισμένος είναι καθένας που δεν σκέφτεται θνητά. (Αναφορικο-υποθετική: «αν/όποιος δεν φρονεί θνητά».)"},{"gr":"Οἱ κρατοῦντες ἀεί τοῖς νόμοις χρῶνται πρός τό συμφέρον.","an":"Οι κρατούντες πάντοτε χρησιμοποιούν τους νόμους προς το συμφέρον τους. (Δύο ουσιαστικοποιημένες μετοχές: <i>οἱ κρατοῦντες</i> υποκείμενο, <i>τό συμφέρον</i> εμπρόθετο.)"},{"gr":"Ὁ βουλόμενος Ἀθηναίων ἐγράφετο τόν ἀδικοῦντα.","an":"Όποιος Αθηναίος ήθελε μπορούσε να καταγγείλει τον αδικούντα. (Ουσιαστικοποιημένες <i>ὁ βουλόμενος</i> = υποκείμενο, <i>τόν ἀδικοῦντα</i> = αντικείμενο.)"},{"gr":"Ἔδει τά δέοντα πράττειν τούς ἄρχοντας.","an":"Δημ. (τύπου) — Έπρεπε οι άρχοντες να κάνουν τα πρέποντα. (Ουσιαστικοποιημένη ουδέτερη <i>τά δέοντα</i> = αντικείμενο του <i>πράττειν</i>: αφηρημένη έννοια.)"}],"table":{"title":"Συχνές ουσιαστικοποιημένες (έναρθρες) μετοχές","cols":["Μετοχή","Σημασία ως ουσιαστικό"],"rows":[["ὁ λέγων / οἱ λέγοντες","ο ομιλητής / οι ομιλητές"],["οἱ κρατοῦντες / οἱ ἄρχοντες","οι ισχυροί / οι άρχοντες"],["ὁ βουλόμενος","ο καθένας που θέλει, ο τυχών"],["τό μέλλον","το μέλλον"],["τό συμφέρον / τά συμφέροντα","το συμφέρον / τα συμφέροντα"],["τό δέον / τά δέοντα","το πρέπον / τα δέοντα, οι υποχρεώσεις"],["τά γενόμενα / τά παρόντα","τα γεγονότα / η παρούσα κατάσταση"]]}},{"h":"Β. Κατηγορηματική μετοχή – ορισμός και αναγνώριση","body":"<p>Η <b>κατηγορηματική</b> μετοχή είναι πάντοτε <b>άναρθρη</b>, <b>εξαρτάται από ορισμένα ρήματα</b> και αποδίδει ένα <b>χαρακτηριστικό γνώρισμα</b> στο <i>υποκείμενο</i> ή στο <i>αντικείμενο</i> του ρήματος εξάρτησης. Αντιστοιχεί στο κατηγορούμενο/κατηγορηματικό προσδιορισμό της απλής πρότασης· γι' αυτό είναι <b>αναγκαία</b> για το νόημα (δεν αφαιρείται).</p><p><b>Συντακτικός ρόλος:</b></p><ul><li><b>Κατηγορούμενο</b> στο υποκείμενο, όταν εξαρτάται από συνδετικό ρήμα (εἰμί, γίγνομαι, ὑπάρχω).</li><li><b>Κατηγορηματικός προσδιορισμός</b> στο υποκείμενο ή στο αντικείμενο των υπόλοιπων ρημάτων.</li></ul><p><b>Πώς ξεχωρίζει από την επιρρηματική:</b> η κατηγορηματική «κλειδώνει» σε ένα συγκεκριμένο ρήμα μιας ορισμένης σημασίας (αἰσθήσεως, γνώσεως, δείξεως, ψυχικού πάθους κ.λπ.) και είναι απαραίτητη· η επιρρηματική προσθέτει μια περίσταση και θα μπορούσε να λείπει.</p><p><b>Άρνηση:</b> κανονικά <b>οὐ</b>. <b>Μετάφραση:</b> ανάλογα με το ρήμα, «ότι/πως + οριστική», «να + υποτακτική» ή «που + οριστική».</p><p><b>Ανάλυση:</b> αναλύεται σε <b>δευτερεύουσα ειδική πρόταση (με ότι/πως)</b> μόνο όταν εξαρτάται από ρήματα <i>αἰσθήσεως, γνώσεως, μνήμης, δείξεως ή αγγελίας</i>.</p>","examples":[{"gr":"Οὐκ ἐπίστασθε θνητοί ὄντες;","an":"Δεν γνωρίζετε ότι είστε θνητοί; (Ρήμα γνώσεως <i>ἐπίσταμαι</i>· η μετοχή <i>ὄντες</i> = κατηγορ. προσδ. στο υποκείμενο, αναλύεται σε ειδική: <i>ὅτι θνητοί ἐστε</i>.)"},{"gr":"Ὁρῶμεν ὑμᾶς ἀπόρους ὄντας.","an":"Βλέπουμε ότι εσείς είστε σε αμηχανία. (Ρήμα αισθήσεως <i>ὁρῶ</i>· <i>ὄντας</i> = κατηγορ. προσδ. στο αντικείμενο <i>ὑμᾶς</i>.)"},{"gr":"Προσεοικότες γίγνονται τοῖς γονεῦσιν οἱ παῖδες.","an":"Τα παιδιά γίνονται όμοια με τους γονείς τους. (Συνδετικό <i>γίγνονται</i>· <i>προσεοικότες</i> = κατηγορούμενο στο υποκείμενο <i>οἱ παῖδες</i>.)"},{"gr":"Καί γάρ ὁμίχλη ἐγένετο, ὥστ' ἔλαθον ἐγγύς προσελθόντες.","an":"Ξεν. Ἀνάβ. 4.2.7 — Και πράγματι έπεσε ομίχλη, ώστε πλησίασαν χωρίς να γίνουν αντιληπτοί. (Ρήμα <i>λανθάνω</i> + κατηγ. μετοχή <i>προσελθόντες</i>· μεταφράζεται με το ρήμα ως επίρρημα «κρυφά/απαρατήρητα».)"},{"gr":"Ἐτύγχανον λέγοντες περί τῶν παρόντων.","an":"Ξεν. (τύπου) — Έτυχε να μιλούν για τα παρόντα. (Ρήμα <i>τυγχάνω</i> + κατηγ. μετοχή <i>λέγοντες</i>· βλ. Smyth 2096.)"}],"note":"Διάκριση από την επιθετική: η κατηγορηματική είναι ΑΝΑΡΘΡΗ και κρέμεται από ορισμένο ρήμα. Διάκριση από την επιρρηματική: η κατηγορηματική είναι ΑΝΑΓΚΑΙΑ (συμπλήρωμα του ρήματος), ενώ η επιρρηματική είναι περίσταση που μπορεί να αφαιρεθεί."},{"h":"Β2. Κατηγορηματική μετοχή – οι ομάδες ρημάτων (πλήρεις κατάλογοι)","body":"<p>Η κατηγορηματική μετοχή ζητείται από <b>συγκεκριμένες σημασιολογικές ομάδες ρημάτων</b>. Η εκμάθηση αυτών των ομάδων είναι το κλειδί για την αναγνώριση. Διακρίνουμε:</p><ul><li><b>Συνδετικά:</b> εἰμί, γίγνομαι, ὑπάρχω → μετοχή = κατηγορούμενο.</li><li><b>Διάρκειας / καρτερίας / λήθης / τύχης:</b> διατελῶ, διάγω, διαβιῶ, διαμένω, (οὐ) διαλείπω, λανθάνω (= διαφεύγω), οἴχομαι, τυγχάνω, φαίνομαι / φανερός εἰμι, δῆλός εἰμι, φθάνω. Πολλά μεταφράζονται με <b>τροπικό επίρρημα</b> + κύριο ρήμα (βλ. πίνακα).</li><li><b>Έναρξης / λήξης:</b> ἄρχω, ἄρχομαι, παύομαι, παύω, λήγω, ἀπολείπω, ἐπιλείπω· και ανοχής/κόπωσης: ἀνέχομαι, κάμνω, καρτερῶ, ὑπομένω → μετάφραση «να + υποτακτική».</li><li><b>Αισθήσεως:</b> αἰσθάνομαι, ὁρῶ, ἀκούω, πυνθάνομαι.</li><li><b>Γνώσεως / μάθησης / μνήμης / λήθης:</b> γιγνώσκω, οἶδα, ἐπίσταμαι, μανθάνω, ἐνθυμοῦμαι, μέμνημαι, ἐπιλανθάνομαι, ἀγνοῶ, περιορῶ.</li><li><b>Δείξεως / αγγελίας / ελέγχου:</b> δείκνυμι, ἐπιδείκνυμι, ἀποδείκνυμι, δηλῶ, ἀποφαίνω, (ἀν/ἀπ)αγγέλλω, ἐλέγχω, παρέχω, φαίνω, φαίνομαι.</li><li><b>Ψυχικού πάθους:</b> χαίρω, ἥδομαι, τέρπομαι, ἀγαπῶ, ἀγανακτῶ, ἄχθομαι, ἀλγῶ, λυποῦμαι, ὀργίζομαι, αἰσχύνομαι, αἰδοῦμαι, μεταμέλομαι, βαρέως φέρω.</li><li><b>Ευεργεσίας / αδικίας / νίκης / ήττας:</b> εὖ/καλῶς/κακῶς ποιῶ, χαρίζομαι, ἀδικῶ, νικῶ, περιγίγνομαι, κρατῶ, ἡττῶμαι, λείπομαι.</li></ul><p>Στα ρήματα <i>αἰσθήσεως</i> (ἀκούω, αἰσθάνομαι) ισχύει λεπτή διάκριση: <b>γενική + μετοχή</b> = άμεση αντίληψη («το είδα/άκουσα ο ίδιος»), ενώ <b>αιτιατική + μετοχή</b> = έμμεση γνώση/πληροφορία.</p>","examples":[{"gr":"Ἀλλ' αὐτοί φθήσονται τοῦτο δράσαντες.","an":"Αλλά αυτοί οι ίδιοι θα το κάνουν πρώτοι. (Ρήμα <i>φθάνω</i> + μετοχή· μεταφράζεται με επίρρημα «πρώτοι».)"},{"gr":"Οὗτος ἦρξεν ἀδικῶν ἡμᾶς.","an":"Αυτός άρχισε να μας αδικεί. (Ρήμα έναρξης <i>ἄρχομαι</i> + μετοχή <i>ἀδικῶν</i> → «να + υποτακτική».)"},{"gr":"Μή κάμῃς φίλον ἄνδρα εὐεργετῶν.","an":"Μην κουραστείς να ευεργετείς τον φίλο σου. (Ρήμα ανοχής/κόπωσης <i>κάμνω</i>.)"},{"gr":"Ἐπέδειξα τοῦτον ψευδόμενον.","an":"Απέδειξα ότι αυτός ψεύδεται. (Ρήμα δείξεως <i>ἐπιδείκνυμι</i>· αναλύεται σε ειδική: <i>ὅτι οὗτος ψεύδεται</i>.)"},{"gr":"Ἀκούω αὐτόν ταῦτα ποιοῦντα.","an":"Πληροφορούμαι ότι αυτός κάνει αυτά. (Αιτιατική + μετοχή → έμμεση γνώση. Πβ. γενική + μετοχή = άμεση αντίληψη.)"},{"gr":"Ἄλλοι δέ τῶν στρατηγῶν κατά ἀτριβεῖς ὁδούς ἐπορεύοντο ᾗ ἔτυχον ἕκαστοι ὄντες.","an":"Ξεν. Ἀνάβ. 4.2.8 — Άλλοι πάλι από τους στρατηγούς προχωρούσαν από απάτητους δρόμους, από όπου ο καθένας τύχαινε να βρίσκεται. (Ρήμα τύχης <i>τυγχάνω</i> + κατηγ. μετοχή <i>ὄντες</i>.)"},{"gr":"Διετέλει εὖ ποιῶν τούς φίλους.","an":"Ξεν. (τύπου) — Συνεχώς ευεργετούσε τους φίλους. (Ρήμα διάρκειας <i>διατελῶ</i> + μετοχή· «εὖ ποιῶ» + μετοχή της ευεργεσίας. Μεταφρ. με επίρρημα «συνεχώς».)"}],"table":{"title":"Ομάδες ρημάτων που ζητούν κατηγορηματική μετοχή","cols":["Σημασιολογική ομάδα","Κύρια ρήματα","Συνήθης μετάφραση μετοχής"],"rows":[["Συνδετικά","εἰμί, γίγνομαι, ὑπάρχω","κατηγορούμενο («είμαι/γίνομαι …»)"],["Διάρκειας / καρτερίας / τύχης","διατελῶ, διάγω, λανθάνω, τυγχάνω, φθάνω, οἴχομαι, φαίνομαι, δῆλός/φανερός εἰμι","με τροπικό επίρρημα (συνεχώς, κρυφά, τυχαία, πρώτος, φανερά…)"],["Έναρξης / λήξης / ανοχής","ἄρχομαι, παύομαι, λήγω, ἀνέχομαι, κάμνω, καρτερῶ","«να + υποτακτική»"],["Αισθήσεως","αἰσθάνομαι, ὁρῶ, ἀκούω, πυνθάνομαι","«ότι + οριστική» / «να + υποτ.»"],["Γνώσεως / μνήμης","γιγνώσκω, οἶδα, ἐπίσταμαι, μανθάνω, μέμνημαι, ἐπιλανθάνομαι, ἀγνοῶ","«ότι + οριστική»"],["Δείξεως / αγγελίας / ελέγχου","δείκνυμι, δηλῶ, ἀποφαίνω, ἀγγέλλω, ἐλέγχω, παρέχω","«ότι + οριστική»"],["Ψυχικού πάθους","χαίρω, ἥδομαι, ἀγανακτῶ, ἄχθομαι, αἰσχύνομαι, ὀργίζομαι, μεταμέλομαι","«που / γιατί + οριστική», «να…»"],["Ευεργεσίας / αδικίας / νίκης / ήττας","εὖ ποιῶ, ἀδικῶ, νικῶ, κρατῶ, ἡττῶμαι, περιγίγνομαι","«να + υποτακτική» / «που + οριστική»"]]},"note":"Πρακτικά: τα ρήματα διάρκειας/τύχης (λανθάνω, τυγχάνω, φθάνω, διατελῶ) μεταφράζονται καλύτερα αν κάνουμε το ρήμα επίρρημα και τη μετοχή κύριο ρήμα: «ἔλαθεν ἀποδράς» = «ξέφυγε κρυφά». Δες τον πίνακα στο επόμενο block."},{"h":"Β3. Κατηγορηματική μετοχή – ψυχικού πάθους & τα ρήματα-«παγίδες»","body":"<p><b>Ρήματα ψυχικού πάθους</b> (χαίρω, ἥδομαι, ἀγανακτῶ, ἄχθομαι, αἰσχύνομαι, ὀργίζομαι, μεταμέλομαι, λυποῦμαι, βαρέως φέρω): η μετοχή τους είναι <b>κατηγορηματική</b> όταν δηλώνει πράξη <b>σύγχρονη</b> με το συναίσθημα, αλλά γίνεται <b>επιρρηματική αιτιολογική</b> όταν δηλώνει πράξη <b>προτερόχρονη</b> (το προηγούμενο γεγονός που προκάλεσε το συναίσθημα). Αυτό είναι κλασικό σημείο εξετάσεων.</p><p><b>Ρήματα που αλλάζουν σημασία</b> με μετοχή ή με απαρέμφατο. Η μετοχή δηλώνει <i>πραγματικό γεγονός / γνώση</i>, ενώ το απαρέμφατο δηλώνει <i>ικανότητα, απόφαση ή τάση</i>:</p><ul><li><b>γιγνώσκω</b> + μετοχή = αντιλαμβάνομαι ότι· + απαρέμφατο = αποφασίζω να.</li><li><b>οἶδα / ἐπίσταμαι</b> + μετοχή = γνωρίζω ότι· + απαρέμφατο = ξέρω να (έχω την ικανότητα).</li><li><b>μανθάνω</b> + μετοχή = πληροφορούμαι ότι· + απαρέμφατο = μαθαίνω να.</li><li><b>αἰσχύνομαι / αἰδοῦμαι</b> + μετοχή = ντρέπομαι για κάτι που (το κάνω παρ' όλα αυτά)· + απαρέμφατο = ντρέπομαι και δεν το κάνω.</li><li><b>φαίνομαι</b> + μετοχή = είναι φανερό ότι (και πράγματι)· + απαρέμφατο = φαίνεται/δίνει την εντύπωση ότι (χωρίς βεβαιότητα).</li></ul>","examples":[{"gr":"Ἔχαιρεν ἀκούων ταῦτα.","an":"Χαιρόταν που άκουγε αυτά. (Κατηγορηματική: η ακρόαση είναι σύγχρονη με τη χαρά.)"},{"gr":"Μετεμέλοντο τάς σπονδάς οὐ δεξάμενοι.","an":"Μετάνιωναν που δεν είχαν δεχτεί τη συνθήκη. (Προτερόχρονη πράξη → αιτιολογική μετοχή: «επειδή δεν είχαν δεχτεί».)"},{"gr":"Οὐ γάρ αἰσχύνομαι μανθάνων.","an":"Δεν ντρέπομαι που μαθαίνω. (αἰσχύνομαι + μετοχή = το κάνω παρ' όλη την ντροπή.)"},{"gr":"Αἰσχύνομαι εἰπεῖν τἀληθῆ.","an":"Ντρέπομαι να πω την αλήθεια (και γι' αυτό δεν τη λέω). (αἰσχύνομαι + απαρέμφατο = αναστολή.)"},{"gr":"Ἀλέξανδρος ἔγνω διαβαίνειν τόν Ἴστρον.","an":"Ο Αλέξανδρος αποφάσισε να περάσει τον Ίστρο. (γιγνώσκω + απαρέμφατο = απόφαση· πβ. + μετοχή = αντίληψη.)"},{"gr":"Φαίνεται ἀδικῶν ὁ κατήγορος.","an":"Είναι φανερό ότι ο κατήγορος αδικεί. (φαίνομαι + κατηγ. μετοχή <i>ἀδικῶν</i> = πραγματικό γεγονός· πβ. <i>φαίνεται ἀδικεῖν</i> = δίνει την εντύπωση ότι αδικεί.)"},{"gr":"Ἐπίσταμαι Ἑλληνιστί γράφειν.","an":"Ξέρω να γράφω ελληνικά. (ἐπίσταμαι + απαρέμφατο = ικανότητα· πβ. <i>ἐπίσταμαι θνητός ὤν</i> = γνωρίζω ότι είμαι θνητός.)"}],"table":{"title":"Μετοχή vs. απαρέμφατο σε ρήματα-«παγίδες»","cols":["Ρήμα","+ μετοχή (γεγονός/γνώση)","+ απαρέμφατο (ικανότητα/απόφαση/τάση)"],"rows":[["γιγνώσκω","αντιλαμβάνομαι ότι","αποφασίζω να"],["οἶδα / ἐπίσταμαι","γνωρίζω ότι","ξέρω να (ικανότητα)"],["μανθάνω","πληροφορούμαι ότι","μαθαίνω να"],["αἰσχύνομαι","ντρέπομαι για κάτι (μα το κάνω)","ντρέπομαι (και δεν το κάνω)"],["φαίνομαι","είναι φανερό ότι (πραγματικά)","δίνω την εντύπωση ότι (αβέβαια)"]]}},{"h":"Γ. Επιρρηματική μετοχή – χρονική, αιτιολογική, τελική","body":"<p>Η <b>επιρρηματική</b> μετοχή είναι πάντοτε <b>άναρθρη</b> και λειτουργεί ως <b>επιρρηματικός προσδιορισμός</b>, εκφράζοντας την περίσταση μέσα στην οποία γίνεται η πράξη του ρήματος. Αναλύεται σε αντίστοιχη <b>δευτερεύουσα επιρρηματική πρόταση</b>. Έχει έξι είδη· τα τρία πρώτα:</p><h3>1. Χρονική μετοχή</h3><p>Δηλώνει τον <b>χρόνο</b> της κύριας πράξης (σύγχρονο/προτερόχρονο, σπάνια υστερόχρονο). Άρνηση <b>οὐ</b> (ή <b>μή</b> με υποθετική χροιά). Αναλύεται με <b>ὅτε, ἐπεί, ἐπειδή</b> + οριστική. Ενισχύεται από τα <i>ἅμα, μεταξύ, εὐθύς, αὐτίκα</i>.</p><h3>2. Αιτιολογική μετοχή</h3><p>Δηλώνει την <b>αιτία</b>. Άρνηση <b>οὐ</b>. Εισάγεται/ενισχύεται από: <b>ἅτε, οἷον, οἷα</b> (αντικειμενική, πραγματική αιτία) και <b>ὡς</b> (υποκειμενική αιτία, γνώμη του υποκειμένου/ομιλητή). Αναλύεται με <b>ἐπεί, ὅτι, διότι</b> + οριστική (ή ευκτική του πλαγίου λόγου με <i>ὡς</i>).</p><h3>3. Τελική μετοχή</h3><p>Δηλώνει τον <b>σκοπό</b>. Είναι κατά κανόνα μετοχή <b>μέλλοντα</b> (υστερόχρονο) και συντάσσεται με ρήματα <i>κίνησης</i>. Άρνηση <b>μή</b>. Με <b>ὡς</b> δηλώνεται υποκειμενικός σκοπός. Αναλύεται με <b>ἵνα, ὅπως, ὡς</b> + υποτακτική.</p>","examples":[{"gr":"Ταῦτα εἰπών ἐπαύσατο.","an":"Αφού είπε αυτά, σταμάτησε. (Χρονική, προτερόχρονη → <i>ἐπεί ταῦτα εἶπεν, ἐπαύσατο</i>.)"},{"gr":"Ὁρῶν αὐτούς λυπουμένους ὑπεσχόμην γράφειν.","an":"Επειδή τους έβλεπα λυπημένους, υποσχέθηκα να γράψω. (Αιτιολογική → <i>ἐπεί ἑώρων…</i>.)"},{"gr":"Ἅτε οὖν νίκης ἐρῶντες ἀνδρείως μάχεσθε.","an":"Επειδή λοιπόν πραγματικά ποθείτε τη νίκη, να μάχεστε γενναία. (Αιτιολογική με <i>ἅτε</i> → αντικειμενική, πραγματική αιτία.)"},{"gr":"Ὡς προθυμοτάτοις οὖσιν ὑμῖν χάριν εἴσεται Κῦρος.","an":"Επειδή κατά τη γνώμη του είστε προθυμότατοι, ο Κύρος θα σας χρωστά χάρη. (Αιτιολογική με <i>ὡς</i> → υποκειμενική αιτία.)"},{"gr":"Πέμπουσιν Ἱερώνυμον ἐροῦντα ταῦτα.","an":"Στέλνουν τον Ιερώνυμο για να πει αυτά. (Τελική, μετοχή μέλλοντα <i>ἐροῦντα</i> με ρήμα κίνησης → <i>ἵνα ταῦτα εἴπῃ</i>.)"},{"gr":"Ἐπειδή δέ ἐτελεύτησε Δαρεῖος, κατέστη Ἀρταξέρξης εἰς τήν βασιλείαν.","an":"Ξεν. Ἀνάβ. 1.1.3 (τύπου, χρον. ρήμα) — Όταν πέθανε ο Δαρείος, ανέβηκε στον θρόνο ο Αρταξέρξης. Πβ. χρονική μετοχή: <i>τελευτήσαντος Δαρείου</i> → προτερόχρονο."},{"gr":"Ἐπείσθη καί συλλαμβάνει Κῦρον ὡς ἀποκτενῶν.","an":"Ξεν. Ἀνάβ. 1.1.3 — Πείστηκε και συλλαμβάνει τον Κύρο με τον σκοπό να τον σκοτώσει. (Τελική μετοχή μέλλοντα <i>ἀποκτενῶν</i> με <i>ὡς</i> → υποκειμενικός σκοπός.)"}],"table":{"title":"Εισαγωγικά / ανάλυση των τριών πρώτων επιρρηματικών μετοχών","cols":["Είδος","Εισαγωγικά μόρια","Άρνηση","Ανάλυση (σύνδεσμος + έγκλιση)"],"rows":[["Χρονική","ἅμα, μεταξύ, εὐθύς (ενισχυτικά)","οὐ","ὅτε / ἐπεί / ἐπειδή + οριστική"],["Αιτιολογική","ἅτε, οἷον, οἷα (αντικ.) · ὡς (υποκ.)","οὐ","ἐπεί / ὅτι / διότι + οριστική (ή ευκτ. πλαγ.)"],["Τελική","ὡς (υποκειμενικός σκοπός)","μή","ἵνα / ὅπως / ὡς + υποτακτική"]]},"note":"Κλειδί διάκρισης αιτίας: ἅτε / οἷα → αντικειμενική (πραγματική) αιτία· ὡς → υποκειμενική αιτία (η αιτία παρουσιάζεται ως υποκειμενική γνώμη). Η τελική μετοχή είναι σχεδόν πάντα μέλλοντα και συνοδεύει ρήμα κίνησης."},{"h":"Γ2. Επιρρηματική μετοχή – υποθετική, εναντιωματική, τροπική","body":"<h3>4. Υποθετική μετοχή</h3><p>Ισοδυναμεί με την <b>υπόθεση</b> ενός υποθετικού λόγου (δηλώνει όρο/προϋπόθεση). Άρνηση <b>μή</b> (αυτό βοηθά στην αναγνώριση). Βρίσκεται συχνά σε περιβάλλον με <i>δυνητικό ἄν</i>, μέλλοντα οριστικής ή απρόσωπα του «δύνασθαι». Αναλύεται με <b>εἰ</b> (+ οριστική/ευκτική) ή <b>ἐάν</b> (+ υποτακτική), ανάλογα με το είδος του υποθετικού λόγου.</p><h3>5. Εναντιωματική / παραχωρητική μετοχή</h3><p>Δηλώνει <b>εναντίωση/παραχώρηση</b> (κάτι που γίνεται παρά την αντίθετη προσδοκία). Άρνηση <b>οὐ</b>. Ενισχύεται πολύ συχνά από <b>καίπερ</b> (όταν είναι συνημμένη) ή <b>καί</b>, και από τα <i>καίτοι, ὅμως, πάνυ, καί ταῦτα</i> στην κύρια. Αναλύεται με <b>εἰ καί, καί εἰ, ἄν καί, καίτοι</b> + οριστική.</p><h3>6. Τροπική μετοχή</h3><p>Δηλώνει τον <b>τρόπο/μέσο</b> με τον οποίο γίνεται η πράξη. Είναι κατά κανόνα μετοχή <b>ενεστώτα</b> και βρίσκεται σε συνεχή σχέση με το ρήμα (σύγχρονο). Άρνηση <b>οὐ</b> (με άρνηση αποδίδεται «χωρίς να…»). <b>Δεν αναλύεται</b> σε δευτερεύουσα πρόταση – αποδίδεται με «με το να…», γερουνδιακή φράση ή τροπικό επίρρημα.</p><p>Πολλές τροπικές μετοχές έχουν παγιωθεί ως επιρρήματα: <i>λαθών/λαθραίως</i> (κρυφά), <i>φθάσας</i> (γρήγορα/πρώτος), <i>ἀρξάμενος</i> (αρχικά), <i>τελευτῶν</i> (στο τέλος), <i>χαίρων</i> (ατιμώρητα).</p>","examples":[{"gr":"Νικήσαντες μέν ἁπάντων τούτων ὑμεῖς κύριοι ἔσεσθε.","an":"Αν νικήσετε, εσείς θα γίνετε κύριοι όλων αυτών. (Υποθετική → <i>ἐάν νικήσητε…</i>· περιβάλλον μέλλοντα.)"},{"gr":"Οἱ μή τοῦτο ποιοῦντες οὐκ ἄν σωθεῖεν.","an":"Όσοι δεν κάνουν αυτό, δεν θα μπορούσαν να σωθούν. (Άρνηση <i>μή</i> + δυνητικό <i>ἄν</i> → υποθετική: «αν δεν…».)"},{"gr":"Καίπερ αἰσθανόμενος ταῦτα ὅμως ἐπέμενε ταῖς σπονδαῖς.","an":"Αν και τα αντιλαμβανόταν αυτά, παρ' όλα αυτά έμενε πιστός στη συνθήκη. (Εναντιωματική με <i>καίπερ</i> → <i>εἰ καί ᾐσθάνετο…</i>.)"},{"gr":"Οἱ βάρβαροι ἀπῆλθον οὐδέν ἀποκρινάμενοι.","an":"Οι βάρβαροι έφυγαν χωρίς να απαντήσουν τίποτε. (Τροπική με άρνηση → «χωρίς να…».)"},{"gr":"Ἀφίκοντο πρός ἡμᾶς τήν ἐπιστολήν φέροντες.","an":"Έφτασαν σ' εμάς φέρνοντας την επιστολή. (Τροπική, μετοχή ενεστώτα → «με το να φέρνουν».)"},{"gr":"Σύ δέ καί παρών οὐ βοηθεῖς.","an":"Εσύ όμως, αν και είσαι παρών, δεν βοηθάς. (Εναντιωματική με ενισχυτικό <i>καί</i> → <i>εἰ καί πάρει…</i>· άρνηση οὐ.)"},{"gr":"Ταῦτα ποιοῦντες εὖ ἄν πράττοιτε.","an":"Αν κάνετε αυτά, θα ευημερούσατε. (Υποθετική σε περιβάλλον δυνητικής ευκτικής <i>ἄν πράττοιτε</i> → <i>εἰ ταῦτα ποιοῖτε</i>.)"}],"table":{"title":"Εισαγωγικά / ανάλυση των τριών τελευταίων επιρρηματικών μετοχών","cols":["Είδος","Εισαγωγικά / δείκτες","Άρνηση","Ανάλυση / απόδοση"],"rows":[["Υποθετική","δυνητικό ἄν, μέλλ. οριστ. στην κύρια","μή","εἰ + οριστ./ευκτ. ή ἐάν + υποτακτική"],["Εναντιωματική","καίπερ, καί · (κύρια: ὅμως, καίτοι)","οὐ","εἰ καί / καί εἰ / ἄν καί + οριστική"],["Τροπική","(συχνά παγιωμένη: λαθών, φθάσας…)","οὐ → «χωρίς να»","δεν αναλύεται· «με το να…» / επίρρημα"]]},"note":"Κανόνας άρνησης ως κλειδί: υποθετική και τελική → μή· χρονική, αιτιολογική, εναντιωματική, τροπική → οὐ. Άρα μια άναρθρη μετοχή με μή είναι, κατά κανόνα, υποθετική ή τελική."},{"h":"Δ. Συνημμένη και απόλυτη μετοχή – γενική & αιτιατική απόλυτη","body":"<p>Με κριτήριο αν το <b>υποκείμενο της μετοχής</b> έχει ή όχι άλλη θέση στην πρόταση, η μετοχή είναι συνημμένη ή απόλυτη.</p><h3>Συνημμένη μετοχή</h3><p>Το υποκείμενο της μετοχής έχει <b>και άλλη συντακτική θέση</b> στην πρόταση: είναι το <i>υποκείμενο</i>, το <i>αντικείμενο</i> ή έμμεσο αντικείμενο (δοτική) του ρήματος. Τότε η μετοχή συμφωνεί κατά πτώση με τον όρο αυτόν.</p><h3>Απόλυτη μετοχή</h3><p>Το υποκείμενο της μετοχής <b>δεν έχει καμία άλλη θέση</b> στην πρόταση – υπάρχει μόνο για χάρη της μετοχής. Δύο μορφές:</p><ul><li><b>Γενική απόλυτη:</b> για <b>προσωπικά</b> ρήματα. Μετοχή + υποκείμενο σε <b>γενική</b>. Καλύπτει όλα τα επιρρηματικά είδη (χρονική, αιτιολογική, υποθετική, εναντιωματική) – <i>όχι</i> την τελική.</li><li><b>Αιτιατική απόλυτη:</b> για <b>απρόσωπα</b> ρήματα και εκφράσεις. Η μετοχή μπαίνει σε <b>ουδέτερο ενικού, αιτιατική</b>. Συνηθέστερα εναντιωματική, αλλά και αιτιολογική/χρονική/υποθετική.</li></ul><p>Συχνές αιτιατικές απόλυτες (απρόσωπα): <i>δέον</i> (αφού/αν και πρέπει), <i>ἐξόν</i> (αν και ήταν δυνατό), <i>παρόν</i> (ενώ ήταν δυνατό), <i>προσῆκον</i> (αν και ταίριαζε), <i>δυνατόν ὄν</i>, <i>δόξαν</i> / <i>δεδογμένον</i> (αφού αποφασίστηκε), <i>εἰρημένον</i> / <i>γεγραμμένον</i> / <i>προστεταγμένον</i> (αφού/αν και είχε οριστεί).</p>","examples":[{"gr":"Κρέοντος βασιλεύοντος οὐ μικρά συμφορά κατέσχε Θήβας.","an":"Όταν βασίλευε ο Κρέων, μεγάλη συμφορά κατέλαβε τη Θήβα. (Γενική απόλυτη, χρονική: το <i>Κρέοντος</i> δεν έχει άλλη θέση.)"},{"gr":"Χρημάτων δεομένης τῆς Σπάρτης πρός πόλεμον ἐπορεύθη ὁ Ἀγησίλαος.","an":"Επειδή η Σπάρτη χρειαζόταν χρήματα για τον πόλεμο, ξεκίνησε ο Αγησίλαος. (Γενική απόλυτη, αιτιολογική.)"},{"gr":"Ἐξόν μοι ἴσον λαμβάνειν οὐκ ἐλάμβανον.","an":"Αν και ήταν δυνατό να παίρνω ίσο μερίδιο, δεν έπαιρνα. (Αιτιατική απόλυτη <i>ἐξόν</i> από απρόσωπο <i>ἔξεστι</i>, εναντιωματική· υποκείμενο το <i>λαμβάνειν</i>.)"},{"gr":"Ἀδύνατον ὄν ἐν νυκτί ἄλλῳ τῳ σημῆναι, παρεκελεύοντο κραυγῇ χρώμενοι.","an":"Επειδή ήταν αδύνατο να σημάνουν αλλιώς μέσα στη νύχτα, παρότρυναν με κραυγές. (Αιτιατική απόλυτη <i>ἀδύνατον ὄν</i>, αιτιολογική.)"},{"gr":"Σκότους ὄντος προσέβαλον τῷ τείχει.","an":"Θουκ. (τύπου) — Επειδή ήταν σκοτάδι, επιτέθηκαν στο τείχος. (Γενική απόλυτη, αιτιολογική: το <i>σκότους</i> δεν έχει άλλη θέση.)"},{"gr":"Δόξαν ταῦτα, ἐπορεύοντο εἰς τό στρατόπεδον.","an":"Ξεν. (τύπου) — Αφού αποφασίστηκαν αυτά, βάδιζαν προς το στρατόπεδο. (Αιτιατική απόλυτη <i>δόξαν</i> από απρόσωπο <i>δοκεῖ</i>, χρονικο-αιτιολογική.)"}],"table":{"title":"Συνημμένη vs. απόλυτη μετοχή","cols":["Τύπος","Υποκείμενο μετοχής","Πτώση","Πότε"],"rows":[["Συνημμένη","έχει κι άλλη θέση (υποκ./αντικ./δοτ.) στην πρόταση","ανάλογα με τον όρο","γενική περίπτωση"],["Γενική απόλυτη","δεν έχει άλλη θέση","γενική","προσωπικά ρήματα (όχι τελική)"],["Αιτιατική απόλυτη","δεν έχει άλλη θέση / απρόσωπο","ουδέτ. ενικ. αιτιατική","απρόσωπα ρήματα/εκφράσεις"]]},"note":"Μνημονικό: γενική απόλυτη = προσωπικά ρήματα· αιτιατική απόλυτη = απρόσωπα (ἐξόν, δέον, παρόν, προσῆκον, δόξαν, δεδογμένον). Η τελική σχέση δεν εκφέρεται με γενική απόλυτη."},{"h":"Ε. Η ανάλυση της μετοχής σε πρόταση – μέθοδος & πίνακας-σύνοψη","body":"<p>Η <b>ανάλυση</b> μετατρέπει τη μετοχή στην ισοδύναμη δευτερεύουσα πρόταση. Ακολουθούμε σταθερά βήματα:</p><ul><li><b>1.</b> Αναγνωρίζω <i>είδος</i> μετοχής (επιθετική / κατηγορηματική / επιρρηματική και ποια).</li><li><b>2.</b> Βρίσκω το <i>υποκείμενο</i> της μετοχής και τον <i>χρόνο</i> της (→ χρονική σχέση: σύγχρονο/προτερόχρονο/υστερόχρονο).</li><li><b>3.</b> Κοιτάζω τον <i>χρόνο/έγκλιση του ρήματος</i> εξάρτησης (καθορίζει την έγκλιση: αρκτικός → υποτακτική, ιστορικός → ευκτική πλαγίου, στις προτάσεις που το επιτρέπουν).</li><li><b>4.</b> Επιλέγω τον κατάλληλο <i>σύνδεσμο</i> και την <i>έγκλιση</i> (βλ. πίνακα).</li><li><b>5.</b> Διατηρώ το υποκείμενο, μεταφέρω αντικείμενα/προσδιορισμούς, ελέγχω το νόημα.</li></ul><p><b>Επιθετική</b> → αναφορική πρόταση (άρθρο → αναφορική αντωνυμία). <b>Κατηγορηματική</b> από ρήμα αἰσθήσεως/γνώσεως/δείξεως/αγγελίας → <b>ειδική</b> πρόταση (ὅτι/ὡς). <b>Επιρρηματική</b> → η αντίστοιχη επιρρηματική πρόταση. Η <b>τροπική</b> κανονικά δεν αναλύεται.</p>","examples":[{"gr":"Οἱ δέ Ἀθηναῖοι ναῦς δώδεκα λαβόντες ἀνεχώρησαν.","an":"Οι Αθηναίοι, αφού πήραν δώδεκα πλοία, αποχώρησαν. → <i>Οἱ Ἀθηναῖοι, ἐπεί ναῦς δώδεκα ἔλαβον, ἀνεχώρησαν.</i> (Χρονική, προτερόχρονη· ρήμα ιστορικού χρόνου → οριστική.)"},{"gr":"Ἀδικοῦσιν οἱ τάς σπονδάς λύοντες.","an":"Αδικούν αυτοί που καταλύουν τις συνθήκες. → <i>Ἀδικοῦσιν οἵ τάς σπονδάς λύουσιν.</i> (Επιθετική → αναφορική.)"},{"gr":"Ἤκουε τιμώμενος ὑπό πάντων.","an":"Μάθαινε ότι τον τιμούσαν όλοι. → <i>Ἤκουε ὅτι ἐτιμᾶτο ὑπό πάντων.</i> (Κατηγορηματική από ρήμα αἰσθήσεως → ειδική πρόταση.)"},{"gr":"Βουλόμενος μαθεῖν ἦλθεν.","an":"Επειδή ήθελε να μάθει, ήρθε. → <i>ἐπεί ἐβούλετο μαθεῖν, ἦλθεν.</i> (Επιρρηματική αιτιολογική → αιτιολογική πρόταση με οριστική, ρήμα ιστορικού χρόνου.)"},{"gr":"Πέμπει ἄγγελον ἐροῦντα ταῦτα.","an":"Στέλνει αγγελιαφόρο για να πει αυτά. → <i>ἵνα ταῦτα εἴπῃ.</i> (Τελική μετοχή μέλλοντα → τελική πρόταση· ρήμα αρκτικού χρόνου → υποτακτική.)"}],"table":{"title":"Πίνακας-σύνοψη ανάλυσης μετοχής","cols":["Είδος μετοχής","Αναλύεται σε","Σύνδεσμος","Έγκλιση"],"rows":[["Επιθετική / αναφορική","αναφορική πρόταση","ὅς, ἥ, ὅ","οριστική (όπως το ρήμα)"],["Κατηγορηματική (αἰσθ./γνώσ./δείξ./αγγ.)","ειδική (ονοματική) πρόταση","ὅτι, ὡς","οριστική / ευκτική πλαγίου"],["Χρονική","χρονική πρόταση","ὅτε, ἐπεί, ἐπειδή","οριστική"],["Αιτιολογική","αιτιολογική πρόταση","ἐπεί, ὅτι, διότι","οριστική (ή ευκτ. πλαγ. με ὡς)"],["Τελική","τελική πρόταση","ἵνα, ὅπως, ὡς","υποτακτική (ή ευκτ. πλαγ.)"],["Υποθετική","υπόθεση υποθ. λόγου","εἰ, ἐάν","οριστ./ευκτ./υποτακτική"],["Εναντιωματική","εναντιωματική/παραχωρητική","εἰ καί, καί εἰ, ἄν καί","οριστική / υποτακτική"],["Τροπική","(δεν αναλύεται)","—","«με το να…» / επίρρημα"]]},"note":"Η έγκλιση στην ανάλυση εξαρτάται και από τον χρόνο του ρήματος εξάρτησης: μετά από αρκτικό χρόνο διατηρείται η κύρια έγκλιση (π.χ. υποτακτική στις τελικές), ενώ μετά από ιστορικό χρόνο μπορεί να εμφανιστεί ευκτική του πλαγίου λόγου, όπου αυτή επιτρέπεται."}]);
  T("syn-synimmeni-apolyti", [{"h":"Το υποκείμενο της μετοχής — η βάση της διάκρισης","body":"<p>Η μετοχή είναι <b>ρηματικό επίθετο</b>: μετέχει συγχρόνως στη φύση του ρήματος (έχει υποκείμενο, χρόνο, φωνή, μπορεί να παίρνει αντικείμενο και προσδιορισμούς) και στη φύση του επιθέτου (κλίνεται κατά γένος, αριθμό και πτώση και προσαρμόζεται στο υποκείμενό της). Κάθε μετοχή, λοιπόν, έχει <b>δικό της υποκείμενο</b>, ακριβώς όπως κάθε ρήμα έχει υποκείμενο.</p><p>Η μετοχή <b>συμφωνεί με το υποκείμενό της στο γένος, στον αριθμό και στην πτώση</b>. Όπου βρίσκεται η μετοχή (γένος / αριθμός / πτώση), εκεί ακριβώς θα βρίσκεται και το υποκείμενό της. Αυτή η συμφωνία είναι το πρώτο εργαλείο για να βρούμε το υποκείμενο της μετοχής.</p><p>Με βάση το <b>τι ρόλο παίζει το υποκείμενο της μετοχής μέσα στην πρόταση</b>, οι (κυρίως επιρρηματικές) μετοχές χωρίζονται σε δύο μεγάλες κατηγορίες:</p><ul><li><b>συνημμένη μετοχή</b>: το υποκείμενο της μετοχής έχει <i>και άλλη</i> συντακτική θέση στην πρόταση (είναι π.χ. υποκείμενο ή αντικείμενο του ρήματος)·</li><li><b>απόλυτη μετοχή</b>: το υποκείμενο της μετοχής <i>δεν έχει καμία άλλη</i> συντακτική θέση· λειτουργεί <b>αποκλειστικά</b> ως υποκείμενο της μετοχής.</li></ul><p>Η διάκριση αυτή αφορά κατεξοχήν την <b>επιρρηματική</b> μετοχή (χρονική, αιτιολογική, υποθετική, εναντιωματική/παραχωρητική, τελική, τροπική) και δευτερευόντως την κατηγορηματική. Η <i>επιθετική</i> μετοχή (αυτή με άρθρο, που ισοδυναμεί με αναφορική πρόταση) δεν εντάσσεται σε αυτή τη διάκριση.</p>","examples":[{"gr":"Ὁ νόμος ἀπαγορεύων φαίνεται.","an":"Μετοχή «ἀπαγορεύων» και υποκείμενό της «ὁ νόμος»: αρσενικό, ενικός, ονομαστική — πλήρης συμφωνία γένους-αριθμού-πτώσης."},{"gr":"Ἐπιγενομένη ἡ νόσος ἐπίεσε τούς Ἀθηναίους.","an":"Μετοχή «ἐπιγενομένη» και υποκείμενό της «ἡ νόσος»: θηλυκό, ενικός, ονομαστική (η αρρώστια, αφού ξέσπασε, πίεσε τους Αθηναίους)."},{"gr":"Οὐκ ἔστιν ἡμῖν μή νικῶσι σωτηρία.","an":"Μετοχή «νικῶσι» και υποκείμενό της «ἡμῖν»: αρσενικό, πληθυντικός, δοτική (δεν υπάρχει για εμάς σωτηρία, αν δεν νικήσουμε)."},{"gr":"Ἔστι ταῦτα τήν ῥᾳθυμίαν ὑμῶν αὐξάνοντα.","an":"Μετοχή «αὐξάνοντα» και υποκείμενό της «ταῦτα»: ουδέτερο, πληθυντικός, αιτιατική."},{"gr":"Κῦρος συλλέξας στράτευμα ἐπολιόρκει Μίλητον.","an":"Ξεν. Ἀνάβ. 1.1.7 (τύπου) — μετοχή «συλλέξας» και υποκείμενό της «Κῦρος»: αρσενικό, ενικός, ονομαστική (συμφωνία με το υποκ. του ρήματος «ἐπολιόρκει»)."},{"gr":"Καταγελῶντες αὐτοῦ οἱ δικασταί ἀπεψηφίσαντο.","an":"Μετοχή «καταγελῶντες» και υποκείμενό της «οἱ δικασταί»: αρσενικό, πληθυντικός, ονομαστική — η μετοχή συμφωνεί πλήρως με το υποκείμενό της."}],"note":"Πρακτικός κανόνας εντοπισμού: βρες πρώτα τη μετοχή, δες σε ποιο γένος-αριθμό-πτώση είναι, και ψάξε στην πρόταση τη λέξη με την οποία συμφωνεί απόλυτα. Αυτή είναι το υποκείμενό της."},{"h":"Η συνημμένη μετοχή — τέσσερις τρόποι σύνδεσης","body":"<p>Η μετοχή λέγεται <b>συνημμένη</b> (δηλ. «συνδεδεμένη», από το ρ. <i>συνάπτω</i>) όταν το υποκείμενό της είναι <b>ταυτόχρονα</b> και κάποιος άλλος όρος της πρότασης. Το υποκείμενο της μετοχής, με άλλα λόγια, έχει <b>διπλό ρόλο</b>: πέρα από υποκείμενο της μετοχής, παίζει και έναν δεύτερο συντακτικό ρόλο στην πρόταση.</p><p>Οι περιπτώσεις σύνδεσης είναι τέσσερις. Το υποκείμενο της μετοχής μπορεί να είναι:</p><ul><li><b>α)</b> <b>υποκείμενο του ρήματος</b> της πρότασης (η συχνότερη περίπτωση — μετοχή σε ονομαστική)·</li><li><b>β)</b> <b>αντικείμενο του ρήματος</b> (άμεσο ή έμμεσο — μετοχή σε αιτιατική ή δοτική)·</li><li><b>γ)</b> <b>δοτική προσωπική</b> (κυρίως με απρόσωπες/δοξαστικές εκφράσεις τύπου «ἔδοξε», «δοκεῖ»)·</li><li><b>δ)</b> <b>υποκείμενο απαρεμφάτου</b> (στις περιπτώσεις ταυτοπροσωπίας ή ετεροπροσωπίας).</li></ul><p>Σε όλες αυτές τις περιπτώσεις η μετοχή <b>παίρνει την ίδια πτώση</b> με τον δεύτερο ρόλο του υποκειμένου της (συμφωνεί μαζί του), γι' αυτό και η μετοχή «προσαρτάται», «κολλάει» πάνω σε έναν ήδη υπάρχοντα όρο της πρότασης.</p>","examples":[{"gr":"Ἐπιγενομένη ἡ νόσος ἐπίεσε τούς Ἀθηναίους.","an":"(α) Το «ἡ νόσος» είναι υποκείμενο και της μετοχής «ἐπιγενομένη» και του ρήματος «ἐπίεσε». Η μετοχή είναι συνημμένη στο υποκείμενο του ρήματος."},{"gr":"Οἱ βάρβαροι ἐτόξευον αὐτούς ἀναβαίνοντας.","an":"(β) Το «αὐτούς» είναι αντικείμενο του ρήματος «ἐτόξευον» και ταυτόχρονα υποκείμενο της μετοχής «ἀναβαίνοντας». Συνημμένη στο αντικείμενο (οι βάρβαροι τους τόξευαν την ώρα που ανέβαιναν)."},{"gr":"Ἀκούσασι τοῖς στρατηγοῖς ταῦτα ἔδοξε συναγαγεῖν τό στράτευμα.","an":"(γ) Το «τοῖς στρατηγοῖς» είναι δοτική προσωπική (στο απρόσωπο «ἔδοξε») και ταυτόχρονα υποκείμενο της μετοχής «ἀκούσασι». Συνημμένη στη δοτική προσωπική (αφού άκουσαν αυτά οι στρατηγοί, αποφάσισαν να συγκεντρώσουν τον στρατό)."},{"gr":"Ἔδει ὑμᾶς ταῦτα ἀκοῦσαι καί ἀκούσαντας ἀπελθεῖν.","an":"(δ) Το «ὑμᾶς» είναι υποκείμενο των απαρεμφάτων «ἀκοῦσαι / ἀπελθεῖν» (στο απρόσωπο «ἔδει») και υποκείμενο της μετοχής «ἀκούσαντας». Συνημμένη στο υποκείμενο του απαρεμφάτου (έπρεπε εσείς να ακούσετε αυτά και, αφού τα ακούσετε, να φύγετε)."},{"gr":"Κῦρος συλλέξας στράτευμα ἐπολιόρκει Μίλητον.","an":"(α) Το «Κῦρος» (εννοούμενο υποκείμενο του «ἐπολιόρκει») είναι και υποκείμενο της μετοχής «συλλέξας». Συνημμένη στο υποκείμενο (ο Κύρος, αφού συγκέντρωσε στρατό, πολιορκούσε τη Μίλητο)."},{"gr":"Λαβόντες τούς αἰχμαλώτους ἀπήγαγον εἰς τό στρατόπεδον.","an":"(α) Το εννοούμενο υποκείμενο (αὐτοί) είναι υποκ. και της μετοχής «λαβόντες» και του ρήματος «ἀπήγαγον». Συνημμένη στο υποκείμενο (αφού έπιασαν τους αιχμαλώτους, τους οδήγησαν στο στρατόπεδο)."},{"gr":"Εἶδον τόν Σωκράτη διαλεγόμενον τοῖς νέοις.","an":"(β) Το «τόν Σωκράτη» είναι αντικείμενο του «εἶδον» και ταυτόχρονα υποκείμενο της κατηγορηματικής μετοχής «διαλεγόμενον». Συνημμένη στο αντικείμενο (είδα τον Σωκράτη να συζητάει με τους νέους)."}],"note":"Μνημονικό: στη συνημμένη μετοχή το υποκείμενό της «κρύβεται» μέσα στην πρόταση παίζοντας και δεύτερο ρόλο. Αν διαγράψεις τη μετοχή, η λέξη αυτή εξακολουθεί να χρειάζεται στην πρόταση (ως υποκ./αντικ./δοτ. προσ.)."},{"h":"Η απόλυτη μετοχή — γενική και αιτιατική","body":"<p>Η μετοχή λέγεται <b>απόλυτη</b> (δηλ. «λυμένη», «ξεχωριστή», από το ρ. <i>ἀπολύω</i> = αποδεσμεύω) όταν το υποκείμενό της είναι λέξη που <b>δεν έχει καμία άλλη συντακτική θέση</b> στην πρόταση και λειτουργεί <b>αποκλειστικά</b> ως υποκείμενο της μετοχής. Η μετοχή με το υποκείμενό της σχηματίζουν έτσι ένα <b>αυτοτελές σύνολο</b>, συντακτικά «ανεξάρτητο» από τους υπόλοιπους όρους της πρότασης (όπως η λατινική <i>ablativus absolutus</i>).</p><p>Η απόλυτη μετοχή εμφανίζεται σε δύο πτώσεις, και ανάλογα ονομάζεται:</p><h3>1. Γενική απόλυτη</h3><p>Η <b>συνηθέστερη</b> μορφή. Η μετοχή και το υποκείμενό της τίθενται σε <b>γενική</b> πτώση. Με γενική απόλυτη εκφέρεται <b>κάθε επιρρηματική μετοχή προσωπικού ρήματος</b> — δηλαδή χρονική, αιτιολογική, υποθετική, εναντιωματική/παραχωρητική, τροπική — <b>εκτός από την τελική</b> (η τελική μετοχή είναι πάντοτε συνημμένη, σε ονομαστική ή αιτιατική, και αναφέρεται στο υποκείμενο ή το αντικείμενο του ρήματος κίνησης).</p><h3>2. Αιτιατική απόλυτη</h3><p>Η <b>σπανιότερη</b> μορφή. Η μετοχή τίθεται σε <b>αιτιατική ουδετέρου ενικού</b> και προέρχεται κατά κανόνα από <b>απρόσωπα ρήματα ή απρόσωπες εκφράσεις</b> (βλ. χωριστή ενότητα). Εκφράζει συνήθως εναντιωματική, αιτιολογική, υποθετική ή χρονική σχέση.</p>","examples":[{"gr":"Κρέοντος βασιλεύοντος οὐ μικρά συμφορά κατέσχε Θήβας.","an":"Γενική απόλυτη (χρονική). Το «Κρέοντος» είναι υποκείμενο μόνο της μετοχής «βασιλεύοντος» — δεν παίζει κανέναν άλλο ρόλο στην πρόταση. Μτφρ.: «Όταν βασίλευε ο Κρέοντας, μεγάλη συμφορά έπληξε τη Θήβα.»"},{"gr":"Ἀποπλεῖ οἴκαδε καίπερ μέσου χειμῶνος ὄντος.","an":"Γενική απόλυτη (εναντιωματική, με «καίπερ»). Το «χειμῶνος» είναι μόνο υποκείμενο της μετοχής «ὄντος». Μτφρ.: «Αποπλέει για την πατρίδα, μολονότι ήταν καταμεσής του χειμώνα.»"},{"gr":"Κῦρος δ' οὖν ἀνέβη ἐπί τά ὄρη οὐδενός κωλύοντος.","an":"Ξεν. Ἀνάβ. 1.2.22 (τύπου) — γενική απόλυτη (τροπική/χρονική). Το «οὐδενός» είναι μόνο υποκείμενο της μετοχής «κωλύοντος». Μτφρ.: «Ο Κύρος λοιπόν ανέβηκε στα βουνά χωρίς να τον εμποδίζει κανείς.»"},{"gr":"Χρημάτων δεομένης τῆς Σπάρτης πρός πόλεμον, ἐπορεύθη Ἀγησίλαος εἰς Αἴγυπτον.","an":"Γενική απόλυτη (αιτιολογική). Το «τῆς Σπάρτης» είναι μόνο υποκείμενο της μετοχής «δεομένης». Μτφρ.: «Επειδή η Σπάρτη χρειαζόταν χρήματα για τον πόλεμο, ο Αγησίλαος εκστράτευσε στην Αίγυπτο.»"},{"gr":"Κολαζόντων ὑμῶν τούς ἀδικοῦντας ἔσονται οἱ νόμοι καλοί καί δίκαιοι.","an":"Γενική απόλυτη (υποθετική). Το «ὑμῶν» είναι μόνο υποκείμενο της μετοχής «κολαζόντων». Μτφρ.: «Αν τιμωρείτε τους αδικούντες, οι νόμοι θα είναι ωραίοι και δίκαιοι.»"},{"gr":"Τόν δέ Κῦρον ἦγον ἔσω οἱ θεράποντες, κελεύσαντος τοῦ Ἀστυάγεος.","an":"Ξεν. Κύρ. Παιδ. 1.3.x (τύπου) — γενική απόλυτη (χρονική/αιτιολογική). Το «τοῦ Ἀστυάγεος» είναι μόνο υποκ. της «κελεύσαντος»· υποκ. του ρήματος «ἦγον» είναι «οἱ θεράποντες». Μτφρ.: «Τον Κύρο τον οδηγούσαν μέσα οι υπηρέτες, αφού το διέταξε ο Αστυάγης.»"},{"gr":"Ἐξόν ἀπιέναι, οὐκ ἀπῆλθον.","an":"Αιτιατική απόλυτη (εναντιωματική, από το απρόσωπο «ἔξεστι»). Μτφρ.: «Αν και μου ήταν δυνατό να φύγω, δεν έφυγα.»"},{"gr":"Ἀφικομένων τῶν πολεμίων ἐκ τῆς πόλεως, ἐλείπομεν.","an":"Γενική απόλυτη (χρονική). Το «τῶν πολεμίων» είναι μόνο υποκ. της «ἀφικομένων»· υποκ. του ρήματος «ἐλείπομεν» είναι το εννοούμενο «ἡμεῖς». Μτφρ.: «Όταν έφτασαν οι εχθροί από την πόλη, εμείς αναχωρούσαμε.»"}],"note":"Κρίσιμη ασφαλιστική δικλείδα: για να είναι όντως απόλυτη η μετοχή, το υποκείμενό της δεν πρέπει να επαναλαμβάνεται ούτε να εννοείται ως όρος της κύριας δομής. Αν η ίδια λέξη ξαναβρίσκεται ως υποκ./αντικ. του ρήματος, η μετοχή είναι συνημμένη, όχι απόλυτη."},{"h":"Η αιτιατική απόλυτη και τα απρόσωπα ρήματα","body":"<p>Η <b>αιτιατική απόλυτη</b> είναι ειδική περίπτωση απόλυτης μετοχής. Σχηματίζεται από <b>απρόσωπα ρήματα και απρόσωπες εκφράσεις</b>, των οποίων η μετοχή τίθεται σε <b>αιτιατική ουδετέρου ενικού</b> (γιατί τα απρόσωπα δεν έχουν προσωπικό υποκείμενο — υποκείμενό τους είναι ένα απαρέμφατο ή μια ολόκληρη πρόταση).</p><p>Διακρίνουμε δύο τύπους:</p><ul><li><b>Απρόσωπα ρήματα</b> → μετοχή ενός λεκτικού τύπου: <i>ἐξόν</i> (ἔξεστι), <i>δέον</i> (δεῖ), <i>παρόν / παρασχόν</i> (πάρεστι / παρέχει), <i>προσῆκον</i> (προσήκει), <i>μέλον</i> (μέλει), <i>μεταμέλον</i> (μεταμέλει), <i>μετόν</i> (μέτεστι), <i>πρέπον</i> (πρέπει), <i>τυχόν</i> (τυγχάνει), <i>δόξαν / δόξαντα</i> (δοκεῖ/ἔδοξε), <i>χρεών</i> (χρή).</li><li><b>Απρόσωπες εκφράσεις</b> (επίθετο/μετοχή ουδ. + μετοχή <i>ὄν</i>): <i>δυνατόν ὄν</i>, <i>ἀδύνατον ὄν</i>, <i>δίκαιον ὄν</i>, <i>αἰσχρόν ὄν</i>, <i>ῥᾴδιον ὄν</i>, <i>ἄδηλον ὄν</i>, <i>οἷόν τε ὄν</i>, <i>εἰρημένον</i>, <i>γεγραμμένον</i>, <i>προσταχθέν / προστεταγμένον</i>, <i>ὑπάρχον</i>.</li></ul><p>Νοηματικά η αιτιατική απόλυτη ισοδυναμεί συχνότατα με <b>εναντιωματική / παραχωρητική</b> πρόταση («αν και…», «μολονότι…»), αλλά μπορεί να εκφράζει και <b>αιτία, υπόθεση ή χρόνο</b>, όπως κάθε επιρρηματική μετοχή.</p>","examples":[{"gr":"Ἐξόν μοι ἴσον λαμβάνειν οὐκ ἐλάμβανον.","an":"Αιτιατική απόλυτη από το «ἔξεστι» (εναντιωματική). Υποκείμενο της «ἐξόν» είναι το απαρέμφατο «λαμβάνειν». Μτφρ.: «Αν και μου ήταν δυνατό να παίρνω ίσο μερίδιο, δεν έπαιρνα.»"},{"gr":"Δέον αὐτούς βοηθεῖν, ἡσύχαζον.","an":"Αιτιατική απόλυτη από το «δεῖ» (εναντιωματική). Μτφρ.: «Ενώ έπρεπε αυτοί να βοηθήσουν, έμεναν αδρανείς.»"},{"gr":"Δόξαν ταῦτα, ἐπορεύοντο.","an":"Αιτιατική απόλυτη από το «δοκεῖ/ἔδοξε» (χρονική/αιτιολογική). Υποκείμενο το «ταῦτα». Μτφρ.: «Αφού αποφασίστηκαν αυτά, ξεκινούσαν.»"},{"gr":"Παρόν φεύγειν, ἔμεινεν.","an":"Αιτιατική απόλυτη από το «πάρεστι» (εναντιωματική). Μτφρ.: «Αν και του δινόταν η δυνατότητα να φύγει, παρέμεινε.»"},{"gr":"Προσῆκον αὐτῷ ἄρχειν, οὐκ ἦρξεν.","an":"Αιτιατική απόλυτη από το «προσήκει» (εναντιωματική). Μτφρ.: «Αν και του ταίριαζε / του άρμοζε να άρχει, δεν άρχισε.»"},{"gr":"Δυνατόν ὄν σωθῆναι, ἀπώλοντο.","an":"Αιτιατική απόλυτη (απρόσωπη έκφραση «δυνατόν ὄν», εναντιωματική). Μτφρ.: «Αν και ήταν δυνατό να σωθούν, χάθηκαν.»"},{"gr":"Ὡς ἐξόν ἤδη ποιεῖν αὐτοῖς ὅ τι βούλοιντο, πολλούς ἀπέκτεινον.","an":"Ξεν. Ἑλλ. 2.3.21 — αιτιατική απόλυτη από το «ἔξεστι» (αιτιολογική, με «ὡς» υποκειμενικής αιτίας). Μτφρ.: «Με την ιδέα ότι τους ήταν πια δυνατό να κάνουν ό,τι ήθελαν, σκότωναν πολλούς.»"},{"gr":"Δόξαν δέ ταῦτα, ἐκήρυξαν ἀναπαύεσθαι.","an":"Ξεν. Ἀνάβ. (τύπου) — αιτιατική απόλυτη από το «ἔδοξε» (χρονική/αιτιολογική). Υποκ. το «ταῦτα». Μτφρ.: «Αφού αποφασίστηκαν αυτά, διέταξαν με κήρυκα ανάπαυση.»"}],"table":{"title":"Συχνότερες μετοχές σε αιτιατική απόλυτη (απρόσωπα)","cols":["Μετοχή (αιτ. απόλ.)","Από το ρήμα/έκφραση","Σημασία"],"rows":[["ἐξόν","ἔξεστι","είναι δυνατό / επιτρέπεται"],["δέον / δεῆσον","δεῖ","πρέπει / χρειάζεται"],["χρεών","χρή","πρέπει"],["παρόν / παρασχόν","πάρεστι / παρέχει","δίνεται η δυνατότητα"],["προσῆκον","προσήκει","ταιριάζει / αρμόζει"],["πρέπον","πρέπει","αρμόζει"],["μέλον","μέλει","ενδιαφέρει / νοιάζει"],["μεταμέλον","μεταμέλει","μεταμελείται κανείς"],["μετόν","μέτεστι","υπάρχει μερίδιο / δικαίωμα"],["τυχόν","τυγχάνει","τυχαίνει / ίσως"],["δόξαν / δόξαντα","δοκεῖ / ἔδοξε","αποφασίστηκε / φάνηκε σωστό"],["δυνατόν ὄν / ἀδύνατον ὄν","ἐστί δυνατόν/ἀδύνατον","είναι (α)δύνατο"],["δίκαιον ὄν","ἐστί δίκαιον","είναι δίκαιο"],["αἰσχρόν ὄν","ἐστί αἰσχρόν","είναι ντροπή"],["οἷόν τε ὄν","οἷόν τέ ἐστι","είναι δυνατό"],["εἰρημένον / γεγραμμένον","εἴρηται / γέγραπται","έχει ειπωθεί / γραφτεί"],["προσταχθέν / προστεταγμένον","προστέτακται","έχει διαταχθεί"],["ὑπάρχον","ὑπάρχει","υπάρχει η δυνατότητα"]]},"note":"Θυμήσου: τα απρόσωπα δεν έχουν προσωπικό υποκείμενο, γι' αυτό η μετοχή τους μένει σε ουδέτερο αιτιατικής. Πολλά συνοδεύονται από τα «καίπερ», «καί», «ὅμως» που ενισχύουν την εναντιωματική χροιά."},{"h":"Πώς ξεχωρίζω συνημμένη από απόλυτη — μεθοδολογία","body":"<p>Η διάκριση συνημμένης / απόλυτης μετοχής είναι καθαρά <b>συντακτική</b> και απαντάται σε τρία βήματα:</p><ul><li><b>Βήμα 1 — Βρίσκω τη μετοχή.</b> Εντοπίζω το ρηματικό επίθετο (π.χ. «-ων / -ουσα / -ον», «-σας / -σασα / -σαν», «-μενος» κ.λπ.).</li><li><b>Βήμα 2 — Βρίσκω το υποκείμενο της μετοχής.</b> Είναι η λέξη που συμφωνεί μαζί της σε γένος, αριθμό και πτώση.</li><li><b>Βήμα 3 — Ελέγχω τον ρόλο του υποκειμένου στην υπόλοιπη πρόταση.</b><br>α) Αν η λέξη αυτή έχει <b>και άλλη</b> θέση (υποκ. ρήματος / αντικ. / δοτ. προσ. / υποκ. απαρεμφάτου) → <b>συνημμένη</b>.<br>β) Αν η λέξη αυτή <b>δεν έχει καμία άλλη</b> θέση → <b>απόλυτη</b> (γενική ή αιτιατική).</li></ul><p><b>Κρίσιμη ένδειξη πτώσης:</b> αν η μετοχή με το υποκείμενό της είναι σε <b>γενική</b> που δεν δικαιολογείται από κανέναν όρο της πρότασης, έχουμε σχεδόν σίγουρα <b>γενική απόλυτη</b>. Αν είναι σε <b>αιτιατική ουδετέρου</b> από απρόσωπο, έχουμε <b>αιτιατική απόλυτη</b>. Αν η μετοχή είναι σε ονομαστική (συμφωνεί με το υποκ. του ρήματος) ή σε αιτιατική/δοτική που ταυτίζεται με αντικείμενο, είναι <b>συνημμένη</b>.</p><p><b>Προσοχή — η τελική μετοχή.</b> Η τελική επιρρηματική μετοχή είναι <b>πάντα συνημμένη</b>, ποτέ απόλυτη: αναφέρεται στο υποκείμενο ή στο αντικείμενο ρήματος κίνησης (π.χ. «πέμπω πρέσβεις διδάξοντας»). Δεν εκφέρεται με γενική απόλυτη.</p>","examples":[{"gr":"ΣΥΓΚΡΙΣΗ — Οἱ στρατιῶται ἀκούσαντες ταῦτα ἀπῆλθον.","an":"Συνημμένη: «οἱ στρατιῶται» είναι υποκ. και της «ἀκούσαντες» και του «ἀπῆλθον». Η μετοχή είναι σε ονομαστική, συμφωνεί με το υποκ. του ρήματος."},{"gr":"ΣΥΓΚΡΙΣΗ — Τῶν στρατιωτῶν ἀκουσάντων ταῦτα, ὁ στρατηγός ἀπῆλθεν.","an":"Απόλυτη (γενική): «τῶν στρατιωτῶν» είναι μόνο υποκ. της «ἀκουσάντων». Υποκ. του ρήματος «ἀπῆλθεν» είναι ο «στρατηγός». Δύο διαφορετικά πρόσωπα → γενική απόλυτη."},{"gr":"Ταῦτα εἰπών ὁ Κῦρος ἀπῆλθεν.","an":"Συνημμένη (ονομαστική): το «Κῦρος» είναι υποκ. και της «εἰπών» και του «ἀπῆλθεν» — το ίδιο πρόσωπο κάνει και τα δύο."},{"gr":"Πέμπουσι πρέσβεις διδάξοντας ταῦτα.","an":"Τελική μετοχή «διδάξοντας», συνημμένη στο αντικείμενο «πρέσβεις» — ποτέ απόλυτη. (Στέλνουν πρέσβεις για να διδάξουν αυτά.)"},{"gr":"ΣΥΓΚΡΙΣΗ — Ἡμέρας γενομένης, οἱ στρατηγοί συνῆλθον.","an":"Απόλυτη (γενική): «ἡμέρας» είναι μόνο υποκ. της «γενομένης»· υποκ. του ρήματος «συνῆλθον» είναι «οἱ στρατηγοί». Διαφορετικό υποκ. → γενική απόλυτη (όταν ξημέρωσε, οι στρατηγοί συγκεντρώθηκαν)."},{"gr":"ΣΥΓΚΡΙΣΗ — Ἰδών δέ ὁ Κλέαρχος προσιόντας τούς πολεμίους παρετάξατο.","an":"Συνημμένη (ονομαστική): «ὁ Κλέαρχος» = υποκ. της «ἰδών» + του «παρετάξατο»· η «προσιόντας» είναι συνημμένη στο αντικείμενο «τούς πολεμίους»."}],"note":"Χρυσός κανόνας: ίδιο πρόσωπο δράσης μετοχής και ρήματος → τάση για συνημμένη· διαφορετικό πρόσωπο/πράγμα που δρα στη μετοχή → τάση για (γενική) απόλυτη."},{"h":"Ανάλυση της επιρρηματικής μετοχής σε δευτερεύουσα πρόταση","body":"<p>Κάθε επιρρηματική μετοχή (συνημμένη ή απόλυτη) μπορεί να <b>αναλυθεί</b> σε ισοδύναμη <b>δευτερεύουσα επιρρηματική πρόταση</b>. Η ανάλυση γίνεται σε τρία βήματα: (1) βρίσκουμε το <b>είδος</b> της μετοχής, (2) επιλέγουμε τον κατάλληλο <b>σύνδεσμο εισαγωγής</b>, (3) βρίσκουμε το σωστό <b>ρήμα (έγκλιση + χρόνο)</b>, με βάση τη <b>χρονική βαθμίδα</b> της μετοχής και τον <b>χρόνο του ρήματος</b> εξάρτησης (αρκτικός ή ιστορικός).</p><p>Καθοριστικός κανόνας για τον <b>χρόνο</b> του ρήματος ανάλυσης: <i>ενεστώτας/παρατατικός</i> μετοχή → <b>σύγχρονο</b>· <i>αόριστος/παρακείμενος</i> μετοχή → <b>προτερόχρονο</b>· <i>μέλλοντας</i> μετοχή → <b>υστερόχρονο</b>.</p><h3>Χρονική μετοχή</h3><p>Εισάγεται με <b>ὅτε, ὡς, ἐπεί, ἐπειδή</b> (+ οριστική) ή <b>ἐνῷ / ἕως</b>. Δηλώνει σύγχρονο ή (συχνότερα) προτερόχρονο.</p><h3>Αιτιολογική μετοχή</h3><p><b>Αντικειμενική</b> αιτία → <b>ὅτι / διότι / ἐπεί / ἐπειδή</b> + οριστική. <b>Υποκειμενική</b> αιτία (συνοδεύεται από «ὡς», «ἅτε», «οἷον») → <b>ὡς</b> + οριστική (αρκτ. χρ.) ή <b>ὡς</b> + ευκτική του πλαγίου λόγου (ιστ. χρ.).</p><h3>Τελική μετοχή</h3><p>Εισάγεται με <b>ἵνα / ὅπως / ὡς</b> + υποτακτική (αρκτ. χρόνος) ή + ευκτική του πλαγίου λόγου (ιστ. χρόνος).</p><h3>Υποθετική μετοχή</h3><p>Αναλύεται σε <b>υποθετικό λόγο</b>· το είδος του (πραγματικό, προσδοκώμενο, αόριστη επανάληψη, αντίθετο του πραγματικού) καθορίζεται από το <b>ρήμα της κύριας</b> πρότασης (απόδοση).</p><h3>Εναντιωματική / παραχωρητική μετοχή</h3><p>Εισάγεται με <b>εἰ καί / καί εἰ / καίτοι / ἄν καί</b>. Τα «καίπερ, καί, καίτοι, καί ταῦτα» που συνοδεύουν τη μετοχή <b>δεν</b> μεταφέρονται στη δευτερεύουσα πρόταση.</p><h3>Τροπική μετοχή</h3><p>Συνήθως δεν αναλύεται σε πρόταση (δηλώνει τρόπο)· κατά περίπτωση αποδίδεται με «με το να…».</p>","examples":[{"gr":"Κρέοντος βασιλεύοντος συμφορά κατέσχε Θήβας. → Ὅτε ἐβασίλευε(ν) ὁ Κρέων, συμφορά κατέσχε Θήβας.","an":"Χρονική γενική απόλυτη → χρονική πρόταση με «ὅτε» + οριστική παρατατικού (σύγχρονο, γιατί η μετοχή είναι ενεστώτα)."},{"gr":"Ἀκούσαντες ταῦτα ἀπῆλθον. → Ἐπεί / Ἀφοῦ ἤκουσαν ταῦτα, ἀπῆλθον.","an":"Χρονική (αορίστου) → προτερόχρονο: «ἐπεί» + οριστική αορίστου."},{"gr":"Πέμπουσι πρέσβεις διδάξοντας. → Πέμπουσι πρέσβεις, ἵνα διδάξωσι.","an":"Τελική μετοχή (μέλλοντα) → «ἵνα» + υποτακτική, γιατί το ρήμα «πέμπουσι» είναι αρκτικού χρόνου."},{"gr":"Τριήρεις ἐπλήρου ὡς βοηθήσων. → Τριήρεις ἐπλήρου, ἵνα βοηθήσειε(ν).","an":"Τελική μετοχή → «ἵνα» + ευκτική του πλαγίου λόγου, γιατί το «ἐπλήρου» είναι ιστορικού χρόνου."},{"gr":"Νικήσαντες κύριοι ἔσεσθε. → Ἐάν νικήσητε, κύριοι ἔσεσθε.","an":"Υποθετική μετοχή → προσδοκώμενο (απόδοση μέλλοντας): «ἐάν» + υποτακτική."},{"gr":"Ἀποπλεῖ καίπερ μέσου χειμῶνος ὄντος. → Ἀποπλεῖ, εἰ καί μέσος χειμών ἦν / ἐστιν.","an":"Εναντιωματική γενική απόλυτη → «εἰ καί» + οριστική. Το «καίπερ» δεν μεταφέρεται."},{"gr":"Χρημάτων δεομένης τῆς Σπάρτης, ἐπορεύθη Ἀγησίλαος. → Ἐπεί ἡ Σπάρτη ἐδεῖτο χρημάτων, ἐπορεύθη Ἀγησίλαος.","an":"Αιτιολογική γενική απόλυτη → «ἐπεί» + οριστική (αντικειμενική αιτία)."},{"gr":"Ἅτε παῖς ὤν ἥδετο τῇ στολῇ. → Ἐπεί παῖς ἦν, ἥδετο τῇ στολῇ.","an":"Ξεν. Κύρ. Παιδ. 1.3.3 (τύπου) — αιτιολογική συνημμένη (υποκειμενική αιτία, με «ἅτε») → «ἐπεί / ὅτι» + οριστική (επειδή ήταν παιδί, χαιρόταν με τη στολή)."}],"table":{"title":"Ανάλυση επιρρηματικών μετοχών — συνοπτικός πίνακας","cols":["Είδος μετοχής","Σύνδεσμος εισαγωγής","Έγκλιση / εκφορά"],"rows":[["Χρονική","ὅτε, ὡς, ἐπεί, ἐπειδή, ἐνῷ, ἕως","οριστική (σύγχρονο/προτερόχρονο)"],["Αιτιολογική (αντικειμ.)","ὅτι, διότι, ἐπεί, ἐπειδή","οριστική"],["Αιτιολογική (υποκειμ.: ὡς/ἅτε)","ὡς","οριστική ή ευκτική πλαγίου λόγου"],["Τελική","ἵνα, ὅπως, ὡς","υποτακτική (αρκτ.) / ευκτ. πλ. λόγου (ιστ.)"],["Υποθετική","εἰ / ἐάν","κατά το είδος του υποθετικού λόγου"],["Εναντιωματική / παραχωρ.","εἰ καί, καί εἰ, καίτοι","κατά την απόδοση / οριστική"]]},"note":"Στην ανάλυση πάντα: 1) υποκείμενο μετοχής → υποκείμενο νέου ρήματος, 2) χρόνος μετοχής → χρονική σχέση, 3) χρόνος ρήματος εξάρτησης (αρκτικός/ιστορικός) → επιλογή υποτακτικής ή ευκτικής πλαγίου λόγου."},{"h":"Συγκεντρωτική σύγκριση συνημμένης και απόλυτης μετοχής","body":"<p>Συνοψίζουμε τις βασικές διαφορές των δύο κατηγοριών. Και οι δύο είναι κατά κανόνα <b>επιρρηματικές</b> μετοχές και εκφράζουν τις ίδιες λογικές σχέσεις (χρόνο, αιτία, υπόθεση, εναντίωση, τρόπο, σκοπό)· διαφέρουν μόνο ως προς το αν το <b>υποκείμενο της μετοχής συμμετέχει</b> στη συντακτική δομή της πρότασης ή όχι.</p><ul><li>Η <b>συνημμένη</b> «κολλάει» σε έναν όρο της πρότασης (το υποκείμενό της έχει διπλό ρόλο). Παίρνει την πτώση εκείνου του όρου: ονομαστική (υποκ. ρήματος), αιτιατική/δοτική (αντικ.), δοτική (δοτ. προσ.), αιτιατική (υποκ. απαρεμφ.).</li><li>Η <b>απόλυτη</b> στέκεται μόνη της με δικό της υποκείμενο. Παίρνει <b>γενική</b> (προσωπικά ρήματα — γενική απόλυτη) ή <b>αιτιατική ουδ.</b> (απρόσωπα — αιτιατική απόλυτη).</li></ul><p>Μνημονικός συσχετισμός: <i>συν-ημμένη</i> = «συν-δεδεμένη» (δένεται με την πρόταση)· <i>από-λυτη</i> = «από-λυμένη» (λυμένη/ανεξάρτητη από την πρόταση).</p>","examples":[{"gr":"Νικήσαντες οἱ Ἕλληνες ἐχάρησαν.","an":"Συνημμένη (ονομ.): «οἱ Ἕλληνες» = υποκ. μετοχής + υποκ. ρήματος."},{"gr":"Νικησάντων τῶν Ἑλλήνων, οἱ βάρβαροι ἔφυγον.","an":"Γενική απόλυτη: «τῶν Ἑλλήνων» = μόνο υποκ. μετοχής· υποκ. ρήματος = «οἱ βάρβαροι»."},{"gr":"Ἐξόν μένειν, ἀπῆλθον.","an":"Αιτιατική απόλυτη (απρόσωπο «ἔξεστι»): «ἐξόν» σε αιτ. ουδ., υποκ. της το απαρ. «μένειν»."},{"gr":"Ταῦτα εἰπών ἀπῆλθεν.","an":"Συνημμένη (ονομ.): το εννοούμενο υποκείμενο είναι υποκ. και της μετοχής «εἰπών» και του ρήματος «ἀπῆλθεν» — ένα και το αυτό πρόσωπο."},{"gr":"Σαλπίγξαντος τοῦ σαλπικτοῦ, οἱ στρατιῶται ἐπῄεσαν.","an":"Γενική απόλυτη (χρονική): «τοῦ σαλπικτοῦ» = μόνο υποκ. της μετοχής «σαλπίγξαντος»· υποκ. του ρήματος «ἐπῄεσαν» = «οἱ στρατιῶται» (αφού σήμανε ο σαλπιγκτής, οι στρατιώτες προχωρούσαν εναντίον)."},{"gr":"Δέον βοηθεῖν, οὐκ ἐβοήθησαν.","an":"Αιτιατική απόλυτη (απρόσωπο «δεῖ», εναντιωματική): «δέον» σε αιτ. ουδ., υποκ. της το απαρ. «βοηθεῖν»."}],"table":{"title":"Συνημμένη ↔ Απόλυτη: οι διαφορές με μια ματιά","cols":["Κριτήριο","Συνημμένη","Απόλυτη"],"rows":[["Υποκείμενο μετοχής","έχει και άλλη θέση στην πρόταση","δεν έχει καμία άλλη θέση"],["Σχέση με την πρόταση","συνδεδεμένη (εξαρτημένη)","ανεξάρτητη / αυτοτελής"],["Πτώση μετοχής","ονομ. / αιτ. / δοτ. (κατά τον 2ο ρόλο)","γενική ή αιτιατική ουδ."],["Ονομασία πτώσης","—","γενική απόλυτη / αιτιατική απόλυτη"],["Τύπος ρήματος","κάθε ρήμα","γεν. απόλ.: προσωπικά· αιτ. απόλ.: απρόσωπα"],["Τελική μετοχή","ΝΑΙ (πάντα συνημμένη)","ΟΧΙ"],["Παράδειγμα","Ταῦτα εἰπών ἀπῆλθεν","Κρέοντος βασιλεύοντος…"]]},"note":"Πηγές σχολικής παράδοσης και εμπλουτισμού: users.sch.gr/ipap (Θεωρία αρχαία), ebooks.edu.gr (Συντακτικό Α-Β-Γ Γυμνασίου, ΙΕΠ), greek-language.gr (Πύλη), Smyth «Greek Grammar» §§2058-2075 (genitive/accusative absolute), Perseus."}]);
})();
